  // Момент загрузки страницы — нужен для подавления «догоняющих» тостов достижений
  const _appBootAt = Date.now();

  // ── Data ──
  const consonants = ['ㄱ','ㄴ','ㄷ','ㄹ','ㅁ','ㅂ','ㅅ','ㅇ','ㅈ','ㅎ'];
  const vowels     = ['ㅏ','ㅑ','ㅓ','ㅕ','ㅗ','ㅛ','ㅜ','ㅠ','ㅡ','ㅣ'];
  const translitMap = {
    'ㄱ':'g','ㄴ':'n','ㄷ':'d','ㄹ':'r','ㅁ':'m','ㅂ':'b','ㅅ':'s','ㅇ':'','ㅈ':'j','ㅎ':'h',
    'ㅏ':'a','ㅑ':'ya','ㅓ':'eo','ㅕ':'yeo','ㅗ':'o','ㅛ':'yo','ㅜ':'u','ㅠ':'yu','ㅡ':'eu','ㅣ':'i'
  };
  let flashcardSession = [];

  function buildSyllable(c, v) {
    const ci = ['ㄱ','ㄲ','ㄴ','ㄷ','ㄸ','ㄹ','ㅁ','ㅂ','ㅃ','ㅅ','ㅆ','ㅇ','ㅈ','ㅉ','ㅊ','ㅋ','ㅌ','ㅍ','ㅎ'].indexOf(c);
    const vi = ['ㅏ','ㅐ','ㅑ','ㅒ','ㅓ','ㅔ','ㅕ','ㅖ','ㅗ','ㅘ','ㅙ','ㅚ','ㅛ','ㅜ','ㅝ','ㅞ','ㅟ','ㅠ','ㅡ','ㅢ','ㅣ'].indexOf(v);
    if (ci < 0 || vi < 0) return c + v;
    return String.fromCharCode(0xAC00 + ci * 588 + vi * 28);
  }

  // ── Screen switching ──
  // Память скролла по экранам: «назад» возвращает туда, где был, а не наверх
  let _curScreen = 'home';
  const _screenScroll = {};
  function _scrollEl() { const main = document.querySelector('.app-main'); return (main && getComputedStyle(main).overflowY === 'auto') ? main : null; }
  function _getScroll() { const el = _scrollEl(); return el ? el.scrollTop : (window.scrollY || 0); }
  function _setScroll(y) { const el = _scrollEl(); if (el) el.scrollTo(0, y); else window.scrollTo(0, y); }
  function switchScreen(name, restoreScroll) {
    if (name === 'admin' && !isAdmin()) name = 'home'; // кабинет только для админа
    _screenScroll[_curScreen] = _getScroll();
    document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    document.getElementById('screen-' + name).classList.add('active');
    // Activate matching nav items in BOTH bottom nav and sidebar nav
    document.querySelectorAll(`.nav-item[data-screen="${name}"]`).forEach(n => n.classList.add('active'));
    if (name === 'hangul' && !document.getElementById('consonants-grid').children.length) initHangulLab();
    if (name === 'games') syncBestScoreCards();
    if (name === 'home') { renderCustomVideos(); renderCustomFeedPosts(); renderHeroLesson(); renderDailyGoal(); renderSrsWidget(); renderContinue(); }
    if (name === 'lessons') { renderModuleSwitcher(); renderCustomLessons(); renderLessonPath(); }
    if (name === 'profile') { syncAchievementsStrip(); renderWeeklyXpChart(); renderHomeworkList(); renderSavedWords(); renderPlanCard(); }
    if (name === 'social') renderFriendsAndChat();
    if (name === 'words') renderSavedWords();
    if (name === 'topik') { _topikSection = null; _topikReturn = null; renderTopik(); }
    if (name === 'selfstudy') { _ssSection = null; renderSelfStudy(); }
    if (name === 'topikdeep') { tdReset(); tdRender(); }
    if (name === 'reading') renderReading();
    if (name === 'studykr') renderStudyKr();
    if (name === 'admin') renderProfileAdminPanel(adminCurrentTab || 'hub');
    _curScreen = name;
    tagInteractive(); // make any freshly-rendered clickable cards keyboard-focusable
    if (restoreScroll) {
      const y = _screenScroll[name] || 0;
      requestAnimationFrame(() => _setScroll(y)); // после перерисовки экрана
    } else {
      _setScroll(0);
    }
  }

  // ── Keyboard accessibility: clickable <div>s (with onclick) become focusable and
  //    respond to Enter/Space like a real button, without rewriting every card. ──
  function tagInteractive(root) {
    (root || document).querySelectorAll('[onclick]:not([data-kbd]):not(button):not(a):not(input):not(textarea):not(select)').forEach(el => {
      el.setAttribute('data-kbd', '1');
      if (!el.hasAttribute('tabindex')) el.setAttribute('tabindex', '0');
      if (!el.hasAttribute('role')) el.setAttribute('role', 'button');
    });
  }
  document.addEventListener('keydown', e => {
    if (e.key !== 'Enter' && e.key !== ' ' && e.key !== 'Spacebar') return;
    const el = document.activeElement;
    if (!el || !el.getAttribute || !el.getAttribute('onclick')) return;
    const tag = el.tagName;
    if (tag === 'BUTTON' || tag === 'A' || tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
    e.preventDefault();
    el.click();
  });

  // ── Hero progress segments ──
  function buildHeroSegments() {
    const c = document.getElementById('hero-segments');
    if (!c) return;
    const total = 30, done = 5;
    let html = '';
    for (let i = 0; i < total; i++) {
      const cls = i < done ? 'done' : (i === done ? 'current' : '');
      html += '<span class="' + cls + '"></span>';
    }
    c.innerHTML = html;
  }

  // ── Waveform ──
  function buildWaveform() {
    const c = document.getElementById('waveform');
    if (!c) return;
    let html = '';
    for (let i = 0; i < 48; i++) {
      const h = 4 + Math.floor(Math.abs(Math.sin(i * 0.7) + Math.sin(i * 0.31)) * 9);
      const o = (0.45 + Math.random() * 0.45).toFixed(2);
      html += '<div style="flex:1; background:var(--card); border-radius:999px; height:' + h + 'px; opacity:' + o + ';"></div>';
    }
    c.innerHTML = html;
  }

  // ── Streak calendar ──
  function buildStreakCal() {
    const c = document.getElementById('streak-cal');
    if (!c) return;
    const days = ['Пн','Вт','Ср','Чт','Пт','Сб','Вс'];
    const now = new Date();
    const y = now.getFullYear(), mo = now.getMonth();
    const todayD = now.getDate();
    const visited = new Set(stats.dates || []);
    const firstDow = (new Date(y, mo, 1).getDay() + 6) % 7; // shift Sun=0..Sat=6 → Mon=0..Sun=6
    const daysInMonth = new Date(y, mo + 1, 0).getDate();
    let html = '';
    days.forEach(d => html += '<div style="color:var(--hush); padding: 4px 0;">' + d + '</div>');
    for (let i = 0; i < firstDow; i++) html += '<div></div>';
    for (let d = 1; d <= daysInMonth; d++) {
      const iso = `${y}-${String(mo + 1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
      const completed = visited.has(iso);
      const isToday = d === todayD;
      const bg = isToday ? 'background: var(--coral); color:white; font-weight:700;'
                : completed ? 'background: var(--blush); color: var(--berry);'
                : 'color:var(--hush);';
      html += `<div style="border-radius:999px; padding: 6px 0;${bg}">${d}</div>`;
    }
    c.innerHTML = html;

    const monthChip = document.getElementById('profile-month-chip');
    if (monthChip) monthChip.textContent = `${monthsRu[mo]} ${y}`;
    const streakText = document.getElementById('profile-streak-text');
    if (streakText) streakText.textContent = `${stats.streak} ${pluralDays(stats.streak)}`;
  }

  // ── Hangul Lab ──
  let curCons = 'ㄱ', curVowel = 'ㅏ';
  function initHangulLab() {
    const cg = document.getElementById('consonants-grid');
    const vg = document.getElementById('vowels-grid');
    cg.innerHTML = '';
    vg.innerHTML = '';
    consonants.forEach((c, i) => {
      const b = document.createElement('button');
      b.className = 'hangul-key ko' + (i === 0 ? ' cons-active' : '');
      b.innerHTML = '<div>' + c + '</div><div class="rom">' + (translitMap[c] || '') + '</div>';
      b.onclick = () => selectCons(c, b);
      cg.appendChild(b);
    });
    vowels.forEach((v, i) => {
      const b = document.createElement('button');
      b.className = 'hangul-key ko' + (i === 0 ? ' vow-active' : '');
      b.innerHTML = '<div>' + v + '</div><div class="rom">' + (translitMap[v] || '') + '</div>';
      b.onclick = () => selectVowel(v, b);
      vg.appendChild(b);
    });
    updateHangul();
  }
  function selectCons(c, btn) {
    document.querySelectorAll('.hangul-key.cons-active').forEach(e => e.classList.remove('cons-active'));
    btn.classList.add('cons-active');
    curCons = c;
    updateHangul();
    recordHangulInteraction();
  }
  function selectVowel(v, btn) {
    document.querySelectorAll('.hangul-key.vow-active').forEach(e => e.classList.remove('vow-active'));
    btn.classList.add('vow-active');
    curVowel = v;
    updateHangul();
    recordHangulInteraction();
  }
  function updateHangul() {
    const r = buildSyllable(curCons, curVowel);
    document.getElementById('hangul-result').textContent = r;
    document.getElementById('hangul-translit').textContent = '[ ' + (translitMap[curCons]||'') + (translitMap[curVowel]||'') + ' ]';
    document.getElementById('cons-display').textContent = curCons;
    document.getElementById('vowel-display').textContent = curVowel;
    document.getElementById('result-display').textContent = r;
    document.getElementById('hangul-formula').textContent = curCons + ' + ' + curVowel + ' = ' + r;
  }
  function speakSyllable(btn) {
    const r = document.getElementById('hangul-result').textContent;
    playSyllable(r, btn);
    const el = document.getElementById('hangul-result');
    el.style.transform = 'scale(1.18)';
    el.style.transition = 'transform .25s cubic-bezier(.34,1.56,.64,1)';
    setTimeout(() => el.style.transform = 'scale(1)', 250);
  }
  function resetHangul() {
    initHangulLab();
    curCons = 'ㄱ'; curVowel = 'ㅏ';
    updateHangul();
    const inp = document.getElementById('hangul-word');
    if (inp) inp.value = '';
  }

  // ── Audio (with proper play/pause toggle) ──
  let currentUtter = null;
  let currentBtn   = null;

  function setBtnPlaying(btn, isPlaying) {
    if (!btn) return;
    if (!btn.dataset.original) btn.dataset.original = btn.innerHTML;
    if (isPlaying) {
      // Replace the play icon with pause; keep label intact.
      btn.innerHTML = btn.dataset.original
        .replace(/fa-play/g, 'fa-pause')
        .replace(/(>\s*)Слушать/, '$1Пауза')
        .replace(/(>\s*)Послушать/, '$1Пауза');
      btn.dataset.playing = '1';
    } else {
      btn.innerHTML = btn.dataset.original;
      delete btn.dataset.playing;
    }
  }

  function stopSpeech() {
    try { speechSynthesis.cancel(); } catch (_) {}
    setBtnPlaying(currentBtn, false);
    currentUtter = null;
    currentBtn   = null;
  }

  function playSyllable(text, btn) {
    if (!('speechSynthesis' in window)) { toast('Голос недоступен в этом браузере'); return; }
    if (typeof getSettings === 'function' && !getSettings().sound) { toast('Озвучка выключена в настройках 🔇', 'var(--berry)'); return; }
    // Toggle: tapping the same button while playing -> stop
    if (btn && btn === currentBtn && btn.dataset.playing) { stopSpeech(); return; }
    stopSpeech();
    const u = new SpeechSynthesisUtterance(text);
    u.lang  = 'ko-KR';
    u.rate  = (typeof getSettings === 'function' && getSettings().slowVoice) ? 0.6 : 0.85;
    u.pitch = 1.05;
    u.onend = u.onerror = () => {
      if (currentBtn === btn) { setBtnPlaying(btn, false); currentUtter = null; currentBtn = null; }
    };
    currentUtter = u;
    currentBtn   = btn || null;
    setBtnPlaying(btn, true);
    speechSynthesis.speak(u);
  }

  function playMadieVoice(btn) {
    playSyllable('안녕하세요. 오늘은 화이팅이라는 단어에 대해 이야기해 볼게요.', btn);
  }

  // ── Pronunciation check (Web Speech API · ko-KR) ──
  function pronounceSupported() {
    return !!(window.SpeechRecognition || window.webkitSpeechRecognition);
  }
  function normalizeKo(s) {
    return (s || '').toString().trim().toLowerCase()
      .replace(/[?.!,。、？！'"`]/g, '')
      .replace(/\s+/g, ' ');
  }
  function scoreKoMatch(target, said) {
    if (!target || !said) return 0;
    if (target === said) return 2;                                   // exact
    if (target.includes(said) || said.includes(target)) return 1;    // partial / substring
    // Jaccard on character sets (rough fuzzy fallback)
    const A = new Set([...target]), B = new Set([...said]);
    let inter = 0; A.forEach(c => { if (B.has(c)) inter++; });
    const union = new Set([...A, ...B]).size;
    return (inter / union) >= 0.6 ? 1 : 0;
  }
  function setMicState(btn, state) {
    if (!btn) return;
    btn.classList.remove('mic-listening','mic-ok','mic-near','mic-bad');
    if (state === 'listening') {
      btn.dataset.listening = '1';
      btn.classList.add('mic-listening');
    } else {
      delete btn.dataset.listening;
      if (state === 'ok')   btn.classList.add('mic-ok');
      if (state === 'near') btn.classList.add('mic-near');
      if (state === 'bad')  btn.classList.add('mic-bad');
    }
  }
  function pronounceCheck(targetKo, btn, opts) {
    opts = opts || {};
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { toast('Распознавание речи доступно в Chrome/Edge 🎤'); return; }
    if (btn && btn.dataset.listening === '1') {
      try { btn._rec && btn._rec.abort(); } catch (_) {}
      setMicState(btn, 'idle'); return;
    }
    // Pause TTS so it doesn't bleed into the mic
    try { speechSynthesis.cancel(); } catch (_) {}
    const rec = new SR();
    rec.lang = 'ko-KR';
    rec.interimResults = false;
    rec.maxAlternatives = 3;
    rec.continuous = false;
    setMicState(btn, 'listening');
    if (btn) btn._rec = rec;
    let gotResult = false;
    rec.onresult = (e) => {
      gotResult = true;
      const alts = Array.from(e.results[0]).map(a => (a.transcript || '').trim());
      const target = normalizeKo(targetKo);
      let best = { transcript: alts[0] || '', score: 0 };
      for (const a of alts) {
        const s = scoreKoMatch(target, normalizeKo(a));
        if (s > best.score) best = { transcript: a, score: s };
      }
      finishPronounce(btn, best, targetKo, opts);
    };
    rec.onerror = (e) => {
      setMicState(btn, 'idle');
      if (e.error === 'not-allowed' || e.error === 'service-not-allowed') toast('Разреши доступ к микрофону 🎤');
      else if (e.error === 'no-speech') toast('Не услышала — попробуй ещё 🌸');
      else if (e.error === 'audio-capture') toast('Микрофон не найден');
    };
    rec.onend = () => { if (!gotResult) setMicState(btn, 'idle'); };
    try { rec.start(); } catch (_) { setMicState(btn, 'idle'); }
  }
  function finishPronounce(btn, result, targetKo, opts) {
    const state = result.score === 2 ? 'ok' : result.score === 1 ? 'near' : 'bad';
    setMicState(btn, state);
    stats.pronunciationAttempts = (stats.pronunciationAttempts || 0) + 1;
    if (result.score === 2) {
      stats.pronunciationCorrect = (stats.pronunciationCorrect || 0) + 1;
      stats.pronunciationStreak = (stats.pronunciationStreak || 0) + 1;
      stats.pronunciationBestStreak = Math.max(stats.pronunciationBestStreak || 0, stats.pronunciationStreak);
      addXp(5);
      if (typeof opts.onCorrect === 'function') opts.onCorrect();
    } else {
      stats.pronunciationStreak = 0;
    }
    UStore.set('stats', stats);
    checkAchievements(true);
    const text = result.score === 2
      ? `잘했어! Произношение чёткое 🌸 +5 XP`
      : result.score === 1
        ? `Близко: «${result.transcript}» — попробуй ещё раз`
        : `Услышала: «${result.transcript || '—'}» · попробуй ещё 🌸`;
    const color = result.score === 2 ? 'var(--sage)' : result.score === 1 ? 'var(--gold)' : 'var(--bad-ink)';
    toast(text, color);
    setTimeout(() => setMicState(btn, 'idle'), 2400);
  }

  // ── Toast ──
  function toast(text, color) {
    // Один тост за раз: новый заменяет предыдущий (не стопкой друг на друге)
    document.querySelectorAll('.toast').forEach(el => el.remove());
    const t = document.createElement('div');
    t.className = 'toast';
    if (color) t.style.background = color;
    t.innerHTML = text;
    document.body.appendChild(t);
    setTimeout(() => {
      t.style.transition = 'opacity .3s, transform .3s';
      t.style.opacity = '0';
      t.style.transform = 'translate(-50%, 6px)';
      setTimeout(() => t.remove(), 320);
    }, 1800);
  }

  // ── Password show/hide toggle (uniform across all password fields) ──
  function togglePass(btn) {
    const wrap = btn.closest('.pass-wrap');
    const inp = wrap && wrap.querySelector('input');
    if (!inp) return;
    const showing = inp.type === 'text';
    inp.type = showing ? 'password' : 'text';
    const icon = btn.querySelector('i');
    if (icon) icon.className = showing ? 'fa-solid fa-eye' : 'fa-solid fa-eye-slash';
    btn.setAttribute('aria-label', showing ? 'Показать пароль' : 'Скрыть пароль');
  }

  // ── Hangul Lab: сборка слова из слогов ──
  function addSyllableToWord() {
    const inp = document.getElementById('hangul-word');
    if (!inp) return;
    inp.value += document.getElementById('hangul-result').textContent;
    recordHangulInteraction();
  }
  function backspaceWord() {
    const inp = document.getElementById('hangul-word');
    if (inp) inp.value = inp.value.slice(0, -1);
  }
  function saveHangulWord() {
    const inp = document.getElementById('hangul-word');
    const word = (inp ? inp.value : '').trim();
    if (!word) { toast('Сначала собери или впиши слово 🌸'); return; }
    const added = saveMyWord(word, '', '', '🌸', 'hangul');
    if (!added) { toast('Это слово уже сохранено 🌸'); return; }
    if (inp) inp.value = '';
    toast('🌸 «' + word + '» сохранено в словарик');
    recordHangulSave();
    renderSavedWords();
  }
  // ── My Words (personal vocab) ──
  // Unified storage for words user wants to remember — from Hangul Lab, flashcards,
  // game word pool, lessons. Migrates old "hangulWords" format on first read.
  function getMyWords() {
    let list = UStore.get('myWords', null);
    if (!Array.isArray(list)) {
      // Migrate legacy hangulWords storage (ko-only, no translation)
      const legacy = UStore.get('hangulWords', []);
      list = legacy.map(w => ({ ko: w.ko, ru: '', translit: '', emoji: '🌸', source: 'hangul', ts: w.ts || Date.now() }));
      UStore.set('myWords', list);
    }
    return list;
  }
  function saveMyWord(ko, ru, translit, emoji, source) {
    if (!ko) return false;
    const list = getMyWords();
    const idx = list.findIndex(w => w.ko === ko);
    if (idx >= 0) {
      // Already saved — backfill missing fields if we have richer data now
      if (ru && !list[idx].ru) list[idx].ru = ru;
      if (translit && !list[idx].translit) list[idx].translit = translit;
      if (emoji && list[idx].emoji === '🌸') list[idx].emoji = emoji;
      UStore.set('myWords', list);
      return false; // not newly added
    }
    list.unshift({ ko, ru: ru || '', translit: translit || '', emoji: emoji || '🌸', source: source || 'manual', ts: Date.now() });
    UStore.set('myWords', list);
    recordWordSeen(ko);
    return true;
  }
  function removeMyWord(ko) {
    const list = getMyWords().filter(w => w.ko !== ko);
    UStore.set('myWords', list);
    renderSavedWords();
  }
  function isMyWord(ko) {
    return getMyWords().some(w => w.ko === ko);
  }
  function toggleMyWord(ko, ru, translit, emoji, source, btn) {
    if (isMyWord(ko)) {
      removeMyWord(ko);
      toast(`«${ko}» удалено из словарика`);
    } else {
      saveMyWord(ko, ru, translit, emoji, source);
      toast(`🌸 «${ko}» сохранено в словарик`, 'var(--sage)');
    }
    // Re-paint button if provided
    if (btn) {
      const saved = isMyWord(ko);
      btn.innerHTML = saved
        ? '<i class="fa-solid fa-heart" style="color:var(--coral);"></i>'
        : '<i class="fa-regular fa-heart"></i>';
    }
    renderSavedWords();
  }

  // My Words view state (search / sort / multi-select)
  let _wordsQuery = '';
  let _wordsSort = 'recent';        // 'recent' | 'alpha'
  let _wordsSelected = new Set();   // ko of words ticked for "study selected"

  function renderSavedWords() {
    const list = getMyWords();
    // Keep the profile entry's subtitle in sync (it links to this full screen).
    const countEl = document.getElementById('profile-words-count');
    if (countEl) {
      const n = list.length;
      const wf = (n % 10 === 1 && n % 100 !== 11) ? 'слово'
        : ([2,3,4].includes(n % 10) && ![12,13,14].includes(n % 100)) ? 'слова' : 'слов';
      countEl.textContent = n ? `${n} ${wf} в словарике` : 'Личный словарик';
    }
    const slot = document.getElementById('saved-words-list');
    if (!slot) return;
    if (!list.length) {
      _wordsSelected.clear();
      slot.innerHTML = `<div style="font-size:11.5px; color:var(--soft); text-align:center; padding:14px; font-style:italic;">Пока пусто. Сохрани слово ♡ из карточек или 한글 Lab 🌸</div>`;
      return;
    }
    // Controls (search + sort) are rendered once here; the list re-renders separately
    // so typing in search doesn't recreate (and unfocus) the input.
    slot.innerHTML = `
      <div class="words-controls">
        <div class="words-search">
          <i class="fa-solid fa-magnifying-glass" aria-hidden="true"></i>
          <input id="words-search-input" type="search" placeholder="Поиск слова…" value="${escAttrSafe(_wordsQuery)}" oninput="onWordsSearch(this.value)" aria-label="Поиск по словарику">
        </div>
        <div class="words-sort">
          <button type="button" class="words-sort-btn ${_wordsSort==='recent'?'active':''}" onclick="setWordsSort('recent')">Новые</button>
          <button type="button" class="words-sort-btn ${_wordsSort==='alpha'?'active':''}" onclick="setWordsSort('alpha')">А-Я</button>
        </div>
      </div>
      <div id="saved-words-actionbar" style="display:flex; justify-content:space-between; align-items:center; gap:10px; margin:10px 2px;"></div>
      <div id="saved-words-items" style="display:grid; gap:6px;"></div>`;
    renderSavedWordsItems();
  }

  function renderSavedWordsItems() {
    const itemsSlot = document.getElementById('saved-words-items');
    if (!itemsSlot) return;
    const list = getMyWords();
    // Drop any selected words that no longer exist.
    const koSet = new Set(list.map(w => w.ko));
    [..._wordsSelected].forEach(k => { if (!koSet.has(k)) _wordsSelected.delete(k); });
    const q = _wordsQuery.trim().toLowerCase();
    let filtered = q
      ? list.filter(w => String(w.ko).toLowerCase().includes(q)
                      || String(w.ru || '').toLowerCase().includes(q)
                      || String(w.translit || '').toLowerCase().includes(q))
      : list.slice();
    if (_wordsSort === 'alpha') filtered.sort((a, b) => String(a.ko).localeCompare(String(b.ko), 'ko'));
    else filtered.sort((a, b) => (b.ts || 0) - (a.ts || 0));

    const selN = _wordsSelected.size;
    const bar = document.getElementById('saved-words-actionbar');
    if (bar) {
      const studyAction = selN > 0 ? 'studySelectedWords()' : 'startMyWordsFlashcards()';
      const studyLabel  = selN > 0 ? `Учить выбранные (${selN})` : `Учить все (${list.length})`;
      bar.innerHTML = `
        <div style="font-size:10.5px; color:var(--soft); min-width:0;">
          ${q ? `Найдено: <b style="color:var(--coral);">${filtered.length}</b>` : `Всего: <b style="color:var(--coral);">${list.length}</b>`}
          ${selN > 0 ? ` · выбрано ${selN} <button type="button" onclick="clearWordSelection()" style="background:none; border:none; color:var(--coral); cursor:pointer; font-size:10.5px; text-decoration:underline; padding:0 0 0 4px;">сбросить</button>` : ''}
        </div>
        ${list.length >= 2 ? `<button type="button" onclick="${studyAction}" class="btn btn-primary" style="padding:7px 14px; font-size:11.5px; flex-shrink:0;"><i class="fa-solid fa-graduation-cap" style="font-size:10px;" aria-hidden="true"></i> ${studyLabel}</button>` : ''}`;
    }

    if (!filtered.length) {
      itemsSlot.innerHTML = `<div style="font-size:11.5px; color:var(--soft); text-align:center; padding:14px; font-style:italic;">Ничего не найдено по «${escHtml(_wordsQuery)}» 🌸</div>`;
      return;
    }
    itemsSlot.innerHTML = filtered.map(w => {
      const koEsc = String(w.ko).replace(/'/g, "\\'");
      const sel = _wordsSelected.has(w.ko);
      return `<div class="word-row ${sel ? 'selected' : ''}">
        <label class="word-check" aria-label="Выбрать слово"><input type="checkbox" ${sel ? 'checked' : ''} onchange="toggleWordSelect('${koEsc}', this.checked)"></label>
        <span style="font-size:18px; flex-shrink:0;">${w.emoji || '🌸'}</span>
        <div style="flex:1; min-width:0; cursor:pointer;" onclick="playSyllable('${koEsc}', this)">
          <div class="ko" style="font-size:16px; font-weight:700; color:var(--berry); line-height:1.2;">${escHtml(w.ko)}</div>
          ${w.ru || w.translit ? `<div style="font-size:11px; color:var(--soft); margin-top:1px;">${w.translit ? `[${escHtml(w.translit)}] · ` : ''}${escHtml(w.ru || '')}</div>` : ''}
        </div>
        <button onclick="removeMyWord('${koEsc}')" aria-label="Удалить" style="background:none; border:none; color:var(--soft); cursor:pointer; font-size:18px; line-height:1; padding:4px 6px; flex-shrink:0;">×</button>
      </div>`;
    }).join('');
  }

  function onWordsSearch(v) { _wordsQuery = v || ''; renderSavedWordsItems(); }
  function setWordsSort(s) { _wordsSort = s; renderSavedWords(); }
  function toggleWordSelect(ko, checked) { if (checked) _wordsSelected.add(ko); else _wordsSelected.delete(ko); renderSavedWordsItems(); }
  function clearWordSelection() { _wordsSelected.clear(); renderSavedWordsItems(); }
  function studySelectedWords() {
    const list = getMyWords().filter(w => _wordsSelected.has(w.ko));
    if (!list.length) { toast('Выбери хотя бы одно слово 🌸'); return; }
    fcReplayFn = studySelectedWords;
    startFlashcardSession(list.map(w => ({
      front: w.ko, translit: w.translit || '', emoji: w.emoji || '🌸', meaning: w.ru || w.ko, example: ''
    })));
  }

  function startMyWordsFlashcards() {
    const list = getMyWords();
    if (!list.length) { toast('Сначала сохрани несколько слов 🌸'); return; }
    // Build flashcard session from saved words. Words without ru get ko as fallback meaning.
    fcReplayFn = startMyWordsFlashcards;
    startFlashcardSession(list.map(w => ({
      front: w.ko,
      translit: w.translit || '',
      emoji: w.emoji || '🌸',
      meaning: w.ru || w.ko,
      example: ''
    })));
  }


  // ── Modals ──
  // ── Korean holidays 2026 (fixed + lunar approximations) ──
  const koreanHolidays = {
    '01-01': { ko: '신정',           ru: 'Новый год',           emoji: '🎊' },
    '02-16': { ko: '설날 연휴',       ru: 'Канун Соллаль',        emoji: '🥮' },
    '02-17': { ko: '설날',           ru: 'Соллаль · Лунный НГ',   emoji: '🥟' },
    '02-18': { ko: '설날 연휴',       ru: 'После Соллаль',        emoji: '🍵' },
    '03-01': { ko: '삼일절',          ru: 'День независимости',   emoji: '🇰🇷' },
    '04-05': { ko: '식목일',          ru: 'День посадки деревьев', emoji: '🌳' },
    '05-05': { ko: '어린이날',        ru: 'День детей',            emoji: '🎏' },
    '05-08': { ko: '어버이날',        ru: 'День родителей',        emoji: '🌷' },
    '05-15': { ko: '스승의 날',        ru: 'День учителя',          emoji: '🌸' },
    '05-24': { ko: '부처님 오신 날',   ru: 'Рождение Будды',         emoji: '🪷' },
    '06-06': { ko: '현충일',          ru: 'День памяти',           emoji: '🕊️' },
    '07-17': { ko: '제헌절',          ru: 'День Конституции',      emoji: '📜' },
    '08-15': { ko: '광복절',          ru: 'День освобождения',     emoji: '🎆' },
    '09-24': { ko: '추석 연휴',       ru: 'Канун Чхусок',          emoji: '🌾' },
    '09-25': { ko: '추석',            ru: 'Чхусок · Урожай',        emoji: '🌕' },
    '09-26': { ko: '추석 연휴',       ru: 'После Чхусок',          emoji: '🍶' },
    '10-03': { ko: '개천절',          ru: 'День основания',        emoji: '🏔️' },
    '10-09': { ko: '한글날',          ru: 'День хангыля',          emoji: '한' },
    '11-11': { ko: '빼빼로 데이',      ru: 'День Пеппеpo',          emoji: '🥢' },
    '12-25': { ko: '성탄절',          ru: 'Рождество',             emoji: '🎄' },
    '12-31': { ko: '제야',            ru: 'Канун Нового года',    emoji: '🔔' }
  };
  const monthsRu = ['Январь','Февраль','Март','Апрель','Май','Июнь','Июль','Август','Сентябрь','Октябрь','Ноябрь','Декабрь'];
  const monthsKo = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
  const weekdaysRu = ['Пн','Вт','Ср','Чт','Пт','Сб','Вс'];
  const weekdaysRuLong = ['воскресенье','понедельник','вторник','среда','четверг','пятница','суббота'];
  const _now = new Date();
  const TODAY = { y: _now.getFullYear(), m: _now.getMonth(), d: _now.getDate() };

  let calMonth = TODAY.m, calYear = TODAY.y;

  // ── Russian plural for "день/дня/дней" ──
  function pluralDays(n) {
    const m100 = n % 100, m10 = n % 10;
    if (m100 >= 11 && m100 <= 14) return 'дней';
    if (m10 === 1) return 'день';
    if (m10 >= 2 && m10 <= 4) return 'дня';
    return 'дней';
  }
  function untilLabel(diff) {
    if (diff === 0) return 'СЕГОДНЯ';
    if (diff === 1) return 'ЗАВТРА';
    return `ЧЕРЕЗ ${diff} ${pluralDays(diff).toUpperCase()}`;
  }

  // ── Compute upcoming holidays from TODAY ──
  function computeUpcoming(limit) {
    const todayDate = new Date(TODAY.y, TODAY.m, TODAY.d);
    return Object.entries(koreanHolidays).map(([key, h]) => {
      const [mm, dd] = key.split('-').map(n => parseInt(n, 10));
      const date = new Date(TODAY.y, mm - 1, dd);
      const diff = Math.round((date - todayDate) / 86400000);
      return { key, h, mm, dd, diff };
    })
    .filter(x => x.diff >= 0)
    .sort((a, b) => a.diff - b.diff)
    .slice(0, limit);
  }

  // ── Заполняем баннер «Сегодня в Корее» ближайшим праздником ──
  function renderCultureBanner() {
    let next = computeUpcoming(1)[0];
    if (!next) {
      // Все праздники года позади — берём первый праздник следующего года
      const first = Object.entries(koreanHolidays)
        .map(([key, h]) => { const [mm, dd] = key.split('-').map(n => parseInt(n, 10)); return { h, mm, dd }; })
        .sort((a, b) => (a.mm - b.mm) || (a.dd - b.dd))[0];
      if (first) next = { ...first, diff: -1 };
    }
    if (!next) return;
    const { h, mm, dd, diff } = next;
    const emojiEl = document.getElementById('culture-emoji');
    const dateEl  = document.getElementById('culture-date');
    const titleEl = document.getElementById('culture-title');
    const labelEl = document.getElementById('culture-label');
    if (labelEl) labelEl.textContent = diff === 0 ? 'СЕГОДНЯ В КОРЕЕ' : 'БЛИЖАЙШИЙ ПРАЗДНИК КОРЕИ';
    if (emojiEl) emojiEl.textContent = h.emoji;
    if (dateEl)  dateEl.textContent  = diff === 0 ? 'СЕГОДНЯ'
                                     : diff >= 1  ? untilLabel(diff)
                                     : `${dd}.${String(mm).padStart(2, '0')}`;
    if (titleEl) titleEl.textContent = `${h.ko} — ${h.ru}`;
  }

  function showCalendar() {
    recordCalendarOpen();
    calMonth = TODAY.m; calYear = TODAY.y;
    const upcoming = computeUpcoming(4);
    const nearest = upcoming.find(u => u.diff > 0);
    const nearestLine = nearest
      ? `Скоро <span class="ko">${nearest.h.ko}</span> ${nearest.h.emoji} — ${untilLabel(nearest.diff).toLowerCase()}`
      : 'Праздников впереди пока нет 🌸';

    const upcomingCards = upcoming.map(u => {
      const todayMark = u.diff === 0;
      return `
        <div onclick="showHolidayInfo('${u.key}')" class="card card-press" style="padding:12px 12px 10px;">
          <div style="display:flex; justify-content:space-between; align-items:flex-start; gap:8px;">
            <span style="font-size:22px; line-height:1;">${u.h.emoji}</span>
            ${todayMark ? '<span class="chip chip-coral" style="font-size:8px; padding:2px 7px;">СЕГОДНЯ</span>' : ''}
          </div>
          <div class="ko" style="font-weight:700; color:var(--berry); margin-top:8px; font-size:14px; line-height:1.15;">${u.h.ko}</div>
          <div style="font-size:11px; color:var(--soft); margin-top:1px; line-height:1.3;">${u.h.ru}</div>
          <div style="display:flex; justify-content:space-between; align-items:flex-end; margin-top:10px; gap:6px;">
            <span style="font-size:8.5px; color:var(--coral); font-weight:600; letter-spacing:.08em;">${untilLabel(u.diff)}</span>
            <span style="font-size:12.5px; font-weight:700; color:var(--berry); white-space:nowrap;">${u.dd} ${monthsRu[u.mm-1].toLowerCase().slice(0,3)}</span>
          </div>
        </div>
      `;
    }).join('');

    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-sheet cal-sheet" style="border-radius: 28px; margin: 0 16px;">
        <div style="padding: 22px 18px 20px;">
          <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom: 14px;">
            <div>
              <div class="page-eyebrow">한국 달력 · КАЛЕНДАРЬ</div>
              <div class="display" style="font-size:20px; color:var(--berry); margin-top:2px;">2026</div>
              <div style="font-size:11px; color: var(--soft); margin-top:2px;">12 месяцев · ${Object.keys(koreanHolidays).length} праздников</div>
            </div>
            <div onclick="this.closest('.modal-bg').remove()" style="font-size:26px; line-height:1; color:var(--soft); cursor:pointer; padding:4px;">×</div>
          </div>

          <!-- Today card -->
          <div class="card card-padded" style="background: linear-gradient(135deg, var(--coral), var(--rose)); color:white; border:none; margin-bottom:16px;">
            <span class="chip" style="background:rgba(255,255,255,.28); color:white;">СЕГОДНЯ</span>
            <div class="ko" style="font-weight:700; font-size:18px; margin-top:8px;">${TODAY.m+1}월 ${TODAY.d}일</div>
            <div style="font-size:13px;">${TODAY.d} ${monthsRu[TODAY.m].toLowerCase()} · ${weekdaysRuLong[new Date(TODAY.y, TODAY.m, TODAY.d).getDay()]}</div>
            <div style="font-size:11.5px; opacity:.9; margin-top:6px;">${nearestLine}</div>
          </div>

          <!-- Upcoming holidays (top block) -->
          <div class="section-head">
            <div class="left"><div class="rule"></div><span class="title">Скоро</span></div>
            <span class="meta">ближайшие праздники</span>
          </div>
          <div style="display:grid; grid-template-columns: 1fr 1fr; gap:10px; margin-bottom:18px;">
            ${upcomingCards}
          </div>

          <!-- Month switcher -->
          <div class="section-head">
            <div class="left"><div class="rule"></div><span class="title">Календарь</span></div>
            <span class="meta">все 12 месяцев</span>
          </div>
          <div style="display:flex; align-items:center; justify-content:space-between; margin-bottom:14px; gap:10px;">
            <button onclick="changeMonth(-1)" class="btn btn-ghost" style="padding:10px 14px; min-width:auto;"><i class="fa-solid fa-chevron-left" style="font-size:11px;"></i></button>
            <div style="text-align:center; flex:1;">
              <div class="display" id="cal-month-ru" style="font-size:18px; color:var(--berry); line-height:1.1;">Май</div>
              <div class="ko" id="cal-month-ko" style="font-size:11px; color:var(--coral); margin-top:2px; letter-spacing:.08em;">5월</div>
            </div>
            <button onclick="changeMonth(1)" class="btn btn-ghost" style="padding:10px 14px; min-width:auto;"><i class="fa-solid fa-chevron-right" style="font-size:11px;"></i></button>
          </div>

          <!-- Weekday header -->
          <div style="display:grid; grid-template-columns:repeat(7,1fr); gap:2px; margin-bottom:4px;">
            ${weekdaysRu.map((d,i) => `<div style="font-size:10px; color:${i>=5?'var(--coral)':'var(--soft)'}; padding:6px 0; text-align:center; font-weight:600; letter-spacing:.06em;">${d}</div>`).join('')}
          </div>

          <!-- Date grid -->
          <div id="cal-grid" style="display:grid; grid-template-columns:repeat(7,1fr); gap:3px;"></div>

          <!-- Legend -->
          <div style="display:flex; gap:14px; justify-content:center; margin-top:14px; font-size:10px; color:var(--soft);">
            <span style="display:inline-flex; align-items:center; gap:5px;"><span style="width:8px; height:8px; border-radius:50%; background:var(--grad-coral);"></span> сегодня</span>
            <span style="display:inline-flex; align-items:center; gap:5px;"><span style="width:6px; height:6px; border-radius:50%; background:var(--gold);"></span> праздник</span>
            <span style="display:inline-flex; align-items:center; gap:5px;"><span style="width:6px; height:6px; border-radius:50%; background:var(--rose);"></span> выходной</span>
          </div>

          <!-- Holiday list of month -->
          <div id="cal-holidays-wrap" style="margin-top:18px;">
            <div class="section-head">
              <div class="left"><div class="rule"></div><span class="title">Праздники месяца</span></div>
            </div>
            <div id="cal-holidays" style="display:grid; gap:8px;"></div>
          </div>
        </div>
      </div>
    `;
    document.body.appendChild(m);
    renderCalendarMonth();
  }

  function changeMonth(delta) {
    calMonth += delta;
    if (calMonth < 0) { calMonth = 11; calYear--; }
    else if (calMonth > 11) { calMonth = 0; calYear++; }
    renderCalendarMonth();
  }

  function renderCalendarMonth() {
    const headRu = document.getElementById('cal-month-ru');
    const headKo = document.getElementById('cal-month-ko');
    const grid   = document.getElementById('cal-grid');
    const list   = document.getElementById('cal-holidays');
    if (!grid) return;
    headRu.textContent = `${monthsRu[calMonth]} ${calYear}`;
    headKo.textContent = monthsKo[calMonth];

    const daysInMonth = new Date(calYear, calMonth + 1, 0).getDate();
    const firstDow = (new Date(calYear, calMonth, 1).getDay() + 6) % 7; // Mon=0..Sun=6

    let html = '';
    for (let i = 0; i < firstDow; i++) html += '<div></div>';
    for (let d = 1; d <= daysInMonth; d++) {
      const key = `${String(calMonth+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
      const h = koreanHolidays[key];
      const wd = (firstDow + d - 1) % 7;
      const isWeekend = wd >= 5;
      const isToday = (calYear === TODAY.y && calMonth === TODAY.m && d === TODAY.d);

      let style = 'position:relative; aspect-ratio:1; display:flex; align-items:center; justify-content:center; font-size:13px; font-weight:500; border-radius:10px; transition:transform .15s var(--ease-out), background .15s ease;';
      let dot = '';
      let onclick = '';

      if (isToday) {
        style += ' background:var(--grad-coral); color:white; font-weight:700; box-shadow:0 4px 12px -4px rgba(var(--accent-rgb),.55), inset 0 1px 0 rgba(255,255,255,.3);';
      } else if (h) {
        style += ' background:linear-gradient(140deg, rgba(201,165,92,.18), rgba(201,165,92,.08)); color:var(--gold-ink); font-weight:600; cursor:pointer;';
        dot = `<div style="position:absolute; bottom:3px; left:50%; transform:translateX(-50%); width:4px; height:4px; border-radius:50%; background:var(--gold);"></div>`;
        onclick = `onclick="showHolidayInfo('${key}')"`;
      } else if (isWeekend) {
        style += ' color:var(--rose);';
      } else {
        style += ' color:var(--berry);';
      }

      html += `<div ${onclick} style="${style}">${d}${dot}</div>`;
    }
    grid.innerHTML = html;

    // Holiday list for this month
    const monthHolidays = Object.entries(koreanHolidays)
      .filter(([k]) => k.startsWith(String(calMonth+1).padStart(2,'0') + '-'))
      .sort(([a],[b]) => a.localeCompare(b));
    if (monthHolidays.length === 0) {
      list.innerHTML = `<div style="text-align:center; font-size:11.5px; color:var(--soft); padding:14px 0; font-style:italic;">В этом месяце праздников нет 🌸</div>`;
    } else {
      list.innerHTML = monthHolidays.map(([key, h]) => {
        const day = parseInt(key.split('-')[1], 10);
        const isToday = (calYear === TODAY.y && calMonth === TODAY.m && day === TODAY.d);
        return `
          <div onclick="showHolidayInfo('${key}')" class="card card-press" style="display:flex; gap:12px; align-items:center; padding:12px 14px;">
            <div style="width:38px; height:38px; flex-shrink:0; border-radius:12px; background:linear-gradient(140deg, var(--blush), var(--paper)); display:flex; align-items:center; justify-content:center; font-size:20px;">${h.emoji}</div>
            <div style="flex:1; min-width:0;">
              <div class="ko" style="font-weight:700; color:var(--berry); font-size:13.5px;">${h.ko}</div>
              <div style="font-size:11px; color:var(--soft); margin-top:1px;">${h.ru}</div>
            </div>
            <div style="text-align:right; flex-shrink:0;">
              <div style="font-size:13px; font-weight:700; color:${isToday?'var(--coral)':'var(--berry)'};">${day} ${monthsRu[calMonth].toLowerCase().slice(0,3)}</div>
              ${isToday ? '<div style="font-size:9px; color:var(--coral); font-weight:600; letter-spacing:.1em;">СЕГОДНЯ</div>' : ''}
            </div>
          </div>
        `;
      }).join('');
    }
  }

  function showHolidayInfo(key) {
    const h = koreanHolidays[key];
    if (!h) return;
    const [mm, dd] = key.split('-').map(n => parseInt(n,10));
    toast(`${h.emoji} <span class="ko">${h.ko}</span> · ${h.ru} — ${dd} ${monthsRu[mm-1].toLowerCase()}`);
  }

  function showCultureDetail() {
    recordCultureOpen();
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card">
        <div style="display:flex; justify-content:space-between; align-items:flex-start;">
          <div>
            <div style="font-size:28px;">🎎</div>
            <div class="display" style="font-size:22px; color:var(--berry); margin-top:6px;">정 (jeong)</div>
            <div style="color: var(--coral); font-size: 12px; margin-top:2px;">Непереводимое корейское слово</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:28px; line-height:1; color:var(--soft); cursor:pointer; padding:4px;">×</div>
        </div>
        <div style="font-size:13.5px; color:var(--text2); line-height:1.55; margin-top:18px; display:grid; gap: 10px;">
          <p><span class="ko" style="font-weight:600;">정</span> — это глубокая привязанность и тёплая связь между людьми, которая <em>растёт со временем</em>.</p>
          <p>Нельзя перевести одним русским словом: это и любовь, и дружба, и привычка, и тоска по близкому человеку.</p>
          <p class="ko" style="color:var(--coral); font-style:italic;">«정이 들었어» — «Я привязалась к тебе всей душой»</p>
        </div>
        <div class="ko-quote" style="margin-top: 16px; font-size: 12px;">
          💡 Корейцы говорят, что 정 может возникнуть даже с местом или едой — не только с людьми.
        </div>
      </div>
    `;
    document.body.appendChild(m);
  }

  // ── Lesson flow (слайдовый, по презентации) ──
  let lessonStage = 0;
  let lessonViewId = null; // админ: открыть конкретный урок мимо прогресса
  function startLessonFlow(id, fromStart) { lessonViewId = id || null; lessonStage = fromStart ? 0 : (id ? getLessonStage(id) : 0); renderLesson(); }
  function lessonSlides() {
    const l = getCurrentLesson();
    return (l && Array.isArray(l.slides)) ? l.slides : [];
  }
  function renderLesson() {
    const lesson = getCurrentLesson();
    // Reuse existing page element so the slide-in animation doesn't replay on each step
    let m = document.getElementById('lesson-modal');
    const isNew = !m;
    if (isNew) {
      m = document.createElement('div');
      m.className = 'lesson-page';
      m.id = 'lesson-modal';
      document.body.appendChild(m);
      document.body.classList.add('lesson-open');
    }
    if (!lesson) {
      m.innerHTML = `
        <div class="lesson-page-body" style="text-align:center; justify-content:center;">
          <div style="font-size:64px;">🎉</div>
          <div class="display" style="font-size:28px; color:var(--berry); margin-top:14px;">Все уроки пройдены</div>
          <div style="font-size:13px; color:var(--soft); margin-top:8px;">Ждём новых уроков от Мади 🌸</div>
          <button onclick="closeLessonFlow()" class="btn btn-primary" style="margin-top:24px; max-width:280px;">Закрыть</button>
        </div>`;
      return;
    }
    const slides = lesson.slides || [];
    const total = slides.length + 1;
    lessonStage = Math.max(0, Math.min(lessonStage, total - 1));
    const isDone = lessonStage >= slides.length;
    const slide = isDone ? { kind:'done' } : slides[lessonStage];
    const body = renderLessonSlide(lesson, slide);
    const segs = Array.from({length: total}, (_,j) =>
      `<span style="flex:1; height:3px; border-radius:999px; background:${j<=lessonStage?'var(--coral)':'rgba(var(--rose-rgb),.3)'};"></span>`).join('');
    // If page already exists, update only header + body so the wrapper isn't recreated
    let header = m.querySelector('.lesson-page-header');
    let bodyEl = m.querySelector('.lesson-page-body');
    if (!header || !bodyEl) {
      m.innerHTML = `
        <div class="lesson-page-header">
          <button onclick="closeLessonFlow()" aria-label="Закрыть" style="background:none; border:none; font-size:24px; color:var(--soft); cursor:pointer; line-height:1; padding:4px 8px;">×</button>
          <div class="lesson-segs" style="display:flex; gap:4px; flex:1;">${segs}</div>
          <div class="lesson-counter" style="font-size:11px; color: var(--soft); white-space:nowrap;">${lessonStage+1} / ${total}</div>
        </div>
        <div class="lesson-page-body">${body}</div>
      `;
    } else {
      const segsHost = header.querySelector('.lesson-segs');
      const counter  = header.querySelector('.lesson-counter');
      if (segsHost) segsHost.innerHTML = segs;
      if (counter)  counter.textContent = `${lessonStage+1} / ${total}`;
      bodyEl.innerHTML = body;
      bodyEl.scrollTop = 0;
    }
  }
  // ── Homework (общий блок: урок + профиль) ──
  function homeworkBodyHtml(lesson) {
    const hw = (lesson && lesson.homework) || {};
    const tasks = Array.isArray(hw.tasks) ? hw.tasks : [];
    const words = Array.isArray(lesson && lesson.vocab) ? lesson.vocab : [];
    const file = hw.file;
    const taskHtml = tasks.map((t,i) => `
      <div class="card card-padded" style="display:flex; gap:12px; align-items:flex-start;">
        <div style="width:26px; height:26px; flex-shrink:0; border-radius:50%; background:var(--blush); color:var(--berry); font-weight:700; display:flex; align-items:center; justify-content:center; font-size:13px;">${i+1}</div>
        <p style="font-size:12.5px; color:var(--berry); line-height:1.5;">${t}</p>
      </div>`).join('');
    const wordsHtml = words.map(w => `
      <div style="display:flex; align-items:center; gap:8px; padding:8px 10px; background:var(--card); border:1px solid var(--line); border-radius:12px;">
        <span class="ko" style="font-size:17px; font-weight:700; color:var(--berry); flex-shrink:0;">${w.ko}</span>
        <span style="font-size:11px; color:var(--soft); line-height:1.25;">${w.ru}</span>
      </div>`).join('');
    const fileHtml = file ? `
      <div style="font-size:10px; letter-spacing:.18em; color:var(--soft); margin:18px 0 8px;">МАТЕРИАЛЫ</div>
      <div class="card card-padded" style="display:flex; align-items:center; gap:12px;">
        <div style="width:42px; height:42px; flex-shrink:0; border-radius:12px; background:rgba(201,165,92,.15); display:flex; align-items:center; justify-content:center; font-size:20px;">📄</div>
        <div style="flex:1; min-width:0;">
          <div style="font-weight:600; color:var(--berry); font-size:12.5px;">${file.label}</div>
          <div style="font-size:10.5px; color:var(--soft); margin-top:1px;">${file.note || ''}</div>
        </div>
        ${file.url
          ? `<a href="${file.url}" download class="btn btn-primary" style="flex-shrink:0; padding:9px 14px; font-size:12px;"><i class="fa-solid fa-download"></i> Скачать</a>`
          : `<button onclick="toast('Файл скоро добавим 🌸')" class="btn btn-ghost" style="flex-shrink:0; padding:9px 14px; font-size:12px;"><i class="fa-solid fa-download"></i> Скоро</button>`}
      </div>` : '';
    return `
      <div style="display:grid; gap:10px;">${taskHtml}</div>
      ${words.length ? `
        <div style="font-size:10px; letter-spacing:.18em; color:var(--soft); margin:18px 0 8px;">СЛОВА ДЛЯ ЗАУЧИВАНИЯ · ${words.length}</div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:6px;">${wordsHtml}</div>` : ''}
      ${fileHtml}
    `;
  }
  function openHomework(lessonId) {
    const lesson = getAllLessons().find(l => l.id === lessonId);
    if (!lesson) { toast('Урок не найден 🌸'); return; }
    // Студенты получают доступ к домашке только после прохождения урока.
    if (!isAdmin()) {
      const progress = getLessonProgress();
      if (!progress.completed.includes(lessonId)) {
        toast('Сначала пройди урок — потом откроется домашка 🌸', 'var(--coral)');
        return;
      }
    }
    const m = document.createElement('div');
    m.className = 'modal-bg';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-sheet" style="height: 90vh;">
        <div style="padding: 18px 20px; border-bottom: 1px solid var(--line); display:flex; align-items:center; justify-content:space-between; gap:14px; position:sticky; top:0; background: var(--cream); z-index:1;">
          <div style="min-width:0;">
            <div class="page-eyebrow">УРОК ${lesson.num} · ${lesson.title}</div>
            <div class="display" style="font-size:19px; color:var(--berry); margin-top:2px;">Домашнее задание</div>
          </div>
          <button onclick="this.closest('.modal-bg').remove()" style="background:none; border:none; font-size:22px; color:var(--soft); cursor:pointer; line-height:1;">×</button>
        </div>
        <div style="padding: 22px 20px 32px;">
          ${homeworkBodyHtml(lesson)}
          <button onclick="this.closest('.modal-bg').remove()" class="btn btn-primary btn-block" style="margin-top:20px;">Понятно ✓</button>
        </div>
      </div>`;
    document.body.appendChild(m);
  }
  function renderHomeworkList() {
    const slot = document.getElementById('homework-list');
    if (!slot) return;
    if (!LESSON_CATALOG.length) {
      slot.innerHTML = `<div style="font-size:12px; color:var(--soft); text-align:center; padding:14px;">Уроков пока нет 🌸</div>`;
      return;
    }
    const admin = isAdmin();
    const progress = getLessonProgress();
    const completed = new Set(progress.completed || []);
    slot.innerHTML = LESSON_CATALOG.map(l => {
      const isDone = admin || completed.has(l.id);
      const tasks = (l.homework && l.homework.tasks ? l.homework.tasks.length : 0);
      const words = Array.isArray(l.vocab) ? l.vocab.length : 0;
      if (isDone) {
        return `
          <div class="card card-padded card-press" onclick="openHomework('${l.id}')" style="display:flex; align-items:center; gap:12px; cursor:pointer; margin-bottom:10px;">
            <div style="width:38px; height:38px; flex-shrink:0; border-radius:12px; background:var(--blush); display:flex; align-items:center; justify-content:center; font-size:18px;">📒</div>
            <div style="flex:1; min-width:0;">
              <div style="font-weight:600; color:var(--berry); font-size:13px;">Урок ${l.num} · ${l.title}</div>
              <div style="font-size:10.5px; color:var(--soft); margin-top:1px;">${tasks} задания · ${words} слов</div>
            </div>
            <span class="chip chip-coral" style="flex-shrink:0; font-size:10px;">Открыть →</span>
          </div>`;
      }
      // Locked card — visually muted, no click handler
      return `
        <div class="card card-padded" style="display:flex; align-items:center; gap:12px; margin-bottom:10px; border-style:dashed; background:var(--card); cursor:not-allowed;">
          <div style="width:38px; height:38px; flex-shrink:0; border-radius:12px; background:var(--veil); display:flex; align-items:center; justify-content:center; font-size:14px; color:var(--hush);"><i class="fa-solid fa-lock"></i></div>
          <div style="flex:1; min-width:0; opacity:.55;">
            <div style="font-weight:500; color:var(--berry); font-size:13px;">Урок ${l.num} · ${l.title}</div>
            <div style="font-size:10.5px; color:var(--soft); margin-top:1px;">Откроется после прохождения урока</div>
          </div>
          <span class="chip" style="flex-shrink:0; font-size:10px; background:var(--veil); color:var(--soft);">🔒</span>
        </div>`;
    }).join('');
  }
  function lessonNav(nextLabel, lockNext) {
    return `
      <div style="display:flex; gap:10px; margin-top:22px;">
        <button onclick="prevLesson()" class="btn btn-ghost" style="flex:1;">← Назад</button>
        <button ${lockNext ? 'id="quiz-next-btn" disabled' : ''} onclick="nextLesson()" class="btn btn-primary" style="flex:1.6;${lockNext ? ' opacity:.45; pointer-events:none;' : ''}">${nextLabel}</button>
      </div>`;
  }
  // Кнопка быстрого сохранения слова/фразы/грамматики в личный словарик.
  // Иконка отражает текущее состояние; toggleMyWord перерисовывает её при клике.
  // event.stopPropagation — чтобы не сработал onclick карточки (озвучка).
  function lessonSaveHeart(ko, ru, translit, emoji, source, cls) {
    if (!ko) return '';
    const saved = isMyWord(ko);
    const icon = saved
      ? '<i class="fa-solid fa-heart" style="color:var(--coral);"></i>'
      : '<i class="fa-regular fa-heart"></i>';
    return `<button type="button" class="lsave-btn ${cls || ''}" aria-label="В словарик" title="Сохранить в Мои слова" onclick="event.stopPropagation(); toggleMyWord('${jsStr(ko)}','${jsStr(ru || '')}','${jsStr(translit || '')}','${jsStr(emoji || '🌸')}','${source || 'lesson'}', this)">${icon}</button>`;
  }

  function renderLessonSlide(lesson, slide) {
    const hint = note => note ? `
      <div class="card card-padded" style="background: rgba(201,165,92,.10); border-color: rgba(201,165,92,.4); margin-top:18px;">
        <div style="display:flex; gap:10px;">
          <span style="font-size:18px;">✨</span>
          <p style="font-size:12.5px; color:var(--berry); line-height:1.5;">${note}</p>
        </div>
      </div>` : '';
    if (slide.kind === 'intro') {
      return `
        <div style="text-align:center;">
          <div class="page-eyebrow">УРОК ${lesson.num}</div>
          <div class="ko" style="font-size:56px; font-weight:800; color:var(--berry); margin-top:10px; line-height:1;">${lesson.ko}</div>
          <div class="display" style="font-size:23px; color:var(--berry); margin-top:8px;">${slide.title}</div>
          <div style="font-size:13px; color:var(--text2); margin-top:6px;">${slide.sub}</div>
        </div>
        <div class="ko-quote" style="margin-top:22px;">
          <div style="display:flex; align-items:center; gap:10px; margin-bottom:8px;">
            <div style="width:28px; height:28px; background:var(--card); border-radius:50%; border:1px solid var(--gold); display:flex; align-items:center; justify-content:center;">🌸</div>
            <div style="font-size:13px;"><span style="font-weight:600;">Мади</span> <span style="color:var(--soft); font-size:11px; margin-left:6px;">учитель</span></div>
          </div>
          <p>${slide.intro || (lesson && LESSON_INTROS[lesson.id]) || '«Сегодня знакомимся с <span class="ko" style="font-weight:600;">한글</span> — корейской азбукой. Пройдём буквы, послушаем звуки и выучим первые слова. Это магия 🌸 화이팅!»'}</p>
        </div>
        <div style="margin-top:20px;">
          <div style="font-size:10px; letter-spacing:0.18em; color:var(--soft); padding:0 4px; margin-bottom:8px;">ЧТО ВЫУЧИМ</div>
          <div style="display:grid; grid-template-columns:repeat(3,1fr); gap:8px;">
            ${(slide.learn||[]).map(([e,t]) => `<div class="card card-padded" style="text-align:center; padding:12px 8px;"><div style="font-size:22px;">${e}</div><div style="font-size:10.5px; margin-top:4px;">${t}</div></div>`).join('')}
          </div>
        </div>
        <button onclick="nextLesson()" class="btn btn-rose btn-block" style="margin-top:22px;">Поехали <span class="ko">시작!</span> <i class="fa-solid fa-arrow-right" style="font-size:11px;"></i></button>
      `;
    }
    if (slide.kind === 'info') {
      const cols = slide.cols || 5;
      const cells = slide.grid.map(g => {
        const tap = slide.noPlay ? '' : `onclick="lessonPlay('${g.ko}', this)"`;
        return `<div class="card card-padded" ${tap} style="text-align:center; padding:12px 6px; ${slide.noPlay?'':'cursor:pointer;'} ${cols===1?'display:flex; align-items:center; gap:14px; text-align:left;':''}">
          <div class="ko" style="font-size:${cols===1?'22px':'30px'}; font-weight:700; color:var(--berry); ${cols===1?'flex-shrink:0; min-width:96px;':''}">${g.ko}</div>
          <div style="font-size:${cols===1?'12.5px':'11px'}; color:var(--soft); margin-top:${cols===1?'0':'3px'};">${g.ru}</div>
        </div>`;
      }).join('');
      // Сетки букв (cols ≥ 4) — адаптивные: колонки переносятся, ничего не обрезается
      // ни на 375px, ни на планшете/ПК. Малые сетки (1–3) держат заданное число колонок.
      const gridCols = cols === 1 ? '1fr'
        : cols >= 4 ? 'repeat(auto-fill, minmax(64px, 1fr))'
        : `repeat(${cols}, minmax(0, 1fr))`;
      return `
        <div class="page-eyebrow">${slide.eyebrow}</div>
        <div class="display" style="font-size:22px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        <div class="ko" style="font-size:13px; color:var(--coral); margin-top:2px;">${slide.sub||''}</div>
        <div style="display:grid; grid-template-columns:${gridCols}; gap:8px; margin-top:16px;">${cells}</div>
        ${hint(slide.note)}
        ${lessonNav('Понятно ✓')}
      `;
    }
    if (slide.kind === 'quiz') {
      const rows = slide.items.map(it => lessonQuizItem(it, slide.pool)).join('');
      return `
        <div class="page-eyebrow">${slide.eyebrow}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        <div style="font-size:12px; color:var(--coral); margin-top:2px;">Выбери правильный звук для каждой буквы</div>
        <div id="quiz-grid" style="display:grid; gap:10px; margin-top:16px;">${rows}</div>
        ${lessonNav('Дальше →', true)}
      `;
    }
    if (slide.kind === 'words') {
      const cards = slide.items.map(w => `
        <div onclick="lessonWordTap(this, '${w.ko}')" class="card card-press" style="padding:14px 10px; text-align:center; cursor:pointer; position:relative;">
          ${lessonSaveHeart(w.ko, w.ru, w.translit || '', w.emoji || '🌸', 'lesson-word', 'lsave-corner')}
          <div style="font-size:32px;">${w.emoji}</div>
          <div class="ko" style="font-size:22px; font-weight:700; color:var(--berry); margin-top:4px;">${w.ko}</div>
          <div style="font-size:11px; color:var(--soft); margin-top:2px;">${w.ru}</div>
        </div>`).join('');
      return `
        <div class="page-eyebrow">${slide.eyebrow}</div>
        <div class="display" style="font-size:22px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        <div style="font-size:12px; color:var(--coral); margin-top:2px;">Тапни карточку — услышишь слово 🔊</div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:16px;">${cards}</div>
        ${lessonNav('Дальше →')}
      `;
    }
    if (slide.kind === 'homework') {
      return `
        <div style="text-align:center;">
          <div style="font-size:42px;">📒</div>
          <div class="display" style="font-size:23px; color:var(--berry); margin-top:6px;">Домашнее задание</div>
        </div>
        <div style="margin-top:18px;">${homeworkBodyHtml(lesson)}</div>
        ${lessonNav('Завершить урок →')}
      `;
    }
    // ── Модуль 2: диалог (2 голоса TTS) ──
    if (slide.kind === 'dialog') {
      const bubbles = (slide.lines || []).map((ln, i) => {
        const isB = ln.who === 'B';
        return `
          <div class="dlg-row ${isB ? 'b' : 'a'}" data-dlg-i="${i}">
            <div class="dlg-ava">${ln.av || (isB ? '🧑' : '🙂')}</div>
            <div class="dlg-bubble" onclick="lessonPlay('${jsStr(ln.ko)}', this)">
              <div class="ko dlg-ko">${escHtml(ln.ko)}</div>
              ${ln.ru ? `<div class="dlg-ru">${escHtml(ln.ru)}</div>` : ''}
            </div>
            ${lessonSaveHeart(ln.ko, ln.ru || '', '', '💬', 'lesson-dialog', 'lsave-inline')}
          </div>`;
      }).join('');
      return `
        <div class="page-eyebrow">${slide.eyebrow || 'ДИАЛОГ'}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        ${slide.sub ? `<div style="font-size:12px; color:var(--coral); margin-top:2px;">${slide.sub}</div>` : ''}
        <button onclick="lessonSpeakDialog(this)" class="btn btn-rose btn-block" style="margin-top:14px;"><i class="fa-solid fa-headphones"></i> Прослушать диалог</button>
        <div class="dlg-list" style="margin-top:14px;">${bubbles}</div>
        ${hint(slide.note)}
        ${lessonNav('Дальше →')}
      `;
    }
    // ── Модуль 2: грамматический паттерн + дрилы ──
    if (slide.kind === 'pattern') {
      const examples = (slide.examples || []).map(ex => `
        <div class="card card-padded" onclick="lessonPlay('${jsStr(ex.ko)}', this)" style="cursor:pointer; display:flex; align-items:center; gap:10px; margin-top:8px;">
          <div style="flex:1; min-width:0;"><div class="ko" style="font-size:15px; color:var(--berry); font-weight:600;">${escHtml(ex.ko)}</div><div style="font-size:12px; color:var(--soft); margin-top:2px;">${escHtml(ex.ru)}</div></div>
          <i class="fa-solid fa-volume-up" style="color:var(--coral); flex-shrink:0;"></i>
          ${lessonSaveHeart(ex.ko, ex.ru || '', '', '📝', 'lesson-grammar', 'lsave-inline')}
        </div>`).join('');
      const drills = (slide.drills || []).map(d => {
        const opts = shuffleArr([...d.options]);
        return `<div class="pattern-drill card card-padded" data-done="0" style="margin-top:10px;">
          <div class="ko" style="font-size:15px; color:var(--berry); font-weight:600; line-height:1.4;">${escHtml(d.q)}</div>
          ${d.ru ? `<div style="font-size:11.5px; color:var(--soft); margin-top:3px;">${escHtml(d.ru)}</div>` : ''}
          <div style="display:flex; gap:8px; flex-wrap:wrap; margin-top:10px;">
            ${opts.map(o => `<button class="btn btn-ghost lesson-opt" style="flex:1; min-width:78px; padding:10px 8px;" onclick="lessonPatternPick(this, '${jsStr(o)}', '${jsStr(d.answer)}')">${escHtml(o)}</button>`).join('')}
          </div>
        </div>`;
      }).join('');
      return `
        <div class="page-eyebrow">${slide.eyebrow || 'ГРАММАТИКА'}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        ${slide.sub ? `<div style="font-size:12px; color:var(--coral); margin-top:2px;">${slide.sub}</div>` : ''}
        <div class="card card-padded" style="background:rgba(201,165,92,.10); border-color:rgba(201,165,92,.4); margin-top:14px;">
          <div style="font-size:13px; color:var(--berry); line-height:1.6;">${slide.rule}</div>
        </div>
        ${examples ? `<div style="margin-top:8px;">${examples}</div>` : ''}
        ${drills ? `<div style="margin-top:14px;"><div style="font-size:10px; letter-spacing:.18em; color:var(--soft); margin-bottom:2px;">ПОТРЕНИРУЙСЯ</div>${drills}</div>` : ''}
        ${lessonNav('Дальше →', !!drills)}
      `;
    }
    // ── Модуль 2: собери предложение из слов ──
    if (slide.kind === 'build') {
      const chips = shuffleArr([...(slide.target || []), ...(slide.pool || [])]);
      const chipHtml = chips.map(w => `<button type="button" class="build-chip" data-w="${escHtml(w)}" onclick="lessonBuildPick(this)">${escHtml(w)}</button>`).join('');
      return `
        <div class="page-eyebrow">${slide.eyebrow || 'СОБЕРИ ФРАЗУ'}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        <div class="card card-padded" style="margin-top:12px; text-align:center;">
          <div style="font-size:10px; color:var(--soft); letter-spacing:.16em;">ПЕРЕВЕДИ НА КОРЕЙСКИЙ</div>
          <div style="font-size:16px; color:var(--berry); font-weight:600; margin-top:6px;">${escHtml(slide.ru)}</div>
        </div>
        <div id="build-answer" class="build-answer" data-target="${(slide.target || []).map(escHtml).join('|')}" data-ru="${escHtml(slide.ru || '')}"></div>
        <div id="build-pool" class="build-pool">${chipHtml}</div>
        <div id="build-feedback" style="text-align:center; font-size:13px; margin-top:10px; min-height:18px;"></div>
        <div style="display:flex; gap:10px; margin-top:8px;">
          <button onclick="prevLesson()" class="btn btn-ghost" style="flex:1;">← Назад</button>
          <button id="build-check-btn" onclick="lessonBuildCheck(this)" class="btn btn-primary" style="flex:1.6;">Проверить</button>
        </div>
      `;
    }
    // ── Модуль 2: аудирование — услышь и выбери ──
    if (slide.kind === 'listen') {
      const opts = shuffleArr([...(slide.options || [])]);
      return `
        <div class="page-eyebrow">${slide.eyebrow || 'АУДИРОВАНИЕ'}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:4px;">${slide.title}</div>
        <div style="font-size:12px; color:var(--coral); margin-top:2px;">${slide.sub || 'Нажми ▶ и выбери, что услышал(а)'}</div>
        <div style="text-align:center; margin:20px 0;">
          <button onclick="lessonPlay('${jsStr(slide.ko)}', this)" class="listen-play" aria-label="Прослушать"><i class="fa-solid fa-play"></i></button>
          <div style="font-size:11px; color:var(--soft); margin-top:10px;">Тапни, чтобы прослушать ещё раз 🔊</div>
        </div>
        <div id="quiz-grid" style="display:grid; gap:10px;" data-save-ko="${escHtml(slide.ko || '')}" data-save-ru="${escHtml(slide.ru || '')}">
          ${opts.map(o => `<button class="btn btn-ghost lesson-opt" onclick="lessonChoicePick(this, '${jsStr(o)}', '${jsStr(slide.answer)}')" style="padding:13px;">${escHtml(o)}</button>`).join('')}
        </div>
        ${lessonNav('Дальше →', true)}
      `;
    }
    // done
    const wordCount = Array.isArray(lesson.vocab) ? lesson.vocab.length : 0;
    return `
      <div style="text-align:center; padding-top:8px;">
        <div style="font-size:56px;">🌸</div>
        <div class="display" style="font-size:25px; color:var(--berry); margin-top:8px;">Урок ${lesson.num} пройден</div>
        <div class="ko" style="font-size:18px; color:var(--coral); margin-top:2px;">잘했어 🌸</div>
        <div style="margin:24px auto 0; width:120px; height:120px; background:var(--card); border:8px solid rgba(201,165,92,.18); border-radius:50%; display:flex; align-items:center; justify-content:center; font-size:64px; color:var(--gold-ink);">✓</div>
        <div class="card card-padded" style="background: linear-gradient(135deg, var(--gold), var(--coral)); color:white; border:none; margin:22px 0 0; text-align:left;">
          <div style="font-size:9.5px; letter-spacing:0.2em; opacity:.85;">🎮 ЧТО ДАЛЬШЕ</div>
          <div style="font-weight:600; margin-top:4px;">Слова урока добавлены в игры</div>
          <div style="font-size:11.5px; opacity:.9; margin-top:2px;">${wordCount} слов теперь в карточках, мемори, переводе и других играх</div>
        </div>
        <button onclick="completeLesson()" class="btn btn-primary btn-block" style="margin-top:18px;">Готово ✓</button>
      </div>
    `;
  }
  function lessonQuizItem(it, pool) {
    const wrong = shuffleArr((pool||[]).filter(s => s !== it.ru)).slice(0, 2);
    const opts = shuffleArr([it.ru, ...wrong]);
    // Korean column auto-widens to its content (white-space: nowrap),
    // font shrinks for longer verbs so 4-char words stay on one line.
    const koLen = (it.ko || '').replace(/\s/g, '').length;
    const koSize = koLen >= 4 ? '22px' : (koLen === 3 ? '26px' : '32px');
    return `
      <div class="card card-padded quiz-row" style="display:flex; align-items:center; gap:14px; padding:14px 16px;">
        <div class="ko" style="font-size:${koSize}; font-weight:800; color:var(--berry); flex-shrink:0; white-space:nowrap; line-height:1.1; min-width:64px; text-align:center;">${it.ko}</div>
        <div style="display:flex; gap:8px; flex:1; flex-wrap:wrap; min-width:0;">
          ${opts.map(o => `<button onclick="lessonQuizPick(this, '${o}', '${it.ru}')" class="btn btn-ghost" style="flex:1; min-width:70px; padding:10px 8px; font-size:12.5px; white-space:nowrap;">${o}</button>`).join('')}
        </div>
      </div>`;
  }
  function lessonQuizPick(btn, chosen, correct) {
    const row = btn.closest('.quiz-row');
    if (chosen === correct) {
      [...btn.parentElement.children].forEach(b => { b.style.pointerEvents = 'none'; });
      btn.style.background = 'rgba(132,196,116,.22)';
      btn.style.borderColor = 'var(--ok-ink)';
      btn.style.color = 'var(--ok-ink)';
      btn.classList.add('quiz-correct-pop');
      if (row) row.dataset.done = '1';
      lessonQuizCheck();
    } else {
      btn.style.background = 'var(--bad-bg)';
      btn.style.borderColor = 'var(--bad-line)';
      btn.style.color = 'var(--bad-ink)';
      btn.classList.add('quiz-wrong-shake');
      setTimeout(() => {
        btn.style.background = '';
        btn.style.borderColor = '';
        btn.style.color = '';
        btn.classList.remove('quiz-wrong-shake');
      }, 700);
    }
  }
  function lessonQuizCheck() {
    const grid = document.getElementById('quiz-grid');
    if (!grid) return;
    const rows = [...grid.querySelectorAll('.quiz-row')];
    if (rows.length && rows.every(r => r.dataset.done === '1')) {
      const nb = document.getElementById('quiz-next-btn');
      if (nb && nb.hasAttribute('disabled')) {
        nb.removeAttribute('disabled');
        nb.style.opacity = '1';
        nb.style.pointerEvents = '';
        addXp(10);
        toast('잘했어! Всё верно 🌸 +10 XP', 'var(--sage)');
      }
    }
  }
  function lessonWordTap(el, ko) { playSyllable(ko, el); recordWordSeen(ko); }
  function lessonPlay(text, el) { playSyllable(text, el); }

  // ── Модуль 2: озвучка диалога двумя голосами (по образцу speakExamScript) ──
  let _seqItems = null, _seqIdx = 0, _seqBtn = null;
  function stopKoSequence() {
    _seqItems = null; _seqIdx = 0;
    try { window.speechSynthesis && window.speechSynthesis.cancel(); } catch (_) {}
    document.querySelectorAll('.dlg-row.speaking').forEach(r => r.classList.remove('speaking'));
    if (_seqBtn) { if (_seqBtn.dataset.idle) _seqBtn.innerHTML = _seqBtn.dataset.idle; _seqBtn.classList.remove('playing'); _seqBtn = null; }
  }
  function speakKoSequence(items, btn) {
    if (!('speechSynthesis' in window)) { toast('Голос недоступен в этом браузере'); return; }
    if (typeof getSettings === 'function' && !getSettings().sound) { toast('Озвучка выключена в настройках 🔇', 'var(--berry)'); return; }
    if (btn && btn === _seqBtn && _seqItems) { stopKoSequence(); return; } // toggle
    stopSpeech(); stopKoSequence();
    _seqBtn = btn || null;
    if (btn) { if (!btn.dataset.idle) btn.dataset.idle = btn.innerHTML; btn.classList.add('playing'); btn.innerHTML = '<i class="fa-solid fa-stop"></i> Остановить'; }
    const slow = (typeof getSettings === 'function' && getSettings().slowVoice);
    _seqItems = items.slice(); _seqIdx = 0;
    const next = () => {
      document.querySelectorAll('.dlg-row.speaking').forEach(r => r.classList.remove('speaking'));
      if (!_seqItems || _seqIdx >= _seqItems.length) { stopKoSequence(); return; }
      const it = _seqItems[_seqIdx];
      const row = document.querySelector(`.dlg-row[data-dlg-i="${it.i}"]`);
      if (row) { row.classList.add('speaking'); try { row.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch (_) {} }
      _seqIdx++;
      const u = new SpeechSynthesisUtterance(it.ko);
      u.lang = 'ko-KR';
      u.rate = slow ? 0.6 : 0.9;
      u.pitch = it.who === 'B' ? 1.3 : 0.85;
      u.onend = () => next();
      u.onerror = () => next();
      try { window.speechSynthesis.speak(u); } catch (_) { next(); }
    };
    next();
  }
  function lessonSpeakDialog(btn) {
    const l = getCurrentLesson();
    const slide = (l && Array.isArray(l.slides)) ? l.slides[lessonStage] : null;
    if (!slide || !Array.isArray(slide.lines)) return;
    const items = slide.lines.map((ln, i) => ({ ko: ln.ko, who: ln.who, i })).filter(x => x.ko);
    speakKoSequence(items, btn);
  }

  // ── Модуль 2: выбор одного правильного варианта (listen) ──
  function lessonChoicePick(btn, chosen, correct) {
    const grid = btn.closest('#quiz-grid') || btn.parentElement;
    if (chosen === correct) {
      grid.querySelectorAll('button').forEach(b => { b.disabled = true; b.style.pointerEvents = 'none'; });
      btn.classList.add('opt-correct');
      const nb = document.getElementById('quiz-next-btn');
      if (nb && nb.hasAttribute('disabled')) {
        nb.removeAttribute('disabled'); nb.style.opacity = '1'; nb.style.pointerEvents = '';
        addXp(8); toast('맞아요! Верно 🌸 +8 XP', 'var(--sage)');
      }
      // Услышанную фразу можно сохранить в словарик (показываем после верного ответа).
      const koSave = grid.dataset && grid.dataset.saveKo;
      if (koSave && grid.parentElement && !grid.parentElement.querySelector('.listen-save')) {
        const wrap = document.createElement('div');
        wrap.className = 'listen-save';
        wrap.style.cssText = 'text-align:center; margin-top:12px; font-size:12px; color:var(--soft); display:flex; align-items:center; justify-content:center; gap:8px;';
        wrap.innerHTML = 'Запомнить фразу ' + lessonSaveHeart(koSave, grid.dataset.saveRu || '', '', '🎧', 'lesson-listen', 'lsave-inline');
        grid.parentElement.insertBefore(wrap, grid.nextSibling);
      }
    } else {
      btn.classList.add('opt-wrong');
      setTimeout(() => btn.classList.remove('opt-wrong'), 600);
    }
  }

  // ── Модуль 2: грамматические дрилы (несколько в слайде) ──
  function lessonPatternPick(btn, chosen, correct) {
    const drill = btn.closest('.pattern-drill');
    if (chosen === correct) {
      if (drill) { drill.querySelectorAll('button').forEach(b => { b.disabled = true; b.style.pointerEvents = 'none'; }); drill.dataset.done = '1'; }
      btn.classList.add('opt-correct');
      lessonPatternCheck();
    } else {
      btn.classList.add('opt-wrong');
      setTimeout(() => btn.classList.remove('opt-wrong'), 600);
    }
  }
  function lessonPatternCheck() {
    const drills = [...document.querySelectorAll('.pattern-drill')];
    if (drills.length && drills.every(d => d.dataset.done === '1')) {
      const nb = document.getElementById('quiz-next-btn');
      if (nb && nb.hasAttribute('disabled')) {
        nb.removeAttribute('disabled'); nb.style.opacity = '1'; nb.style.pointerEvents = '';
        addXp(10); toast('완벽해요! 🌸 +10 XP', 'var(--sage)');
      }
    }
  }

  // ── Модуль 2: конструктор предложения ──
  function clearBuildFeedback() { const f = document.getElementById('build-feedback'); if (f) f.textContent = ''; }
  function lessonBuildPick(btn) {
    const ans = document.getElementById('build-answer');
    if (!ans) return;
    btn.style.display = 'none';
    const chip = document.createElement('button');
    chip.type = 'button';
    chip.className = 'build-chip in-answer';
    chip.textContent = btn.dataset.w;
    chip.onclick = () => { btn.style.display = ''; chip.remove(); clearBuildFeedback(); };
    ans.appendChild(chip);
    clearBuildFeedback();
  }
  function lessonBuildCheck(btn) {
    const ans = document.getElementById('build-answer');
    const fb = document.getElementById('build-feedback');
    if (!ans) return;
    const target = (ans.dataset.target || '').split('|').filter(Boolean);
    const cur = [...ans.querySelectorAll('.build-chip')].map(c => c.textContent);
    const ok = cur.length === target.length && cur.every((w, i) => w === target[i]);
    if (ok) {
      ans.querySelectorAll('.build-chip').forEach(c => { c.classList.add('correct'); c.onclick = null; });
      const koPhrase = target.join(' ');
      const ruPhrase = ans.dataset.ru || '';
      if (fb) {
        fb.style.color = 'var(--ok-ink)';
        fb.innerHTML = '맞아요! Верно 🌸 ' + lessonSaveHeart(koPhrase, ruPhrase, '', '🧩', 'lesson-build', 'lsave-inline');
      }
      addXp(10); toast('잘했어요! +10 XP', 'var(--sage)');
      btn.textContent = 'Дальше →';
      btn.onclick = () => nextLesson();
    } else {
      if (fb) { fb.style.color = 'var(--bad-ink)'; fb.textContent = 'Не совсем — попробуй другой порядок 🌸'; }
      ans.classList.add('build-shake');
      setTimeout(() => ans.classList.remove('build-shake'), 500);
    }
  }
  function nextLesson() {
    const total = lessonSlides().length + 1;
    lessonStage = Math.min(total - 1, lessonStage + 1);
    const l = getCurrentLesson(); if (l) saveLessonStage(l.id, lessonStage); // resume point
    renderLesson();
  }
  function prevLesson() {
    lessonStage = Math.max(0, lessonStage - 1);
    const l = getCurrentLesson(); if (l) saveLessonStage(l.id, lessonStage);
    renderLesson();
  }
  function closeLessonFlow() {
    lessonViewId = null;
    stopKoSequence();
    document.getElementById('lesson-modal')?.remove();
    document.body.classList.remove('lesson-open');
  }
  function completeLesson() {
    const lesson = getCurrentLesson();
    if (lesson && Array.isArray(lesson.vocab)) lesson.vocab.forEach(w => recordWordSeen(w.ko));
    // Повтор уже пройденного урока (через «Пройти ещё раз») или просмотр админом —
    // это review: прогресс/XP не трогаем, чтобы не сбить текущий урок и не выдать XP заново.
    const p0 = getLessonProgress();
    const isReview = isAdmin() || (lesson && lessonViewId && p0.completed.includes(lesson.id));
    closeLessonFlow();
    if (isReview) {
      renderLessonPath();
      showLessonCompletePopup(lesson, 0);
      return;
    }
    const xp = 20;
    const wasComplete = isModuleComplete(_activeModule);
    completeCurrentLesson();
    addXp(xp);
    renderModuleSwitcher();   // вдруг открылся следующий модуль — обновим вкладки
    renderLessonPath();
    renderHeroLesson();
    renderHomeworkList();
    // Поздравление + анонс открытого следующего модуля
    if (!wasComplete && isModuleComplete(_activeModule)) {
      const order = Object.keys(LESSON_MODULES);
      const idx = order.indexOf(_activeModule);
      const next = order[idx + 1];
      if (next) setTimeout(() => toast(`🎉 Модуль ${idx + 1} пройден! Открыт «${LESSON_MODULES[next].short}» 🌸`, 'var(--sage)'), 900);
    }
    showLessonCompletePopup(lesson, xp);
    checkAchievements();
  }
  function showLessonCompletePopup(lesson, xp) {
    if (!lesson) return;
    document.getElementById('lesson-complete-page')?.remove();
    const m = document.createElement('div');
    m.className = 'lesson-complete-page';
    m.id = 'lesson-complete-page';
    const xpChip = xp > 0
      ? `<div style="margin-top:18px;"><span class="chip" style="background:linear-gradient(140deg,var(--coral),var(--gold)); color:white; font-weight:600; font-size:13px; padding:6px 16px;">+${xp} XP · 🔥</span></div>`
      : '';
    m.innerHTML = `
      <div class="lesson-complete-inner">
        <img src="assets/bear5.png" alt="" class="lesson-complete-bear-big" onerror="this.style.display='none'">
        <div class="page-eyebrow" style="color:var(--coral); letter-spacing:.22em;">УРОК ${lesson.num} ПРОЙДЕН</div>
        <div class="display" style="font-size:30px; color:var(--berry); margin-top:8px; line-height:1.15;">${lesson.title}</div>
        ${lesson.ko ? `<div class="ko" style="font-size:18px; color:var(--soft); margin-top:6px;">${lesson.ko}</div>` : ''}
        ${xpChip}
        <div style="margin-top:18px; font-size:14px; color:var(--soft); line-height:1.55; max-width:320px;">
          Отлично! Мади гордится тобой 🌸<br>Продолжай в том же духе.
        </div>
      </div>
      <button onclick="document.getElementById('lesson-complete-page')?.remove()" class="btn btn-primary lesson-complete-cta">
        Дальше <i class="fa-solid fa-arrow-right" style="font-size:11px;"></i>
      </button>
    `;
    document.body.appendChild(m);
    // Confetti for extra celebration
    if (typeof spawnConfetti === 'function') spawnConfetti();
  }

  // ── Flashcards (интервальное повторение · SM-2-lite) ──
  // Per-word schedule persisted in UStore('srs'): { [ko]: { box, due, reps } }.
  // box 0..5 → растущий интервал. Сессия — это очередь: «не помню/с трудом»
  // возвращают карточку позже в этой же сессии (с лимитом), потом — итог.
  let cardIdx = 0, flipped = false;            // cardIdx kept for back-compat
  let fcQueue = [], fcPos = 0, fcReviewed = 0, fcLearned = 0;
  let fcReplayFn = startFlashcards;
  const SRS_INTERVALS_DAYS = [0, 1, 3, 7, 16, 35]; // box → days until due
  function srsAll() { const v = UStore.get('srs', {}); return (v && typeof v === 'object') ? v : {}; }
  function srsDue(ko) { const e = srsAll()[ko]; return e ? (e.due || 0) : 0; }
  function srsSchedule(ko, rating) {
    if (!ko) return;
    const all = srsAll();
    const e = all[ko] || { box: 0, reps: 0 };
    if (rating <= 0)       e.box = 0;                       // не помню → сброс
    else if (rating === 1) e.box = Math.max(1, e.box);     // с трудом → держим
    else if (rating === 2) e.box = Math.min(5, (e.box || 0) + 1);
    else                   e.box = Math.min(5, (e.box || 0) + 2);
    e.reps = (e.reps || 0) + 1;
    e.due  = Date.now() + (SRS_INTERVALS_DAYS[e.box] || 0) * 86400000;
    all[ko] = e;
    UStore.set('srs', all);
  }
  function buildFlashcards() {
    return [
      ...gameWordPool().map(w => ({ front:w.ko, translit:w.translit||'', emoji:w.emoji||'🌸', meaning:w.ru, example:w.example||'' })),
      ...Store.get('customFlashcards', [])
    ];
  }
  // Earliest-due first (due 0 = новое/просроченное идёт вперёд).
  function orderByDue(cards) {
    return cards
      .filter(c => c && c.front)
      .map(c => ({ c, due: srsDue(c.front) }))
      .sort((a, b) => a.due - b.due)
      .map(x => x.c);
  }
  function startFlashcardSession(cards) {
    fcQueue = orderByDue(cards);
    fcQueue.forEach(c => { c._tries = 0; });
    fcPos = 0; fcReviewed = 0; fcLearned = 0; flipped = false;
    flashcardSession = fcQueue;                  // keep legacy global in sync
    renderFlashcardModal();
  }
  function startFlashcards() { fcReplayFn = startFlashcards; startFlashcardSession(shuffleArr(buildFlashcards())); }
  function replayFlashcards() { (fcReplayFn || startFlashcards)(); }
  // Full-screen flashcard page; created once, then content swapped in place (no re-animation flicker).
  function flashSetContent(inner) {
    let page = document.getElementById('flash-modal');
    if (!page) {
      page = document.createElement('div');
      page.className = 'game-page';
      page.id = 'flash-modal';
      page.innerHTML = '<div class="game-page-scroll"><div class="game-page-card"></div></div>';
      document.body.appendChild(page);
      document.body.classList.add('game-open');
    }
    page.querySelector('.game-page-card').innerHTML = inner;
  }
  function renderFlashcardModal() {
    if (fcPos >= fcQueue.length) { renderFlashcardDone(); return; }
    const card = fcQueue[fcPos];
    const remaining = fcQueue.length - fcPos;
    const saved = isMyWord(card.front);
    const heartIcon = saved
      ? '<i class="fa-solid fa-heart" style="color:var(--coral);"></i>'
      : '<i class="fa-regular fa-heart"></i>';
    flashSetContent(`
      <div style="background:var(--card); border-radius:24px; padding:22px; box-shadow:var(--shadow-md); border:1px solid var(--line);">
        <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:14px;">
          <div>
            <div class="page-eyebrow">КАРТОЧКИ СЛОВ</div>
            <div style="font-size:11px; color:var(--soft); margin-top:2px;">осталось: ${remaining} · 🌸 интервальное повторение</div>
          </div>
          <div style="display:flex; gap:6px; align-items:center;">
            <button onclick="toggleMyWord('${jsStr(card.front)}', '${jsStr(card.meaning||'')}', '${jsStr(card.translit||'')}', '${jsStr(card.emoji||'')}', 'flashcards', this)" aria-label="В словарик" title="Сохранить в Мои слова" style="background:var(--card); border:1px solid var(--line); width:34px; height:34px; border-radius:10px; cursor:pointer; font-size:14px; line-height:1; padding:0;">${heartIcon}</button>
            <div onclick="closeGameModal('flash-modal')" style="font-size:24px; line-height:1; color:var(--soft); cursor:pointer; padding:4px 8px;">×</div>
          </div>
        </div>
        <div class="flashcard ${flipped ? 'flipped' : ''}" id="fc" style="width:100%; height:240px;" onclick="flipFlashcard()">
          <div class="flashcard-inner">
            <div class="flashcard-face flashcard-front">
              <div style="font-size:42px;">${escHtml(card.emoji)}</div>
              <div class="ko" style="font-size:50px; font-weight:700; color:var(--berry); line-height:1; margin-top:6px;">${escHtml(card.front)}</div>
              ${card.translit ? `<div style="color:var(--coral); letter-spacing: 0.32em; margin-top: 6px;">[ ${escHtml(card.translit)} ]</div>` : ''}
              <div style="display:flex; gap:8px; margin-top:14px;" onclick="event.stopPropagation();">
                <button onclick="event.stopPropagation(); playSyllable('${jsStr(card.front)}', this)" class="btn-mic" style="background:var(--card); border-color:var(--line-strong);"><i class="fa-solid fa-volume-up"></i> Послушать</button>
                <button onclick="event.stopPropagation(); pronounceCheck('${jsStr(card.front)}', this)" class="btn-mic"><i class="fa-solid fa-microphone"></i> Произнести</button>
              </div>
              <div style="position:absolute; bottom:10px; font-size:10px; color: var(--soft);">Тапни карточку, чтобы перевернуть</div>
            </div>
            <div class="flashcard-face flashcard-back">
              <div style="font-size:10px; opacity:.7; letter-spacing: 0.16em;">ЗНАЧИТ</div>
              <div class="display" style="font-size:32px; margin-top:4px;">${escHtml(card.meaning)}</div>
              ${card.example ? `<div style="border-top:1px solid rgba(255,255,255,.18); border-bottom:1px solid rgba(255,255,255,.18); padding: 14px 0; margin-top:18px; font-size:12.5px; text-align:center; line-height:1.5;">
                <span class="ko">«${escHtml(card.example.split(' — ')[0])}»</span><br>
                <span style="opacity:.8;">— ${escHtml(card.example.split(' — ')[1] || '')}</span>
              </div>` : ''}
            </div>
          </div>
        </div>
        <div style="display:grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-top: 18px;">
          <button onclick="rateCard(0)" class="btn btn-ghost" style="padding: 10px 6px; font-size: 11px; flex-direction:column; gap: 2px; border-color: #E89BA1; color: #E89BA1;">😵<span style="font-size:9px;">Не помню</span></button>
          <button onclick="rateCard(1)" class="btn btn-ghost" style="padding: 10px 6px; font-size: 11px; flex-direction:column; gap: 2px;">🤔<span style="font-size:9px;">С трудом</span></button>
          <button onclick="rateCard(2)" class="btn btn-ghost" style="padding: 10px 6px; font-size: 11px; flex-direction:column; gap: 2px; border-color: var(--sage); color: var(--ok-ink);">🙂<span style="font-size:9px;">Знаю</span></button>
          <button onclick="rateCard(3)" class="btn btn-primary" style="padding: 10px 6px; font-size: 11px; flex-direction:column; gap: 2px;">🌟<span style="font-size:9px;">Идеально!</span></button>
        </div>
      </div>
    `);
  }
  function renderFlashcardDone() {
    flashSetContent(`
      <div style="background:var(--card); border-radius:24px; padding:24px; box-shadow:var(--shadow-md); border:1px solid var(--line); text-align:center;">
        <div style="font-size:56px;">🌸</div>
        <div class="display" style="font-size:24px; color:var(--berry); margin-top:6px;">Колода пройдена</div>
        <div style="font-size:13px; color:var(--coral); margin-top:2px;">잘했어! Так держать ✨</div>
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px; margin-top:18px;">
          <div class="card card-padded" style="text-align:center; padding:12px 6px;"><div class="display" style="font-size:18px; color:var(--berry);">${fcReviewed}</div><div style="font-size:10px; color:var(--soft);">повторено</div></div>
          <div class="card card-padded" style="text-align:center; padding:12px 6px;"><div class="display" style="font-size:18px; color:var(--gold-ink);">${fcLearned}</div><div style="font-size:10px; color:var(--soft);">уверенно</div></div>
        </div>
        <div style="font-size:10.5px; color:var(--soft); margin-top:12px; line-height:1.5;">Слова, что давались с трудом, всплывут раньше в следующий раз 🌙</div>
        <button onclick="replayFlashcards()" class="btn btn-rose btn-block" style="margin-top:16px;">↻ Ещё раз</button>
        <button onclick="closeGameModal('flash-modal')" class="btn btn-ghost btn-block" style="margin-top:8px;">Готово ✓</button>
      </div>
    `);
  }
  function flipFlashcard() { flipped = !flipped; const fc = document.getElementById('fc'); if (fc) fc.classList.toggle('flipped', flipped); }
  function rateCard(rating) {
    const card = fcQueue[fcPos];
    if (!card) return;
    const msgs = ['Ах, ничего страшного 🌸 Попробуем позже', 'Хорошо, что стараешься! 💪', '잘했어! Отлично ✨', '와! Идеально 🔥'];
    toast(msgs[rating]);
    srsSchedule(card.front, rating);
    fcReviewed++;
    if (rating >= 2) {
      addXp(rating === 3 ? 15 : 8);
      if (card.front) recordWordSeen(card.front);
      fcLearned++;
    }
    // Count flashcards as a "play" for the games-1 / games-10 / games-50 / games-all achievements
    if (!stats.gamePlays.flashcards) stats.gamePlays.flashcards = 0;
    stats.gamePlays.flashcards++;
    UStore.set('stats', stats);
    if (stats.gamePlays.flashcards % 5 === 0) checkAchievements();
    // «Не помню/с трудом» — вернуть карточку позже в этой сессии (с лимитом повторов)
    card._tries = (card._tries || 0) + 1;
    if (rating <= 1 && card._tries < 3) {
      const insertAt = Math.min(fcQueue.length, fcPos + (rating === 0 ? 3 : 5));
      fcQueue.splice(insertAt, 0, card);
    }
    setTimeout(() => { fcPos++; flipped = false; renderFlashcardModal(); }, 900);
  }

  // ── SRS "review today" widget (home) ──
  // Cards whose scheduled `due` time has arrived (only words already studied at
  // least once carry a schedule, so this counts genuine repetitions, not new words).
  function srsDueList() {
    const now = Date.now();
    const all = srsAll();
    const seen = new Set();
    const due = [];
    for (const c of buildFlashcards()) {
      if (!c || !c.front || seen.has(c.front)) continue;
      seen.add(c.front);
      const e = all[c.front];
      if (e && (e.due || 0) <= now) due.push(c);
    }
    return due;
  }
  function startDueFlashcards() {
    const due = srsDueList();
    if (!due.length) { toast('Сейчас нет карточек к повторению 🌸', 'var(--sage)'); renderSrsWidget(); return; }
    fcReplayFn = startDueFlashcards;
    startFlashcardSession(due);
  }
  function renderSrsWidget() {
    const slot = document.getElementById('srs-widget');
    if (!slot) return;
    const n = srsDueList().length;
    if (!n) { slot.innerHTML = ''; return; }
    const wordForm = (n % 10 === 1 && n % 100 !== 11) ? 'карточка'
      : ([2,3,4].includes(n % 10) && ![12,13,14].includes(n % 100)) ? 'карточки' : 'карточек';
    slot.innerHTML = `
      <div onclick="startDueFlashcards()" class="card card-press" style="padding:14px 16px; cursor:pointer; background:linear-gradient(135deg, rgba(201,165,92,.16), rgba(255,255,255,.7));">
        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px;">
          <div style="display:flex; align-items:center; gap:10px; min-width:0;">
            <span style="font-size:22px;">🔁</span>
            <div style="min-width:0;">
              <div style="font-size:13px; font-weight:700; color:var(--berry);">Повторить сегодня</div>
              <div style="font-size:10.5px; color:var(--soft); margin-top:1px;">${n} ${wordForm} «созрело» к повторению</div>
            </div>
          </div>
          <span class="chip chip-coral" style="flex-shrink:0;">Начать →</span>
        </div>
      </div>`;
  }

  // ── Avatar / Share ──
  function applyAvatar(url) {
    const apply = el => {
      if (!el) return;
      const isHomeAvatar = el.id === 'home-greet-avatar';
      if (url) {
        if (isHomeAvatar) {
          // Override CSS bear fallback with user photo via inline image
          el.style.backgroundImage = `url(${url})`;
          el.style.backgroundColor = '';
        } else {
          el.style.background = `url(${url}) center/cover no-repeat`;
          el.textContent = '';
        }
        el.classList.add('photo-zoom');
      } else {
        if (isHomeAvatar) {
          // Clear inline → falls back to CSS bear illustration
          el.style.backgroundImage = '';
          el.style.backgroundColor = '';
        } else {
          el.style.background = '';
          el.textContent = '👧🏻';
        }
        el.classList.remove('photo-zoom');
      }
    };
    apply(document.querySelector('#screen-profile .placeholder-img'));
    apply(document.getElementById('ep-avatar-preview'));
    apply(document.getElementById('home-greet-avatar'));
    // Make sure the current user's avatar in the cache reflects what we just applied
    // so their own comments/replies show the latest avatar immediately.
    try {
      const uid = socialUserId();
      if (uid && _userAvatars[uid] !== (url || null)) {
        _userAvatars[uid] = url || null;
        if (typeof _structureHashCache !== 'undefined') {
          Object.keys(_structureHashCache).forEach(k => delete _structureHashCache[k]);
        }
        if (typeof refreshFeedSocial === 'function') refreshFeedSocial();
      }
    } catch (_) {}
  }
  function changeAvatar(ev) {
    const f = ev.target.files[0];
    if (!f) return;
    if (!/^image\//.test(f.type)) { toast('Можно загружать только картинки'); return; }
    if (f.size > 12 * 1024 * 1024) { toast('Фото слишком большое (макс 12 МБ)'); return; }
    const reader = new FileReader();
    reader.onload = e => {
      const img = new Image();
      img.onload = () => {
        // Уменьшаем фото до 320px и пережимаем в JPEG: исходный data URL
        // не влезает в localStorage (квота ~5 МБ) и фото не сохраняется
        const max = 320;
        let w = img.width, h = img.height;
        if (w > h && w > max) { h = Math.round(h * max / w); w = max; }
        else if (h > max)     { w = Math.round(w * max / h); h = max; }
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        const url = canvas.toDataURL('image/jpeg', 0.82);
        UStore.set('avatar', url);
        applyAvatar(url);
        toast('Фото обновлено 📷', 'var(--sage)');
        recordAvatarSet();
        pushUserToCloud();
      };
      img.onerror = () => toast('Не удалось обработать фото');
      img.src = e.target.result;
    };
    reader.readAsDataURL(f);
  }
  // Обложка профиля (фон в стиле Telegram Premium). Сжимаем до 640px по длинной
  // стороне и в JPEG — чтобы влезла в синк (RTDB) и localStorage.
  function changeCover(ev) {
    const f = ev.target.files[0];
    if (!f) return;
    if (!/^image\//.test(f.type)) { toast('Можно загружать только картинки'); return; }
    if (f.size > 12 * 1024 * 1024) { toast('Фото слишком большое (макс 12 МБ)'); return; }
    const reader = new FileReader();
    reader.onload = e => {
      const img = new Image();
      img.onload = () => {
        const max = 640;
        let w = img.width, h = img.height;
        if (w > h) { if (w > max) { h = Math.round(h * max / w); w = max; } }
        else       { if (h > max) { w = Math.round(w * max / h); h = max; } }
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        const url = canvas.toDataURL('image/jpeg', 0.78);
        UStore.set('cover', url);                       // локально + авто-синк (обычные юзеры)
        if (isAdmin()) pushProfilePublicField('cover', url); // у админа авто-синк отключён
        const prev = document.getElementById('ep-cover-preview');
        if (prev) { prev.style.background = `url(${url}) center/cover no-repeat`; prev.classList.add('has-photo'); }
        toast('Обложка обновлена 🌸', 'var(--sage)');
      };
      img.onerror = () => toast('Не удалось обработать фото');
      img.src = e.target.result;
    };
    reader.readAsDataURL(f);
  }
  function saveUserBio(bio) {
    bio = (bio || '').slice(0, 200);
    UStore.set('bio', bio);                         // локально + авто-синк (обычные юзеры)
    if (isAdmin()) pushProfilePublicField('bio', bio); // у админа авто-синк отключён
  }
  // Шер-карточка профиля: красивая картинка для Stories/Telegram —
  // в том же стиле, что и карточка результата ТОПИК (shareExamCard).
  async function shareProgress() {
    const u = Store.get('user') || {};
    const lvl = getLevel(stats.xp);
    const rank = getRank(lvl);
    const W = 1080, H = 1350;
    const c = document.createElement('canvas');
    c.width = W; c.height = H;
    const x = c.getContext('2d');
    // фон: кремовый градиент + лепестки
    const bg = x.createLinearGradient(0, 0, 0, H);
    bg.addColorStop(0, '#FFFAF6'); bg.addColorStop(.55, '#FCF0EC'); bg.addColorStop(1, '#F9E3E6');
    x.fillStyle = bg; x.fillRect(0, 0, W, H);
    x.globalAlpha = .5;
    x.textAlign = 'center';
    [[90,140],[990,110],[160,1190],[930,1230],[70,640],[1010,700],[540,90],[250,330],[840,380]].forEach(([px,py],i) => {
      x.save(); x.translate(px,py); x.rotate((i*47)%360*Math.PI/180);
      x.font = `${30+(i%3)*16}px serif`; x.fillText('🌸',0,0); x.restore();
    });
    x.globalAlpha = 1;
    // логотип
    const logo = await _loadImg('assets/logo-horizontal.png');
    if (logo) {
      const lw = 460, lh = lw * (logo.height / logo.width);
      x.drawImage(logo, (W - lw) / 2, 70, lw, lh);
    }
    // белая карточка
    const cardY = 300, cardH = 740, cardX = 90, cardW = W - 180, r = 48;
    x.save();
    x.shadowColor = 'rgba(92,42,51,.18)'; x.shadowBlur = 60; x.shadowOffsetY = 24;
    x.fillStyle = '#fff';
    x.beginPath(); x.roundRect(cardX, cardY, cardW, cardH, r); x.fill();
    x.restore();
    // аватар (кружок) или инициал; пустой src не грузим — у Image('') не сработает onerror
    const avUrl = UStore.get('avatar');
    const av = avUrl ? await _loadImg(avUrl) : null;
    const aR = 110, aCx = W / 2, aCy = cardY + 160;
    x.save();
    x.beginPath(); x.arc(aCx, aCy, aR, 0, Math.PI * 2); x.clip();
    if (av) {
      // cover-обрезка квадратом по центру
      const side = Math.min(av.width, av.height);
      x.drawImage(av, (av.width - side) / 2, (av.height - side) / 2, side, side, aCx - aR, aCy - aR, aR * 2, aR * 2);
    } else {
      x.fillStyle = '#FBE8EA'; x.fillRect(aCx - aR, aCy - aR, aR * 2, aR * 2);
      x.fillStyle = '#E07686'; x.font = '700 110px Inter, sans-serif'; x.textAlign = 'center';
      x.fillText((u.name || '🌸').charAt(0).toUpperCase(), aCx, aCy + 38);
    }
    x.restore();
    x.lineWidth = 10; x.strokeStyle = '#F2A6AE';
    x.beginPath(); x.arc(aCx, aCy, aR + 5, 0, Math.PI * 2); x.stroke();
    // имя + ранг
    x.textAlign = 'center';
    x.fillStyle = '#5C2A33';
    x.font = '700 64px Inter, sans-serif';
    x.fillText((u.name || 'Ученица Madie').slice(0, 18), W / 2, cardY + 360);
    x.fillStyle = '#E07686';
    x.font = '600 40px Inter, sans-serif';
    x.fillText(`${rank.emoji} ${rank.label} · Уровень ${lvl}`, W / 2, cardY + 425);
    // статистика
    x.fillStyle = '#5C2A33';
    x.font = '800 150px Fraunces, Georgia, serif';
    x.fillText(`${stats.xp}`, W / 2, cardY + 590);
    x.fillStyle = '#C9A55C';
    x.font = '700 52px Fraunces, Georgia, serif';
    x.fillText('XP', W / 2 + (String(stats.xp).length * 42) + 60, cardY + 585);
    x.fillStyle = 'rgba(92,42,51,.6)';
    x.font = '500 44px Inter, sans-serif';
    x.fillText(`🔥 стрик ${stats.streak} · 📚 ${stats.words || 0} слов · 🌸 ${stats.daysEntered || 0} дней`, W / 2, cardY + 680);
    // мишка + подпись
    const bear = await _loadImg('assets/bear2.png');
    if (bear) {
      const bh = 330, bw = bh * (bear.width / bear.height);
      x.drawImage(bear, W - bw - 100, H - bh - 130, bw, bh);
    }
    x.textAlign = 'left';
    x.fillStyle = '#5C2A33';
    x.font = '700 46px Inter, sans-serif';
    x.fillText('Учу корейский с Madie', 100, H - 200);
    x.fillStyle = 'rgba(92,42,51,.55)';
    x.font = '500 36px Inter, sans-serif';
    x.fillText('Korean with Madie 🌸 화이팅!', 100, H - 140);
    // поделиться / скачать
    c.toBlob(async blob => {
      if (!blob) { toast('Не получилось создать картинку'); return; }
      const file = new File([blob], 'madie-profile.png', { type: 'image/png' });
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        try {
          await navigator.share({ files: [file], title: 'Мой прогресс в корейском', text: `Учу корейский с Korean with Madie 🌸 Уровень ${lvl} · ${stats.xp} XP · стрик ${stats.streak} 🔥` });
          return;
        } catch (e) { if (e && e.name === 'AbortError') return; }
      }
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = 'madie-profile.png';
      a.click();
      setTimeout(() => URL.revokeObjectURL(a.href), 4000);
      toast('Карточка сохранена — выложи в сторис! 📸', 'var(--sage)');
    }, 'image/png');
  }

  // ── Storage ──
  const Store = {
    get(k, d=null) { try { const v = localStorage.getItem('madie_'+k); return v == null ? d : JSON.parse(v); } catch { return d; } },
    set(k, v) { try { localStorage.setItem('madie_'+k, JSON.stringify(v)); } catch (_) {} },
    del(k) { try { localStorage.removeItem('madie_'+k); } catch (_) {} }
  };

  // ── Firebase Sync — shared admin content visible to all users ──
  const SHARED_KEYS = ['customFeedPosts','customFlashcards','customKpop','customVideos','customLessons','topikMaterials'];
  const _origStoreSet = Store.set.bind(Store);
  Store.set = function(k, v) {
    _origStoreSet(k, v);
    if (SHARED_KEYS.includes(k) && typeof _db !== 'undefined') {
      _db.ref('shared/' + k).set(v).catch(e => console.warn('Firebase write error:', e));
    }
  };

  // ── Media upload helpers ──
  function compressImageFile(file, maxDim = 1280, quality = 0.78) {
    return new Promise((resolve, reject) => {
      const img = new Image();
      const reader = new FileReader();
      reader.onload = e => { img.src = e.target.result; };
      reader.onerror = () => reject(new Error('read failed'));
      img.onload = () => {
        let { width, height } = img;
        if (width > maxDim || height > maxDim) {
          const k = Math.min(maxDim / width, maxDim / height);
          width = Math.round(width * k);
          height = Math.round(height * k);
        }
        const canvas = document.createElement('canvas');
        canvas.width = width; canvas.height = height;
        canvas.getContext('2d').drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', quality));
      };
      img.onerror = () => reject(new Error('image load failed'));
      reader.readAsDataURL(file);
    });
  }
  async function uploadFileToStorage(file, folder) {
    const safeName = file.name.replace(/[^\w.\-]+/g, '_');
    const path = `${folder}/${Date.now()}_${safeName}`;
    const ref = _storage.ref(path);
    const snap = await ref.put(file);
    return await snap.ref.getDownloadURL();
  }

  // ── Cloud user profile sync ──
  function firebaseUserId() {
    return currentUserId().replace(/[.#$\[\]\/]/g, '_');
  }
  let _pushUserTimer = null;
  function pushUserToCloud() {
    if (_pushUserTimer) clearTimeout(_pushUserTimer);
    _pushUserTimer = setTimeout(_doPushUserToCloud, 600);
  }
  async function _doPushUserToCloud() {
    if (typeof _db === 'undefined') return;
    const u = Store.get('user');
    if (!u || u.guest) return;
    const uid = firebaseUserId();
    if (!uid || uid === 'guest') return;
    // Push profile metadata for both students and admins (so they're discoverable in chat search).
    // Per-user stats/unlocks/etc still skip admin via pushUserField guards.
    const profile = {
      name: u.name || 'Без имени',
      email: u.email || '',
      lastSeen: Date.now(),
      joinedAt: stats.firstOpenTs || Date.now(),
      isAdmin: !!u.isAdmin
    };
    try {
      await _db.ref('users/' + uid).update(profile);
    } catch (e) {
      console.warn('pushUserToCloud failed:', e);
    }
  }
  function relativeTime(ts) {
    if (!ts) return '—';
    const diff = Date.now() - ts;
    if (diff < 60000) return 'только что';
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return `${mins} мин назад`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs} ч назад`;
    const days = Math.floor(hrs / 24);
    if (days === 1) return 'вчера';
    if (days < 7) return `${days} ${pluralDays(days)} назад`;
    const d = new Date(ts);
    return `${d.getDate()} ${monthsRu[d.getMonth()].toLowerCase()}`;
  }

  // ── Per-user data sync (full mirror to Firebase) ──
  const USTORE_SYNC_KEYS = ['stats', 'avatar', 'unlocks', 'lessonProgress', 'lessonProgress_m2', 'lessonProgress_m3', 'lessonProgress_m4', 'lessonProgress_m5', 'bestScores', 'cover', 'bio'];
  let _skipCloudPush = false;
  const _userFieldDebounce = {};
  const _userFieldPending = {};
  function _writeUserField(uid, k, v) {
    const safe = (v === undefined) ? null : v;
    return _db.ref(`users/${uid}/${k}`).set(safe)
      .catch(e => console.warn(`pushUserField(${k}) failed:`, e));
  }
  // Публичные поля профиля (обложка, «о себе»): пишем в облако ДАЖЕ для админа —
  // у обычного pushUserField админ исключён (его per-user стата не синкается),
  // но учитель тоже виден ученикам в чате, поэтому его обложку/био сохраняем.
  function pushProfilePublicField(k, v) {
    if (typeof _db === 'undefined') return;
    const u = Store.get('user');
    if (!u || u.guest) return;
    const uid = firebaseUserId();
    if (!uid || uid === 'guest') return;
    _writeUserField(uid, k, (v === undefined ? null : v));
  }
  function pushUserField(k, v) {
    if (typeof _db === 'undefined') return;
    const u = Store.get('user');
    if (!u || u.isAdmin || u.guest) return;
    const uid = firebaseUserId();
    if (!uid || uid === 'guest') return;
    _userFieldPending[k] = v; // remember latest so a flush can write it immediately
    if (_userFieldDebounce[k]) clearTimeout(_userFieldDebounce[k]);
    _userFieldDebounce[k] = setTimeout(() => {
      delete _userFieldDebounce[k];
      if (k in _userFieldPending) { const val = _userFieldPending[k]; delete _userFieldPending[k]; _writeUserField(uid, k, val); }
    }, 400);
  }
  // Write all pending (debounced) user fields RIGHT NOW. Called when the tab is
  // hidden/closing so a change made within the 400 ms debounce window isn't lost.
  function flushUserFieldPushes() {
    if (typeof _db === 'undefined') return;
    const u = Store.get('user');
    if (!u || u.isAdmin || u.guest) return;
    const uid = firebaseUserId();
    if (!uid || uid === 'guest') return;
    Object.keys(_userFieldPending).forEach(k => {
      if (_userFieldDebounce[k]) { clearTimeout(_userFieldDebounce[k]); delete _userFieldDebounce[k]; }
      const val = _userFieldPending[k]; delete _userFieldPending[k];
      _writeUserField(uid, k, val);
    });
  }
  let _ustoreOverridden = false;
  function applyUStoreCloudSync() {
    if (_ustoreOverridden || typeof UStore === 'undefined') return;
    _ustoreOverridden = true;
    const orig = UStore.set.bind(UStore);
    UStore.set = function(k, v) {
      orig(k, v);
      if (!_skipCloudPush && USTORE_SYNC_KEYS.includes(k)) {
        pushUserField(k, v);
      }
    };
  }
  let _userListeners = [];
  function detachUserListeners() {
    _userListeners.forEach(off => { try { off(); } catch (_) {} });
    _userListeners = [];
  }
  // Cloud-sync gating for the profile. While the first snapshot is in flight we
  // show a skeleton instead of a misleading "new user / 0 achievements" state,
  // and we reconcile achievements SILENTLY once data lands — so a returning user
  // never gets flooded with catch-up unlock toasts (the old "all at once" bug).
  let _cloudSyncPending = false;
  let _cloudSyncTimeout = null;
  let _achReconcileScheduled = false;
  function settleCloudSync() {
    if (!_cloudSyncPending) return;
    _cloudSyncPending = false;
    if (_cloudSyncTimeout) { clearTimeout(_cloudSyncTimeout); _cloudSyncTimeout = null; }
    syncAchievementsStrip();
  }
  function scheduleAchReconcile() {
    if (_achReconcileScheduled) return;
    _achReconcileScheduled = true;
    // Microtask: runs after the listener's _skipCloudPush window closes, so any
    // freshly-derived unlocks still get pushed to the cloud. skipXp=true avoids
    // re-crediting XP that the just-loaded stats already include.
    Promise.resolve().then(() => {
      _achReconcileScheduled = false;
      try { checkAchievements(true, true); } catch (_) {}
    });
  }
  function attachUserListeners() {
    detachUserListeners();
    if (typeof _db === 'undefined') return;
    const u = Store.get('user');
    if (!u || u.isAdmin || u.guest) return;
    const uid = firebaseUserId();
    if (!uid || uid === 'guest') return;
    // Expect a cloud snapshot shortly; show skeletons until it lands (≤4s safety net).
    _cloudSyncPending = true;
    if (_cloudSyncTimeout) clearTimeout(_cloudSyncTimeout);
    _cloudSyncTimeout = setTimeout(() => { _cloudSyncPending = false; syncAchievementsStrip(); }, 4000);
    syncAchievementsStrip();
    USTORE_SYNC_KEYS.forEach(k => {
      const ref = _db.ref(`users/${uid}/${k}`);
      let firstFire = true;
      const handler = snap => {
        const val = snap.val();
        // First fire: if cloud empty, seed from local
        if (firstFire) {
          firstFire = false;
          if (val === null || val === undefined) {
            const local = UStore.get(k, null);
            if (local !== null && local !== undefined) pushUserField(k, local);
            settleCloudSync(); // cloud reachable but empty for this key → drop skeletons
            return;
          }
        }
        if (val === null || val === undefined) return;
        let value = val;
        if (k === 'unlocks') value = Array.isArray(val) ? val : Object.values(val);
        _skipCloudPush = true;
        try {
          // For stats: smart-merge so cloud doesn't clobber unpushed local progress
          // (e.g. user did addXp and refreshed within the 400 ms debounce window —
          // cloud still has yesterday's stats and would otherwise wipe today's gain)
          if (k === 'stats') {
            const before = UStore.get('stats', null) || {};
            const today = (typeof todayIsoDate === 'function') ? todayIsoDate() : new Date().toISOString().slice(0, 10);
            let merged = { ...value };
            // If local has strictly more XP, local is fresher — keep it as the base
            if ((before.xp || 0) > (merged.xp || 0)) merged = { ...before };
            // Preserve today's daily progress
            if (before.dailyDate === today) {
              merged.dailyDate = today;
              merged.dailyXp = Math.max(before.dailyXp || 0, merged.dailyXp || 0);
            }
            if (before.dailyGoal && !merged.dailyGoal) merged.dailyGoal = before.dailyGoal;
            if (Array.isArray(before.dailyGoalReachedDates) && before.dailyGoalReachedDates.length) {
              const s = new Set([...(merged.dailyGoalReachedDates || []), ...before.dailyGoalReachedDates]);
              merged.dailyGoalReachedDates = [...s];
            }
            // Preserve dates union so streak doesn't shrink from a stale cloud snapshot
            if (Array.isArray(before.dates) && before.dates.length) {
              const s = new Set([...(Array.isArray(merged.dates) ? merged.dates : []), ...before.dates]);
              merged.dates = [...s].sort();
            }
            value = merged;
            UStore.set(k, value);
            Object.keys(stats).forEach(s => delete stats[s]);
            Object.assign(stats, defaultStats(), value);
            if (!Array.isArray(stats.dates))         stats.dates         = stats.dates         ? Object.values(stats.dates)         : [];
            if (!Array.isArray(stats.wordsLearned))  stats.wordsLearned  = stats.wordsLearned  ? Object.values(stats.wordsLearned)  : [];
            if (!stats.gamePlays    || typeof stats.gamePlays    !== 'object') stats.gamePlays    = {};
            if (!stats.perfectGames || typeof stats.perfectGames !== 'object') stats.perfectGames = {};
            syncStats();
            syncBestScoreCards();
            syncAchievementsStrip();
            renderDailyGoal();
            settleCloudSync();      // real data landed → drop skeletons
            scheduleAchReconcile(); // reconcile unlocks to loaded progress, silently
            // Push merged back so cloud catches up with the local fields it was missing
            if (JSON.stringify(merged) !== JSON.stringify(val)) {
              _skipCloudPush = false;
              pushUserField('stats', merged);
              _skipCloudPush = true;
            }
          } else { UStore.set(k, value); }
          if (k === 'avatar') {
            applyAvatar(value);
          } else if (k === 'unlocks') {
            syncAchievementsStrip();
            settleCloudSync();
            scheduleAchReconcile();
          } else if (k === 'lessonProgress' || k === 'lessonProgress_m2') {
            renderLessonPath();
            renderHeroLesson();
          } else if (k === 'bestScores') {
            syncBestScoreCards();
          }
        } finally {
          _skipCloudPush = false;
        }
      };
      ref.on('value', handler);
      _userListeners.push(() => ref.off('value', handler));
    });
    // Доступ ученицы (оплата/заморозка) — управляется из админ-панели
    const accRef = _db.ref(`users/${uid}/access`);
    const accHandler = snap => applyAccessGate(snap.val());
    accRef.on('value', accHandler);
    _userListeners.push(() => { accRef.off('value', accHandler); applyAccessGate(null); });
    // Тариф (free/master/proai) — Мади назначает из админки, тут подхватываем
    const planRef = _db.ref(`users/${uid}/plan`);
    const planHandler = snap => {
      const v = snap.val();
      if (v && PLANS[v.id]) { _skipCloudPush = true; try { UStore.set('plan', v); } finally { _skipCloudPush = false; } }
      renderPlanCard();
    };
    planRef.on('value', planHandler);
    _userListeners.push(() => planRef.off('value', planHandler));
  }

  // ── Экран «доступ приостановлен»: не оплачено (⛔) или заморозка (❄️) ──
  function applyAccessGate(access) {
    const status = access && access.status;
    const gate = document.getElementById('access-gate');
    if (status !== 'unpaid' && status !== 'frozen') { gate?.remove(); return; }
    const frozen = status === 'frozen';
    const html = `
      <div style="max-width:340px; text-align:center; padding:32px 24px;">
        <div style="font-size:54px;">${frozen ? '❄️' : '🌙'}</div>
        <div class="display" style="font-size:24px; color:var(--berry); margin-top:14px; line-height:1.2;">${frozen ? 'Занятия на паузе' : 'Доступ приостановлен'}</div>
        <div style="font-size:13.5px; color:var(--soft); margin-top:10px; line-height:1.6;">
          ${frozen
            ? 'Твой доступ временно заморожен. Напиши Мади, когда будешь готова продолжить — всё сохранится: XP, стрик и прогресс 🌸'
            : 'Похоже, занятия ещё не оплачены. Напиши Мади, чтобы продолжить обучение — прогресс никуда не денется 🌸'}
        </div>
        <div class="ko" style="font-size:13px; color:var(--coral); margin-top:14px;">곧 다시 만나요! · До скорой встречи!</div>
        <button onclick="logoutUser(); document.getElementById('access-gate')?.remove();" class="btn btn-ghost btn-block" style="margin-top:22px;">Выйти из аккаунта</button>
      </div>`;
    if (gate) { gate.firstElementChild?.remove(); gate.insertAdjacentHTML('beforeend', html); return; }
    const el = document.createElement('div');
    el.id = 'access-gate';
    el.style.cssText = 'position:fixed; inset:0; z-index:12000; background:var(--linen); display:flex; align-items:center; justify-content:center; overflow-y:auto;';
    el.innerHTML = html;
    document.body.appendChild(el);
  }

  // ════════════════════════ ТАРИФЫ (free / master / proai) ════════════════════════
  // Хранение: UStore 'plan' = { id, period: 'monthly'|'yearly', since, updatedAt, by }.
  // Синк: users/<uid>/plan (слушатель в attachUserListeners, запись через pushUserField).
  // Оплаты в клиенте НЕТ (статичный сайт без бэкенда) — платный тариф подключает Мади
  // вручную из админки; кнопка «Подключить» отправляет ей сообщение в чат.
  const PLANS = {
    free: {
      id: 'free', name: 'Базовый', emoji: '🌱', tagline: 'Старт в корейском',
      priceM: 0, features: [
        'Все уроки хангыля и первые слова',
        'Мини-игры и Hangul Lab',
        'Личный словарик, стрики и достижения',
        'Чат с друзьями и учителем'
      ]
    },
    master: {
      id: 'master', name: 'Master', emoji: '🌸', tagline: 'Полный курс без границ',
      priceM: 10, priceYM: 8, priceY: 99, firstM: 5, features: [
        'Всё из Базового',
        'TOPIK I и TOPIK II — полные тренажёры с разборами',
        'K-Pop Fill — учим корейский по любимым песням',
        'Архив реальных экзаменов с аудио',
        'Домашние задания с проверкой от Мади'
      ]
    },
    proai: {
      id: 'proai', name: 'Pro AI', emoji: '✨', tagline: 'Максимум + личный ИИ',
      priceM: 18, priceYM: 16, priceY: 199, firstM: 9, features: [
        'Всё из Master',
        'ИИ-репетитор 24/7 — урок с ИИ в любое время',
        'ИИ-словарь: примеры, синонимы, похожие слова',
        'Объяснение ошибок и подсказки от ИИ'
      ]
    }
  };
  const PLAN_ORDER = { free: 0, master: 1, proai: 2 };
  function myPlanObj() {
    const p = UStore.get('plan', null);
    return (p && PLANS[p.id]) ? p : { id: 'free', period: 'monthly' };
  }
  function myPlanId() {
    const u = Store.get('user');
    if (u && u.isAdmin) return 'proai'; // у Мади открыто всё
    return myPlanObj().id;
  }
  function planAtLeast(want) { return PLAN_ORDER[myPlanId()] >= PLAN_ORDER[want]; }
  // Гейт функции: true — можно; false — показана апселл-модалка.
  function requirePlan(want, featureLabel) {
    if (planAtLeast(want)) return true;
    showPlanUpsell(want, featureLabel);
    return false;
  }
  function setMyPlan(id, period, by) {
    if (!PLANS[id]) return;
    const plan = { id, period: period || 'monthly', since: (myPlanObj().id === id ? myPlanObj().since : Date.now()) || Date.now(), updatedAt: Date.now(), by: by || 'self' };
    UStore.set('plan', plan);
    pushUserField('plan', plan);
    renderPlanCard();
  }
  function planPriceLine(p, period) {
    if (p.id === 'free') return '<span class="plan-price">0 $</span><span class="plan-price-sub">навсегда</span>';
    if (period === 'yearly') {
      return `<span class="plan-price">${p.priceYM} $<i>/мес</i></span><span class="plan-price-sub">${p.priceY} $ в год · выгода ${p.priceM * 12 - p.priceY} $</span>`;
    }
    return `<span class="plan-price">${p.priceM} $<i>/мес</i></span><span class="plan-price-sub">первый месяц ${p.firstM} $ · −50%</span>`;
  }

  // Карточка «Мой тариф» в профиле
  function renderPlanCard() {
    const slot = document.getElementById('profile-plan-slot');
    if (!slot) return;
    const u = Store.get('user');
    if (!u || u.isAdmin) { slot.innerHTML = ''; return; }
    const cur = PLANS[myPlanId()];
    const isFree = cur.id === 'free';
    slot.innerHTML = `
      <div onclick="openPlanPage()" class="card card-press card-padded plan-profile-card ${isFree ? '' : 'plan-profile-paid'}" style="cursor:pointer; display:flex; align-items:center; gap:13px;">
        <div class="plan-profile-ico">${cur.emoji}</div>
        <div style="flex:1; min-width:0;">
          <div style="font-weight:700; font-size:14.5px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">Тариф ${cur.name}${isFree ? '' : ' <span style="color:var(--ok-ink); font-size:11px;">· активен ✓</span>'}</div>
          <div style="font-size:11px; opacity:.8; margin-top:2px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${isFree ? 'Открой TOPIK, K-Pop и ИИ-репетитора' : cur.tagline}</div>
        </div>
        <span class="chip ${isFree ? 'chip-coral' : 'chip-blush'}" style="font-size:10px; flex-shrink:0; white-space:nowrap;">${isFree ? 'Улучшить ✨' : 'Сменить →'}</span>
      </div>`;
    // Компактный индикатор активного тарифа вверху профиля
    const top = document.getElementById('profile-plan-top');
    if (top) {
      top.innerHTML = `<button onclick="openPlanPage()" class="profile-plan-chip ${isFree ? '' : 'paid'}" type="button">
        <span>${cur.emoji}</span> Тариф ${cur.name}${isFree ? '' : ' · активен'} <i class="fa-solid fa-chevron-right" style="font-size:9px; opacity:.7;"></i>
      </button>`;
    }
  }

  // Полноэкранная страница тарифов
  let _planPeriod = 'yearly';
  function openPlanPage(highlight) {
    document.getElementById('plan-page')?.remove();
    const el = document.createElement('div');
    el.className = 'plan-page';
    el.id = 'plan-page';
    el.innerHTML = `<div class="plan-page-inner" id="plan-page-inner"></div>`;
    document.body.appendChild(el);
    document.body.classList.add('chat-open'); // прячем нижнюю навигацию
    _renderPlanPage(highlight);
  }
  function closePlanPage() {
    document.getElementById('plan-page')?.remove();
    if (!document.getElementById('chat-page')) document.body.classList.remove('chat-open');
  }
  function setPlanPeriod(p) { _planPeriod = p; _renderPlanPage(); }
  function _renderPlanPage(highlight) {
    const root = document.getElementById('plan-page-inner');
    if (!root) return;
    const curId = myPlanId();
    const yearly = _planPeriod === 'yearly';
    const planCard = p => {
      const isCur = p.id === curId;
      const featured = p.id === 'proai'; // акцент на Pro AI — наш флагман
      const hl = highlight === p.id;
      let cta;
      if (isCur) {
        cta = `<button class="btn btn-ghost btn-block" disabled style="opacity:.7;">✓ Твой тариф</button>`;
      } else if (p.id === 'free') {
        cta = `<button onclick="selectPlan('free')" class="btn btn-ghost btn-block">Перейти на Базовый</button>`;
      } else {
        cta = `<button onclick="selectPlan('${p.id}')" class="btn ${featured ? 'btn-primary' : 'btn-rose'} btn-block">${p.emoji} Подключить ${p.name}</button>`;
      }
      const ribbon = featured ? '<div class="plan-ribbon">✨ Выбор Мади · с ИИ</div>'
        : (p.id === 'master' ? '<div class="plan-ribbon plan-ribbon-soft">Популярный</div>' : '');
      const mascot = featured ? `<img class="plan-mascot" src="assets/bear5.png" alt="" onerror="this.style.display='none'">` : '';
      return `
        <div class="plan-card ${featured ? 'plan-featured' : ''} ${isCur ? 'plan-current' : ''} ${hl ? 'plan-highlight' : ''}">
          ${ribbon}
          ${isCur ? '<div class="plan-current-badge">сейчас активен ✓</div>' : ''}
          ${mascot}
          <div class="plan-head">
            <span class="plan-emoji">${p.emoji}</span>
            <div>
              <div class="plan-name">${p.name}</div>
              <div class="plan-tagline">${p.tagline}</div>
            </div>
          </div>
          <div class="plan-price-row">${planPriceLine(p, _planPeriod)}</div>
          ${p.id !== 'free' && !yearly ? `<div class="plan-promo">🎁 Первый месяц −50% — всего ${p.firstM} $</div>` : ''}
          ${p.id !== 'free' && yearly ? `<div class="plan-promo">🎁 Годовая со скидкой: ${p.priceY} $ вместо ${p.priceM * 12} $</div>` : ''}
          <ul class="plan-features">
            ${p.features.map(f => `<li><i class="fa-solid fa-check"></i><span>${f}</span></li>`).join('')}
          </ul>
          ${cta}
        </div>`;
    };
    root.innerHTML = `
      <div class="plan-topbar">
        <button onclick="closePlanPage()" class="chat-back-btn" aria-label="Назад"><i class="fa-solid fa-arrow-left"></i></button>
        <div style="flex:1; text-align:center;">
          <div class="page-eyebrow">KOREAN WITH MADIE</div>
          <div class="display" style="font-size:19px; color:var(--berry);">Тарифы</div>
        </div>
        <div style="width:36px;"></div>
      </div>
      <div class="plan-period-toggle" role="tablist">
        <button role="tab" aria-selected="${!yearly}" class="plan-period-btn ${yearly ? '' : 'active'}" onclick="setPlanPeriod('monthly')">Помесячно</button>
        <button role="tab" aria-selected="${yearly}" class="plan-period-btn ${yearly ? 'active' : ''}" onclick="setPlanPeriod('yearly')">Годовая <span class="plan-save-chip">выгоднее</span></button>
      </div>
      <div class="plan-cards">
        ${planCard(PLANS.free)}${planCard(PLANS.master)}${planCard(PLANS.proai)}
      </div>
      <div class="plan-footnote">Оплата проходит через Мади — после запроса она напишет тебе в чат и подключит тариф 🌸</div>`;
  }

  // Выбор тарифа: free — сразу; платный — заявка Мади в чат (без оплат в клиенте)
  async function selectPlan(id) {
    if (id === 'free') {
      if (!confirm('Перейти на Базовый? Платные функции закроются.')) return;
      setMyPlan('free', 'monthly', 'self');
      _renderPlanPage();
      toast('Тариф Базовый включён 🌱');
      return;
    }
    const u = Store.get('user');
    if (!u || u.guest) { toast('Сначала войди в аккаунт 🌸'); return; }
    const p = PLANS[id];
    const periodLabel = _planPeriod === 'yearly' ? `годовая (${p.priceY} $/год)` : `помесячно (${p.priceM} $/мес, первый месяц ${p.firstM} $)`;
    // Подтверждение у ученика перед отправкой заявки
    if (!confirm(`Отправить Мади заявку на тариф ${p.emoji} ${p.name} — ${periodLabel}?`)) return;
    try {
      if (!_usersDirCache) await loadUsersDirectory();
      const adminEntry = Object.entries(_usersDirCache || {}).find(([, v]) => v && v.isAdmin);
      if (!adminEntry) { toast('Не нашла учителя — напиши через «Написать нам» 💌'); return; }
      const [adminUid, adminInfo] = adminEntry;
      await sendChatMessage(adminUid, adminInfo.name || 'Мади',
        `Хочу подключить тариф ${p.emoji} ${p.name} — ${periodLabel} 🌸`);
      closePlanPage();
      switchScreen('social');
      openChat(adminUid, adminInfo.name || 'Мади');
      toast('Заявка отправлена Мади 💌', 'var(--sage)');
    } catch (e) {
      console.warn(e);
      toast('Не получилось отправить заявку — попробуй ещё раз');
    }
  }

  // Апселл при закрытой функции
  function showPlanUpsell(want, featureLabel) {
    const p = PLANS[want];
    document.getElementById('plan-upsell-modal')?.remove();
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.id = 'plan-upsell-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:360px; text-align:center;">
        <div class="plan-upsell-emoji">${p.emoji}</div>
        <div class="display" style="font-size:21px; color:var(--berry); margin-top:10px;">${escHtml(featureLabel || 'Эта функция')} — в тарифе ${p.name}</div>
        <div style="font-size:12.5px; color:var(--soft); margin-top:8px; line-height:1.6;">
          Открой ${p.name} — ${p.tagline.toLowerCase()}. ${want === 'proai' ? 'ИИ-репетитор, умный словарь и объяснения ошибок.' : 'TOPIK-тренажёры, K-Pop Fill и архив экзаменов.'}
        </div>
        <div class="plan-upsell-price">от ${_planPeriod === 'yearly' ? p.priceYM : p.firstM} $<i>/мес</i></div>
        <button onclick="this.closest('.modal-bg').remove(); openPlanPage('${want}')" class="btn btn-primary btn-block" style="margin-top:6px;">Смотреть тарифы ✨</button>
        <button onclick="this.closest('.modal-bg').remove()" class="btn btn-ghost btn-block" style="margin-top:8px;">Позже</button>
      </div>`;
    document.body.appendChild(m);
  }

  function initFirebaseSync() {
    if (typeof _db === 'undefined') return;
    applyUStoreCloudSync();
    SHARED_KEYS.forEach(key => {
      let firstFire = true;
      _db.ref('shared/' + key).on('value', snap => {
        const val = snap.val();
        // Seed cloud from local on first fire if cloud is empty
        if (firstFire) {
          firstFire = false;
          if (val === null || val === undefined) {
            const local = Store.get(key, []);
            if (Array.isArray(local) && local.length > 0) {
              _db.ref('shared/' + key).set(local).catch(e => console.warn('seed shared/'+key+' failed:', e));
            }
            return;
          }
        }
        let data = [];
        if (val !== null && val !== undefined) {
          data = Array.isArray(val) ? val : Object.values(val);
        }
        _origStoreSet(key, data);
        if (key === 'customFeedPosts') renderCustomFeedPosts();
        if (key === 'customVideos') renderCustomVideos();
        if (key === 'customLessons') { renderCustomLessons(); renderHeroLesson(); renderLessonPath(); }
        if (key === 'topikMaterials' && document.getElementById('screen-topik')?.classList.contains('active')) renderTopik();
      });
    });
  }
  // ── Friends & Chat ──
  let _friendsCache = {};
  let _inboxCache = {};
  let _outgoingCache = {};
  let _groupsCache = {};   // gid -> {title, since} (my group chats, users/<me>/groups)
  let _usersDirCache = null;
  let _chatListenerOff = null;
  let _chatCurrentId = null;
  let _chatOtherUid = null;        // uid of the person in the open chat (for read receipts); gid for groups
  let _chatIsGroup = false;        // открыт групповой чат
  let _chatMembers = {};           // group: uid -> name (typing line + sender labels)
  let _chatReadMeta = {};          // chats/{id}/meta/read → { uid: lastReadTs }
  let _lastChatMsgs = {};          // last messages snapshot (so reactions/ticks re-render)
  let _chatReplyTo = null;         // { id, text, from, fromName } when replying
  // Telegram-Premium chat FX state
  let _chatSeenKeys = null;        // Set of message keys already painted (null = first paint, no entrance anim)
  let _chatPrevReactions = {};     // mid -> { uid: emoji } from the previous render (for burst diff)
  let _chatTyping = {};            // chats/{id}/meta/typing → { uid: ts } (other side typing)
  let _typingWriteAt = 0;          // throttle for my own typing writes
  let _typingClearTimer = null;    // clears my typing flag after a pause
  let _sendingFriendReq = new Set();
  function myUid() { return firebaseUserId(); }
  function myName() { const u = Store.get('user'); return (u && u.name) || 'Без имени'; }
  function chatIdFor(a, b) { return [a, b].sort().join('__'); }

  function escHtml(s) {
    return String(s || '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
  // Safe to drop inside a single-quoted JS string that itself lives inside a
  // double-quoted HTML attribute (e.g. onclick="fn('…')"). Escapes the JS-string
  // delimiter, backslashes, the attribute delimiter and line breaks.
  function jsStr(s) {
    return String(s == null ? '' : s)
      .replace(/\\/g, '\\\\')
      .replace(/'/g, "\\'")
      .replace(/"/g, '&quot;')
      .replace(/[\r\n]+/g, ' ');
  }

  async function loadUsersDirectory() {
    if (typeof _db === 'undefined') return {};
    try {
      const snap = await _db.ref('users').once('value');
      _usersDirCache = snap.val() || {};
      return _usersDirCache;
    } catch (e) { console.warn('users dir load', e); return {}; }
  }

  async function searchUsersByName(q) {
    const dir = _usersDirCache || await loadUsersDirectory();
    const me = myUid();
    const qq = (q || '').toLowerCase().trim();
    return Object.entries(dir)
      .map(([uid, u]) => ({ uid, ...u }))
      .filter(u => u.uid !== me)
      .filter(u => !qq || (u.name || '').toLowerCase().includes(qq) || (u.email || '').toLowerCase().includes(qq))
      .sort((a, b) => (b.lastSeen || 0) - (a.lastSeen || 0))
      .slice(0, 40);
  }

  async function sendFriendRequest(toUid, toName) {
    if (typeof _db === 'undefined') { toast('Нет связи с сервером'); return; }
    const me = myUid();
    if (!me || me === 'guest') { toast('Войди, чтобы добавлять друзей'); return; }
    if (me === toUid) { toast('Нельзя добавить себя 🌸'); return; }
    if (_sendingFriendReq.has(toUid)) return;       // Уже отправляем — игнор спама
    if (_outgoingCache[toUid])        { toast('Заявка уже отправлена ⏳'); return; }
    if (_friendsCache[toUid])         { toast('Уже в друзьях'); return; }
    _sendingFriendReq.add(toUid);
    if (document.getElementById('add-friend-modal')) filterAddFriend();
    try {
      const existingFr = await _db.ref(`users/${me}/friends/${toUid}`).once('value');
      if (existingFr.exists()) { toast('Уже в друзьях'); return; }
      const existingOut = await _db.ref(`users/${me}/outgoing/${toUid}`).once('value');
      if (existingOut.exists()) { toast('Заявка уже отправлена ⏳'); return; }
      const ref = _db.ref(`users/${toUid}/inbox`).push();
      const updates = {};
      updates[`users/${toUid}/inbox/${ref.key}`] = {
        type: 'friend_request',
        from: me,
        fromName: myName(),
        at: Date.now()
      };
      updates[`users/${me}/outgoing/${toUid}`] = {
        name: toName || '',
        at: Date.now(),
        inboxKey: ref.key
      };
      await _db.ref().update(updates);
      toast('Заявка отправлена 🌸', 'var(--sage)');
    } catch (e) {
      console.warn('sendFriendRequest failed:', e);
      toast('Не удалось отправить: ' + (e.code || e.message || 'ошибка'));
    } finally {
      _sendingFriendReq.delete(toUid);
      if (document.getElementById('add-friend-modal')) filterAddFriend();
    }
  }

  async function cancelFriendRequest(toUid) {
    const me = myUid();
    if (typeof _db === 'undefined') return;
    const outRef = _db.ref(`users/${me}/outgoing/${toUid}`);
    const snap = await outRef.once('value');
    const data = snap.val();
    const updates = {};
    updates[`users/${me}/outgoing/${toUid}`] = null;
    if (data && data.inboxKey) {
      updates[`users/${toUid}/inbox/${data.inboxKey}`] = null;
    }
    try {
      await _db.ref().update(updates);
      toast('Заявка отменена');
      if (document.getElementById('add-friend-modal')) filterAddFriend();
    } catch (e) { console.warn(e); toast('Не получилось отменить'); }
  }

  async function acceptFriendRequest(reqKey, fromUid, fromName) {
    const me = myUid();
    const now = Date.now();
    const updates = {};
    updates[`users/${me}/friends/${fromUid}`] = { name: fromName, since: now };
    updates[`users/${fromUid}/friends/${me}`] = { name: myName(), since: now };
    updates[`users/${me}/inbox/${reqKey}`] = null;
    // Clean up the sender's outgoing record now that we're friends
    updates[`users/${fromUid}/outgoing/${me}`] = null;
    try {
      await _db.ref().update(updates);
      toast('Теперь вы друзья 💗', 'var(--sage)');
    } catch (e) { console.warn(e); toast('Не получилось — попробуй ещё раз'); }
  }

  async function declineFriendRequest(reqKey, fromUid) {
    const me = myUid();
    const updates = {};
    updates[`users/${me}/inbox/${reqKey}`] = null;
    if (fromUid) updates[`users/${fromUid}/outgoing/${me}`] = null;
    try { await _db.ref().update(updates); } catch (_) {}
  }

  async function removeFriend(friendUid) {
    if (!confirm('Удалить друга? История чата сохранится.')) return;
    const me = myUid();
    const updates = {};
    updates[`users/${me}/friends/${friendUid}`] = null;
    updates[`users/${friendUid}/friends/${me}`] = null;
    try {
      await _db.ref().update(updates);
      toast('Удалён из друзей');
    } catch (e) { console.warn(e); }
  }

  async function sendChatMessage(otherUid, otherName, text, replyTo) {
    text = (text || '').trim();
    if (!text) return;
    if (text.length > 2000) text = text.slice(0, 2000);
    if (typeof _db === 'undefined') throw new Error('Нет связи с сервером');
    const me = myUid();
    if (!me || me === 'guest') throw new Error('Войди в аккаунт');
    const chatId = chatIdFor(me, otherUid);
    const now = Date.now();
    const updates = {};
    const newRef = _db.ref(`chats/${chatId}/messages`).push();
    const msg = { from: me, fromName: myName(), text, at: now };
    if (replyTo && replyTo.id) {
      msg.replyTo = {
        id: replyTo.id,
        text: String(replyTo.text || '').slice(0, 200),
        from: replyTo.from || '',
        fromName: replyTo.fromName || ''
      };
    }
    updates[`chats/${chatId}/messages/${newRef.key}`] = msg;
    updates[`chats/${chatId}/meta/members/${me}`] = true;
    updates[`chats/${chatId}/meta/members/${otherUid}`] = true;
    updates[`chats/${chatId}/meta/lastMessage`] = text.slice(0, 140);
    updates[`chats/${chatId}/meta/lastAt`] = now;
    updates[`chats/${chatId}/meta/lastFrom`] = me;
    updates[`chats/${chatId}/meta/lastFromName`] = myName();
    // My own read pointer moves forward (I just wrote, so I've seen up to now).
    updates[`chats/${chatId}/meta/read/${me}`] = now;
    // Bump the unread COUNTER on the other side (Telegram-style number, not just a dot).
    updates[`users/${otherUid}/unreadFrom/${me}`] = firebase.database.ServerValue.increment(1);
    // Auto-friend on first contact (covers admin→student first message).
    // No-op idempotent overwrite if already friends.
    if (!_friendsCache || !_friendsCache[otherUid]) {
      updates[`users/${me}/friends/${otherUid}`]   = { name: otherName || '', since: now };
      updates[`users/${otherUid}/friends/${me}`]   = { name: myName(),       since: now };
      // Clear any pending request leftovers between these two users
      updates[`users/${me}/outgoing/${otherUid}`]  = null;
      updates[`users/${otherUid}/outgoing/${me}`]  = null;
    }
    await _db.ref().update(updates);
    bumpChatActivity(otherUid, now); // my outgoing message also surfaces the chat
  }

  // ── Group chat: send a message to chats/<gid> and bump unread for every member ──
  async function sendGroupMessage(gid, text, replyTo) {
    text = (text || '').trim();
    if (!text) return;
    if (text.length > 2000) text = text.slice(0, 2000);
    if (typeof _db === 'undefined') throw new Error('Нет связи с сервером');
    const me = myUid();
    if (!me || me === 'guest') throw new Error('Войди в аккаунт');
    const now = Date.now();
    const updates = {};
    const newRef = _db.ref(`chats/${gid}/messages`).push();
    const msg = { from: me, fromName: myName(), text, at: now };
    if (replyTo && replyTo.id) {
      msg.replyTo = {
        id: replyTo.id,
        text: String(replyTo.text || '').slice(0, 200),
        from: replyTo.from || '',
        fromName: replyTo.fromName || ''
      };
    }
    updates[`chats/${gid}/messages/${newRef.key}`] = msg;
    updates[`chats/${gid}/meta/lastMessage`] = text.slice(0, 140);
    updates[`chats/${gid}/meta/lastAt`] = now;
    updates[`chats/${gid}/meta/lastFrom`] = me;
    updates[`chats/${gid}/meta/lastFromName`] = myName();
    updates[`chats/${gid}/meta/read/${me}`] = now;
    // Unread counter for every member except me (key = gid, just like DM keys by uid).
    let members = Object.keys(_chatMembers || {});
    if (!members.length) {
      // члены ещё не подгрузились (медленная сеть) — дочитываем напрямую
      try {
        const snap = await _db.ref(`chats/${gid}/meta/members`).once('value');
        members = Object.keys(snap.val() || {});
      } catch (_) {}
    }
    members.forEach(uid => {
      if (uid !== me) updates[`users/${uid}/unreadFrom/${gid}`] = firebase.database.ServerValue.increment(1);
    });
    await _db.ref().update(updates);
    bumpChatActivity(gid, now);
  }

  // ── Group chat: creation ──
  function openCreateGroupModal() {
    if (!isLoggedInForChat()) { toast('Войди в аккаунт, чтобы создавать группы'); return; }
    // Admin invites any student; a student invites their friends.
    let friends;
    if (isAdmin()) {
      const dir = _usersDirCache || {};
      const me = myUid();
      friends = {};
      Object.keys(dir).forEach(uid => {
        if (uid !== me && !(dir[uid] && dir[uid].isAdmin)) friends[uid] = { name: dir[uid].name || 'Ученица' };
      });
    } else {
      friends = _friendsCache || {};
    }
    const fids = Object.keys(friends);
    if (!fids.length) { toast(isAdmin() ? 'Учеников пока нет 🌸' : 'Сначала добавь друзей 🌸'); return; }
    _groupPhoto = null;
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.id = 'create-group-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:380px;">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:14px;">
          <div>
            <div class="page-eyebrow">НОВАЯ ГРУППА</div>
            <div class="display" style="font-size:20px;color:var(--berry);margin-top:2px;">Групповой чат</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:24px;color:var(--soft);cursor:pointer;line-height:1;padding:2px 6px;">×</div>
        </div>
        <div style="display:flex;align-items:center;gap:13px;margin-bottom:12px;">
          <button type="button" id="group-photo-btn" onclick="document.getElementById('group-photo-file').click()" class="group-photo-pick" aria-label="Фото группы">
            <i class="fa-solid fa-camera"></i>
          </button>
          <input type="file" accept="image/*" id="group-photo-file" style="display:none;" onchange="onGroupPhotoPick(event)">
          <div style="flex:1;min-width:0;">
            <input id="group-title-input" class="input" placeholder="Название группы…" maxlength="60" style="font-size:14px;">
          </div>
        </div>
        <textarea id="group-desc-input" class="input" rows="2" placeholder="Описание (необязательно)…" maxlength="200" style="font-size:13px;resize:vertical;margin-bottom:4px;"></textarea>
        <div style="font-size:10px;letter-spacing:.18em;color:var(--soft);margin:14px 2px 8px;">УЧАСТНИКИ</div>
        <div id="group-member-list" style="display:grid;gap:6px;max-height:260px;overflow-y:auto;">
          ${fids.map(uid => {
            const nm = (friends[uid] && friends[uid].name) || 'Друг';
            const dir = (_usersDirCache && _usersDirCache[uid]) || {};
            const av = dir.avatar
              ? `<div class="chat-row-av" style="width:34px;height:34px;background:url(${dir.avatar}) center/cover no-repeat;"></div>`
              : `<div class="chat-row-av chat-row-av-initial" style="width:34px;height:34px;font-size:13px;">${escHtml(nm.charAt(0).toUpperCase())}</div>`;
            return `
              <label class="group-pick-row">
                ${av}
                <span style="flex:1;font-size:13px;font-weight:600;color:var(--berry);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escHtml(nm)}</span>
                <input type="checkbox" class="group-pick-check" value="${escHtml(uid)}">
                <span class="group-pick-mark"><i class="fa-solid fa-check"></i></span>
              </label>`;
          }).join('')}
        </div>
        <button onclick="createGroupChat()" class="btn btn-primary btn-block" style="margin-top:16px;"><i class="fa-solid fa-user-group" style="font-size:11px;"></i> Создать группу</button>
      </div>`;
    document.body.appendChild(m);
    setTimeout(() => { document.getElementById('group-title-input')?.focus(); }, 80);
  }

  let _groupPhoto = null; // временный dataURL фото при создании группы
  async function onGroupPhotoPick(ev) {
    const file = ev.target.files && ev.target.files[0];
    if (!file) return;
    try {
      _groupPhoto = await compressImageFile(file, 256, 0.8);
      const btn = document.getElementById('group-photo-btn');
      if (btn) { btn.style.background = `url(${_groupPhoto}) center/cover no-repeat`; btn.innerHTML = ''; }
    } catch (_) { toast('Не получилось загрузить фото'); }
  }
  async function createGroupChat() {
    const titleInp = document.getElementById('group-title-input');
    const title = ((titleInp && titleInp.value) || '').trim();
    const desc = (document.getElementById('group-desc-input')?.value || '').trim();
    const picked = [...document.querySelectorAll('#group-member-list .group-pick-check:checked')].map(c => c.value);
    if (!title) { toast('Дай группе название 🌸'); titleInp?.focus(); return; }
    if (!picked.length) { toast('Выбери хотя бы одного участника'); return; }
    if (typeof _db === 'undefined') { toast('Нет связи с сервером'); return; }
    const me = myUid();
    const now = Date.now();
    const gid = 'g_' + _db.ref('chats').push().key;
    const members = { [me]: true };
    picked.forEach(uid => { members[uid] = true; });
    const updates = {};
    updates[`chats/${gid}/meta`] = {
      group: true, title, desc: desc || null, photo: _groupPhoto || null,
      members, owner: me, createdAt: now,
      lastMessage: '', lastAt: now, lastFrom: '', lastFromName: '',
      read: { [me]: now }
    };
    Object.keys(members).forEach(uid => {
      updates[`users/${uid}/groups/${gid}`] = { title, since: now };
    });
    // Системное сообщение о создании + участниках
    const sysKey = _db.ref(`chats/${gid}/messages`).push().key;
    updates[`chats/${gid}/messages/${sysKey}`] = { type: 'system', text: `${myName()} создал(а) группу «${title}»`, at: now };
    try {
      await _db.ref().update(updates);
      _groupPhoto = null;
      document.getElementById('create-group-modal')?.remove();
      toast(`Группа «${title}» создана 🎉`, 'var(--sage)');
      openGroupChat(gid, title);
    } catch (e) { console.warn(e); toast('Не получилось создать группу'); }
  }

  // ── Typing indicator (Telegram-style "печатает…") ──
  function signalTyping() {
    const me = myUid(); const chatId = _chatCurrentId;
    if (!me || me === 'guest' || !chatId || typeof _db === 'undefined') return;
    const now = Date.now();
    if (now - _typingWriteAt > 2200) {           // throttle writes
      _typingWriteAt = now;
      try { _db.ref(`chats/${chatId}/meta/typing/${me}`).set(now); } catch (_) {}
    }
    if (_typingClearTimer) clearTimeout(_typingClearTimer);
    _typingClearTimer = setTimeout(stopTyping, 3500); // auto-clear after a pause
  }
  function stopTyping() {
    if (_typingClearTimer) { clearTimeout(_typingClearTimer); _typingClearTimer = null; }
    _typingWriteAt = 0;
    const me = myUid(); const chatId = _chatCurrentId;
    if (!me || me === 'guest' || !chatId || typeof _db === 'undefined') return;
    try { _db.ref(`chats/${chatId}/meta/typing/${me}`).remove(); } catch (_) {}
  }

  // ── Emoji picker for the chat input ──
  const CHAT_EMOJIS = ['😀','😂','🥹','😊','😍','😘','🥰','😎','🤗','😅','😴','😭','😱','🥳','😡','👍','👎','👏','🙏','💪','🔥','✨','🎉','💯','❤️','🧡','💛','💚','💙','💜','🤍','💔','🌸','🌺','🌷','🌼','🐰','🐻','🐱','🍓','🍡','☕','🎮','📚','✅','💖'];
  function closeEmojiPanel() {
    const panel = document.getElementById('chat-emoji-panel');
    const btn = document.getElementById('chat-emoji-btn');
    if (panel) panel.style.display = 'none';
    if (btn) btn.classList.remove('active');
  }
  function toggleEmojiPicker() {
    const panel = document.getElementById('chat-emoji-panel');
    const btn = document.getElementById('chat-emoji-btn');
    if (!panel) return;
    if (panel.style.display !== 'none') { closeEmojiPanel(); return; }
    if (!panel.dataset.filled) {
      panel.innerHTML = CHAT_EMOJIS.map(e => `<button type="button" class="emoji-cell" onclick="insertEmoji('${e}')">${e}</button>`).join('');
      panel.dataset.filled = '1';
    }
    panel.style.display = 'flex';
    if (btn) btn.classList.add('active');
  }
  function insertEmoji(em) {
    const inp = document.getElementById('chat-input');
    if (!inp) return;
    const start = inp.selectionStart != null ? inp.selectionStart : inp.value.length;
    const end = inp.selectionEnd != null ? inp.selectionEnd : inp.value.length;
    inp.value = inp.value.slice(0, start) + em + inp.value.slice(end);
    const caret = start + em.length;
    inp.focus();
    try { inp.setSelectionRange(caret, caret); } catch (_) {}
    signalTyping();
  }

  async function markChatRead(key, chatId) {
    // key = friend uid (DM) or gid (group); chatId defaults to the DM id for the uid.
    const me = myUid();
    if (!me || me === 'guest' || typeof _db === 'undefined') return;
    if (!chatId) chatId = chatIdFor(me, key);
    try {
      const updates = {};
      updates[`users/${me}/unreadFrom/${key}`] = null;            // clear my unread counter
      updates[`chats/${chatId}/meta/read/${me}`] = Date.now();    // tell the sender I've read up to now (✓✓)
      await _db.ref().update(updates);
    } catch (_) {}
  }
  // Normalize an unread value to a small count. Legacy entries stored a timestamp
  // (~1.7e12); treat those as a single unread so old data doesn't show "9+".
  function unreadCountFor(uid) {
    const v = Number(_unreadFromCache && _unreadFromCache[uid]) || 0;
    if (v <= 0) return 0;
    return v > 100000 ? 1 : v;
  }

  let _unreadFromCache = {};
  // ── Chat list metadata: last message preview + server-side ordering ──
  // key = friend uid (DM) or group id; value = {lastMessage, lastAt, lastFrom, lastFromName}
  let _chatMetaCache = {};
  async function loadChatMetas(items) {
    if (typeof _db === 'undefined') return;
    await Promise.all(items.map(async it => {
      try {
        const snap = await _db.ref(`chats/${it.chatId}/meta`).once('value');
        const meta = snap.val() || {};
        _chatMetaCache[it.key] = {
          lastMessage: meta.lastMessage || '',
          lastAt: meta.lastAt || 0,
          lastFrom: meta.lastFrom || '',
          lastFromName: meta.lastFromName || '',
          members: meta.members || null,
          title: meta.title || '',
          photo: meta.photo || '',
          desc: meta.desc || ''
        };
      } catch (_) {}
    }));
  }
  // Telegram-style time label in the chat list: HH:MM today, weekday this week, DD.MM later.
  function chatListTimeLabel(ts) {
    if (!ts) return '';
    const d = new Date(ts), now = new Date();
    const sameDay = d.toDateString() === now.toDateString();
    if (sameDay) return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
    const diffDays = (now - d) / 86400000;
    if (diffDays < 7) return ['Вс','Пн','Вт','Ср','Чт','Пт','Сб'][d.getDay()];
    return `${String(d.getDate()).padStart(2,'0')}.${String(d.getMonth()+1).padStart(2,'0')}`;
  }
  // Deterministic per-user color index (0–6) for sender names in group chats.
  function nameColorIdx(uid) {
    let h = 0;
    const s = String(uid || '');
    for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
    return h % 7;
  }
  // Chat list ordering + new-message popups
  let _chatLastAt = {};          // uid -> last activity ts (local, persisted per user)
  let _chatLastAtLoaded = false;
  let _prevUnreadFrom = null;    // diff source: detect a NEW incoming message
  function loadChatLastAt() {
    try { _chatLastAt = UStore.get('chatLastAt', {}) || {}; } catch (_) { _chatLastAt = {}; }
    _chatLastAtLoaded = true;
  }
  function bumpChatActivity(uid, ts) {
    if (!uid) return;
    if (!_chatLastAtLoaded) loadChatLastAt();
    _chatLastAt[uid] = ts || Date.now();
    try { UStore.set('chatLastAt', _chatLastAt); } catch (_) {}
  }
  // ── Закреп чатов (локально, как chatLastAt) ──
  let _pinnedChats = null;
  function _loadPins() { if (_pinnedChats === null) { try { _pinnedChats = UStore.get('pinnedChats', {}) || {}; } catch (_) { _pinnedChats = {}; } } return _pinnedChats; }
  function isChatPinned(key) { return !!_loadPins()[key]; }
  function toggleChatPin(key) {
    const p = _loadPins();
    if (p[key]) delete p[key]; else p[key] = Date.now();
    try { UStore.set('pinnedChats', p); } catch (_) {}
    if (isAdmin()) renderAdminChatList(); else renderFriendsAndChat();
  }
  // Called when users/{me}/unreadFrom changes — bumps recency + pops a banner for new ones.
  function handleUnreadFromUpdate(val) {
    val = val || {};
    if (_prevUnreadFrom) {
      Object.keys(val).forEach(uid => {
        const nv = Number(val[uid]) || 0, ov = Number(_prevUnreadFrom[uid]) || 0;
        if (nv > ov) {                       // a new message arrived from `uid`
          bumpChatActivity(uid);
          if (uid !== _chatOtherUid) notifyNewMessage(uid); // skip if that chat is open
        }
      });
    }
    _prevUnreadFrom = val;
    _unreadFromCache = val;
    renderFriendsAndChat();
    updateChatBadges();
  }
  function notifyNewMessage(key) {
    // key = friend uid (DM) or gid (group chat)
    const isGroup = !!(_groupsCache && _groupsCache[key]);
    const dir = (_usersDirCache && _usersDirCache[key]) || {};
    const fr  = (_friendsCache && _friendsCache[key]) || {};
    const name = isGroup
      ? (_groupsCache[key].title || 'Группа')
      : (dir.name || fr.name || 'Новое сообщение');
    showChatPopup(key, name, isGroup ? '' : (dir.avatar || ''), '', isGroup);
    // Enrich with the actual last message text once it's available.
    if (typeof _db !== 'undefined') {
      try {
        const chatId = isGroup ? key : chatIdFor(myUid(), key);
        _db.ref(`chats/${chatId}/meta/lastMessage`).once('value')
          .then(s => { const t = s.val(); if (t) updateChatPopupText(key, t); }).catch(() => {});
      } catch (_) {}
    }
  }
  function _popupId(uid) { return 'chat-popup-' + String(uid).replace(/[^a-zA-Z0-9_-]/g, '_'); }
  function showChatPopup(uid, name, avatar, text, isGroup) {
    document.getElementById(_popupId(uid))?.remove();
    const el = document.createElement('div');
    el.className = 'chat-popup';
    el.id = _popupId(uid);
    el.setAttribute('role', 'button');
    el.onclick = () => {
      el.remove();
      try { switchScreen('social'); } catch (_) {}
      if (isGroup) openGroupChat(uid, name); else openChat(uid, name);
    };
    const av = avatar
      ? `<div class="chat-popup-av" style="background:url(${avatar}) center/cover no-repeat;"></div>`
      : `<div class="chat-popup-av">${isGroup ? '<i class="fa-solid fa-user-group" style="font-size:13px;"></i>' : escHtml((name || '?').charAt(0).toUpperCase())}</div>`;
    el.innerHTML = `${av}
      <div class="chat-popup-body">
        <div class="chat-popup-name">${escHtml(name)}</div>
        <div class="chat-popup-text" id="${_popupId(uid)}-t">${text ? escHtml(text.length > 64 ? text.slice(0, 64) + '…' : text) : 'новое сообщение 💬'}</div>
      </div>
      <i class="fa-solid fa-chevron-right" style="color:var(--soft);font-size:12px;flex-shrink:0;"></i>`;
    document.body.appendChild(el);
    requestAnimationFrame(() => el.classList.add('in'));
    el._t = setTimeout(() => { el.classList.remove('in'); el.classList.add('out'); setTimeout(() => el.remove(), 320); }, 4400);
  }
  function updateChatPopupText(uid, text) {
    const t = document.getElementById(_popupId(uid) + '-t');
    if (t && text) t.textContent = text.length > 64 ? text.slice(0, 64) + '…' : text;
  }
  let _friendsListenerOffs = [];
  function detachFriendsListeners() {
    _friendsListenerOffs.forEach(off => { try { off(); } catch(_){} });
    _friendsListenerOffs = [];
  }

  function attachFriendsListeners() {
    detachFriendsListeners();
    if (typeof _db === 'undefined') return;
    const me = myUid();
    if (!me || me === 'guest') return;
    const wire = (path, onSnap) => {
      const ref = _db.ref(path);
      const handler = snap => onSnap(snap.val() || {});
      ref.on('value', handler);
      _friendsListenerOffs.push(() => ref.off('value', handler));
    };
    wire(`users/${me}/friends`,  val => { _friendsCache  = val; renderFriendsAndChat(); if (document.getElementById('add-friend-modal')) filterAddFriend(); });
    wire(`users/${me}/groups`,   val => { _groupsCache   = val; renderFriendsAndChat(); });
    wire(`users/${me}/inbox`,    val => { _inboxCache    = val; renderFriendsAndChat(); updateChatBadges(); processReferralRewards(); });
    wire(`users/${me}/outgoing`, val => { _outgoingCache = val; if (document.getElementById('add-friend-modal')) filterAddFriend(); });
    wire(`users/${me}/unreadFrom`, val => { handleUnreadFromUpdate(val); });
  }

  function updateChatBadges() {
    // Friend requests + unread messages → badge on the "Общение" tab.
    // Update BOTH nav copies (mobile bottom nav + desktop sidebar), since only
    // one is visible at a time depending on viewport.
    const requestsCount = Object.keys(_inboxCache || {}).length;
    const unreadCount = Object.keys(_unreadFromCache || {}).reduce((a, uid) => a + unreadCountFor(uid), 0);
    const total = requestsCount + unreadCount;
    document.querySelectorAll('.nav-item[data-screen="social"]').forEach(navItem => {
      let badge = navItem.querySelector('.profile-nav-badge');
      if (total > 0) {
        if (!badge) {
          badge = document.createElement('span');
          badge.className = 'profile-nav-badge';
          navItem.appendChild(badge);
        }
        badge.textContent = total > 9 ? '9+' : String(total);
      } else if (badge) {
        badge.remove();
      }
    });
  }

  function friendRowHtml(uid, info) {
    const name = escHtml(info && info.name ? info.name : 'Друг');
    const unread = unreadCountFor(uid);
    const dir = (_usersDirCache && _usersDirCache[uid]) || {};
    const isAdmin = dir.isAdmin;
    const online = dir.lastSeen && (Date.now() - dir.lastSeen) < ONLINE_WINDOW_MS;
    const meta = _chatMetaCache[uid] || {};
    const avatarInner = dir.avatar
      ? `<div class="photo-zoom chat-row-av" style="background:url(${dir.avatar}) center/cover no-repeat;"></div>`
      : `<div class="chat-row-av chat-row-av-initial">${escHtml(name.charAt(0).toUpperCase())}</div>`;
    const avatar = `<div class="friend-avatar-wrap">${avatarInner}${online ? '<span class="friend-online-dot" title="в сети"></span>' : ''}</div>`;
    // Telegram-style preview: "Ты: …" for my own last message, plain text otherwise.
    let preview;
    if (meta.lastMessage) {
      const mine = meta.lastFrom === myUid();
      preview = `${mine ? '<span class="chat-row-me">Ты:</span> ' : ''}${escHtml(meta.lastMessage)}`;
    } else {
      preview = online ? '<span style="color:var(--ok-ink);font-weight:600;">в сети</span>' : 'Напиши первое сообщение 🌸';
    }
    const timeLabel = chatListTimeLabel(meta.lastAt);
    const pinned = isChatPinned(uid);
    return `
      <div class="card card-press chat-list-row${pinned ? ' chat-pinned' : ''}" onclick="openChat('${escHtml(uid)}','${name.replace(/'/g,"&#39;")}')">
        ${avatar}
        <div class="chat-row-main">
          <div class="chat-row-top">
            <span class="chat-row-name">${pinned ? '<i class="fa-solid fa-thumbtack chat-pin-i"></i> ' : ''}${name}${isAdmin ? ' <span class="chip chip-coral" style="font-size:9px;padding:1px 6px;">🎓 учитель</span>' : ''}</span>
            <span class="chat-row-time ${unread > 0 ? 'unread' : ''}">${timeLabel}</span>
          </div>
          <div class="chat-row-bottom">
            <span class="chat-row-preview">${preview}</span>
            ${unread > 0 ? `<span class="chat-unread-badge">${unread > 99 ? '99+' : unread}</span>` : ''}
            <button class="chat-pin-btn" onclick="event.stopPropagation(); toggleChatPin('${escHtml(uid)}')" aria-label="${pinned ? 'Открепить' : 'Закрепить'}" title="${pinned ? 'Открепить' : 'Закрепить'}"><i class="fa-solid fa-thumbtack"></i></button>
          </div>
        </div>
      </div>`;
  }

  function groupRowHtml(gid, info) {
    const title = escHtml((info && info.title) || (_chatMetaCache[gid] && _chatMetaCache[gid].title) || 'Группа');
    const unread = unreadCountFor(gid);
    const meta = _chatMetaCache[gid] || {};
    const memberCount = meta.members ? Object.keys(meta.members).length : 0;
    let preview;
    if (meta.lastMessage) {
      const mine = meta.lastFrom === myUid();
      const who = mine ? '<span class="chat-row-me">Ты:</span>' : (meta.lastFromName ? `<span class="chat-row-me">${escHtml(meta.lastFromName)}:</span>` : '');
      preview = `${who} ${escHtml(meta.lastMessage)}`;
    } else {
      preview = memberCount ? `${memberCount} участников` : 'Групповой чат';
    }
    const timeLabel = chatListTimeLabel(meta.lastAt);
    const photo = meta.photo || (info && info.photo);
    const avInner = photo
      ? `<div class="chat-row-av" style="background:url(${photo}) center/cover no-repeat;"></div>`
      : `<div class="chat-row-av chat-group-av"><i class="fa-solid fa-user-group"></i></div>`;
    const pinned = isChatPinned(gid);
    return `
      <div class="card card-press chat-list-row${pinned ? ' chat-pinned' : ''}" onclick="openGroupChat('${escHtml(gid)}','${title.replace(/'/g,"&#39;")}')">
        <div class="chat-av-wrap">${avInner}<span class="chat-group-tag" title="Групповой чат"><i class="fa-solid fa-user-group"></i></span></div>
        <div class="chat-row-main">
          <div class="chat-row-top">
            <span class="chat-row-name">${pinned ? '<i class="fa-solid fa-thumbtack chat-pin-i"></i> ' : ''}${title}</span>
            <span class="chat-row-time ${unread > 0 ? 'unread' : ''}">${timeLabel}</span>
          </div>
          <div class="chat-row-bottom">
            <span class="chat-row-preview">${preview}</span>
            ${unread > 0 ? `<span class="chat-unread-badge">${unread > 99 ? '99+' : unread}</span>` : ''}
            <button class="chat-pin-btn" onclick="event.stopPropagation(); toggleChatPin('${escHtml(gid)}')" aria-label="${pinned ? 'Открепить' : 'Закрепить'}" title="${pinned ? 'Открепить' : 'Закрепить'}"><i class="fa-solid fa-thumbtack"></i></button>
          </div>
        </div>
      </div>`;
  }

  function requestRowHtml(reqKey, req) {
    const name = escHtml(req.fromName || 'Без имени');
    const fromUid = escHtml(req.from);
    return `
      <div class="card card-padded" style="display:flex;align-items:center;gap:10px;background:var(--grad-cream);">
        <div style="width:38px;height:38px;border-radius:50%;background:var(--blush);display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0;">✉️</div>
        <div style="flex:1;min-width:0;">
          <div style="font-weight:600;color:var(--berry);font-size:13px;">${name}</div>
          <div style="font-size:10.5px;color:var(--soft);">хочет добавить в друзья</div>
        </div>
        <div style="display:flex;gap:6px;flex-shrink:0;">
          <button onclick="acceptFriendRequest('${escHtml(reqKey)}','${fromUid}','${name.replace(/'/g,"&#39;")}')" class="btn btn-primary" style="padding:7px 12px;font-size:11px;">Принять</button>
          <button onclick="declineFriendRequest('${escHtml(reqKey)}','${fromUid}')" class="btn btn-ghost" style="padding:7px 10px;font-size:11px;">×</button>
        </div>
      </div>`;
  }

  let _renderFriendsSeq = 0; // drop stale async renders (meta fetches race otherwise)
  async function renderFriendsAndChat() {
    const slot = document.getElementById('friends-chat-section');
    if (!slot) return;
    const seq = ++_renderFriendsSeq;
    if (!_usersDirCache) await loadUsersDirectory();
    if (isAdmin()) { renderAdminChatList(); return; }
    const friends = _friendsCache || {};
    const groups = _groupsCache || {};
    const inbox = _inboxCache || {};
    if (!_chatLastAtLoaded) loadChatLastAt();
    const me = myUid();
    // Pull fresh chat meta (last message + server timestamp) for every conversation.
    if (me && me !== 'guest') {
      await loadChatMetas([
        ...Object.keys(friends).map(uid => ({ key: uid, chatId: chatIdFor(me, uid) })),
        ...Object.keys(groups).map(gid => ({ key: gid, chatId: gid }))
      ]);
    }
    if (seq !== _renderFriendsSeq) return; // a newer render started while we awaited
    // Telegram order: the conversation with the newest message on top.
    const lastTs = key => {
      const meta = _chatMetaCache[key] || {};
      return meta.lastAt || _chatLastAt[key] ||
        (friends[key] && friends[key].since) || (groups[key] && groups[key].since) || 0;
    };
    const convos = [
      ...Object.keys(friends).map(uid => ({ kind: 'dm', key: uid })),
      ...Object.keys(groups).map(gid => ({ kind: 'group', key: gid }))
    ].sort((a, b) => {
      // Закреплённые — всегда вверху, затем по времени последнего сообщения
      const pa = isChatPinned(a.key) ? 1 : 0, pb = isChatPinned(b.key) ? 1 : 0;
      if (pa !== pb) return pb - pa;
      return lastTs(b.key) - lastTs(a.key);
    });
    const requests = Object.entries(inbox).filter(([k, v]) => v && v.type === 'friend_request');

    const requestsHtml = requests.length
      ? `<div style="font-size:10px;letter-spacing:.18em;color:var(--coral);font-weight:700;margin:4px 4px 8px;">ЗАЯВКИ · ${requests.length}</div>
         <div style="display:grid;gap:8px;margin-bottom:14px;">${requests.map(([k,r]) => requestRowHtml(k, r)).join('')}</div>`
      : '';

    const listHtml = convos.length
      ? `<div class="stagger-in" style="display:grid;gap:8px;">${convos.map(c => c.kind === 'group' ? groupRowHtml(c.key, groups[c.key]) : friendRowHtml(c.key, friends[c.key])).join('')}</div>`
      : `<div class="card" style="text-align:center; padding:26px 18px 22px; background:linear-gradient(160deg, var(--card), var(--paper));">
           <img src="assets/bear3.png" alt="" style="width:92px; margin:0 auto 4px; display:block; filter:drop-shadow(0 8px 14px rgba(92,42,51,.18));" onerror="this.style.display='none'">
           <div class="display" style="font-size:18px; color:var(--berry);">Здесь будут твои друзья</div>
           <div style="font-size:12px; color:var(--soft); margin-top:6px; line-height:1.55; max-width:260px; margin-left:auto; margin-right:auto;">
             Добавь одногруппников или учителя — сможете переписываться, делиться прогрессом и поддерживать стрик вместе 🌸
           </div>
           <div style="display:grid; gap:8px; margin-top:14px; text-align:left; max-width:280px; margin-left:auto; margin-right:auto;">
             <div style="display:flex; align-items:center; gap:10px; font-size:12px; color:var(--berry);"><span style="width:30px; height:30px; flex-shrink:0; border-radius:10px; background:var(--blush); display:flex; align-items:center; justify-content:center;">💬</span> Личный чат с друзьями</div>
             <div style="display:flex; align-items:center; gap:10px; font-size:12px; color:var(--berry);"><span style="width:30px; height:30px; flex-shrink:0; border-radius:10px; background:var(--blush); display:flex; align-items:center; justify-content:center;">🔥</span> Видно стрик и уровень друг друга</div>
             <div style="display:flex; align-items:center; gap:10px; font-size:12px; color:var(--berry);"><span style="width:30px; height:30px; flex-shrink:0; border-radius:10px; background:var(--blush); display:flex; align-items:center; justify-content:center;">👩‍🏫</span> Вопросы учителю — прямо здесь</div>
           </div>
           <button onclick="openAddFriendModal()" class="btn btn-primary" style="margin-top:16px;"><i class="fa-solid fa-user-plus" style="font-size:11px;"></i> Найти друзей</button>
         </div>`;

    slot.innerHTML = `
      <div id="week-leaderboard"></div>
      <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;padding:0 4px;margin-bottom:10px;">
        <div style="font-size:10px;letter-spacing:.2em;color:var(--soft);">ЧАТЫ ${convos.length ? `<span style="color:var(--coral);font-weight:700;letter-spacing:.04em;">${convos.length}</span>` : ''}</div>
        <div style="display:flex;gap:6px;">
          ${Object.keys(friends).length ? `<button onclick="openCreateGroupModal()" class="chip" style="font-size:11px;padding:5px 12px;cursor:pointer;border:none;background:var(--blush);color:var(--berry);"><i class="fa-solid fa-user-group" style="font-size:10px;"></i> Создать группу</button>` : ''}
          <button onclick="openAddFriendModal()" class="chip chip-coral" style="font-size:11px;padding:5px 12px;cursor:pointer;border:none;"><i class="fa-solid fa-user-plus" style="font-size:10px;"></i> Добавить</button>
        </div>
      </div>
      ${pushPermissionCtaHtml()}
      ${requestsHtml}
      ${listHtml}
    `;
    renderWeekLeaderboard();
  }

  // ── Лидерборд недели: я + друзья по XP с понедельника ──
  function _weekStartIso() {
    const d = new Date();
    const day = (d.getDay() + 6) % 7; // 0 = понедельник
    d.setDate(d.getDate() - day);
    return d.toISOString().slice(0, 10);
  }
  function _weekXpFrom(xpByDay) {
    const start = _weekStartIso();
    let sum = 0;
    Object.entries(xpByDay || {}).forEach(([k, v]) => { if (k >= start) sum += (+v || 0); });
    return sum;
  }
  // Рейтинг. Две оси: охват (друзья / глобальный) и период (неделя / всё время).
  let _lbMode = 'week';      // 'week' — XP с понедельника, 'all' — общий накопленный XP
  let _lbScope = 'friends';  // 'friends' — я + друзья, 'global' — все ученики
  let _lbFriendRows = null;  // кэш строк друзей (с week/all) — переключаем период без перезагрузки
  let _lbGlobalRows = null;  // кэш строк глобального рейтинга
  function setLeaderboardMode(mode) { _lbMode = (mode === 'all') ? 'all' : 'week'; paintLeaderboard(); }
  function setLbScope(scope) { _lbScope = (scope === 'global') ? 'global' : 'friends'; paintLeaderboard(); }
  async function renderWeekLeaderboard() {
    const slot = document.getElementById('week-leaderboard');
    if (!slot) return;
    const me = Store.get('user');
    if (!me || me.guest || typeof _db === 'undefined') { slot.innerHTML = ''; _lbFriendRows = _lbGlobalRows = null; return; }
    const myUid = firebaseUserId();
    const myRow = { uid: myUid, name: me.name || 'Я', me: true, week: _weekXpFrom(stats.xpByDay), all: stats.xp || 0 };

    // — Друзья: я + друзья (свежая стата каждого из облака) —
    const friends = _friendsCache || {};
    const fids = Object.keys(friends);
    let friendRows = null;
    if (fids.length) {
      friendRows = [myRow];
      await Promise.all(fids.map(async fid => {
        try {
          const snap = await _db.ref('users/' + fid + '/stats').once('value');
          const s = snap.val() || {};
          friendRows.push({ uid: fid, name: (friends[fid] && friends[fid].name) || 'Друг', week: _weekXpFrom(s.xpByDay), all: (+s.xp || 0) });
        } catch (_) {}
      }));
    }
    _lbFriendRows = friendRows;

    // — Глобальный: все ученики из общего справочника (без админов) —
    if (!_usersDirCache) { try { await loadUsersDirectory(); } catch (_) {} }
    const dir = _usersDirCache || {};
    const globalRows = [];
    Object.entries(dir).forEach(([uid, u]) => {
      if (!u || u.isAdmin) return;            // учителей в рейтинг учеников не включаем
      if (uid === myUid) return;              // себя добавим из живой статы ниже
      const s = u.stats || {};
      globalRows.push({ uid, name: u.name || 'Ученик', week: _weekXpFrom(s.xpByDay), all: (+s.xp || 0) });
    });
    globalRows.push(myRow);
    _lbGlobalRows = globalRows;

    // Выбор охвата по умолчанию: если друзей нет — показываем глобальный.
    if (!fids.length && _lbScope === 'friends') _lbScope = 'global';
    paintLeaderboard();
  }
  function paintLeaderboard() {
    const slot = document.getElementById('week-leaderboard');
    if (!slot) return;
    const hasFriends = !!(_lbFriendRows && _lbFriendRows.length);
    const globalHasRivals = !!(_lbGlobalRows && _lbGlobalRows.length > 1);
    if (!hasFriends && !globalHasRivals) { slot.innerHTML = ''; return; } // соревноваться не с кем

    const mode = _lbMode;
    const scope = (_lbScope === 'friends' && !hasFriends) ? 'friends' : _lbScope; // оставим вкладку, покажем подсказку
    const src = scope === 'global' ? (_lbGlobalRows || []) : (_lbFriendRows || []);
    const rows = src.map(r => ({ ...r, xp: mode === 'all' ? (r.all || 0) : (r.week || 0) })).sort((a, b) => b.xp - a.xp);
    const sub = mode === 'all' ? 'по всему опыту' : 'XP с понедельника';
    const medal = i => i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `<span style="font-size:11px;color:var(--hush);font-weight:700;">${i + 1}</span>`;
    const myIdx = rows.findIndex(r => r.me);
    const rowHtml = (r, i) => `
      <div style="display:flex; align-items:center; gap:10px; padding:8px 10px; border-radius:12px; background:${r.me ? 'rgba(var(--accent-rgb),.10)' : 'transparent'}; ${r.me ? 'box-shadow: inset 0 0 0 1px rgba(var(--accent-rgb),.25);' : ''}">
        <span style="width:22px; text-align:center; font-size:15px;">${medal(i)}</span>
        <span style="flex:1; min-width:0; font-weight:600; font-size:13px; color:var(--berry); overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${escHtml(r.name)}${r.me ? ' <span style="font-size:10px;color:var(--coral);">· это ты</span>' : ''}</span>
        <span style="font-weight:800; font-size:13px; color:${i === 0 ? 'var(--gold)' : 'var(--soft)'};">${r.xp} XP</span>
      </div>`;

    let body;
    if (scope === 'friends' && !hasFriends) {
      body = `<div style="text-align:center; font-size:12px; color:var(--soft); padding:14px 8px; line-height:1.55;">
          Добавь друзей, чтобы соревноваться лично 🌸<br>
          <button onclick="openAddFriendModal()" class="chip chip-coral" style="margin-top:10px; font-size:11px; padding:6px 14px; cursor:pointer; border:none;"><i class="fa-solid fa-user-plus" style="font-size:10px;"></i> Найти друзей</button>
        </div>`;
    } else {
      const top = rows.slice(0, 5).map((r, i) => rowHtml(r, i)).join('');
      // Если я вне топ-5 (актуально для глобального) — показать мою строку отдельно с реальным местом.
      const tail = (myIdx >= 5)
        ? `<div style="text-align:center; font-size:11px; color:var(--hush); margin:2px 0;">···</div>${rowHtml(rows[myIdx], myIdx)}`
        : '';
      const hint = myIdx > 0
        ? `<div style="text-align:center; font-size:11px; color:var(--soft); margin-top:8px;">До ${escHtml(rows[myIdx - 1].name)} осталось ${rows[myIdx - 1].xp - rows[myIdx].xp + 1} XP — догоняй! 🔥</div>`
        : (myIdx === 0 ? `<div style="text-align:center; font-size:11px; color:var(--gold-ink); margin-top:8px;">Ты впереди всех — 화이팅! 🌟</div>` : '');
      body = `<div style="display:grid; gap:6px;">${top}${tail}</div>${hint}`;
    }

    const count = scope === 'global' ? rows.length : Math.max(0, rows.length);
    slot.innerHTML = `
      <div class="card card-padded" style="margin-bottom:16px; background:linear-gradient(160deg, var(--card), var(--paper));">
        <div class="auth-tabs" style="margin-bottom:8px;">
          <button type="button" class="auth-tab ${scope === 'friends' ? 'auth-tab-active' : ''}" onclick="setLbScope('friends')">👥 Друзья</button>
          <button type="button" class="auth-tab ${scope === 'global' ? 'auth-tab-active' : ''}" onclick="setLbScope('global')">🌍 Глобальный</button>
        </div>
        <div style="display:flex; justify-content:space-between; align-items:center; gap:8px; margin-bottom:8px;">
          <div style="display:flex; gap:6px;">
            <button type="button" class="lb-chip ${mode === 'week' ? 'lb-chip-on' : ''}" onclick="setLeaderboardMode('week')">Неделя</button>
            <button type="button" class="lb-chip ${mode === 'all' ? 'lb-chip-on' : ''}" onclick="setLeaderboardMode('all')">Всё время</button>
          </div>
          <div style="font-size:10px; color:var(--hush); white-space:nowrap;">${sub}${scope === 'global' ? ` · ${count} 🌍` : ''}</div>
        </div>
        ${body}
      </div>`;
  }

  function pushPermissionCtaHtml() {
    if (!_messaging || !('Notification' in window)) return '';
    if (!_VAPID_KEY || _VAPID_KEY.startsWith('REPLACE_')) return '';
    if (Notification.permission === 'granted') return '';
    if (Notification.permission === 'denied') {
      return `<div style="background:rgba(var(--rose-rgb),.12);border:1px dashed rgba(var(--rose-rgb),.5);border-radius:14px;padding:10px 12px;margin-bottom:12px;font-size:11.5px;color:var(--bad-ink);text-align:center;">
        🔕 Уведомления заблокированы в браузере. Разреши их в настройках, чтобы получать сообщения в фоне.
      </div>`;
    }
    return `<div style="background:var(--card);border:1px solid var(--line);border-radius:14px;padding:12px;margin-bottom:12px;display:flex;align-items:center;gap:10px;">
      <div style="font-size:22px;">🔔</div>
      <div style="flex:1;min-width:0;">
        <div style="font-weight:600;color:var(--berry);font-size:12.5px;">Включи уведомления</div>
        <div style="font-size:10.5px;color:var(--soft);margin-top:1px;">Чтобы видеть новые сообщения даже когда сайт закрыт.</div>
      </div>
      <button onclick="askPushPermission()" class="btn btn-primary" style="padding:7px 12px;font-size:11px;flex-shrink:0;">Включить</button>
    </div>`;
  }

  async function renderAdminChatList() {
    const slot = document.getElementById('friends-chat-section');
    if (!slot) return;
    const dir = _usersDirCache || {};
    const me = myUid();
    const groups = _groupsCache || {};
    // Fresh previews: last message + server timestamp for students and admin's groups.
    const studentUids = Object.keys(dir).filter(uid => !(dir[uid] && dir[uid].isAdmin) && uid !== me);
    if (me && me !== 'guest') {
      await loadChatMetas([
        ...studentUids.map(uid => ({ key: uid, chatId: chatIdFor(me, uid) })),
        ...Object.keys(groups).map(gid => ({ key: gid, chatId: gid }))
      ]);
    }
    if (!document.getElementById('friends-chat-section')) return;
    const students = studentUids
      .map(uid => ({ uid, ...dir[uid] }))
      .sort((a, b) => {
        const pa = isChatPinned(a.uid) ? 1 : 0, pb = isChatPinned(b.uid) ? 1 : 0;
        if (pa !== pb) return pb - pa;
        const aUnread = unreadCountFor(a.uid);
        const bUnread = unreadCountFor(b.uid);
        if (aUnread !== bUnread) return bUnread - aUnread;
        const aAt = (_chatMetaCache[a.uid] && _chatMetaCache[a.uid].lastAt) || 0;
        const bAt = (_chatMetaCache[b.uid] && _chatMetaCache[b.uid].lastAt) || 0;
        if (aAt !== bAt) return bAt - aAt;
        return (b.lastSeen || 0) - (a.lastSeen || 0);
      });

    const groupRows = Object.keys(groups)
      .sort((a, b) => ((_chatMetaCache[b] && _chatMetaCache[b].lastAt) || 0) - ((_chatMetaCache[a] && _chatMetaCache[a].lastAt) || 0))
      .map(gid => groupRowHtml(gid, groups[gid])).join('');

    const listHtml = students.length
      ? `<div class="stagger-in" style="display:grid;gap:8px;">${groupRows}${students.map(s => adminChatRowHtml(s)).join('')}</div>`
      : `<div style="text-align:center;padding:18px 12px;color:var(--soft);font-size:12px;background:var(--blush);border:1px dashed var(--line);border-radius:14px;">Учеников пока нет 🌸</div>`;

    slot.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;padding:0 4px;margin-bottom:10px;">
        <div style="font-size:10px;letter-spacing:.2em;color:var(--soft);">УЧЕНИКИ И ЧАТ <span style="color:var(--coral);font-weight:700;letter-spacing:.04em;">${students.length}</span></div>
        <div style="display:flex;gap:6px;">
          <button onclick="openCreateGroupModal()" class="chip" style="font-size:11px;padding:5px 12px;cursor:pointer;border:none;background:var(--blush);color:var(--berry);"><i class="fa-solid fa-user-group" style="font-size:10px;"></i> Создать группу</button>
          <button onclick="refreshAdminChatList()" class="chip" style="font-size:11px;padding:5px 12px;cursor:pointer;border:none;background:var(--blush);color:var(--berry);"><i class="fa-solid fa-rotate" style="font-size:10px;"></i> Обновить</button>
        </div>
      </div>
      ${listHtml}
    `;
  }

  function adminChatRowHtml(u) {
    const name = escHtml(u.name || 'Без имени');
    const unread = unreadCountFor(u.uid);
    const xp = (u.stats && u.stats.xp) || 0;
    const lvl = getLevel(xp);
    const rank = getRank(lvl);
    const initial = escHtml((u.name || '?').charAt(0).toUpperCase());
    const online = u.lastSeen && (Date.now() - u.lastSeen) < ONLINE_WINDOW_MS;
    const meta = _chatMetaCache[u.uid] || {};
    const avatarInner = u.avatar
      ? `<div class="photo-zoom chat-row-av" style="background:url(${u.avatar}) center/cover no-repeat;"></div>`
      : `<div class="chat-row-av chat-row-av-initial">${initial}</div>`;
    const avatar = `<div class="friend-avatar-wrap">${avatarInner}${online ? '<span class="friend-online-dot" title="в сети"></span>' : ''}</div>`;
    let preview;
    if (meta.lastMessage) {
      const mine = meta.lastFrom === myUid();
      preview = `${mine ? '<span class="chat-row-me">Ты:</span> ' : ''}${escHtml(meta.lastMessage)}`;
    } else {
      preview = `${escHtml(u.email || '')} · 🔥 ${(u.stats && u.stats.streak) || 0} · ${xp} XP`;
    }
    const timeLabel = chatListTimeLabel(meta.lastAt);
    const pinned = isChatPinned(u.uid);
    return `
      <div class="card card-press chat-list-row${pinned ? ' chat-pinned' : ''}" onclick="openChat('${escHtml(u.uid)}','${name.replace(/'/g,"&#39;")}')">
        ${avatar}
        <div class="chat-row-main">
          <div class="chat-row-top">
            <span class="chat-row-name">${pinned ? '<i class="fa-solid fa-thumbtack chat-pin-i"></i> ' : ''}${name} <span style="font-size:10.5px;color:var(--coral);font-weight:600;">${rank.emoji} Lv ${lvl}</span></span>
            <span class="chat-row-time ${unread > 0 ? 'unread' : ''}">${timeLabel}</span>
          </div>
          <div class="chat-row-bottom">
            <span class="chat-row-preview">${preview}</span>
            ${unread > 0 ? `<span class="chat-unread-badge">${unread > 99 ? '99+' : unread}</span>` : ''}
            <button class="chat-pin-btn" onclick="event.stopPropagation(); toggleChatPin('${escHtml(u.uid)}')" aria-label="${pinned ? 'Открепить' : 'Закрепить'}" title="${pinned ? 'Открепить' : 'Закрепить'}"><i class="fa-solid fa-thumbtack"></i></button>
          </div>
        </div>
      </div>`;
  }

  async function refreshAdminChatList() {
    _usersDirCache = null;
    await loadUsersDirectory();
    renderAdminChatList();
    toast('Список обновлён 🌸', 'var(--sage)');
  }

  function openAddFriendModal() {
    if (!isLoggedInForChat()) { toast('Войди в аккаунт, чтобы добавлять друзей'); return; }
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.id = 'add-friend-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:380px;">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:14px;">
          <div>
            <div class="page-eyebrow">НАЙТИ ДРУГА</div>
            <div class="display" style="font-size:20px;color:var(--berry);margin-top:2px;">Поиск по имени</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:24px;color:var(--soft);cursor:pointer;line-height:1;padding:2px 6px;">×</div>
        </div>
        <input id="add-friend-search" class="input" placeholder="Имя или email…" oninput="filterAddFriend()" style="font-size:13px;">
        <div id="add-friend-results" style="display:grid;gap:8px;margin-top:14px;max-height:340px;overflow-y:auto;">
          <div style="text-align:center;padding:18px;color:var(--soft);font-size:12px;">Загружаю…</div>
        </div>
      </div>`;
    document.body.appendChild(m);
    setTimeout(() => { document.getElementById('add-friend-search')?.focus(); }, 80);
    filterAddFriend();
  }

  async function filterAddFriend() {
    const q = document.getElementById('add-friend-search')?.value || '';
    const list = document.getElementById('add-friend-results');
    if (!list) return;
    const users = await searchUsersByName(q);
    const friends = _friendsCache || {};
    if (!users.length) {
      list.innerHTML = `<div style="text-align:center;padding:18px;color:var(--soft);font-size:12px;">Никого не нашла 🌸</div>`;
      return;
    }
    list.innerHTML = users.map(u => {
      const isFriend  = !!friends[u.uid];
      const isPending = !!(_outgoingCache && _outgoingCache[u.uid]);
      const isSending = _sendingFriendReq.has(u.uid);
      const initial = escHtml((u.name || '?').charAt(0).toUpperCase());
      const avatar = u.avatar
        ? `<div class="photo-zoom" style="width:38px;height:38px;border-radius:50%;background:url(${u.avatar}) center/cover no-repeat;flex-shrink:0;border:1.5px solid var(--rose);"></div>`
        : `<div style="width:38px;height:38px;border-radius:50%;background:var(--paper);flex-shrink:0;border:1.5px solid var(--rose);display:flex;align-items:center;justify-content:center;font-size:14px;color:var(--coral);font-weight:700;">${initial}</div>`;
      let actionHtml;
      if (isFriend) {
        actionHtml = '<span class="chip chip-sage" style="font-size:10px;flex-shrink:0;">✓ в друзьях</span>';
      } else if (isPending) {
        actionHtml = `
          <div style="display:flex;gap:5px;flex-shrink:0;align-items:center;">
            <span class="chip" style="font-size:10px;background:rgba(201,165,92,.18);color:var(--gold-ink);border:1px solid rgba(201,165,92,.5);">⏳ Отправлен</span>
            <button onclick="cancelFriendRequest('${escHtml(u.uid)}')" class="btn btn-ghost" style="padding:5px 9px;font-size:10.5px;border-color:rgba(var(--rose-rgb),.5);color:var(--bad-ink);">Отмена</button>
          </div>`;
      } else if (isSending) {
        actionHtml = `<button disabled class="btn btn-primary" style="padding:6px 10px;font-size:11px;flex-shrink:0;opacity:.55;cursor:wait;">Отправляю…</button>`;
      } else {
        actionHtml = `<button onclick="sendFriendRequest('${escHtml(u.uid)}','${escHtml(u.name||'').replace(/'/g,'&#39;')}')" class="btn btn-primary" style="padding:6px 10px;font-size:11px;flex-shrink:0;">+ Добавить</button>`;
      }
      return `
        <div style="display:flex;align-items:center;gap:10px;padding:8px 4px;">
          ${avatar}
          <div style="flex:1;min-width:0;">
            <div style="font-weight:600;color:var(--berry);font-size:13px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escHtml(u.name || 'Без имени')} ${u.isAdmin ? '<span class="chip chip-coral" style="font-size:9px;padding:1px 6px;">🎓</span>' : ''}</div>
            <div style="font-size:10.5px;color:var(--soft);">${escHtml(u.email || '')}</div>
          </div>
          ${actionHtml}
        </div>`;
    }).join('');
  }

  function isLoggedInForChat() {
    const u = Store.get('user');
    return !!(u && !u.guest);
  }

  // ── Chat as full page (no modal) ──
  let _chatBuddyListenerOff = null;
  let _chatStatusTick = null;
  let _chatBuddyLastSeen = 0;
  const ONLINE_WINDOW_MS = 90 * 1000; // 90s — within this lastSeen window = "в сети"

  function chatStatusHtml(lastSeen) {
    if (!lastSeen) return `<span>—</span>`;
    const diff = Date.now() - lastSeen;
    if (diff < ONLINE_WINDOW_MS) {
      return `<span class="chat-online-dot"></span><span>в сети</span>`;
    }
    return `<span>был в сети ${relativeTime(lastSeen)}</span>`;
  }

  function paintChatHeaderStatus() {
    const slot = document.getElementById('chat-buddy-status');
    if (!slot) return;
    const now = Date.now();
    if (_chatIsGroup) {
      // Group: "Имя печатает…" beats the member count line.
      const me = myUid();
      const typing = Object.entries(_chatTyping || {})
        .filter(([uid, ts]) => uid !== me && now - Number(ts) < 6000);
      if (typing.length) {
        const nm = (_chatMembers && _chatMembers[typing[0][0]]) || 'Кто-то';
        slot.innerHTML = `<span class="chat-typing">${escHtml(nm)} печатает<span class="chat-typing-dots"><i></i><i></i><i></i></span></span>`;
        slot.classList.add('online');
        return;
      }
      const n = Object.keys(_chatMembers || {}).length;
      slot.innerHTML = `<span>${n ? `${n} ${pluralRu(n, 'участник', 'участника', 'участников')}` : 'группа'}</span>`;
      slot.classList.remove('online');
      return;
    }
    // Typing takes priority over the online/last-seen line.
    const t = _chatOtherUid && _chatTyping && Number(_chatTyping[_chatOtherUid]);
    if (t && (now - t < 6000)) {
      slot.innerHTML = '<span class="chat-typing">печатает<span class="chat-typing-dots"><i></i><i></i><i></i></span></span>';
      slot.classList.add('online');
      return;
    }
    slot.innerHTML = chatStatusHtml(_chatBuddyLastSeen);
    const isOnline = _chatBuddyLastSeen && (now - _chatBuddyLastSeen) < ONLINE_WINDOW_MS;
    slot.classList.toggle('online', !!isOnline);
  }

  function paintChatHeaderAvatar(avatar, name) {
    const av = document.getElementById('chat-buddy-avatar');
    if (!av) return;
    if (avatar) {
      av.style.background = `url(${avatar}) center/cover no-repeat`;
      av.textContent = '';
      av.classList.add('photo-zoom');
      av.dataset.photoSrc = avatar;
    } else {
      av.style.background = '';
      av.textContent = (name || '?').charAt(0).toUpperCase();
      av.classList.remove('photo-zoom');
      delete av.dataset.photoSrc;
    }
  }

  function attachChatBuddyListener(uid) {
    detachChatBuddyListener();
    if (typeof _db === 'undefined') return;
    const ref = _db.ref(`users/${uid}`);
    const handler = snap => {
      const u = snap.val() || {};
      _chatBuddyLastSeen = u.lastSeen || 0;
      paintChatHeaderAvatar(u.avatar, u.name);
      paintChatHeaderStatus();
    };
    ref.on('value', handler);
    _chatBuddyListenerOff = () => ref.off('value', handler);
    // Keep "X min ago" fresh while the chat is open
    _chatStatusTick = setInterval(paintChatHeaderStatus, 30000);
  }

  function detachChatBuddyListener() {
    if (_chatBuddyListenerOff) { try { _chatBuddyListenerOff(); } catch(_){} _chatBuddyListenerOff = null; }
    if (_chatStatusTick) { clearInterval(_chatStatusTick); _chatStatusTick = null; }
    _chatBuddyLastSeen = 0;
  }

  function openChat(otherUid, otherName) {
    if (!isLoggedInForChat()) { toast('Войди в аккаунт, чтобы открыть чат'); return; }
    _openConversation({ isGroup: false, key: otherUid, chatId: chatIdFor(myUid(), otherUid), title: otherName });
  }

  function openGroupChat(gid, title) {
    if (!isLoggedInForChat()) { toast('Войди в аккаунт, чтобы открыть чат'); return; }
    const t = title || (_groupsCache && _groupsCache[gid] && _groupsCache[gid].title) || 'Группа';
    _openConversation({ isGroup: true, key: gid, chatId: gid, title: t });
  }

  function pluralRu(n, one, few, many) {
    const m100 = n % 100, m10 = n % 10;
    if (m100 >= 11 && m100 <= 14) return many;
    if (m10 === 1) return one;
    if (m10 >= 2 && m10 <= 4) return few;
    return many;
  }

  function _openConversation(opts) {
    const isGroup = !!opts.isGroup;
    const key = opts.key;            // friend uid (DM) or gid (group) — also the unreadFrom key
    const chatId = opts.chatId;
    const title = opts.title || '';
    _chatCurrentId = chatId;
    _chatOtherUid = key;
    _chatIsGroup = isGroup;
    _chatMembers = {};               // uid -> name (groups: typing line + sender labels)
    _chatReplyTo = null;
    _chatReadMeta = {};
    _lastChatMsgs = {};
    _chatSeenKeys = null; _chatPrevReactions = {}; _chatTyping = {}; // reset FX so history doesn't animate
    bumpChatActivity(key); // opening a chat surfaces it to the top of the list
    document.getElementById(_popupId(key))?.remove(); // clear any pending banner for this chat
    // Remove existing if any
    document.getElementById('chat-page')?.remove();
    const m = document.createElement('div');
    m.className = 'chat-page';
    m.id = 'chat-page';
    const showRemoveBtn = !isGroup && !isAdmin();
    // Seed from cache so header doesn't flash empty before Firebase responds
    const cached = (!isGroup && _usersDirCache && _usersDirCache[key]) || {};
    const initialAvatar = cached.avatar || '';
    const initialLastSeen = cached.lastSeen || 0;
    _chatBuddyLastSeen = initialLastSeen;
    const avatarStyle = (initialAvatar && !isGroup)
      ? `background:url(${initialAvatar}) center/cover no-repeat;`
      : '';
    const avatarContent = isGroup
      ? '<i class="fa-solid fa-user-group" style="font-size:13px;"></i>'
      : (initialAvatar ? '' : escHtml((title || '?').charAt(0).toUpperCase()));
    const avatarClass = 'chat-buddy-avatar' + ((initialAvatar && !isGroup) ? ' photo-zoom' : '') + (isGroup ? ' chat-group-av' : '');
    const avatarData = (initialAvatar && !isGroup) ? `data-photo-src="${initialAvatar}"` : '';
    const statusInitial = isGroup ? '<span>группа</span>' : chatStatusHtml(initialLastSeen);
    m.innerHTML = `
      <div class="chat-sheet">
        <div class="chat-header">
          <button id="chat-close-btn" class="chat-back-btn" aria-label="Назад"><i class="fa-solid fa-arrow-left"></i></button>
          <div class="chat-buddy-info">
            <div class="chat-buddy-name">${escHtml(title)}</div>
            <div id="chat-buddy-status" class="chat-buddy-status">${statusInitial}</div>
          </div>
          ${isGroup ? '<button id="chat-group-menu-btn" class="chat-mini-btn chat-mini-neutral" aria-label="Меню группы" title="Меню группы"><i class="fa-solid fa-ellipsis"></i></button>' : ''}
          ${showRemoveBtn ? '<button id="chat-remove-friend-btn" class="chat-mini-btn" aria-label="Удалить из друзей" title="Удалить из друзей"><i class="fa-solid fa-user-xmark"></i></button>' : ''}
          <div id="chat-buddy-avatar" class="${avatarClass}" ${avatarData} style="${avatarStyle}">${avatarContent}</div>
        </div>
        <div class="chat-body" id="chat-body">
          <div style="text-align:center;padding:24px;color:var(--soft);font-size:12px;">Загружаю…</div>
        </div>
        <button type="button" id="chat-scroll-fab" class="chat-scroll-fab" aria-label="К новым сообщениям"><i class="fa-solid fa-chevron-down"></i></button>
        <div id="chat-reply-preview" class="chat-reply-preview" style="display:none;"></div>
        <div id="chat-emoji-panel" class="chat-emoji-panel" style="display:none;"></div>
        <form class="chat-input-row" id="chat-form">
          <button type="button" id="chat-emoji-btn" class="chat-emoji-btn" aria-label="Эмодзи" onclick="toggleEmojiPicker()"><i class="fa-regular fa-face-smile"></i></button>
          <input id="chat-input" class="chat-input" placeholder="Сообщение…" autocomplete="off" maxlength="2000">
          <button type="submit" id="chat-send-btn" class="chat-send-btn" aria-label="Отправить"><i class="fa-solid fa-paper-plane"></i></button>
        </form>
      </div>`;
    document.body.appendChild(m);
    document.body.classList.add('chat-open');
    // Apply online class to seeded status
    paintChatHeaderStatus();
    // DM: live avatar + lastSeen. Group: load member names for the status line.
    if (!isGroup) attachChatBuddyListener(key);
    else loadGroupMembers(chatId);

    // Event listeners (avoid inline onclick — safer with names containing apostrophes etc.)
    document.getElementById('chat-close-btn').addEventListener('click', closeChat);
    // DM: тап по имени/статусу открывает профиль собеседника (Telegram-style).
    if (!isGroup) {
      const info = m.querySelector('.chat-buddy-info');
      if (info) {
        info.classList.add('chat-buddy-info-tap');
        info.addEventListener('click', () => openUserProfile(key));
      }
    }
    if (showRemoveBtn) {
      document.getElementById('chat-remove-friend-btn').addEventListener('click', () => removeFriend(key));
    }
    if (isGroup) {
      document.getElementById('chat-group-menu-btn').addEventListener('click', () => openGroupMenu(chatId, title));
    }
    const form = document.getElementById('chat-form');
    const inp  = document.getElementById('chat-input');
    const btn  = document.getElementById('chat-send-btn');
    // Keep the mobile keyboard open: buttons must never steal focus from the input.
    const keepFocus = e => e.preventDefault();
    btn.addEventListener('pointerdown', keepFocus);
    document.getElementById('chat-emoji-btn').addEventListener('pointerdown', keepFocus);
    document.getElementById('chat-emoji-panel').addEventListener('pointerdown', keepFocus);
    form.addEventListener('submit', async (e) => {
      e.preventDefault();
      const text = (inp.value || '').trim();
      if (!text) return;
      const replyTo = _chatReplyTo;
      inp.value = '';
      _chatReplyTo = null;
      renderReplyPreview();
      closeEmojiPanel();  // Telegram-style: панель эмодзи закрывается после отправки
      stopTyping();       // I just sent → clear my "печатает…" flag
      inp.focus();        // keyboard stays up
      btn.disabled = true;
      try {
        if (isGroup) await sendGroupMessage(chatId, text, replyTo);
        else await sendChatMessage(key, title, text, replyTo);
      } catch (err) {
        console.error('chat send error', err);
        toast('Сообщение не отправилось: ' + (err.message || err.code || 'ошибка'));
        inp.value = text; // restore so user can retry
        _chatReplyTo = replyTo; renderReplyPreview();
      } finally {
        btn.disabled = false;
        if (document.activeElement !== inp) inp.focus();
      }
    });
    inp.addEventListener('input', signalTyping); // broadcast "печатает…" to the other side
    const body = document.getElementById('chat-body');
    attachChatGestures(body);
    // Scroll-to-bottom FAB (Telegram): appears once you scroll up to read history.
    const fab = document.getElementById('chat-scroll-fab');
    body.addEventListener('scroll', () => {
      const away = body.scrollHeight - body.scrollTop - body.clientHeight;
      fab.classList.toggle('show', away > 280);
    }, { passive: true });
    fab.addEventListener('click', () => { body.scrollTo({ top: body.scrollHeight, behavior: 'smooth' }); });
    setTimeout(() => inp.focus(), 100);
    attachChatListener(chatId, key);
    markChatRead(key, chatId);
  }

  let _chatGroupMeta = null;
  async function loadGroupMembers(gid) {
    if (typeof _db === 'undefined') return;
    try {
      if (!_usersDirCache) await loadUsersDirectory();
      const snap = await _db.ref(`chats/${gid}/meta`).once('value');
      const meta = snap.val() || {};
      _chatGroupMeta = meta;
      const members = meta.members || {};
      const names = {};
      Object.keys(members).forEach(uid => {
        const d = (_usersDirCache && _usersDirCache[uid]) || {};
        names[uid] = d.name || (_friendsCache && _friendsCache[uid] && _friendsCache[uid].name) || 'Участник';
      });
      _chatMembers = names;
      // Фото группы в шапку (если задано)
      if (meta.photo) {
        const av = document.getElementById('chat-buddy-avatar');
        if (av) { av.style.background = `url(${meta.photo}) center/cover no-repeat`; av.innerHTML = ''; av.classList.remove('chat-group-av'); }
      }
      paintChatHeaderStatus();
    } catch (_) {}
  }

  function openGroupMenu(gid, title) {
    const me = myUid();
    const names = Object.entries(_chatMembers || {});
    const meta = _chatGroupMeta || {};
    const photo = meta.photo;
    const headAv = photo
      ? `<div class="chat-row-av" style="width:64px;height:64px;background:url(${photo}) center/cover no-repeat;margin:0 auto;"></div>`
      : `<div class="chat-row-av chat-group-av" style="width:64px;height:64px;font-size:24px;margin:0 auto;"><i class="fa-solid fa-user-group"></i></div>`;
    const sheet = document.createElement('div');
    sheet.className = 'modal-bg';
    sheet.onclick = e => { if (e.target === sheet) sheet.remove(); };
    sheet.innerHTML = `
      <div class="modal-sheet" style="border-radius:24px 24px 0 0; padding:18px 16px calc(20px + env(safe-area-inset-bottom,0px));">
        <div style="text-align:center;margin-bottom:10px;">
          ${headAv}
          <div class="display" style="font-size:20px;color:var(--berry);margin-top:8px;">${escHtml(title)}</div>
          ${meta.desc ? `<div style="font-size:12.5px;color:var(--soft);margin-top:4px;line-height:1.5;">${escHtml(meta.desc)}</div>` : ''}
        </div>
        <div style="display:flex;justify-content:space-between;align-items:center;margin:0 2px 8px;">
          <span style="font-size:10px;letter-spacing:.18em;color:var(--soft);">УЧАСТНИКИ · ${names.length}</span>
          <button class="chip chip-coral" style="font-size:10px;padding:4px 10px;cursor:pointer;border:none;" onclick="openAddGroupMember('${escHtml(gid)}')"><i class="fa-solid fa-user-plus" style="font-size:9px;"></i> Добавить</button>
        </div>
        <div style="display:grid;gap:6px;max-height:240px;overflow-y:auto;">
          ${names.map(([uid, nm]) => `
            <div style="display:flex;align-items:center;gap:10px;padding:7px 8px;border-radius:12px;background:var(--paper);">
              <div class="chat-row-av chat-row-av-initial" style="width:34px;height:34px;font-size:13px;">${escHtml((nm || '?').charAt(0).toUpperCase())}</div>
              <span style="flex:1;font-size:13px;font-weight:600;color:var(--berry);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escHtml(nm)}${uid === me ? ' <span style="font-size:10px;color:var(--coral);">· это ты</span>' : (uid === meta.owner ? ' <span style="font-size:10px;color:var(--gold-ink);">· создатель</span>' : '')}</span>
            </div>`).join('')}
        </div>
        <button class="btn btn-ghost btn-block" style="margin-top:14px; color:var(--bad-ink); border-color:rgba(179,58,74,.25);" onclick="leaveGroupChat('${escHtml(gid)}'); this.closest('.modal-bg').remove();"><i class="fa-solid fa-right-from-bracket"></i> Покинуть группу</button>
      </div>`;
    document.body.appendChild(sheet);
  }

  // Добавить участника в группу (из друзей / всех учеников у админа) + системное сообщение
  function openAddGroupMember(gid) {
    const me = myUid();
    let pool;
    if (isAdmin()) {
      const dir = _usersDirCache || {};
      pool = {}; Object.keys(dir).forEach(uid => { if (uid !== me && !(dir[uid] && dir[uid].isAdmin)) pool[uid] = { name: dir[uid].name || 'Ученик' }; });
    } else pool = _friendsCache || {};
    const current = _chatMembers || {};
    const candidates = Object.keys(pool).filter(uid => !current[uid]);
    if (!candidates.length) { toast('Все уже в группе 🌸'); return; }
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center'; m.id = 'add-gm-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:340px;">
        <div class="page-eyebrow">ДОБАВИТЬ В ГРУППУ</div>
        <div class="display" style="font-size:18px;color:var(--berry);margin:2px 0 12px;">Кого добавить?</div>
        <div style="display:grid;gap:6px;max-height:300px;overflow-y:auto;">
          ${candidates.map(uid => {
            const nm = (pool[uid] && pool[uid].name) || (_usersDirCache && _usersDirCache[uid] && _usersDirCache[uid].name) || 'Участник';
            return `<button type="button" class="cw-lobby-card" style="padding:9px 12px;" onclick="addGroupMember('${escHtml(gid)}','${escHtml(uid)}','${escHtml(nm).replace(/'/g,'&#39;')}')">
              <div class="chat-row-av chat-row-av-initial" style="width:34px;height:34px;font-size:13px;">${escHtml(nm.charAt(0).toUpperCase())}</div>
              <span style="flex:1;font-size:13px;font-weight:600;color:var(--berry);text-align:left;">${escHtml(nm)}</span>
              <i class="fa-solid fa-plus" style="color:var(--coral);font-size:12px;"></i>
            </button>`;
          }).join('')}
        </div>
      </div>`;
    document.body.appendChild(m);
  }
  async function addGroupMember(gid, uid, nm) {
    if (typeof _db === 'undefined') return;
    const now = Date.now();
    const title = (_chatGroupMeta && _chatGroupMeta.title) || (_groupsCache[gid] && _groupsCache[gid].title) || 'Группа';
    const updates = {};
    updates[`chats/${gid}/meta/members/${uid}`] = true;
    updates[`users/${uid}/groups/${gid}`] = { title, since: now };
    const sysKey = _db.ref(`chats/${gid}/messages`).push().key;
    updates[`chats/${gid}/messages/${sysKey}`] = { type: 'system', text: `${nm} добавлен(а) в группу`, at: now };
    updates[`chats/${gid}/meta/lastAt`] = now;
    try {
      await _db.ref().update(updates);
      document.getElementById('add-gm-modal')?.remove();
      document.querySelector('.modal-sheet')?.closest('.modal-bg')?.remove();
      toast(`${nm} добавлен(а) 🌸`, 'var(--sage)');
      loadGroupMembers(gid);
    } catch (e) { console.warn(e); toast('Не получилось добавить'); }
  }

  async function leaveGroupChat(gid) {
    if (!confirm('Выйти из группы? История чата останется у остальных.')) return;
    const me = myUid();
    if (typeof _db === 'undefined') return;
    const now = Date.now();
    const updates = {};
    updates[`chats/${gid}/meta/members/${me}`] = null;
    updates[`users/${me}/groups/${gid}`] = null;
    updates[`users/${me}/unreadFrom/${gid}`] = null;
    // Системное сообщение о выходе
    const sysKey = _db.ref(`chats/${gid}/messages`).push().key;
    updates[`chats/${gid}/messages/${sysKey}`] = { type: 'system', text: `${myName()} вышел(ла) из группы`, at: now };
    updates[`chats/${gid}/meta/lastAt`] = now;
    try {
      await _db.ref().update(updates);
      closeChat();
      toast('Ты вышел(ла) из группы');
    } catch (e) { console.warn(e); toast('Не получилось выйти'); }
  }

  function closeChat() {
    stopTyping(); // clear my typing flag before tearing down
    detachChatListener();
    detachChatBuddyListener();
    _chatCurrentId = null;
    _chatOtherUid = null;
    _chatIsGroup = false;
    _chatMembers = {};
    _chatGroupMeta = null;
    _chatReplyTo = null;
    document.getElementById('chat-page')?.remove();
    document.getElementById('chat-modal')?.remove();
    document.body.classList.remove('chat-open');
    // Снимаем фокус, чтобы строка чата не оставалась с залипшей рамкой-обводкой
    try { document.activeElement?.blur(); } catch (_) {}
    renderFriendsAndChat(); // refresh previews/ordering after the conversation
  }

  // ════════════════ ПРОФИЛЬ ЧЕЛОВЕКА (стиль Telegram Premium) ════════════════
  // Открывается тапом по имени/аватару в шапке чата (и по своему профилю).
  // Сверху — фон-обложка, поверх — аватар, ниже — имя, статус, уровень, «о себе».
  function _userProfileHtml(o) {
    const name = escHtml(o.name || 'Профиль');
    const initial = escHtml((o.name || '?').charAt(0).toUpperCase());
    const coverStyle = o.cover ? `background-image:url(${o.cover});` : '';
    const avInner = o.avatar
      ? `<div class="up-avatar-img photo-zoom" data-photo-src="${o.avatar}" style="background:url(${o.avatar}) center/cover no-repeat;"></div>`
      : `<div class="up-avatar-initial">${initial}</div>`;
    const online = o.lastSeen && (Date.now() - o.lastSeen) < ONLINE_WINDOW_MS;
    const status = o.isMe ? 'это ты 🌸'
      : online ? '<span class="chat-online-dot"></span> в сети'
      : (o.lastSeen ? 'был(а) в сети ' + relativeTime(o.lastSeen) : 'не в сети');
    // Уровень / ранг / стрик
    let chips = '';
    if (o.stats) {
      const lvl = getLevel(o.stats.xp || 0);
      const rank = getRank(lvl, o.gender);
      const streak = o.stats.streak || 0;
      const words = (o.stats.wordsLearned && o.stats.wordsLearned.length) || o.stats.words || 0;
      chips = `<div class="up-chips">
        <div class="up-chip"><span class="up-chip-ico">${rank.emoji}</span><span><b>${lvl}</b> уровень<br><span class="up-chip-sub">${escHtml(rank.label)}</span></span></div>
        <div class="up-chip"><span class="up-chip-ico">🔥</span><span><b>${streak}</b><br><span class="up-chip-sub">${pluralDays(streak)} подряд</span></span></div>
        <div class="up-chip"><span class="up-chip-ico">📚</span><span><b>${words}</b><br><span class="up-chip-sub">слов выучено</span></span></div>
      </div>`;
    }
    const adminBadge = o.isAdmin ? ' <span class="chip chip-coral" style="font-size:10px;padding:2px 8px;vertical-align:middle;">🎓 учитель</span>' : '';
    const bioBlock = o.bio
      ? `<div class="up-section"><div class="up-section-label">О СЕБЕ</div><div class="up-bio">${escHtml(o.bio)}</div></div>`
      : (o.isMe ? `<div class="up-section"><div class="up-section-label">О СЕБЕ</div><div class="up-bio up-bio-empty" onclick="closeUserProfile(); showEditProfile();">Расскажи о себе — тапни, чтобы добавить 🌸</div></div>` : '');
    const joinLine = o.joinedAt ? `<div class="up-join">🌸 с нами с ${_fmtJoinDate(o.joinedAt)}</div>` : '';
    const action = o.isMe
      ? `<button class="up-action up-action-ghost" onclick="closeUserProfile(); showEditProfile();"><i class="fa-solid fa-pen"></i> Редактировать профиль</button>`
      : `<button class="up-action up-action-primary" onclick="_profileToChat('${escHtml(o.uid)}','${name.replace(/'/g,"&#39;")}')"><i class="fa-solid fa-paper-plane"></i> Написать сообщение</button>`;
    const editCover = o.isMe
      ? `<button class="up-cover-edit" onclick="closeUserProfile(); showEditProfile();" aria-label="Сменить обложку" title="Сменить обложку"><i class="fa-solid fa-camera"></i></button>`
      : '';
    return `
      <div class="up-cover${o.cover ? ' has-photo' : ''}" style="${coverStyle}">
        <button class="up-back" onclick="closeUserProfile()" aria-label="Назад"><i class="fa-solid fa-arrow-left"></i></button>
        ${editCover}
      </div>
      <div class="up-body">
        <div class="up-avatar">${avInner}${online ? '<span class="up-online-dot"></span>' : ''}</div>
        <div class="up-name">${name}${adminBadge}</div>
        <div class="up-status${online ? ' online' : ''}">${status}</div>
        ${chips}
        ${bioBlock}
        ${joinLine}
        <div class="up-actions">${action}</div>
      </div>`;
  }
  function _fmtJoinDate(ts) {
    const d = new Date(ts);
    return `${d.getDate()} ${monthsRu[d.getMonth()].toLowerCase()} ${d.getFullYear()}`;
  }
  function openUserProfile(uid) {
    if (!uid) return;
    const isMe = uid === myUid();
    document.getElementById('user-profile-page')?.remove();
    const dir = (_usersDirCache && _usersDirCache[uid]) || {};
    // Для себя — берём свежие локальные данные (имя/аватар/обложка/био/статистика)
    const seed = isMe
      ? { uid, isMe: true, name: (Store.get('user') || {}).name || dir.name, avatar: UStore.get('avatar') || dir.avatar,
          cover: UStore.get('cover') || dir.cover, bio: UStore.get('bio') || dir.bio,
          lastSeen: Date.now(), isAdmin: isAdmin(), stats, gender: userGender(), joinedAt: stats.firstOpenTs || dir.joinedAt }
      : { uid, isMe: false, name: dir.name, avatar: dir.avatar, cover: dir.cover, bio: dir.bio,
          lastSeen: dir.lastSeen, isAdmin: dir.isAdmin, stats: dir.stats, gender: dir.gender, joinedAt: dir.joinedAt };
    const m = document.createElement('div');
    m.className = 'user-profile-page';
    m.id = 'user-profile-page';
    m.innerHTML = _userProfileHtml(seed);
    document.body.appendChild(m);
    document.body.classList.add('chat-open');
    tagInteractive(m);
    // Подтягиваем свежий снимок (био/обложка могли обновиться на другом устройстве)
    if (!isMe && typeof _db !== 'undefined') {
      _db.ref('users/' + uid).once('value').then(snap => {
        const u = snap.val(); if (!u) return;
        const cur = document.getElementById('user-profile-page');
        if (!cur) return;
        cur.innerHTML = _userProfileHtml({ uid, isMe: false, name: u.name, avatar: u.avatar, cover: u.cover,
          bio: u.bio, lastSeen: u.lastSeen, isAdmin: u.isAdmin, stats: u.stats, gender: u.gender, joinedAt: u.joinedAt });
        tagInteractive(cur);
      }).catch(() => {});
    }
  }
  function closeUserProfile() {
    document.getElementById('user-profile-page')?.remove();
    // Снимаем chat-open только если под профилем нет открытого чата/игры.
    if (!document.querySelector('.chat-page') && !document.querySelector('.game-page')) {
      document.body.classList.remove('chat-open');
    }
  }
  function _profileToChat(uid, name) {
    closeUserProfile();
    // Если мы уже в этом чате (профиль открыли из шапки) — просто вернуться в него.
    if (_chatCurrentId && _chatCurrentId === chatIdFor(myUid(), uid)) return;
    openChat(uid, name);
  }

  // ── Chat message interactions: swipe-to-reply (Telegram-style), double-tap ❤️,
  //    long-press menu, reactions. All bound on the container via delegation so they
  //    survive the innerHTML re-render on every new message. ────────────────────────
  function attachChatGestures(bodyEl) {
    if (!bodyEl || bodyEl._gesturesBound) return;
    bodyEl._gesturesBound = true;
    let lpTimer = null, lpFired = false, lastMid = null, lastAt = 0, startX = 0, startY = 0;
    // swipe-to-reply state
    let swBubble = null, swMid = null, swDir = null, swPull = 0, swArmed = false;
    const SW_THRESHOLD = 56, SW_MAX = 84;
    const clearLp = () => { if (lpTimer) { clearTimeout(lpTimer); lpTimer = null; } };
    const bubbleOf = e => (e.target.closest ? e.target.closest('.chat-bubble[data-mid]') : null);
    const onChip = e => !!(e.target.closest && e.target.closest('.chat-react-chip'));

    const swipeArrow = () => {
      let a = document.getElementById('chat-swipe-arrow');
      if (!a) {
        a = document.createElement('div');
        a.id = 'chat-swipe-arrow';
        a.className = 'chat-swipe-arrow';
        a.innerHTML = '<i class="fa-solid fa-reply"></i>';
        document.body.appendChild(a);
      }
      return a;
    };
    const positionArrow = () => {
      if (!swBubble) return;
      const r = swBubble.getBoundingClientRect();
      const a = swipeArrow();
      const f = Math.min(1, swPull / SW_THRESHOLD);
      a.style.top = (r.top + r.height / 2) + 'px';
      a.style.left = Math.max(16, r.left - 34) + 'px';
      a.style.opacity = String(Math.max(0, f));
      a.style.transform = 'translate(-50%,-50%) scale(' + (0.5 + 0.5 * f) + ')';
      a.classList.toggle('armed', swArmed);
    };
    const hideArrow = () => {
      const a = document.getElementById('chat-swipe-arrow');
      if (a) { a.style.opacity = '0'; a.classList.remove('armed'); }
    };
    const resetSwipe = animate => {
      if (swBubble) {
        swBubble.style.transition = animate ? 'transform .18s ease' : '';
        swBubble.style.transform = '';
      }
      hideArrow();
      swBubble = null; swMid = null; swDir = null; swPull = 0; swArmed = false;
    };

    bodyEl.addEventListener('pointerdown', e => {
      if (onChip(e)) return;
      const b = bubbleOf(e); if (!b) return;
      lpFired = false; startX = e.clientX; startY = e.clientY;
      swBubble = b; swMid = b.dataset.mid; swDir = null; swPull = 0; swArmed = false;
      lpTimer = setTimeout(() => { lpFired = true; resetSwipe(true); openMsgMenu(b.dataset.mid); }, 480);
    });

    bodyEl.addEventListener('pointermove', e => {
      const dx = e.clientX - startX, dy = e.clientY - startY;
      if (lpTimer && (Math.abs(dx) > 10 || Math.abs(dy) > 10)) clearLp();
      if (!swBubble) return;
      if (swDir === null) {
        if (Math.abs(dx) < 8 && Math.abs(dy) < 8) return;
        if (dx > 0 && Math.abs(dx) > Math.abs(dy)) {
          swDir = 'h';
          swBubble.style.transition = 'none';
        } else {
          swDir = 'v'; swBubble = null; // vertical → native scroll, abandon swipe
          return;
        }
      }
      if (swDir === 'h') {
        if (e.cancelable) e.preventDefault();
        let p = dx;
        if (p > SW_THRESHOLD) p = SW_THRESHOLD + (p - SW_THRESHOLD) * 0.35; // rubber-band past threshold
        swPull = Math.max(0, Math.min(p, SW_MAX));
        swBubble.style.transform = 'translateX(' + swPull + 'px)';
        const armedNow = swPull >= SW_THRESHOLD;
        if (armedNow && !swArmed && navigator.vibrate) { try { navigator.vibrate(12); } catch (_) {} }
        swArmed = armedNow;
        positionArrow();
      }
    });

    bodyEl.addEventListener('pointerup', e => {
      clearLp();
      const dir = swDir;
      if (dir === 'h') {
        const fire = swArmed, mid = swMid;
        resetSwipe(true);
        if (fire && mid) startReply(mid);
        return; // a swipe is not also a tap
      }
      resetSwipe(false);
      if (dir === 'v') return;            // was a scroll, ignore
      if (lpFired || onChip(e)) return;
      const b = bubbleOf(e); if (!b) return;
      const mid = b.dataset.mid, now = Date.now();
      if (lastMid === mid && now - lastAt < 320) { lastMid = null; lastAt = 0; quickReact(mid); }
      else { lastMid = mid; lastAt = now; }
    });

    bodyEl.addEventListener('pointercancel', () => { clearLp(); resetSwipe(true); });
    bodyEl.addEventListener('contextmenu', e => {
      const b = bubbleOf(e); if (b) { e.preventDefault(); openMsgMenu(b.dataset.mid); }
    });
  }

  const CHAT_REACTIONS = ['❤️','😂','😮','😢','👍','🔥'];
  function openMsgMenu(mid) {
    const m = _lastChatMsgs[mid]; if (!m) return;
    const me = myUid();
    const mine = m.from === me;
    const myReact = (m.reactions && m.reactions[me]) || '';
    const sheet = document.createElement('div');
    sheet.className = 'modal-bg';
    sheet.onclick = e => { if (e.target === sheet) sheet.remove(); };
    sheet.innerHTML = `
      <div class="modal-sheet" style="border-radius:24px 24px 0 0; padding:16px 16px calc(20px + env(safe-area-inset-bottom,0px));">
        <div class="msg-react-row">
          ${CHAT_REACTIONS.map(em => `<button class="msg-react-btn ${myReact === em ? 'active' : ''}" onclick="reactMessage('${mid}','${em}'); this.closest('.modal-bg').remove();">${em}</button>`).join('')}
        </div>
        <div class="msg-menu-quote"><b>${escHtml(m.fromName || '')}</b><br>${escHtml((m.text || '').slice(0, 140))}</div>
        <button class="btn btn-ghost btn-block" style="margin-top:10px;" onclick="startReply('${mid}'); this.closest('.modal-bg').remove();"><i class="fa-solid fa-reply"></i> Ответить</button>
        ${mine ? `<button class="btn btn-ghost btn-block" style="margin-top:8px; color:var(--bad-ink); border-color:rgba(179,58,74,.25);" onclick="deleteChatMessage('${mid}'); this.closest('.modal-bg').remove();"><i class="fa-solid fa-trash"></i> Удалить</button>` : ''}
      </div>`;
    document.body.appendChild(sheet);
  }

  async function reactMessage(mid, emoji) {
    const m = _lastChatMsgs[mid]; if (!m || typeof _db === 'undefined') return;
    const me = myUid(); const chatId = _chatCurrentId; if (!chatId) return;
    const cur = (m.reactions && m.reactions[me]) || '';
    const ref = _db.ref(`chats/${chatId}/messages/${mid}/reactions/${me}`);
    try { if (cur === emoji) await ref.remove(); else await ref.set(emoji); } catch (_) {}
  }
  function quickReact(mid) { reactMessage(mid, '❤️'); }

  function startReply(mid) {
    const m = _lastChatMsgs[mid]; if (!m) return;
    _chatReplyTo = { id: mid, text: (m.text || '').slice(0, 200), from: m.from, fromName: m.fromName || '' };
    renderReplyPreview();
    document.getElementById('chat-input')?.focus();
  }
  function cancelReply() { _chatReplyTo = null; renderReplyPreview(); }
  function renderReplyPreview() {
    const bar = document.getElementById('chat-reply-preview');
    if (!bar) return;
    if (!_chatReplyTo) { bar.style.display = 'none'; bar.innerHTML = ''; return; }
    bar.style.display = 'flex';
    bar.innerHTML = `
      <div class="crp-bar"></div>
      <div class="crp-body">
        <div class="crp-name"><i class="fa-solid fa-reply" style="font-size:10px;"></i> ${escHtml(_chatReplyTo.fromName || '')}</div>
        <div class="crp-text">${escHtml(_chatReplyTo.text)}</div>
      </div>
      <button class="crp-x" onclick="cancelReply()" aria-label="Отменить ответ">×</button>`;
  }

  async function deleteChatMessage(mid) {
    const m = _lastChatMsgs[mid]; if (!m) return;
    if (m.from !== myUid()) { toast('Можно удалить только своё сообщение'); return; }
    const chatId = _chatCurrentId; if (!chatId || typeof _db === 'undefined') return;
    if (!confirm('Удалить сообщение?')) return;
    try { await _db.ref(`chats/${chatId}/messages/${mid}`).remove(); } catch (_) { toast('Не удалось удалить'); }
  }

  function detachChatListener() {
    if (_chatListenerOff) { try { _chatListenerOff(); } catch(_){} _chatListenerOff = null; }
  }

  function attachChatListener(chatId, otherUid) {
    detachChatListener();
    if (typeof _db === 'undefined') return;
    const mref = _db.ref(`chats/${chatId}/messages`).limitToLast(200);
    const mh = snap => {
      _lastChatMsgs = snap.val() || {};
      renderChatMessages(_lastChatMsgs);
      // New messages arrived while the chat is open → mark them read (clears unread, sets ✓✓).
      if (otherUid) markChatRead(otherUid, chatId);
    };
    mref.on('value', mh);
    // Read receipts: re-render ticks when the other side's read pointer moves.
    const rref = _db.ref(`chats/${chatId}/meta/read`);
    const rh = snap => { _chatReadMeta = snap.val() || {}; renderChatMessages(_lastChatMsgs); };
    rref.on('value', rh);
    // Typing indicator: repaint the header when the other side starts/stops typing.
    const tref = _db.ref(`chats/${chatId}/meta/typing`);
    const th = snap => { _chatTyping = snap.val() || {}; paintChatHeaderStatus(); };
    tref.on('value', th);
    // Tick so a stale "печатает…" fades on its own even without a new event.
    const typingTick = setInterval(paintChatHeaderStatus, 2500);
    _chatListenerOff = () => { mref.off('value', mh); rref.off('value', rh); tref.off('value', th); clearInterval(typingTick); };
  }

  // Detect a 1–3 emoji-only message so it can render big & bubble-less (jumbo), like Telegram.
  function emojiOnlyCount(text) {
    const t = (text || '').trim();
    if (!t) return 0;
    if (!/\p{Extended_Pictographic}/u.test(t)) return 0;
    // Strip emoji + modifiers + ZWJ + variation selectors + regional indicators + keycap mark.
    const stripped = t.replace(/[\p{Extended_Pictographic}\u{1F1E6}-\u{1F1FF}\u{1F3FB}-\u{1F3FF}\uFE0F\uFE0E\u200D\u20E3\s]/gu, '');
    if (stripped.length > 0) return 0; // contains real text → not jumbo
    try {
      if (typeof Intl !== 'undefined' && Intl.Segmenter) {
        return [...new Intl.Segmenter('en', { granularity: 'grapheme' }).segment(t)].length;
      }
    } catch (_) {}
    return (t.match(/\p{Extended_Pictographic}/gu) || []).length;
  }

  // Telegram-style reaction "pop": a big emoji + sparkle ring at the bubble.
  function burstReactionAt(mid, emoji) {
    const bubble = document.querySelector(`#chat-body .chat-bubble[data-mid="${mid}"]`);
    if (!bubble) return;
    const anchor = bubble.querySelector('.chat-reactions') || bubble;
    const r = anchor.getBoundingClientRect();
    if (!r.width && !r.height) return;
    const cx = r.left + Math.min(r.width, 44) / 2;
    const cy = r.top + r.height / 2;
    const pop = document.createElement('div');
    pop.className = 'react-burst';
    pop.textContent = emoji;
    pop.style.left = cx + 'px'; pop.style.top = cy + 'px';
    document.body.appendChild(pop);
    setTimeout(() => pop.remove(), 720);
    for (let i = 0; i < 6; i++) {
      const s = document.createElement('div');
      s.className = 'react-spark';
      const ang = (Math.PI * 2 * i) / 6 + Math.random() * 0.5;
      const dist = 20 + Math.random() * 16;
      s.style.left = cx + 'px'; s.style.top = cy + 'px';
      s.style.setProperty('--bx', (Math.cos(ang) * dist).toFixed(1) + 'px');
      s.style.setProperty('--by', (Math.sin(ang) * dist).toFixed(1) + 'px');
      s.style.animationDelay = (i * 12) + 'ms';
      document.body.appendChild(s);
      setTimeout(() => s.remove(), 720);
    }
  }

  function renderChatMessages(msgs) {
    const body = document.getElementById('chat-body');
    if (!body) return;
    const me = myUid();
    // ✓✓ logic: DM — the other side's read pointer; group — the freshest read among other members.
    let otherRead = 0;
    if (_chatIsGroup) {
      Object.entries(_chatReadMeta || {}).forEach(([uid, ts]) => {
        if (uid !== me && Number(ts) > otherRead) otherRead = Number(ts);
      });
    } else {
      otherRead = (_chatOtherUid && _chatReadMeta && _chatReadMeta[_chatOtherUid]) || 0;
    }
    const entries = Object.entries(msgs).map(([k, v]) => ({ key: k, ...v })).sort((a, b) => (a.at || 0) - (b.at || 0));
    if (!entries.length) {
      body.innerHTML = `<div style="text-align:center;padding:36px 24px;color:var(--soft);font-size:12px;">Пока тут пусто 🌸<br>Напиши первое сообщение!</div>`;
      _chatSeenKeys = new Set();
      return;
    }
    const firstPaint = _chatSeenKeys === null; // don't animate history when a chat opens
    // Keep the user's place if they scrolled up to read history.
    const nearBottom = (body.scrollHeight - body.scrollTop - body.clientHeight) < 90;
    let lastDay = '';
    let prevFrom = '';
    let html = '';
    for (const m of entries) {
      const d = new Date(m.at || Date.now());
      const dayKey = d.toDateString();
      if (dayKey !== lastDay) {
        html += `<div class="chat-day-label"><span>${escHtml(formatChatDay(d))}</span></div>`;
        lastDay = dayKey;
        prevFrom = ''; // a day break restarts the sender-name grouping
      }
      // Системное сообщение (вошёл/вышел/создал) — по центру, без пузыря
      if (m.type === 'system') {
        html += `<div class="chat-system"><span>${escHtml(m.text || '')}</span></div>`;
        prevFrom = '';
        continue;
      }
      const mine = m.from === me;
      // Group chats: show the sender name on the first bubble of each run (Telegram-style).
      const senderHtml = (_chatIsGroup && !mine && m.from !== prevFrom)
        ? `<div class="chat-sender-name nc-${nameColorIdx(m.from)}">${escHtml(m.fromName || (_chatMembers && _chatMembers[m.from]) || 'Участник')}</div>`
        : '';
      prevFrom = m.from;
      const time = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
      // Reply quote
      const replyHtml = m.replyTo ? `
        <div class="chat-reply-quote">
          <div class="crq-name">${escHtml(m.replyTo.fromName || '')}</div>
          <div class="crq-text">${escHtml((m.replyTo.text || '').slice(0, 120))}</div>
        </div>` : '';
      // Reactions (grouped emoji chips)
      let reactHtml = '';
      if (m.reactions && typeof m.reactions === 'object') {
        const counts = {};
        Object.values(m.reactions).forEach(em => { if (em) counts[em] = (counts[em] || 0) + 1; });
        const myEm = m.reactions[me] || '';
        const chips = Object.entries(counts).map(([em, n]) =>
          `<button class="chat-react-chip ${myEm === em ? 'mine' : ''}" onclick="event.stopPropagation(); reactMessage('${m.key}','${em}')">${em}${n > 1 ? ` ${n}` : ''}</button>`).join('');
        if (chips) reactHtml = `<div class="chat-reactions">${chips}</div>`;
      }
      // Delivery ticks on my own messages (✓ sent / ✓✓ read — visible to both)
      const tick = mine ? `<span class="chat-tick ${otherRead >= (m.at || 0) ? 'read' : ''}">${otherRead >= (m.at || 0) ? '✓✓' : '✓'}</span>` : '';
      // Jumbo: 1–3 emoji only → big, no bubble chrome.
      const jc = emojiOnlyCount(m.text);
      const jumbo = (jc >= 1 && jc <= 3) ? ` jumbo jumbo-${jc}` : '';
      // Entrance animation only for messages that appeared after the chat was open.
      const isNew = _chatSeenKeys && !_chatSeenKeys.has(m.key);
      const enter = isNew ? (mine ? ' chat-enter-mine' : ' chat-enter') : '';
      html += `
        <div class="chat-msg-row ${mine ? 'mine' : 'theirs'}">
          <div class="chat-bubble ${mine ? 'mine' : 'theirs'}${jumbo}${enter}" data-mid="${m.key}">
            ${senderHtml}
            ${replyHtml}
            <div class="chat-bubble-text">${escHtml(m.text)}</div>
            <div class="chat-bubble-meta"><span class="chat-bubble-time">${time}</span>${tick}</div>
            ${reactHtml}
          </div>
        </div>`;
    }
    body.innerHTML = html;
    if (nearBottom) body.scrollTop = body.scrollHeight;
    // Reaction burst: animate reactions that appeared since the previous render (either side).
    const curReactions = {};
    for (const m of entries) {
      if (m.reactions && typeof m.reactions === 'object') curReactions[m.key] = { ...m.reactions };
      if (!firstPaint) {
        const prev = _chatPrevReactions[m.key] || {};
        const cur = curReactions[m.key] || {};
        for (const uid in cur) {
          if (cur[uid] && cur[uid] !== prev[uid]) burstReactionAt(m.key, cur[uid]);
        }
      }
    }
    _chatPrevReactions = curReactions;
    if (firstPaint) _chatSeenKeys = new Set();
    entries.forEach(m => _chatSeenKeys.add(m.key));
  }

  function formatChatDay(d) {
    const today = new Date();
    today.setHours(0,0,0,0);
    const day = new Date(d);
    day.setHours(0,0,0,0);
    const diffDays = Math.round((today - day) / 86400000);
    if (diffDays === 0) return 'Сегодня';
    if (diffDays === 1) return 'Вчера';
    const months = ['янв','фев','мар','апр','мая','июн','июл','авг','сен','окт','ноя','дек'];
    return `${d.getDate()} ${months[d.getMonth()]}`;
  }

  async function sendCurrentChatMessage(otherUid, otherName) {
    const inp = document.getElementById('chat-input');
    if (!inp) return;
    const text = inp.value;
    if (!text.trim()) return;
    inp.value = '';
    await sendChatMessage(otherUid, otherName, text);
    inp.focus();
  }

  // ─────────────────────────── PUSH NOTIFICATIONS (FCM) ───────────────────────────
  // Foreground (site open): show in-app toast + sound; the OS banner is suppressed
  //   for the chat that's currently open so the user isn't spammed about their
  //   own active conversation.
  // Background (site minimized / closed): firebase-messaging-sw.js handles it and
  //   the browser/OS draws the banner.
  let _pushInitDone = false;
  let _pushUnsubFg = null;
  let _pushCurrentToken = null;

  async function initPushNotifications() {
    if (_pushInitDone) return;
    if (!_messaging) return; // unsupported browser (e.g. Safari on older iOS, file://)
    if (!('Notification' in window)) return;
    if (!isLoggedInForChat()) return;
    if (!_VAPID_KEY || _VAPID_KEY.startsWith('REPLACE_')) {
      console.warn('[push] VAPID key not configured — skipping push setup');
      return;
    }
    _pushInitDone = true;

    // Register the service worker explicitly. Default `firebase-messaging-sw.js`
    // at site root is picked up automatically, but doing it manually lets us
    // pass it to getToken and avoid race conditions on slow connections.
    let swReg;
    try {
      swReg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
    } catch (e) {
      console.warn('[push] SW register failed', e);
      return;
    }

    // Don't auto-prompt — wait until the user explicitly asks (see askPushPermission)
    if (Notification.permission !== 'granted') return;
    await registerFcmToken(swReg);
    attachForegroundMessageHandler();
  }

  async function askPushPermission() {
    if (!_messaging) { toast('Этот браузер не поддерживает push 🌸'); return; }
    if (!('Notification' in window)) { toast('Этот браузер не поддерживает уведомления'); return; }
    if (!_VAPID_KEY || _VAPID_KEY.startsWith('REPLACE_')) {
      toast('Push ещё не настроен (нет VAPID ключа)');
      return;
    }
    if (Notification.permission === 'granted') {
      toast('Уведомления уже включены ✓', 'var(--sage)');
      return;
    }
    if (Notification.permission === 'denied') {
      toast('Разреши уведомления в настройках браузера');
      return;
    }
    const res = await Notification.requestPermission();
    if (res !== 'granted') {
      toast('Уведомления не включены');
      return;
    }
    let swReg;
    try {
      swReg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
    } catch (e) { console.warn('[push] SW register failed', e); return; }
    await registerFcmToken(swReg);
    attachForegroundMessageHandler();
    toast('Push-уведомления включены 🔔', 'var(--sage)');
    renderSettingsCard(); // строка «Уведомления» сразу показывает «ВКЛ ✓»
  }

  async function registerFcmToken(swReg) {
    try {
      const token = await _messaging.getToken({
        vapidKey: _VAPID_KEY,
        serviceWorkerRegistration: swReg
      });
      if (!token) { console.warn('[push] empty token'); return; }
      _pushCurrentToken = token;
      const uid = firebaseUserId();
      if (!uid || uid === 'guest') return;
      // Save under users/{uid}/fcmTokens/{token} = lastUpdatedAt — the Cloud
      // Function reads this list to deliver pushes. Storing as a sub-key (not
      // a value) lets us prune invalid tokens individually.
      await _db.ref(`users/${uid}/fcmTokens/${token}`).set(Date.now());
    } catch (e) {
      console.warn('[push] getToken failed', e);
    }
  }

  function attachForegroundMessageHandler() {
    if (!_messaging || _pushUnsubFg) return;
    _pushUnsubFg = _messaging.onMessage(payload => {
      const data = payload.data || {};
      const noti = payload.notification || {};
      const title = noti.title || data.fromName || 'Новое сообщение';
      const body  = noti.body  || '';
      // Suppress if the chat with that sender is already open
      const fromUid = data.from || '';
      const chatId  = data.chatId || '';
      if (chatId && _chatCurrentId === chatId) {
        // Same chat is open — message will appear in real time anyway
        return;
      }
      // In-app banner (same component as the realtime popup, deduped by sender uid)
      try {
        if (fromUid) showChatPopup(fromUid, title, (data.fromAvatar || ''), body);
        else toast(`💬 ${title}: ${body.length > 60 ? body.slice(0, 60) + '…' : body}`, 'var(--berry)');
      } catch (_) {}
      // Some browsers also fire the SW notification while the page is foregrounded;
      // others don't. We render it ourselves so behavior is consistent.
      try {
        if (Notification.permission === 'granted' && document.hidden) {
          new Notification(title, {
            body, icon: '/assets/logo-app.png', tag: chatId ? `chat-${chatId}` : undefined
          });
        }
      } catch (_) {}
    });
  }

  // Listen for SW → page messages: "open chat X" when user taps the notification
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.addEventListener('message', ev => {
      const m = ev.data || {};
      if (m.kind === 'fcm-notification-click' && m.data && m.data.from) {
        const fromUid = m.data.from;
        const fromName = m.data.fromName || 'Друг';
        try { switchScreen('profile'); } catch (_) {}
        try { openChat(fromUid, fromName); } catch (_) {}
      }
    });
  }

  // ─────────────────────────── PWA INSTALL HINT ───────────────────────────
  function _pwaIsStandalone() {
    return (window.matchMedia && window.matchMedia('(display-mode: standalone)').matches)
      || window.navigator.standalone === true;
  }
  function _pwaIsIos() {
    return /iphone|ipad|ipod/i.test(navigator.userAgent) && !window.MSStream;
  }
  function renderPwaInstallHint() {
    if (_pwaIsStandalone()) return;                       // уже установлено
    if (Store.get('pwaHintDismissed')) return;            // пользователь закрыл
    if (document.getElementById('pwa-install-hint')) return;
    const canPrompt = !!window._pwaInstallEvent;
    const ios = _pwaIsIos();
    if (!canPrompt && !ios) return;                       // нечего предложить
    const slot = document.getElementById('continue-slot');
    if (!slot) return;
    const card = document.createElement('div');
    card.id = 'pwa-install-hint';
    card.style.cssText = 'margin-bottom:10px;';
    card.innerHTML = `
      <div class="card" style="padding:13px 14px; display:flex; align-items:center; gap:12px; background:linear-gradient(135deg, var(--blush), var(--card));">
        <img src="assets/pwa/icon-192.png" alt="" style="width:42px; height:42px; border-radius:12px; flex-shrink:0; box-shadow:var(--shadow-md);">
        <div style="flex:1; min-width:0;">
          <div style="font-weight:600; color:var(--berry); font-size:13px;">Установи Madie на телефон</div>
          <div style="font-size:11px; color:var(--soft); margin-top:1px;">${ios && !canPrompt
            ? 'Нажми <i class="fa-solid fa-arrow-up-from-bracket"></i> Поделиться → «На экран “Домой”»'
            : 'Своя иконка, быстрый запуск, работает как приложение'}</div>
        </div>
        ${canPrompt ? `<button onclick="pwaPromptInstall()" class="btn btn-primary" style="padding:8px 14px; font-size:12px; flex-shrink:0;">Установить</button>` : ''}
        <button onclick="pwaDismissHint()" aria-label="Скрыть" style="background:none; border:none; color:var(--hush); font-size:14px; cursor:pointer; padding:4px; flex-shrink:0;"><i class="fa-solid fa-xmark"></i></button>
      </div>`;
    slot.parentNode.insertBefore(card, slot);
  }
  async function pwaPromptInstall() {
    const e = window._pwaInstallEvent;
    if (!e) return;
    e.prompt();
    try {
      const { outcome } = await e.userChoice;
      if (outcome === 'accepted') {
        toast('Madie теперь на твоём экране 🌸', 'var(--sage)');
        document.getElementById('pwa-install-hint')?.remove();
      }
    } catch (_) {}
    window._pwaInstallEvent = null;
  }
  function pwaDismissHint() {
    Store.set('pwaHintDismissed', 1);
    document.getElementById('pwa-install-hint')?.remove();
  }

  // ─────────────────────────── РЕФЕРАЛКА ───────────────────────────
  const REFERRAL_XP = 200;
  // захват ?ref=... при загрузке (до регистрации)
  (function captureRef() {
    try {
      const ref = new URLSearchParams(location.search).get('ref');
      if (ref && !Store.get('user')) Store.set('pendingRef', ref);
    } catch (_) {}
  })();
  function shareInviteLink() {
    const u = Store.get('user');
    const uid = (typeof firebaseUserId === 'function' ? firebaseUserId() : '') || '';
    if (!u || u.guest || !uid || uid === 'guest') { toast('Сначала войди в аккаунт 🌸'); return; }
    const link = location.origin + location.pathname + '?ref=' + encodeURIComponent(uid);
    const text = `Учу корейский с Madie 🌸 — присоединяйся! Зарегистрируешься по моей ссылке — нам обоим +${REFERRAL_XP} XP: ${link}`;
    if (navigator.share) {
      navigator.share({ title: 'Korean with Madie', text }).catch(() => {});
    } else {
      navigator.clipboard?.writeText(text).then(
        () => toast('Ссылка-приглашение скопирована 💌', 'var(--sage)'),
        () => toast(link, 'var(--berry)')
      );
    }
  }
  // вызвать после успешной регистрации нового пользователя
  function applyPendingReferral(newUid, newName) {
    const refUid = Store.get('pendingRef');
    if (!refUid || typeof _db === 'undefined') return;
    Store.del('pendingRef');
    if (!newUid || refUid === newUid) return;
    try {
      _db.ref('shared/referrals').push({ newUid, newName: newName || '', refUid, ts: Date.now() });
      // награда пригласившему — письмо в его inbox (его клиент начислит XP)
      _db.ref('users/' + refUid + '/inbox').push({ type: 'referral', fromName: newName || 'Новый ученик', ts: Date.now() });
      // награда новичку — сразу
      setTimeout(() => {
        addXp(REFERRAL_XP, false);
        toast(`Бонус за приглашение: +${REFERRAL_XP} XP 💌`, 'var(--sage)');
      }, 1500);
    } catch (_) {}
  }
  // пригласивший получает свои XP, когда его клиент видит письмо type='referral'
  function processReferralRewards() {
    if (typeof _db === 'undefined') return;
    const me = (typeof firebaseUserId === 'function' ? firebaseUserId() : '') || '';
    if (!me || me === 'guest') return;
    Object.entries(_inboxCache || {}).forEach(([key, v]) => {
      if (!v || v.type !== 'referral' || v.claimed) return;
      _db.ref(`users/${me}/inbox/${key}`).remove();
      addXp(REFERRAL_XP, false);
      toast(`${escHtml(v.fromName || 'Друг')} присоединился по твоей ссылке! +${REFERRAL_XP} XP 💌`, 'var(--sage)');
    });
  }

  // ─────────────────────────── НАСТРОЙКИ ПРИЛОЖЕНИЯ ───────────────────────────
  const SETTINGS_DEFAULTS = { sound: true, slowVoice: false, petals: true, calmMotion: false, scape: null, scapeVol: 0.5, darkTheme: false, darkAuto: false, colorTheme: 'madie', gender: '' };
  // Пол пользователя ('f'|'m'|''). Пусто → спрашиваем. Гендерные обращения по всему UI.
  function userGender() {
    const g = getSettings().gender;
    return (g === 'm' || g === 'f') ? g : '';
  }
  // gw(женская_форма, мужская_форма) — выбирает по полу пользователя (по умолчанию женская).
  function gw(f, m) { return userGender() === 'm' ? m : f; }
  function setGender(g) {
    const s = getSettings();
    s.gender = (g === 'm') ? 'm' : 'f';
    UStore.set('settings', s);
    renderSettingsCard();
    // Перерисовать места с гендерными обращениями (ранг в профиле и т.п.)
    try { syncAchievementsStrip(); } catch (_) {}
    try { if (_curScreen === 'profile') switchScreen('profile', true); } catch (_) {}
    toast(g === 'm' ? 'Готово — обращаемся в мужском роде 🙂' : 'Готово — обращаемся в женском роде 🙂', 'var(--berry)');
  }
  // Для конкретного пользователя (ученика в админке): пол берём из meta.gender 'Ж'/'М'.
  function gwFor(metaGender, f, m) { return metaGender === 'М' ? m : f; }
  // ── Цветовые темы (свотчи в Настройках; CSS-классы ct-* в styles.css) ──
  const COLOR_THEMES = [
    { key: 'madie',   name: 'Madie',     a: '#D9687A', b: '#FBE8EA' },
    { key: 'emerald', name: 'Изумруд',   a: '#3A6F69', b: '#D2FBF7' },
    { key: 'blossom', name: 'Роза·лайм', a: '#EEC1DF', b: '#E3FB9E' },
    { key: 'lime',    name: 'Лайм',      a: '#494949', b: '#C3FA4E' },
    { key: 'sky',     name: 'Небо',      a: '#A0D3F7', b: '#F7EDC0' },
    { key: 'mono',    name: 'Ч/б',       a: '#2B2B2B', b: '#F5F5F5' }
  ];
  function setColorTheme(key) {
    if (!COLOR_THEMES.some(t => t.key === key)) return;
    const s = getSettings();
    s.colorTheme = key;
    // Цветовые темы — светлые палитры; тёмный режим перекрыл бы их целиком.
    // Поэтому выбор цветовой темы выключает тёмный режим, чтобы тема была видна.
    s.darkTheme = false;
    s.darkAuto = false;
    UStore.set('settings', s);
    applySettings();
    // Обновляем активный свотч на месте, без перерисовки карточки
    document.querySelectorAll('#settings-card .theme-swatch-wrap').forEach(b =>
      b.classList.toggle('active', b.dataset.theme === key));
    // Синхронизируем переключатели «Тёмная тема» / «Авто-тёмная» в карточке настроек
    const dsw = document.querySelector('#settings-card [data-setting="darkTheme"] .switch');
    if (dsw) dsw.classList.remove('on');
    const asw = document.querySelector('#settings-card [data-setting="darkAuto"] .switch');
    if (asw) asw.classList.remove('on');
    const t = COLOR_THEMES.find(t => t.key === key);
    toast(`Тема «${t.name}» включена 🎨`, 'var(--berry)');
  }
  // Ночь для авто-тёмной темы: с 20:00 до 08:00
  function isNightTime() {
    const h = new Date().getHours();
    return h >= 20 || h < 8;
  }
  let _darkAutoTimer = null;
  function getSettings() {
    const s = UStore.get('settings', null);
    return { ...SETTINGS_DEFAULTS, ...(s && typeof s === 'object' ? s : {}) };
  }
  function toggleSetting(key) {
    const s = getSettings();
    s[key] = !s[key];
    UStore.set('settings', s);
    applySettings();
    // Плавно: переключаем класс на месте, без перерисовки всей карточки
    const sw = document.querySelector(`#settings-card [data-setting="${key}"] .switch`);
    if (sw) sw.classList.toggle('on', s[key]); else renderSettingsCard();
    if (key === 'sound') toast(s.sound ? 'Озвучка включена 🔊' : 'Озвучка выключена 🔇', 'var(--berry)');
  }
  function openSettingsModal() {
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.id = 'settings-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:420px; max-height:84vh; display:flex; flex-direction:column;">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; flex-shrink:0;">
          <div style="display:flex; align-items:center; gap:10px;">
            <span style="width:36px; height:36px; border-radius:12px; background:var(--blush); display:flex; align-items:center; justify-content:center; font-size:17px;"><i class="fa-solid fa-gear" style="color:var(--coral);"></i></span>
            <div class="display" style="font-size:20px; color:var(--berry);">Настройки</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:24px; color:var(--soft); cursor:pointer; padding:2px 6px;">×</div>
        </div>
        <div style="overflow-y:auto; min-height:0;">
          <div id="settings-card" style="padding:0 4px;"></div>
          <div style="text-align:center; padding:14px 0 6px; font-size:10.5px; color:var(--hush);">Korean with Madie · сделано с 🌸</div>
        </div>
      </div>`;
    document.body.appendChild(m);
    renderSettingsCard();
  }
  function applySettings() {
    const s = getSettings();
    document.body.classList.toggle('no-petals', !s.petals);
    document.body.classList.toggle('calm-motion', s.calmMotion);
    // Тёмная тема: вручную ИЛИ авто-режимом ночью (20:00–08:00)
    const dark = !!s.darkTheme || (s.darkAuto && isNightTime());
    document.body.classList.toggle('theme-dark', dark);
    // Цветовая тема: один класс ct-<key>; 'madie' — родная палитра без класса.
    // ВАЖНО: цветовые темы — только для светлого режима. В тёмной теме своя полная
    // палитра, и ct-* НЕ применяем — иначе !important-оверрайды цветовой темы
    // (напр. ч/б .topik-hero) перебивают тёмные поверхности и текст становится
    // нечитаемым (светлый текст на светлой карточке).
    COLOR_THEMES.forEach(t => { if (t.key !== 'madie') document.body.classList.remove('ct-' + t.key); });
    if (!dark && s.colorTheme && s.colorTheme !== 'madie') document.body.classList.add('ct-' + s.colorTheme);
    // Авто-режим: раз в минуту проверяем, не наступила ли ночь/утро
    if (s.darkAuto && !_darkAutoTimer) _darkAutoTimer = setInterval(applySettings, 60000);
    if (!s.darkAuto && _darkAutoTimer) { clearInterval(_darkAutoTimer); _darkAutoTimer = null; }
    const meta = document.querySelector('meta[name="theme-color"]');
    if (meta) meta.setAttribute('content', dark ? '#121212' : '#FFFAF6');
  }
  function renderSettingsCard() {
    const slot = document.getElementById('settings-card');
    if (!slot) return;
    const s = getSettings();
    const pushPerm = !('Notification' in window) ? 'unsupported' : Notification.permission;
    const pushState = pushPerm === 'unsupported' ? 'недоступны в этом браузере'
      : pushPerm === 'granted' ? 'включены · придут новые сообщения и стрик'
      : pushPerm === 'denied' ? 'заблокированы — разреши в настройках браузера'
      : 'выключены · нажми, чтобы включить';
    const pushRight = pushPerm === 'granted'
      ? '<span class="chip chip-sage" style="font-size:9px; padding:3px 9px;">ВКЛ ✓</span>'
      : pushPerm === 'denied'
        ? '<span class="chip chip-coral" style="font-size:9px; padding:3px 9px;">БЛОК</span>'
        : `<i class="fa-solid fa-chevron-right" style="color:var(--coral); font-size:11px;"></i>`;
    const row = (ico, title, sub, right, onclick, key) => `
      <button type="button" class="settings-row" ${key ? `data-setting="${key}"` : ''} onclick="${onclick}">
        <span class="settings-ico">${ico}</span>
        <span class="settings-tx">
          <span class="settings-title" style="display:block;">${title}</span>
          ${sub ? `<span class="settings-sub" style="display:block;">${sub}</span>` : ''}
        </span>
        ${right}
      </button>`;
    const sw = on => `<span class="switch ${on ? 'on' : ''}"></span>`;
    const chev = `<i class="fa-solid fa-chevron-right" style="color:var(--coral); font-size:11px;"></i>`;
    slot.innerHTML = [
      row('🔊', 'Озвучка слов', 'Произношение слогов и слов', sw(s.sound), "toggleSetting('sound')", 'sound'),
      row('🐢', 'Медленный голос', 'Озвучка помедленнее — легче расслышать', sw(s.slowVoice), "toggleSetting('slowVoice')", 'slowVoice'),
      row('🌸', 'Лепестки сакуры', 'Падающие лепестки на фоне', sw(s.petals), "toggleSetting('petals')", 'petals'),
      row('🕊️', 'Спокойный режим', 'Меньше анимаций и движения', sw(s.calmMotion), "toggleSetting('calmMotion')", 'calmMotion'),
      row('🌙', 'Тёмная тема', 'Графит и синий — строго и спокойно', sw(s.darkTheme), "toggleSetting('darkTheme')", 'darkTheme'),
      row('🌗', 'Авто-тёмная ночью', 'С 20:00 до 08:00 тёмная тема включается сама', sw(s.darkAuto), "toggleSetting('darkAuto')", 'darkAuto'),
      `<div class="theme-picker">
        <div class="theme-picker-title">🎨 Цветовая тема <span style="font-weight:500; color:var(--hush); font-size:10.5px;">— меняет всё приложение</span></div>
        <div class="theme-swatches">
          ${COLOR_THEMES.map(t => `
            <button type="button" class="theme-swatch-wrap ${s.colorTheme === t.key ? 'active' : ''}" data-theme="${t.key}" onclick="setColorTheme('${t.key}')" aria-label="Тема ${t.name}">
              <span class="theme-swatch"><span style="background:${t.a}"></span><span style="background:${t.b}"></span><i class="fa-solid fa-check" aria-hidden="true"></i></span>
              <span class="theme-swatch-name">${t.name}</span>
            </button>`).join('')}
        </div>
      </div>`,
      `<div class="gender-pick" ${s.gender ? '' : 'data-required="1"'}>
        <div class="gender-pick-title">🧑 Пол <span style="font-weight:500; color:var(--hush); font-size:10.5px;">— для правильных обращений${s.gender ? '' : ' · укажи, пожалуйста'}</span></div>
        <div class="gender-pick-row">
          <button type="button" class="gender-opt ${s.gender === 'f' ? 'active' : ''}" onclick="setGender('f')">👩 Женский</button>
          <button type="button" class="gender-opt ${s.gender === 'm' ? 'active' : ''}" onclick="setGender('m')">👨 Мужской</button>
        </div>
      </div>`,
      ...((Store.get('user') && !Store.get('user').isAdmin) ? [
        row('💎', 'Мой тариф', `Сейчас: ${PLANS[myPlanId()].emoji} ${PLANS[myPlanId()].name} — посмотреть или сменить`, chev, "document.getElementById('settings-modal')?.remove(); openPlanPage()")
      ] : []),
      row('🌸', 'Знакомство с Madie', 'Посмотреть интро и пройти квиз заново', chev, 'startOnboardingTour()'),
      row('🎯', 'Цель дня', 'Сколько XP в день хочешь набирать', chev, 'openDailyGoalSettings()'),
      row('🔔', 'Уведомления', pushState, pushRight, 'askPushPermission()'),
      row('💌', 'Написать нам', 'Идеи, ошибки, пожелания — читает Мади', chev, 'openFeedbackModal()'),
      row('📜', 'Условия использования', 'Правила и политика конфиденциальности', chev, 'showTermsModal()'),
      ...(Store.get('user') ? [
        row('✏️', 'Редактировать профиль', 'Имя, аватар и фон профиля', chev, "document.getElementById('settings-modal')?.remove(); showEditProfile()"),
        row('🚪', 'Выйти из аккаунта', 'Прогресс сохранён — вернёшься в любой момент', `<i class="fa-solid fa-arrow-right-from-bracket" style="color:var(--bad-ink); font-size:13px;"></i>`, "document.getElementById('settings-modal')?.remove(); logoutUser()")
      ] : [])
    ].join('');
  }

  // ─────────────────────────── ОБРАТНАЯ СВЯЗЬ ───────────────────────────
  let _fbType = 'idea';
  function openFeedbackModal(presetType) {
    _fbType = presetType || 'idea';
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.id = 'feedback-modal';
    m.onclick = e => { if (e.target === m) m.remove(); };
    m.innerHTML = `
      <div class="modal-card" style="max-width:400px;">
        <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:12px;">
          <div>
            <div class="page-eyebrow">ОБРАТНАЯ СВЯЗЬ</div>
            <div class="display" style="font-size:20px; color:var(--berry); margin-top:4px;">Напиши нам 💌</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:24px; color:var(--soft); cursor:pointer;">×</div>
        </div>
        <div style="font-size:12px; color:var(--soft); margin-bottom:12px; line-height:1.5;">Нашла ошибку? Есть идея, как сделать Madie лучше? Расскажи — мы читаем каждое сообщение 🌸</div>
        <div style="display:flex; gap:8px; margin-bottom:12px;">
          ${[['idea','💡 Идея'],['bug','🐞 Ошибка'],['other','💬 Другое']].map(([k,l]) =>
            `<button type="button" data-fbtype="${k}" onclick="setFbType('${k}')" class="auth-tab ${k===_fbType?'auth-tab-active':''}" style="flex:1; font-size:12px; padding:9px 4px;">${l}</button>`).join('')}
        </div>
        <textarea id="fb-text" class="input" rows="4" placeholder="Опиши подробно: что случилось или что хочется добавить…" style="resize:vertical; min-height:96px; padding-top:10px;"></textarea>
        <button onclick="submitFeedback(this)" class="btn btn-primary btn-block" style="margin-top:12px;">Отправить 🌸</button>
        <div style="text-align:center; font-size:10.5px; color:var(--hush); margin-top:8px;">Сообщение уйдёт команде Madie вместе с твоим именем</div>
      </div>`;
    document.body.appendChild(m);
    setTimeout(() => document.getElementById('fb-text')?.focus(), 60);
  }
  function setFbType(t) {
    _fbType = t;
    document.querySelectorAll('#feedback-modal [data-fbtype]').forEach(b =>
      b.classList.toggle('auth-tab-active', b.getAttribute('data-fbtype') === t));
  }
  function submitFeedback(btn) {
    const ta = document.getElementById('fb-text');
    const text = (ta && ta.value || '').trim();
    if (text.length < 5) { toast('Напиши чуть подробнее 🌸'); return; }
    if (typeof _db === 'undefined') { toast('Нет соединения — попробуй позже'); return; }
    const u = Store.get('user') || {};
    if (btn) { btn.disabled = true; btn.textContent = 'Отправляю…'; }
    _db.ref('shared/feedback').push({
      type: _fbType,
      text: text.slice(0, 2000),
      name: u.name || 'Гость',
      email: u.email || '',
      uid: (typeof firebaseUserId === 'function' ? firebaseUserId() : '') || '',
      ts: Date.now(),
      ua: (navigator.userAgent || '').slice(0, 160),
      done: false
    }).then(() => {
      document.getElementById('feedback-modal')?.remove();
      toast('Спасибо! Сообщение у Мади 💌', 'var(--sage)');
    }).catch(e => {
      if (btn) { btn.disabled = false; btn.textContent = 'Отправить 🌸'; }
      const denied = e && (e.code === 'PERMISSION_DENIED' || /permission/i.test(e.message || ''));
      toast(denied ? 'Нет доступа к базе — скажи Мади про правила 🌸' : 'Не отправилось — проверь интернет');
    });
  }

  // — Админ: входящие письма —
  let _feedbackCache = null;
  let _feedbackRefOn = false;
  function ensureFeedbackListener() {
    if (_feedbackRefOn || typeof _db === 'undefined') return;
    _feedbackRefOn = true;
    _db.ref('shared/feedback').on('value', snap => {
      _feedbackCache = snap.val() || {};
      if (adminCurrentTab === 'inbox') renderProfileAdminPanel('inbox');
      else if (adminCurrentTab === 'hub') renderProfileAdminPanel('hub'); // бейдж на карточке «Письма»
      const badge = document.getElementById('admin-inbox-count');
      if (badge) {
        const fresh = Object.values(_feedbackCache).filter(f => f && !f.done).length;
        badge.textContent = fresh || '';
      }
    });
  }
  function renderAdminInbox() {
    ensureFeedbackListener();
    if (_feedbackCache === null) {
      return `<div style="text-align:center; padding:24px; color:var(--soft); font-size:12px;">Загружаю сообщения…</div>`;
    }
    const items = Object.entries(_feedbackCache)
      .map(([id, f]) => ({ id, ...(f || {}) }))
      .sort((a, b) => (b.ts || 0) - (a.ts || 0));
    if (!items.length) {
      return `<div style="text-align:center; padding:24px; color:var(--soft); font-size:12px;">Пока ни одного сообщения 💌</div>`;
    }
    const typeLabel = { idea: '💡 Идея', bug: '🐞 Ошибка', other: '💬 Другое' };
    return `<div style="display:grid; gap:10px;">${items.map(f => `
      <div class="card card-padded" style="${f.done ? 'opacity:.6;' : ''}">
        <div style="display:flex; justify-content:space-between; align-items:center; gap:8px; margin-bottom:6px;">
          <span class="chip ${f.type === 'bug' ? 'chip-coral' : 'chip-blush'}" style="font-size:10px;">${typeLabel[f.type] || '💬'}</span>
          <span style="font-size:10px; color:var(--hush);">${f.ts ? new Date(f.ts).toLocaleString('ru-RU', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' }) : ''}</span>
        </div>
        <div style="font-size:13px; color:var(--ink); line-height:1.55; white-space:pre-wrap; word-break:break-word;">${escHtml(f.text || '')}</div>
        <div style="font-size:10.5px; color:var(--soft); margin-top:8px;">${escHtml(f.name || 'Гость')}${f.email ? ` · ${escHtml(f.email)}` : ''}</div>
        <div style="display:flex; gap:8px; margin-top:10px;">
          <button onclick="adminToggleFeedbackDone('${f.id}', ${f.done ? 'false' : 'true'})" class="btn btn-ghost" style="flex:1; padding:7px 8px; font-size:11px;">${f.done ? '↩ Вернуть в новые' : '✓ Прочитано'}</button>
          <button onclick="adminDeleteFeedback('${f.id}')" class="btn btn-ghost" style="padding:7px 12px; font-size:11px; color:var(--bad-ink); border-color:rgba(179,58,74,.25);"><i class="fa-solid fa-trash"></i></button>
        </div>
      </div>`).join('')}</div>`;
  }
  function adminToggleFeedbackDone(id, done) {
    if (!ensureAdminAccess() || typeof _db === 'undefined') return;
    _db.ref('shared/feedback/' + id + '/done').set(done);
  }
  function adminDeleteFeedback(id) {
    if (!ensureAdminAccess() || typeof _db === 'undefined') return;
    if (!confirm('Удалить это сообщение?')) return;
    _db.ref('shared/feedback/' + id).remove();
  }

  // ─────────────────────────── УСЛОВИЯ ИСПОЛЬЗОВАНИЯ ───────────────────────────
  function showTermsModal() {
    const m = document.createElement('div');
    m.className = 'modal-bg modal-center';
    m.onclick = e => { if (e.target === m) m.remove(); };
    const h = t => `<div style="font-weight:700; color:var(--berry); font-size:13.5px; margin:16px 0 6px;">${t}</div>`;
    const p = t => `<div style="font-size:12.5px; color:var(--ink); line-height:1.65;">${t}</div>`;
    m.innerHTML = `
      <div class="modal-card" style="max-width:440px; max-height:84vh; display:flex; flex-direction:column;">
        <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px; flex-shrink:0;">
          <div>
            <div class="page-eyebrow">KOREAN WITH MADIE</div>
            <div class="display" style="font-size:20px; color:var(--berry); margin-top:4px;">Условия использования</div>
            <div style="font-size:10.5px; color:var(--hush); margin-top:3px;">Обновлено: 10 июня 2026</div>
          </div>
          <div onclick="this.closest('.modal-bg').remove()" style="font-size:24px; color:var(--soft); cursor:pointer;">×</div>
        </div>
        <div style="overflow-y:auto; padding-right:6px; min-height:0;">
          ${h('1. О приложении')}
          ${p('Korean with Madie («Madie», «мы») — образовательное приложение для изучения корейского языка: уроки хангыля, мини-игры, словарь, общение между учениками и подготовка к экзамену TOPIK I. Используя приложение, ты соглашаешься с этими условиями. Если ты не согласен(на) — пожалуйста, не используй приложение.')}
          ${h('2. Аккаунт')}
          ${p('Для сохранения прогресса нужен аккаунт: имя, email и пароль. Пароль хранится в защищённом виде в Firebase Authentication (Google) — мы не видим его. Ты отвечаешь за сохранность своего пароля и за действия, совершённые с твоего аккаунта. Можно пользоваться приложением как гость — тогда прогресс хранится только на твоём устройстве.')}
          ${h('3. Какие данные мы храним')}
          ${p('• Имя и email — для входа и отображения в профиле.<br>• Прогресс обучения: XP, стрик, пройденные уроки, результаты игр и тестов, сохранённые слова.<br>• Аватар, если ты его загрузишь.<br>• Сообщения в чате — видны только тебе и собеседнику.<br>• Сообщения обратной связи — их читает команда Madie.<br>Данные хранятся в Google Firebase. Мы НЕ продаём и не передаём твои данные третьим лицам. Данные используются только для работы приложения.')}
          ${h('4. Дети и подростки')}
          ${p('Приложение подходит для всех возрастов. Если тебе меньше 14 лет — попроси родителей помочь с регистрацией: регистрируясь, они соглашаются с этими условиями за тебя.')}
          ${h('5. Правила общения')}
          ${p('В чате и комментариях запрещены: оскорбления, травля, спам, реклама, контент 18+, разжигание ненависти и любые незаконные материалы. Нарушителей можем ограничить или заблокировать без предупреждения.')}
          ${h('6. Контент и материалы')}
          ${p('Уроки, игры, дизайн и тексты приложения принадлежат Korean with Madie и предназначены только для личного обучения. Материалы прошедших экзаменов TOPIK публикуются их правообладателем (NIIED, Республика Корея) и используются в образовательных целях. Копировать и распространять материалы приложения в коммерческих целях нельзя.')}
          ${h('7. Без гарантий')}
          ${p('Приложение развивается и предоставляется «как есть»: возможны ошибки, перерывы в работе и изменения функций. Мы стараемся, чтобы всё работало идеально, но не можем это гарантировать. Мы не несём ответственности за результаты экзаменов — но искренне за тебя болеем 🌸')}
          ${h('8. Удаление данных')}
          ${p('Хочешь удалить аккаунт и все данные — напиши нам через «Настройки → Написать нам», удалим в течение 30 дней.')}
          ${h('9. Изменения условий')}
          ${p('Мы можем обновлять эти условия. О существенных изменениях сообщим в приложении. Продолжая пользоваться Madie после изменений, ты принимаешь новую версию.')}
          ${h('10. Связь с нами')}
          ${p('Вопросы, идеи и жалобы: «Профиль → Настройки → Написать нам». Читаем всё.')}
          <div style="text-align:center; padding:18px 0 6px; font-size:11px; color:var(--hush);">Сделано с 🌸 командой Korean with Madie</div>
        </div>
        <button onclick="this.closest('.modal-bg').remove()" class="btn btn-primary btn-block" style="margin-top:12px; flex-shrink:0;">Понятно 🌸</button>
      </div>`;
    document.body.appendChild(m);
  }

  // Per-user storage (namespace by current logged-in user)
  function currentUserId() {
    const u = Store.get('user');
    if (!u) return 'guest';
    if (u.isAdmin) return `admin_${(u.email || u.name).toLowerCase()}`;
    if (u.email) return `user_${u.email.toLowerCase()}`;
    if (u.guest) return 'guest';
    return `user_${u.name.toLowerCase()}`;
  }
  function uKey(name) { return `u_${currentUserId()}_${name}`; }
  const UStore = {
    get(k, d=null) { return Store.get(uKey(k), d); },
    set(k, v) { Store.set(uKey(k), v); },
    del(k) { Store.del(uKey(k)); }
  };

  // Default stats schema (used as baseline for every new user/guest)
  function defaultStats() {
    return {
      xp: 0, streak: 0, lessons: 0, words: 0,
      firstOpenTs: null,
      dates: [], daysEntered: 0, minutesSpent: 0,
      gamePlays: {}, perfectGames: {}, wordsLearned: [],
      hangulSyllables: 0, hangulSaved: 0,
      pronunciationAttempts: 0, pronunciationCorrect: 0, pronunciationStreak: 0, pronunciationBestStreak: 0,
      hasAvatar: false, openedCalendar: false, openedCulture: false,
      // Daily goal — резетится каждый день в полночь по локальному времени
      dailyGoal: 30, dailyXp: 0, dailyDate: '', dailyGoalReachedDates: [],
      // XP earned per calendar day (for the weekly profile chart); pruned to ~30 days
      xpByDay: {}
    };
  }
  // In-memory stats (mutated, kept identical reference across user switches)
  const stats = defaultStats();

  // Load all per-user state from storage (call on init + after login/logout)
  function loadUserData() {
    // Chat ordering + popup state are per-user — reload them for this namespace.
    _chatLastAtLoaded = false; _prevUnreadFrom = null;
    const saved = UStore.get('stats') || {};
    Object.keys(stats).forEach(k => delete stats[k]);
    Object.assign(stats, defaultStats(), saved);
    if (!stats.firstOpenTs) { stats.firstOpenTs = Date.now(); UStore.set('stats', stats); }
    if (!Array.isArray(stats.wordsLearned)) stats.wordsLearned = [];
    if (!stats.gamePlays || typeof stats.gamePlays !== 'object') stats.gamePlays = {};
    if (!stats.perfectGames || typeof stats.perfectGames !== 'object') stats.perfectGames = {};
    if (!Array.isArray(stats.dates)) stats.dates = [];
    _activeModule = UStore.get('activeModule') || 'm1';
    if (!LESSON_MODULES[_activeModule]) _activeModule = 'm1';
    // Если сохранённый модуль ещё не открыт (прогресс сброшен/не пройден) — откатываемся на m1
    if (!isModuleUnlocked(_activeModule) && !isAdmin()) _activeModule = 'm1';
    syncStats();
    syncBestScoreCards();
    syncAchievementsStrip();
    renderModuleSwitcher();
    renderLessonPath();
    renderHeroLesson();
    renderSavedWords();
    renderDailyGoal();
    renderSrsWidget();
    renderContinue();
    applyAvatar(UStore.get('avatar'));
  }

