  const TOPIK_MAT_META = {
    vocab:   { icon:'📖', label:'Лексика',    cls:'vocab' },
    grammar: { icon:'🧩', label:'Грамматика', cls:'grammar' },
    tip:     { icon:'💡', label:'Совет',      cls:'tip' },
    file:    { icon:'📎', label:'Материал',   cls:'file' }
  };
  // Materials are grouped into these sections (in this order) on the hub.
  const TOPIK_MAT_ORDER = ['vocab','grammar','tip','file'];
  const TOPIK_GROUP_LABEL = { vocab:'Лексика', grammar:'Грамматика', tip:'Советы', file:'Файлы' };
  function getTopikMaterials() {
    const admin = Store.get('topikMaterials', []);
    return [...TOPIK_STARTER_MATERIALS, ...(Array.isArray(admin) ? admin : [])];
  }
  function topikReadSet() {
    const r = UStore.get('topikRead', []);
    return new Set(Array.isArray(r) ? r : []);
  }
  function markTopikRead(id) {
    const set = topikReadSet();
    if (set.has(id)) return;
    set.add(id);
    UStore.set('topikRead', [...set]);
  }
  function toggleTopikRule(id) {
    const card = document.getElementById('topik-rule-' + id);
    if (!card) return;
    const open = card.classList.toggle('open');
    if (open) { markTopikRead(id); card.classList.add('read'); }
    updateTopikReadCount();
  }
  function updateTopikReadCount() {
    const el = document.getElementById('topik-read-count');
    if (!el) return;
    const read = topikReadSet();
    el.textContent = `${TOPIK_WRITING_RULES.filter(r => read.has(r.id)).length}/${TOPIK_WRITING_RULES.length}`;
  }
  function topikMatCard(m, admin) {
    const meta = TOPIK_MAT_META[m.kind] || TOPIK_MAT_META.tip;
    const bodyHtml = m.kind === 'file'
      ? (m.url ? `<a href="${escAttrSafe(m.url)}" target="_blank" rel="noopener" class="topik-mat-link"><i class="fa-solid fa-arrow-up-right-from-square"></i> Открыть материал</a>` : '')
      : `<div class="topik-mat-body">${m.builtin ? m.body : escHtml(m.body || '').replace(/\n/g, '<br>')}</div>`;
    const del = (admin && !m.builtin) ? `<button type="button" class="topik-mat-del" onclick="deleteTopikMaterial('${escAttrSafe(m.id)}')" aria-label="Удалить">×</button>` : '';
    return `<div class="topik-mat topik-mat-${meta.cls}">
      <div class="topik-mat-head"><div class="topik-mat-title">${escHtml(m.title || '')}</div>${del}</div>
      ${bodyHtml}
    </div>`;
  }
