  // 쓰기 №83 и №91 — реальные задания с официальных опубликованных тестов (topik.go.kr).
  const TOPIK2_EXAMS = {
    7027: {"mock":true,"readingOnly":true,"no":"마디 모의고사 ②<br><b>읽기</b>","reading":{"durationMin":70,"total":50,"label":"Пробный · 읽기 (50) · оригинал ②","questions":[{"n":1,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"친구를 ( ) 카페에서 한 시간이나 기다렸어요.","options":["만나려고","만나서","만나도","만나거나"],"answer":1,"explain":"Ждал, <b>чтобы</b> встретить друга.<br>✅ <b>① 만나려고</b> = «чтобы встретить» (цель)."},{"n":2,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"날씨가 추워서 두꺼운 옷을 ( ) 나갔어요.","options":["입지만","입고","입거나","입어도"],"answer":2,"explain":"Холодно → надел тёплое и вышел.<br>✅ <b>② 입고</b> = «надев и…»."},{"n":3,"points":2,"instr":"밑줄 친 부분과 의미가 비슷한 것을 고르십시오.","passage":"급하게 먹은 <u>탓에</u> 배탈이 났다.","options":["먹은 덕분에","먹은 바람에","먹은 대신에","먹은 김에"],"answer":2,"explain":"탓에 — негативная причина.<br>✅ <b>② 바람에</b> — тоже «из-за (плохой итог)»."},{"n":4,"points":2,"instr":"밑줄 친 부분과 의미가 비슷한 것을 고르십시오.","passage":"하늘을 보니 곧 비가 올 <u>듯하다</u>.","options":["올 뻔하다","온 적이 있다","올 리가 없다","올 것 같다"],"answer":4,"explain":"듯하다 = «похоже».<br>✅ <b>④ 올 것 같다</b> — синоним."},{"n":5,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"물 없이도 깨끗하게! 향기로운 거품으로 손을 보호하세요.","options":["치약","샴푸","손 소독제","세탁기"],"answer":3,"explain":"«Чистит без воды, пенка для рук» → дезинфектор для рук.<br>✅ <b>③ 손 소독제</b>."},{"n":6,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"버리지 마세요, 다시 쓸 수 있어요. 종이, 캔, 병을 나눠 주세요.","options":["재활용","요리","빨래","운동"],"answer":1,"explain":"«Не выбрасывайте, сортируйте бумагу/банки/бутылки» → переработка.<br>✅ <b>① 재활용</b>."},{"n":7,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"조용한 공간에서 집중! 책과 함께하는 하루.","options":["놀이공원","식당","병원","도서관"],"answer":4,"explain":"«Тихое место, день с книгами» → библиотека.<br>✅ <b>④ 도서관</b>."},{"n":8,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"한 시간에 한 번, 창문을 열어요. 맑은 공기가 건강을 지킵니다.","options":["요리","환기","청소","운동"],"answer":2,"explain":"«Раз в час открывайте окно, свежий воздух» → проветривание.<br>✅ <b>② 환기</b>."},{"n":9,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"한강 벚꽃 축제 / 기간: 4월 5일~4월 9일 / 장소: 한강 공원 / 입장료: 무료 / 야간 개장: 오후 9시까지","options":["축제는 5일 동안 열린다.","입장료를 내야 한다.","밤에는 문을 닫는다.","장소는 시청이다."],"answer":1,"explain":"✅ <b>① 5일 동안</b> (5~9일).<br>✖️ бесплатно, ночью до 21:00, место — парк."},{"n":10,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"<svg viewBox='0 0 300 165' width='100%' style='max-width:300px;display:block;margin:4px auto 10px;background:#FFFFFF;border:1px solid #EADDE0;border-radius:10px' xmlns='http://www.w3.org/2000/svg'><line x1='28' y1='128' x2='288' y2='128' stroke='#C9B6BB'/><rect x='42' y='38' width='36' height='90' rx='3' fill='#EE8893'/><rect x='112' y='51' width='36' height='77' rx='3' fill='#F2A6AE'/><rect x='182' y='77' width='36' height='51' rx='3' fill='#F6C2C7'/><rect x='252' y='89' width='36' height='39' rx='3' fill='#F8D6D9'/><text x='60' y='31' font-size='12' text-anchor='middle' fill='#7A5560'>35%</text><text x='130' y='44' font-size='12' text-anchor='middle' fill='#7A5560'>30%</text><text x='200' y='70' font-size='12' text-anchor='middle' fill='#7A5560'>20%</text><text x='270' y='82' font-size='12' text-anchor='middle' fill='#7A5560'>15%</text><text x='60' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>봄</text><text x='130' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>가을</text><text x='200' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>여름</text><text x='270' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>겨울</text></svg> ‘가장 좋아하는 계절’을 조사한 결과입니다.","options":["여름을 가장 좋아한다.","봄을 가장 좋아한다.","겨울이 가을보다 많다.","가을이 봄보다 많다."],"answer":2,"explain":"График: 봄 35% — больше всех.<br>✅ <b>② 봄을 가장 좋아한다</b>."},{"n":11,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"어제 도서관에서 우산을 잃어버렸다. 다행히 오늘 아침에 직원이 보관함에 있다고 연락을 주었다. 점심시간에 찾으러 갈 생각이다.","options":["우산을 영영 잃어버렸다.","직원이 연락하지 않았다.","나는 우산을 찾으러 갈 것이다.","어제 우산을 찾았다."],"answer":3,"explain":"✅ <b>③ пойду забрать зонт</b> (в обед)."},{"n":12,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"우리 가게는 다음 주부터 영업시간을 한 시간 늘린다. 저녁 늦게 오는 손님이 많기 때문이다. 대신 휴무일은 그대로 유지한다.","options":["가게가 문을 닫는다.","영업시간이 길어진다.","휴무일이 늘어난다.","손님이 줄었다."],"answer":2,"explain":"✅ <b>② часы работы увеличатся</b> на час."},{"n":13,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 그래서 친구에게 사용법을 물어봤다. (나) 새 휴대폰을 샀다. (다) 친구의 설명을 듣고 쉽게 쓸 수 있었다. (라) 처음에는 사용법을 몰라 당황했다.","options":["(나)-(가)-(라)-(다)","(나)-(라)-(가)-(다)","(라)-(나)-(가)-(다)","(나)-(라)-(다)-(가)"],"answer":2,"explain":"✅ <b>② (나)-(라)-(가)-(다)</b>: купил телефон → сначала растерялся → спросил друга → легко разобрался."},{"n":14,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 음식을 직접 만들어 먹기로 했다. (나) 매일 배달 음식을 시켜 먹었다. (다) 건강이 점점 나빠지는 것을 느꼈다. (라) 그러자 몸이 가벼워지고 기분도 좋아졌다.","options":["(나)-(가)-(다)-(라)","(다)-(나)-(가)-(라)","(나)-(다)-(가)-(라)","(나)-(다)-(라)-(가)"],"answer":3,"explain":"✅ <b>③ (나)-(다)-(가)-(라)</b>: ел доставку → почувствовал ухудшение → решил готовить сам → стало легче."},{"n":15,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 표를 미리 예매해 두었다. (나) 주말에 콘서트에 가기로 했다. (다) 덕분에 좋은 자리에서 볼 수 있었다. (라) 콘서트 당일 일찍 도착했다.","options":["(나)-(라)-(가)-(다)","(가)-(나)-(라)-(다)","(나)-(가)-(다)-(라)","(나)-(가)-(라)-(다)"],"answer":4,"explain":"✅ <b>④ (나)-(가)-(라)-(다)</b>: решил пойти → заранее купил билеты → пришёл рано → получил хорошие места."},{"n":16,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"운동을 꾸준히 하면 몸이 건강해진다. 하지만 무리하게 하면 오히려 ( ). 그래서 자신에게 맞는 양을 지키는 것이 중요하다.","options":["더 튼튼해진다","살이 빠진다","다칠 수 있다","기분이 좋아진다"],"answer":3,"explain":"✅ <b>③ 다칠 수 있다</b> — переусердствуешь → можно навредить (далее: важна своя мера)."},{"n":17,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"책을 많이 읽으면 어휘력이 좋아진다. 다양한 표현을 ( ) 글쓰기에도 도움이 된다. 그래서 독서는 좋은 습관이다.","options":["잊어버려서","접하게 되어","피하게 되어","줄여서"],"answer":2,"explain":"✅ <b>② 접하게 되어</b> = знакомишься с выражениями → помогает письму."},{"n":18,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"여행지에서는 그 지역의 음식을 먹어 보는 것이 좋다. 음식에는 그곳의 ( ) 담겨 있기 때문이다. 음식을 통해 문화를 이해할 수 있다.","options":["날씨가","교통이","가격이","문화가"],"answer":4,"explain":"✅ <b>④ 문화가</b> — в еде заключена культура места."},{"n":19,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"요즘 온라인으로 물건을 사는 사람이 많아졌다. 집에서 편하게 주문할 수 있고 가격을 비교하기도 쉽다. ( ) 직접 보지 못하고 사기 때문에 실제 물건이 다를 때도 있다. 그래서 후기를 잘 살펴보는 것이 좋다.","options":["하지만","그래서","또한","예를 들어"],"answer":1,"explain":"✅ <b>① 하지만</b> = «но» — переход к недостатку."},{"n":20,"points":2,"instr":"이 글의 중심 내용으로 알맞은 것을 고르십시오.","passage":"요즘 온라인으로 물건을 사는 사람이 많아졌다. 집에서 편하게 주문할 수 있고 가격을 비교하기도 쉽다. 하지만 직접 보지 못하고 사기 때문에 실제 물건이 다를 때도 있다. 그래서 후기를 잘 살펴보는 것이 좋다.","options":["온라인 쇼핑은 항상 위험하다.","가격 비교는 불가능하다.","온라인 쇼핑은 편리하지만 주의할 점도 있다.","후기는 볼 필요가 없다."],"answer":3,"explain":"✅ <b>③ удобно, но есть на что обратить внимание</b> — главная мысль."},{"n":21,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"이웃집에 불이 났을 때 동생은 ( ) 사람들을 도왔다. 위험한 상황인데도 망설이지 않고 뛰어들었다. 나는 그런 동생이 자랑스러웠다.","options":["발 벗고 나서서","강 건너 불구경하듯","손을 놓고","모르는 척하며"],"answer":1,"explain":"✅ <b>① 발 벗고 나서서</b> = «засучив рукава», активно взялся помогать."},{"n":22,"points":2,"instr":"이 글을 통해 알 수 있는 것을 고르십시오.","passage":"이웃집에 불이 났을 때 동생은 발 벗고 나서서 사람들을 도왔다. 위험한 상황인데도 망설이지 않고 뛰어들었다. 나는 그런 동생이 자랑스러웠다.","options":["동생은 도망쳤다.","동생은 불을 냈다.","나는 동생이 부끄러웠다.","동생은 적극적으로 이웃을 도왔다."],"answer":4,"explain":"✅ <b>④ брат активно помогал соседям</b>."},{"n":23,"points":2,"instr":"이 글의 마지막에 나타난 ‘나’의 심정으로 알맞은 것을 고르십시오.","passage":"면접장을 나오는데 다리가 후들거렸다. 준비한 답을 절반밖에 말하지 못한 것 같았다. 집으로 돌아오는 길 내내 한숨이 나왔다. 그런데 며칠 뒤, 합격했다는 문자를 받고 나는 그 자리에서 펄쩍 뛰었다.","options":["기쁘고 신난다","불안하고 초조하다","화가 나고 억울하다","지루하고 답답하다"],"answer":1,"explain":"✅ <b>① радость и восторг</b> — «펄쩍 뛰었다» (подпрыгнул от радости) после новости о зачислении."},{"n":24,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"면접장을 나오는데 다리가 후들거렸다. 준비한 답을 절반밖에 말하지 못한 것 같았다. 집으로 돌아오는 길 내내 한숨이 나왔다. 그런데 며칠 뒤, 합격했다는 문자를 받고 나는 그 자리에서 펄쩍 뛰었다.","options":["나는 답을 모두 말했다.","나는 면접에 합격했다.","나는 면접을 보지 않았다.","나는 합격 소식에 실망했다."],"answer":2,"explain":"✅ <b>② я прошёл собеседование</b> (пришло уведомление о зачислении)."},{"n":25,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"첫눈 ‘펑펑’… 도심 교통 마비","options":["눈이 안 와 길이 한산했다.","교통이 원활했다.","첫눈이 많이 내려 도심 교통이 막혔다.","도심에 눈이 녹았다."],"answer":3,"explain":"✅ <b>③</b> 펑펑=обильно, 마비=паралич → первый снег парализовал движение."},{"n":26,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"전기차 판매 ‘쑥쑥’… 충전소는 ‘아직’","options":["전기차 판매가 줄었다.","충전소가 넘쳐난다.","전기차가 사라졌다.","전기차는 늘지만 충전소는 부족하다."],"answer":4,"explain":"✅ <b>④</b> 쑥쑥=быстро растёт, 아직=пока нет → машин больше, а зарядок не хватает."},{"n":27,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"독서 인구 ‘뚝’… 도서관은 ‘북적’","options":["독서 인구가 늘었다.","책 읽는 사람은 줄었지만 도서관 이용은 많다.","도서관이 텅 비었다.","책값이 올랐다."],"answer":2,"explain":"✅ <b>②</b> 뚝=резко упало, 북적=многолюдно → читателей меньше, но библиотеки полны."},{"n":28,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"여행은 새로운 경험을 준다. 낯선 곳에서 다른 문화를 만나면 생각의 폭이 넓어진다. 그래서 여행은 ( ) 좋은 기회가 된다.","options":["돈을 모으는","자신을 성장시키는","집에 머무는","시간을 낭비하는"],"answer":2,"explain":"✅ <b>② вырасти над собой</b> — путешествие расширяет кругозор."},{"n":29,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"사람의 첫인상은 몇 초 만에 결정된다고 한다. 그래서 옷차림이나 표정이 ( ). 하지만 시간이 지나면 진짜 모습이 더 중요해진다.","options":["아무 의미가 없다","점점 사라진다","중요한 역할을 한다","문제를 일으킨다"],"answer":3,"explain":"✅ <b>③ играют важную роль</b> — первое впечатление за секунды."},{"n":30,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"도시에 나무가 많으면 여름에도 시원하다. 나무 그늘이 햇볕을 막아 주고, 잎이 ( ) 공기를 맑게 한다. 그래서 도시에 나무를 심는 일이 중요하다.","options":["더위를 만들어","소음을 키워","물을 막아","나쁜 공기를 걸러"],"answer":4,"explain":"✅ <b>④ фильтруют плохой воздух</b> — листья очищают воздух."},{"n":31,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"운동선수는 경기 전에 충분히 몸을 푼다. 갑자기 무리하면 ( ) 때문이다. 준비 운동은 부상을 막는 중요한 과정이다.","options":["다칠 수 있기","빨라질 수 있기","강해질 수 있기","편해질 수 있기"],"answer":1,"explain":"✅ <b>① можно получить травму</b> — разминка защищает от травм."},{"n":32,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"꿀은 오래 두어도 잘 상하지 않는다. 수분이 적고 당분이 많아 세균이 살기 어렵기 때문이다. 그래서 옛날부터 꿀은 약으로도 쓰였다.","options":["꿀은 수분이 많다.","꿀은 금방 상한다.","꿀은 잘 상하지 않는다.","꿀은 약으로 쓸 수 없다."],"answer":3,"explain":"✅ <b>③ мёд почти не портится</b> (мало влаги, много сахара)."},{"n":33,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"최근 도시에서 도시 농업이 인기다. 사람들은 옥상이나 베란다에서 채소를 직접 기른다. 작은 공간에서도 신선한 먹거리를 얻을 수 있어 만족도가 높다.","options":["넓은 땅이 있어야 한다.","사람들이 직접 채소를 기른다.","채소를 사 먹기만 한다.","만족도가 낮다."],"answer":2,"explain":"✅ <b>② люди сами выращивают овощи</b> (на крыше/балконе)."},{"n":34,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"박쥐는 어두운 동굴에 살지만 길을 잘 찾는다. 눈 대신 소리를 이용하기 때문이다. 박쥐가 내는 소리는 물체에 부딪혀 되돌아오고, 그 소리로 거리를 안다.","options":["박쥐는 소리로 길을 찾는다.","박쥐는 눈으로 길을 찾는다.","박쥐는 밝은 곳에 산다.","박쥐는 소리를 내지 않는다."],"answer":1,"explain":"✅ <b>① летучая мышь находит путь по звуку</b> (эхолокация)."},{"n":35,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"실패는 끝이 아니라 배움의 기회이다. 실패를 통해 무엇이 잘못되었는지 알 수 있고, 다음에는 더 잘할 수 있다. 그러니 실패를 너무 두려워하지 말자.","options":["실패하면 끝이다.","실패는 성장의 기회가 될 수 있다.","실패는 피할 수 없다.","실패는 의미가 없다."],"answer":2,"explain":"✅ <b>② неудача может стать шансом для роста</b>."},{"n":36,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"작은 친절이 사람의 하루를 바꾼다. 따뜻한 말 한마디, 작은 도움이 누군가에게는 큰 힘이 된다. 우리도 주변에 작은 친절을 베풀어 보자.","options":["친절은 소용없다.","도움은 받기만 해야 한다.","말은 중요하지 않다.","작은 친절이 큰 힘이 된다."],"answer":4,"explain":"✅ <b>④ маленькая доброта даёт большую силу</b>."},{"n":37,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"계획을 세우면 시간을 효율적으로 쓸 수 있다. 무엇을 먼저 할지 정해 두면 덜 헤매게 된다. 바쁜 사람일수록 계획의 힘이 크다.","options":["계획은 시간을 효율적으로 쓰게 한다.","계획은 필요 없다.","바쁘면 계획을 세우면 안 된다.","계획은 시간을 낭비한다."],"answer":1,"explain":"✅ <b>① план помогает эффективно тратить время</b>."},{"n":38,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"남의 말을 잘 들어 주는 것도 큰 능력이다. 끝까지 들어 주면 상대는 존중받는다고 느낀다. 좋은 관계는 잘 듣는 것에서 시작된다.","options":["말을 많이 해야 한다.","듣기는 중요하지 않다.","잘 듣는 것이 좋은 관계의 시작이다.","남의 말은 무시해도 된다."],"answer":3,"explain":"✅ <b>③ умение слушать — начало хороших отношений</b>."},{"n":39,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 그러나 무엇이든 지나치면 문제가 된다. ── 물은 우리 몸에 꼭 필요하다. ㉠ 하루에 적당한 양을 마시면 건강에 좋다. ㉡ 물을 너무 많이 마시면 오히려 몸에 무리가 갈 수 있다. ㉢ 그러므로 적당히 마시는 것이 중요하다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"✅ <b>② ㉡</b>: «но всё чрезмерное вредит» — перед фразой о вреде избытка воды."},{"n":40,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 그 결과 많은 사람들이 계단을 이용하게 되었다. ── 한 건물에서 재미있는 실험을 했다. ㉠ 계단을 누르면 소리가 나는 피아노 계단을 만든 것이다. ㉡ 사람들은 호기심에 계단을 밟아 보았다. ㉢ 건강에도 좋고 재미도 있는 아이디어였다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b>: «в результате люди стали ходить по лестнице» — после того как из любопытства стали наступать."},{"n":41,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 예를 들어 미소만으로도 친근함을 전할 수 있다. ── 표정은 말보다 더 많은 것을 전한다. ㉠ 우리는 얼굴을 보고 상대의 기분을 짐작한다. ㉡ 그래서 같은 말도 표정에 따라 다르게 들린다. ㉢ 이처럼 표정은 중요한 의사소통 수단이다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: пример (улыбкой передаёшь дружелюбие) идёт сразу после «мимика передаёт больше слов»."},{"n":42,"points":2,"instr":"이 글에 나타난 ‘나’의 심정으로 알맞은 것을 고르십시오.","passage":"할머니께서 보내 주신 택배 상자를 열자 익숙한 냄새가 났다. 직접 말리신 나물과 손으로 꾹꾹 눌러 담은 반찬들이 가득했다. 바쁘다는 핑계로 자주 찾아뵙지 못한 것이 떠올라 마음이 무거워졌다. 나는 상자를 한참 동안 바라보았다.","options":["죄송하고 그립다","즐겁고 신난다","화가 난다","무섭다"],"answer":1,"explain":"✅ <b>① вина и тоска</b> — давно не навещал бабушку, на сердце тяжело."},{"n":43,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"할머니께서 보내 주신 택배 상자를 열자 익숙한 냄새가 났다. 직접 말리신 나물과 손으로 꾹꾹 눌러 담은 반찬들이 가득했다. 바쁘다는 핑계로 자주 찾아뵙지 못한 것이 떠올라 마음이 무거워졌다. 나는 상자를 한참 동안 바라보았다.","options":["나는 할머니를 자주 찾아뵈었다.","상자는 비어 있었다.","할머니가 직접 만든 음식을 보냈다.","나는 음식을 버렸다."],"answer":3,"explain":"✅ <b>③ бабушка прислала еду своего приготовления</b>."},{"n":44,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"도서관은 단순히 책을 빌리는 곳이 아니다. 요즘 도서관에서는 영화 상영, 강연, 전시 같은 다양한 행사가 열린다. 또한 누구나 무료로 참여할 수 있어 ( ) 공간이 되고 있다. 책을 읽지 않더라도 도서관은 충분히 즐길 만한 곳이다.","options":["지역 주민이 함께 즐기는","책만 빌리는","돈을 내야 하는","조용히 있어야만 하는"],"answer":1,"explain":"✅ <b>① где вместе отдыхают местные жители</b> — бесплатно, для всех."},{"n":45,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"도서관은 단순히 책을 빌리는 곳이 아니다. 요즘 도서관에서는 영화 상영, 강연, 전시 같은 다양한 행사가 열린다. 또한 누구나 무료로 참여할 수 있어 지역 주민이 함께 즐기는 공간이 되고 있다. 책을 읽지 않더라도 도서관은 충분히 즐길 만한 곳이다.","options":["도서관은 책만 빌리는 곳이다.","도서관은 다양한 활동을 즐길 수 있는 공간이다.","도서관은 이용료가 비싸다.","도서관은 사라지고 있다."],"answer":2,"explain":"✅ <b>② библиотека — место для разных активностей</b>."},{"n":46,"points":2,"instr":"필자의 태도로 가장 알맞은 것을 고르십시오.","passage":"재택근무가 늘면서 일하는 방식이 빠르게 바뀌고 있다. 출퇴근 시간을 아낄 수 있다는 점은 분명한 장점이다. 그러나 동료와의 소통이 줄고 일과 휴식의 경계가 흐려지는 문제도 있다. 따라서 새로운 방식의 장점은 살리되 단점을 보완하려는 노력이 필요하다.","options":["변화의 장점을 인정하되 단점 보완을 강조한다.","재택근무를 무조건 반대한다.","변화에 관심이 없다.","단점은 무시해도 된다고 본다."],"answer":1,"explain":"✅ <b>① признаёт плюсы перемен, но подчёркивает компенсацию минусов</b>."},{"n":47,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"재택근무가 늘면서 일하는 방식이 빠르게 바뀌고 있다. 출퇴근 시간을 아낄 수 있다는 점은 분명한 장점이다. 그러나 동료와의 소통이 줄고 일과 휴식의 경계가 흐려지는 문제도 있다. 따라서 새로운 방식의 장점은 살리되 단점을 보완하려는 노력이 필요하다.","options":["재택근무는 단점이 없다.","재택근무에는 장점과 단점이 모두 있다.","출퇴근 시간이 늘었다.","소통이 더 활발해졌다."],"answer":2,"explain":"✅ <b>② у удалёнки есть и плюсы, и минусы</b>."},{"n":48,"points":2,"instr":"필자가 이 글을 쓴 목적으로 알맞은 것을 고르십시오.","passage":"최근 음식물 쓰레기를 줄이자는 움직임이 활발하다. 한 식당은 손님이 먹을 만큼만 담아 가는 방식을 도입했다. 처음에는 번거롭다는 반응도 있었지만, 남는 음식이 크게 줄자 ( ) 손님이 늘었다. 작은 실천이 쓰레기와 비용을 동시에 줄인 것이다. 이런 방식이 더 많은 곳으로 퍼지길 바란다.","options":["음식물 쓰레기를 줄이는 사례를 알리려고","식당을 광고하려고","손님의 불만을 전하려고","새 메뉴를 소개하려고"],"answer":1,"explain":"✅ <b>① рассказать о примере сокращения пищевых отходов</b>."},{"n":49,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"최근 음식물 쓰레기를 줄이자는 움직임이 활발하다. 한 식당은 손님이 먹을 만큼만 담아 가는 방식을 도입했다. 처음에는 번거롭다는 반응도 있었지만, 남는 음식이 크게 줄자 ( ) 손님이 늘었다. 작은 실천이 쓰레기와 비용을 동시에 줄인 것이다.","options":["끝까지 반대하는","방식에 공감하는","식당을 떠나는","음식을 더 남기는"],"answer":2,"explain":"✅ <b>② поддерживающих подход</b> — отходы упали, число согласных выросло."},{"n":50,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"최근 음식물 쓰레기를 줄이자는 움직임이 활발하다. 한 식당은 손님이 먹을 만큼만 담아 가는 방식을 도입했다. 처음에는 번거롭다는 반응도 있었지만, 남는 음식이 크게 줄자 방식에 공감하는 손님이 늘었다. 작은 실천이 쓰레기와 비용을 동시에 줄인 것이다.","options":["음식물 쓰레기가 늘었다.","손님이 모두 반대했다.","비용이 더 늘었다.","먹을 만큼만 담는 방식에 공감하는 손님이 늘었다."],"answer":4,"explain":"✅ <b>④ выросло число согласных с подходом «бери сколько съешь»</b>."}]}},
    7026: {"mock":true,"readingOnly":true,"no":"마디 모의고사 ①<br><b>읽기</b>","reading":{"durationMin":70,"total":50,"label":"Пробный · 읽기 (50) · оригинал","questions":[{"n":1,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"아침에 일찍 ( ) 지하철에서 자리에 앉을 수 있었다.","options":["나오려고","나와서","나오거나","나오지만"],"answer":2,"explain":"Встал рано → поэтому смог сесть.<br>✅ <b>② 나와서</b> = «вышел и (поэтому)» — причина.<br>✖️ ① «чтобы выйти», ③ «или», ④ «но» — не по смыслу."},{"n":2,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"하늘을 보니 비가 올 것 ( ) 우산을 가지고 나왔어요.","options":["같지만","같거나","같아서","같아도"],"answer":3,"explain":"Похоже, будет дождь → поэтому взял зонт.<br>✅ <b>③ 같아서</b> = «похоже, что…, поэтому».<br>✖️ остальные связки не дают причины."},{"n":3,"points":2,"instr":"밑줄 친 부분과 의미가 비슷한 것을 고르십시오.","passage":"시험이 <u>어려운 탓에</u> 점수가 낮았다.","options":["어려운 덕분에","어려운 대신에","어려운 김에","어려운 바람에"],"answer":4,"explain":"탓에 — негативная причина «по вине / из-за».<br>✅ <b>④ 바람에</b> — тоже «из-за (плохой итог)».<br>✖️ 덕분에 «благодаря» (положит.), 대신에 «вместо», 김에 «заодно»."},{"n":4,"points":2,"instr":"밑줄 친 부분과 의미가 비슷한 것을 고르십시오.","passage":"그 사람은 모르면서 아는 <u>척했다</u>.","options":["아는 편이다","아는 체했다","아는 셈이다","아는 모양이다"],"answer":2,"explain":"척하다 = делать вид.<br>✅ <b>② 체했다</b> — синоним 척하다.<br>✖️ 편이다 «скорее», 셈이다 «считай что», 모양이다 «похоже»."},{"n":5,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"흐르는 물에 30초! 깨끗이 씻으면 감기를 예방할 수 있습니다.","options":["감기약","손 씻기","수도 요금","운동"],"answer":2,"explain":"«30 секунд под водой, мытьё предотвращает простуду» → о мытье рук.<br>✅ <b>② 손 씻기</b>."},{"n":6,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"한 잔의 여유, 따뜻한 향기. 아침을 깨우는 진한 맛.","options":["커피","치약","비누","우유"],"answer":1,"explain":"«Чашка, тёплый аромат, насыщенный вкус, будит утро» → кофе.<br>✅ <b>① 커피</b>."},{"n":7,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"신어도 발이 편안하게. 가벼운 무게, 미끄럼 방지 바닥.","options":["모자","가방","신발","시계"],"answer":3,"explain":"«Ноге удобно, лёгкие, нескользящая подошва» → обувь.<br>✅ <b>③ 신발</b>."},{"n":8,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"끄고 나가요! 작은 습관이 지구를 지킵니다.","options":["교통 안전","건강 관리","독서","전기 절약"],"answer":4,"explain":"«Выключайте свет — привычка бережёт планету» → экономия электричества.<br>✅ <b>④ 전기 절약</b>."},{"n":9,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"한국어 말하기 대회 / 일시: 5월 10일 토요일 오후 2시 / 장소: 시민회관 / 참가비: 무료 / 신청: 4월 30일까지 인터넷으로","options":["참가비를 내야 한다.","대회는 토요일에 열린다.","전화로 신청한다.","대회는 오전에 시작한다."],"answer":2,"explain":"✅ <b>② 토요일에 열린다</b> — 5월 10일 토요일.<br>✖️ участие бесплатное, заявка по интернету, начало в 14:00 (день)."},{"n":10,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"<svg viewBox='0 0 300 165' width='100%' style='max-width:300px;display:block;margin:4px auto 10px;background:#FFFFFF;border:1px solid #EADDE0;border-radius:10px' xmlns='http://www.w3.org/2000/svg'><line x1='28' y1='128' x2='288' y2='128' stroke='#C9B6BB'/><rect x='42' y='38' width='36' height='90' rx='3' fill='#EE8893'/><rect x='112' y='60' width='36' height='68' rx='3' fill='#F2A6AE'/><rect x='182' y='83' width='36' height='45' rx='3' fill='#F6C2C7'/><rect x='252' y='106' width='36' height='22' rx='3' fill='#F8D6D9'/><text x='60' y='31' font-size='12' text-anchor='middle' fill='#7A5560'>40%</text><text x='130' y='53' font-size='12' text-anchor='middle' fill='#7A5560'>30%</text><text x='200' y='76' font-size='12' text-anchor='middle' fill='#7A5560'>20%</text><text x='270' y='99' font-size='12' text-anchor='middle' fill='#7A5560'>10%</text><text x='60' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>저녁</text><text x='130' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>점심</text><text x='200' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>아침</text><text x='270' y='146' font-size='12' text-anchor='middle' fill='#5A4046'>밤</text></svg> ‘하루 중 휴대폰을 가장 많이 쓰는 시간’을 조사한 결과입니다.","options":["아침이 가장 많다.","점심이 저녁보다 많다.","저녁에 가장 많이 쓴다.","밤이 점심보다 많다."],"answer":3,"explain":"✅ <b>③ 저녁(40%)이 가장 많다</b>.<br>✖️ остальные противоречат цифрам."},{"n":11,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"지난주에 우리 동네에 작은 도서관이 문을 열었다. 책뿐만 아니라 영화도 빌릴 수 있다. 회원증을 만들면 누구나 무료로 이용할 수 있다.","options":["책은 돈을 내고 빌린다.","도서관은 오래전에 생겼다.","회원증이 없어도 빌린다.","도서관에서 영화도 빌릴 수 있다."],"answer":4,"explain":"✅ <b>④ 영화도 빌릴 수 있다</b>.<br>✖️ открылась на прошлой неделе, бесплатно по членскому билету."},{"n":12,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"우리 회사는 다음 달부터 일주일에 하루는 집에서 일하기로 했다. 직원들은 출퇴근 시간을 아낄 수 있어 좋아한다. 다만 회의는 사무실에서 한다.","options":["회의는 사무실에서 한다.","매일 집에서 일한다.","직원들은 이 제도를 싫어한다.","출퇴근 시간이 늘었다."],"answer":1,"explain":"✅ <b>① 회의는 사무실에서</b>.<br>✖️ из дома один день в неделю, сотрудники довольны, время в пути экономится."},{"n":13,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 그래서 매일 아침 30분씩 걷기로 했다. (나) 나는 요즘 운동이 부족하다고 느꼈다. (다) 한 달이 지나자 몸이 훨씬 가벼워졌다. (라) 처음에는 힘들었지만 점점 익숙해졌다.","options":["(가)-(나)-(다)-(라)","(나)-(가)-(라)-(다)","(가)-(라)-(나)-(다)","(나)-(다)-(가)-(라)"],"answer":2,"explain":"✅ <b>② (나)-(가)-(라)-(다)</b>: почувствовал нехватку движения → решил ходить → сначала тяжело → через месяц стало легче."},{"n":14,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 하지만 표가 모두 팔려서 볼 수 없었다. (나) 지난 주말에 영화를 보러 갔다. (다) 그래서 근처 식당에서 저녁만 먹고 돌아왔다. (라) 친구와 함께 영화관에 도착했다.","options":["(나)-(가)-(라)-(다)","(라)-(나)-(가)-(다)","(나)-(라)-(가)-(다)","(나)-(라)-(다)-(가)"],"answer":3,"explain":"✅ <b>③ (나)-(라)-(가)-(다)</b>: пошёл в кино → пришли в кинотеатр → но билеты раскуплены → поэтому только поужинали."},{"n":15,"points":2,"instr":"다음을 순서대로 맞게 배열한 것을 고르십시오.","passage":"(가) 면접 날 아침에 일찍 일어났다. (나) 며칠 동안 예상 질문을 준비했다. (다) 준비한 덕분에 자신 있게 대답할 수 있었다. (라) 지난달에 회사 면접을 봤다.","options":["(라)-(가)-(나)-(다)","(나)-(라)-(가)-(다)","(라)-(나)-(다)-(가)","(라)-(나)-(가)-(다)"],"answer":4,"explain":"✅ <b>④ (라)-(나)-(가)-(다)</b>: было собеседование → готовил вопросы → встал рано в день → ответил уверенно."},{"n":16,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"사람은 누구나 실수를 한다. 중요한 것은 그 후의 태도이다. 실수를 ( ) 다음에는 같은 잘못을 하지 않게 된다.","options":["숨기면","반복하면","무시하면","반성하면"],"answer":4,"explain":"✅ <b>④ 반성하면</b> = если осмыслить → не повторишь ошибку.<br>✖️ скрыть/повторять/игнорировать — не дают такого результата."},{"n":17,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"식물도 빛이 필요하다. 빛이 부족하면 잎이 노랗게 변한다. 그래서 화분은 ( ) 곳에 두는 것이 좋다.","options":["바람이 없는","햇빛이 잘 드는","어두운","물이 많은"],"answer":2,"explain":"✅ <b>② 햇빛이 잘 드는</b> = где много солнца (растению нужен свет)."},{"n":18,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"여행 갈 때 짐이 많으면 불편하다. 꼭 필요한 것만 챙기면 ( ) 다닐 수 있다. 그래서 짐을 쌀 때는 신중하게 골라야 한다.","options":["가볍게","무겁게","천천히","위험하게"],"answer":1,"explain":"✅ <b>① 가볍게</b> = брать только нужное → ходить налегке."},{"n":19,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"요즘 자전거로 출퇴근하는 사람이 늘고 있다. 자전거는 교통비가 들지 않고 건강에도 좋다. ( ) 길이 막혀도 늦을 걱정이 적다. 이런 이유로 자전거 출퇴근은 인기를 얻고 있다.","options":["그러나","예를 들면","또한","그런데"],"answer":3,"explain":"✅ <b>③ 또한</b> = «к тому же» — добавляет ещё одно достоинство.<br>✖️ «однако/например/кстати» не подходят."},{"n":20,"points":2,"instr":"이 글의 중심 내용으로 알맞은 것을 고르십시오.","passage":"요즘 자전거로 출퇴근하는 사람이 늘고 있다. 자전거는 교통비가 들지 않고 건강에도 좋다. 또한 길이 막혀도 늦을 걱정이 적다. 이런 이유로 자전거 출퇴근은 인기를 얻고 있다.","options":["자전거 출퇴근이 인기를 얻고 있다.","자전거는 위험하다.","교통비가 비싸지고 있다.","도시에 자동차가 많아졌다."],"answer":1,"explain":"✅ <b>① велопоездки на работу набирают популярность</b> — главная мысль."},{"n":21,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"동생은 시험에 떨어지고도 ( ) 태연한 표정이었다. 속으로는 많이 속상했을 텐데 가족 앞에서는 웃어 보였다. 나는 그런 동생이 오히려 더 안쓰러웠다.","options":["발 벗고 나서서","아무렇지도 않은 듯","손을 놓고","입을 모아"],"answer":2,"explain":"✅ <b>② 아무렇지도 않은 듯</b> = «как ни в чём не бывало» — спокойное лицо, хотя внутри переживает."},{"n":22,"points":2,"instr":"이 글을 통해 알 수 있는 것을 고르십시오.","passage":"동생은 시험에 떨어지고도 아무렇지도 않은 듯 태연한 표정이었다. 속으로는 많이 속상했을 텐데 가족 앞에서는 웃어 보였다. 나는 그런 동생이 오히려 더 안쓰러웠다.","options":["동생은 속상한 마음을 감추었다.","동생은 시험에 합격했다.","동생은 가족에게 화를 냈다.","나는 동생이 부러웠다."],"answer":1,"explain":"✅ <b>① 동생은 속상함을 감췄다</b> — улыбался, хотя расстроен."},{"n":23,"points":2,"instr":"이 글에 나타난 ‘나’의 심정으로 알맞은 것을 고르십시오.","passage":"버스에 올라타려는 순간 지갑이 없는 것을 알았다. 얼굴이 빨개졌고 뒤에 선 사람들의 시선이 느껴졌다. 그때 한 학생이 조용히 카드를 대 주며 ‘괜찮아요’라고 말했다. 나는 고맙다는 말도 제대로 하지 못한 채 자리에 앉았다.","options":["즐겁고 신난다","화가 나고 억울하다","지루하고 답답하다","고맙고 미안하다"],"answer":4,"explain":"✅ <b>④ благодарность и неловкость</b> — студент выручил, а «я» не смог толком поблагодарить."},{"n":24,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"버스에 올라타려는 순간 지갑이 없는 것을 알았다. 얼굴이 빨개졌고 뒤에 선 사람들의 시선이 느껴졌다. 그때 한 학생이 조용히 카드를 대 주며 ‘괜찮아요’라고 말했다. 나는 고맙다는 말도 제대로 하지 못한 채 자리에 앉았다.","options":["학생이 버스 요금을 대신 내 주었다.","나는 지갑을 버스에 두고 내렸다.","나는 학생에게 길게 인사했다.","버스에는 사람이 아무도 없었다."],"answer":1,"explain":"✅ <b>① студент оплатил проезд за меня</b> (приложил карту)."},{"n":25,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"주말 나들이객 ‘북적’… 고속도로 몸살","options":["주말에 고속도로가 한가했다.","나들이객이 줄어 도로가 비었다.","주말에 나들이객이 많아 도로가 매우 붐볐다.","고속도로가 공사로 막혔다."],"answer":3,"explain":"✅ <b>③</b> 북적=толпа, 몸살=мучается → дороги забиты из-за множества отдыхающих."},{"n":26,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"채솟값 껑충… 식탁 부담 ↑","options":["채소 가격이 올라 가계 부담이 커졌다.","채소가 싸져서 가정이 좋아했다.","채소 생산이 멈췄다.","식탁이 부족하다."],"answer":1,"explain":"✅ <b>①</b> 껑충=резкий скачок, 부담↑ → цены на овощи выросли, нагрузка на семью."},{"n":27,"points":2,"instr":"다음 신문 기사 제목을 가장 잘 설명한 것을 고르십시오.","passage":"폭염 속 전력 사용 ‘사상 최고’","options":["날씨가 시원해 전기를 적게 썼다.","더위로 전기 사용량이 역대 가장 많았다.","전기 요금이 내렸다.","전력 공급이 끊겼다."],"answer":2,"explain":"✅ <b>②</b> 폭염=жара, 사상 최고=рекорд → потребление электричества рекордное из-за жары."},{"n":28,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"웃음은 몸과 마음에 좋다. 크게 웃으면 스트레스가 줄고 기분이 좋아진다. 또한 웃을 때 쓰는 근육은 운동 효과까지 있어 ( ) 도움이 된다.","options":["건강에도","수면 부족에도","스트레스 증가에도","체중 증가에도"],"answer":1,"explain":"✅ <b>① 건강에도</b> — смех снижает стресс и работает как упражнение → полезен здоровью."},{"n":29,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"도시의 밤이 점점 밝아지고 있다. 밝은 불빛은 편리하지만 너무 강하면 ( ). 실제로 밤에 빛이 너무 많으면 잠을 제대로 자기 어렵다는 연구도 있다.","options":["에너지를 절약해 준다","별을 더 잘 보이게 한다","낮처럼 따뜻해진다","오히려 건강을 해칠 수 있다"],"answer":4,"explain":"✅ <b>④ может навредить здоровью</b> — далее: слишком много света мешает спать."},{"n":30,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"새 언어를 배울 때는 완벽하게 말하려고 애쓰기보다 ( ) 더 중요하다. 틀려도 자꾸 말하다 보면 실력이 는다. 실수를 두려워하면 입이 열리지 않는다.","options":["자주 사용해 보는 것이","문법을 외우는 것이","발음을 숨기는 것이","말을 줄이는 것이"],"answer":1,"explain":"✅ <b>① чаще пробовать использовать</b> — далее: говори, даже с ошибками."},{"n":31,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"동물도 서로 신호를 주고받는다. 예를 들어 꿀벌은 춤을 추어 꽃이 있는 ( ) 동료에게 알린다. 이렇게 동물들은 저마다의 방법으로 의사소통을 한다.","options":["색깔을","위치를","이름을","무게를"],"answer":2,"explain":"✅ <b>② 위치를</b> — пчела танцем сообщает место цветов."},{"n":32,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"한글은 1443년에 만들어진 문자이다. 백성이 쉽게 글을 배울 수 있도록 만들어졌다. 글자 모양은 발음 기관의 모양을 본떠 만들어 매우 과학적이다.","options":["한글은 백성을 위해 만들어졌다.","한글은 외국에서 들여왔다.","한글은 배우기 매우 어렵다.","한글 모양에는 원리가 없다."],"answer":1,"explain":"✅ <b>① создан для народа</b>.<br>✖️ создан в Корее, лёгок, в основе — научный принцип."},{"n":33,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"최근 ‘제로 웨이스트’ 가게가 늘고 있다. 이곳에서는 포장 없이 필요한 만큼만 살 수 있다. 손님은 직접 용기를 가져와 담아 간다. 쓰레기를 줄이려는 사람들에게 인기가 많다.","options":["물건이 모두 포장되어 있다.","원하는 양보다 많이 사야 한다.","손님이 용기를 직접 가져온다.","쓰레기가 늘어난다."],"answer":3,"explain":"✅ <b>③ покупатель приносит свою тару</b>.<br>✖️ без упаковки, сколько нужно, мусор сокращается."},{"n":34,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"고래는 물속에 살지만 물고기가 아니라 포유류이다. 그래서 새끼를 낳아 젖을 먹여 키운다. 또한 숨을 쉬기 위해 가끔 물 위로 올라온다.","options":["고래는 새끼에게 젖을 먹인다.","고래는 물고기이다.","고래는 숨을 쉬지 않는다.","고래는 알을 낳는다."],"answer":1,"explain":"✅ <b>① кит кормит детёныша молоком</b> (млекопитающее)."},{"n":35,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"물건을 오래 쓰는 것은 환경을 지키는 가장 쉬운 방법이다. 새것을 사기 전에 지금 것을 고쳐 쓸 수 있는지 생각해 보자. 작은 실천이 모이면 큰 변화를 만든다.","options":["새 물건은 빨리 사는 것이 좋다.","물건을 오래 쓰면 환경을 지킬 수 있다.","고치는 것은 시간 낭비이다.","환경 문제는 해결할 수 없다."],"answer":2,"explain":"✅ <b>② долго пользоваться вещами = беречь среду</b> — главная мысль."},{"n":36,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"칭찬은 사람을 변화시키는 힘이 있다. 작은 일이라도 진심으로 칭찬하면 상대는 더 잘하고 싶어진다. 비난보다 칭찬이 사람을 움직인다.","options":["진심 어린 칭찬은 사람을 성장시킨다.","칭찬은 효과가 없다.","비난이 칭찬보다 낫다.","칭찬은 자주 하면 안 된다."],"answer":1,"explain":"✅ <b>① искренняя похвала растит человека</b>."},{"n":37,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"충분한 잠은 건강의 기본이다. 잠이 부족하면 집중력이 떨어지고 쉽게 피곤해진다. 바쁘더라도 잠자는 시간을 먼저 지키는 것이 좋다.","options":["잠은 적게 잘수록 좋다.","바쁘면 잠을 줄여야 한다.","집중력은 잠과 관계없다.","건강을 위해 충분한 잠이 중요하다."],"answer":4,"explain":"✅ <b>④ для здоровья важен достаточный сон</b>."},{"n":38,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"혼자 하는 일에도 한계가 있다. 서로 다른 생각을 가진 사람들이 힘을 모으면 더 좋은 결과가 나온다. 협력은 부족한 부분을 채워 준다.","options":["함께 협력하면 더 좋은 결과를 얻는다.","일은 혼자 하는 것이 가장 좋다.","다른 생각은 방해가 된다.","협력은 결과를 나쁘게 만든다."],"answer":1,"explain":"✅ <b>① сотрудничество даёт лучший результат</b>."},{"n":39,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 하지만 시간이 지나자 점점 익숙해졌다. ── 처음 외국에 도착했을 때 모든 것이 낯설었다. ㉠ 음식도 입에 맞지 않고 말도 통하지 않았다. ㉡ 이제는 그곳 생활이 고향처럼 편안하다. ㉢ 낯선 환경도 시간이 약이 되는 것 같다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"✅ <b>② ㉡</b>: «но со временем привык» стоит между трудностями (㉠) и «теперь комфортно» (㉡)."},{"n":40,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 그 결과 도시의 공기가 한결 맑아졌다. ── 시는 작년부터 도심에 나무를 많이 심었다. ㉠ 또한 오래된 공장의 매연도 줄이도록 했다. ㉡ 시민들은 예전보다 숨쉬기가 편해졌다고 말한다. ㉢ 앞으로도 이런 노력이 계속되기를 바란다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"✅ <b>② ㉡</b>: «в результате воздух стал чище» — после мер (деревья, меньше дыма), перед реакцией жителей."},{"n":41,"points":2,"instr":"다음 문장이 들어갈 위치로 가장 알맞은 것을 고르십시오.","passage":"[보기] 예를 들어 색깔만 봐도 그 과일이 익었는지 알 수 있다. ── 우리는 눈으로 많은 정보를 얻는다. ㉠ 시각은 다른 감각보다 빠르게 판단을 돕는다. ㉡ 그래서 물건을 고를 때도 먼저 눈으로 살핀다. ㉢ 이처럼 눈은 일상에서 중요한 역할을 한다. ㉣","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b>: пример (по цвету видно зрелость) идёт после «выбираем глазами» (㉢)."},{"n":42,"points":2,"instr":"이 글에 나타난 ‘나’의 심정으로 알맞은 것을 고르십시오.","passage":"교실 문을 열자 친구들이 모두 나를 보며 박수를 쳤다. 칠판에는 ‘생일 축하해’라고 적혀 있었다. 잊고 있던 내 생일을 친구들이 기억하고 있었던 것이다. 코끝이 찡해지면서 나도 모르게 눈물이 났다.","options":["감동스럽다","실망스럽다","지루하다","무섭다"],"answer":1,"explain":"✅ <b>① растроган(а)/тронут(а)</b> — друзья помнили о дне рождения, навернулись слёзы."},{"n":43,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"교실 문을 열자 친구들이 모두 나를 보며 박수를 쳤다. 칠판에는 ‘생일 축하해’라고 적혀 있었다. 잊고 있던 내 생일을 친구들이 기억하고 있었던 것이다. 코끝이 찡해지면서 나도 모르게 눈물이 났다.","options":["나는 친구들의 생일을 잊었다.","친구들이 나의 생일을 준비해 주었다.","교실에는 아무도 없었다.","나는 박수를 치며 들어갔다."],"answer":2,"explain":"✅ <b>② друзья устроили мне день рождения</b>."},{"n":44,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"걷기는 가장 쉬운 운동이다. 특별한 장비나 돈이 필요 없고 언제 어디서나 할 수 있다. 게다가 무리가 적어 ( ) 부담 없이 시작할 수 있다. 하루 30분만 꾸준히 걸어도 건강에 큰 도움이 된다.","options":["운동선수만","어린아이만","운동을 처음 하는 사람도","건강한 사람만"],"answer":3,"explain":"✅ <b>③ даже новичок в спорте</b> — нагрузка мала, начать может каждый."},{"n":45,"points":2,"instr":"이 글의 주제로 알맞은 것을 고르십시오.","passage":"걷기는 가장 쉬운 운동이다. 특별한 장비나 돈이 필요 없고 언제 어디서나 할 수 있다. 게다가 무리가 적어 운동을 처음 하는 사람도 부담 없이 시작할 수 있다. 하루 30분만 꾸준히 걸어도 건강에 큰 도움이 된다.","options":["걷기는 돈이 많이 든다.","운동은 장비가 있어야 한다.","걷기는 누구나 쉽게 할 수 있는 좋은 운동이다.","걷기는 효과가 없다."],"answer":3,"explain":"✅ <b>③ ходьба — доступное всем хорошее упражнение</b>."},{"n":46,"points":2,"instr":"필자의 태도로 가장 알맞은 것을 고르십시오.","passage":"인공지능 기술이 빠르게 발전하면서 편리함이 커지고 있다. 그러나 우리는 그 이면도 함께 살펴야 한다. 일자리 변화나 개인 정보 보호 같은 문제에 미리 대비하지 않으면 큰 혼란이 올 수 있다. 기술 발전은 환영할 일이지만 그만큼 신중한 준비가 필요하다.","options":["기술 발전을 반기면서도 신중한 대비를 강조한다.","기술 발전을 무조건 반대한다.","기술에 전혀 관심이 없다.","문제를 무시해도 된다고 본다."],"answer":1,"explain":"✅ <b>① приветствует развитие, но требует осторожной подготовки</b>."},{"n":47,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"인공지능 기술이 빠르게 발전하면서 편리함이 커지고 있다. 그러나 우리는 그 이면도 함께 살펴야 한다. 일자리 변화나 개인 정보 보호 같은 문제에 미리 대비하지 않으면 큰 혼란이 올 수 있다. 기술 발전은 환영할 일이지만 그만큼 신중한 준비가 필요하다.","options":["인공지능은 문제를 일으키지 않는다.","기술 발전에는 대비가 필요하다.","일자리는 전혀 변하지 않는다.","필자는 기술을 반대한다."],"answer":2,"explain":"✅ <b>② развитие требует подготовки</b> (рабочие места, защита данных)."},{"n":48,"points":2,"instr":"필자가 이 글을 쓴 목적으로 알맞은 것을 고르십시오.","passage":"최근 일회용품을 줄이자는 목소리가 높다. 이에 많은 카페가 매장 안에서는 다회용 컵을 쓰기 시작했다. 처음에는 불편하다는 의견도 있었지만 시간이 지나며 ( ) 사람들이 늘었다. 작은 불편이 환경을 지키는 큰 걸음이 된다는 것을 알게 된 것이다.","options":["일회용품을 줄이려는 변화를 알리고 권하기 위해","카페를 광고하기 위해","다회용 컵의 단점을 알리기 위해","불편함을 불평하기 위해"],"answer":1,"explain":"✅ <b>① рассказать о переменах и призвать сокращать одноразовое</b>."},{"n":49,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"최근 일회용품을 줄이자는 목소리가 높다. 이에 많은 카페가 매장 안에서는 다회용 컵을 쓰기 시작했다. 처음에는 불편하다는 의견도 있었지만 시간이 지나며 ( ) 사람들이 늘었다. 작은 불편이 환경을 지키는 큰 걸음이 된다는 것을 알게 된 것이다.","options":["끝까지 반대하는","기꺼이 동참하는","전혀 모르는","불편해서 떠나는"],"answer":2,"explain":"✅ <b>② охотно присоединяющихся</b> — со временем поняли пользу, число выросло."},{"n":50,"points":2,"instr":"이 글의 내용과 같은 것을 고르십시오.","passage":"최근 일회용품을 줄이자는 목소리가 높다. 이에 많은 카페가 매장 안에서는 다회용 컵을 쓰기 시작했다. 처음에는 불편하다는 의견도 있었지만 시간이 지나며 기꺼이 동참하는 사람들이 늘었다. 작은 불편이 환경을 지키는 큰 걸음이 된다는 것을 알게 된 것이다.","options":["모든 사람이 끝까지 반대했다.","카페는 일회용품만 쓴다.","환경에는 도움이 되지 않는다.","다회용 컵 사용에 동참하는 사람이 늘었다."],"answer":4,"explain":"✅ <b>④ число участвующих в многоразовых стаканах выросло</b>."}]}},
    7025: {"mock":true,"readingOnly":true,"no":"국가 경시대회<br><b>읽기</b>","reading":{"durationMin":60,"total":40,"label":"Олимпиада · 읽기 (40)","questions":[{"n":1,"points":1,"instr":"Выберите наиболее подходящее для пропуска ( ).","passage":"어머니 생신인데 외국에 있어서 찾아뵐 수 없어요. 전화( ) 드려야겠어요.","options":["조차","라도","만큼","까지"],"answer":2,"explain":"Не могу приехать на день рождения мамы → «хотя бы позвонить».<br>✅ <b>② 라도</b> = «хотя бы, на худой конец» (выбор меньшего из возможного).<br>✖️ ① 조차 «даже не», ③ 만큼 «настолько», ④ 까지 «вплоть до» — не подходят по смыслу."},{"n":2,"points":1,"instr":"Выберите наиболее подходящее для пропуска ( ).","passage":"내일 중요한 시험이 있는데 늦게 ( ) 형한테 깨워 달라고 했어요.","options":["일어나게","일어날 텐데","일어날까 봐","일어나더라도"],"answer":3,"explain":"Попросил брата разбудить → «боясь, что просплю».<br>✅ <b>③ 일어날까 봐</b> = «боясь, что (поздно встану)».<br>✖️ ① 일어나게 «чтобы встал», ② 일어날 텐데 «вероятно встану, но», ④ 일어나더라도 «даже если встану» — не дают причину просьбы."},{"n":3,"points":1,"instr":"Выберите наиболее подходящее для пропуска ( ).","passage":"날씨가 흐린 걸 보니까 비가 ( ).","options":["오더라고요","오거든요","오면 안 돼요","올 모양이에요"],"answer":4,"explain":"«Судя по тому, что пасмурно (흐린 걸 보니까)» → предположение по признаку.<br>✅ <b>④ 올 모양이에요</b> = «похоже, пойдёт (дождь)».<br>✖️ ① 오더라고요 «(я видел) шёл», ② 오거든요 «ведь идёт», ③ 오면 안 돼요 «нельзя, чтобы шёл» — не выражают догадку."},{"n":4,"points":1,"instr":"Выберите наиболее подходящее для пропуска ( ).","passage":"가을이 되니까 우리 집 감나무에 감이 ( ) 달렸다.","options":["주렁주렁","사각사각","보글보글","퐁당퐁당"],"answer":1,"explain":"Хурма «висит гроздьями» на дереве.<br>✅ <b>① 주렁주렁</b> = звукоподр. «гроздьями, обильно (свисают плоды)».<br>✖️ ② 사각사각 «хруст», ③ 보글보글 «бульканье», ④ 퐁당퐁당 «плюх» — не про висящие плоды."},{"n":5,"points":1,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"미안해요. 음악을 듣느라고 전화 소리를 못 들었어요.\n(밑줄: 듣느라고)","options":["듣겠지만","들어 봤더니","듣는 김에","듣고 있어서"],"answer":4,"explain":"«-느라고» = «из-за того что (был занят) слушанием» (причина-помеха).<br>✅ <b>④ 듣고 있어서</b> = «потому что слушал» — та же причинная связь.<br>✖️ ① «послушаю, но», ② «попробовал послушать и», ③ 김에 «заодно» — другое значение."},{"n":6,"points":1,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"주말에 영화를 봤는데 영화가 눈물이 날 정도로 감동적이었어요.\n(밑줄: 눈물이 날 정도로)","options":["눈물이 나길래","눈물이 날 만큼","눈물이 날 때까지","눈물이 난 덕분에"],"answer":2,"explain":"«-(으)ㄹ 정도로» = «настолько, что» = степень.<br>✅ <b>② 눈물이 날 만큼</b> = «настолько, что наворачивались слёзы» — то же «-(으)ㄹ 만큼».<br>✖️ ① 길래 «раз уж», ③ 때까지 «пока не», ④ 덕분에 «благодаря» — другое."},{"n":7,"points":1,"instr":"Выберите слово, которое подходит в оба пропуска ( ).","passage":"이제 호텔에 들어왔으니까 방에 들어가서 짐을 ( ) 쉬세요.\n쉬면서 쌓인 피로를 ( )고 싶어요.","options":["풀다","넣다","나다","쌓다"],"answer":1,"explain":"짐을 풀다 = «разобрать вещи», 피로를 풀다 = «снять усталость» — глагол 풀다 подходит в оба.<br>✅ <b>① 풀다</b>.<br>✖️ ② 넣다 «класть», ③ 나다 «возникать», ④ 쌓다 «накапливать» — не сочетаются с обоими."},{"n":8,"points":1,"instr":"Выберите пословицу, подходящую к ситуации диалога.","passage":"가: 그분은 참 겸손한 것 같아요. 그렇게 큰 상을 받고도 수상 소감을 겸손하게 말하더라고요.\n나: 맞아요. 그런 겸손한 태도는 배울 만해요.","options":["입에 쓴 약이 몸에 좋다","달면 삼키고 쓰면 뱉는다","우물을 파도 한 우물만 파라","벼는 익을수록 고개를 숙인다"],"answer":4,"explain":"Речь о скромности человека, добившегося многого.<br>✅ <b>④ 벼는 익을수록 고개를 숙인다</b> «спелый колос клонит голову» = чем достойнее человек, тем он скромнее.<br>✖️ ① «горькое лекарство полезно», ② «сладкое глотают, горькое выплёвывают», ③ «копай один колодец» — не про скромность."},{"n":9,"points":1,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"한강 공원은 우리 집에서 가깝습니다. 그래서 저는 저녁마다 동생과 한강 공원에 갑니다. 동생은 자전거를 타고 저는 달리기를 합니다.","options":["저는 한강 공원에 가끔 갑니다.","저는 저녁마다 자전거를 탑니다.","한강 공원은 우리 집 근처에 있습니다.","동생은 저녁에 혼자 한강 공원에 갑니다."],"answer":3,"explain":"«공원은 우리 집에서 가깝습니다» = парк рядом с домом.<br>✅ <b>③ 우리 집 근처에 있습니다</b> (рядом с домом).<br>✖️ ① хожу 저녁마다 (каждый вечер), не иногда, ② на велосипеде — брат, я бегаю, ④ ходим вместе, не он один."},{"n":10,"points":1,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"저는 어제 지하철에 가방을 놓고 내렸습니다. 그래서 지하철 분실물 센터에 가서 물어봤는데 제 가방이 없었습니다. 오늘 수업이 끝나고 다시 분실물 센터에 가 보려고 합니다.","options":["저는 오늘 수업이 없습니다.","저는 어제 가방을 잃어버렸습니다.","저는 오늘 지하철에서 가방을 찾았습니다.","제 가방은 지하철 분실물센터에 있었습니다."],"answer":2,"explain":"«어제 지하철에 가방을 놓고 내렸다» = вчера забыл сумку в метро.<br>✅ <b>② 어제 가방을 잃어버렸습니다</b> (вчера потерял сумку).<br>✖️ ① сегодня есть занятия (수업이 끝나고), ③ ещё не нашёл, ④ сумки в бюро находок не было."},{"n":11,"points":1,"instr":"Прочитайте и выберите главную мысль текста.","passage":"저는 고등학교를 졸업한 후 외국에서 공부하고 있기 때문에 동창들을 오랫동안 만나지 못했습니다. 그래서 친구들이 보고 싶습니다. 다음 방학에 고향에 가려고 합니다. 빨리 방학이 되면 좋겠습니다.","options":["저는 외국으로 유학을 가야 합니다.","저는 외국에서 공부하는 것이 좋습니다.","저는 방학이 되기 전에 친구들을 볼 겁니다.","저는 방학에 고등학교 친구들을 만나고 싶습니다."],"answer":4,"explain":"Скучает по школьным друзьям, на каникулах поедет домой.<br>✅ <b>④ 방학에 고등학교 친구들을 만나고 싶습니다</b> (хочу встретить друзей на каникулах).<br>✖️ ① «должен ехать учиться» — не мысль, ② про учёбу за границей — не главное, ③ поедет в каникулы, а не «до» них."},{"n":12,"points":1,"instr":"О чём этот текст (реклама)? Выберите.","passage":"포근한 느낌!\n따뜻하게 숙면을 취할 수 있어요.","options":["이불","수건","휴지","안경"],"answer":1,"explain":"«Уютно, тепло, крепкий сон» → про одеяло.<br>✅ <b>① 이불</b> (одеяло).<br>✖️ ② 수건 полотенце, ③ 휴지 салфетки, ④ 안경 очки — не про сон и тепло."},{"n":13,"points":1,"instr":"О чём этот текст? Выберите.","passage":"사용하지 않을 때는 전원을 꺼 주세요.\n미래를 위해 남겨 두세요.","options":["화재 예방","교통 문제","전기 절약","이웃 사랑"],"answer":3,"explain":"«Выключайте питание, когда не пользуетесь; сбережём для будущего» → экономия электричества.<br>✅ <b>③ 전기 절약</b> (экономия электроэнергии).<br>✖️ ① пожарная безопасность, ② транспорт, ④ любовь к ближнему — не о питании/энергии."},{"n":14,"points":1,"instr":"Выберите вариант, совпадающий с содержанием объявления (афиша концерта).","passage":"[Афиша музыкального концерта] Указаны: время, место, условия входа и скидка для жителей района 성북구.","options":["이 음악회는 주말 오전에 열린다.","이 음악회는 누구나 관람할 수 있다.","이 음악회에서는 영화도 볼 수 있다.","성북구에 사는 사람은 할인을 받을 수 있다."],"answer":4,"explain":"По ключу верно: на афише есть скидка для жителей района Сонбук-гу.<br>✅ <b>④ 성북구에 사는 사람은 할인을 받을 수 있다</b> (жителям 성북구 — скидка).<br>✖️ ① время не «утро выходного», ② вход не для всех, ③ кино на концерте не показывают."},{"n":15,"points":1,"instr":"Выберите вариант, совпадающий с содержанием графика (где слушают музыку: 20-летние и 50-летние).","passage":"[График] Где люди 20 и 50 лет слушают музыку: на ходу, дома за делами, во время спорта, в транспорте, в авто.","options":["20대는 길을 걸으면서 음악을 듣는 사람이 가장 많다.","50대는 집안일을 하면서 음악을 듣는 사람이 가장 적다.","20대가 50대보다 운동하면서 음악 듣는 것을 더 선호한다.","50대는 대중교통보다 자동차에서 음악을 듣는 사람이 더 많다."],"answer":4,"explain":"По ключу верно: у 50-летних слушают музыку в авто больше, чем в общественном транспорте.<br>✅ <b>④ 50대는 대중교통보다 자동차에서 듣는 사람이 더 많다</b>.<br>✖️ ①②③ — противоречат данным графика (подмена «больше/меньше» и сравнения возрастов)."},{"n":16,"points":1,"instr":"Выберите вариант, совпадающий с содержанием графика (досуг школьников 2012 vs 2022).","passage":"[График] Доля учеников начальной школы по длительности свободного времени в 2012 и 2022 годах (менее 1 ч, 1–2 ч, 2–3 ч, 3–4 ч).","options":["2012년에는 여가 시간이 2~3시간인 초등학생이 가장 많았다.","2022년에는 여가 시간이 1~2시간인 초등학생이 가장 적었다.","여가 시간이 3~4시간인 초등학생의 비율은 2012년보다 2022년이 높았다.","여가 시간이 1시간 미만인 초등학생의 비율은 2012년에 비해 2022년에 늘었다."],"answer":3,"explain":"По ключу верно: доля школьников с досугом 3–4 часа в 2022 году выше, чем в 2012.<br>✅ <b>③ 3~4시간 비율은 2012년보다 2022년이 높았다</b>.<br>✖️ ①②④ — не соответствуют цифрам графика."},{"n":17,"points":1,"instr":"Выберите подходящее для пропуска ( ).","passage":"어렸을 때부터 심부름을 한 아이가 자라서 성공할 가능성이 높다는 연구 결과가 나왔다. 아이들은 이런 일을 스스로 해내는 과정을 통해 다른 사람에게 무엇이 필요한지 살펴보는 ( ) 되고, 부모가 시킨 일을 완수하면서 성취감을 느끼게 된다. 즉, 심부름을 수행하는 과정에서 문제 해결 능력이 좋아지고, 자신감과 성취감, 책임감도 생길 수 있다.","options":["일을 시키게","능력을 키우게","인상을 받게 되고","성공할 기회를 얻고"],"answer":2,"explain":"Через поручения ребёнок «учится замечать, что нужно другим» → развивает способность.<br>✅ <b>② 능력을 키우게 (되고)</b> = «развивает способность».<br>✖️ ① «заставлять работать», ③ «получать впечатление», ④ «получать шанс на успех» — не вяжутся с «살펴보는 … 되고»."},{"n":18,"points":1,"instr":"О чём этот текст? Выберите.","passage":"어렸을 때부터 심부름을 한 아이가 자라서 성공할 가능성이 높다는 연구 결과가 나왔다. 심부름을 수행하는 과정에서 문제 해결 능력이 좋아지고, 일을 다 완수한 후 칭찬을 통해 자신감과 성취감을 느낄 수 있을 뿐만 아니라 책임감도 생길 수 있다.","options":["심부름을 잘하게 하는 방법","심부름이 필요한 아이의 특징","심부름을 통해 얻을 수 있는 효과","심부름을 시킬 때 어른이 해야 할 일"],"answer":3,"explain":"Текст перечисляет, что даёт ребёнку выполнение поручений (навыки, уверенность, ответственность).<br>✅ <b>③ 심부름을 통해 얻을 수 있는 효과</b> (эффект/польза от поручений).<br>✖️ ① как научить, ② черты ребёнка, ④ что делать взрослому — текст об этом не говорит."},{"n":19,"points":1,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"우리 아파트는 쓰레기 수거장을 관리해 주는 관리 사무소가 없어서 쓰레기 수거장이 항상 지저분하고 냄새가 났습니다. ( ㉠ ) 그런데 어느 날부터 쓰레기장이 점점 깨끗해지기 시작했습니다. ( ㉡ ) 이 주민은 항상 웃으면서 다른 사람이 버린 쓰레기까지 치웠습니다. ( ㉢ ) 이런 모습을 보고 다른 주민들도 쓰레기를 잘 버리고 쓰레기 수거장도 잘 정리했습니다. ( ㉣ ) 그래서 우리 아파트가 깨끗해졌습니다.\n\n<보기> 여성 주민 한 분이 이곳을 정리하고 청소해 주었기 때문입니다.","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"После ㉡ идёт «이 주민(этот житель)…» — значит перед ним надо ВВЕСТИ этого жителя.<br>✅ <b>② ㉡</b>: «…стало чище. (Потому что одна жительница убирала это место.) Эта жительница всегда с улыбкой…».<br>✖️ при других вставках «이 주민» остаётся без введённого подлежащего."},{"n":20,"points":1,"instr":"Выберите выражение (4-знак), лучше всего подходящее к содержанию текста.","passage":"한 여성 주민이 솔선해서 쓰레기 수거장을 청소하자 다른 주민들도 따라서 깨끗이 정리하게 되었다는 이야기.","options":["갑론을박","사면초가","고진감래","솔선수범"],"answer":4,"explain":"Жительница первой подала пример, и другие последовали.<br>✅ <b>④ 솔선수범 (率先垂範)</b> = «подавать личный пример, идти впереди».<br>✖️ ① 갑론을박 «жаркий спор», ② 사면초가 «безвыходное положение», ③ 고진감래 «после горького — сладкое» — не подходят."},{"n":21,"points":1,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"퇴직 후 20년 가까이 아이들에게 동화책을 읽어 주는 할머니가 있다. 동화책 할머니는 30여 년의 교사 생활을 하고 퇴직 후 봉사 활동을 하고 있다. 또한 이 할머니는 5년 전부터 사회복지 회관에 가서 할머니들에게도 동화를 읽어 주면서 친구가 되어 주고 있다. 할머니들은 동화를 들으면서 어린 시절을 추억할 수 있어서 좋다고 한다.","options":["동화책 할머니는 다른 할머니들에게도 동화책을 읽어 준다.","동화책 할머니는 교사 생활을 하면서 봉사 활동을 하고 있다.","동화책 할머니는 동화책을 읽어 주기 시작한 지 얼마 안 되었다.","아이들은 동화책 할머니가 들려주는 것보다 책을 읽는 것을 좋아한다."],"answer":1,"explain":"«할머니들에게도 동화를 읽어 주면서» — читает сказки и пожилым.<br>✅ <b>① 다른 할머니들에게도 동화책을 읽어 준다</b>.<br>✖️ ② сначала была учителем, ПОТОМ волонтёр (после 퇴직), ③ занимается уже ~20 лет, ④ детям так интереснее, чем читать самим."},{"n":22,"points":1,"instr":"Расставьте (가)~(라) в правильном порядке.","passage":"(가) 그동안 대부분의 사무실은 개인 공간이 보장된 폐쇄형 사무실이었다.\n(나) 오히려 혼란스러워서 직원들의 집중력을 떨어뜨렸기 때문이다.\n(다) 그러나 예상과 달리 이 사무실은 소통과 협업에 도움이 되지 않았다.\n(라) 그런데 팀 작업이 중시되면서 협업과 소통을 위해 개방형 사무실로 바꾸었다.","options":["(가)-(나)-(라)-(다)","(가)-(라)-(다)-(나)","(라)-(가)-(나)-(다)","(라)-(다)-(나)-(가)"],"answer":2,"explain":"(가) вводит тему (раньше — закрытые офисы) → (라) 그런데 перешли к открытым → (다) 그러나 не помогло → (나) причина (наоборот мешало).<br>✅ <b>② (가)-(라)-(다)-(나)</b>.<br>✖️ остальные нарушают связки 그런데/그러나/오히려."},{"n":23,"points":1,"instr":"Расставьте (가)~(라) в правильном порядке.","passage":"(가) 밖으로 나와 빗자루로 눈을 쓸기 시작했다.\n(나) 그래서 눈 쓸기를 멈추고 새하얀 눈 세상을 바라보았다.\n(다) 눈을 쓸다 보니 새하얀 눈 세상을 쓸어버리기가 아까워졌다.\n(라) 아침에 일어나 밖을 내다보니 눈이 와 세상이 온통 새하얗게 변했다.","options":["(가)-(다)-(라)-(나)","(가)-(라)-(다)-(나)","(라)-(가)-(다)-(나)","(라)-(나)-(가)-(다)"],"answer":3,"explain":"(라) утром увидел снег → (가) вышел и стал мести → (다) стало жаль сметать белизну → (나) 그래서 остановился и залюбовался.<br>✅ <b>③ (라)-(가)-(다)-(나)</b>.<br>✖️ первое предложение не может содержать 그래서(나)/начинаться с действия без завязки."},{"n":24,"points":1,"instr":"Выберите вариант, лучше всего объясняющий заголовок новости.","passage":"응급 사이렌에 도로가 쫙, 응급 환자 목숨 살려","options":["도로가 파여서 응급 환자 이송을 위해 달리던 응급차가 사고를 당했다.","도로를 달리던 응급차가 사고가 나서 응급 환자를 구할 수 없게 되었다.","응급 환자의 목숨을 살리기 위해 응급차가 속도를 내어 도로에 문제가 생겼다.","응급차의 사이렌 소리가 나자 차들이 비켜 준 덕분에 응급 환자를 살릴 수 있었다."],"answer":4,"explain":"«도로가 쫙» = машины расступились перед сиреной → спасли пациента.<br>✅ <b>④ 사이렌 소리에 차들이 비켜 준 덕분에 환자를 살렸다</b>.<br>✖️ ①②③ говорят об аварии/проблеме на дороге — заголовок же о спасении."},{"n":25,"points":1,"instr":"Выберите вариант, лучше всего объясняющий заголовок новости.","passage":"'K 게임' 수출·고용 다 잡은 효자 산업 됐다","options":["'K 게임'을 수출하기 전에 게임 산업 분야에 고용 문제가 발생했다.","'K 게임' 산업 부분에 젊은 효자들의 고용을 늘렸더니 수출이 증가하였다.","'K 게임' 분야는 수출도 증가하고 일자리도 증가하여 산업 발전에 기여했다.","'K 게임'의 수출과 고용 증가는 젊은 사람들의 게임에 대한 관심 때문이다."],"answer":3,"explain":"«수출·고용 다 잡은 효자 산업» = и экспорт, и рабочие места выросли — отрасль-«молодец».<br>✅ <b>③ 수출도 증가, 일자리도 증가하여 산업 발전에 기여</b>.<br>✖️ ① «до экспорта была безработица», ② путает 효자(отрасль) с людьми, ④ причину «интерес молодёжи» заголовок не утверждает."},{"n":26,"points":1,"instr":"Выберите вариант, лучше всего объясняющий заголовок новости.","passage":"'콜록콜록' 독감 유행 조짐…\"미리 예방접종\"","options":["독감이 유행할 것으로 예상되니 미리 독감 예방주사를 맞는 것이 좋겠다.","기침을 통해 독감이 퍼지게 되어 미리 예방주사를 맞으려는 사람이 늘었다.","독감이 유행하면서 독감에 걸려 치료를 받으려는 사람들이 병원을 찾고 있다.","독감 예방주사를 미리 맞았는데도 독감에 걸려 기침을 하는 사람이 많아졌다."],"answer":1,"explain":"«유행 조짐(признаки эпидемии)…미리 예방접종» = ожидается грипп → стоит заранее привиться.<br>✅ <b>① 유행이 예상되니 미리 예방주사를 맞는 것이 좋겠다</b>.<br>✖️ ②③④ добавляют факты (рост заболевших, неэффективность прививки), которых в заголовке нет."},{"n":27,"points":1,"instr":"Выберите чувство автора в подчёркнутой части.","passage":"우리 집 막내 앵무새 '미미'가 거실 문을 잠깐 열어 놓은 사이에 밖으로 날아가 버렸다. 집 밖으로 나간 적이 없는 앵무새는 바깥에서 30분 정도 살아남기 힘들기 때문에 그 시간 안에 반드시 찾아야 했다. \"미미야!\" 소리치며 온 동네를 다 찾아다녔다. 비까지 세차게 내리기 시작했다. 미미가 살아 있을 가능성이 점점 희박해졌다. 아무도 없는 집에 돌아와 텅 빈 새장을 보고는 아이처럼 엉엉 울었다.\n(밑줄: 텅 빈 새장을 보고는 아이처럼 엉엉 울었다)","options":["화나고 짜증스럽다","긴장되고 실망스럽다","답답하고 조심스럽다","안타깝고 걱정스럽다"],"answer":4,"explain":"Попугай пропал, дождь, шансы тают, автор рыдает у пустой клетки.<br>✅ <b>④ 안타깝고 걱정스럽다</b> (горестно и тревожно).<br>✖️ ① злость, ② лишь «нервозность/разочарование», ③ «досада и осторожность» — слабее реальных чувств утраты."},{"n":28,"points":1,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"앵무새 '미미'가 밖으로 날아가 버려 온 동네를 찾아다니고 중고 거래 어플, 앵무새 카페, 동물 실종 센터에 사례금 글도 올렸다. 실종된 지 나흘째 되던 날, 중고 거래 알림이 울렸고 한 남성이 보낸 사진 속 앵무새가 바로 미미였다. 그 남자와 약속을 하고 미미를 찾아왔다.","options":["앵무새를 30분 동안 데리고 나갔다가 잃어버렸다.","중고 거래 사이트를 통해 잃어버린 앵무새를 찾았다.","앵무새를 찾다가 집에 돌아와 보니 아이가 울고 있었다.","잃어버린 앵무새를 찾으려고 동물 실종 센터에 찾아갔다."],"answer":2,"explain":"«중고 거래 알림…사진 속 앵무새가 미미였다» — нашёл через сайт объявлений.<br>✅ <b>② 중고 거래 사이트를 통해 앵무새를 찾았다</b>.<br>✖️ ① попугай улетел сам, ③ плакал сам автор (как ребёнок), ④ объявление разместил онлайн, лично в центр не ездил."},{"n":29,"points":1,"instr":"Выберите подходящее для пропуска ( ).","passage":"파리는 다리를 비비는 행동을 자주 한다. 이것은 파리가 입이 아니라 다리를 통해 맛과 냄새를 더 많이 느끼기 때문이다. 파리는 다리털에 무엇인가 묻어 있으면 맛과 냄새를 잘 느낄 수 없다. 그래서 틈만 나면 다리를 비벼서 다리털에 묻은 ( ) 것이다.","options":["맛을 잘 느끼는","이물질을 제거하는","냄새를 맡아 보는","음식물을 먹게 되는"],"answer":2,"explain":"Если на волосках лап что-то налипло, муха хуже чувствует → трёт лапки, чтобы это убрать.<br>✅ <b>② 이물질을 제거하는</b> (удаляет налипшее/инородное).<br>✖️ ① «хорошо чувствует вкус» (это цель, а не действие «묻은 …»), ③ нюхает, ④ ест — не вяжутся с «묻은(налипшее)»."},{"n":30,"points":1,"instr":"Выберите подходящее для пропуска ( ).","passage":"사람들은 자신이 알고 있는 것을 상대방도 알고 있을 거라는 착각에 빠지곤 한다. 조직에서 구성원들이 서로 '알고 있겠지'라는 착각에 작은 일이라도 그냥 넘어가다 보면 의도하지 않게 업무에 지장을 주게 되고, 생산성이 떨어진다. 결국 이런 착각이 업무를 망치게 된다. ( ) 구성원들이 업무를 정확하게 판단하고 일의 효율도 높아지는 것이다.","options":["정보를 공유해야","지식이 풍부해야","일의 계획을 잘 세워야","생산성과 효율을 높여야"],"answer":1,"explain":"Проблема — иллюзия «другой и так знает». Решение — обмениваться информацией.<br>✅ <b>① 정보를 공유해야</b> (нужно делиться информацией) → тогда работа точнее, эффективность выше.<br>✖️ ② «нужно много знаний», ③ «хорошо планировать», ④ «повышать эффективность» — не устраняют причину (несообщённое знание)."},{"n":31,"points":2,"instr":"Выберите подходящее для пропуска ( ).","passage":"대부분의 부모나 교사들은 아이들이 싸웠을 때 아이들의 잘잘못을 가려 화해시키려고 한다. 하지만 이렇게 한다고 해서 문제가 해결되는 것은 아니다. 아이들을 서로 화해시키기 위해서는 아이들에게 자신의 상황과 감정에 대해 ( ) 이야기할 기회를 주어 상대방의 입장과 기분을 알게 하는 것이 중요하다. 잘못을 한 아이는 자신의 말과 행동이 상대방에게 어떤 감정을 느끼게 했는지 직접 듣고 진심으로 사과해야 한다.","options":["가슴을 열고","두 팔을 벌리고","어깨가 무거우며","귀에 못이 박히며"],"answer":1,"explain":"Дать детям возможность откровенно рассказать о чувствах.<br>✅ <b>① 가슴을 열고</b> «открыв сердце» = искренне, откровенно.<br>✖️ ② 두 팔을 벌리고 «раскрыв объятия» (буквально), ③ 어깨가 무겁다 «тяжесть ответственности», ④ 귀에 못이 박히다 «уши прожужжали» — не подходят к «искренне рассказать»."},{"n":32,"points":2,"instr":"Выберите главную мысль текста.","passage":"부모나 교사가 아이들의 잘잘못을 가려 화해시키려 해도 문제는 해결되지 않는다. 잘못한 아이가 자신의 말과 행동이 상대방에게 어떤 감정을 느끼게 했는지 직접 듣고 자신의 잘못을 깨달은 후 진심으로 사과해야 상처받은 아이도 용서할 수 있게 된다.","options":["어른들은 상처받은 아이를 우선 이해해 주는 것이 좋다.","아이들 간의 문제는 어른이 개입해야 쉽게 해결될 수 있다.","사과하는 아이가 상처받은 아이의 감정을 이해해야 화해할 수 있다.","어른들은 아이들을 화해시키기 위해 누가 잘못했는지 알려 줘야 한다."],"answer":3,"explain":"Примирение наступает, когда виноватый осознаёт чувства другого и искренне извиняется.<br>✅ <b>③ 사과하는 아이가 상대의 감정을 이해해야 화해할 수 있다</b>.<br>✖️ ①②④ — позиции «разобрать вину/вмешательство взрослого», которые текст как раз критикует."},{"n":33,"points":2,"instr":"Выберите подходящее для пропуска ( ).","passage":"1945년 해방 이후 여성들이 모여 시작한 국극은 1950년대에 인기를 끌었던 공연 예술이다. 여성 소리꾼이 여성과 남성 배역을 모두 소화하는 국악 연극이다. 국극은 소리에 춤과 연기를 더해 대중성과 오락성에 큰 비중을 두며 인기를 끌었다. 그러나 영화가 발달해 대중화되면서 국극의 인기는 떨어지기 시작했다. 게다가 국극단 수가 늘어난 데다 시대감각이 변하는데도 주제나 표현 방식을 바꾸지 않고 ( ) 고루하고 진부하다는 느낌을 주어 급격히 쇠퇴했다.","options":["그대로 고수함으로써","다른 방법을 찾아냄으로써","연기 훈련 방식을 바꿈으로써","영화의 방식을 받아들임으로써"],"answer":1,"explain":"«주제나 표현 방식을 바꾸지 않고 ( )» — не меняя темы → «придерживаясь по-старому» → старомодно.<br>✅ <b>① 그대로 고수함으로써</b> (сохраняя всё как есть).<br>✖️ ②③④ означают перемены, что противоречит «바꾸지 않고(не меняя)»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"국극은 여성 소리꾼이 남녀 배역을 모두 맡는 국악 연극으로 1950년대 인기를 끌었다. 그러나 영화의 발달, 국극단의 난립, 그리고 시대 변화에도 주제·표현을 바꾸지 않은 점 때문에 1950년대 말부터 급격히 쇠퇴하였다.","options":["국극은 판소리의 형식을 그대로 유지하는 것을 중요시했다.","국극이 인기를 얻으면서 영화에 대한 사람들의 관심도 커졌다.","국극은 남자 배우와 여자 배우들의 연기가 조화를 잘 이루고 있다.","국극의 쇠퇴 원인 중 하나는 시대의 변화를 따르지 못했기 때문이다."],"answer":4,"explain":"«시대감각이 변하는데도 바꾸지 않아 쇠퇴» — не успели за временем.<br>✅ <b>④ 쇠퇴 원인 중 하나는 시대 변화를 따르지 못한 것</b>.<br>✖️ ① 국극 ≠ 판소리 (как раз добавляли танец/игру), ② наоборот — кино отняло популярность, ③ роли играют только женщины-소리꾼."},{"n":35,"points":2,"instr":"Выберите слово-связку для пропуска ( ).","passage":"드론의 활용 범위가 넓어지고 있다. 의약품 수송 시험 비행 성공으로 드론이 의약품을 나르고 응급 환자도 이송하는 시대가 곧 열릴 것이라 한다. 드론은 좁은 공간에 착륙할 수 있고, 접근이 어려운 지역에 의약품을 수송하며, 구급차보다 빨리 갈 수 있다. ( ) 의약품 수송 드론을 실용화하려면 아직 해결할 과제가 남아 있다. 열에 민감한 의약품을 보존하며 운반해야 하므로 적정 온도와 기압 유지 실험으로 안정성을 확보해야 한다.","options":["그러나","그리고","그래서","따라서"],"answer":1,"explain":"До пропуска — плюсы дрона; после — «но есть нерешённые задачи». Это контраст.<br>✅ <b>① 그러나</b> (однако).<br>✖️ ② 그리고 «и», ③ 그래서 / ④ 따라서 «поэтому» — выражают следствие, а здесь противопоставление."},{"n":36,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"의약품 수송 드론은 좁은 공간에 착륙할 수 있고 구급차보다 빨리 응급 현장에 갈 수 있다. 다만 열에 민감한 의약품을 상공에서 보존하며 운반해야 하므로 적정 온도와 기압을 유지하는 실험을 거쳐 안정성을 확보해야 한다.","options":["드론에 비해 구급차가 응급 현장에 더 빨리 도착할 수 있다.","드론으로 의약품을 나를 때 의약품의 온도 유지가 중요하다.","드론을 이용해서 응급 환자를 병원으로 옮기는 건 불가능하다.","드론 착륙에는 기술적 문제 때문에 아직 넓은 공간이 필요하다."],"answer":2,"explain":"«열에 민감한 의약품…적정 온도 유지» — важно сохранять температуру лекарств.<br>✅ <b>② 의약품의 온도 유지가 중요하다</b>.<br>✖️ ① дрон быстрее скорой, ③ перевозить пациентов как раз ожидается возможным, ④ дрон садится на малой площади (좁은 공간)."},{"n":37,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"제주도의 밭담이 세계농업유산으로 지정되며 해마다 밭담 축제가 열린다. 밭담은 밭의 경계에 돌을 쌓아 올린 것이다. ( ㉠ ) 예전부터 제주도에서는 돌이 흔해 돌로 담을 쌓아 밭의 경계를 구분 지었다. 제주도에서는 소와 말을 방목해 키웠다. ( ㉡ ) 그래서 소와 말이 밭에 들어와 농사를 망치는 것을 막기 위해 밭담을 쌓았다. ( ㉢ ) 그래서 바람을 막아 땅을 보호하기 위해 밭담을 쌓아 농작물을 길러냈다. ( ㉣ )\n\n<보기> 또한 제주도는 바람이 잦아 농사짓기가 어려운 척박한 환경이었다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"После ㉢ идёт «그래서 바람을 막아…(поэтому, чтобы защитить от ветра…)». Значит перед ним нужно ввести тему ветра.<br>✅ <b>③ ㉢</b>: «<보기> К тому же на Чеджу часты ветры… → поэтому строили 밭담 для защиты от ветра».<br>✖️ при ㉠/㉡/㉣ упоминание ветра повисает без связи со следующим 그래서."},{"n":38,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"제주도의 밭담은 밭의 경계에 돌을 쌓은 것으로, 돌이 흔한 제주에서 경계를 짓고, 방목하는 소와 말이 밭에 들어오는 것을 막고, 잦은 바람을 막아 땅과 농작물을 보호하는 역할을 했다. 밭담은 세계농업유산으로 지정되었다.","options":["제주도는 예전부터 말과 소를 밭에 가두어서 키웠다.","제주도에서는 돌이 많지 않아 밭담을 어렵게 쌓았다.","제주도의 밭담은 제주도의 농사에 도움을 주는 역할을 했다.","제주도의 밭담이 올해 세계농업유산으로 지정되어 축제가 열렸다."],"answer":3,"explain":"밭담 защищал поля от скота и ветра → помогал земледелию.<br>✅ <b>③ 밭담은 농사에 도움을 주는 역할을 했다</b>.<br>✖️ ① скот пасли свободно (방목), а담 не пускал его в поле, ② камня было много (돌이 흔해), ④ «올해(в этом году)» — не указано, фестиваль ежегодный (해마다)."},{"n":39,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"소액 사건 심판은 3000만 원 이하 민사 사건에서 국민의 편의를 위해 간단한 절차로 신속히 소송을 진행하게 한 제도이다. 그런데 판사는 판결서에 판결 이유를 쓰지 않고, 말로도 대부분 설명하지 않는다. 재판 당사자는 판결 근거를 알아야 항소할 수 있는데 이유를 알지 못해 항소가 어렵다. 원래 목적과 달리 국민의 알 권리와 재판받을 권리가 침해당할 수 있다.","options":["소액 사건 심판의 과정을 설명하려고","소액 사건 심판의 문제점을 알리려고","소액 사건 심판의 확대 실시를 요구하려고","소액 사건 심판 당사자의 참여를 비판하려고"],"answer":2,"explain":"Текст показывает, что система ущемляет право на информацию и обжалование → указывает на её проблему.<br>✅ <b>② 문제점을 알리려고</b> (сообщить о проблеме).<br>✖️ ① не просто описание процесса, ③ не призыв расширять, ④ критикует не участников, а недостаток системы."},{"n":40,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"소액 사건 심판에서 판사는 판결서에 판결 이유를 쓰지 않고 말로도 대부분 설명하지 않는다. 재판 당사자는 판결의 근거를 알아야 항소할 수 있는데 그 이유를 제대로 알지 못해 항소하기가 어렵다.","options":["소송 당사자들은 판사의 판결 이유를 파악하기 어렵다.","소액 사건 심판은 소송 절차가 다른 사건에 비해 복잡하다.","소액 사건 심판은 국민의 알 권리를 위해 만들어진 제도이다.","소액 사건 심판에서 판사는 판결문을 써서 결과를 알려 준다."],"answer":1,"explain":"«판결 이유를 쓰지 않아…근거를 알지 못해» — сторонам трудно понять основание решения.<br>✅ <b>① 당사자들은 판결 이유를 파악하기 어렵다</b>.<br>✖️ ② процедура упрощённая (간단한 절차), ③ создана для удобства/быстроты, а право знать как раз ущемляется, ④ судья НЕ пишет причины в решении."}]}},
    3001: {
      mock: true,
      no: "\uBAA8\uC758\uACE0\uC0AC<br><b>3\uAE09</b>",
      listening: {
        durationMin: 20, total: 30, label: '\uBAA8\uC758\uACE0\uC0AC 3\uAE09 \u00B7 \uB4E3\uAE30',
        questions: [{"n":1,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","script":"여자: 민수 씨, 주말에 같이 등산 갈래요?\n남자: 좋아요. 그런데 토요일이랑 일요일 중에 언제가 좋아요?\n여자:","options":["저는 일요일이 더 좋아요.","등산은 정말 재미있었어요.","산이 별로 안 높아서 괜찮아요.","다음에는 꼭 같이 가고 싶어요."],"answer":1,"explain":"🎧 Мужчина спрашивает: «когда удобнее — суббота или воскресенье?» → нужно назвать день.<br>✅ <b>① 저는 일요일이 더 좋아요.</b> (мне удобнее воскресенье).<br>✖️ ② о прошедшем походе, ③ про высоту горы, ④ «в следующий раз» — не отвечают на вопрос «когда»."},{"n":2,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","script":"남자: 여보세요? 거기 한국식당이지요? 오늘 저녁 일곱 시에 네 명 예약하고 싶은데요.\n여자: 죄송합니다. 오늘 저녁은 예약이 다 찼습니다.\n남자:","options":["그럼 내일은 자리가 있어요?","음식이 정말 맛있었어요.","네 명이 모두 왔어요.","일곱 시까지 갈 수 있어요."],"answer":1,"explain":"🎧 На сегодня всё забронировано → логично спросить про другой день.<br>✅ <b>① 그럼 내일은 자리가 있어요?</b> (а завтра есть места?).<br>✖️ ② о вкусе еды (ещё не ели), ③ «все четверо пришли», ④ «успею к семи» — не подходят после отказа в брони."},{"n":3,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","script":"여자: 어, 비가 오네요. 우산 가져왔어요?\n남자: 아니요, 안 가져왔어요. 우산이 없어서 큰일이네요.\n여자:","options":["제가 우산을 하나 빌려줄게요.","비가 와서 날씨가 좋아요.","우산을 사서 기분이 좋아요.","어제 비가 많이 왔어요."],"answer":1,"explain":"🎧 У мужчины нет зонта → собеседница предлагает помощь.<br>✅ <b>① 제가 우산을 하나 빌려줄게요.</b> (я одолжу вам зонт).<br>✖️ ② «погода хорошая из-за дождя» — нелогично, ③ про покупку зонта, ④ о вчерашнем дожде."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","script":"남자: 수미 씨, 회의 자료 다 준비됐어요?\n여자: 네, 거의 다 됐는데 마지막으로 복사만 하면 돼요. 지금 복사하러 갈게요.\n남자: 그래요. 그럼 저는 회의실에 가 있을게요.","options":["회의실에 간다.","자료를 복사한다.","회의를 시작한다.","남자에게 자료를 준다."],"answer":2,"explain":"🎧 Женщина: «осталось только сделать копии, сейчас иду копировать».<br>✅ <b>② 자료를 복사한다.</b> (делает копии материалов).<br>✖️ ① в зал идёт мужчина, ③ совещание ещё не начали, ④ материалы никому не передаёт."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","script":"여자: 민호 씨, 이 책 도서관에서 빌린 거예요?\n남자: 네, 그런데 오늘까지 반납해야 하는데 시간이 없어서 걱정이에요.\n여자: 그래요? 그럼 제가 도서관에 가는 길에 대신 반납해 줄게요.\n남자: 정말요? 고마워요. 여기 책이요.","options":["책을 빌린다.","도서관에서 공부한다.","책을 반납한다.","남자에게 책을 준다."],"answer":3,"explain":"🎧 Женщина обещает по пути сдать книгу за мужчину, он отдаёт ей книгу.<br>✅ <b>③ 책을 반납한다.</b> (сдаёт книгу в библиотеку).<br>✖️ ① книгу не берёт, а возвращает, ② учиться не собирается, ④ книгу отдаёт мужчина ей, а не наоборот."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите действие, которое мужчина (продавец) совершит далее.","script":"남자: 어서 오세요. 무엇을 도와드릴까요?\n여자: 이 신발을 어제 샀는데 좀 작아서요. 한 사이즈 큰 걸로 바꾸고 싶어요.\n남자: 네, 잠깐만요. 같은 색으로 큰 사이즈가 있는지 확인해 보겠습니다.\n여자: 네, 감사합니다.","options":["신발을 환불해 준다.","큰 사이즈가 있는지 알아본다.","다른 색 신발을 추천한다.","여자에게 영수증을 받는다."],"answer":2,"explain":"🎧 Продавец: «проверю, есть ли больший размер того же цвета».<br>✅ <b>② 큰 사이즈가 있는지 알아본다.</b> (проверяет наличие большего размера).<br>✖️ ① речь об обмене, не о возврате денег, ③ другой цвет не предлагал, ④ чек не просил."},{"n":7,"points":2,"instr":"Прослушайте объявление и выберите вариант, совпадающий с услышанным.","script":"여자: 손님 여러분께 안내 말씀 드립니다. 지금부터 일 층 식품 매장에서 특별 행사를 시작합니다. 오늘 하루 동안 과일과 채소를 삼십 퍼센트 싸게 판매하니 많은 이용 바랍니다. 행사는 오후 아홉 시까지입니다.","options":["이 행사는 일주일 동안 한다.","과일을 평소보다 싸게 살 수 있다.","행사는 이 층 식품 매장에서 한다.","채소는 행사 상품에 포함되지 않는다."],"answer":2,"explain":"🎧 «Сегодня фрукты и овощи на 30% дешевле».<br>✅ <b>② 과일을 평소보다 싸게 살 수 있다.</b> (фрукты можно купить дешевле обычного).<br>✖️ ① акция только сегодня (하루 동안), ③ на 1-м этаже, ④ овощи тоже со скидкой."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите вариант, совпадающий с услышанным.","script":"남자: 수미 씨, 다음 달에 부산으로 여행 간다면서요?\n여자: 네, 친구하고 같이 가요. 기차표는 벌써 예매했는데 아직 호텔은 못 정했어요.\n남자: 그럼 바다 근처 호텔로 예약해요. 경치가 정말 좋아요.\n여자: 좋은 생각이에요. 오늘 저녁에 인터넷으로 찾아볼게요.","options":["여자는 혼자 부산에 간다.","여자는 기차표를 아직 안 샀다.","여자는 호텔을 아직 예약하지 않았다.","남자는 여자와 같이 여행을 간다."],"answer":3,"explain":"🎧 «Билеты на поезд уже купила, но отель ещё не выбрала».<br>✅ <b>③ 여자는 호텔을 아직 예약하지 않았다.</b> (отель ещё не забронировала).<br>✖️ ① едет с подругой, ② билеты уже купила (예매했다), ④ мужчина с ней не едет — только советует."},{"n":9,"points":2,"instr":"Прослушайте диалог и выберите вариант, совпадающий с услышанным.","script":"여자: 민수 씨는 보통 주말에 뭐 해요?\n남자: 저는 토요일마다 요리 교실에 다녀요. 한국 음식 만드는 걸 배우고 있어요.\n여자: 와, 재미있겠어요. 저도 배우고 싶은데 어디에서 해요?\n남자: 우리 집 근처 문화 센터에서 해요. 같이 가요.","options":["남자는 매주 요리를 배운다.","여자는 요리 교실에 다닌다.","요리 교실은 일요일에 한다.","남자는 요리를 가르친다."],"answer":1,"explain":"🎧 «Хожу на кулинарные курсы каждую субботу, учусь готовить».<br>✅ <b>① 남자는 매주 요리를 배운다.</b> (учится готовить каждую неделю — 토요일마다).<br>✖️ ② на курсы пока ходит мужчина, ③ по субботам, ④ он учится, а не учит."},{"n":10,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","script":"여자: 민호 씨, 아침을 매일 먹어요? 저는 시간이 없어서 거의 못 먹어요.\n남자: 저는 꼭 먹어요. 아침을 먹으면 하루 종일 힘이 나고 일도 더 잘돼요. 좀 일찍 일어나서라도 아침은 꼭 먹는 게 좋아요.","options":["아침을 먹으면 살이 찐다.","아침은 꼭 챙겨 먹는 것이 좋다.","아침에는 일찍 일어나기 어렵다.","바쁠 때는 아침을 안 먹어도 된다."],"answer":2,"explain":"🎧 «Завтрак даёт силы на весь день, лучше обязательно завтракать».<br>✅ <b>② 아침은 꼭 챙겨 먹는 것이 좋다.</b> (завтрак стоит обязательно есть).<br>✖️ ① про набор веса не говорил, ③ это лишь деталь (встать пораньше), ④ противоположно сказанному."},{"n":11,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","script":"여자: 요즘 인터넷으로 옷을 많이 사는데, 민수 씨도 그래요?\n남자: 저는 옷은 꼭 가게에 가서 사요. 인터넷은 편하지만 직접 입어 봐야 저한테 맞는지 알 수 있잖아요. 그래서 좀 불편해도 가게에 가요.","options":["인터넷 쇼핑이 더 편하고 좋다.","옷은 직접 입어 보고 사는 것이 좋다.","가게보다 인터넷이 옷이 더 싸다.","옷을 살 때는 시간을 아껴야 한다."],"answer":2,"explain":"🎧 «Одежду надо примерить, поэтому хожу в магазин».<br>✅ <b>② 옷은 직접 입어 보고 사는 것이 좋다.</b> (одежду лучше покупать, примерив).<br>✖️ ① удобство признаёт, но выбирает магазин, ③ про цену не говорил, ④ про экономию времени — нет."},{"n":12,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","script":"여자: 민호 씨, 또 자전거 타고 출근해요? 버스가 더 편하지 않아요?\n남자: 자전거를 타면 시간도 비슷하고 운동도 돼서 좋아요. 돈도 안 들고 공기도 안 나빠지니까 저는 자전거가 제일 좋은 것 같아요.","options":["자전거는 버스보다 빠르다.","출근할 때는 버스가 편하다.","자전거로 출근하면 좋은 점이 많다.","운동을 하려면 일찍 일어나야 한다."],"answer":3,"explain":"🎧 Перечисляет плюсы велосипеда: то же время, спорт, бесплатно, не загрязняет воздух.<br>✅ <b>③ 자전거로 출근하면 좋은 점이 많다.</b> (у поездок на велосипеде много плюсов).<br>✖️ ① время «비슷하다» (примерно равно), ② наоборот — выбирает велосипед, ④ про ранний подъём не говорил."},{"n":13,"points":2,"instr":"Прослушайте диалог и выберите, где он происходит.","script":"여자: 어떻게 오셨어요?\n남자: 어제부터 목이 아프고 열도 좀 나요. 약을 먹었는데 낫지 않아서요.\n여자: 그럼 입을 한번 벌려 보세요. 음, 감기네요. 제가 약을 처방해 드릴게요.","options":["약국","병원","식당","학교"],"answer":2,"explain":"🎧 Жалобы на боль в горле и температуру, врач осматривает горло и выписывает (처방) лекарство.<br>✅ <b>② 병원</b> (больница/поликлиника).<br>✖️ ① в аптеке лекарства продают, но не «выписывают» и не осматривают, ③ ресторан, ④ школа — не подходят."},{"n":14,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","script":"남자: 민지 씨, 이번 주 토요일에 우리 집에서 집들이를 하는데 올 수 있어요?\n여자: 토요일이요? 그날 약속이 있어서 좀 어려울 것 같은데요.\n남자:","options":["그럼 다음에 꼭 초대할게요.","집들이에 와 주셔서 고마워요.","토요일에 만나서 반가웠어요.","우리 집은 학교에서 가까워요."],"answer":1,"explain":"🎧 Женщина не сможет прийти в субботу → мужчина мягко переносит на потом.<br>✅ <b>① 그럼 다음에 꼭 초대할게요.</b> (тогда обязательно приглашу в следующий раз).<br>✖️ ② благодарность за приход (а она не придёт), ③ «был рад встрече» (встречи не было), ④ про расположение дома — не к месту."},{"n":15,"points":2,"instr":"Прослушайте объявление и выберите вариант, совпадающий с услышанным.","script":"여자: 시민 여러분, 안녕하십니까? 다음 주 월요일부터 도서관 일 층을 수리합니다. 그래서 한 달 동안 일 층은 이용할 수 없습니다. 이 층과 삼 층은 평소처럼 이용하실 수 있습니다. 불편을 드려 죄송합니다.","options":["도서관 전체를 한 달 동안 닫는다.","수리하는 동안 이 층은 이용할 수 없다.","일 층은 다음 주부터 이용할 수 없다.","도서관 수리는 일주일 동안 한다."],"answer":3,"explain":"🎧 «Со следующего понедельника ремонт 1-го этажа, месяц им пользоваться нельзя; 2-й и 3-й работают как обычно».<br>✅ <b>③ 일 층은 다음 주부터 이용할 수 없다.</b> (1-й этаж недоступен со следующей недели).<br>✖️ ① закрывают только 1-й этаж, ② 2-й работает, ④ ремонт длится месяц, а не неделю."}]
      },
      reading: {
        durationMin: 25, total: 30, label: '\uBAA8\uC758\uACE0\uC0AC 3\uAE09 \u00B7 \uC77D\uAE30',
        questions: [{"n":1,"points":2,"instr":"Выберите наиболее подходящее слово для пропуска ( ).","passage":"밥을 ( ) 이를 닦아요.","options":["먹어서","먹고","먹으면","먹지만"],"answer":2,"explain":"Последовательность действий «поесть, а потом…» передаётся через <b>-고</b>.<br>✅ <b>② 먹고</b> (поел и (потом) чищу зубы).<br>✖️ ① 먹어서 — причина/после (здесь не нужна причинность), ③ 먹으면 — «если», ④ 먹지만 — «но»."},{"n":2,"points":2,"instr":"Выберите наиболее подходящее слово для пропуска ( ).","passage":"시간이 ( ) 운동을 하려고 해요.","options":["있으면","있어서","있지만","있고"],"answer":1,"explain":"«Если будет время, собираюсь заняться спортом» — условие через <b>-(으)면</b>.<br>✅ <b>① 있으면</b> (если есть/будет время).<br>✖️ ② 있어서 «потому что есть», ③ 있지만 «но есть», ④ 있고 «есть и» — по смыслу не подходят."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"그 영화는 <u>슬퍼서</u> 눈물이 났어요.","options":["슬프니까","슬프지만","슬프거나","슬프려고"],"answer":1,"explain":"<b>-아/어서</b> и <b>-(으)니까</b> здесь оба выражают причину «потому что грустный».<br>✅ <b>① 슬프니까</b>.<br>✖️ ② 슬프지만 «хоть и грустный», ③ 슬프거나 «или грустный», ④ 슬프려고 «чтобы (быть) грустным»."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"한국어를 <u>배우려고</u> 학원에 다녀요.","options":["배우거나","배우기 위해","배우는 동안","배우는 대신"],"answer":2,"explain":"<b>-(으)려고</b> = «чтобы», цель. Близкое — <b>-기 위해</b>.<br>✅ <b>② 배우기 위해</b> (чтобы учить).<br>✖️ ① 배우거나 «или учить», ③ 배우는 동안 «пока учу», ④ 배우는 대신 «вместо того чтобы учить»."},{"n":5,"points":2,"instr":"Прочитайте и выберите, о чём этот текст.","passage":"깨끗한 공기, 맑은 물\n우리가 함께 지켜요","options":["환경 보호","교통 안전","건강 관리","시간 약속"],"answer":1,"explain":"«Чистый воздух, прозрачная вода — бережём вместе» — это про охрану природы.<br>✅ <b>① 환경 보호</b> (защита окружающей среды).<br>✖️ ② безопасность движения, ③ забота о здоровье, ④ пунктуальность — не о том."},{"n":6,"points":2,"instr":"Прочитайте и выберите, о чём этот текст.","passage":"한 잔에 2,000원\n따뜻한 커피와 함께 편안한 시간을 보내세요","options":["도서관","카페","병원","은행"],"answer":2,"explain":"«Чашка за 2000 вон, проведите время за тёплым кофе» — реклама кофейни.<br>✅ <b>② 카페</b> (кафе).<br>✖️ ① библиотека, ③ больница, ④ банк — не продают кофе «за чашку»."},{"n":7,"points":2,"instr":"Прочитайте объявление и выберите вариант, совпадающий с содержанием.","passage":"〈한국어 말하기 대회〉\n날짜: 6월 20일 토요일\n장소: 시민회관 2층\n참가비: 무료\n신청: 6월 15일까지 인터넷으로","options":["대회는 일요일에 열린다.","참가하려면 돈을 내야 한다.","인터넷으로 신청할 수 있다.","신청은 6월 20일까지 받는다."],"answer":3,"explain":"«Заявки — до 15 июня через интернет».<br>✅ <b>③ 인터넷으로 신청할 수 있다.</b> (можно подать заявку онлайн).<br>✖️ ① конкурс в субботу, ② участие бесплатное (무료), ④ заявки до 15-го, а не до 20-го."},{"n":8,"points":2,"instr":"Прочитайте и выберите вариант, совпадающий с содержанием.","passage":"저는 매일 아침 공원에서 운동을 합니다. 처음에는 삼십 분만 걸었는데 지금은 한 시간씩 뜁니다. 운동을 시작한 후에 몸이 더 건강해졌습니다.","options":["저는 저녁마다 운동을 한다.","저는 지금 삼십 분 동안 걷는다.","운동을 한 후에 건강해졌다.","저는 공원에서 자전거를 탄다."],"answer":3,"explain":"«После того как начал заниматься, стал здоровее».<br>✅ <b>③ 운동을 한 후에 건강해졌다.</b><br>✖️ ① по утрам, ② сейчас бегает час, а не идёт 30 минут, ④ про велосипед не сказано."},{"n":9,"points":2,"instr":"Прочитайте и выберите вариант, совпадающий с содержанием.","passage":"우리 회사는 다음 주 금요일에 체육대회를 합니다. 모든 직원이 참가하며, 점심은 회사에서 준비합니다. 운동하기 편한 옷을 입고 오시기 바랍니다.","options":["체육대회는 이번 주에 한다.","직원들은 점심을 직접 가져와야 한다.","편한 옷을 입고 가는 것이 좋다.","체육대회에 참가하지 않아도 된다."],"answer":3,"explain":"«Приходите в удобной для спорта одежде».<br>✅ <b>③ 편한 옷을 입고 가는 것이 좋다.</b><br>✖️ ① в следующую пятницу, ② обед готовит компания, ④ участвуют все сотрудники."},{"n":10,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 그래서 어제 서점에 가서 책을 한 권 샀다.\n(나) 나는 요즘 한국 역사에 관심이 많다.\n(다) 집에 와서 그 책을 읽으니 정말 재미있었다.\n(라) 하지만 역사에 대해 잘 몰라서 책을 읽기로 했다.","options":["(나)-(라)-(가)-(다)","(나)-(가)-(다)-(라)","(라)-(나)-(가)-(다)","(라)-(가)-(나)-(다)"],"answer":1,"explain":"Логика: интерес к истории (나) → но плохо знаю, решил читать (라) → поэтому купил книгу (가) → дома прочитал, понравилось (다).<br>✅ <b>① (나)-(라)-(가)-(다)</b>. Начинать надо с (나): только там тема без связок «그래서/하지만»."},{"n":11,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 친구가 약을 사다 주고 죽도 만들어 주었다.\n(나) 지난주에 감기에 심하게 걸렸다.\n(다) 친구 덕분에 감기가 빨리 나았다.\n(라) 너무 아파서 친구에게 전화를 했다.","options":["(나)-(라)-(가)-(다)","(나)-(가)-(라)-(다)","(라)-(나)-(다)-(가)","(라)-(가)-(나)-(다)"],"answer":1,"explain":"Логика: сильно простыл (나) → было плохо, позвонил другу (라) → друг купил лекарство и сварил кашу (가) → благодаря другу быстро выздоровел (다).<br>✅ <b>① (나)-(라)-(가)-(다)</b>."},{"n":12,"points":2,"instr":"Прочитайте и выберите подходящее содержание для пропуска ( ).","passage":"요즘 많은 사람들이 반려동물을 키운다. 반려동물과 함께 살면 ( ). 강아지나 고양이와 시간을 보내면 외롭지 않고 스트레스도 줄어들기 때문이다.","options":["돈이 많이 든다","마음이 편안해진다","집이 좁아진다","시간이 부족해진다"],"answer":2,"explain":"Дальше объясняется: «не одиноко и стресс уменьшается» → значит на душе спокойнее.<br>✅ <b>② 마음이 편안해진다</b> (на душе становится спокойно).<br>✖️ ① деньги, ③ тесно в доме, ④ нехватка времени — это минусы, а пропуск требует плюса (по причине после)."},{"n":13,"points":2,"instr":"Прочитайте и выберите подходящее содержание для пропуска ( ).","passage":"책을 많이 읽으면 좋은 점이 많다. 우선 새로운 지식을 얻을 수 있다. 또한 다른 사람의 생각을 이해하게 되어 ( ). 그래서 어릴 때부터 책 읽는 습관을 기르는 것이 좋다.","options":["잠이 잘 온다","마음이 넓어진다","눈이 나빠진다","시간이 많이 든다"],"answer":2,"explain":"«Начинаешь понимать мысли других» → расширяется кругозор, душа становится «шире».<br>✅ <b>② 마음이 넓어진다</b> (становишься более широких взглядов).<br>✖️ ① про сон, ③ портится зрение, ④ уходит много времени — это не «좋은 점» (плюс)."},{"n":14,"points":2,"instr":"Прочитайте и выберите тему текста.","passage":"건강을 지키려면 잠을 잘 자는 것이 중요하다. 사람은 잠을 자는 동안 몸과 마음이 쉬게 된다. 잠이 부족하면 쉽게 피곤해지고 집중도 잘 안 된다. 그러므로 매일 충분히 자는 것이 좋다.","options":["잠을 적게 자야 일을 많이 한다.","충분한 잠은 건강에 중요하다.","피곤할 때는 운동을 해야 한다.","집중하려면 커피를 마셔야 한다."],"answer":2,"explain":"Главная мысль (그러므로…): «лучше каждый день высыпаться».<br>✅ <b>② 충분한 잠은 건강에 중요하다.</b> (достаточный сон важен для здоровья).<br>✖️ ① противоположно, ③ про спорт не сказано, ④ про кофе не сказано."},{"n":15,"points":2,"instr":"Прочитайте и выберите тему текста.","passage":"요즘은 휴대 전화로 모든 것을 할 수 있다. 길을 찾고, 물건을 사고, 친구와 이야기도 한다. 하지만 휴대 전화만 보다 보면 가족과 대화할 시간이 줄어든다. 그러므로 휴대 전화를 사용하는 시간을 스스로 정해 두는 것이 좋다.","options":["휴대 전화로 물건을 사면 편리하다.","휴대 전화 사용 시간을 조절하는 것이 좋다.","가족과는 전화로 자주 연락해야 한다.","휴대 전화는 길을 찾을 때 유용하다."],"answer":2,"explain":"Вывод (그러므로…): «лучше самому ограничивать время за телефоном».<br>✅ <b>② 휴대 전화 사용 시간을 조절하는 것이 좋다.</b><br>✖️ ① и ④ — лишь примеры удобства, ③ про звонки семье не сказано."}]
      },
      writing: {"durationMin":30,"label":"모의고사 3급 · 쓰기 (51~52)","tasks":[{"n":51,"points":10,"korInstr":"다음 글을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰십시오.","instr":"Впишите в ㉠ и ㉡ подходящие законченные выражения (стиль текста — вежливый -아요/어요).","passage":"민수 씨, 이번 주 토요일이 제 생일이에요. 그래서 우리 집에서 작은 생일 파티를 ( ㉠ ). 시간이 ( ㉡ ) 꼭 오세요. 맛있는 음식을 많이 준비할게요.","blanks":[{"slot":"㉠","model":"하려고 해요 / 할 거예요 / 열려고 해요"},{"slot":"㉡","model":"있으면 / 괜찮으면 / 되면"}]},{"n":52,"points":10,"korInstr":"다음 글을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰십시오.","instr":"Впишите в ㉠ и ㉡ подходящие законченные выражения (письменный стиль -ㄴ다/-는다).","passage":"운동은 건강에 좋다. 그러나 운동을 너무 ( ㉠ ) 오히려 몸에 좋지 않다. 그러므로 운동은 자신의 몸 상태에 ( ㉡ ) 것이 좋다.","blanks":[{"slot":"㉠","model":"많이 하면 / 무리하게 하면"},{"slot":"㉡","model":"맞게 하는 / 맞춰서 하는"}]}]}
    },
    /* EBS-1 */
    1: {
      no: "EBS<br><b>제1회</b>",
      mock: true,
      listening: {"durationMin":60,"total":100,"label":"EBS 모의고사 제1회 · 듣기 (1~50)","questions":[{"n":1,"points":2,"image":"assets/topik2/exams/img/ebs1-l-q1.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":4,"script":"여자: 이 소포를 보내고 싶은데요.\n남자: 무게를 먼저 재야 하니까 저울 위에 올려 주세요.\n여자: 네, 그럼 오늘 보내면 얼마나 걸릴까요?","explain":"🎧 여자: 이 소포를 보내고 싶은데요.<br>남자: 무게를 먼저 재야 하니까 저울 위에 올려 주세요.<br>여자: 네, 그럼 오늘 보내면 얼마나 걸릴까요?<br><br>На почте: женщина хочет отправить посылку, сотрудник просит положить её на весы.<br>✅ <b>④</b> — у почтовой стойки клиентка отправляет посылку, рядом весы.<br>✖️ ① клиентка только держит коробку, ② сцена в банке, ③ упаковка коробок на складе.<br>🧩 소포 = «посылка»; 저울 = «весы»; 무게를 재다 = «взвешивать»."},{"n":2,"points":2,"image":"assets/topik2/exams/img/ebs1-l-q2.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":3,"script":"남자: 이 상자는 어디에 놓을까요?\n여자: 여기 책상 옆에 두면 될 것 같아요. 무거운데 괜찮으세요?\n남자: 네, 괜찮아요. 이쪽 거의 다 정리됐어요.","explain":"🎧 남자: 이 상자는 어디에 놓을까요?<br>여자: 여기 책상 옆에 두면 될 것 같아요. 무거운데 괜찮으세요?<br>남자: 네, 괜찮아요. 이쪽 거의 다 정리됐어요.<br><br>Переезд/обустройство офиса: мужчина несёт коробку, женщина показывает, куда поставить — у стола.<br>✅ <b>③</b> — в офисе мужчина с коробкой, женщина у стола, вещи раскладывают.<br>✖️ ① переносят телевизор в гостиной, ② приём посылки у стойки, ④ погрузка коробок в грузовик.<br>🧩 상자 = «коробка»; 놓다 = «класть, ставить»; 정리되다 = «быть прибранным»."},{"n":3,"points":2,"image":"assets/topik2/exams/img/ebs1-l-q3.png","instr":"Прослушайте и выберите подходящий график.","options":["①","②","③","④"],"answer":1,"script":"남자: 여러분, 여름밤 편히 잠을 자고 계신가요? 최근 열대야 현상으로 잠을 못 이루는 분들이 많은데요. 기상청에 따르면, 2021년부터 열대야 발생 일수가 해마다 늘어나고 있는 것으로 나타났습니다. 열대야를 이겨 내는 방법으로는 미지근한 물로 샤워하기가 가장 많았으며, 가벼운 운동 그리고 시원한 침구 사용하기가 그 뒤를 이었습니다.","explain":"🎧 남자: 여러분, 여름밤 편히 잠을 자고 계신가요? 최근 열대야 현상으로 잠을 못 이루는 분들이 많은데요. 기상청에 따르면, 2021년부터 열대야 발생 일수가 해마다 늘어나고 있는 것으로 나타났습니다. 열대야를 이겨 내는 방법으로는 '미지근한 물로 샤워하기'가 가장 많았으며 '가벼운 운동' 그리고 '시원한 침구 사용하기'가 그 뒤를 이었습니다.<br><br>Новости: число «тропических ночей» (열대야) растёт с 2021 года год от года. Способы пережить жару: 1) тёплый душ, 2) лёгкая зарядка, 3) прохладное постельное бельё.<br>✅ <b>①</b> — линейный график со стабильным ежегодным ростом числа тропических ночей.<br>✖️ ② график сначала падает (2022), потом растёт — не «каждый год растёт», ③④ это диаграммы способов с неверным порядком пунктов.<br>🧩 열대야 = «тропическая ночь»; 기상청 = «метеослужба»; 발생 일수 = «число дней»."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["나도 바지 하나 사야겠어.","특별한 날에 입으면 좋지.","그럼 빨리 가서 바꿔야지.","그럼 다른 색으로 골라 봐."],"answer":3,"script":"여자: 어제 산 바지 왜 안 입었어?\n남자: 항상 입던 사이즈라 괜찮을 줄 알았는데 집에서 입어 보니까 좀 작더라고.","explain":"🎧 여자: 어제 산 바지 왜 안 입었어?<br>남자: 항상 입던 사이즈라 괜찮을 줄 알았는데 집에서 입어 보니까 좀 작더라고.<br><br>Купленные вчера брюки оказались маловаты → совет обменять.<br>✅ <b>③ 그럼 빨리 가서 바꿔야지.</b> (тогда скорее иди и поменяй).<br>✖️ ① «и мне надо купить брюки», ② «хорошо надевать по особым дням», ④ «тогда выбери другой цвет» (проблема в размере, не в цвете).<br>🧩 작다 = «маловат»; 바꾸다 = «обменять»."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그래요? 저도 책 있는 거 좋아해요.","정말요? 그런 일이 있는지 몰랐어요.","그래요? 그럼 다음 모임은 거기서 해요.","정말요? 그럼 날짜를 조금 미뤄야겠네요."],"answer":3,"script":"여자: 다음 주 동아리 모임 어디에서 할까요?\n남자: 학교 앞에 새로 생긴 북카페는 어때요? 거기 조용하고 좋던데요.","explain":"🎧 여자: 다음 주 동아리 모임 어디에서 할까요?<br>남자: 학교 앞에 새로 생긴 북카페는 어때요? 거기 조용하고 좋던데요.<br><br>Где провести встречу кружка → мужчина предлагает новое тихое книжное кафе у школы.<br>✅ <b>③ 그래요? 그럼 다음 모임은 거기서 해요.</b> (тогда проведём следующую встречу там).<br>✖️ ① «я тоже люблю, когда есть книги», ② «не знала, что такое было», ④ «тогда перенесём дату» — не отвечают на предложение места.<br>🧩 동아리 = «кружок, клуб»; 북카페 = «книжное кафе»."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["우선 낮에 표가 있는지 볼게.","벌써 사람들이 입장한 것 같아.","그럼 오후 6시 표로 하면 되겠다.","아직 영화가 언제 개봉할지 모른대."],"answer":3,"script":"여자: 우리 토요일에 영화 보기로 했잖아. 몇 시쯤 만날까?\n남자: 난 낮에 일이 좀 있어서 저녁이 좋을 것 같은데.","explain":"🎧 여자: 우리 토요일에 영화 보기로 했잖아. 몇 시쯤 만날까?<br>남자: 난 낮에 일이 좀 있어서 저녁이 좋을 것 같은데.<br><br>В субботу идут в кино; мужчина занят днём, удобнее вечером.<br>✅ <b>③ 그럼 오후 6시 표로 하면 되겠다.</b> (тогда возьмём билет на 18:00).<br>✖️ ① «сначала посмотрю, есть ли дневные билеты» (он хочет вечер), ② «кажется, люди уже вошли», ④ «ещё неизвестно, когда выйдет фильм» — уже решили смотреть.<br>🧩 표 = «билет»; 저녁 = «вечер»."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["우리 축하 파티를 해야겠어요.","자격증이 있어야 할 수 있어요.","이번 시험이 정말 쉬웠나 봐요.","다음에는 좋은 결과가 있을 거예요."],"answer":4,"script":"여자: 전기 기사 자격증 시험 본 거, 결과 나왔어요?\n남자: 아, 그거 떨어졌어요. 지금부터 다음 시험 준비하려고요.","explain":"🎧 여자: 전기 기사 자격증 시험 본 거, 결과 나왔어요?<br>남자: 아, 그거 떨어졌어요. 지금부터 다음 시험 준비하려고요.<br><br>Мужчина не сдал экзамен на сертификат электрика, готовится к следующему → слова поддержки.<br>✅ <b>④ 다음에는 좋은 결과가 있을 거예요.</b> (в следующий раз всё получится).<br>✖️ ① «устроим праздник» (он провалил), ② «нужен сертификат, чтобы этим заниматься», ③ «экзамен был очень лёгким» — неуместно.<br>🧩 자격증 = «сертификат»; 떨어지다 = «провалить (экзамен)»."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["두리공원 정문 앞에 있는 가로등이에요.","공원 앞 가로등 수를 좀 더 늘려야겠어요.","가로등이 새로 생겨서 거리가 환해졌네요.","가로등을 설치하는 데 시간이 많이 걸려요."],"answer":1,"script":"남자: 가로등이 고장 나서 신고하려고 합니다.\n여자: 네, 제보해 주셔서 감사합니다. 위치를 정확히 말씀해 주시면 빠르게 처리하겠습니다.","explain":"🎧 남자: 가로등이 고장 나서 신고하려고 합니다.<br>여자: 네, 제보해 주셔서 감사합니다. 위치를 정확히 말씀해 주시면 빠르게 처리하겠습니다.<br><br>Мужчина сообщает о сломанном фонаре; оператор просит точное место → он называет адрес.<br>✅ <b>① 두리공원 정문 앞에 있는 가로등이에요.</b> (это фонарь у главного входа в парк Тури).<br>✖️ ② «надо увеличить число фонарей», ③ «новый фонарь осветил улицу», ④ «установка фонарей занимает много времени» — не дают местоположение.<br>🧩 가로등 = «уличный фонарь»; 신고하다 = «сообщать»; 위치 = «местоположение»."},{"n":9,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["밥값을 계산한다.","화장실에 들른다.","식당에 전화한다.","식당으로 뛰어간다."],"answer":3,"script":"남자: 어? 내 휴대폰이 어디 있지?\n여자: 없어? 아까 식당 화장실에 두고 온 거 아니야? 계산하고 나올 때 들렀잖아.\n남자: 아, 그런가 봐. 요 앞이니까 금방 다녀올게.\n여자: 내가 식당에 전화해 볼게. 잠깐 기다려 봐.","explain":"🎧 남자: 어? 내 휴대폰이 어디 있지?<br>여자: 없어? 아까 식당 화장실에 두고 온 거 아니야? 계산하고 나올 때 들렀잖아.<br>남자: 아, 그런가 봐. 요 앞이니까 금방 다녀올게.<br>여자: 내가 식당에 전화해 볼게. 잠깐 기다려 봐.<br><br>Телефон забыт в туалете ресторана. Мужчина хочет сходить сам, но женщина говорит, что позвонит.<br>✅ <b>③ 식당에 전화한다.</b> — «내가 식당에 전화해 볼게».<br>✖️ ① оплатить счёт (уже оплачен), ② зайти в туалет, ④ бежать в ресторан — это собирался сделать мужчина.<br>🧩 휴대폰 = «телефон»; 들르다 = «заглянуть»."},{"n":10,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["그릇을 꺼낸다.","그릇을 분류한다.","그릇을 상자에 담는다.","그릇을 현관 앞에 둔다."],"answer":2,"script":"여자: 오래된 그릇 좀 정리해야겠어요. 너무 많네요.\n남자: 제가 여기 있는 그릇들을 다 꺼낼게요. 당신이 쓸 것과 버릴 걸 나눠 주세요.\n여자: 네, 제가 분류해 놓을게요. 그럼 버릴 건 저 상자에 담아서 현관 앞에 놔 주세요.\n남자: 알겠어요. 바로 시작해 볼까요?","explain":"🎧 여자: 오래된 그릇 좀 정리해야겠어요. 너무 많네요.<br>남자: 제가 여기 있는 그릇들을 다 꺼낼게요. 당신이 쓸 것과 버릴 걸 나눠 주세요.<br>여자: 네, 제가 분류해 놓을게요. 그럼 버릴 건 저 상자에 담아서 현관 앞에 놔 주세요.<br>남자: 알겠어요. 바로 시작해 볼까요?<br><br>Разбирают старую посуду. Мужчина достаёт, женщина берётся рассортировать на нужное/ненужное.<br>✅ <b>② 그릇을 분류한다.</b> — «제가 분류해 놓을게요».<br>✖️ ① достаёт посуду — это мужчина, ③ складывает в коробку / ④ ставит у входа — это мужчина с ненужным.<br>🧩 그릇 = «посуда»; 분류하다 = «сортировать»."},{"n":11,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["도서관에 간다.","점심을 먹는다.","자료를 검토한다.","참고 자료를 찾는다."],"answer":1,"script":"남자: 발표 준비 다 됐어? 자료 정리하는 게 쉽지 않네.\n여자: 나도 아직이야. 지금 자료 찾으러 도서관에 가려던 참이야.\n남자: 그래? 나도 같이 가도 돼? 끝나고 점심도 같이 먹자.\n여자: 그래. 자료도 같이 보고, 서로 도와 가면서 하자.","explain":"🎧 남자: 발표 준비 다 됐어? 자료 정리하는 게 쉽지 않네.<br>여자: 나도 아직이야. 지금 자료 찾으러 도서관에 가려던 참이야.<br>남자: 그래? 나도 같이 가도 돼? 끝나고 점심도 같이 먹자.<br>여자: 그래. 자료도 같이 보고, 서로 도와 가면서 하자.<br><br>Готовят доклад. Женщина прямо сейчас собирается в библиотеку за материалами.<br>✅ <b>① 도서관에 간다.</b> — «지금 자료 찾으러 도서관에 가려던 참이야».<br>✖️ ② обед (после), ③ просмотреть материалы (позже вместе), ④ искать справочные материалы — это цель похода, но ближайшее действие — идти в библиотеку.<br>🧩 발표 = «доклад»; ~려던 참이다 = «как раз собираться сделать»."},{"n":12,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["설문지를 복사한다.","설문지를 나누어 준다.","회의 자료를 정리한다.","회의장 상태를 점검한다."],"answer":3,"script":"여자: 회의가 끝날 때 이 설문지를 나눠 드려야 하죠?\n남자: 네, 인원 수에 맞게 복사해 놨지요?\n여자: 아니요, 아직이요. 아직 시간 있으니까 회의 자료부터 정리해 놓고 복사하겠습니다.\n남자: 고마워요. 전 회의장 상태를 한번 확인할게요.","explain":"🎧 여자: 회의가 끝날 때 이 설문지를 나눠 드려야 하죠?<br>남자: 네, 인원 수에 맞게 복사해 놨지요?<br>여자: 아니요, 아직이요. 아직 시간 있으니까 회의 자료부터 정리해 놓고 복사하겠습니다.<br>남자: 고마워요. 전 회의장 상태를 한번 확인할게요.<br><br>Подготовка к собранию. Женщина сначала разберёт материалы собрания, потом сделает копии.<br>✅ <b>③ 회의 자료를 정리한다.</b> — «회의 자료부터 정리해 놓고».<br>✖️ ① копировать анкеты (после), ② раздавать анкеты (в конце собрания), ④ проверить зал — это делает мужчина.<br>🧩 설문지 = «анкета»; 회의장 = «зал собраний»."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자는 혼자 등산을 가려고 한다.","남자는 마라톤 대회에 처음 나간다.","여자는 주말에 민아 씨를 만날 것이다.","남자의 형은 마라톤 대회에 여러 번 참가했다."],"answer":3,"script":"여자: 이번 주말에 민아 씨랑 등산 가려고 하는데 같이 갈래요?\n남자: 아, 아쉽네요. 이번 주말에 마라톤 대회가 있어서 못 갈 것 같아요.\n여자: 우와, 대회에 또 나가는 거예요?\n남자: 네, 이번엔 제 형이 처음 대회에 참여하게 돼서 저도 같이 뛰기로 했어요.","explain":"🎧 여자: 이번 주말에 민아 씨랑 등산 가려고 하는데 같이 갈래요?<br>남자: 아, 아쉽네요. 이번 주말에 마라톤 대회가 있어서 못 갈 것 같아요.<br>여자: 우와, 대회에 또 나가는 거예요?<br>남자: 네, 이번엔 제 형이 처음 대회에 참여하게 돼서 저도 같이 뛰기로 했어요.<br><br>Женщина в выходные идёт в поход с Мина, зовёт мужчину; он не может — марафон; на марафоне впервые бежит его старший брат.<br>✅ <b>③ Женщина в выходные встретится с Мина.</b> — «민아 씨랑 등산 가려고».<br>✖️ ① идёт в поход одна (нет, с Мина), ② у мужчины первый марафон (он бежит «снова», впервые — брат), ④ брат участвовал много раз (наоборот, впервые).<br>🧩 등산 = «поход в горы»; 마라톤 대회 = «марафон»."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["소방 점검은 오전에 실시한다.","소방 점검에 대한 사전 안내가 없었다.","소방 점검을 할 때 조명이 모두 꺼진다.","점검이 모두 끝나면 안내 방송을 할 것이다."],"answer":4,"script":"여자: 아파트 주민 여러분께 안내 말씀드립니다. 사전에 안내해 드린 대로, 잠시 후 오후 3시부터 소방 설비를 점검합니다. 점검 중에는 화재 경보음이 울리거나 일부 조명이 꺼질 수 있으나 실제 화재 상황은 아니니 놀라지 마시기 바랍니다. 점검이 완료되면 다시 안내 방송을 해 드리겠습니다.","explain":"🎧 여자(안내방송): 아파트 주민 여러분께 안내 말씀드립니다. 사전에 안내해 드린 대로, 잠시 후 오후 3시부터 소방 설비를 점검합니다. 점검 중에는 화재 경보음이 울리거나 일부 조명이 꺼질 수 있으나 실제 화재 상황은 아니니 놀라지 마시기 바랍니다. 점검이 완료되면 다시 안내 방송을 해 드리겠습니다.<br><br>Объявление в доме: с 15:00 проверка противопожарного оборудования; могут звучать сигналы и гаснуть часть света.<br>✅ <b>④ По завершении проверки сделают новое объявление.</b> — «점검이 완료되면 다시 안내 방송».<br>✖️ ① проверка утром (нет, 오후 3시 — днём), ② не было предупреждения (было: «사전에 안내해 드린 대로»), ③ гаснет весь свет (только «일부 조명» — часть).<br>🧩 소방 점검 = «противопожарная проверка»; 사전 안내 = «предварительное оповещение»."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 대회는 시민들의 참가율이 저조했다.","이 대회는 한국인만 참여할 수 있는 프로그램이다.","이 대회는 서로 경쟁하지 않고 경기를 즐길 수 있다.","이 대회에서는 수영, 자전거, 걷기 종목에 참여할 수 있다."],"answer":3,"script":"남자: 오늘 인주시청이 개최한 쉬엄쉬엄 인주 3종 축제가 이만 명 이상의 많은 시민들이 참가한 가운데 성공적으로 마무리되었습니다. 이 축제는 각자의 체력 수준에 따라 나만의 속도와 방식으로 수영, 자전거, 달리기 세 가지 종목에 참여하며 즐길 수 있는 프로그램인데요. 특히 외국인들도 축제를 마음껏 즐길 수 있도록 행사장 곳곳에서 외국어 서비스를 제공했습니다. 참가자 모두 경쟁 없이 운동을 즐길 수 있도록 했습니다.","explain":"🎧 남자: 오늘 인주시청이 개최한 '쉬엄쉬엄 인주 3종 축제'가 이만 명 이상의 많은 시민들이 참가한 가운데 성공적으로 마무리되었습니다. 이 축제는 각자의 체력 수준에 따라 나만의 속도와 방식으로 수영, 자전거, 달리기 세 가지 종목에 참여하며 즐길 수 있는 프로그램인데요. 특히 외국인들도 마음껏 즐길 수 있도록 외국어 서비스를 제공했습니다. 참가자 모두 경쟁 없이 운동을 즐길 수 있도록 했습니다.<br><br>Фестиваль «троеборья» в г. Инджу: более 20 000 участников, в своём темпе, без соревнования.<br>✅ <b>③ На этом мероприятии можно наслаждаться без соперничества друг с другом.</b> — «경쟁 없이 운동을 즐길 수 있도록».<br>✖️ ① низкая явка (наоборот, 이만 명 이상), ② только для корейцев (были и иностранцы), ④ виды — плавание, велосипед, <b>ходьба</b> (на самом деле <b>бег</b> 달리기, а не 걷기).<br>🧩 축제 = «фестиваль»; 경쟁 = «соревнование»; 종목 = «вид (спорта)»."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 프로그램은 도시 아이들을 위한 것이다.","이 프로그램에서는 일 년 동안 집을 빌려준다.","도시 아이들을 위한 농촌 프로그램이 부족하다.","도시 아이들은 부모와 함께 집을 수리해야 한다."],"answer":1,"script":"남자: 이번에 도시 아이들이 농촌 체험을 해 볼 수 있는 프로그램을 만드셨다고요? 어떤 프로그램인지 소개 좀 부탁드리겠습니다.\n여자: 네, 도시 아이들이 농촌에서 한 달 동안 살아 보는 프로그램인데요. 비어 있는 농촌 집을 수리해서, 신청한 가족이 한 달 동안 실제로 지낼 수 있도록 집을 빌려드리고요. 물고기 잡기, 고구마 캐기, 옥수수 따기 등 농촌 체험을 함께 해 볼 수 있도록 다양한 프로그램을 준비했습니다.","explain":"🎧 남자: 이번에 도시 아이들이 농촌 체험을 해 볼 수 있는 프로그램을 만드셨다고요? 어떤 프로그램인지 소개 좀 부탁드리겠습니다.<br>여자: 네, 도시 아이들이 농촌에서 한 달 동안 살아 보는 프로그램인데요. 비어 있는 농촌 집을 수리해서, 신청한 가족이 한 달 동안 실제로 지낼 수 있도록 집을 빌려드리고요. 물고기 잡기, 고구마 캐기, 옥수수 따기 등 농촌 체험을 함께 해 볼 수 있도록 다양한 프로그램을 준비했습니다.<br><br>Программа: городские дети на месяц едут «пожить» в деревне; организаторы ремонтируют пустые сельские дома и сдают семьям.<br>✅ <b>① Эта программа — для городских детей.</b> — «도시 아이들이 농촌 체험을 해 볼 수 있는 프로그램».<br>✖️ ② дом дают на год (на самом деле «한 달» — на месяц), ③ таких программ не хватает (не сказано), ④ дети с родителями сами ремонтируют дом (ремонтируют организаторы).<br>🧩 농촌 체험 = «сельский опыт»; 수리하다 = «ремонтировать»; 빌려주다 = «сдавать, давать в пользование»."},{"n":17,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["잘 쉬어야 할 일을 더 잘할 수 있다.","평소 드라마 보는 시간을 줄여야 한다.","시간을 잘 관리하려면 연습이 필요하다.","숙제를 다 한 후에 드라마 보는 것이 좋다."],"answer":4,"script":"남자: 민아야, 숙제 다 했어?\n여자: 아직 시간 많으니까 이 드라마만 보고 할게요.\n남자: 할 일을 먼저 해 놓고 여유 있게 보는 게 더 좋지 않을까?","explain":"🎧 남자: 민아야, 숙제 다 했어?<br>여자: 아직 시간 많으니까 이 드라마만 보고 할게요.<br>남자: 할 일을 먼저 해 놓고 여유 있게 보는 게 더 좋지 않을까?<br><br>Дочь хочет доделать уроки после сериала; отец советует сначала закончить дела, а потом смотреть спокойно.<br>✅ <b>④ Сериал лучше смотреть после того, как доделаны уроки.</b> — «할 일을 먼저 해 놓고».<br>✖️ ① «хорошо отдохнув, лучше справишься с делами», ② «надо сократить время на сериалы», ③ «для тайм-менеджмента нужна практика» — не главная мысль.<br>🧩 할 일 = «дела, что нужно сделать»; 여유 있게 = «без спешки»."},{"n":18,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["발표 준비는 미리 하는 것이 좋다.","목소리가 커야 발표 내용이 잘 전달된다.","앞자리에 앉아야 발표를 잘 들을 수 있다.","연습을 많이 해야 발표할 때 긴장하지 않는다."],"answer":2,"script":"남자: 민아야, 발표할 때 좀 더 크게 하지 그랬어. 뒤에서는 잘 안 들리더라고.\n여자: 그래? 너무 긴장해서 목소리가 작아졌나 봐.\n남자: 너 정말 열심히 준비했는데, 발표 내용이 잘 안 들려서 좀 안타까웠어.","explain":"🎧 남자: 민아야, 발표할 때 좀 더 크게 하지 그랬어. 뒤에서는 잘 안 들리더라고.<br>여자: 그래? 너무 긴장해서 목소리가 작아졌나 봐.<br>남자: 너 정말 열심히 준비했는데, 발표 내용이 잘 안 들려서 좀 안타까웠어.<br><br>Доклад был хорошо подготовлен, но сзади его не было слышно из-за тихого голоса.<br>✅ <b>② Чтобы содержание доклада дошло, нужен громкий голос.</b><br>✖️ ① «к докладу лучше готовиться заранее», ③ «надо сидеть впереди, чтобы хорошо слышать», ④ «много репетируй — не будешь волноваться» — не главная мысль.<br>🧩 발표 = «доклад, презентация»; 전달되다 = «доноситься, передаваться»."},{"n":19,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["단어를 많이 쓰면 읽기 실력에 도움이 된다.","외국어를 잘하려면 단어를 많이 외워야 한다.","친구와 함께 단어를 공부하면 더 효과적이다.","단어를 소리 내어 읽으면 더 쉽게 외울 수 있다."],"answer":4,"script":"여자: 너 영어 시험 준비 잘하고 있어? 난 단어 외우는 게 너무 힘들어.\n남자: 다들 그렇지. 근데 나는 소리 내서 읽으면 더 잘 외워지더라.\n여자: 아, 그래? 난 계속 쓰면서 외웠는데, 나도 너처럼 읽으면서 해 볼까?\n남자: 한번 해 봐. 훨씬 기억에 잘 남을 거야.","explain":"🎧 여자: 너 영어 시험 준비 잘하고 있어? 난 단어 외우는 게 너무 힘들어.<br>남자: 다들 그렇지. 근데 나는 소리 내서 읽으면 더 잘 외워지더라.<br>여자: 아, 그래? 난 계속 쓰면서 외웠는데, 나도 너처럼 읽으면서 해 볼까?<br>남자: 한번 해 봐. 훨씬 기억에 잘 남을 거야.<br><br>Мужчина советует заучивать слова, читая их вслух — так лучше запоминается.<br>✅ <b>④ Если читать слова вслух, их легче запомнить.</b> — «소리 내서 읽으면 더 잘 외워지더라».<br>✖️ ① «много писать слова помогает чтению», ② «чтобы знать язык, надо много зубрить», ③ «учить слова с другом эффективнее» — не главная мысль.<br>🧩 소리 내어 읽다 = «читать вслух»; 외워지다 = «запоминаться»."},{"n":20,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["설명이 자세한 요리책이 인기가 많다.","쉽게 들고 다닐 수 있는 요리책이 좋다.","요리책은 누구나 쉽게 따라 할 수 있어야 한다.","요리를 처음 배울 때는 요리책을 참고하는 것이 좋다."],"answer":3,"script":"여자: 이번에 새로 내신 요리책은 이전 책들과 어떤 점이 가장 다른가요?\n남자: 예전 요리책들은 대부분 요리를 좀 해 본 사람들을 대상으로 한 거였어요. 그래서 처음 요리하는 사람들에게는 따라 하기 어려운 부분이 많았죠. 저는 누구든지 쉽게 요리할 수 있도록 했어요. 설명은 간단하게 하고 과정은 한눈에 볼 수 있도록 그림도 많이 넣었습니다.","explain":"🎧 여자: 이번에 새로 내신 요리책은 이전 책들과 어떤 점이 가장 다른가요?<br>남자: 예전 요리책들은 대부분 요리를 좀 해 본 사람들을 대상으로 한 거였어요. 그래서 처음 요리하는 사람들에게는 따라 하기 어려운 부분이 많았죠. 저는 누구든지 쉽게 요리할 수 있도록 했어요. 설명은 간단하게 하고 과정은 한눈에 볼 수 있도록 그림도 많이 넣었습니다.<br><br>Интервью: прежние кулинарные книги были для опытных; автор сделал так, чтобы готовить мог любой новичок (простые описания, много картинок).<br>✅ <b>③ Кулинарная книга должна быть такой, чтобы любой мог легко повторить.</b> — «누구든지 쉽게 요리할 수 있도록».<br>✖️ ① «популярны книги с подробными объяснениями», ② «удобно носить с собой», ④ «новичку лучше сверяться с книгой» — не главная мысль.<br>🧩 요리책 = «кулинарная книга»; 따라 하다 = «повторять за»; 한눈에 = «с одного взгляда»."},{"n":21,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["제품 포장의 색이 매출에 영향을 준다.","제품 포장지의 색을 바꾸지 않아도 된다.","주요 구매자가 좋아하는 색을 알아야 한다.","회사 로고 색과 제품 포장지 색이 같아야 한다."],"answer":2,"script":"여자: 오늘 회의에서 제품 포장 색깔을 좀 더 밝게 바꾸자는 의견이 나왔어요. 어떻게 생각하세요?\n남자: 저는 지금 색상이 우리 회사 이미지와 잘 맞는 것 같은데요. 회사 로고와 같은 색이잖아요.\n여자: 그래도 색깔이 조금 무겁게 느껴지지 않아요? 우리 제품은 10대 아이들이 주 대상이라 좀 더 가볍고 밝은 느낌이 있어야 할 것 같아요.\n남자: 10년 동안 같은 색인데 매출이 계속 상승했잖아요. 저는 변화의 필요성을 잘 못 느끼겠는데요.","explain":"🎧 여자: 오늘 회의에서 제품 포장 색깔을 좀 더 밝게 바꾸자는 의견이 나왔어요. 어떻게 생각하세요?<br>남자: 저는 지금 색상이 우리 회사 이미지와 잘 맞는 것 같은데요. 회사 로고와 같은 색이잖아요.<br>여자: 그래도 색깔이 조금 무겁게 느껴지지 않아요? 우리 제품은 10대 아이들이 주 대상이라 좀 더 가볍고 밝은 느낌이 있어야 할 것 같아요.<br>남자: 10년 동안 같은 색인데 매출이 계속 상승했잖아요. 저는 변화의 필요성을 잘 못 느끼겠는데요.<br><br>Женщина предлагает сделать упаковку ярче; мужчина считает, что нынешний цвет совпадает с логотипом и за 10 лет продажи только росли.<br>✅ <b>② Цвет упаковки можно не менять.</b> — «변화의 필요성을 잘 못 느끼겠는데요».<br>✖️ ① «цвет упаковки влияет на продажи» (это ближе к позиции женщины), ③ «надо знать любимый цвет покупателей», ④ «цвет логотипа и упаковки должны совпадать» — не центральная мысль мужчины.<br>🧩 포장지 = «упаковка»; 매출 = «выручка»; 변화의 필요성 = «необходимость перемен»."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 제품의 매출이 최근 감소하였다.","이 제품의 주요 구매자는 아이들이다.","최근에 이 제품의 포장지 색이 바뀌었다.","이 제품 포장지 색은 회사 로고의 색과 다르다."],"answer":2,"script":"여자: 오늘 회의에서 제품 포장 색깔을 좀 더 밝게 바꾸자는 의견이 나왔어요. 어떻게 생각하세요?\n남자: 저는 지금 색상이 우리 회사 이미지와 잘 맞는 것 같은데요. 회사 로고와 같은 색이잖아요.\n여자: 그래도 색깔이 조금 무겁게 느껴지지 않아요? 우리 제품은 10대 아이들이 주 대상이라 좀 더 가볍고 밝은 느낌이 있어야 할 것 같아요.\n남자: 10년 동안 같은 색인데 매출이 계속 상승했잖아요. 저는 변화의 필요성을 잘 못 느끼겠는데요.","explain":"🎧 (тот же диалог, что в вопросе 21).<br><br>✅ <b>② Основные покупатели этого товара — дети.</b> — «10대 아이들이 주 대상».<br>✖️ ① продажи недавно упали (наоборот, «계속 상승»), ③ цвет упаковки недавно изменили (нет: «10년 동안 같은 색»), ④ цвет упаковки отличается от логотипа (наоборот, «로고와 같은 색»).<br>🧩 주요 구매자 = «основные покупатели»; 10대 = «подростки»."},{"n":23,"points":2,"instr":"Прослушайте и определите, что делает мужчина.","options":["모바일 중고 거래 앱을 비판하고 있다.","모바일 중고 거래 앱 이용을 권유하고 있다.","모바일 중고 거래 앱에 대해 문의하고 있다.","모바일 중고 거래 앱의 불만 사항을 말하고 있다."],"answer":2,"script":"여자: 새 자전거 하나 사고 싶은데, 생각보다 비싸네요. 그래서 중고 자전거를 사 볼까 고민 중이에요.\n남자: 그럼 모바일 중고 거래 앱을 한번 이용해 보세요. 저도 가끔 쓰는데 자전거뿐만 아니라 전자기기, 옷 같은 것도 살 수 있어요.\n여자: 그래요? 근데 상태가 괜찮을까요? 온라인으로 거래하는 건 좀 불안해서요.\n남자: 요즘은 판매자들이 제품 상태를 자세히 올려놔서 믿을 만해요. 무엇보다 저렴하고 품질도 괜찮아요. 저도 노트북이랑 식탁을 그렇게 샀는데 지금까지 잘 쓰고 있어요.","explain":"🎧 여자: 새 자전거 하나 사고 싶은데, 생각보다 비싸네요. 그래서 중고 자전거를 사 볼까 고민 중이에요.<br>남자: 그럼 모바일 중고 거래 앱을 한번 이용해 보세요. 저도 가끔 쓰는데 자전거뿐만 아니라 전자기기, 옷 같은 것도 살 수 있어요.<br>여자: 그래요? 근데 상태가 괜찮을까요? 온라인으로 거래하는 건 좀 불안해서요.<br>남자: 요즘은 판매자들이 제품 상태를 자세히 올려놔서 믿을 만해요. 무엇보다 저렴하고 품질도 괜찮아요. 저도 노트북이랑 식탁을 그렇게 샀는데 지금까지 잘 쓰고 있어요.<br><br>Женщина думает купить б/у велосипед; мужчина советует приложение для сделок с подержанным и приводит свой опыт.<br>✅ <b>② Рекомендует пользоваться приложением для сделок с б/у.</b><br>✖️ ① критикует приложение, ③ спрашивает о приложении, ④ высказывает жалобы — мужчина, наоборот, советует.<br>🧩 중고 거래 = «сделки с подержанным»; 권유하다 = «советовать, рекомендовать»."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["모바일 중고 거래 앱의 제품은 질이 좋지 않다.","모바일 중고 거래 앱을 이용하는 것은 위험하다.","이 여자는 모바일 중고 거래 앱을 자주 이용한다.","이 남자는 모바일 중고 거래 앱에서 제품을 구매했다."],"answer":4,"script":"여자: 새 자전거 하나 사고 싶은데, 생각보다 비싸네요. 그래서 중고 자전거를 사 볼까 고민 중이에요.\n남자: 그럼 모바일 중고 거래 앱을 한번 이용해 보세요. 저도 가끔 쓰는데 자전거뿐만 아니라 전자기기, 옷 같은 것도 살 수 있어요.\n여자: 그래요? 근데 상태가 괜찮을까요? 온라인으로 거래하는 건 좀 불안해서요.\n남자: 요즘은 판매자들이 제품 상태를 자세히 올려놔서 믿을 만해요. 무엇보다 저렴하고 품질도 괜찮아요. 저도 노트북이랑 식탁을 그렇게 샀는데 지금까지 잘 쓰고 있어요.","explain":"🎧 (тот же диалог, что в вопросе 23).<br><br>✅ <b>④ Этот мужчина покупал товары в приложении для сделок с б/у.</b> — «저도 노트북이랑 식탁을 그렇게 샀는데».<br>✖️ ① товары плохого качества (наоборот, «품질도 괜찮아요»), ② пользоваться опасно (наоборот, «믿을 만해요»), ③ женщина часто пользуется (она только раздумывает и переживает).<br>🧩 구매하다 = «покупать»; 거래 = «сделка»."},{"n":25,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["장난감을 조심해서 사용해야 한다.","장난감 수리점이 더 많아져야 한다.","장난감 수리는 빨리하는 것이 중요하다.","장난감 수리 방법을 사람들에게 알려 줘야 한다."],"answer":2,"script":"여자: 20년 동안 아이들의 장난감을 고쳐 주고 계신데요. 어려운 점도 있으실 것 같습니다.\n남자: 사실 가장 어려운 점은 일손이 부족하다는 것입니다. 아이들 장난감을 빨리 고쳐 주고 싶지만 전국에서 장난감을 보내 주셔서 그게 쉽지가 않습니다. 부품을 구하기 어려운 경우도 자주 있고요. 장난감 수리점이 여기저기 더 많아진다면 아이들에게 조금 더 빨리 장난감을 돌려줄 수 있을 것입니다. 제가 장난감 고치는 방법을 영상으로 만들어 인터넷에 올리고 있는데 많은 분들이 이 일에 관심을 가져 주시면 좋겠습니다.","explain":"🎧 여자: 20년 동안 아이들의 장난감을 고쳐 주고 계신데요. 어려운 점도 있으실 것 같습니다.<br>남자: 사실 가장 어려운 점은 일손이 부족하다는 것입니다. 아이들 장난감을 빨리 고쳐 주고 싶지만 전국에서 장난감을 보내 주셔서 그게 쉽지가 않습니다. 부품을 구하기 어려운 경우도 자주 있고요. 장난감 수리점이 여기저기 더 많아진다면 아이들에게 조금 더 빨리 장난감을 돌려줄 수 있을 것입니다. 제가 장난감 고치는 방법을 영상으로 만들어 인터넷에 올리고 있는데 많은 분들이 이 일에 관심을 가져 주시면 좋겠습니다.<br><br>Мастер 20 лет чинит детские игрушки. Не хватает рук, игрушки шлют со всей страны, трудно с запчастями.<br>✅ <b>② Мастерских по ремонту игрушек должно стать больше.</b> — «수리점이 여기저기 더 많아진다면 … 더 빨리 돌려줄 수 있을 것».<br>✖️ ① «игрушками надо пользоваться аккуратно», ③ «важно чинить быстро», ④ «надо обучать людей способам ремонта» — упомянуто, но не главная мысль.<br>🧩 수리점 = «мастерская»; 일손이 부족하다 = «не хватает рабочих рук»; 부품 = «деталь»."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["먼 지역에서 장난감을 보내기도 한다.","요즘 장난감 수리점에 일이 많지 않다.","이 남자는 장난감 부품을 쉽게 구할 수 있다.","이 남자는 최근에 장난감 고치는 일을 시작했다."],"answer":1,"script":"여자: 20년 동안 아이들의 장난감을 고쳐 주고 계신데요. 어려운 점도 있으실 것 같습니다.\n남자: 사실 가장 어려운 점은 일손이 부족하다는 것입니다. 아이들 장난감을 빨리 고쳐 주고 싶지만 전국에서 장난감을 보내 주셔서 그게 쉽지가 않습니다. 부품을 구하기 어려운 경우도 자주 있고요. 장난감 수리점이 여기저기 더 많아진다면 아이들에게 조금 더 빨리 장난감을 돌려줄 수 있을 것입니다. 제가 장난감 고치는 방법을 영상으로 만들어 인터넷에 올리고 있는데 많은 분들이 이 일에 관심을 가져 주시면 좋겠습니다.","explain":"🎧 (то же интервью, что в вопросе 25).<br><br>✅ <b>① Игрушки присылают и из далёких регионов.</b> — «전국에서 장난감을 보내 주셔서».<br>✖️ ② сейчас в мастерских мало работы (наоборот, рук не хватает), ③ мужчина легко достаёт детали (наоборот, «부품을 구하기 어려운 경우도 자주»), ④ начал чинить недавно (наоборот, «20년 동안»).<br>🧩 먼 지역 = «дальний регион»; 전국 = «вся страна»."},{"n":27,"points":2,"instr":"Прослушайте и выберите, с какой целью говорит мужчина.","options":["임시 공휴일 제도를 반대하기 위해","임시 공휴일에 쉬지 못하는 아쉬움을 말하기 위해","임시 공휴일이 회사에 미치는 영향을 주장하기 위해","임시 공휴일에 아이를 맡길 수 있는 시설을 소개하기 위해"],"answer":2,"script":"여자: 이번에 정부에서 다음 주 금요일을 임시 공휴일로 지정했대. 금요일까지 쉬면서 연휴가 꽤 길어지겠네.\n남자: 나도 들었어. 근데 우리 회사는 임시 공휴일에도 정상 근무라 나는 전혀 상관없어. 쉬는 사람들은 좋겠다. 부러워.\n여자: 나도 그래. 우리 회사도 같이 쉬면 좋을 텐데. 그날 나는 출근해야 하는데 아이 학교가 쉬니까 당장 아이 맡길 만한 곳도 알아봐야 해.\n남자: 임시 공휴일이라는 게 누구한테는 휴일인데, 우리 같은 직장인들에겐 오히려 부담이네.","explain":"🎧 여자: 이번에 정부에서 다음 주 금요일을 임시 공휴일로 지정했대. 금요일까지 쉬면서 연휴가 꽤 길어지겠네.<br>남자: 나도 들었어. 근데 우리 회사는 임시 공휴일에도 정상 근무라 나는 전혀 상관없어. 쉬는 사람들은 좋겠다. 부러워.<br>여자: 나도 그래. 우리 회사도 같이 쉬면 좋을 텐데. 그날 나는 출근해야 하는데 아이 학교가 쉬니까 당장 아이 맡길 만한 곳도 알아봐야 해.<br>남자: 임시 공휴일이라는 게 누구한테는 휴일인데, 우리 같은 직장인들에겐 오히려 부담이네.<br><br>Объявили временный выходной, но компания мужчины работает как обычно — он завидует отдыхающим, для офисных это «обуза».<br>✅ <b>② Чтобы выразить досаду, что не получится отдохнуть в выходной.</b> — «쉬는 사람들은 좋겠다. 부러워», «오히려 부담이네».<br>✖️ ① против самой системы выходных, ③ доказать влияние на компанию, ④ представить место, куда сдать ребёнка — мужчина об этом не говорит.<br>🧩 임시 공휴일 = «временный нерабочий день»; 아쉬움 = «досада, сожаление»; 부담 = «обуза»."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["아이 학교는 임시 공휴일에 쉬지 않는다.","남자는 임시 공휴일에 여행을 갈 계획이다.","남자와 여자는 임시 공휴일에도 출근해야 한다.","정부는 이번 주 금요일을 임시 공휴일로 지정했다."],"answer":3,"script":"여자: 이번에 정부에서 다음 주 금요일을 임시 공휴일로 지정했대. 금요일까지 쉬면서 연휴가 꽤 길어지겠네.\n남자: 나도 들었어. 근데 우리 회사는 임시 공휴일에도 정상 근무라 나는 전혀 상관없어. 쉬는 사람들은 좋겠다. 부러워.\n여자: 나도 그래. 우리 회사도 같이 쉬면 좋을 텐데. 그날 나는 출근해야 하는데 아이 학교가 쉬니까 당장 아이 맡길 만한 곳도 알아봐야 해.\n남자: 임시 공휴일이라는 게 누구한테는 휴일인데, 우리 같은 직장인들에겐 오히려 부담이네.","explain":"🎧 (тот же диалог, что в вопросе 27).<br><br>✅ <b>③ И мужчина, и женщина должны выйти на работу даже в выходной.</b> — он «정상 근무», она «그날 나는 출근해야 하는데».<br>✖️ ① школа ребёнка не отдыхает (наоборот, «아이 학교가 쉬니까»), ② мужчина планирует поездку (нет), ④ правительство назначило <b>эту</b> пятницу (на самом деле «다음 주 금요일» — следующую).<br>🧩 정상 근무 = «обычный рабочий день»; 출근하다 = «выходить на работу»."},{"n":29,"points":2,"instr":"Прослушайте и определите, кто такой мужчина.","options":["건물을 관리하는 시설 직원","사건 현장을 조사하는 경찰관","사고 현장을 정리하는 전문가","화재 현장에서 불을 끄는 소방관"],"answer":3,"script":"여자: 하시는 일이 일반적인 청소와는 좀 다르다고 들었습니다. 어떤 일을 주로 하시나요?\n남자: 네, 저는 주로 화재나 범죄가 일어난 장소를 청소하고 정리하는 일을 합니다. 이런 곳은 일반적인 청소로는 해결할 수 없는 상황이 많기 때문에 특별한 장비를 사용해서 청소를 해야 합니다.\n여자: 현장 상황에 따라 작업 방식도 달라지겠네요.\n남자: 네, 맞습니다. 예를 들어 불이 난 곳은 탄 먼지가 많고 범죄가 일어난 곳은 위험한 물건이 남아 있을 수 있어요. 그래서 먼저 현장을 잘 살펴보고 알맞은 약품과 도구를 준비합니다.\n여자: 정신적으로도 힘든 일일 것 같네요.\n남자: 그렇죠. 안타까운 사고의 흔적이 남아 있는 장소를 정리할 때는 마음이 힘들 때도 있습니다. 그래도 누군가는 꼭 해야 할 일이라서 책임감을 가지고 일하고 있습니다.","explain":"🎧 여자: 하시는 일이 일반적인 청소와는 좀 다르다고 들었습니다. 어떤 일을 주로 하시나요?<br>남자: 네, 저는 주로 화재나 범죄가 일어난 장소를 청소하고 정리하는 일을 합니다. … 특별한 장비를 사용해서 청소를 해야 합니다.<br>여자: 현장 상황에 따라 작업 방식도 달라지겠네요.<br>남자: 네. 먼저 현장을 잘 살펴보고 알맞은 약품과 도구를 준비합니다.<br>남자: 안타까운 사고의 흔적이 남아 있는 장소를 정리할 때는 마음이 힘들 때도 있습니다. 그래도 누군가는 꼭 해야 할 일이라서 책임감을 가지고 일하고 있습니다.<br><br>Мужчина убирает и приводит в порядок места после пожаров и преступлений — это не обычная уборка.<br>✅ <b>③ Специалист, который приводит в порядок места происшествий.</b><br>✖️ ① работник по обслуживанию здания, ② полицейский, расследующий происшествие, ④ пожарный, тушащий огонь — он именно убирает место после.<br>🧩 사고 현장 = «место происшествия»; 정리하다 = «приводить в порядок»; 전문가 = «специалист»."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["현장마다 같은 방법을 사용해서 청소해야 한다.","이 일은 감정에 영향을 받지 않고 일할 수 있다.","현장을 분석한 후 특별한 도구를 사용해야 한다.","이 일은 일반적인 청소보다 간단하고 하기가 쉽다."],"answer":3,"script":"여자: 하시는 일이 일반적인 청소와는 좀 다르다고 들었습니다. 어떤 일을 주로 하시나요?\n남자: 네, 저는 주로 화재나 범죄가 일어난 장소를 청소하고 정리하는 일을 합니다. 이런 곳은 일반적인 청소로는 해결할 수 없는 상황이 많기 때문에 특별한 장비를 사용해서 청소를 해야 합니다.\n여자: 현장 상황에 따라 작업 방식도 달라지겠네요.\n남자: 네, 맞습니다. 예를 들어 불이 난 곳은 탄 먼지가 많고 범죄가 일어난 곳은 위험한 물건이 남아 있을 수 있어요. 그래서 먼저 현장을 잘 살펴보고 알맞은 약품과 도구를 준비합니다.\n여자: 정신적으로도 힘든 일일 것 같네요.\n남자: 그렇죠. 안타까운 사고의 흔적이 남아 있는 장소를 정리할 때는 마음이 힘들 때도 있습니다. 그래도 누군가는 꼭 해야 할 일이라서 책임감을 가지고 일하고 있습니다.","explain":"🎧 (то же интервью, что в вопросе 29).<br><br>✅ <b>③ Сначала анализируют место, потом используют специальные инструменты.</b> — «먼저 현장을 잘 살펴보고 알맞은 약품과 도구를 준비».<br>✖️ ① на каждом месте один и тот же метод (наоборот, «현장 상황에 따라 달라짐»), ② работа без влияния на эмоции (наоборот, «정신적으로 힘든»), ④ проще обычной уборки (наоборот, сложнее).<br>🧩 분석하다 = «анализировать»; 약품 = «химические средства»; 도구 = «инструмент»."},{"n":31,"points":2,"instr":"Прослушайте и выберите мнение мужчины.","options":["자동차보다 보행자의 안전을 우선해야 한다.","속도 제한은 도시 외곽에서만 시행해야 한다.","교통 흐름을 위해 속도 제한을 완화해야 한다.","자동차 속도 제한은 실제로 효과가 높지 않다."],"answer":1,"script":"여자: 도시에서 자동차 사고를 줄이려고 속도를 제한하고 있는데 저는 너무 심한 것 같아요.\n남자: 저는 속도 제한이 필요하다고 생각해요. 특히 보행자가 많은 도심에서는 차량이 빠르게 달리면 사고 위험이 커지잖아요. 실제로 시속 30킬로미터 이하로 제한한 구간에서는 사고 발생률이 크게 줄었다는 통계도 있어요.\n여자: 물론 사고 예방은 중요하지만 너무 낮은 속도 제한은 교통 흐름을 방해하고 운전자에게 불편을 줄 수 있잖아요.\n남자: 그렇지만 교통보다 사람의 안전이 더 중요하다고 생각해요. 도로는 자동차만을 위한 공간이 아니니까요.","explain":"🎧 여자: 도시에서 자동차 사고를 줄이려고 속도를 제한하고 있는데 저는 너무 심한 것 같아요.<br>남자: 저는 속도 제한이 필요하다고 생각해요. 특히 보행자가 많은 도심에서는 차량이 빠르게 달리면 사고 위험이 커지잖아요. 실제로 시속 30킬로미터 이하로 제한한 구간에서는 사고 발생률이 크게 줄었다는 통계도 있어요.<br>여자: 물론 사고 예방은 중요하지만 너무 낮은 속도 제한은 교통 흐름을 방해하고 운전자에게 불편을 줄 수 있잖아요.<br>남자: 그렇지만 교통보다 사람의 안전이 더 중요하다고 생각해요. 도로는 자동차만을 위한 공간이 아니니까요.<br><br>Мужчина за ограничение скорости: в городе с пешеходами опасно, безопасность людей важнее, чем поток машин.<br>✅ <b>① Безопасность пешеходов важнее автомобилей.</b> — «교통보다 사람의 안전이 더 중요», «도로는 자동차만을 위한 공간이 아니».<br>✖️ ② ограничение только на окраинах, ③ ослабить ограничение ради потока, ④ ограничение неэффективно — это не его позиция.<br>🧩 속도 제한 = «ограничение скорости»; 보행자 = «пешеход»; 우선하다 = «ставить в приоритет»."},{"n":32,"points":2,"instr":"Прослушайте и выберите, какова позиция мужчины.","options":["여자의 의견에 대해 동의하고 있다.","상대방의 의견을 수용하며 조율하고 있다.","상대방에게 추가적인 자료 제시를 요구하고 있다.","통계 자료를 제시하며 여자의 의견에 반박하고 있다."],"answer":4,"script":"여자: 도시에서 자동차 사고를 줄이려고 속도를 제한하고 있는데 저는 너무 심한 것 같아요.\n남자: 저는 속도 제한이 필요하다고 생각해요. 특히 보행자가 많은 도심에서는 차량이 빠르게 달리면 사고 위험이 커지잖아요. 실제로 시속 30킬로미터 이하로 제한한 구간에서는 사고 발생률이 크게 줄었다는 통계도 있어요.\n여자: 물론 사고 예방은 중요하지만 너무 낮은 속도 제한은 교통 흐름을 방해하고 운전자에게 불편을 줄 수 있잖아요.\n남자: 그렇지만 교통보다 사람의 안전이 더 중요하다고 생각해요. 도로는 자동차만을 위한 공간이 아니니까요.","explain":"🎧 (тот же диалог, что в вопросе 31).<br><br>✅ <b>④ Приводит статистику и возражает мнению женщины.</b> — «실제로 … 사고 발생률이 크게 줄었다는 통계도 있어요» + «그렇지만 …».<br>✖️ ① соглашается с женщиной (наоборот), ② принимает её мнение и подстраивается (наоборот, спорит), ③ требует у неё дополнительных данных — данные приводит сам мужчина.<br>🧩 통계 자료 = «статистические данные»; 반박하다 = «возражать, опровергать»."},{"n":33,"points":2,"instr":"Прослушайте и определите, о чём идёт речь.","options":["낙타가 혹을 가지고 있는 이유","낙타가 몸속에 지방을 저장하는 방법","낙타가 사막의 더위를 이겨 내는 방법","낙타가 오랫동안 물 없이 살 수 있는 이유"],"answer":4,"script":"여자: 사막에서 쉽게 떠올릴 수 있는 동물, 바로 낙타입니다. 낙타의 등에 있는 혹에 물이 저장되어 있다고 알고 계신 분들이 많은데, 사실 그곳에는 지방이 저장되어 있습니다. 이 지방은 에너지가 부족할 때 천천히 사용되지요. 또 낙타는 체온을 잘 조절해서 땀을 거의 흘리지 않기 때문에 몸속의 물이 빠져나가는 양이 아주 적습니다. 게다가 낙타는 짧은 시간에 많은 물을 마실 수 있어서 물이 적은 환경에서도 잘 살아갈 수 있는 겁니다.","explain":"🎧 여자: 사막에서 쉽게 떠올릴 수 있는 동물, 바로 낙타입니다. 낙타의 등에 있는 혹에 물이 저장되어 있다고 알고 계신 분들이 많은데, 사실 그곳에는 지방이 저장되어 있습니다. 이 지방은 에너지가 부족할 때 천천히 사용되지요. 또 낙타는 체온을 잘 조절해서 땀을 거의 흘리지 않기 때문에 몸속의 물이 빠져나가는 양이 아주 적습니다. 게다가 낙타는 짧은 시간에 많은 물을 마실 수 있어서 물이 적은 환경에서도 잘 살아갈 수 있는 겁니다.<br><br>Весь рассказ объясняет, как верблюд выживает в пустыне почти без воды (жир в горбе, мало пота, быстро много пьёт).<br>✅ <b>④ Почему верблюд может долго жить без воды.</b><br>✖️ ① почему у верблюда есть горб (это лишь часть), ② как именно жир запасается (механизм не объясняется), ③ как переносит жару — рассказ шире, о выживании без воды.<br>🧩 낙타 = «верблюд»; 혹 = «горб»; 지방 = «жир»."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["낙타는 땀을 많이 흘린다.","낙타는 체온 조절을 잘한다.","낙타의 혹에는 물이 많이 들어 있다.","낙타는 긴 시간 동안 물을 마셔야 한다."],"answer":2,"script":"여자: 사막에서 쉽게 떠올릴 수 있는 동물, 바로 낙타입니다. 낙타의 등에 있는 혹에 물이 저장되어 있다고 알고 계신 분들이 많은데, 사실 그곳에는 지방이 저장되어 있습니다. 이 지방은 에너지가 부족할 때 천천히 사용되지요. 또 낙타는 체온을 잘 조절해서 땀을 거의 흘리지 않기 때문에 몸속의 물이 빠져나가는 양이 아주 적습니다. 게다가 낙타는 짧은 시간에 많은 물을 마실 수 있어서 물이 적은 환경에서도 잘 살아갈 수 있는 겁니다.","explain":"🎧 (та же лекция, что в вопросе 33).<br><br>✅ <b>② Верблюд хорошо регулирует температуру тела.</b> — «체온을 잘 조절해서 땀을 거의 흘리지 않기».<br>✖️ ① много потеет (наоборот, «땀을 거의 흘리지 않»), ③ в горбе много воды (там жир, не вода), ④ должен долго пить (наоборот, «짧은 시간에 많은 물을 마실 수 있어서»).<br>🧩 체온 조절 = «терморегуляция»; 땀을 흘리다 = «потеть»."},{"n":35,"points":2,"instr":"Прослушайте и определите, что делает мужчина.","options":["회사의 신제품을 홍보하고 있다.","창업 기념식에서 인사를 하고 있다.","회사 고객 불만에 대해 사과하고 있다.","회사 신입 직원 교육을 진행하고 있다."],"answer":2,"script":"남자: 오늘은 우리 기업이 30주년을 맞이하는 뜻깊은 날입니다. 그동안 수많은 도전과 변화 속에서도 흔들림 없이 함께해 주신 직원 여러분의 수고에 깊이 감사드립니다. 또한 저희를 믿고 신뢰를 보내 주신 고객 여러분께도 감사의 말씀을 전합니다. 30년 전, 작은 회사로 출발한 우리 기업은 고객 중심의 가치와 정직한 경영을 바탕으로 꾸준히 성장해 왔습니다. 앞으로도 지속 가능한 성장과 사회적 책임을 함께 실천하는 기업으로서, 더 나은 미래를 만들어 가는 데 최선을 다하겠습니다.","explain":"🎧 남자: 오늘은 우리 기업이 30주년을 맞이하는 뜻깊은 날입니다. 그동안 함께해 주신 직원 여러분과 고객 여러분께 깊이 감사드립니다. 30년 전, 작은 회사로 출발한 우리 기업은 고객 중심의 가치와 정직한 경영을 바탕으로 꾸준히 성장해 왔습니다. 앞으로도 지속 가능한 성장과 사회적 책임을 함께 실천하는 기업으로서 최선을 다하겠습니다.<br><br>Руководитель выступает с поздравительной речью на 30-летии компании.<br>✅ <b>② Произносит приветственную речь на юбилее основания.</b> — «30주년을 맞이하는 … 감사드립니다».<br>✖️ ① рекламирует новый продукт, ③ извиняется за жалобы клиентов, ④ проводит обучение новичков — речь именно юбилейная.<br>🧩 창업 = «основание (фирмы)»; 기념식 = «торжество, церемония»; 인사말 = «приветственная речь»."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 기업은 정직한 경영을 바탕으로 발전해 왔다.","이 기업은 올해 20주년을 맞이해서 기념식을 열었다.","이 기업은 사회의 책임보다 회사의 이익을 중요시한다.","이 기업은 처음부터 큰 기업으로 시작해서 빠르게 성장했다."],"answer":1,"script":"남자: 오늘은 우리 기업이 30주년을 맞이하는 뜻깊은 날입니다. 그동안 수많은 도전과 변화 속에서도 흔들림 없이 함께해 주신 직원 여러분의 수고에 깊이 감사드립니다. 또한 저희를 믿고 신뢰를 보내 주신 고객 여러분께도 감사의 말씀을 전합니다. 30년 전, 작은 회사로 출발한 우리 기업은 고객 중심의 가치와 정직한 경영을 바탕으로 꾸준히 성장해 왔습니다. 앞으로도 지속 가능한 성장과 사회적 책임을 함께 실천하는 기업으로서, 더 나은 미래를 만들어 가는 데 최선을 다하겠습니다.","explain":"🎧 (та же речь, что в вопросе 35).<br><br>✅ <b>① Эта компания развивалась на основе честного управления.</b> — «정직한 경영을 바탕으로 꾸준히 성장».<br>✖️ ② отмечает 20-летие (на самом деле 30주년), ③ ставит прибыль выше соц. ответственности (наоборот, «사회적 책임을 함께 실천»), ④ сразу начинала крупной (наоборот, «작은 회사로 출발»).<br>🧩 정직한 경영 = «честное управление»; 사회적 책임 = «социальная ответственность»."},{"n":37,"points":2,"instr":"Прослушайте и выберите центральную мысль женщины.","options":["일회용품을 대체할 수 있는 제품을 만들어야 한다.","일회용품 사용을 줄이기 위한 작은 실천이 중요하다.","친환경 제품의 가격을 현실적으로 조정할 필요가 있다.","정부는 환경 보호 정책을 보다 구체적으로 마련해야 한다."],"answer":2,"script":"남자: 요즘 환경 문제가 점점 심각해지고 있는데요. 변화를 위해서는 어떤 노력이 필요할까요?\n여자: 정부는 2030년까지 플라스틱 사용량을 줄이고 재활용률을 높이겠다는 목표로 다양한 정책을 시행하고 있지만 이것만으로는 한계가 있습니다. 반드시 일상에서 한 사람, 한 사람의 실천이 동반되어야 하지요. 예를 들어 텀블러를 들고 다니거나 장바구니를 사용하는 것처럼 일회용품 사용을 줄이려는 노력이 필요합니다. 물론 친환경 제품은 가격이 비싸지요. 또 규제가 없던 시절, 카페나 편의점에서 일회용품을 기본적으로 받았던 경험 때문에 이런 실천이 쉽지만은 않습니다.","explain":"🎧 남자: 요즘 환경 문제가 점점 심각해지고 있는데요. 변화를 위해서는 어떤 노력이 필요할까요?<br>여자: 정부는 2030년까지 플라스틱 사용량을 줄이고 재활용률을 높이겠다는 목표로 다양한 정책을 시행하고 있지만 이것만으로는 한계가 있습니다. 반드시 일상에서 한 사람, 한 사람의 실천이 동반되어야 하지요. 예를 들어 텀블러를 들고 다니거나 장바구니를 사용하는 것처럼 일회용품 사용을 줄이려는 노력이 필요합니다. 물론 친환경 제품은 가격이 비싸지요. 또 규제가 없던 시절, 카페나 편의점에서 일회용품을 기본적으로 받았던 경험 때문에 이런 실천이 쉽지만은 않습니다.<br><br>Женщина: одних госполитик мало — нужны повседневные действия каждого (тумблер, шопер).<br>✅ <b>② Важны маленькие действия ради сокращения одноразовых товаров.</b> — «한 사람, 한 사람의 실천이 동반되어야».<br>✖️ ① создавать замену одноразовым товарам, ③ скорректировать цену эко-товаров, ④ правительству нужна более конкретная политика — не главная мысль.<br>🧩 일회용품 = «одноразовые товары»; 실천 = «практика, действие»; 텀블러 = «термокружка»."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["최근 환경 문제가 조금씩 개선되고 있다.","요즘 카페에서는 일회용품을 기본으로 제공한다.","요즘은 친환경 제품이 저렴해 쉽게 구할 수 있다.","정부는 플라스틱 재활용률을 높이기 위한 정책을 시행하고 있다."],"answer":4,"script":"남자: 요즘 환경 문제가 점점 심각해지고 있는데요. 변화를 위해서는 어떤 노력이 필요할까요?\n여자: 정부는 2030년까지 플라스틱 사용량을 줄이고 재활용률을 높이겠다는 목표로 다양한 정책을 시행하고 있지만 이것만으로는 한계가 있습니다. 반드시 일상에서 한 사람, 한 사람의 실천이 동반되어야 하지요. 예를 들어 텀블러를 들고 다니거나 장바구니를 사용하는 것처럼 일회용품 사용을 줄이려는 노력이 필요합니다. 물론 친환경 제품은 가격이 비싸지요. 또 규제가 없던 시절, 카페나 편의점에서 일회용품을 기본적으로 받았던 경험 때문에 이런 실천이 쉽지만은 않습니다.","explain":"🎧 (тот же диалог, что в вопросе 37).<br><br>✅ <b>④ Правительство проводит политику для повышения уровня переработки пластика.</b> — «재활용률을 높이겠다는 목표로 다양한 정책을 시행».<br>✖️ ① проблемы среды улучшаются (наоборот, «점점 심각»), ② сейчас в кафе одноразовое дают по умолчанию (это про «규제가 없던 시절» — прошлое), ③ эко-товары дёшевы и доступны (наоборот, «가격이 비싸»).<br>🧩 재활용률 = «уровень переработки»; 정책을 시행하다 = «проводить политику»."},{"n":39,"points":2,"instr":"Прослушайте и выберите, о чём говорилось перед этим разговором.","options":["농촌 지역의 인구가 줄어서 많은 어려움이 생기고 있다.","농촌 지역 인구 유출에 대한 국민의 인식이 변화되었다.","농촌 지역 인구 유출 문제에 대한 해결책을 마련하였다.","농촌 지역 인구 유출로 인해 농촌 생활에는 여유가 생겼다."],"answer":1,"script":"여자: 이처럼 농촌 지역의 인구 유출로 인해 여러 가지 문제가 발생하고 있습니다. 농촌 지역의 인구 유출 문제를 해결하기 위한 방안에는 무엇이 있을까요?\n남자: 네. 농촌의 인구 감소는 단순히 사람이 줄어드는 것을 넘어 지역 경제와 공동체의 붕괴로 이어질 수 있기 때문에 빠른 대응이 필요합니다. 먼저, 제도적인 측면에서 청년들이 농촌에서도 안정적으로 일하고 정착할 수 있도록 창업이나 주거에 대한 실질적인 지원이 필요하고요. 또한 농업뿐만 아니라 교육, 문화, 복지 같은 생활 기반도 함께 마련되어야 합니다. 그리고 무엇보다 중요한 건 인식 개선입니다. 많은 사람들이 농촌을 불편하고 기회가 없는 곳으로 생각하는데 농촌의 장점과 가능성을 널리 알리는 노력도 함께 이루어져야 합니다.","explain":"🎧 여자: 이처럼 농촌 지역의 인구 유출로 인해 여러 가지 문제가 발생하고 있습니다. … 해결하기 위한 방안에는 무엇이 있을까요?<br>남자: 농촌의 인구 감소는 … 지역 경제와 공동체의 붕괴로 이어질 수 있기 때문에 빠른 대응이 필요합니다. 청년들이 정착할 수 있도록 창업·주거 지원이 필요하고, 교육·문화·복지 기반도 마련되어야 합니다. 무엇보다 중요한 건 인식 개선입니다.<br><br>Женщина начинает со слова «이처럼» (вот так / как видно) — значит, ДО этого речь шла о проблемах оттока населения.<br>✅ <b>① Из-за убыли населения села возникает много трудностей.</b> — «이처럼 … 여러 가지 문제가 발생».<br>✖️ ② изменилось восприятие людей (это цель, а не предыстория), ③ решение уже найдено (его только обсуждают), ④ в селе стало вольготнее (наоборот, проблемы).<br>🧩 인구 유출 = «отток населения»; 공동체 = «сообщество»; 인식 개선 = «изменение восприятия»."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["농촌 인구가 줄어들면서 범죄가 많아지고 있다.","정부의 체계적인 농촌 귀촌 정책이 마련되었다.","매년 농촌 인구가 도시 인구보다 증가하고 있다.","농촌 인구 정책은 빠르게 해결해야 할 문제이다."],"answer":4,"script":"여자: 이처럼 농촌 지역의 인구 유출로 인해 여러 가지 문제가 발생하고 있습니다. 농촌 지역의 인구 유출 문제를 해결하기 위한 방안에는 무엇이 있을까요?\n남자: 네. 농촌의 인구 감소는 단순히 사람이 줄어드는 것을 넘어 지역 경제와 공동체의 붕괴로 이어질 수 있기 때문에 빠른 대응이 필요합니다. 먼저, 제도적인 측면에서 청년들이 농촌에서도 안정적으로 일하고 정착할 수 있도록 창업이나 주거에 대한 실질적인 지원이 필요하고요. 또한 농업뿐만 아니라 교육, 문화, 복지 같은 생활 기반도 함께 마련되어야 합니다. 그리고 무엇보다 중요한 건 인식 개선입니다. 많은 사람들이 농촌을 불편하고 기회가 없는 곳으로 생각하는데 농촌의 장점과 가능성을 널리 알리는 노력도 함께 이루어져야 합니다.","explain":"🎧 (та же беседа, что в вопросе 39).<br><br>✅ <b>④ Политика по сельскому населению — проблема, которую надо решать быстро.</b> — «빠른 대응이 필요합니다».<br>✖️ ① растёт преступность (не упомянуто), ② системная госполитика уже создана (её только обсуждают), ③ село каждый год обгоняет город по населению (наоборот, отток).<br>🧩 빠른 대응 = «быстрое реагирование»; 귀촌 = «переезд в село»."},{"n":41,"points":2,"instr":"Прослушайте и выберите основное содержание лекции.","options":["사무 의자에는 조절 기능이 필요하다.","요즘 다양한 디자인의 의자가 인기를 끌고 있다.","요즘 의자는 인체 공학적 설계가 중심이 되고 있다.","의자는 기능뿐만 아니라 사용되는 소재도 중요하다."],"answer":3,"script":"여자: 여기 왼쪽 사진은 과거에 많이 사용되던 의자입니다. 높이나 각도를 조절할 수 없고 단단한 목재로 만들어져서 오래 앉아 있으면 불편했지요. 오른쪽 사진은 요즘 많이 볼 수 있는 의자인데요. 사용자의 편안함을 고려해 인체 공학적으로 설계되어 등받이 각도, 의자 높이, 팔걸이 위치를 내 몸에 맞게 조절할 수 있어 오래 앉아도 편안합니다.","explain":"🎧 여자: 여기 왼쪽 사진은 과거에 많이 사용되던 의자입니다. 높이나 각도를 조절할 수 없고 단단한 목재로 만들어져서 오래 앉아 있으면 불편했지요. 오른쪽 사진은 요즘 많이 볼 수 있는 의자인데요. 사용자의 편안함을 고려해 인체 공학적으로 설계되어 등받이 각도, 의자 높이, 팔걸이 위치를 내 몸에 맞게 조절할 수 있어 오래 앉아도 편안합니다.<br><br>Сравнение старого жёсткого деревянного стула и современного — спроектированного эргономично, с регулировками.<br>✅ <b>③ Современные стулья всё больше строятся вокруг эргономичного дизайна.</b> — «인체 공학적으로 설계되어».<br>✖️ ① офисному стулу нужна регулировка (узко), ② популярны разные дизайны, ④ важен и материал — не центральная мысль лекции.<br>🧩 인체 공학 = «эргономика»; 등받이 = «спинка»; 팔걸이 = «подлокотник»."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["요즘 의자의 기능이 점점 단순해지고 있다.","요즘 팔걸이 위치를 바꿀 수 있는 의자가 있다.","최근 조절 기능이 있는 의자라 판매율이 떨어진다.","옛날 나무 의자는 오래 앉아 있어도 편안함이 있었다."],"answer":2,"script":"여자: 여기 왼쪽 사진은 과거에 많이 사용되던 의자입니다. 높이나 각도를 조절할 수 없고 단단한 목재로 만들어져서 오래 앉아 있으면 불편했지요. 오른쪽 사진은 요즘 많이 볼 수 있는 의자인데요. 사용자의 편안함을 고려해 인체 공학적으로 설계되어 등받이 각도, 의자 높이, 팔걸이 위치를 내 몸에 맞게 조절할 수 있어 오래 앉아도 편안합니다.","explain":"🎧 (та же лекция, что в вопросе 41).<br><br>✅ <b>② Сейчас есть стулья, у которых можно менять положение подлокотника.</b> — «팔걸이 위치를 내 몸에 맞게 조절할 수 있어».<br>✖️ ① функции стульев упрощаются (наоборот), ③ из-за регулировки падают продажи (не сказано), ④ старый деревянный стул был удобен при долгом сидении (наоборот, «불편했지요»).<br>🧩 조절하다 = «регулировать»; 목재 = «древесина»."},{"n":43,"points":2,"instr":"Прослушайте и определите, о чём идёт речь.","options":["종이를 만드는 과정","종이를 관리하는 방법","종이가 지닌 문화적 가치","종이가 인간에게 미치는 영향"],"answer":1,"script":"남자: 나무를 잘게 부수고 물과 섞어 펄프를 만들어 낸다. 이 펄프를 망틀 위에 얇게 펼쳐 고르게 펴 준 뒤 롤러로 눌러 어느 정도 수분을 없앤다. 그다음 펄프를 깨끗한 물로 충분히 씻어 불순물을 제거한다. 이 과정은 매우 중요한데 펄프를 제대로 씻지 않으면 종이에 얼룩이 남고 인쇄할 때 품질이 떨어지기 때문이다. 세척이 끝난 펄프는 다시 롤러로 눌러 남은 수분을 최대한 제거한다. 그래야 종이의 밀도가 높아진다. 이후 종이를 말리는 실린더를 통해 완전히 건조시키고 섬유의 결을 고르게 정리한다. 그래야 종이가 구겨지거나 글자가 번지는 것을 줄일 수 있다. 이제 한 장의 종이가 완성된다.","explain":"🎧 남자: 나무를 잘게 부수고 물과 섞어 펄프를 만들어 낸다. 이 펄프를 망틀 위에 얇게 펼쳐 … 롤러로 눌러 어느 정도 수분을 없앤다. 그다음 펄프를 깨끗한 물로 충분히 씻어 불순물을 제거한다. … 세척이 끝난 펄프는 다시 롤러로 눌러 남은 수분을 최대한 제거한다. 그래야 종이의 밀도가 높아진다. 이후 종이를 말리는 실린더를 통해 완전히 건조시키고 … 이제 한 장의 종이가 완성된다.<br><br>Весь текст пошагово описывает, как из древесины получают лист бумаги.<br>✅ <b>① Процесс изготовления бумаги.</b><br>✖️ ② как ухаживать за бумагой, ③ культурная ценность бумаги, ④ влияние бумаги на человека — об этом речи нет.<br>🧩 펄프 = «целлюлоза, пульпа»; 불순물 = «примеси»; 밀도 = «плотность»."},{"n":44,"points":2,"instr":"Прослушайте и выберите причину, по которой пульпу прижимают роликом.","options":["종이의 결을 위해서","종이의 구김을 막기 위해서","종이의 인쇄 품질을 위해서","종이의 밀도를 높이기 위해서"],"answer":4,"script":"남자: 나무를 잘게 부수고 물과 섞어 펄프를 만들어 낸다. 이 펄프를 망틀 위에 얇게 펼쳐 고르게 펴 준 뒤 롤러로 눌러 어느 정도 수분을 없앤다. 그다음 펄프를 깨끗한 물로 충분히 씻어 불순물을 제거한다. 이 과정은 매우 중요한데 펄프를 제대로 씻지 않으면 종이에 얼룩이 남고 인쇄할 때 품질이 떨어지기 때문이다. 세척이 끝난 펄프는 다시 롤러로 눌러 남은 수분을 최대한 제거한다. 그래야 종이의 밀도가 높아진다. 이후 종이를 말리는 실린더를 통해 완전히 건조시키고 섬유의 결을 고르게 정리한다. 그래야 종이가 구겨지거나 글자가 번지는 것을 줄일 수 있다. 이제 한 장의 종이가 완성된다.","explain":"🎧 (тот же текст, что в вопросе 43).<br><br>✅ <b>④ Чтобы повысить плотность бумаги.</b> — «세척이 끝난 펄프는 다시 롤러로 눌러 남은 수분을 최대한 제거한다. 그래야 종이의 밀도가 높아진다».<br>✖️ ① ради текстуры бумаги, ② чтобы не мялась, ③ ради качества печати — прижим роликом нужен именно для плотности (через удаление влаги).<br>🧩 수분 = «влага»; 밀도를 높이다 = «повышать плотность»."},{"n":45,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 지역은 철거 후 아파트 단지로 재개발되었다.","도시 재생 사업은 외부 전문가 중심으로 추진되었다.","도시 재생 사업을 통해 주민들의 참여가 활발하였다.","도시 재생 사업은 공연과 전시보다는 주거 환경 개선에 집중했다."],"answer":3,"script":"여자: 여기 보이는 사진은 노후된 주택들이 밀집해 있는 한 도시의 골목입니다. 이 지역은 한때 낙후된 지역으로 분류되어 전면 철거 후 아파트 단지를 조성하자는 의견이 많았지만, 다른 방향의 재생 사업이 이루어졌습니다. 바로 기존 건축물과 골목길을 그대로 보존하면서 문화와 예술을 입혀 지역을 되살리는 방식이었죠. 주민들과 예술가들이 협력해 공간을 재구성하고, 지역의 이야기를 담은 전시와 공연을 기획하면서 외부 방문객들의 발길도 이어지게 됐습니다. 이 과정에서 핵심적인 역할을 한 것은 바로 주민 참여였습니다. 행정 기관이 일방적으로 주도하는 개발이 아니라, 주민이 직접 회의에 참여하고 의견을 제안하면서 지역의 주체로서 적극적인 관여를 한 것입니다. 이처럼 도시 재생은 물리적인 환경 변화뿐 아니라, 공동체 회복과 지역 정체성 회복이라는 사회적 가치도 함께 담고 있습니다.","explain":"🎧 여자: 여기 보이는 사진은 노후된 주택들이 밀집해 있는 한 도시의 골목입니다. … 전면 철거 후 아파트 단지를 조성하자는 의견이 많았지만, 다른 방향의 재생 사업이 이루어졌습니다. 바로 기존 건축물과 골목길을 그대로 보존하면서 문화와 예술을 입혀 지역을 되살리는 방식이었죠. … 이 과정에서 핵심적인 역할을 한 것은 바로 주민 참여였습니다. 행정 기관이 일방적으로 주도하는 개발이 아니라, 주민이 직접 회의에 참여하고 의견을 제안하면서 적극적인 관여를 한 것입니다.<br><br>Старый переулок возродили, сохранив здания и добавив культуру/искусство; ключевую роль сыграло участие жителей.<br>✅ <b>③ Благодаря проекту обновления участие жителей было активным.</b> — «핵심적인 역할을 한 것은 바로 주민 참여».<br>✖️ ① снесли и застроили жильём (наоборот, здания сохранили), ② вели внешние эксперты (вели сами жители), ④ упор на жильё, а не выставки (наоборот, делали выставки и спектакли).<br>🧩 도시 재생 = «городская регенерация»; 노후되다 = «обветшать»; 주민 참여 = «участие жителей»."},{"n":46,"points":2,"instr":"Прослушайте и выберите, каким способом говорит женщина.","options":["도시 재생의 사례를 통해 주요 내용을 설명하고 있다.","도시 재생 사업의 문제점을 비판적으로 분석하고 있다.","도시 재생 사업이 가진 문제의 주요 원인을 유추하고 있다.","통계를 중심으로 도시 재생 사업의 효과를 수치로 제시하고 있다."],"answer":1,"script":"여자: 여기 보이는 사진은 노후된 주택들이 밀집해 있는 한 도시의 골목입니다. 이 지역은 한때 낙후된 지역으로 분류되어 전면 철거 후 아파트 단지를 조성하자는 의견이 많았지만, 다른 방향의 재생 사업이 이루어졌습니다. 바로 기존 건축물과 골목길을 그대로 보존하면서 문화와 예술을 입혀 지역을 되살리는 방식이었죠. 주민들과 예술가들이 협력해 공간을 재구성하고, 지역의 이야기를 담은 전시와 공연을 기획하면서 외부 방문객들의 발길도 이어지게 됐습니다. 이 과정에서 핵심적인 역할을 한 것은 바로 주민 참여였습니다. 행정 기관이 일방적으로 주도하는 개발이 아니라, 주민이 직접 회의에 참여하고 의견을 제안하면서 지역의 주체로서 적극적인 관여를 한 것입니다. 이처럼 도시 재생은 물리적인 환경 변화뿐 아니라, 공동체 회복과 지역 정체성 회복이라는 사회적 가치도 함께 담고 있습니다.","explain":"🎧 (та же лекция, что в вопросе 45).<br><br>✅ <b>① Объясняет суть на конкретном примере городской регенерации.</b> — весь рассказ построен вокруг одного реального переулка-кейса.<br>✖️ ② критически анализирует проблемы, ③ выводит причины проблем, ④ приводит эффект в цифрах по статистике — этого нет.<br>🧩 사례 = «пример, кейс»; 설명하다 = «объяснять»."},{"n":47,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["도서관 이용자 중 청소년의 비율이 가장 높다.","도서관의 분위기가 새롭게 바뀌면서 청년층이 많아졌다.","도서관은 정보 제공을 넘어 문화 공간으로의 전환이 요구된다.","도서관에서는 이미 청소년 맞춤형 서비스가 충분히 제공되고 있다."],"answer":3,"script":"여자: 최근 청소년의 도서관 이용률을 높이기 위해 다양한 프로그램이 운영되고 있지만 실질적 변화를 끌어내기 어렵다는 지적도 나오고 있는데요. 청소년들의 도서관 이용을 활성화하려면 어떤 방안이 필요할까요?\n남자: 네, 무엇보다 청소년들이 도서관을 찾지 않게 되는 근본적인 원인을 분석하는 것이 중요하다고 생각합니다. 현재 도서관 이용자 층은 주로 중장년층에 편중되어 있죠. 따라서 청소년들도 자연스럽게 도서관을 찾을 수 있도록 도서관의 환경이나 분위기부터 변화가 필요합니다. 예를 들어, 청소년들의 관심사를 반영한 전시를 기획하거나 보다 쾌적한 학습 공간을 조성함으로써 도서관이 단순한 정보 제공 공간을 넘어 매력적인 문화 공간으로 인식되도록 해야 합니다.","explain":"🎧 여자: 최근 청소년의 도서관 이용률을 높이기 위해 다양한 프로그램이 운영되고 있지만 실질적 변화를 끌어내기 어렵다는 지적도 나오고 있는데요. … 어떤 방안이 필요할까요?<br>남자: 청소년들이 도서관을 찾지 않게 되는 근본적인 원인을 분석하는 것이 중요합니다. 현재 도서관 이용자 층은 주로 중장년층에 편중되어 있죠. … 도서관이 단순한 정보 제공 공간을 넘어 매력적인 문화 공간으로 인식되도록 해야 합니다.<br><br>✅ <b>③ От библиотеки требуется переход от выдачи информации к культурному пространству.</b> — «단순한 정보 제공 공간을 넘어 매력적인 문화 공간으로».<br>✖️ ① доля подростков среди читателей самая высокая (наоборот, «중장년층에 편중»), ② атмосфера сменилась и молодёжи стало больше (перемены ещё нужны), ④ услуги для подростков уже достаточны (наоборот, их не хватает).<br>🧩 청소년 = «подростки»; 중장년층 = «люди среднего и старшего возраста»; 문화 공간 = «культурное пространство»."},{"n":48,"points":2,"instr":"Прослушайте и выберите, какова позиция мужчины.","options":["도서관 활성화 방안에 대해 불신하고 있다.","청소년 맞춤형 접근이 필요하다는 입장을 보이고 있다.","도서관의 기존 운영 방식을 긍정적으로 평가하고 있다.","청소년보다는 중장년층을 위한 공간 확대를 주장하고 있다."],"answer":2,"script":"여자: 최근 청소년의 도서관 이용률을 높이기 위해 다양한 프로그램이 운영되고 있지만 실질적 변화를 끌어내기 어렵다는 지적도 나오고 있는데요. 청소년들의 도서관 이용을 활성화하려면 어떤 방안이 필요할까요?\n남자: 네, 무엇보다 청소년들이 도서관을 찾지 않게 되는 근본적인 원인을 분석하는 것이 중요하다고 생각합니다. 현재 도서관 이용자 층은 주로 중장년층에 편중되어 있죠. 따라서 청소년들도 자연스럽게 도서관을 찾을 수 있도록 도서관의 환경이나 분위기부터 변화가 필요합니다. 예를 들어, 청소년들의 관심사를 반영한 전시를 기획하거나 보다 쾌적한 학습 공간을 조성함으로써 도서관이 단순한 정보 제공 공간을 넘어 매력적인 문화 공간으로 인식되도록 해야 합니다.","explain":"🎧 (тот же диалог, что в вопросе 47).<br><br>✅ <b>② Высказывает позицию, что нужен подход, адаптированный под подростков.</b> — «청소년들의 관심사를 반영한 전시를 기획… 변화가 필요».<br>✖️ ① не верит в меры по оживлению библиотек (наоборот, предлагает их), ③ положительно оценивает нынешнюю работу (наоборот, нужны перемены), ④ требует расширить пространство для старших, а не подростков (наоборот).<br>🧩 맞춤형 = «адаптированный, под запрос»; 접근 = «подход»."},{"n":49,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["우주 개발에서는 민간 기업들의 참여가 제한되어 있다.","우주 개발은 단순한 과학 기술을 넘어 안보와 연결된다.","단기적인 프로젝트를 추진하여 우주 개발의 성과를 내고 있다.","우주에서의 주도권 확보를 위해 국가 간의 경쟁을 금지하고 있다."],"answer":2,"script":"남자: 여러분, 최근 세계 각국이 우주 개발에 박차를 가하고 있는 이유는 무엇일까요? 단순히 과학 기술의 진보만을 위한 것은 아닙니다. 우주 개발은 곧 국가 경쟁력과 안보 전략에 직결되는 중요한 영역이기 때문입니다. 예를 들어, 인공위성은 통신, 기상 예보, 재난 대응 등 다양한 분야에서 핵심적인 역할을 하고 있으며 한 나라가 위성 운용 능력을 갖추는 것은 전략적 자립성과 연결됩니다. 특히 최근에는 민간 기업들이 참여하면서 기술 발전이 가속화되고 우주 자원을 둘러싼 경쟁도 본격화되고 있습니다. 우리나라도 위성 발사 및 개발, 우주 인터넷 통신망 구축 등 장기 프로젝트를 추진 중이며 우주 개발은 단기간의 성과보다 지속 가능한 투자와 전략적 비전이 중요한 분야입니다. 결국 미래를 준비하는 국가는 우주에서의 주도권 확보를 국가 안보와 경제 성장의 핵심 축으로 삼고 있습니다.","explain":"🎧 남자: 최근 세계 각국이 우주 개발에 박차를 가하고 있는 이유는 무엇일까요? 단순히 과학 기술의 진보만을 위한 것은 아닙니다. 우주 개발은 곧 국가 경쟁력과 안보 전략에 직결되는 중요한 영역이기 때문입니다. … 민간 기업들이 참여하면서 기술 발전이 가속화되고 우주 자원을 둘러싼 경쟁도 본격화되고 있습니다. … 우주 개발은 단기간의 성과보다 지속 가능한 투자와 전략적 비전이 중요한 분야입니다.<br><br>✅ <b>② Освоение космоса — это не просто наука, оно связано с безопасностью.</b> — «국가 경쟁력과 안보 전략에 직결».<br>✖️ ① участие частных компаний ограничено (наоборот, «민간 기업들이 참여»), ③ успехов добиваются краткосрочными проектами (наоборот, «단기간의 성과보다 지속 가능한 투자»), ④ соперничество стран запрещено (наоборот, «경쟁도 본격화»).<br>🧩 우주 개발 = «освоение космоса»; 안보 = «безопасность»; 인공위성 = «искусственный спутник»."},{"n":50,"points":2,"instr":"Прослушайте и выберите, каким способом говорит мужчина.","options":["우주 개발의 위험성을 이용하여 설득하고 있다.","민간 주도의 우주 개발을 비판적으로 접근하고 있다.","주요 국가들의 경쟁 사례를 비교하며 장단점을 분석하고 있다.","우주 개발의 효율을 설명하며 전략적 중요성을 강조하고 있다."],"answer":4,"script":"남자: 여러분, 최근 세계 각국이 우주 개발에 박차를 가하고 있는 이유는 무엇일까요? 단순히 과학 기술의 진보만을 위한 것은 아닙니다. 우주 개발은 곧 국가 경쟁력과 안보 전략에 직결되는 중요한 영역이기 때문입니다. 예를 들어, 인공위성은 통신, 기상 예보, 재난 대응 등 다양한 분야에서 핵심적인 역할을 하고 있으며 한 나라가 위성 운용 능력을 갖추는 것은 전략적 자립성과 연결됩니다. 특히 최근에는 민간 기업들이 참여하면서 기술 발전이 가속화되고 우주 자원을 둘러싼 경쟁도 본격화되고 있습니다. 우리나라도 위성 발사 및 개발, 우주 인터넷 통신망 구축 등 장기 프로젝트를 추진 중이며 우주 개발은 단기간의 성과보다 지속 가능한 투자와 전략적 비전이 중요한 분야입니다. 결국 미래를 준비하는 국가는 우주에서의 주도권 확보를 국가 안보와 경제 성장의 핵심 축으로 삼고 있습니다.","explain":"🎧 (та же лекция, что в вопросе 49).<br><br>✅ <b>④ Объясняет значимость освоения космоса и подчёркивает его стратегическую важность.</b> — «전략적 자립성», «전략적 비전», «국가 안보와 경제 성장의 핵심 축».<br>✖️ ① убеждает, играя на опасности космоса, ② критически подходит к частному освоению космоса, ③ сравнивает кейсы соперничества стран с плюсами и минусами — этого нет.<br>🧩 전략적 중요성 = «стратегическая важность»; 주도권 = «лидерство, инициатива»."}]},
      reading: {"durationMin":70,"total":100,"label":"EBS 모의고사 제1회 · 읽기 (1~50)","questions":[{"n":1,"points":2,"instr":"Выберите подходящее выражение в ( ).","passage":"고향에 (　　) 부모님께 전화를 드렸다.","options":["도착해도","도착하거나","도착하더라도","도착하자마자"],"answer":4,"explain":"✅ <b>④ 도착하자마자</b> — «как только прибыл»: приехав на родину, сразу позвонил родителям.<br>✖️ ① 도착해도 «даже если приедет», ② 도착하거나 «приедет или», ③ 도착하더라도 «даже если бы приехал» — не подходят к завершённому действию в прошлом.<br>🧩 -자마자 — «как только, сразу после»: 집에 오자마자 잤어요 — Лёг спать, как только пришёл домой."},{"n":2,"points":2,"instr":"Выберите подходящее выражение в ( ).","passage":"늦어서 급하게 뛰어가다가 (　　).","options":["넘어질 뻔했다","넘어질 셈이다","넘어지려던 참이다","넘어지기 나름이다"],"answer":1,"explain":"✅ <b>① 넘어질 뻔했다</b> — «чуть не упал»: опаздывал, бежал второпях — и чуть не упал.<br>✖️ ② 넘어질 셈이다 «намерен упасть», ③ 넘어지려던 참이다 «как раз собирался упасть», ④ 넘어지기 나름이다 «зависит от того, как упасть» — нелогичны.<br>🧩 -(으)ㄹ 뻔하다 — «чуть не (произошло)»: 늦을 뻔했어요 — Чуть не опоздал."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому (가기 위해서).","passage":"방학에 여행을 <u>가기 위해서</u> 아르바이트를 시작했다.","options":["가려면","가려고","가는 대신에","가는 바람에"],"answer":2,"explain":"✅ <b>② 가려고</b> — выражает ту же цель, что и «가기 위해서» (чтобы поехать).<br>✖️ ① 가려면 «если собираешься ехать» (условие), ③ 가는 대신에 «вместо того чтобы ехать», ④ 가는 바람에 «из-за того что поехал» — другое значение.<br>🧩 -(으)려고 = -기 위해서 — цель: 돈을 모으려고 일해요 — Работаю, чтобы накопить денег."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"산 지 오래된 옷이지만 한두 번만 입었으니까 <u>새 옷이나 마찬가지이다</u>.","options":["새 옷이 좀 못났다","새 옷일 리가 없다","새 옷이나 다름없다","새 옷이 될 마련이다"],"answer":3,"explain":"✅ <b>③ 새 옷이나 다름없다</b> — «всё равно что новая» = «не отличается от новой».<br>✖️ ① «выглядит хуже новой», ② 새 옷일 리가 없다 «не может быть новой», ④ «непременно станет новой» — не передают смысл «как новая».<br>🧩 N(이)나 마찬가지이다 = N(와)과 다름없다 — «всё равно что N, не отличается от N»."},{"n":5,"points":2,"instr":"О чём этот текст (что рекламируют)?","passage":"🛍️ 하루 종일 든든한 것 같은 편안함으로\n더 산뜻한 하루를 경험하세요.","options":["안경","침대","수건","모자"],"answer":1,"explain":"✅ <b>① 안경</b> (очки): «надёжный комфорт весь день», «переживите более ясный (산뜻한) день» — реклама очков (чёткое, комфортное зрение).<br>✖️ ② 침대 кровать, ③ 수건 полотенце, ④ 모자 шляпа — к «산뜻한 하루 (ясный день)» не подходят.<br>🧩 산뜻하다 — свежий, ясный; 든든하다 — надёжный, основательный."},{"n":6,"points":2,"instr":"О чём этот текст (что рекламируют)?","passage":"🏪 약도, 택배도 여기서!\n24시간 당신의 옆에 있는 든든한 친구","options":["체육관","우체국","여행사","편의점"],"answer":4,"explain":"✅ <b>④ 편의점</b> (магазин у дома): работает «24시간», принимает посылки (택배), «друг рядом» — это круглосуточный магазин.<br>✖️ ② 우체국 почта работает не круглосуточно; ① 체육관 спортзал, ③ 여행사 турагентство — не про посылки и 24 часа.<br>🧩 택배 — доставка/посылка; 편의점 — мини-маркет (24 ч)."},{"n":7,"points":2,"instr":"О чём этот текст?","passage":"🚦 멈춰요! 지켜요!\n신호등 앞, 함께 만드는 안전한 약속","options":["환경 보호","자리 양보","교통 규칙","절약 습관"],"answer":3,"explain":"✅ <b>③ 교통 규칙</b> (правила дорожного движения): «остановись! соблюдай!», «у светофора (신호등) — общий безопасный уговор» — про ПДД.<br>✖️ ① 환경 보호 защита природы, ② 자리 양보 уступить место, ④ 절약 습관 экономия — не про светофор и безопасность на дороге.<br>🧩 신호등 — светофор; 지키다 — соблюдать."},{"n":8,"points":2,"instr":"О чём этот текст?","passage":"⚠️ 젖은 손으로 만지지 마십시오.\n사용 후 반드시 전원을 끄고 보관 바랍니다.","options":["신청 조건","주의 사항","이용 안내","장소 문의"],"answer":2,"explain":"✅ <b>② 주의 사항</b> (меры предосторожности): «не трогайте мокрыми руками», «после использования обязательно выключите питание» — это предупреждения по технике безопасности.<br>✖️ ① 신청 조건 условия заявки, ③ 이용 안내 инструкция по пользованию (шире), ④ 장소 문의 вопрос о месте — не подходят: текст именно предостерегает.<br>🧩 젖다 — намокнуть; 전원을 끄다 — выключить питание."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"🌿 제4회 녹색 한강 문화 축제\n• 기간: 4월 2일(수) ~ 4월 6일(일)\n• 장소: 인주시청 앞 광장\n• 내용: 재활용 가방 만들기 체험 및 친환경 제품 전시\n※ 체험을 원하시는 분은 현장에서 직접 신청하시기 바랍니다.","options":["이 축제는 일주일 동안 열린다.","이 축제는 인주 시청에서 진행된다.","축제에서 재활용 가방을 구입할 수 있다.","축제에서 체험을 하려면 현장에서 신청해야 한다."],"answer":4,"explain":"✅ <b>④</b> — «※체험을 원하시는 분은 현장에서 직접 신청» → чтобы участвовать в мастер-классе, нужна заявка на месте.<br>✖️ ① фестиваль идёт 4/2~4/6 — это 5 дней, а не неделя; ② проходит «인주시청 앞 광장 (на площади перед мэрией)», а не «в мэрии»; ③ сумки можно СДЕЛАТЬ (재활용 가방 만들기 체험), а не купить.<br>🧩 현장에서 신청하다 — подать заявку на месте; 체험 — мастер-класс, проба."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с данными графика.","passage":"📊 1인 가구 한 달 생활비, 어디에 쓸까? (조사 대상: 1인 가구 1,000명)\n식비 31% · 주거비 27% · 문화비 14% · 교통비 10% · 통신비 9% · 기타 9%","options":["주거에 사용하는 비용이 두 번째로 많았다.","월 생활비 중 교통비와 기타의 비율이 같았다.","1인 가구는 생활비의 절반 이상을 식비로 지출했다.","통신비가 문화 생활에 쓰는 돈보다 두 배 이상 많았다."],"answer":1,"explain":"✅ <b>①</b> — жильё (주거비) 27% — на втором месте после еды (식비 31%).<br>✖️ ② 교통비 10% ≠ 기타 9% (не равны); ③ еда 31% — меньше половины, а не «절반 이상»; ④ связь 9% МЕНЬШЕ культуры 14%, а не «в два раза больше».<br>🧩 절반 이상 — больше половины; 두 배 이상 — в два с лишним раза."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"인주시가 작년에 이어 올해도 아이를 키우는 가정을 위해 ‘장난감 도서관’을 운영한다. 이 서비스는 미리 신청한 가정에 차량이 직접 방문하여 다양한 장난감을 빌려주는 서비스이다. 이 도서관을 이용하면 새 장난감을 자주 사지 않아도 되기 때문에 이용 가정들의 만족도가 높다. 인주시청은 이 서비스를 확대해 더 많은 가정이 이용할 수 있도록 할 계획이라고 밝혔다.","options":["올해 처음으로 이 서비스가 시작되었다.","이 서비스는 신청을 해야 이용할 수 있다.","이 서비스를 이용한 가정들의 반응이 좋지 않다.","내년에는 장난감 도서관을 운영하지 않을 예정이다."],"answer":2,"explain":"✅ <b>②</b> — «미리 신청한 가정에 … 빌려주는 서비스» → услугой можно воспользоваться только по заявке.<br>✖️ ① «впервые в этом году» — нет: «작년에 이어 올해도» (продолжается с прошлого года); ③ «реакция плохая» — наоборот, «만족도가 높다»; ④ «в следующем году не будут проводить» — наоборот, планируют расширить (확대).<br>🧩 미리 신청하다 — заранее подать заявку; 만족도 — уровень удовлетворённости."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 폭설로 인해 차량 사고와 불편이 이어지고 있다. 이런 가운데 눈길에 멈춰 있는 차를 학생들이 밀어 주는 장면이 온라인에서 화제가 되고 있다. 학교 근처에서 멈춰 있는 차를 발견한 학생들은 여러 명이 함께 차를 밀어 도왔다. 이 모습을 본 시민이 사진을 찍어 인터넷에 올렸고 많은 사람들이 학생들의 따뜻한 행동을 칭찬하고 있다.","options":["눈길로 인해 교통사고가 많아졌다.","학생 여러 명이 힘을 모아 차를 밀었다.","한 시민이 차량 사고 사진을 인터넷에 올렸다.","많은 사람들이 학생들의 위험한 행동을 말렸다."],"answer":2,"explain":"✅ <b>②</b> — «여러 명이 함께 차를 밀어 도왔다» → несколько учеников вместе толкали машину.<br>✖️ ① текст не утверждает, что ДТП «стало больше» (сказано: 사고와 불편이 이어진다 — продолжаются); ③ гражданин выложил фото УЧЕНИКОВ, а не аварии; ④ люди не «останавливали» — они ХВАЛИЛИ (칭찬).<br>🧩 힘을 모으다 — объединить силы; 화제가 되다 — стать темой обсуждения, завирусниться."},{"n":13,"points":2,"instr":"Расставьте предложения в правильном порядке.","passage":"(가) 비타민은 언제 먹느냐에 따라 효과에 차이가 있다.\n(나) 따라서 비타민의 효과를 보려면 식사 후에 먹어야 한다.\n(다) 전문가들은 비타민을 식사 후에 먹는 것이 좋다고 말한다.\n(라) 음식과 함께 먹을 때 속이 더 편하고 효과도 좋아지기 때문이다.","options":["(가)-(다)-(라)-(나)","(가)-(라)-(나)-(다)","(다)-(나)-(가)-(라)","(다)-(라)-(가)-(나)"],"answer":1,"explain":"✅ <b>① (가)-(다)-(라)-(나)</b>: (가) общий тезис — эффект витаминов зависит от времени приёма → (다) эксперты советуют принимать после еды → (라) [причина] с едой желудку легче и эффект лучше → (나) 따라서 (поэтому) принимать после еды.<br>🧩 따라서 — «поэтому» (вывод, идёт в конце); -기 때문이다 — «потому что»."},{"n":14,"points":2,"instr":"Расставьте предложения в правильном порядке.","passage":"(가) 작은 일이었지만 좋은 이웃을 알게 되어서 마음이 따뜻해졌다.\n(나) 그날 저녁 옆집 아주머니가 직접 만든 쿠키를 한 봉지 가져다주셨다.\n(다) 얼마 전 우리 집 앞에 다른 이름이 쓰여 있는 택배 상자가 놓여 있었다.\n(라) 주소를 다시 확인하고 옆집에 가져다주었더니 아주머니가 고맙다고 하셨다.","options":["(가)-(나)-(다)-(라)","(가)-(다)-(라)-(나)","(다)-(나)-(라)-(가)","(다)-(라)-(나)-(가)"],"answer":4,"explain":"✅ <b>④ (다)-(라)-(나)-(가)</b>: (다) у дома появилась посылка с чужим именем → (라) проверил адрес, отнёс соседке — она поблагодарила → (나) тем вечером соседка принесла пакет домашнего печенья → (가) мелочь, но узнал хорошего соседа — стало тепло на душе.<br>🧩 가져다주다 — приносить (кому-то); -더니 — «сделал — и в результате»."},{"n":15,"points":2,"instr":"Расставьте предложения в правильном порядке.","passage":"(가) 그래서 기온이 낮은 아침에 안개가 자주 발생한다.\n(나) 공기 중에는 우리 눈에 보이지 않는 수증기가 포함되어 있다.\n(다) 안개는 공기 중에 있는 아주 작은 물방울들이 모여서 만들어진 것이다.\n(라) 이 수증기가 찬 공기와 만나면 작은 물방울로 변하는데 이것이 안개가 된다.","options":["(나)-(가)-(라)-(다)","(나)-(다)-(가)-(라)","(다)-(가)-(나)-(라)","(다)-(나)-(라)-(가)"],"answer":4,"explain":"✅ <b>④ (다)-(나)-(라)-(가)</b>: (다) туман — скопление мельчайших капель в воздухе [определение] → (나) в воздухе есть невидимый водяной пар → (라) когда пар встречает холодный воздух, превращается в капли — это и есть туман → (가) 그래서 поэтому туман часто возникает прохладным утром.<br>🧩 수증기 — водяной пар; 물방울 — капля; 그래서 — поэтому (вывод)."},{"n":16,"points":2,"instr":"Выберите подходящее выражение в ( ).","passage":"사람들은 보통 칭찬을 들으면 기분이 좋아지고 더 열심히 하게 된다고 생각한다. 그래서 누군가를 격려하거나 칭찬하는 것은 좋은 일이라고 생각한다. 그런데 상황에 따라 칭찬이 오히려 (　　) 있다. 칭찬은 받은 사람이 기대에 대한 부담을 느껴 도리어 실수하게 되기 때문이다.","options":["부족하게 느껴질 수도","좋은 상황을 만들 수도","실수의 원인이 될 수도","부담 없는 말이 될 수도"],"answer":3,"explain":"✅ <b>③ 실수의 원인이 될 수도</b> — «может стать причиной ошибки»: дальше поясняется, что похваленный чувствует давление ожиданий и наоборот ошибается (도리어 실수하게 되기 때문이다).<br>✖️ ① «покажется недостаточным», ② «создаст хорошую ситуацию», ④ «станет необременительными словами» — противоречат выводу о вреде похвалы.<br>🧩 오히려/도리어 — наоборот; 부담을 느끼다 — чувствовать давление."},{"n":17,"points":2,"instr":"Выберите подходящее выражение в ( ).","passage":"패스트푸드점이나 식당에서는 빠른 음악을 틀어 놓는 경우가 많다. 이는 단순히 신나는 분위기를 만들 뿐만 아니라 손님들의 행동에 영향을 주기 위한 의도적인 행동이다. 한 연구에 따르면 빠른 음악을 틀어 놓고 식사할 때 사람들은 음식을 더 빨리 먹는 경향이 있다고 한다. 빠른 음악을 틀어 놓으면 손님들이 (　　) 가게는 더 많은 손님을 받을 수 있게 된다.","options":["음식을 먹는 속도가 빨라져서","행복한 기분으로 먹기 때문에","좋은 분위기를 만들 수 있어서","음악의 주문을 방해하기 때문에"],"answer":1,"explain":"✅ <b>① 음식을 먹는 속도가 빨라져서</b> — «оттого что скорость еды растёт»: быстрая музыка → люди едят быстрее → столики освобождаются → заведение принимает больше гостей.<br>✖️ ② «счастливое настроение» и ④ «помехи» не объясняют, почему гостей становится БОЛЬШЕ; ③ «хорошая атмосфера» — лишь побочный эффект, в тексте подчёркнута скорость.<br>🧩 경향이 있다 — есть тенденция; 영향을 주다 — влиять."},{"n":18,"points":2,"instr":"Выберите подходящее выражение в ( ).","passage":"지폐에 등장하는 인물은 단순히 유명한 사람이 아니라 그 나라의 역사와 정체성을 보여 주는 상징으로 여겨진다. 그래서 많은 나라에서는 지폐에 들어갈 인물을 결정할 때 (　　) 한다. 어떤 나라는 지폐에 과학자나 교육자를 넣어 교육의 중요성을 강조하기도 하고, 어떤 나라는 예술가나 작가를 넣어 문화의 자부심을 드러내기도 한다.","options":["지폐의 디자인에 따라","나라에서 유명한 인물로","상징성과 의미를 고려하여","해외에서 알아볼 수 있게"],"answer":3,"explain":"✅ <b>③ 상징성과 의미를 고려하여</b> — «учитывая символизм и смысл»: персонаж на купюре — символ истории и идентичности страны, поэтому его выбирают по смыслу (учёные → важность образования, художники → гордость культурой).<br>✖️ ① «по дизайну купюры», ② «известного в стране человека», ④ «чтобы узнавали за рубежом» — не отражают идею символа нации.<br>🧩 정체성 — идентичность; 상징 — символ; 자부심 — гордость."},{"n":19,"points":2,"instr":"Прочитайте текст и выберите слово в ( ㉠ ).","passage":"펭귄은 일반적으로 추운 지역에 사는 동물로 잘 알려져 있다. 특히 남극처럼 얼음과 눈으로 뒤덮인 지역에서 살아가는 펭귄이 매체를 통해 자주 소개된다. (㉠) 일반적으로 알려진 것과 다르게 따뜻한 지역에서 사는 펭귄도 있다. 호주의 남부 해안이나 아프리카와 같은 지역에도 펭귄이 서식하고 있다. 이처럼 펭귄들은 각기 다른 기후에 맞게 생활하며 다양한 지역의 생태계에서 역할을 하고 있다.","options":["반면","만약","과연","혹시"],"answer":1,"explain":"✅ <b>① 반면</b> — «зато, с другой стороны»: пингвины известны как обитатели холода, ОДНАКО есть и пингвины тёплых регионов — нужен противительный союз.<br>✖️ ② 만약 «если», ③ 과연 «действительно ли», ④ 혹시 «не…ли» — не выражают контраст.<br>🧩 반면(에) — «тогда как, зато»; 서식하다 — обитать."},{"n":20,"points":2,"instr":"Выберите главную мысль текста.","passage":"펭귄은 일반적으로 추운 지역에 사는 동물로 잘 알려져 있다. 특히 남극처럼 얼음과 눈으로 뒤덮인 지역에서 살아가는 펭귄이 매체를 통해 자주 소개된다. (㉠) 일반적으로 알려진 것과 다르게 따뜻한 지역에서 사는 펭귄도 있다. 호주의 남부 해안이나 아프리카와 같은 지역에도 펭귄이 서식하고 있다. 이처럼 펭귄들은 각기 다른 기후에 맞게 생활하며 다양한 지역의 생태계에서 역할을 하고 있다.","options":["펭귄은 얼음과 눈이 있는 환경을 선호한다.","펭귄은 매체에 소개되면서 서식 지역이 알려졌다.","펭귄은 사는 지역에 따라 생김새와 성격이 다르다.","펭귄은 특정 기후가 아닌 다양한 환경에서 서식한다."],"answer":4,"explain":"✅ <b>④</b> — главная мысль: пингвины живут не только в холоде, а в РАЗНЫХ климатах и средах (남극뿐만 아니라 따뜻한 지역에도).<br>✖️ ① «предпочитают лёд и снег» — текст как раз это опровергает; ② про СМИ — второстепенно; ③ про «внешность и характер по регионам» в тексте не сказано.<br>🧩 다양한 환경 — разнообразная среда; 생태계 — экосистема."},{"n":21,"points":2,"instr":"Прочитайте текст и выберите выражение в ( ㉠ ).","passage":"최근 반려동물을 키우는 사람들이 많아지면서 공공장소에서 지켜야 할 기본적인 예절에 대한 관심도 높아지고 있다. 하지만 여전히 공원이나 산책로에서 목줄을 하지 않거나 배설물을 치우지 않고 가는 등 다른 사람들에게 불쾌감을 주는 행동으로 (㉠) 하는 사람들이 있다. 일부의 이런 행동 때문에 반려동물을 키우는 사람들에 대한 부정적인 인식이 생길 수 있으며 타인에게도 피해를 줄 수 있다. 이렇듯 작은 행동 하나가 다른 사람에게 큰 불편을 줄 수 있다는 것을 잊지 말아야 한다.","options":["손을 맞잡게","가슴을 울리게","눈살을 찌푸리게","발걸음을 맞추게"],"answer":3,"explain":"✅ <b>③ 눈살을 찌푸리게</b> — идиома «눈살을 찌푸리다» = «морщиться, хмуриться от недовольства»: люди выгуливают питомцев без поводка, не убирают за ними → вызывают у окружающих неприязнь.<br>✖️ ① 손을 맞잡다 «взяться за руки», ② 가슴을 울리다 «трогать до глубины души», ④ 발걸음을 맞추다 «идти в ногу» — позитивные/нейтральные, не подходят к «불쾌감».<br>🧩 눈살을 찌푸리다 — морщиться от неодобрения; 불쾌감 — неприятное чувство."},{"n":22,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 반려동물을 키우는 사람들이 많아지면서 공공장소에서 지켜야 할 기본적인 예절에 대한 관심도 높아지고 있다. 하지만 여전히 공원이나 산책로에서 목줄을 하지 않거나 배설물을 치우지 않고 가는 등 다른 사람들에게 불쾌감을 주는 행동으로 (㉠) 하는 사람들이 있다. 일부의 이런 행동 때문에 반려동물을 키우는 사람들에 대한 부정적인 인식이 생길 수 있으며 타인에게도 피해를 줄 수 있다. 이렇듯 작은 행동 하나가 다른 사람에게 큰 불편을 줄 수 있다는 것을 잊지 말아야 한다.","options":["최근 공공장소에서 불쾌감을 느끼는 사람이 증가하고 있다.","반려동물과 산책하는 사람들은 공원이나 산책로에서 불편을 겪는다.","요즘 공원이나 산책로에서 반려동물의 배설물을 치우는 사람이 많아졌다.","반려동물과 산책할 때 반려동물의 목줄을 하지 않고 다니는 사람들이 있다."],"answer":4,"explain":"✅ <b>④</b> — «목줄을 하지 않거나 … 가는 사람들이 있다» → есть те, кто выгуливает питомца без поводка.<br>✖️ ① текст говорит о росте интереса к ЭТИКЕТУ, а не числа недовольных; ② неудобство испытывают ОКРУЖАЮЩИЕ, а не сами владельцы; ③ наоборот — проблема в тех, кто НЕ убирает.<br>🧩 목줄 — поводок; 배설물 — экскременты; 치우다 — убирать."},{"n":23,"points":2,"instr":"Выберите чувство «я» в выделенной части (когда клиент по-доброму ответил).","passage":"며칠 전 카페 아르바이트를 할 때 생긴 일이다. 아르바이트가 처음이라 긴장한 상태로 일을 하고 있었는데 점심시간이 되자 주문이 몰려 정신없이 일했다. 너무 정신이 없어서 주문이 잘못된 줄도 몰랐다. 실수를 깨달은 즉시 고객에게 급히 죄송하다고 사과한 후 바로 새 음료를 만들어 드렸다. 그 고객은 나를 보며 “괜찮아요. 저도 실수할 때가 많으니까요.”라고 웃으며 말해 주었다. 그 말을 듣는 순간 굳어 있던 마음이 풀리며 긴장이 사라졌다. 처음에는 너무 당황해서 눈앞이 캄캄했는데 고객의 따뜻한 말 덕분에 다시 힘을 얻어 일할 수 있었다. 그날 이후 나 역시 다른 사람의 실수에 조금 더 너그러운 마음을 가져야겠다고 다짐하게 되었다. 사소한 말 한마디가 얼마나 큰 위로가 될 수 있는지 알게 된 일이었다.","options":["화가 나고 억울했다.","기쁘고 뿌듯했다.","부끄럽고 신경이 쓰였다.","안심되고 마음이 놓였다."],"answer":4,"explain":"✅ <b>④ 안심되고 마음이 놓였다</b> (отлегло, стало спокойно): после ошибки рассказчик был в панике (눈앞이 캄캄), но добрые слова клиента «괜찮아요…» сняли напряжение (굳어 있던 마음이 풀리며).<br>✖️ ① «зол и обижен» — наоборот, благодарен; ② «рад и горд» — слишком, речь об облегчении; ③ «стыдно и тревожно» — это до слов клиента.<br>🧩 마음이 놓이다 — отлегло от сердца; 긴장이 풀리다 — напряжение спадает."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"며칠 전 카페 아르바이트를 할 때 생긴 일이다. 아르바이트가 처음이라 긴장한 상태로 일을 하고 있었는데 점심시간이 되자 주문이 몰려 정신없이 일했다. 너무 정신이 없어서 주문이 잘못된 줄도 몰랐다. 실수를 깨달은 즉시 고객에게 급히 죄송하다고 사과한 후 바로 새 음료를 만들어 드렸다. 그 고객은 나를 보며 “괜찮아요. 저도 실수할 때가 많으니까요.”라고 웃으며 말해 주었다. 그 말을 듣는 순간 굳어 있던 마음이 풀리며 긴장이 사라졌다. 처음에는 너무 당황해서 눈앞이 캄캄했는데 고객의 따뜻한 말 덕분에 다시 힘을 얻어 일할 수 있었다. 그날 이후 나 역시 다른 사람의 실수에 조금 더 너그러운 마음을 가져야겠다고 다짐하게 되었다. 사소한 말 한마디가 얼마나 큰 위로가 될 수 있는지 알게 된 일이었다.","options":["나의 실수 때문에 점심시간이 더 바빠졌다.","나는 고객의 따뜻한 반응 덕분에 위로를 받았다.","고객은 처음에는 웃었지만 결국 나에게 화를 냈다.","고객이 주문을 잘못했지만 너그럽게 용서해 주었다."],"answer":2,"explain":"✅ <b>②</b> — «고객의 따뜻한 말 덕분에 다시 힘을 얻어» → благодаря тёплой реакции клиента рассказчик получил утешение.<br>✖️ ① обед и так был загружен, не из-за ошибки; ③ клиент не злился — он успокоил; ④ ошибся РАССКАЗЧИК, а не клиент.<br>🧩 위로를 받다 — получить утешение; 너그럽다 — великодушный."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 청년 농부 증가, 농촌에 새 바람","options":["청년 농부들이 새로운 농업 방식을 농촌에 알리고 있다.","고령화된 농촌에 청년들이 정착하면서 분위기가 바뀌고 있다.","기존의 농부들은 경쟁을 우려해 청년들과의 거리를 두고 있다.","농촌에 거주하는 청년들이 도시에 비해 일자리를 구하기 어렵다."],"answer":2,"explain":"✅ <b>②</b> — заголовок «Рост числа молодых фермеров — новый ветер в деревне»: в стареющую (고령화된) деревню переезжают молодые, и атмосфера меняется. «새 바람 (новый ветер)» = свежие перемены.<br>✖️ ① про «новый способ земледелия» в заголовке нет; ③ «держат дистанцию из-за конкуренции» — противоречит позитивному «새 바람»; ④ про трудности с работой — другая тема.<br>🧩 새 바람(이 불다) — повеяло переменами; 고령화 — старение (населения); 정착하다 — обосноваться."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 정부 지원금 축소, 전기차 판매 주춤","options":["전기차 가격이 낮아지면서 소비자들의 관심도 높아지고 있다.","전기차 판매자들이 판매 증가 원인을 정부 정책에서 찾고 있다.","정부의 지원이 줄어들자 소비자들의 전기차 구매가 감소하고 있다.","정부는 전기차의 보급을 늘리기 위해 지원금을 대폭 늘리기로 했다."],"answer":3,"explain":"✅ <b>③</b> — заголовок «Сокращение господдержки — продажи электромобилей застопорились»: субсидии урезали (축소) → покупки электромобилей пошли вниз. «주춤» = замедление, заминка.<br>✖️ ① про «снижение цены и рост интереса» — наоборот; ② про «поиск причин роста» — продаж нет, есть спад; ④ «резко увеличивает субсидии» — противоречит «지원금 축소».<br>🧩 주춤하다 — приостановиться, замедлиться; 축소 ↔ 확대 (сокращение ↔ расширение); 보급 — распространение."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 김유진 선수, 올해에도 세계 육상 선수권 금빛 질주","options":["김유진 선수가 이번 세계 대회에서도 우승을 차지했다.","김유진 선수는 세계 대회 금메달을 목표로 훈련하고 있다.","김유진 선수의 금메달 가능성이 높아져서 기대를 모으고 있다.","김유진 선수는 작년의 실패를 딛고 올해 대회에서 모두 우승했다."],"answer":1,"explain":"✅ <b>①</b> — заголовок «Спортсменка Ким Юджин и в этом году — золотой рывок на ЧМ по лёгкой атлетике»: «금빛 질주 (золотой забег)» = снова завоевала победу/золото на чемпионате.<br>✖️ ② «тренируется ради золота» — цель в будущем, а заголовок о результате; ③ «возросла вероятность» — золото уже взято, не «возможность»; ④ «после прошлогоднего провала» — «올해에도 (и в этом году тоже)» означает, что и в прошлом году побеждала.<br>🧩 금빛 질주 — победный (золотой) рывок; 우승을 차지하다 — завоевать первое место; 올해에도 — и в этом году тоже."},{"n":28,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"요즘 아침 시간을 활용하고자 하는 사람들이 늘어나고 있다. (　　)에 따라 하루를 더 효율적으로 보낼 수 있기 때문이다. 아침 시간을 효과적으로 쓰는 방법 중 하나는 일찍 일어나 가벼운 운동을 하거나 독서를 하는 등 자신만의 습관을 만드는 것이다. 습관을 만드는 것이 쉽지는 않지만 아침 시간을 자신만의 방식으로 잘 활용한다면 더욱 계획적이고 여유 있는 하루를 보낼 수 있다.","options":["책을 얼마나 읽느냐","일과를 어떻게 시작하느냐","아침부터 운동을 열심히 하느냐","충분한 수면으로 휴식을 취하느냐"],"answer":2,"explain":"✅ <b>② 일과를 어떻게 시작하느냐</b> — «от того, как начинаешь день»: текст в целом о том, что от способа использования утра (а не конкретно чтения или спорта) зависит эффективность дня — «(일과를 어떻게 시작하느냐)에 따라 하루를 더 효율적으로».<br>✖️ ① 책 (чтение) и ③ 운동 (спорт) — лишь ПРИМЕРЫ привычек, а не общий принцип; ④ 수면 (сон) в тексте не обсуждается.<br>🧩 일과 — распорядок дня; -느냐에 따라 — «в зависимости от того, …ли»; 활용하다 — использовать (с пользой)."},{"n":29,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"누군가 내 제안이나 부탁을 거절했을 때 우리는 종종 그것을 (　　) 받아들일 때가 있다. 하지만 상대는 나라는 사람을 평가하고 거절한 것이 아니라 특정한 조건이나 상황 속의 부탁을 거절한 것에 불과하다. 그 거절은 개인의 필요나 상황을 반영한 결과일 뿐 나라는 존재의 가치를 부정하는 것은 아니다. 따라서 거절을 지나치게 개인적인 것으로 받아들이기보다는 그것을 상황적 판단으로 이해하려는 태도가 필요하다.","options":["단순한 의견 차이로","필요하지 않은 내용으로","자신에 대한 부정적인 평가로","능력이 부족함을 나타내는 신호로"],"answer":3,"explain":"✅ <b>③ 자신에 대한 부정적인 평가로</b> — «как негативную оценку себя»: мы часто воспринимаем отказ как оценку нашей личности, НО («하지만») собеседник отказал не оценивая тебя, а лишь отклонил просьбу в конкретной ситуации.<br>✖️ ① «как простое расхождение во мнениях» и ② «как ненужное» — не вяжутся с дальнейшим «не отрицает ценность тебя»; ④ «сигнал нехватки способностей» — близко, но текст про оценку ЛИЧНОСТИ (나라는 존재의 가치), а не способностей.<br>🧩 거절 — отказ; -(으)로 받아들이다 — воспринимать как…; 지나치게 — чрезмерно."},{"n":30,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"야간에 도로에서 교통정리나 작업을 하는 사람들이 입는 작업복은 어두운 환경에서도 운전자의 눈에 잘 띌 수 있도록 제작된다. 이 작업복은 일반 옷과 달리 (　　) 기능이 있는 특수한 소재로 만들어진다. 자동차 불빛이 작업복에 닿으면 작업복의 특수 소재가 그 빛을 운전자 쪽으로 되돌려 보내기 때문에 어두운 곳에서도 잘 발견되기 쉽다. 이러한 원리를 활용해 교통 표지판이나 도로 경계선에도 같은 소재를 활용하고 있다.","options":["빛을 반사하는","작업을 도와주는","자동차 불빛을 막는","눈의 피로를 줄여 주는"],"answer":1,"explain":"✅ <b>① 빛을 반사하는</b> — «отражающий свет»: дальше прямо сказано, что особый материал «빛을 운전자 쪽으로 되돌려 보낸다» (отправляет свет обратно к водителю) — это и есть отражение.<br>✖️ ② «помогающий работать» — общая фраза, не про свет; ③ «блокирующий свет фар» — наоборот, материал свет ВОЗВРАЩАЕТ; ④ «снижающий усталость глаз» — в тексте нет.<br>🧩 반사하다 — отражать; 되돌려 보내다 — отправлять обратно; 띄다(눈에 띄다) — бросаться в глаза."},{"n":31,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"한국은 약 복용률이 높은 국가로 알려져 있었다. 감기나 가벼운 통증에도 약을 찾는 경우가 많았기 때문이다. 과거에는 병원 진료 없이 약을 쉽게 구입할 수 있어 약을 잘못 사용하거나 과하게 먹는 일이 자주 발생했다. 이런 문제를 줄이기 위해 한국에서는 병원에서 처방전을 받아야만 약국에서 약을 살 수 있는 의약 분업 제도를 시행하게 되었다. 이 제도는 (　　) 국민 건강을 보호하는 데 도움을 준다.","options":["약 구매처를 늘리고","약국에서 쉽게 약을 사고","불필요한 약의 복용을 막고","처방전 없이 약을 구입하고"],"answer":3,"explain":"✅ <b>③ 불필요한 약의 복용을 막고</b> — «предотвращая ненужный приём лекарств»: система «의약 분업» (рецепт от врача → покупка в аптеке) введена, чтобы сократить злоупотребление лекарствами и так защитить здоровье населения.<br>✖️ ① «увеличивая число точек продажи» и ② «легко покупать в аптеке» — противоречат цели контроля; ④ «покупать без рецепта» — именно это система ЗАПРЕЩАЕТ.<br>🧩 의약 분업 — разделение функций врача и аптеки; 처방전 — рецепт; 복용 — приём (лекарства); 막다 — предотвращать."},{"n":32,"points":2,"instr":"Прочитайте текст и выберите вариант, совпадающий с его содержанием.","passage":"일부 동물은 주변 환경과 비슷한 색을 띤다. 이를 보호색이라고 하는데 주로 자신을 숨길 때 사용된다. 사막에 사는 도마뱀은 몸의 색을 모래와 비슷하게 바꿔 천적이 쉽게 발견하지 못한다. 또한 숲속에 사는 생물은 잎이나 나무의 색과 비슷한 녹색을 띠게 된다. 이처럼 보호색은 신체적 방어력이나 발톱 등의 공격력이 약한 생물이 외부의 위협으로부터 자신을 지키는 생존 전략이다.","options":["보호색을 가진 생물은 보통 나무 위에서 생활한다.","보호색은 천적으로부터 안전하게 숨는 데 도움이 된다.","보호색을 가진 도마뱀은 들키지 않고 먹이를 유인할 수 있다.","보호색은 생물이 공격을 위해서 사용하는 대표적인 수단이다."],"answer":2,"explain":"✅ <b>②</b> — «주로 자신을 숨길 때 사용», «천적이 쉽게 발견하지 못한다» → защитная окраска помогает безопасно прятаться от хищников.<br>✖️ ① «обычно живут на деревьях» — нет: ящерица живёт в песке пустыни, цвет лишь похож на листву; ③ ящерица так ИЗБЕГАЕТ хищников (천적), а не приманивает добычу; ④ окраска нужна для ЗАЩИТЫ (자신을 지키는), а не для нападения.<br>🧩 보호색 — защитная окраска; 천적 — естественный враг; 생존 전략 — стратегия выживания."},{"n":33,"points":2,"instr":"Прочитайте текст и выберите вариант, совпадающий с его содержанием.","passage":"문해력은 단순히 글자를 읽는 능력이 아니라 글의 의미를 파악하고 상황에 따라 적절히 활용하는 능력을 말한다. 최근에는 교육 수준과 관계없이 문해력 부족을 겪는 사람들이 많아지고 있다. 이런 현상은 단지 학업 성취에 영향을 줄 뿐 그치지 않고 일상 생활, 사회적 의사소통, 일상 정보 처리 등 다양한 영역에서 문제를 일으킬 수 있다. 그렇기 때문에 문해력은 단순한 학습 능력이 아니라 사회 전반에 영향을 미치는 중요한 역량으로 인식되고 있다.","options":["학업 성적으로 문해력을 측정할 수 있다.","교육 수준에 따라 문해력에 차이가 생긴다.","사회적 중요성으로 인해 문해력이 필수 교과로 지정되었다.","문해력은 일상생활 전반에서 중요한 영향을 미치는 능력이다."],"answer":4,"explain":"✅ <b>④</b> — «사회 전반에 영향을 미치는 중요한 역량» → грамотность (문해력) влияет на повседневную жизнь в целом, а не только на учёбу.<br>✖️ ① грамотность — это понимание смысла, не сводится к «оценкам»; ② наоборот: проблемы возникают «교육 수준과 관계없이» (независимо от уровня образования); ③ про «обязательный школьный предмет» в тексте нет.<br>🧩 문해력 — функциональная грамотность; 역량 — компетенция; 사회 전반 — всё общество в целом."},{"n":34,"points":2,"instr":"Прочитайте текст и выберите вариант, совпадающий с его содержанием.","passage":"한국 전통 건축물의 천장이나 기둥 등에 그려진 색채 무늬를 단청이라고 한다. 대부분의 사람들은 아름다운 무늬와 색깔 때문에 단청을 단순한 장식 요소로만 인식하기 쉽다. 하지만 예로부터 단청은 건물을 아름답게 꾸미기 위한 것만이 아니라 외부 환경으로부터 건축물을 보호하는 기능도 함께 가지고 있었다. 이러한 기능 덕분에 비바람이나 햇볕에 약한 목재 건물이 오랫동안 보존될 수 있었다. 이처럼 단청은 우리 전통 건축의 기능과 아름다움을 함께 담고 있는 중요한 문화 요소이다.","options":["단청은 한국 전통 건축물을 보호하는 역할을 한다.","단청은 실내 공간의 벽면을 장식하기 위해 사용되었다.","한국 전통 건축물의 천장이나 기둥에는 특별한 장식이 없다.","한국 전통 건축물은 비바람과 햇볕에 강한 튼튼한 소재이다."],"answer":1,"explain":"✅ <b>①</b> — «외부 환경으로부터 건축물을 보호하는 기능» → дворцовая роспись 단청 защищает деревянное здание от внешней среды.<br>✖️ ② 단청 наносят на потолки и колонны (снаружи), и это не только украшение; ③ наоборот — 단청 это и есть узор/украшение; ④ дерево как раз СЛАБО к дождю и солнцу (약한 목재), поэтому его и защищает 단청.<br>🧩 단청 — традиционная многоцветная роспись; 목재 — древесина; 보존되다 — сохраняться."},{"n":35,"points":2,"instr":"Прочитайте текст и выберите его главную тему.","passage":"최근 여러 나라가 달 탐사에 관심을 보이며 기술 개발에 힘을 쏟고 있다. 달에는 에너지 자원을 포함한 희귀 자원이 있을 가능성이 높고 우주 연구의 중심지로 활용될 수도 있기 때문이다. 실제로 일부 국가는 탐사선을 달에 보내 달 표면에서 시료를 채취하는 데 성공했으며 관련 기술에서도 앞서 나가고 있다. 하지만 많은 나라들은 기술력이나 예산의 한계로 본격적인 탐사를 시작하지 못하고 있다. 인류의 미래 자원을 확보하기 위해서라도 달 탐사에 대한 투자와 기술 개발에 나설 필요가 있다.","options":["자원을 공정하게 활용하려면 국제적인 협력이 필요하다.","달 탐사를 위한 기술은 이미 대부분의 나라가 보유하고 있다.","희귀한 우주 자원을 개발하기 위해 달 탐사선을 보내야 한다.","미래 자원 확보를 위해 달 탐사에 대한 적극적인 노력이 필요하다."],"answer":4,"explain":"✅ <b>④</b> — вывод текста: «미래 자원을 확보하기 위해서라도 달 탐사에 대한 투자와 기술 개발에 나설 필요가 있다» → ради будущих ресурсов нужны активные усилия (инвестиции + технологии) в освоении Луны.<br>✖️ ① «международное сотрудничество» в тексте не главная мысль; ② «технологии уже у большинства стран» — наоборот, многим мешают «기술력이나 예산의 한계»; ③ слишком узко (только «послать зонд»), тогда как тема шире — нужны вложения и развитие.<br>🧩 달 탐사 — освоение Луны; 자원 확보 — обеспечение ресурсами; 적극적인 — активный."},{"n":36,"points":2,"instr":"Прочитайте текст и выберите его главную тему.","passage":"사람들의 소비 성향이 변화하고 있다. 요즘 사람들은 단순히 품질과 가격만을 기준으로 제품을 고르지 않는다. 착한 초콜릿, 착한 커피처럼 생산 과정에 인권이나 환경 보호의 가치를 반영한 제품을 찾는 경향을 보이고 있다. 과거에는 제품의 품질이나 가격, 또는 기업이 만들어 낸 일자리와 같은 경제적 가치를 중심으로 평가하던 소비자들의 기준이 달라지고 있는 것이다. 이에 따라 많은 기업들이 사회 공헌 활동이나 친환경 경영을 강조하며 브랜드 이미지를 바꾸려는 노력을 하고 있다.","options":["친환경 경영은 기업의 이미지 개선에 효과적인 전략이다.","소비 성향과 기업 평가 기준이 윤리 중심으로 변화하고 있다.","기업의 성공은 얼마나 많은 제품을 판매했는가에 따라 결정된다.","착한 소비를 실천하기 위해 소비자들은 일자리가 많은 기업을 선택한다."],"answer":2,"explain":"✅ <b>②</b> — главная мысль: покупатели уже судят не только по цене/качеству, а по этике (права человека, экология), и фирмы под это меняются → критерии потребления и оценки компаний смещаются к этике.<br>✖️ ① «эко-управление — эффективная стратегия имиджа» — лишь следствие, не тема; ③ «успех = объём продаж» — это ПРОШЛЫЙ подход, который текст как раз пересматривает; ④ про «выбор фирм с рабочими местами» — это тоже устаревший экономический критерий.<br>🧩 소비 성향 — потребительские предпочтения; 윤리 — этика; 착한 소비 — «этичное потребление»."},{"n":37,"points":2,"instr":"Прочитайте текст и выберите его главную тему.","passage":"스마트폰과 같은 디지털 기기의 발달과 함께 짧은 영상 콘텐츠를 즐기는 사람들이 늘고 있다. 이 콘텐츠들은 짧은 시간 안에 많은 정보를 전달하며 빠르게 소비된다. 하지만 이러한 소비 방식이 익숙해질수록 집중력이 필요한 활동에는 쉽게 지루함을 느끼게 된다. 짧은 자극에만 반응하는 습관이 형성되면 길고 복잡한 내용에 집중하는 데 어려움을 느낄 수 있기 때문이다.","options":["짧은 콘텐츠의 자극적인 요소에 대한 개선이 필요하다.","짧은 콘텐츠는 정보 전달 효율성을 높이는 데 기여한다.","짧은 콘텐츠의 반복적 소비는 집중력 저하를 초래할 수 있다.","짧은 콘텐츠는 소비 방식에 따라 습관 형성에 영향을 미친다."],"answer":3,"explain":"✅ <b>③</b> — главная мысль: привыкая к коротким роликам, человек быстро скучает там, где нужна концентрация, и теряет способность удерживать внимание на длинном → частое потребление «коротышей» снижает концентрацию.<br>✖️ ① про «улучшение раздражающих элементов» в тексте нет; ② «повышает эффективность передачи информации» — это плюс, но не главная мысль (текст о минусе); ④ слишком обтекаемо («влияет на привычки»), тема конкретнее — про СНИЖЕНИЕ концентрации.<br>🧩 집중력 — концентрация; 저하 — снижение; 반복적 소비 — повторяющееся потребление."},{"n":38,"points":2,"instr":"Прочитайте текст и выберите его главную тему.","passage":"자신에게는 쉬운 일이 상대에게는 어려운 일일 수 있다는 점을 생각하지 못하면 그 행동은 배려가 아닌 강요가 될 수도 있다. 이를 보여 주는 우화로 여우와 두루미 이야기가 있다. 여우는 두루미를 초대해 자신의 기준대로 평평한 접시에 음식을 내놓았고 두루미는 길고 뾰족한 부리 때문에 제대로 먹지 못했다는 내용이다. 이 이야기는 상대방의 입장을 고려하지 않은 배려가 자기중심적인 행동이 될 수도 있다는 점을 보여 준다.","options":["우화를 통해 진정한 배려가 무엇인지 알아야 한다.","자신만의 기준이 분명할 때 상대방을 배려할 수 있다.","배려할 때 상대방의 입장을 헤아리는 태도가 선행되어야 한다.","내가 좋아하는 것을 상대방에게 해 주는 것이 바람직한 배려이다."],"answer":3,"explain":"✅ <b>③</b> — главная мысль притчи о лисе и журавле: лиса угощала на плоской тарелке «по своим меркам», и журавль с длинным клювом не смог есть → настоящая забота начинается с учёта позиции другого.<br>✖️ ① «через басню узнать, что такое забота» — слишком общо, не выражает идею; ② «когда чёткие СВОИ критерии» — наоборот, эгоцентрично; ④ «давать другому то, что нравится МНЕ» — это и есть ошибка лисы.<br>🧩 배려 — забота, внимание к другому; 강요 — навязывание; 상대방의 입장 — позиция собеседника; 선행되다 — предшествовать."},{"n":39,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить данное предложение:<br><b>「사람들이 모이면서 자연스럽게 골목 상권이 살아나고 지역 사회가 활기를 띠게 된다.」</b>","passage":"도시 재생 사업은 오래된 지역을 새롭게 살려 지역 경제를 활성화하려는 사업이다. ( ㉠ ) 특히 최근에는 오래된 골목길을 새롭게 정비하여 상권을 되살리려는 시도가 늘고 있다. ( ㉡ ) 새롭게 단장한 골목에는 지역 특색을 살린 가게들이 들어서고 많은 사람들이 이곳을 찾기 시작한다. ( ㉢ ) 그러나 지나친 상업화로 인해 원래의 지역 특색이 사라질 위험도 함께 존재한다. ( ㉣ ) 이런 점을 고려하여 경제적 이익뿐만 아니라 지역의 고유문화를 지키는 방향으로 도시 재생이 이루어져야 한다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b> — вставляемое предложение: «когда люди собираются, оживает уличная торговля и район наполняется жизнью». Перед ㉢ сказано «много людей начинают приходить сюда (많은 사람들이 이곳을 찾기 시작한다)» — естественное продолжение: люди собрались → торговля ожила. А после ㉢ идёт «그러나 (однако)» о риске чрезмерной коммерциализации — то есть позитивный пик уже описан.<br>✖️ ㉠/㉡ — там ещё нет «собравшихся людей» (только идёт обустройство переулков); ㉣ — уже идёт вывод, поток людей логически раньше.<br>🧩 골목 상권 — торговля в переулках; 활기를 띠다 — оживляться; 도시 재생 — городское обновление (реновация)."},{"n":40,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить данное предложение:<br><b>「즉, 열이 식는 속도와 균열이 생기는 방향에 따라 기둥의 굵기나 모양, 배열 형태가 달라지는 것이다.」</b>","passage":"주상절리는 화산 활동으로 인해 생긴 암석 지형이다. ( ㉠ ) 화산 활동이 끝나면 용암이 식으면서 열이 급격히 빠져나가게 된다. ( ㉡ ) 이 과정에서 표면에 작은 균열이 발생하는데 이 균열은 시간이 지나면서 점점 아래로 뻗어나가 기둥 모양을 이루게 된다. ( ㉢ ) 각기 다른 모양과 독특한 형태 때문에 오늘날에는 관광 명소로 널리 알려져 있다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b> — вставляемое предложение начинается с «즉 (то есть)» и поясняет, КАК образуются колонны: от скорости остывания и направления трещин зависят толщина, форма и расположение столбов. Прямо перед ㉢ как раз описано, что трещины ползут вниз и формируют форму столба (기둥 모양을 이루게 된다) — «즉…» подытоживает этот механизм.<br>✖️ ㉠/㉡ — механизм трещин ещё не описан, обобщать нечего; ㉣ — речь уже о туристической славе, а не о формировании.<br>🧩 주상절리 — столбчатая отдельность (базальтовые колонны); 균열 — трещина; 용암 — лава."},{"n":41,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить данное предложение:<br><b>「이러한 점에서 조선왕조실록은 단순한 역사 기록을 넘어 진실을 자세히 남기려 한 문화적 태도의 상징이라 할 수 있다.」</b>","passage":"조선왕조실록은 조선 시대의 국왕과 정치, 사회, 외교 등 국가 운영 전반을 연대순으로 기록한 역사서이다. ( ㉠ ) 이 기록은 왕이 사망한 뒤 특별한 기관을 만들어 사관들이 편찬하였다. ( ㉡ ) 사실을 왜곡하지 않고 충실히 기록하기 위해 국왕조차도 함부로 열람할 수 없도록 하였다. ( ㉢ ) 실록에는 왕의 말과 행동, 대신들의 논쟁, 백성의 삶까지 상세하게 담겨 있다. ( ㉣ ) 현재 조선왕조실록은 그 가치를 인정받아 유네스코 세계기록유산으로 등재되어 세계적인 역사 자료로 평가받고 있다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"✅ <b>④ ㉣</b> — вставляемое предложение начинается с «이러한 점에서 (в этом отношении)» и подытоживает ВСЕ ранее перечисленные черты: составление историографами, отказ от искажений, запрет даже королю читать, подробная запись всего. Поэтому оно идёт после последнего такого пункта (㉣) и перед финальной фразой о внесении в реестр ЮНЕСКО.<br>✖️ ㉠/㉡/㉢ — там перечисление ещё не завершено, обобщать рано.<br>🧩 조선왕조실록 — «Анналы династии Чосон»; 왜곡하다 — искажать; 사관 — придворный историограф; 세계기록유산 — реестр «Память мира» ЮНЕСКО."},{"n":42,"points":2,"instr":"Прочитайте отрывок и выберите чувство «재민» в подчёркнутой части.","passage":"재민은 오늘 생애 첫 월급을 받았다. 월급 통장을 확인하고 나니 마음 한편이 괜히 허전했다. 아버지께서 돌아가신 지 3년째 되는 날이어서 더욱 공허하게 느껴지는 것 같았다. 아버지가 살아 계셨다면 퇴근길에 아버지 댁에 들러 같이 밥 한 끼 했을지도 모를 일이었다. (중략)<br>재민의 아버지는 말이 없는 사람이었다. 늦게 퇴근하고도 말없이 아들을 위해 밥을 차렸고 주말이면 고장 난 전등을 갈거나 오래된 책상을 고치곤 했다. 재민은 중학생 시절에 그런 아버지의 모습이 답답하게 느껴지기도 했다. 가끔 다른 친구들의 아버지처럼 유쾌하게 농담을 주고받는 아버지를 상상한 적도 있었다. (중략)<br>입대 전 훈련소 앞에서 재민의 아버지는 덤덤하게 아들에게 봉투 하나를 건네며 말했다.<br>“필요한 거 있으면 쓰고 훈련 끝나면 전화 한번 줘라.”<br>그때 재민은 알겠다고 대답했지만 결국 아버지에게 전화를 한 건 입대한 지 6개월이 지난 어느 주말이었다. 그마저도 아버지와 통화는 하지 못했다. (중략)<br><u>재민은 아버지 번호를 눌러 보다가 천천히 손을 내렸다. 손에 쥔 휴대 전화가 유독 무겁게 느껴지는 날이었다.</u>","options":["서운하다","후회스럽다","후련하다","의심스럽다"],"answer":2,"explain":"✅ <b>② 후회스럽다</b> (полон сожаления): отец умер 3 года назад, при жизни был немногословным и заботливым, а Джэмин редко звонил ему; теперь, набрав номер, он опускает руку — телефон «кажется особенно тяжёлым». Это тяжесть запоздалого раскаяния.<br>✖️ ① 서운하다 «обидно» — обиды на отца нет; ③ 후련하다 «облегчение» — наоборот, тяжесть; ④ 의심스럽다 «подозрение» — ни к чему не относится.<br>🧩 후회스럽다 — испытывать сожаление; 허전하다 — пусто на душе; 덤덤하다 — невозмутимый, сдержанный."},{"n":43,"points":2,"instr":"Выберите то, что можно понять из содержания отрывка.","passage":"재민은 오늘 생애 첫 월급을 받았다. 월급 통장을 확인하고 나니 마음 한편이 괜히 허전했다. 아버지께서 돌아가신 지 3년째 되는 날이어서 더욱 공허하게 느껴지는 것 같았다. 아버지가 살아 계셨다면 퇴근길에 아버지 댁에 들러 같이 밥 한 끼 했을지도 모를 일이었다. (중략)<br>재민의 아버지는 말이 없는 사람이었다. 늦게 퇴근하고도 말없이 아들을 위해 밥을 차렸고 주말이면 고장 난 전등을 갈거나 오래된 책상을 고치곤 했다. 재민은 중학생 시절에 그런 아버지의 모습이 답답하게 느껴지기도 했다. 가끔 다른 친구들의 아버지처럼 유쾌하게 농담을 주고받는 아버지를 상상한 적도 있었다. (중략)<br>입대 전 훈련소 앞에서 재민의 아버지는 덤덤하게 아들에게 봉투 하나를 건네며 말했다.<br>“필요한 거 있으면 쓰고 훈련 끝나면 전화 한번 줘라.”<br>그때 재민은 알겠다고 대답했지만 결국 아버지에게 전화를 한 건 입대한 지 6개월이 지난 어느 주말이었다. 그마저도 아버지와 통화는 하지 못했다. (중략)<br>재민은 아버지 번호를 눌러 보다가 천천히 손을 내렸다. 손에 쥔 휴대 전화가 유독 무겁게 느껴지는 날이었다.","options":["재민의 아버지는 무뚝뚝한 사람이었다.","재민은 첫 월급을 받고 아버지 옷을 샀다.","재민은 아버지의 유쾌한 농담을 듣는 것을 좋아했다.","재민의 아버지는 훈련소 앞에서 아들에게 전화를 걸었다."],"answer":1,"explain":"✅ <b>①</b> — отец «말이 없는 사람», молча готовил сыну еду, чинил вещи, прощался «덤덤하게» → он был неразговорчивым, суховатым (무뚝뚝한) человеком.<br>✖️ ② про покупку одежды отцу в тексте нет (отец уже умер); ③ Джэмин лишь ВООБРАЖАЛ весёлого шутящего отца — таким отец не был; ④ отец не звонил — он отдал конверт и ПОПРОСИЛ сына позвонить.<br>🧩 무뚝뚝하다 — суровый, неразговорчивый; 덤덤하다 — без эмоций; 봉투 — конверт (с деньгами)."},{"n":44,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"19세기 중반에 등장한 인상주의는 기존 회화의 틀을 깨고 새로운 시도를 한 예술 사조였다. 이전까지의 회화는 사물의 형태와 구도를 정밀하게 묘사하는 데 집중했지만 인상주의 화가들은 자연의 빛과 색채가 순간순간 달라진다는 점에 주목했다. 이들은 정해진 구도나 윤곽선을 따르기보다 (　　) 보이는 인상을 그대로 표현하고자 했다. 하루 중 시간에 따라 빛의 색과 밝기가 변한다는 점에 착안해 같은 장소를 아침, 낮, 저녁 등 시간대별로 여러 번 그리기도 했다. 이는 빛과 색의 변화가 자연의 인상을 결정한다고 믿었던 인상주의 화가들의 생각을 잘 보여 준다. 대표적인 예로 모네는 지베르니 정원의 수련 연못을 250점 이상 그리며 시간과 날씨에 따라 달라지는 빛의 인상을 포착하려 했다. 인상주의는 정적인 재현에서 벗어나 시간성과 순간성을 회화에 도입한 점에서 예술사적 의미를 지닌다.","options":["있는 그대로의 자연을 관찰하며","상상력을 더해 자연을 단순화하며","특징적인 시간대에 자연을 담아내며","이상적인 형태로 자연을 재구성하며"],"answer":1,"explain":"✅ <b>① 있는 그대로의 자연을 관찰하며</b> — «наблюдая природу как она есть»: противопоставлено «정해진 구도나 윤곽선을 따르기보다 (вместо следования заданной композиции и контурам)» — то есть они смотрели на саму натуру и передавали впечатление как видели.<br>✖️ ② «упрощая природу воображением» и ④ «перестраивая в идеальную форму» — противоречат идее фиксировать реальное впечатление; ③ «в характерное время» — это лишь следствие (в следующем предложении), а в самом пропуске нужен контраст «как есть».<br>🧩 인상주의 — импрессионизм; 윤곽선 — контур; 있는 그대로 — как есть."},{"n":45,"points":2,"instr":"Выберите главную тему текста.","passage":"19세기 중반에 등장한 인상주의는 기존 회화의 틀을 깨고 새로운 시도를 한 예술 사조였다. 이전까지의 회화는 사물의 형태와 구도를 정밀하게 묘사하는 데 집중했지만 인상주의 화가들은 자연의 빛과 색채가 순간순간 달라진다는 점에 주목했다. 이들은 정해진 구도나 윤곽선을 따르기보다 (　　) 보이는 인상을 그대로 표현하고자 했다. 하루 중 시간에 따라 빛의 색과 밝기가 변한다는 점에 착안해 같은 장소를 아침, 낮, 저녁 등 시간대별로 여러 번 그리기도 했다. 이는 빛과 색의 변화가 자연의 인상을 결정한다고 믿었던 인상주의 화가들의 생각을 잘 보여 준다. 대표적인 예로 모네는 지베르니 정원의 수련 연못을 250점 이상 그리며 시간과 날씨에 따라 달라지는 빛의 인상을 포착하려 했다. 인상주의는 정적인 재현에서 벗어나 시간성과 순간성을 회화에 도입한 점에서 예술사적 의미를 지닌다.","options":["인상주의는 형태보다 빛의 순간적인 변화를 중시하였다.","인상주의 화가인 모네는 수련을 주제로 다양한 작품을 남겼다.","구도나 윤곽선을 관찰하여 묘사하는 것이 인상주의 회화의 특징이다.","정적인 재현을 통해 자연을 표현하는 인상주의 화풍의 가치가 뛰어나다."],"answer":1,"explain":"✅ <b>①</b> — главная мысль: импрессионисты сосредоточились не на форме и композиции, а на мгновенных изменениях света и цвета (순간성·시간성).<br>✖️ ② Моне с кувшинками — лишь ПРИМЕР, не тема; ③ «наблюдать композицию и контуры» — это СТАРАЯ живопись, импрессионизм её отверг; ④ «статичная репрезентация» — наоборот, импрессионизм ушёл ОТ неё (정적인 재현에서 벗어나).<br>🧩 형태 — форма; 순간적인 변화 — мгновенное изменение; 중시하다 — придавать большое значение."},{"n":46,"points":2,"instr":"Выберите позицию (отношение) автора, выраженную в тексте.","passage":"최근 인공 지능 기술이 의료, 금융, 제조업 등 다양한 분야에서 활용되면서 인간의 삶에 큰 변화를 가져오고 있다. 그러나 인공 지능 기술의 급속한 발전은 사회적·윤리적 문제에 대한 우려도 함께 키우고 있다. 대표적으로 인공 지능이 생성하는 편향된 정보, 개인정보 침해, 인간의 일자리를 대체하는 문제 등이 지적된다. 특히 채용 과정이나 법률 자문과 같은 중요한 의사 결정에서 인공 지능이 인간의 편견을 그대로 학습해 재생산할 가능성이 제기되고 있다. 이로 인해 사회적 약자나 소수 집단이 불이익을 받을 우려가 있다. 이에 따라 전문가들은 인공 지능 개발 단계에서부터 윤리적 기준을 명확히 설정해야 한다고 강조한다. 정부와 기업은 공동으로 윤리 가이드라인을 마련하고 법적 규제를 통해 강제할 필요가 있다. 단순히 자율 규제에만 맡긴다면 기업들은 비용 절감이나 효율성만을 우선시하여 윤리적 책임을 소홀히 할 위험이 있기 때문이다. 기술의 발전은 필연적이지만 그로 인한 부작용을 최소화하려는 노력이 병행되지 않는다면 인공 지능이 초래할 사회적 문제는 더욱 심각해질 수 있다.","options":["인공 지능 기술 확산을 긍정적으로 평가하고 있다.","인공 지능 기술의 정보 전망 문제를 지적하고 있다.","인공 지능으로 인한 다양한 변화에 대해 설명하고 있다.","인공 지능 발전에 따른 윤리적 규제의 필요성을 강조하고 있다."],"answer":4,"explain":"✅ <b>④</b> — позиция автора: эксперты «강조한다» о ранней этической планке, нужны совместные гайдлайны и «법적 규제를 통해 강제할 필요가 있다» → автор подчёркивает необходимость этического регулирования ИИ.<br>✖️ ① «оценивает положительно» — тон предостерегающий, не хвалебный; ② «정보 전망 문제» — искажённая формулировка, не отражает позицию; ③ «просто описывает изменения» — автор идёт дальше описания и ПРИЗЫВАЕТ к регулированию.<br>🧩 강조하다 — подчёркивать; 윤리적 규제 — этическое регулирование; 법적 규제 — правовое регулирование."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 인공 지능 기술이 의료, 금융, 제조업 등 다양한 분야에서 활용되면서 인간의 삶에 큰 변화를 가져오고 있다. 그러나 인공 지능 기술의 급속한 발전은 사회적·윤리적 문제에 대한 우려도 함께 키우고 있다. 대표적으로 인공 지능이 생성하는 편향된 정보, 개인정보 침해, 인간의 일자리를 대체하는 문제 등이 지적된다. 특히 채용 과정이나 법률 자문과 같은 중요한 의사 결정에서 인공 지능이 인간의 편견을 그대로 학습해 재생산할 가능성이 제기되고 있다. 이로 인해 사회적 약자나 소수 집단이 불이익을 받을 우려가 있다. 이에 따라 전문가들은 인공 지능 개발 단계에서부터 윤리적 기준을 명확히 설정해야 한다고 강조한다. 정부와 기업은 공동으로 윤리 가이드라인을 마련하고 법적 규제를 통해 강제할 필요가 있다. 단순히 자율 규제에만 맡긴다면 기업들은 비용 절감이나 효율성만을 우선시하여 윤리적 책임을 소홀히 할 위험이 있기 때문이다. 기술의 발전은 필연적이지만 그로 인한 부작용을 최소화하려는 노력이 병행되지 않는다면 인공 지능이 초래할 사회적 문제는 더욱 심각해질 수 있다.","options":["인공 지능 기술은 다양한 분야에서 일자리 창출에 기여한다.","제품 과정에서 인공 지능을 활용하면 제품 공정성이 높아진다.","개인정보 침해가 인공 지능 기술의 문제점으로 지적되고 있다.","정부는 인공 지능 기술 확산을 억제하기 위한 규제를 시행 중이다."],"answer":3,"explain":"✅ <b>③</b> — «대표적으로 … 개인정보 침해 … 등이 지적된다» → нарушение приватности названо одной из проблем ИИ.<br>✖️ ① наоборот: ИИ «일자리를 대체하는 문제» (замещает рабочие места), а не создаёт их; ② про «справедливость продукции» в тексте нет — ИИ как раз может воспроизводить предвзятость; ④ регулирование пока только НУЖНО ввести («필요가 있다»), а не «시행 중» (уже действует).<br>🧩 개인정보 침해 — нарушение неприкосновенности личных данных; 지적되다 — отмечаться (как недостаток); 시행 중 — в процессе применения."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"최근 기후 변화로 인한 이상 기후, 해수면 상승, 생태계 파괴 등 환경 문제가 심각해지고 있다. 이에 따라 전 세계는 온실가스 배출을 줄이고 탄소 중립 사회로의 전환을 추진하고 있다. 탄소 중립이란 인간의 활동으로 발생하는 이산화 탄소의 양과 이를 흡수하거나 제거하는 양을 같게 만들어 (　　) 것을 목표로 한다. 이를 달성하기 위해 각국 정부는 산업 전반에 걸쳐 탄소 배출을 줄이기 위한 법과 제도를 정비하고 있으며, 기업은 생산 과정에서 친환경 기술과 에너지 절감 방안을 도입하고 있다. 또한 시민들 역시 에너지 절약, 친환경 소비, 대중교통 이용 등 일상생활 속 실천을 통해 탄소 중립에 기여할 수 있다. 하지만 일각에서는 탄소 중립 달성의 부담을 개인에게 과도하게 전가하는 것이 아니냐는 비판도 제기된다. 구조적 변화 없이 시민의 자발적 실천만을 강조할 경우 실질적인 효과를 내기 어렵다는 지적이다. 따라서 탄소 중립은 특정 주체의 노력에만 맡길 것이 아니라 사회 전체가 각자의 책임을 다하며 협력해야 실현 가능한 과제라고 할 수 있다.","options":["탄소 중립 정책이 실패하는 원인을 분석하려고","탄소 중립의 개념과 역사적 기원을 설명하려고","탄소 중립을 위한 다양한 실천 방법을 소개하려고","탄소 중립 달성을 위한 공동의 책임을 강조하려고"],"answer":4,"explain":"✅ <b>④</b> — цель текста: вывод «사회 전체가 각자의 책임을 다하며 협력해야 실현 가능한 과제» → автор подчёркивает ОБЩУЮ ответственность за достижение углеродной нейтральности.<br>✖️ ① «анализ причин провала политики» — текст не о провале; ② «понятие даётся, но «역사적 기원» (исторические истоки) не раскрываются — это не цель; ③ способы практики лишь перечислены как пример, а не главная цель — текст спорит с перекладыванием бремени только на индивида.<br>🧩 탄소 중립 — углеродная нейтральность; 공동의 책임 — общая ответственность; 강조하다 — подчёркивать."},{"n":49,"points":2,"instr":"Выберите наиболее подходящее выражение в ( ).","passage":"최근 기후 변화로 인한 이상 기후, 해수면 상승, 생태계 파괴 등 환경 문제가 심각해지고 있다. 이에 따라 전 세계는 온실가스 배출을 줄이고 탄소 중립 사회로의 전환을 추진하고 있다. 탄소 중립이란 인간의 활동으로 발생하는 이산화 탄소의 양과 이를 흡수하거나 제거하는 양을 같게 만들어 (　　) 것을 목표로 한다. 이를 달성하기 위해 각국 정부는 산업 전반에 걸쳐 탄소 배출을 줄이기 위한 법과 제도를 정비하고 있으며, 기업은 생산 과정에서 친환경 기술과 에너지 절감 방안을 도입하고 있다. 또한 시민들 역시 에너지 절약, 친환경 소비, 대중교통 이용 등 일상생활 속 실천을 통해 탄소 중립에 기여할 수 있다. 하지만 일각에서는 탄소 중립 달성의 부담을 개인에게 과도하게 전가하는 것이 아니냐는 비판도 제기된다. 구조적 변화 없이 시민의 자발적 실천만을 강조할 경우 실질적인 효과를 내기 어렵다는 지적이다. 따라서 탄소 중립은 특정 주체의 노력에만 맡길 것이 아니라 사회 전체가 각자의 책임을 다하며 협력해야 실현 가능한 과제라고 할 수 있다.","options":["친환경 소비를 장려하는","실질적인 탄소 배출을 없애는","온실가스 감축 기술을 개발하는","재생 에너지를 보급하고 활용하는"],"answer":2,"explain":"✅ <b>② 실질적인 탄소 배출을 없애는</b> — «свести на нет фактические выбросы»: углеродная нейтральность = сделать объём выброшенного CO₂ равным объёму поглощённого/удалённого, то есть «нетто-ноль» (실질적인 배출 = 0).<br>✖️ ① «поощрять эко-потребление», ③ «разрабатывать технологии сокращения», ④ «внедрять ВИЭ» — это СПОСОБЫ достижения, упомянутые дальше, а в самом определении нужен результат «нулевых чистых выбросов».<br>🧩 탄소 중립 = нетто-ноль; 흡수/제거 — поглощение/удаление; 없애다 — сводить к нулю, устранять."},{"n":50,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 기후 변화로 인한 이상 기후, 해수면 상승, 생태계 파괴 등 환경 문제가 심각해지고 있다. 이에 따라 전 세계는 온실가스 배출을 줄이고 탄소 중립 사회로의 전환을 추진하고 있다. 탄소 중립이란 인간의 활동으로 발생하는 이산화 탄소의 양과 이를 흡수하거나 제거하는 양을 같게 만들어 (　　) 것을 목표로 한다. 이를 달성하기 위해 각국 정부는 산업 전반에 걸쳐 탄소 배출을 줄이기 위한 법과 제도를 정비하고 있으며, 기업은 생산 과정에서 친환경 기술과 에너지 절감 방안을 도입하고 있다. 또한 시민들 역시 에너지 절약, 친환경 소비, 대중교통 이용 등 일상생활 속 실천을 통해 탄소 중립에 기여할 수 있다. 하지만 일각에서는 탄소 중립 달성의 부담을 개인에게 과도하게 전가하는 것이 아니냐는 비판도 제기된다. 구조적 변화 없이 시민의 자발적 실천만을 강조할 경우 실질적인 효과를 내기 어렵다는 지적이다. 따라서 탄소 중립은 특정 주체의 노력에만 맡길 것이 아니라 사회 전체가 각자의 책임을 다하며 협력해야 실현 가능한 과제라고 할 수 있다.","options":["환경 문제는 각국 정부의 강력한 규제로 해결해야 한다.","실질적인 효과를 위해 구조적 변화가 앞서 이루어져야 한다.","기업의 활발한 산업 활동 확대로 온실가스를 감축할 수 있다.","개인의 생활 속 실천이 가장 효과적인 탄소 중립 대응책이다."],"answer":2,"explain":"✅ <b>②</b> — «구조적 변화 없이 시민의 자발적 실천만을 강조할 경우 실질적인 효과를 내기 어렵다» → для реального эффекта необходимы структурные изменения, а не только личные усилия.<br>✖️ ① «решать только сильным госрегулированием» — текст подчёркивает участие ВСЕХ (사회 전체), а не одного субъекта; ③ «расширение промышленной деятельности сократит выбросы» — нелогично и не из текста; ④ «личная практика — самый эффективный способ» — текст КРИТИКУЕТ переваливание бремени на индивида.<br>🧩 구조적 변화 — структурные изменения; 자발적 실천 — добровольные действия; 전가하다 — перекладывать (ответственность)."}]},
      writing: {"durationMin":50,"label":"EBS 모의고사 제1회 · 쓰기 (51~54)","tasks":[{"n":51,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Это памятка банка (인주은행) клиенту — формальный стиль -ㅂ니다/-야 합니다.","passage":"📋 인주은행 회원 가입 안내 (고객 센터)\n\n비밀번호는 다른 사람이 쉽게 알 수 있는 것으로 만들면 위험합니다. 전화번호나 생일은 사용하지 말고 문자와 숫자를 ( ㉠ ). 그리고 안전을 위해 비밀번호를 가끔 ( ㉡ ).","blanks":[{"slot":"㉠","model":"섞어서 만들어야 합니다","check":"«전화번호나 생일은 사용하지 말고 문자와 숫자를 ( )» → не использовать телефон/день рождения, а буквы и цифры СМЕШАТЬ при создании: 섞어서 만들어야 합니다. Формальный стиль -야 합니다."},{"slot":"㉡","model":"변경해야 합니다","check":"«안전을 위해 비밀번호를 가끔 ( )» → для безопасности пароль время от времени МЕНЯТЬ: 변경해야 합니다 / 바꿔야 합니다. Стиль -야 합니다."}]},{"n":52,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст о вкусе и запахе — письменный стиль -다.","passage":"음식의 맛은 입안에서만 느끼는 것이 아니라 냄새도 큰 영향을 준다. 사람이 음식을 먹을 때 코로 ( ㉠ ) 혀로 느낄 수 없는 향과 맛의 차이를 더 잘 구별할 수 있다. 반대로 감기에 걸려 코가 막히면 평소 좋아하던 음식도 맛이 없는 것처럼 느껴진다. 이처럼 맛을 제대로 느끼려면 혀의 역할뿐 아니라 ( ㉡ )도 매우 중요하다.","blanks":[{"slot":"㉠","model":"냄새를 맡으면","check":"«음식을 먹을 때 코로 ( ) 혀로 느낄 수 없는 … 차이를 더 잘 구별할 수 있다» → если носом НЮХАТЬ запах, различаешь лучше: 냄새를 맡으면. Условие -으면."},{"slot":"㉡","model":"코의 역할","check":"«맛을 제대로 느끼려면 혀의 역할뿐 아니라 ( )도 매우 중요하다» → важна не только роль языка, но и РОЛЬ НОСА: 코의 역할. Параллель с 혀의 역할."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음은 「원격 근무 확산 이후 직장 문화」의 변화에 대한 자료이다. 이 내용을 200~300자의 글로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные об изменении рабочей культуры после распространения удалёнки текстом 200–300 знаков. Передайте динамику доли компаний (линейный график 2019→2022), долю имеющих опыт удалёнки (круговая) и плюсы/минусы. Письменный стиль -다, без заголовка.","image":"assets/topik2/exams/img/ebs1-w53.png","model":"원격 근무 시행 기업의 비율 변화를 살펴보면 2019년에서 2020년 사이에 원격 근무를 시행한 기업이 12.5%에서 54.3%로 급증했으나 이후 2021년 47.8%, 2022년 39.2%로 점차 감소하는 추세를 보이고 있다. 실제 원격 근무 경험에 대한 질문에 과반수가 경험이 있다고 대답했다. 원격 근무 실시 이후 변화에 대해 사람들은 업무 효율성이 증가하고 일과 삶의 균형이 향상되었다고 느꼈지만 동시에 서로 소통이 부족해지고 동료와의 거리감도 커졌다는 부정적인 측면도 느꼈다. 기업들은 이러한 부정적 변화로 원격 근무 시행을 줄이고 있는 것으로 보인다.","check":"① Описан график доли компаний с цифрами (2019→2020 рост 12.5%→54.3%, затем 2021년 47.8%, 2022년 39.2% спад)? ② Передан опыт удалёнки (과반수가 경험이 있다)? ③ Названы плюсы (업무 효율성↑, 일과 삶의 균형↑) и минусы (소통 부족, 동료와의 거리감↑)? ④ Вывод (기업들이 원격 근무 시행을 줄이는 추세)? ⑤ Стиль -다, 200~300 знаков, без заголовка?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 참고하여 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков о важности отдыха и реальных способах его обеспечить. Раскройте все три вопроса, разбейте на абзацы (важность / проблемы при недостатке / решения личное и общественное), письменный стиль -다.","passage":"현대인은 바쁜 일상과 끊임없는 경쟁 속에서 휴식의 중요성을 자주 간과하곤 한다. 그러나 충분한 휴식은 신체적 건강뿐만 아니라 정신적 안정, 일의 효율성에도 큰 영향을 미친다. 아래의 내용을 중심으로 휴식의 중요성과 이를 실천하기 위한 현실적인 방안에 대한 자신의 생각을 쓰라.\n• 휴식이 중요한 이유는 무엇인가?\n• 충분한 휴식을 취하지 못할 경우 어떤 문제가 생기는가?\n• 건강한 휴식 문화를 만들기 위한 방안은 무엇인가?","model":"현대 사회의 치열한 경쟁 속에서 많은 사람들이 일상에 쫓겨 충분한 휴식을 취하지 못하고 있다. 그러나 휴식은 단순히 일을 멈추는 것이 아니라, 신체와 정신을 회복시키고 삶의 질을 향상시키는 중요한 행위이다. 휴식을 통해 우리는 에너지를 재충전하고 스트레스를 완화하며, 더 나아가 창의적인 사고와 효율적인 업무 수행이 가능하다.\n만약 충분한 휴식을 취하지 못한다면 다양한 문제가 발생할 수 있다. 육체적으로는 피로가 누적되어 면역력이 약해지고 병으로 이어질 수 있다. 정신적으로 우울감, 불안이 증가하며, 이는 정신 건강 문제로 이어질 수 있다. 이러한 상태가 지속되면 개인의 삶은 물론 사회 전체에도 부정적인 영향을 미치게 된다.\n이러한 문제를 해결하기 위해서는 개인과 사회가 함께 노력해야 한다. 개인은 일과 휴식의 균형을 스스로 조절하려고 노력해야 한다. 주말이나 여가 시간에는 일과 완전히 분리된 활동을 하며 재충전해야 한다. 기업과 조직은 구성원들이 휴식을 충분히 취할 수 있도록 정시 퇴근, 휴가 사용 권장, 휴식 공간 제공 등 제도적 장치를 만들어야 한다. 마지막으로 사회 전체도 휴식을 긍정적으로 인식하는 문화가 확산되어야 한다. 우리는 휴식의 가치를 재인식하고, 바쁜 일상 속에서도 스스로를 돌보는 시간을 의도적으로 마련해야 한다.","check":"① Раскрыт 1-й вопрос — почему отдых важен (восстановление тела/духа, ↑эффективности и креативности)? ② Раскрыт 2-й вопрос — проблемы при недостатке (физически: усталость, ↓иммунитета, болезни; психически: депрессия, тревога; влияние на общество)? ③ Раскрыт 3-й вопрос — решения: личное (баланс работа/отдых, отдельная от работы деятельность) + компании (정시 퇴근, отпуска, зоны отдыха) + общество (культура позитивного отношения к отдыху)? ④ Три абзаца, связки 그러나·만약·이러한 문제를 해결하기 위해서는·마지막으로? ⑤ Стиль -다, 600~700 знаков, без дословного переписывания задания?"}]}
    },
    102: {
      listening: {
        durationMin: 60, total: 100, label: '제102회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/102/102-TOPIK-II-Listening-Audio-File.mp3',
        questions: [{"n":1,"points":2,"image":"assets/topik2/exams/img/102-l-q1.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 이 책을 소포로 보내고 싶은데요. 소포 상자 살 수 있지요?<br>여자: 네, 손님. 상자는 이쪽에서 고르시면 돼요.<br>남자: 네, 한번 볼게요.<br><br>На почте: мужчина хочет отправить книгу посылкой, сотрудница показывает, где выбрать коробку.<br>✅ <b>②</b> — у стойки почты, стопки коробок-посылок, сотрудница и клиент.<br>🧩 소포 = «посылка»; 상자 = «коробка»."},{"n":2,"points":2,"image":"assets/topik2/exams/img/102-l-q2.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":1,"explain":"🎧 여자: 어, 낚싯대가 움직인다. 물고기 잡은 것 같아.<br>남자: 그래? 낚싯대 잘 잡고 천천히 당겨서 올려 봐.<br>여자: 응, 그런데 진짜 무겁다.<br><br>У воды: женщина поймала рыбу (удочка дёргается), мужчина советует тянуть.<br>✅ <b>①</b> — женщина тянет удочку с уловом, мужчина рядом у реки.<br>🧩 낚싯대 = «удочка»; 당기다 = «тянуть»."},{"n":3,"points":2,"image":"assets/topik2/exams/img/102-l-q3.png","instr":"Прослушайте и выберите подходящий график.","options":["①","②","③","④"],"answer":3,"explain":"🎧 남자: …최근 1년간 친환경 농산물을 구매한 적이 있다는 응답이 76%로 나타났습니다. 친환경 농산물 구매 이유로는 '건강을 위해서'가 1위를 차지했으며, '환경 보호를 위해서', '품질이 좋아서'가 그 뒤를 이었습니다.<br><br>Опыт покупки эко-продуктов: «있다» 76%. Причины: 1) для здоровья, 2) ради экологии, 3) хорошее качество.<br>✅ <b>③</b> — столбцы причин в порядке 건강 &gt; 환경 보호 &gt; 품질.<br>✖️ ① «있다 24%» неверно, ② «있다 67%» неверно, ④ порядок причин (품질 1위) не тот.<br>🧩 친환경 농산물 = «эко-продукция»."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["카페를 찾고 있어.","같이 들어가 보자.","벌써 만난 것 같아.","차를 마시기로 했어."],"answer":2,"explain":"🎧 남자: 우리 차 한잔할까? 저 카페 어때?<br>여자: 그래. 분위기 좋아 보인다.<br>남자: ____<br><br>Кафе нравится обоим → предложить зайти.<br>✅ <b>② 같이 들어가 보자.</b> (давай зайдём вместе).<br>✖️ ① «ищу кафе» (оно уже найдено), ③ «кажется, уже встретились», ④ «решили выпить чаю» — не отвечают на «분위기 좋아 보인다».<br>🧩 분위기 = «атмосфера»."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["신발장에서 꺼내 줄게.","이게 네 운동화였구나.","하얀색 신발이면 좋겠어.","아까 찾을 때는 없었는데."],"answer":4,"explain":"🎧 여자: 민수야, 내 하얀색 운동화 못 봤어? 아무리 찾아도 안 보여.<br>남자: 그거 신발장 위쪽에 있던데.<br>여자: ____<br><br>Парень говорит, что кроссовки на полке; она удивляется.<br>✅ <b>④ 아까 찾을 때는 없었는데.</b> (а когда я искала, их там не было).<br>✖️ ① «достану с полки» (это бы сказал он), ② «так это твои кроссовки?», ③ «хочу белые туфли» — не по контексту.<br>🧩 신발장 = «обувница»; 운동화 = «кроссовки»."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그럼 관심이 없는 거네요.","아르바이트 경험이 다양해요.","그럼 사무실에 한번 가 보세요.","좋은 곳을 구했다니 다행이에요."],"answer":3,"explain":"🎧 남자: 학과 사무실에서 아르바이트할 사람을 찾던데 혹시 관심 있어요?<br>여자: 네. 그렇지 않아도 아르바이트를 하고 싶어서 알아보고 있었어요.<br>남자: ____<br><br>Она заинтересована в подработке → совет сходить в офис.<br>✅ <b>③ 그럼 사무실에 한번 가 보세요.</b><br>✖️ ① «значит, не интересно» (наоборот), ② «у меня разный опыт подработок», ④ «рад, что нашли место» — она ещё не нашла.<br>🧩 학과 사무실 = «деканат, офис кафедры»."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["곧 개봉할 예정이래.","올해는 작품상을 받을 거야.","영화감독이 되려고 준비한대.","요즘 영화는 소재가 다 비슷해."],"answer":1,"explain":"🎧 여자: 김민수 감독 영화가 유명한 국제 영화제에서 작품상을 받았대.<br>남자: 맞아. … 국내에선 언제쯤 볼 수 있을까?<br>여자: ____<br><br>Парень спрашивает, когда выйдет в стране → скоро.<br>✅ <b>① 곧 개봉할 예정이래.</b> (говорят, скоро выйдет в прокат).<br>✖️ ② «в этом году получит приз» (уже получил), ③ «готовится стать режиссёром», ④ «фильмы похожи» — не отвечают на «언제 볼 수 있을까?».<br>🧩 개봉하다 = «выходить в прокат»; 작품상 = «приз за лучший фильм»."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["네. 받으실 주소를 말씀해 주세요.","네. 카드를 신청하시는 분이 많네요.","네. 언제 받으셨는지 확인해 볼게요.","네. 재발급 신청서를 작성하시면 돼요."],"answer":1,"explain":"🎧 남자: 고객님, 오늘 재발급 신청하신 카드는 직접 받으셔야 합니다.<br>여자: 그러면 직장으로 배송해 주시겠어요?<br>남자: ____<br><br>Она просит доставить на работу → нужен адрес.<br>✅ <b>① 네. 받으실 주소를 말씀해 주세요.</b><br>✖️ ② «много кто оформляет карту», ③ «проверю, когда получили», ④ «заполните заявление на перевыпуск» — она уже оформила.<br>🧩 재발급 = «перевыпуск»; 배송하다 = «доставлять»."},{"n":9,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["물을 마신다.","의자에 앉는다.","놀이기구를 탄다.","음료수를 사러 간다."],"answer":4,"explain":"🎧 여자: 놀이기구는 많이 탔으니까 이제 잠깐 쉬는 게 어때?<br>남자: 좋아. … 시원한 거 마시면서 좀 쉬자.<br>여자: 그래. 음료수는 내가 사 올 테니까 너는 여기 잠깐 앉아 있어.<br>남자: 고마워. 나는 물 한 병만 부탁해.<br><br>Женщина пойдёт ЗА напитками.<br>✅ <b>④ 음료수를 사러 간다.</b> — «음료수는 내가 사 올 테니까».<br>✖️ ② сесть на стул — это мужчина, ① пить воду / ③ кататься — позже/не она.<br>🧩 놀이기구 = «аттракцион»; 음료수 = «напиток»."},{"n":10,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["창고에 간다.","다른 옷을 구경한다.","티셔츠를 입어 본다.","직원에게 영수증을 받는다."],"answer":2,"explain":"🎧 여자: 이 티셔츠, 교환하려고요. 입어 보니까 좀 작네요.<br>남자: 영수증 주시고요. … 한 사이즈 큰 걸로 갖다드릴게요.<br>여자: 네, 영수증 여기 있어요. 저는 다른 옷들도 좀 볼게요.<br>남자: 네, 금방 창고에 다녀오겠습니다.<br><br>Пока продавец идёт на склад, женщина посмотрит другую одежду.<br>✅ <b>② 다른 옷을 구경한다.</b> — «저는 다른 옷들도 좀 볼게요».<br>✖️ ① на склад идёт продавец, ③ примерить — уже примерила, ④ она ОТДАЁТ чек, а не получает.<br>🧩 교환하다 = «обменять»; 영수증 = «чек»."},{"n":11,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["수업에 들어간다.","발표 자료를 복사한다.","복사기의 전원을 켠다.","복사기에 종이를 넣는다."],"answer":4,"explain":"🎧 여자: 민수야, 발표 자료 다 복사했어? …<br>남자: 복사기가 고장 났나 봐. 복사가 안 돼.<br>여자: 아, 종이가 없네. 내가 종이 넣어 줄게.<br>남자: … 전원을 껐다 켰는데도 안 되더라고.<br><br>Женщина увидела, что нет бумаги, → вставит её.<br>✅ <b>④ 복사기에 종이를 넣는다.</b> — «내가 종이 넣어 줄게».<br>✖️ ③ включал/выключал питание — это уже сделал мужчина, ① уйти на пару / ② копировать — позже.<br>🧩 복사기 = «копир»; 전원 = «питание»."},{"n":12,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["명함의 연락처로 연락한다.","워크숍 장소를 예약한다.","부장님을 만나러 간다.","강사의 명함을 준다."],"answer":1,"explain":"🎧 남자: 신입 사원 워크숍 준비는 어떻게 되고 있어요?<br>여자: 장소 예약은 완료했고 … 특강해 주실 분을 아직 못 찾았습니다.<br>남자: 그럼 특강 강사로 이분께 한번 연락해 보세요. 여기 명함 있어요.<br>여자: 네, 가능하신지 지금 확인해 보겠습니다.<br><br>Женщина свяжется с лектором по визитке.<br>✅ <b>① 명함의 연락처로 연락한다.</b><br>✖️ ② место уже забронировано, ③ к начальнику не идёт, ④ визитку даёт мужчина.<br>🧩 명함 = «визитка»; 특강 = «спецлекция»."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 택배를 주문하지 않았다.","여자는 택배 도착 문자를 받지 못했다.","여자가 주문한 택배는 동아리 방에 있다.","남자는 여자와 함께 관리실에 갈 것이다."],"answer":4,"explain":"🎧 여자: 동아리 방으로 주문한 택배, 왔다는 문자는 받았는데 안 보이네.<br>남자: 택배는 이제 일 층 관리실에서 찾는 걸로 바뀌었어.<br>여자: 그럼 지금 관리실에 가 봐야겠다.<br>남자: 같이 가. 나도 택배 시킨 거 있어.<br><br>✅ <b>④ Мужчина пойдёт в управляющий офис вместе с женщиной.</b> — «같이 가».<br>✖️ ① не заказывал — наоборот, «나도 택배 시킨 거 있어», ② не получала смс — наоборот, «문자는 받았는데», ③ посылка в клубной комнате — теперь её выдают в офисе.<br>🧩 택배 = «доставка/посылка»; 관리실 = «управляющий офис»."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["입장권 문의는 온라인으로 할 수 있다.","구입한 입장권은 환불이 불가능하다.","내일 경기는 오전에 열릴 예정이다.","비가 그쳐 경기가 다시 시작되었다."],"answer":1,"explain":"🎧 (안내방송) … 갑자기 내리는 비로 오늘 경기는 더 이상 진행이 어렵습니다. 경기는 내일 오후 두 시에 다시 열릴 예정이며 구입하신 입장권은 … 환불 받으실 수 있습니다. 입장권 관련 문의는 홈페이지나 … 안내소를 이용해 주십시오.<br><br>✅ <b>① Вопросы по билетам можно задать онлайн.</b> — «홈페이지나 … 이용».<br>✖️ ② билет не вернуть — наоборот, «환불 받으실 수 있습니다», ③ утром — нет, «오후 두 시», ④ дождь прекратился, игра пошла — наоборот, сегодня отменена.<br>🧩 입장권 = «билет»; 환불 = «возврат денег»."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["정부는 이 교통 카드를 지난달에 출시했다.","실물 카드와 모바일 카드 중 선택할 수 있다.","수익금의 일부가 기후 관련 단체로 전달된다.","공공 자전거 요금 할인은 포함되어 있지 않다."],"answer":3,"explain":"🎧 남자: 정부는 … '기후교통카드'를 다음 달 출시합니다. 이 카드는 … 모바일 카드로만 발급되며 대중교통뿐만 아니라 공공 자전거 요금도 할인을 받을 수 있습니다. 카드 판매 수익금의 일부는 기후 관련 단체에 기부될 예정입니다.<br><br>✅ <b>③ Часть выручки передаётся климатическим организациям.</b><br>✖️ ① вышла в прошлом месяце — нет, «다음 달», ② выбор физ/мобильной — нет, «모바일로만», ④ нет скидки на велосипед — наоборот, «공공 자전거 요금도 할인».<br>🧩 출시 = «выпуск»; 수익금 = «выручка»; 기부 = «пожертвование»."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자의 업무는 전공과 관련이 없다.","여자는 작업에 클래식 음악을 활용한다.","여자의 업무는 제품 완성 후에 시작된다.","여자는 소리에 대한 전문 지식이 부족하다."],"answer":2,"explain":"🎧 남자: 가전제품에 쓰이는 작동음, 경고음 같은 소리를 만드신다고요?<br>여자: 네. … 이때 클래식 음악을 활용하기도 합니다. … 제품 개발 초기 단계부터 개발팀과 함께 일하고 … 제가 음악을 전공한 게 도움이 돼요.<br><br>✅ <b>② Женщина использует в работе классическую музыку.</b> — «클래식 음악을 활용하기도».<br>✖️ ① не связано со специальностью — наоборот, музыка-специальность помогает, ③ начинается после готового продукта — нет, «초기 단계부터», ④ не хватает знаний о звуке — наоборот, есть.<br>🧩 작동음 = «звук работы»; 가전제품 = «бытовая техника»."},{"n":17,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["신청한 책을 빨리 받고 싶다.","도서관 이용 교육이 필요하다.","책을 빌릴 수 있는 기간을 늘려야 한다.","신청 가능한 책의 수가 많아지면 좋겠다."],"answer":4,"explain":"🎧 남자: 도서관에 없는 책을 신청하고 싶은데 세 권밖에 못하네. 좀 아쉽다.<br>여자: 도서 구입 비용이 정해져 있으니까 그럴 거야.<br>남자: 요즘 새로 나오는 책들도 많은데 세 권은 너무 적은 것 같아.<br><br>✅ <b>④ Хочется, чтобы число книг, которые можно запросить, увеличилось.</b> — «세 권은 너무 적은 것 같아».<br>✖️ ① быстрее получить книги, ② нужно обучение пользованию, ③ продлить срок выдачи — он о КОЛИЧЕСТВЕ запрашиваемых книг.<br>🧩 신청하다 = «запрашивать»; 아쉽다 = «жаль»."},{"n":18,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["거실에 맞는 크기의 소파를 골라야 한다.","마음에 드는 색의 소파를 찾기가 어렵다.","관리하기 쉬운 소파를 구입하는 것이 좋다.","거실이 넓어 보이는 밝은색의 소파를 사고 싶다."],"answer":4,"explain":"🎧 남자: 우리 집 거실이 넓지 않으니까 밝은색이 좋겠지?<br>여자: … 밝은 건 관리가 힘드니까 어두운 걸로 하는 게 어때?<br>남자: 거실도 작은데 색까지 어두우면 더 좁아 보여서 안 좋을 것 같아.<br><br>✅ <b>④ Хочет светлый диван, чтобы гостиная казалась просторнее.</b><br>✖️ ① подобрать по размеру, ② трудно найти цвет, ③ выбрать удобный в уходе — он именно за СВЕТЛЫЙ ради простора.<br>🧩 거실 = «гостиная»; 좁아 보이다 = «казаться тесным»."},{"n":19,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["적극적인 직원이 들어오면 좋겠다.","능력이 뛰어난 직원을 뽑아야 한다.","업무 경력이 많은 직원이 필요하다.","일을 실수 없이 하는 것이 중요하다."],"answer":1,"explain":"🎧 여자: 신입 직원 … 어떤 사람들이 들어올까?<br>남자: 난 업무에 관심도 있고 의욕도 넘치는 사람들이 오면 좋겠어.<br>여자: 의욕만 앞서면 실수가 많지 않을까?<br>남자: 업무가 잘 돌아가려면 일을 좀 나서서 해야 빨리 익힐 수 있지.<br><br>✅ <b>① Хорошо бы пришли инициативные сотрудники.</b> — «의욕도 넘치는 … 나서서 해야».<br>✖️ ② брать самых способных, ③ нужен большой стаж, ④ важно работать без ошибок — он ценит ИНИЦИАТИВНОСТЬ.<br>🧩 의욕 = «энтузиазм»; 적극적 = «активный»."},{"n":20,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["진로 결정 전에 다양한 체험을 해야 한다.","학생을 대상으로 진로 교육이 강화되어야 한다.","새로 개발한 교육 자료에 대한 검토가 필요하다.","흥미로운 자료를 만들어야 교육 효과를 높일 수 있다."],"answer":4,"explain":"🎧 여자: 경찰관님이 진행하시는 진로 교육이 … 반응이 아주 좋습니다.<br>남자: … 글로만 쓰인 기존 자료는 흥미를 느끼기 어렵겠더라고요. 그래서 … 재미있게 담아서 영상을 만들었죠. 수업 집중도도 높아지고 … 아주 뿌듯해요.<br><br>✅ <b>④ Только интересные материалы повышают эффект обучения.</b><br>✖️ ① разный опыт до выбора пути, ② усилить профориентацию, ③ нужна проверка материалов — он о ПОЛЬЗЕ интересной подачи.<br>🧩 진로 교육 = «профориентация»; 집중도 = «концентрация»."},{"n":21,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["해외 판매를 위한 새로운 전략이 필요하다.","제품의 이미지는 시대에 따라 달라져야 한다.","현재 광고 모델을 그대로 유지하는 것이 좋다.","소비자 설문을 통해 광고 모델을 정해야 한다."],"answer":3,"explain":"🎧 여자: … 모델을 계속 이민우 씨로 할지 고민이 되네요. … 새 제품은 젊은 층을 대상으로 … 새로운 얼굴로 … 바꿔 보는 것도 좋을 것 같아요.<br>남자: 이민우 씨 덕분에 우리 회사 커피를 신뢰하는 소비자가 많아요. … 다양한 연령층에서 사랑을 받는 모델은 찾기 어려울 겁니다.<br><br>✅ <b>③ Лучше сохранить нынешнюю рекламную модель.</b> — за Ли Минву (доверие, любим всеми возрастами).<br>✖️ ① новая стратегия для экспорта, ② образ должен меняться со временем, ④ выбирать модель опросом — это доводы женщины.<br>🧩 광고 모델 = «рекламное лицо»; 유지하다 = «сохранять»."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 회사는 새 커피의 출시를 앞두고 있다.","이 회사의 커피는 해외에서 많이 팔리고 있다.","이 회사의 커피를 신뢰하지 않는 소비자가 많다.","이 회사의 커피 모델은 드라마에 나온 적이 없다."],"answer":1,"explain":"🎧 여자: 오랜만에 새로 출시할 커피인데 … 이번엔 처음으로 해외 판매도 준비 중이잖아요.<br><br>✅ <b>① Компания готовится к выпуску нового кофе.</b> — «새로 출시할 커피».<br>✖️ ② много продаётся за рубежом — наоборот, экспорт впервые готовят, ③ многие не доверяют — наоборот, «신뢰하는 소비자가 많아요», ④ модель не снималась в дораме — наоборот, «이민우 씨가 나오는 드라마».<br>🧩 출시를 앞두다 = «накануне выпуска»."},{"n":23,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["체육 대회 용품의 대여 일정을 변경하고 있다.","체육 대회 용품 대여의 자격과 기간을 묻고 있다.","대여 가능한 체육 대회 용품의 종류를 알아보고 있다.","대여한 체육 대회 용품의 반납 장소를 확인하고 있다."],"answer":2,"explain":"🎧 남자: … 동호회도 대여가 가능한가요?<br>여자: 그럼요. 대여하시는 분이 인주시 시민이면 됩니다. …<br>남자: … 금요일에 빌리면 반납은 언제까지 하면 될까요?<br><br>✅ <b>② Спрашивает о праве на аренду и сроке.</b> — «동호회도 가능한가요?» (자격) + «반납은 언제까지?» (기간).<br>✖️ ① меняет график, ③ узнаёт виды инвентаря, ④ уточняет место возврата — он именно про условия и срок.<br>🧩 대여 = «прокат»; 자격 = «право/требование»; 반납 = «возврат»."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["대여한 용품은 이용 당일에 반납해야 한다.","남자는 오늘 체육 대회 용품을 받으러 갈 예정이다.","체육 대회 용품을 대여하려면 전화로 예약해야 한다.","인주 시민이 아니어도 체육 대회 용품 대여가 가능하다."],"answer":3,"explain":"🎧 여자: 전화로 먼저 예약하신 후에 받으러 오실 때 신분증 가지고 오시면 돼요. … 일주일 안에만 반납하시면 됩니다.<br><br>✅ <b>③ Чтобы взять инвентарь напрокат, нужно забронировать по телефону.</b> — «전화로 먼저 예약».<br>✖️ ① вернуть в тот же день — нет, в течение недели, ② идёт сегодня — нет, около пятницы, ④ можно не жителю — нет, «인주시 시민이면 됩니다».<br>🧩 예약하다 = «бронировать»; 신분증 = «удостоверение»."},{"n":25,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["합창단을 체계적으로 관리할 필요가 있다.","합창은 노인들의 삶에 긍정적인 영향을 준다.","합창은 오랜 기간 함께 연습하는 것이 중요하다.","합창단원의 연령대를 다양하게 구성하는 것이 좋다."],"answer":2,"explain":"🎧 남자: … 합창이 이분들께 삶의 원동력과 행복을 주고 있습니다. … 소속감도 느끼고 삶의 에너지도 얻는 거죠. … 이런 성취감이 어르신들의 정체성 회복에도 도움이 됩니다.<br><br>✅ <b>② Хоровое пение положительно влияет на жизнь пожилых.</b><br>✖️ ① системно управлять хором, ③ важны долгие репетиции, ④ разнообразить возраст — он о ПОЛЬЗЕ хора для стариков.<br>🧩 합창 = «хоровое пение»; 소속감 = «чувство принадлежности»."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 합창단의 자격은 나이와 상관없다.","이 합창단은 정기적으로 노래 연습을 한다.","이 합창단은 이번에 첫 번째 공연을 마쳤다.","이 합창단 공연에 대한 반응이 좋지 않았다."],"answer":2,"explain":"🎧 남자: 매주 한 번씩 만나 화음을 맞추며 노래하는 … 얼마 전 여덟 번째 공연을 성공적으로 마쳤는데요.<br><br>✅ <b>② Этот хор регулярно репетирует.</b> — «매주 한 번씩 만나 … 노래하는».<br>✖️ ① возраст не важен — нет, 70+ лет, ③ первое выступление — нет, восьмое, ④ плохая реакция — наоборот, «성공적으로 마쳤».<br>🧩 정기적으로 = «регулярно»; 공연 = «выступление»."},{"n":27,"points":2,"instr":"Прослушайте и выберите намерение мужчины.","options":["서비스 이용 시간을 알리려고","서비스 이용 신청을 부탁하려고","서비스를 이용한 경험을 공유하려고","서비스 이용의 불편 사항을 말하려고"],"answer":3,"explain":"🎧 남자: 세무사가 청년 사업자들을 만나서 무료로 세금 상담을 해 주는 서비스가 있더라. 내가 얼마 전에 해 봤는데 도움이 많이 됐어.<br><br>✅ <b>③ Поделиться опытом пользования услугой.</b> — «내가 … 해 봤는데 도움이 많이 됐어».<br>✖️ ① сообщить часы работы, ② попросить подать заявку, ④ рассказать о неудобствах — он именно ДЕЛИТСЯ опытом.<br>🧩 세무사 = «налоговый консультант»; 무료 = «бесплатно»."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자는 창업을 해 본 적이 없다.","이 서비스는 이용 대상에 제한이 없다.","이 서비스는 비용을 내야 이용할 수 있다.","남자는 최근 세무사를 만나서 상담을 받았다."],"answer":4,"explain":"🎧 남자: 내가 얼마 전에 해 봤는데 도움이 많이 됐어. … 연 소득이 5천만 원 이하면 신청할 수 있어.<br><br>✅ <b>④ Мужчина недавно консультировался у налогового специалиста.</b> — «얼마 전에 해 봤는데».<br>✖️ ① женщина не открывала бизнес — наоборот, «나도 창업하고 나서», ② без ограничений — нет, «연 소득 5천만 원 이하», ③ платно — нет, «무료».<br>🧩 창업 = «открытие бизнеса»; 연 소득 = «годовой доход»."},{"n":29,"points":2,"instr":"Прослушайте и выберите, кто такой мужчина.","options":["정전 신고를 처리하는 사람","전기 공급량을 관리하는 사람","지역 발전소를 운영하는 사람","전기 시설 안전을 점검하는 사람"],"answer":2,"explain":"🎧 남자: 이 센터에서 … 실시간 전기 사용량을 보면서 정전이 발생하지 않도록 지역별 수요에 맞춰 전기 공급을 분배합니다.<br><br>✅ <b>② Человек, управляющий объёмом подачи электроэнергии.</b> — «전기 공급을 분배».<br>✖️ ① обрабатывает заявки о сбоях, ③ управляет местной электростанцией, ④ проверяет безопасность э/о — он распределяет ПОДАЧУ.<br>🧩 공급량 = «объём подачи»; 분배하다 = «распределять»."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 주로 혼자서 이 일을 한다.","남자의 일은 야간에 할 수 없는 일이다.","남자의 일에는 기상 자료 분석이 포함된다.","남자는 전기 관련 시설을 찾아다니며 일한다."],"answer":3,"explain":"🎧 남자: 풍력이나 태양광 발전은 날씨 영향을 많이 받거든요. 그래서 기상 자료를 분석해 발전량을 정확히 예측하고 있습니다.<br><br>✅ <b>③ В работу мужчины входит анализ метеоданных.</b> — «기상 자료를 분석».<br>✖️ ① работает один — нет, «팀원들과 함께», ② нельзя ночью — нет, «24시간 … 교대로», ④ ездит по объектам — нет, работает в центре у экранов.<br>🧩 기상 자료 = «метеоданные»; 발전량 = «выработка»."},{"n":31,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["편의점의 의약품 판매 실태를 조사해야 한다.","의약품의 정확한 사용에 대한 교육이 필요하다.","편의점에서 판매하는 의약품 품목을 확대해야 한다.","의약품 판매 편의점에 대한 정부의 관리가 필요하다."],"answer":3,"explain":"🎧 남자: 휴일이나 야간에 문을 여는 약국이 점점 줄고 있습니다. 편의점에서 더 많은 의약품을 판매하도록 해서 의약품 접근성을 높여야 합니다. … 소비자들의 수요를 간과할 순 없죠.<br><br>✅ <b>③ Нужно расширить ассортимент лекарств, продаваемых в магазинах у дома.</b><br>✖️ ① обследовать практику продаж, ② обучать правильному приёму, ④ нужен госконтроль — он за РАСШИРЕНИЕ ассортимента.<br>🧩 편의점 = «магазин у дома»; 의약품 품목 = «номенклатура лекарств»."},{"n":32,"points":2,"instr":"Прослушайте и выберите, как ведёт себя мужчина (его отношение).","options":["예상되는 문제점을 우려하고 있다.","상대의 반론을 일부 인정하고 있다.","상대가 제시한 근거를 의심하고 있다.","자신의 의견을 일관되게 주장하고 있다."],"answer":4,"explain":"🎧 여자: 아무런 제재 없이 구입할 수 있는 품목을 늘리는 건 좀 우려가 됩니다. → 남자: 부작용 사용으로 인한 문제가 없었고 판매량도 증가 … 수요를 간과할 순 없죠. → 여자: 수요만 고려해서 … 아니죠.<br><br>✅ <b>④ Последовательно отстаивает своё мнение.</b> — несмотря на возражения, гнёт линию расширения.<br>✖️ ① опасается проблем, ② частично соглашается, ③ сомневается в доводах — он именно НАСТАИВАЕТ.<br>🧩 일관되게 = «последовательно»; 주장하다 = «утверждать»."},{"n":33,"points":2,"instr":"Прослушайте и выберите, о чём идёт речь.","options":["탑평리 석탑이 국보로 지정된 이유","탑평리 석탑이 훼손된 역사적 배경","탑평리 석탑을 복원하는 과정","탑평리 석탑을 발굴한 시기"],"answer":1,"explain":"🎧 여자: 탑평리 석탑은 … 다보탑보다 먼저 국보로 지정됐습니다. 어떻게 가능했을까요? 이 탑은 … 가장 높습니다. … 정중앙에 위치해 '중앙탑'… 탑 안에서 … 유물들도 발견돼 그 가치를 인정받았던 겁니다.<br><br>✅ <b>① Причина, по которой пагода была признана нацсокровищем.</b><br>✖️ ② история повреждения, ③ процесс реставрации, ④ время раскопок — лектор объясняет, ПОЧЕМУ её признали ценной.<br>🧩 국보 = «национальное сокровище»; 유물 = «реликвия»."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 탑에는 그 시대의 불교와 관련된 물건이 들어 있었다.","이 탑이 위치한 곳은 물자 수송에 어려움이 많았다.","이 탑은 통일 신라의 가장 남쪽에 세워졌다.","이 탑은 너비가 넓어 안정감이 느껴진다."],"answer":1,"explain":"🎧 여자: 탑 안에서 당시 불교 사상을 엿볼 수 있는 유물들도 발견돼 …<br><br>✅ <b>① Внутри пагоды были предметы, связанные с буддизмом той эпохи.</b><br>✖️ ② трудности с транспортом — наоборот, «중요한 역할», ③ на самом юге — нет, «정중앙», ④ широкая, устойчивая — нет, «너비는 좁아 안정감은 덜하지만».<br>🧩 불교 = «буддизм»; 정중앙 = «самый центр»."},{"n":35,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["봉사단원의 선발 기준과 방법을 소개하고 있다.","봉사 활동을 시작하면서 봉사자들을 격려하고 있다.","봉사 활동의 문제점을 밝히며 해결을 촉구하고 있다.","봉사단에 대한 지속적인 관심과 지원을 호소하고 있다."],"answer":2,"explain":"🎧 남자: … '사랑의 집 고치기' 봉사단은 … 낙후된 거주 공간을 개선하기 위해 이 자리에 모였습니다. … 참가해 주신 여러분께 감사의 말씀과 함께 힘내시라는 응원의 박수를 보냅니다. … 일주일 동안 열심히 해 봅시다.<br><br>✅ <b>② Начиная волонтёрскую работу, воодушевляет добровольцев.</b> — «응원의 박수».<br>✖️ ① критерии отбора, ③ проблемы деятельности, ④ призыв к поддержке — он ПОДБАДРИВАЕТ перед стартом.<br>🧩 봉사단 = «волонтёрский отряд»; 격려하다 = «воодушевлять»."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 봉사단은 작년에 조직되었다.","이 봉사단은 지난주부터 활동을 시작했다.","이 봉사단은 거주 공간을 고치는 일을 한다.","이 봉사단의 단원은 시청 직원들로 한정되어 있다."],"answer":3,"explain":"🎧 남자: … 낙후된 거주 공간을 개선하기 위해 … 낡은 집들을 포함해 … 보육원까지 수리합니다.<br><br>✅ <b>③ Этот отряд занимается ремонтом жилых помещений.</b><br>✖️ ① создан в прошлом году — нет, «지난 십 년간», ② с прошлой недели — нет, начинают сегодня, ④ только сотрудники мэрии — нет, ещё студенты и жители.<br>🧩 낙후된 = «обветшалый»; 수리하다 = «ремонтировать»."},{"n":37,"points":2,"instr":"Прослушайте и выберите центральную мысль женщины.","options":["영유아 발달 장애는 빠른 진단이 중요하다.","영유아 발달 장애의 진단 도구를 개발해야 한다.","발달 장애 영유아를 위한 전문 병원이 필요하다.","영유아 발달 장애에 대한 연구가 더 이루어져야 한다."],"answer":1,"explain":"🎧 여자: 아기들의 신경 발달은 3세 전후가 가장 활발 … 그 전에 발달 장애를 발견하는 게 중요한데요. … 진단이 빠를수록 치료 효과가 좋으니 … 즉시 병원을 찾아 검사를 해야 합니다.<br><br>✅ <b>① При нарушениях развития у малышей важна ранняя диагностика.</b><br>✖️ ② разработать инструменты диагностики, ③ нужны спецбольницы, ④ больше исследований — она о СКОРОЙ диагностике.<br>🧩 발달 장애 = «нарушение развития»; 진단 = «диагностика»."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["국가 영유아 검진이 의무적으로 실시되고 있다.","신경 발달은 3세 이후부터 활발하게 이루어진다.","진단을 받으면 나이와 상관없이 장애 등록이 된다.","발달 장애 검사가 국가 영유아 검진에 포함되어 있다."],"answer":4,"explain":"🎧 여자: 우리나라의 경우 국가 영유아 검진에 발달 장애 검사가 포함돼 있긴 하지만 … 의무 사항이 아니라서 …<br><br>✅ <b>④ Тест на нарушения развития включён в гос. осмотр малышей.</b><br>✖️ ① обязателен — наоборот, «의무 사항이 아니라서», ② после 3 лет активно — нет, «3세 전후» (вокруг 3, активнее ДО), ③ регистрация независимо от возраста — нет, «2세 미만은 … 안 돼서».<br>🧩 검진 = «(мед)осмотр»; 의무 = «обязанность»."},{"n":39,"points":2,"instr":"Прослушайте и выберите содержание, которое было ДО этого диалога.","options":["전문 기자는 현장 취재를 나가기 어렵다.","전문 기자를 희망하는 기자들이 줄고 있다.","전문 기자가 보도한 기사가 신뢰를 잃고 있다.","전문 기자 제도가 현장에 정착되지 못하고 있다."],"answer":4,"explain":"🎧 여자: 전문 기자의 보도가 언론에 미치는 영향이 큰데도 전문 기자 제도는 아직까지 자리를 잡지 못하고 있군요.<br><br>Первая реплика «… 자리를 잡지 못하고 있군요» подытоживает сказанное ранее.<br>✅ <b>④ Институт специализированных журналистов не приживается на практике.</b> — «자리를 잡지 못하고 있군요».<br>✖️ ① трудно ездить на места, ② всё меньше желающих, ③ статьи теряют доверие — это идёт ПОСЛЕ.<br>🧩 전문 기자 = «спец. журналист»; 자리를 잡다 = «прижиться»."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["내부의 전문 기자는 단기간 육성이 가능하다.","전문 기자의 보도는 언론에 큰 영향을 미친다.","비용 절감을 위해 외부 전문가 영입을 늘렸다.","기자가 자유롭게 취재 분야를 선택할 수 있다."],"answer":2,"explain":"🎧 여자: 전문 기자의 보도가 언론에 미치는 영향이 큰데도 …<br><br>✅ <b>② Репортажи спец. журналистов сильно влияют на СМИ.</b><br>✖️ ① внутренних готовят быстро — нет, «시간이 오래 걸립니다», ③ ради экономии увеличили найм извне — нет, внешние «비용이 많이 들고», ④ свободно выбирают сферу — нет, «본인의 의사와 상관없이 … 매년 바꾸기».<br>🧩 보도 = «репортаж»; 육성 = «взращивание (кадров)»."},{"n":41,"points":2,"instr":"Прослушайте и выберите центральное содержание лекции.","options":["석농화원을 복원하려는 움직임이 활발하다.","석농화원은 회화사 연구에 중요한 자료이다.","석농화원의 우수성을 밝히려는 노력이 필요하다.","석농화원에 실린 작품들이 새롭게 해석되고 있다."],"answer":2,"explain":"🎧 여자: 이 책은 … '석농화원'이라는 화첩입니다. … 고려부터 조선 … 동서양의 작품도 담겨 … 그림에 대한 비평이 실려 … 당시 국내외 미술 작품의 특징을 알 수 있는 자료로 평가받고 있습니다.<br><br>✅ <b>② «Соннонхвавон» — важный источник для изучения истории живописи.</b><br>✖️ ① активно восстанавливают, ③ нужно доказать ценность, ④ заново трактуют работы — лектор о ЗНАЧЕНИИ как источника.<br>🧩 화첩 = «альбом картин»; 비평 = «критика, разбор»."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 책은 조선 시대 이전부터 유통되었다.","이 책은 원본의 모습을 그대로 유지하고 있다.","이 책에는 그림과 그림에 대한 비평이 실려 있다.","이 책은 김광국이 직접 그린 그림으로 제작되었다."],"answer":3,"explain":"🎧 여자: 책에는 그림과 함께 그림에 대한 비평이 실려 있습니다.<br><br>✅ <b>③ В книге есть и картины, и критика к ним.</b><br>✖️ ① ходила до Чосона — нет, издана в позднем Чосоне, ② сохранила оригинальный вид — нет, «그림이 없거나 훼손된 게 있기는», ④ из картин самого Кима — нет, он СОБИРАЛ чужие.<br>🧩 비평 = «критика»; 훼손되다 = «повреждаться»."},{"n":43,"points":2,"instr":"Прослушайте и выберите, о чём идёт речь.","options":["반구대 암각화에 표현된 내용","반구대 암각화를 보존한 방식","반구대 암각화를 제작한 연대","반구대 암각화가 발견된 과정"],"answer":1,"explain":"🎧 남자: … 암벽에 새겨진 수십 마리 고래들. … 줄무늬가 새겨진 흑등고래, 새끼를 등에 업은 귀신고래. … 작살을 맞은 고래 … 춤을 추는 사내. … 그들의 바다가 생생히 펼쳐져 있다.<br><br>✅ <b>① Содержание, изображённое на петроглифах Бангудэ.</b> — киты, лодка, гарпун, танцующий человек.<br>✖️ ② способ сохранения, ③ датировка, ④ процесс обнаружения — описывается именно ИЗОБРАЖЁННОЕ.<br>🧩 암각화 = «петроглиф»; 고래 = «кит»."},{"n":44,"points":2,"instr":"Прослушайте и выберите верное описание петроглифов Бангудэ.","options":["문자로 된 설명이 새겨져 있다.","강가의 암벽에서 확인할 수 있다.","그림에 다양한 색이 칠해져 있다.","유사한 암각화가 많이 발견되었다."],"answer":2,"explain":"🎧 남자: 강 언저리, … 암벽에 새겨진 수십 마리 고래들. … 색칠도, 문자로 된 설명도 하나 없는 그림들 … 어느 암각화에서도 유례를 찾아볼 수 없는 사실적인 모습들.<br><br>✅ <b>② Их можно увидеть на скале у реки.</b> — «강 언저리 … 암벽에 새겨진».<br>✖️ ① есть надписи — нет, «문자로 된 설명도 하나 없는», ③ раскрашены — нет, «색칠도 … 없는», ④ много похожих — нет, «유례를 찾아볼 수 없는».<br>🧩 강가 = «берег реки»; 암벽 = «скала, утёс»."},{"n":45,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 기술은 우주 자원 탐사에 사용되고 있다.","이 기술은 굴착 속도를 높이는 데 사용된다.","이 기술은 인공 지능으로 지진계의 자료를 종합한다.","이 기술은 땅속 깊은 곳에 설치된 지진계를 활용한다."],"answer":3,"explain":"🎧 여자: 지상에 설치한 지진계를 활용해 … 파동을 측정 … 인공위성으로 전송하면 인공 지능이 종합해 … 광물 매장량을 분석 …<br><br>✅ <b>③ Эта технология с помощью ИИ обобщает данные сейсмографов.</b><br>✖️ ① уже в космической разведке — это лишь будущий прогноз (달 지질 연구), ② повышает скорость бурения — нет, «굴착이 필요 없는», ④ сейсмографы глубоко под землёй — нет, «지상에 설치한».<br>🧩 지진계 = «сейсмограф»; 매장량 = «запасы (недр)»."},{"n":46,"points":2,"instr":"Прослушайте и выберите способ изложения, который использует женщина.","options":["신기술의 보급 전략을 요약하고 있다.","신기술의 여러 유형을 분류하고 있다.","신기술의 원리와 장점을 설명하고 있다.","신기술이 적용된 예시를 나열하고 있다."],"answer":3,"explain":"🎧 여자: 기존 시추 방식은 … 경제성이 떨어집니다. 환경 파괴의 우려도 크죠. 최근 … 기술이 대안으로 … 지진계를 활용해 … 인공위성으로 전송 … AI가 종합 …<br><br>✅ <b>③ Объясняет принцип и преимущества новой технологии.</b> — как работает + плюсы (без бурения, без вреда среде).<br>✖️ ① стратегия распространения, ② классификация типов, ④ перечень примеров применения — она объясняет ПРИНЦИП и ВЫГОДЫ.<br>🧩 원리 = «принцип»; 장점 = «достоинство»."},{"n":47,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["개인 통관 번호는 국내 물품의 해외 발송 시에 필요하다.","개인 통관 번호가 불법 수입에 악용되는 사례가 증가했다.","예전에는 사용자에 의한 개인 통관 번호 해지가 가능했다.","앞으로는 개인 통관 번호의 유효 기간이 폐지될 예정이다."],"answer":2,"explain":"🎧 남자: 개인 통관 번호를 도용한 불법 수입 증가가 문제인데요. 오랫동안 사용하지 않는 번호들이 도용이 됩니다.<br><br>✅ <b>② Участились случаи злоупотребления личным таможенным кодом для незаконного импорта.</b><br>✖️ ① нужен при отправке отечественных товаров за рубеж — нет, при ПОКУПКЕ зарубежных, ③ раньше пользователь мог аннулировать — наоборот, «전과 달리 … 가능해졌는데요», ④ срок действия отменят — нет, «매년 갱신».<br>🧩 통관 번호 = «таможенный код»; 도용 = «незаконное использование»."},{"n":48,"points":2,"instr":"Прослушайте и выберите, как ведёт себя мужчина (его отношение).","options":["제도 개편에 따른 결과에 대해서 낙관하고 있다.","제도 개편에 대한 국민의 협조를 당부하고 있다.","제도 개편을 위한 정부의 노력을 촉구하고 있다.","제도 개편이 미칠 영향에 대해서 비판하고 있다."],"answer":1,"explain":"🎧 남자: … 도용이 어려워지면 불법 수입도 차단이 될 겁니다. … 도용 가능성도 미연에 방지할 수 있을 것으로 기대됩니다.<br><br>✅ <b>① Оптимистично оценивает результаты реформы.</b> — «차단이 될 겁니다», «기대됩니다».<br>✖️ ② просит содействия граждан, ③ призывает к усилиям государства, ④ критикует последствия — он именно ОПТИМИСТИЧЕН.<br>🧩 낙관하다 = «смотреть с оптимизмом»; 미연에 방지하다 = «предотвращать заранее»."},{"n":49,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["원형 감옥에서는 많은 죄수를 하나의 수용실에 가둔다.","원형 감옥의 수용실은 여러 감시대들로 둘러싸여 있다.","원형 감옥의 개념을 적용한 교도소가 실재하지 않는다.","원형 감옥의 감시대 안은 수용실에서 잘 보이지 않는다."],"answer":4,"explain":"🎧 남자: 간수들은 감시대 꼭대기에서 빛을 등지고 수용실을 내려다보는데요. 수용실에서는 역광 때문에 감시대 안이 어둡게 보이죠.<br><br>✅ <b>④ Изнутри камер плохо видно, что внутри сторожевой башни.</b> — «역광 때문에 감시대 안이 어둡게 보이죠».<br>✖️ ① много узников в одной камере — нет, «한 명씩», ② камеры окружены башнями — нет, башня ОДНА, ③ нет реальных тюрем — нет, «실제 교도소에도 적용».<br>🧩 원형 감옥 = «паноптикум»; 역광 = «контровой свет»."},{"n":50,"points":2,"instr":"Прослушайте и выберите способ изложения, который использует мужчина.","options":["사상이 가진 문제의 원인을 유추하고 있다.","사상에 대한 전문가의 의견을 인용하고 있다.","사상에 새롭게 등장할 핵심 개념을 정의하고 있다.","사상에 대한 이해를 돕기 위해 사례를 분석하고 있다."],"answer":4,"explain":"🎧 남자: 공리주의 … 이 공리주의를 토대로 구현된 것 중 하나가 원형 감옥인데요. … 구조를 보면 … 이러한 원리로 죄수들은 … 늘 감시당하고 있다고 의식해 …<br><br>✅ <b>④ Анализирует пример, чтобы помочь понять идею.</b> — паноптикум как ПРИМЕР утилитаризма, разбор его устройства.<br>✖️ ① выводит причины проблем идеи, ② цитирует экспертов, ③ определяет новое понятие — он РАЗБИРАЕТ пример.<br>🧩 공리주의 = «утилитаризм»; 사례 = «пример, случай»."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제102회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"이 동네로 이사한 (        ) 일 년이 됐다.","options":["온 지","올 때","오거나","오다가"],"answer":1,"explain":"«Прошёл год с тех пор, как я переехал в этот район».<br>✅ <b>① 온 지</b> — «-(으)ㄴ 지» = «с тех пор как» (отрезок времени после действия).<br>✖️ ② 올 때 — «когда приезжаю», ③ 오거나 — «или приехать», ④ 오다가 — «приезжая (и потом)».<br>🧩 -(으)ㄴ 지 + 시간이 되다/지나다 = «прошло столько-то с момента»."},{"n":2,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"가을이 되면서 나뭇잎 색이 점점 붉게 (        ).","options":["변해 간다","변할 뻔했다","변한 척했다","변하면 된다"],"answer":1,"explain":"«С приходом осени цвет листьев постепенно становится красным».<br>✅ <b>① 변해 간다</b> — «-아/어 가다» = постепенное продолжающееся изменение.<br>✖️ ② 변할 뻔했다 — «чуть не изменился», ③ 변한 척했다 — «притворился изменившимся», ④ 변하면 된다 — «достаточно измениться».<br>🧩 점점 + -아 가다 = «постепенно становится…»."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"지금 출발하지 않으면 약속 시간에 <u>늦을지도 모른다</u>.","options":["늦는 셈이다","늦어도 된다","늦을 리가 없다","늦을 수도 있다"],"answer":4,"explain":"«Если не выйти сейчас, можно опоздать на встречу».<br>✅ <b>④ 늦을 수도 있다</b> — «-(으)ㄹ지도 모르다» (возможно, что…) ≈ «-(으)ㄹ 수도 있다» (может быть).<br>✖️ ① 늦는 셈이다 — «считай, опоздал», ② 늦어도 된다 — «можно опоздать», ③ 늦을 리가 없다 — «не может быть, что опоздаю».<br>🧩 -(으)ㄹ지도 모르다 / -(으)ㄹ 수도 있다 — обе про вероятность."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"전문가들이 <u>예상한 대로</u> 농산물 가격이 떨어지고 있다.","options":["예상한 탓에","예상하는 동안에","예상하기만 하면","예상한 것과 같이"],"answer":4,"explain":"«Как и предсказывали эксперты, цены на сельхозпродукцию падают».<br>✅ <b>④ 예상한 것과 같이</b> — «-(으)ㄴ 대로» (так, как) ≈ «-(으)ㄴ 것과 같이» (подобно тому, как).<br>✖️ ① 예상한 탓에 — «по вине того, что предсказали», ② 예상하는 동안에 — «пока предсказывают», ③ 예상하기만 하면 — «стоит только предсказать».<br>🧩 -(으)ㄴ 대로 = «в соответствии с тем, как»."},{"n":5,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"👟 걸을 때 발이 편하게~\n가볍고 디자인도 예뻐요.","options":["구두","우산","자전거","선풍기"],"answer":1,"explain":"«Чтобы ногам было удобно при ходьбе~ Лёгкие, и дизайн красивый».<br>✅ <b>① 구두</b> (туфли) — «걸을 때 발이 편하게», «가볍고».<br>✖️ ② 우산 (зонт), ③ 자전거 (велосипед), ④ 선풍기 (вентилятор) — не про обувь.<br>🧩 발이 편하다 = «ногам удобно»; 가볍다 = «лёгкий»."},{"n":6,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"🧺 더러워진 옷을 새 옷처럼!\n두꺼운 이불도 맡겨 주세요.","options":["은행","시장","세탁소","가구점"],"answer":3,"explain":"«Грязную одежду — как новую! Доверьте нам и толстые одеяла».<br>✅ <b>③ 세탁소</b> (химчистка) — «맡겨 주세요» (доверьте стирку), стирают одежду и одеяла.<br>✖️ ① 은행 (банк), ② 시장 (рынок), ④ 가구점 (мебельный) — не про стирку.<br>🧩 맡기다 = «сдавать (на хранение/обработку)»; 이불 = «одеяло»."},{"n":7,"points":2,"instr":"Выберите, о чём этот текст (призыв).","passage":"🏃 달리기, 지금 바로 시작하세요.\n활기찬 내일이 기다립니다.","options":["전기 절약","건강 관리","생활 예절","환경 보호"],"answer":2,"explain":"«Бег — начните прямо сейчас. Вас ждёт бодрое завтра».<br>✅ <b>② 건강 관리</b> (забота о здоровье) — бег ради «활기찬 내일» (энергичного завтра).<br>✖️ ① 전기 절약 (экономия э/э), ③ 생활 예절 (этикет), ④ 환경 보호 (защита природы).<br>🧩 활기차다 = «энергичный, бодрый»."},{"n":8,"points":2,"instr":"Выберите, о чём этот текст (инструкция).","passage":"🎫 1. 공연 날짜, 인원을 선택하고 [다음] 버튼을 누르세요.\n2. 원하는 좌석을 선택한 후 결제하세요.","options":["예매 방법","행사 소개","등록 문의","교환 순서"],"answer":1,"explain":"«1. Выберите дату спектакля и число людей, нажмите [Далее]. 2. Выберите желаемое место и оплатите».<br>✅ <b>① 예매 방법</b> (как купить билет заранее) — выбор даты/мест и оплата = шаги брони.<br>✖️ ② 행사 소개 (анонс), ③ 등록 문의 (запрос регистрации), ④ 교환 순서 (порядок обмена).<br>🧩 예매 = «предварительная покупка билетов»; 좌석 = «место»; 결제 = «оплата»."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"📢 그림책 읽어 주는 자원봉사자 모집\n\"어린이들에게 꿈과 희망을 선물하세요.\"\n· 자격: 고등학생 또는 대학생 (※ 한국어를 잘하는 외국인 학생도 가능)\n· 모집 기간: 11월 10일(월) ~ 11월 21일(금)\n· 신청 방법: 인주어린이도서관 홈페이지(www.injulibrary.or.kr)\n· 활동 기간: 2025년 12월 1일(월) ~ 2026년 2월 28일(토)","options":["봉사 활동은 두 달 동안 하게 된다.","아이들에게 책을 읽어 줄 봉사자를 찾고 있다.","봉사자 신청은 도서관에 직접 가서 해야 한다.","학생이 아닌 사람들도 이 봉사에 참여할 수 있다."],"answer":2,"explain":"✅ <b>② Ищут волонтёров, которые будут читать детям книги.</b> — «그림책 읽어 주는 자원봉사자 모집».<br>✖️ ① два месяца — нет, 1 дек ~ 28 фев (≈3 месяца), ③ подавать лично в библиотеке — нет, через сайт, ④ не-студенты тоже могут — нет, только «고등학생 또는 대학생».<br>🧩 자원봉사자 = «волонтёр»; 모집 = «набор»."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с данными графика.","passage":"📊 «여행사를 선택할 때 중요하게 생각하는 것» (성인 남녀 1,600명)\n가격 48% · 여행 상품의 다양성 25% · 회사의 규모 16% · 이용 후기 9% · 기타 2%.","options":["회사의 규모가 중요하다고 응답한 비율이 가장 낮다.","가격을 중요하게 생각하는 사람이 전체의 반을 넘는다.","이용 후기가 여행 상품의 다양성보다 중요하다는 응답이 두 배 이상 많다.","여행 상품의 다양성보다 회사의 규모를 중요하게 생각하는 사람이 더 적다."],"answer":4,"explain":"✅ <b>④ Тех, кто ценит размер компании, меньше, чем ценящих разнообразие туров.</b> — 회사의 규모 16% &lt; 여행 상품의 다양성 25%.<br>✖️ ① размер компании — самый низкий: нет (16% &gt; 후기 9% и 기타 2%), ② цена &gt; половины: нет (48%), ③ отзывы вдвое важнее разнообразия: наоборот, 9% &lt; 25%.<br>🧩 비율 = «доля»; 규모 = «размер, масштаб»."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"지난달 문을 연 우표 박물관이 시민들에게 사랑을 받고 있다. 박물관 내 역사실에서는 우표의 역사를 한눈에 볼 수 있다. 또 어린이 체험실에서는 향기 나는 우표의 향을 맡거나 나무 우표 등을 만져 볼 수 있다. 자신의 사진이 들어간 우표도 직접 만들 수 있다. 편지를 써서 넣으면 일 년 뒤에 받아 볼 수 있는 박물관의 '느린 우체통'도 인기를 끌고 있다.","options":["이 박물관은 일 년 전부터 운영을 시작했다.","이 박물관에서는 직접 우표를 만들 수 있다.","이 박물관의 체험실에 있는 우표는 만질 수 없다.","이 박물관의 느린 우체통으로는 편지를 보내지 못한다."],"answer":2,"explain":"✅ <b>② В этом музее можно самому сделать марку.</b> — «자신의 사진이 들어간 우표도 직접 만들 수 있다».<br>✖️ ① работает год — нет, «지난달 문을 연» (открылся в прошлом месяце), ③ марки нельзя трогать — наоборот, «만져 볼 수 있다», ④ через «медленный ящик» письма не отправить — наоборот, через год придёт.<br>🧩 체험실 = «зал-практикум»; 느린 우체통 = «медленный почтовый ящик»."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"휴일에 산을 오르던 경찰이 등산객을 구조했다. 지난 1일 김민수 경위는 인주산 정상에서 한 여성이 쓰러져 있는 것을 발견했다. 김 경위는 바로 여성의 체온이 떨어지지 않게 겉옷을 벗어서 덮어 주고 119에 신고했다. 이후 김 경위는 구조대 차량이 올 수 있는 산 중턱 대피소까지 여성을 업고 뛰어 내려갔다. 병원으로 이송된 여성은 치료를 받고 건강을 되찾았다.","options":["한 등산객이 산 정상에 쓰러져 있었다.","김 경위는 대피소까지 차량으로 이동했다.","구조대가 등산객을 업고 뛰어내려갔다.","김 경위는 등산객의 신고를 받고 산에 올라갔다."],"answer":1,"explain":"✅ <b>① Одна туристка лежала без сил на вершине горы.</b> — «정상에서 한 여성이 쓰러져 있는 것을 발견».<br>✖️ ② к убежищу на машине — нет, «업고 뛰어 내려갔다» (нёс на спине бегом), ③ нёс спасотряд — нёс сам Ким (경위), ④ поднялся по вызову туристки — нет, был на выходном восхождении и нашёл её.<br>🧩 구조하다 = «спасать»; 업다 = «нести на спине»."},{"n":13,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 그래서 껍질째 먹기도 편하고 딱딱하지 않아서 식감도 좋다.\n(나) 신비 복숭아는 2017년에 한국에 처음 소개된 여름 과일이다.\n(다) 다른 복숭아에 비해 이른 시기에 먹을 수 있다는 것도 장점이다.\n(라) 껍질이 얇은 복숭아와 속이 부드러운 복숭아의 장점을 결합한 품종이다.","options":["(나)-(라)-(가)-(다)","(나)-(가)-(다)-(라)","(라)-(나)-(다)-(가)","(라)-(다)-(가)-(나)"],"answer":1,"explain":"✅ <b>① (나)-(라)-(가)-(다)</b>: «синби»-персик впервые завезён в 2017 → это сорт, соединивший плюсы тонкокожих и мягких персиков → поэтому удобно есть с кожурой, приятная текстура → ещё плюс: можно есть раньше других.<br>🧩 «그래서» в (가) — следствие из (라); (다) добавляет ещё одно достоинство в конце."},{"n":14,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 아이가 갑자기 걸려 밤새 큰 소리로 울었다.\n(나) 아주머니는 아이가 많이 아팠냐며 오히려 걱정해 주셨다.\n(다) 아침에 아이와 병원에 가려고 집을 나서다 옆집 아주머니를 만났다.\n(라) 나는 우는 아이를 달래면서도 울음소리에 이웃들이 깰까 봐 걱정했다.","options":["(가)-(나)-(라)-(다)","(가)-(라)-(다)-(나)","(나)-(가)-(다)-(라)","(나)-(다)-(라)-(가)"],"answer":2,"explain":"✅ <b>② (가)-(라)-(다)-(나)</b>: ребёнок внезапно заболел и всю ночь громко плакал → я успокаивал, но боялся разбудить соседей → утром, выходя в больницу, встретил соседку → соседка, наоборот, забеспокоилась, не сильно ли болен ребёнок.<br>🧩 (나) с «오히려» (наоборот) — реакция соседки, идёт в конце после встречи с ней (다)."},{"n":15,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 최근 온라인 가구 구매가 늘면서 반품 사례가 많아지고 있다.\n(나) 그런데 반품 비용으로 인해 피해를 보는 소비자가 늘고 있다.\n(다) 따라서 소비자는 구매 전에 반품 비용과 조건을 잘 확인해야 한다.\n(라) 업체가 까다로운 조건을 내세워 반품을 거절하는 경우가 많이 발생한다.","options":["(가)-(나)-(라)-(다)","(가)-(라)-(다)-(나)","(라)-(가)-(나)-(다)","(라)-(다)-(가)-(나)"],"answer":1,"explain":"✅ <b>① (가)-(나)-(라)-(다)</b>: онлайн-покупки мебели растут → возвратов больше → но потребители страдают из-за расходов на возврат → фирмы отказывают, выдвигая строгие условия → поэтому потребителю стоит заранее проверять условия возврата.<br>🧩 «따라서» в (다) — вывод-совет в конце."},{"n":16,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"북극여우는 계절에 따라 털 색깔을 바꾸는 동물이다. 북극여우의 털은 겨울에는 눈과 같은 흰색으로, 여름에는 바위나 흙과 비슷한 갈색빛으로 바뀐다. 이러한 털 색깔의 변화로 북극여우는 몸을 숨길 곳이 없는 북극의 특수한 환경에서도 천적으로부터 자신을 보호하고 사냥할 때 (        ) 수 있다.","options":["동료와 무리를 이룰","먹잇감에 몰래 다가갈","체온을 적절히 유지할","발자국을 남기지 않을"],"answer":2,"explain":"Песец меняет окрас (зимой белый как снег, летом бурый под камни/землю) → маскировка. Это нужно и для защиты от хищников, и при охоте.<br>✅ <b>② 먹잇감에 몰래 다가갈</b> (незаметно подкрасться к добыче).<br>✖️ ① сбиться в стаю с сородичами, ③ поддерживать температуру тела, ④ не оставлять следов — не связаны с «маскировкой при охоте».<br>🧩 천적 = «природный враг»; 먹잇감 = «добыча»; 몰래 다가가다 = «подкрадываться»."},{"n":17,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"요즘 연필을 잡고 글씨를 반듯하게 쓰는 것에 어려움을 느끼는 아이가 많다. 어릴 나이부터 전자 기기를 장시간 사용한 탓이다. 전자 기기의 화면을 단순히 누르거나 미는 동작을 반복하다 보면 손에 있는 근육을 (        ) 못한다. 그래서 전문가들은 소근육이 발달하는 11세까지 손가락을 움직여서 하는 놀이를 많이 하도록 하는 것이 좋다고 말한다.","options":["제대로 갖추지","빠르게 줄이지","충분히 사용하지","완전히 회복하지"],"answer":3,"explain":"Простое нажимание/смахивание экрана не задействует мелкие мышцы руки → ребёнку трудно писать.<br>✅ <b>③ 충분히 사용하지</b> (못하다) — «не может в достаточной мере использовать» мышцы руки.<br>✖️ ① как следует обзавестись, ② быстро сократить, ④ полностью восстановить — не вяжутся с «누르거나 미는 동작만 반복».<br>🧩 소근육 = «мелкая моторика»; 반듯하게 = «ровно»."},{"n":18,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"고인돌은 옛날 청동기 시대의 무덤이다. 고인돌은 받침돌 두 개를 세우고 그 위에 덮개돌을 얹은 형태인데 덮개돌 하나의 무게가 수십 톤에 달하는 것도 있다. 이와 같이 거대한 돌을 운반하고 세우려면 그만큼 많은 사람들의 힘이 필요했다. 그래서 고인돌은 사람들을 불러 모아 무덤 만드는 일을 시킬 수 있을 정도로 (        ) 사람의 무덤이었을 것으로 보인다.","options":["대단한 권력을 가진","체력이 굉장히 약한","무기를 잘 제작하는","수명이 남들보다 짧은"],"answer":1,"explain":"Чтобы перетащить и установить камни в десятки тонн, нужно созвать множество людей → значит, погребённый обладал большой властью.<br>✅ <b>① 대단한 권력을 가진</b> (обладавший огромной властью).<br>✖️ ② с очень слабым телом, ③ хорошо делавший оружие, ④ с короткой жизнью — не следуют из «사람들을 불러 모아 … 시킬 수 있을 정도로».<br>🧩 고인돌 = «дольмен»; 권력 = «власть»."},{"n":19,"points":2,"instr":"Выберите подходящее слово для пропуска ( ).","passage":"도시의 도로는 대부분 물이 스며들지 않는 아스팔트로 뒤덮여 있다. 그래서 비가 오면 빗물이 지하로 잘 흘러 들어가지 못해 지하수가 부족해지고 도로가 물에 잠기는 일도 자주 발생한다. 그런데 최근 물이 잘 스며드는 도로 포장재가 개발되었다. 이 포장재에는 미세한 구멍이 많다. 그래서 빗물이 쉽게 통과해 지하수 자원이 보충된다. (        ) 하수구로 몰리는 빗물의 양이 줄어 도로 침수의 위험도 줄어들게 된다.","options":["또한","비록","과연","반면"],"answer":1,"explain":"Новое покрытие даёт ДВА плюса: пополняет грунтовые воды И снижает риск затопления. Нужна связка-добавление.<br>✅ <b>① 또한</b> (к тому же, также).<br>✖️ ② 비록 (хотя), ③ 과연 (действительно ли), ④ 반면 (напротив) — не передают перечисление двух выгод.<br>🧩 스며들다 = «впитываться»; 침수 = «затопление»."},{"n":20,"points":2,"instr":"Выберите главную мысль (тему) текста.","passage":"도시의 도로는 대부분 물이 스며들지 않는 아스팔트로 뒤덮여 있다. 그래서 비가 오면 빗물이 지하로 잘 흘러 들어가지 못해 지하수가 부족해지고 도로가 물에 잠기는 일도 자주 발생한다. 그런데 최근 물이 잘 스며드는 도로 포장재가 개발되었다. 이 포장재에는 미세한 구멍이 많다. 그래서 빗물이 쉽게 통과해 지하수 자원이 보충된다. 또한 하수구로 몰리는 빗물의 양이 줄어 도로 침수의 위험도 줄어들게 된다.","options":["빗물은 지하수 오염을 줄이는 데 중요한 역할을 한다.","도로 포장재에는 도시마다의 환경적 특성이 반영되어 있다.","도로 침수는 도시에 매우 심각한 피해를 입히는 요인 중 하나이다.","새 포장재가 지하수 부족과 도로 침수 문제 해결에 도움이 될 것이다."],"answer":4,"explain":"✅ <b>④ Новое покрытие поможет решить проблемы нехватки грунтовых вод и затопления дорог.</b><br>✖️ ① дождевая вода снижает загрязнение грунтовых вод, ② покрытие отражает особенности каждого города, ③ затопление дорог — серьёзный вред — это частности, а тема — польза НОВОГО покрытия.<br>🧩 포장재 = «покрытие (дорожное)»; 보충되다 = «пополняться»."},{"n":21,"points":2,"instr":"Выберите подходящее выражение (идиому) для пропуска ( ).","passage":"인주시의 한 거리가 식당과 카페가 모인 먹거리 골목으로 특화되면서 최근 이곳을 찾는 사람들이 늘고 있다. 그런데 차량 통행을 막고 길 한가운데에서 사진을 찍거나 횡단보도 위에서 삼각대를 세우는 등 일부 방문객의 행동이 (        ) 한다. 차량이 오는 것을 보지 못하고 촬영을 하다 사고가 날 뻔한 위험한 상황이 자주 발생하면서 운전자와 방문객 간에 다투는 일도 잦아지고 있다.","options":["목이 빠지게","한숨을 돌리게","눈살을 찌푸리게","코가 납작해지게"],"answer":3,"explain":"Поведение части посетителей (перекрывают дорогу, фотографируются на проезжей части) вызывает недовольство окружающих.<br>✅ <b>③ 눈살을 찌푸리게</b> — «заставляет хмурить брови» (вызывает неодобрение).<br>✖️ ① 목이 빠지게 — «с нетерпением ждать», ② 한숨을 돌리게 — «перевести дух», ④ 코가 납작해지게 — «быть посрамлённым».<br>🧩 눈살을 찌푸리다 = «морщиться от неодобрения»."},{"n":22,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"인주시의 한 거리가 식당과 카페가 모인 먹거리 골목으로 특화되면서 최근 이곳을 찾는 사람들이 늘고 있다. 그런데 차량 통행을 막고 길 한가운데에서 사진을 찍거나 횡단보도 위에서 삼각대를 세우는 등 일부 방문객의 행동이 눈살을 찌푸리게 한다. 차량이 오는 것을 보지 못하고 촬영을 하다 사고가 날 뻔한 위험한 상황이 자주 발생하면서 운전자와 방문객 간에 다투는 일도 잦아지고 있다.","options":["이 거리에서 사진을 찍는 방문객이 줄어들었다.","인주시가 최근 이 거리의 차량 통행을 금지했다.","이 거리의 방문객과 운전자 사이에 갈등이 늘고 있다.","이 거리에는 식당이 없어 방문객들이 불편을 겪고 있다."],"answer":3,"explain":"✅ <b>③ Между посетителями и водителями на этой улице растут конфликты.</b> — «운전자와 방문객 간에 다투는 일도 잦아지고 있다».<br>✖️ ① фотографирующих стало меньше — наоборот, проблема в них, ② город запретил проезд — нет, посетители сами перекрывают, ④ нет ресторанов — наоборот, это «먹거리 골목».<br>🧩 갈등 = «конфликт»; 다투다 = «спорить, ссориться»."},{"n":23,"points":2,"instr":"Выберите чувство героя («나») в подчёркнутой части.","passage":"⚠️ Оригинальный литературный отрывок защищён авторским правом, и Государственный институт (NIIED) НЕ публикует его в открытых материалах 102-го экзамена: «저작권 관련 법령에 따라 본 문항의 지문은 공개하지 않습니다». Полный текст не приводится — ответ по официальному ключу.\n\nКонтекст (по вопросам): рассказ связан с тхэквондо (태권도); герой «я» ни разу не пропускал занятия по тхэквондо.","options":["설레다","샘나다","아쉽다","그립다"],"answer":1,"explain":"Литературный отрывок официально не опубликован, поэтому точную выделенную фразу процитировать нельзя. По официальному ключу верный ответ — <b>① 설레다</b> (быть в радостном волнении, трепетать в предвкушении).<br>🧩 Значения вариантов: ① 설레다 — «волноваться, трепетать (в радостном ожидании)», ② 샘나다 — «завидовать», ③ 아쉽다 — «жаль, досадно», ④ 그립다 — «скучать, тосковать».<br>📌 Тип: 심정 (чувство героя) по выделенной фразе художественного текста."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"⚠️ Тот же отрывок, что и в задании 23, официально не публикуется по авторскому праву («본 문항의 지문은 공개하지 않습니다»). Ответ — по официальному ключу.\n\nКонтекст: герой занимается тхэквондо (태권도).","options":["나는 태권도 승급 시험에서 떨어졌다.","나는 어릴 때부터 태권도를 즐겨 했다.","나는 바로 태권도 성인 반에 등록했다.","나는 태권도 수업에 한 번도 빠지지 않았다."],"answer":4,"explain":"По официальному ключу верный ответ — <b>④ 나는 태권도 수업에 한 번도 빠지지 않았다</b> (я ни разу не пропускал занятия по тхэквондо).<br>✖️ ① провалил экзамен на повышение уровня, ② с детства любил тхэквондо, ③ сразу записался во взрослую группу — текстом не подтверждаются.<br>📌 Тип: 내용과 같은 것 (что совпадает с текстом). Полный отрывок не опубликован NIIED."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 TV 프로그램 방영 효과 '톡톡', 인주시는 관광객 물결","options":["TV 프로그램 제작자들이 관광객을 촬영하러 인주시로 모여들었다.","인주시가 TV 프로그램에 나온 덕분에 많은 관광객이 방문하고 있다.","인주시가 관광객 유치를 위해 TV 프로그램 홍보 방송을 준비하고 있다.","TV 프로그램 방송 후에 관광객이 증가해 인주시에 여러 문제가 발생했다."],"answer":2,"explain":"«Эффект телепрограммы „налицо“ — Инджу захлестнула волна туристов».<br>✅ <b>② Благодаря показу в телепрограмме город Инджу посещает много туристов.</b> — «방영 효과 톡톡», «관광객 물결».<br>✖️ ① создатели съехались снимать туристов, ③ город готовит рекламную передачу, ④ после показа возникли проблемы.<br>🧩 방영 = «эфир, показ»; 톡톡히 = «как следует, ощутимо»; 물결 = «волна»."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 김수미 선수 시상대에 올라, 펜싱 종목 메달 가뭄 끝","options":["김 선수가 펜싱 대표팀에서 메달을 목표로 열심히 훈련했다.","김 선수가 메달을 따면서 오랜만에 펜싱 종목에 메달이 나왔다.","김 선수가 가장 많은 메달을 따며 펜싱 종목에서 신기록을 세웠다.","김 선수가 펜싱 종목에서 좋은 경기를 펼쳤지만 아쉽게 메달을 놓쳤다."],"answer":2,"explain":"«Спортсменка Ким Суми поднялась на пьедестал — конец „медальной засухе“ в фехтовании».<br>✅ <b>② Ким взяла медаль, и впервые за долгое время в фехтовании появилась медаль.</b> — «메달 가뭄 끝».<br>✖️ ① упорно тренировалась ради медали, ③ больше всех медалей и рекорд, ④ хорошо выступила, но медаль упустила — наоборот, взяла.<br>🧩 가뭄 = «засуха»; 시상대 = «пьедестал»."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 선 넘은 악성 댓글, 처벌은 여전히 솜방망이","options":["악의적인 댓글이 줄어든 만큼 처벌 수위를 낮추자는 의견이 제기됐다.","악의적인 댓글에 대한 처벌을 강화했으나 피해는 감소하지 않고 있다.","악의적인 댓글이 지나치게 심각해졌음에도 처벌 수위는 아직도 너무 낮다.","악의적인 댓글이 계속 이어지자 피해자들이 무거운 처벌을 요구하고 나섰다."],"answer":3,"explain":"«Злобные комментарии перешли черту, а наказание всё ещё „мягкое как вата“».<br>✅ <b>③ Хотя злобные комментарии стали чрезмерно серьёзны, уровень наказания всё ещё слишком низок.</b> — «선 넘은», «솜방망이».<br>✖️ ① комментариев меньше → снизить наказание, ② наказание усилили, но вред не падает, ④ жертвы потребовали суровых мер.<br>🧩 솜방망이 (처벌) = «формальное, мягкое наказание»; 선을 넘다 = «переходить черту»."},{"n":28,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"오늘날의 연재 만화처럼 이야기가 회차별로 이어지는 작품의 형식은 이미 18세기에도 존재했다. 영국의 화가 윌리엄 호가스는 드라마 못지않게 흥미진진한 이야기를 여러 장의 그림으로 나누어 구성했다. 그리고 이를 판화에 새긴 후 (        ) 순서대로 인쇄해 판매했다. 독자들은 다음 회를 손꼽아 기다렸고 그 그림을 보기 위해 기꺼이 돈을 지불했다.","options":["만화가 되려고","주문을 받지 않고","작가를 밝히지 않고","일정한 기간을 두고"],"answer":4,"explain":"Хогарт делил историю на серии и печатал по порядку, а читатели «손꼽아 기다렸다» (с нетерпением ждали СЛЕДУЮЩУЮ серию) → значит, выпускал их с регулярными интервалами.<br>✅ <b>④ 일정한 기간을 두고</b> (выдерживая определённые промежутки).<br>✖️ ① чтобы стать комиксом, ② не принимая заказов, ③ не раскрывая автора — не объясняют «다음 회를 기다렸다».<br>🧩 연재 = «серийный выпуск»; 회차별 = «по сериям»."},{"n":29,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"사람들은 보통 식후에 바로 이를 닦는다. 하지만 레몬 등 신맛이 강한 음식을 먹은 후에 바로 양치질을 하는 것은 좋지 않다. 신 음식에 있는 산성이 치아 보호막을 (        ) 때문에 바로 칫솔질로 자극하면 치아가 더 손상된다. 치아 보호막이 원래 강도로 돌아오려면 침으로 산성이 중화되어야 하는데 여기에 30분 정도가 소요된다. 그래서 신맛이 강한 음식을 섭취하면 최소 30분 이상 지나서 양치해야 한다.","options":["누렇게 바꾸기","여러 겹으로 만들기","일시적으로 약화시키기","음식물로부터 보호하기"],"answer":3,"explain":"Кислота кислой пищи ослабляет защитный слой зубов → чистка сразу вредит; слою нужно ~30 мин, чтобы вернуть прочность (кислота нейтрализуется слюной).<br>✅ <b>③ 일시적으로 약화시키기</b> (временно ослабляет).<br>✖️ ① делает жёлтым, ② создаёт в несколько слоёв, ④ защищает от пищи — противоречат «바로 닦으면 더 손상된다».<br>🧩 산성 = «кислотность»; 중화되다 = «нейтрализоваться»."},{"n":30,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"누군가에게 매를 입히고 미안한 척 거짓으로 흘리는 눈물을 '악어의 눈물'에 비유한다. 실제로 악어는 먹잇감을 잡아먹으면서 눈물을 흘린다. 눈물샘을 담당하는 신경과 턱을 움직이는 신경이 연결되어 있기 때문에 음식을 씹을 때면 눈물이 나오는 것이다. 이 눈물 때문에 악어는 마치 다른 동물을 잡아먹으면서 (        ) 것처럼 보인다. '악어의 눈물'이라는 표현은 인간의 가식적인 행위를 악어의 생리적 현상에 비유한 것이다.","options":["두려움에 떠는","죄책감을 느끼는","갈증을 해소하는","배부름에 만족하는"],"answer":2,"explain":"Крокодил плачет, поедая добычу (нервы слёзной железы и челюсти связаны), поэтому КАЖЕТСЯ, будто он чувствует вину, пожирая других.<br>✅ <b>② 죄책감을 느끼는</b> (испытывающий чувство вины) — выражение «крокодиловы слёзы» = притворное раскаяние.<br>✖️ ① дрожащий от страха, ③ утоляющий жажду, ④ довольный сытостью — не вяжутся с «미안한 척 거짓 눈물».<br>🧩 가식적 = «притворный»; 죄책감 = «чувство вины»."},{"n":31,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"음료수 병과 같이 액체를 담는 용기들은 대부분 원기둥 모양이다. 원기둥을 선택하는 가장 큰 이유는 (        ) 위해서이다. 예를 들어 음료수 병의 밑면이 정사각형, 정삼각형, 원일 경우를 비교해 보자. 밑면의 넓이가 똑같이 100cm²일 때 둘레는 각각 40cm, 46cm, 35cm 정도로 원의 둘레가 가장 짧다. 따라서 같은 양의 액체를 담는 조건이라면 둘레를 감싸는 재료가 가장 적게 드는 원기둥으로 만들어 생산비를 낮추고자 하는 것이다.","options":["보기 좋게 만들기","보관을 편리하게 하기","손으로 잡기 편하게 하기","용기의 제작 비용을 줄이기"],"answer":4,"explain":"При равной площади дна периметр у круга наименьший (40/46/35 см) → меньше материала на стенки → ниже себестоимость.<br>✅ <b>④ 용기의 제작 비용을 줄이기</b> (снизить стоимость изготовления тары).<br>✖️ ① сделать красивым, ② удобно хранить, ③ удобно держать — текст про экономию материала.<br>🧩 원기둥 = «цилиндр»; 둘레 = «периметр»; 생산비 = «себестоимость»."},{"n":32,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"멍게는 바다에 서식하는 해양 생물로 성장 과정에서 흥미로운 변화를 겪는다. 어린 멍게는 올챙이와 같이 자유롭게 헤엄쳐 더 나은 서식지를 찾아 이동한다. 바위 등 적절한 장소를 발견하면 멍게는 거기에 붙어 생활하게 되어 더 이상 이동할 필요가 없어진다. 이렇게 자리를 잡은 멍게는 스스로 이동에 필요한 신체 기관들을 없애고 식물처럼 한곳에 정착하며 살아간다.","options":["멍게는 한곳에 자리를 잡으면 서식지를 바꾸지 않는다.","멍게는 평생 동안 바닷속을 헤엄쳐 먹이를 찾아다닌다.","멍게는 성장 과정에서 신체의 변화가 일어나지 않는다.","멍게는 정착 후에도 이동에 필요한 기관을 계속 유지한다."],"answer":1,"explain":"✅ <b>① Закрепившись в одном месте, асцидия не меняет среду обитания.</b> — «붙어 … 더 이상 이동할 필요가 없어진다», «한곳에 정착».<br>✖️ ② всю жизнь плавает за едой — нет, только в юности, ③ нет изменений тела — наоборот, «흥미로운 변화», ④ сохраняет органы движения — наоборот, «없애고».<br>🧩 멍게 = «асцидия (морской пузырь)»; 정착하다 = «оседать»."},{"n":33,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"조선 시대 화가 신윤복의 '월하정인'은 은은한 달빛 아래 다정히 서 있는 연인을 그린 풍속화이다. 이 그림의 제작 연도는 밝혀지지 않았지만 천문학자들은 그림 속 달의 모양, 그림에 쓰여 있는 글을 분석해 1793년 8월 21일 밤이 그림의 배경이 되었다고 추정한다. '월하정인'에 나오는 위가 볼록한 초승달은 보기 드문 형태로 부분 월식 때만 나타난다. 실제로 왕실의 기록에도 그날 밤 월식이 있었다는 내용이 있어 이 추정을 뒷받침한다.","options":["월하정인은 작가를 알 수 없는 그림이다.","월하정인의 제작 연도가 작품에 기록되어 있다.","월하정인의 배경은 부분 월식이 있었던 밤으로 추정된다.","천문학자들은 그림 속 현상이 천문학적으로 불가능하다고 본다."],"answer":3,"explain":"✅ <b>③ Фон «Вольхачжонъин» предположительно — ночь частичного лунного затмения.</b> — необычный «위가 불룩한 초승달» бывает только при частичном затмении; есть и запись о затмении той ночью.<br>✖️ ① автор неизвестен — нет, Син Юнбок, ② год записан в работе — нет, «밝혀지지 않았지만», ④ астрономы считают невозможным — наоборот, проанализировали и датировали.<br>🧩 풍속화 = «жанровая живопись»; 월식 = «лунное затмение»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"국내 연구진이 벌집나방 애벌레에서 플라스틱을 분해하는 효소를 발견했다. 이 애벌레는 벌집을 먹이로 삼는데 연구진은 벌집과 플라스틱의 화학적 구조가 유사하다는 점에 주목했다. 실제로 애벌레에게 플라스틱을 먹였을 때 벌집을 소화하는 효소가 생성되어 플라스틱을 빠르게 분해했다. 연구진은 이 효소를 대량 생산해 활용하면 폐플라스틱 처리의 획기적 방안이 될 것으로 기대하고 있다.","options":["연구진은 애벌레가 환경 문제를 발생시킨다는 점에 주목했다.","벌집과 플라스틱은 화학적으로 서로 다른 구조를 가지고 있다.","애벌레는 벌집과 플라스틱을 먹었을 때 각기 다른 효소를 배출했다.","연구진은 이 효소로 폐플라스틱을 처리할 수 있을 것이라고 기대했다."],"answer":4,"explain":"✅ <b>④ Учёные ожидают, что этим ферментом можно перерабатывать пластиковые отходы.</b> — «폐플라스틱 처리의 획기적 방안».<br>✖️ ① отметили, что личинка создаёт эко-проблемы — нет, отметили схожесть структуры сот и пластика, ② разные структуры — наоборот, «유사», ③ выделяла разные ферменты — нет, тот же фермент (что переваривает соты) расщепляет пластик.<br>🧩 효소 = «фермент»; 분해하다 = «расщеплять»; 폐플라스틱 = «пластиковые отходы»."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"인류를 화성에 보내기 위한 우주 탐사 프로젝트가 한창이다. 이를 두고 당장의 의식주 문제를 해결하는 것이 더 시급하다고 비판하는 일각의 목소리도 있다. 하지만 우주 탐사는 단순히 미지의 세계를 탐구하는 것만은 아니다. 우주라는 극한의 환경은 기존의 기술로는 해결하지 못하는 혁신적인 해결책을 요구한다. 이 과정에서 개발된 기술은 사회의 다양한 분야에서 새로운 산업과 일자리를 창출하며 경제 성장의 동력이 된다.","options":["우주 탐사를 반대하는 주장이 갈수록 힘을 얻고 있다.","우주 탐사는 경제적 가치를 창출하지 못할 가능성이 높다.","우주 탐사 기술은 산업과 경제 전반을 발전시키는 역할을 한다.","우주 탐사의 가장 중요한 임무는 미지의 세계를 탐구하는 것이다."],"answer":3,"explain":"✅ <b>③ Технологии космических исследований развивают промышленность и экономику в целом.</b> — «개발된 기술은 … 새로운 산업과 일자리를 창출하며 경제 성장의 동력».<br>✖️ ① оппозиция набирает силу, ② не создаст экономической ценности — наоборот, ④ важнее всего — исследовать неизвестное — текст подчёркивает именно экономический эффект.<br>🧩 우주 탐사 = «космические исследования»; 동력 = «движущая сила»."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"산업 현장에는 위험 요소가 많아 안전사고가 빈번히 발생한다. 이때 시각적, 물리적 환경을 개선하면 안전사고를 효과적으로 줄일 수 있다. 일례로 기계의 정지 버튼에 빨간 화살표를 붙여 두면 기계의 작동을 급히 멈춰야 하는 비상 상황에서 근로자가 빠르게 버튼을 찾아 누를 수 있다. 또 칼날을 사용하는 작업대 옆에 자석으로 된 수거함을 두어 위험한 칼날을 자석에 부착하게 만듦으로써 사고 발생률을 낮출 수 있다.","options":["근로자들의 작업 효율을 높이기 위한 대책이 마련되었다.","안전사고가 발생하는 원인을 규명하는 연구가 이루어졌다.","산업 현장의 작업 환경을 개선하면 안전사고를 예방할 수 있다.","안전사고 방지를 담당하는 현장 책임자의 역할이 강조되고 있다."],"answer":3,"explain":"✅ <b>③ Улучшение рабочей среды на производстве позволяет предотвращать несчастные случаи.</b> — примеры: красная стрелка на кнопке стоп, магнитный сборник для лезвий.<br>✖️ ① меры для роста эффективности труда, ② исследование причин ЧП, ④ роль ответственного на месте — это не тема (тема — улучшение СРЕДЫ).<br>🧩 안전사고 = «несчастный случай»; 예방하다 = «предотвращать»."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"최근 동네 놀이터와 편의 시설 등에 외부인 출입을 금지하고 그곳에 살고 있는 거주민만 이용할 수 있게 하는 곳이 많아지고 있다. 이러한 변화는 관리의 편리성과 거주민 보호를 추구한 결과이지만 이는 도시의 개방성을 약화시키는 부작용을 낳는다. 도시 발전에 필요한 개방성은 다양한 사람이 어울릴 수 있는 공간을 확보하는 데서 비롯된다. 도시의 공간이 폐쇄적으로 구획화되면 이웃 간의 교류가 줄어 활력을 잃게 된다.","options":["도시 관리의 편리성을 높일 수 있도록 노력해야 한다.","도시를 설계할 때는 거주민 보호를 최우선으로 삼아야 한다.","외부인의 출입을 제한하여 거주민 간의 교류를 활성화해야 한다.","도시의 활력을 위해서는 개방적 공간과 시설을 늘리는 것이 좋다."],"answer":4,"explain":"✅ <b>④ Ради жизненной силы города лучше увеличивать открытые пространства и объекты.</b> — закрытость снижает «개방성», уменьшает обмен и «활력».<br>✖️ ① повышать удобство управления, ② защита жителей — приоритет, ③ ограничивать вход чужих — противоречат идее ОТКРЫТОСТИ.<br>🧩 개방성 = «открытость»; 폐쇄적 = «закрытый»; 활력 = «жизненная сила»."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"목적세는 사용처가 미리 정해진 세금이다. 교통세, 환경세, 교육세 등이 그 예이다. 그런데 목적세가 시의에 따라서는 국가 재정의 효율성을 떨어뜨릴 수 있다. 많은 종류의 목적세가 당해 년에 소진되지 못하고 불필요한 곳에 남용되기 때문이다. 남는 목적세를 적절히 용도 변경해서 필요한 곳에 사용하려고 해도 목적세라는 명목에 묶여 해당 분야 외에는 사용할 수 없는 것은 큰 문제이다.","options":["목적세의 징수 금액을 점진적으로 늘려야 한다.","목적세를 도입할 때는 국민의 동의를 얻어야 한다.","목적세를 통해 신속하게 쓸 수 있는 재원을 확보해야 한다.","목적세를 필요에 따라 유연하게 사용할 수 있도록 해야 한다."],"answer":4,"explain":"✅ <b>④ Целевые налоги нужно позволять использовать гибко, по необходимости.</b> — проблема в том, что остаток «привязан к названию» и не идёт в другие сферы.<br>✖️ ① постепенно увеличивать сборы, ② получать согласие граждан, ③ обеспечить быстро используемые средства — текст именно о ГИБКОСТИ расходования.<br>🧩 목적세 = «целевой налог»; 용도 변경 = «изменение назначения»; 유연하게 = «гибко»."},{"n":39,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"운동선수들의 평균 은퇴 연령은 23.6세로 매우 짧은 편이다. (㉠) 그래서 지도자의 길을 걷는 소수의 선수를 제외하면 대부분의 선수들은 은퇴 후 새로운 직업을 찾아야 한다. (㉡) 하지만 선수들은 오랜 시간 운동에만 매진해 왔기 때문에 개개인이 은퇴 이후의 삶을 준비할 여력이 없다. (㉢) 이에 현역부터 선수들에게 직업 교육 등을 지원하는 구단이 많아지고 있다. (㉣)\n\n<보기> 사회적으로도 이들을 위한 재교육의 장이 충분히 마련되어 있지 않다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기> с «-도» добавляет ещё одну причину (помимо личной неготовности — «사회적으로도 재교육의 장이 부족») к тому, что спортсменам трудно. Идёт после «준비할 여력이 없다» (㉢), перед «이에 … 구단이 많아지고 있다».<br>✅ <b>③ ㉢</b>.<br>🧩 «사회적으로도» подхватывает личную проблему и добавляет общественную; «이에» (㉣) — следствие."},{"n":40,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"인간은 오랫동안 시간을 측정하는 방법을 찾기 위해 노력해 왔다. (㉠) 해시계, 물시계 등을 거쳐 기계식 시계가 개발되면서 정확한 시간의 측정이 가능해졌다. (㉡) 노동자들이 일정한 시간에 출퇴근하고 서로 다른 공간에서도 공동의 일을 동시에 할 수 있게 되었다. (㉢) 또한 출발과 도착 시간이 일정해야 하는 기차나 여객선 등의 대중교통 수단도 크게 발달하였다. (㉣) 오늘날 톱니바퀴처럼 돌아가는 우리의 일상이 다 시계의 지배를 받고 있는 것이다.\n\n<보기> 시간을 정확히 관리·통제할 수 있게 되면서 사회 전반에 획기적인 변화들이 나타나기 시작했다.","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"<보기> «когда время стало точно управляемым, начались перемены» — идёт сразу после «정확한 시간의 측정이 가능해졌다» (㉡), вводя примеры перемен (фиксированный график рабочих и т.д.).<br>✅ <b>② ㉡</b>.<br>🧩 <보기> — обобщающий «мостик» от изобретения точных часов к перечню изменений."},{"n":41,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"역사학자 이승원이 『사대부의 시대』라는 책을 출간했다. (㉠) 사대부는 국가 운영에 중요한 역할을 했던 조선 시대의 양반 계층을 말한다. (㉡) 이 책은 사대부 계층이 조선의 정치·경제·문화에 미친 영향을 깊이 있게 분석하고 있다. (㉢) 무엇보다도 저자는 사대부가 폐쇄적인 신분제 사회에서 특권만을 누리려 했다는 통념을 비판한다. (㉣) 이 책을 통해 독자들은 사대부의 다양한 면모를 볼 수 있다.\n\n<보기> 오히려 사대부가 조선의 변화를 주도한 능력주의 원칙의 신봉자들이었음을 역사적 자료를 통해 증명한다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"<보기> с «오히려» (напротив) опровергает «통념» (расхожее мнение, что садэбу лишь искали привилегий), раскритикованное в ㉣. Поэтому идёт сразу после «통념을 비판한다» (㉣).<br>✅ <b>④ ㉣</b>.<br>🧩 «오히려 … 증명했다» — антитеза к «통념»."},{"n":42,"points":2,"instr":"Выберите чувство героя («그») в подчёркнутой части.","passage":"⚠️ Оригинальный литературный отрывок защищён авторским правом и официально НЕ публикуется в материалах 102-го экзамена: «저작권 관련 법령에 따라 본 문항의 지문은 공개하지 않습니다». Полный текст не приводится — ответ по официальному ключу.\n\nКонтекст (по вопросам): «он» (그) готовится сделать предложение (청혼); упоминается коробочка с кольцом (반지함); он спланировал поездку на выходные ради предложения.","options":["화나고 답답하다","놀라고 당황스럽다","서럽고 짜증스럽다","섭섭하고 허전하다"],"answer":2,"explain":"Литературный отрывок официально не опубликован, поэтому точную выделенную фразу процитировать нельзя. По официальному ключу верный ответ — <b>② 놀라고 당황스럽다</b> (быть удивлённым и растерянным).<br>🧩 Значения: ① 화나고 답답하다 — «зол и стеснён», ② 놀라고 당황스럽다 — «удивлён и растерян», ③ 서럽고 짜증스럽다 — «обидно и раздражённо», ④ 섭섭하고 허전하다 — «досадно и пусто на душе».<br>📌 Тип: 심정 (чувство героя) по выделенной фразе художественного текста."},{"n":43,"points":2,"instr":"Выберите вариант, который можно понять из текста.","passage":"⚠️ Тот же отрывок, что и в задании 42, официально не публикуется по авторскому праву («본 문항의 지문은 공개하지 않습니다»). Ответ — по официальному ключу.\n\nКонтекст: «он» (그) готовит предложение руки и сердца, есть коробочка с кольцом, спланирована поездка на выходные.","options":["그는 반지함이 어디에 있는지 몰랐다.","그는 여자 앞에서 눈물을 자주 보였다.","그는 청혼을 위해 주말여행을 계획했다.","그는 그녀와 함께 반지를 구매하러 갔다."],"answer":3,"explain":"По официальному ключу верный ответ — <b>③ 그는 청혼을 위해 주말여행을 계획했다</b> (он спланировал поездку на выходные ради предложения).<br>✖️ ① не знал, где коробочка с кольцом, ② часто плакал перед девушкой, ④ ходил покупать кольцо вместе с ней — текстом не подтверждаются.<br>📌 Тип: 내용으로 알 수 있는 것 (что можно вывести). Полный отрывок не опубликован NIIED."},{"n":44,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"르네상스 시대에 꽃을 피운 해부학은 인체의 내부를 파악할 수 있게 해 의학 분야에 획기적인 발전을 가져왔다. 동시에 미술가들에게 인물의 움직임을 좀 더 자연스럽게 표현할 수 있는 길을 열어 주었다. 당시 연구 열기가 뜨거웠던 해부학 교실에서는 인체의 근육, 뼈, 장기 등의 세세한 구조를 기록할 누군가가 필요했고, 그 역할은 자연스레 미술가가 수행하게 되었다. 이후 미술가들은 근육의 구조나 그 움직임과 관련된 해부학적 지식을 작품에 적용하여 그림 속 인물들을 한층 더 자연스럽게 그려 냈다. 예를 들어 이전의 그림에서는 (        ) 알지 못해 사람의 발이 떠 있는 것처럼 어색하게 그렸다. 그러나 해부학적 지식이 더해진 이후에는 두 발이 땅을 딛고 서 있는 모습을 현실감 있게 그릴 수 있게 되었다.","options":["질병이 언제 발생하는지","근육이 어떻게 움직이는지","인체의 구조가 왜 단순해지는지","해부학이 어떤 식으로 분류되는지"],"answer":2,"explain":"Раньше художники, не зная, КАК ДВИГАЮТСЯ МЫШЦЫ, рисовали движения конечностей неуклюже; после анатомических знаний — реалистично.<br>✅ <b>② 근육이 어떻게 움직이는지</b> (как движутся мышцы).<br>✖️ ① когда возникает болезнь, ③ почему упрощается строение тела, ④ как классифицируется анатомия — не объясняют «어색하게 그렸다».<br>🧩 해부학 = «анатомия»; 어색하다 = «неестественный»."},{"n":45,"points":2,"instr":"Выберите главную тему текста.","passage":"르네상스 시대에 꽃을 피운 해부학은 인체의 내부를 파악할 수 있게 해 의학 분야에 획기적인 발전을 가져왔다. 동시에 미술가들에게 인물의 움직임을 좀 더 자연스럽게 표현할 수 있는 길을 열어 주었다. 당시 연구 열기가 뜨거웠던 해부학 교실에서는 인체의 근육, 뼈, 장기 등의 세세한 구조를 기록할 누군가가 필요했고, 그 역할은 자연스레 미술가가 수행하게 되었다. 이후 미술가들은 근육의 구조나 그 움직임과 관련된 해부학적 지식을 작품에 적용하여 그림 속 인물들을 한층 더 자연스럽게 그려 냈다. 예를 들어 이전의 그림에서는 근육이 어떻게 움직이는지 알지 못해 사람의 발이 떠 있는 것처럼 어색하게 그렸다. 그러나 해부학적 지식이 더해진 이후에는 두 발이 땅을 딛고 서 있는 모습을 현실감 있게 그릴 수 있게 되었다.","options":["해부학은 의학뿐만 아니라 미술에도 영향을 끼쳤다.","미술가들은 해부학 강의를 통해 경제 활동을 할 수 있었다.","해부학 강의는 일반인들의 그림에 대한 관점을 바꿔 놓았다.","해부학의 발달로 미술에서 다룰 수 있는 소재가 다양해졌다."],"answer":1,"explain":"✅ <b>① Анатомия повлияла не только на медицину, но и на искусство.</b> — «의학 분야에 획기적인 발전» + «미술가들에게 … 길을 열어 주었다».<br>✖️ ② художники могли зарабатывать через лекции по анатомии, ③ изменила взгляд обывателей на живопись, ④ расширила набор сюжетов — это частности, а тема — двойное влияние (медицина И искусство).<br>🧩 해부학 = «анатомия»; -뿐만 아니라 = «не только…, но и»."},{"n":46,"points":2,"instr":"Выберите отношение автора, выраженное в тексте.","passage":"전 세계 바다 밑에는 400개가 넘는 해저 전선이 대양과 연안을 따라 설치돼 있다. 나라 간 정보 통신의 99%가 이 해저 전선을 통해 이루어진다. 하지만 한국은 급증하는 정보 전송량에 비해 해저 전선이 턱없이 부족하다. 여기에는 여러 원인이 있다. 우선 서해안의 경우 수심이 얕아 설치가 까다롭고 어업 피해를 우려한 어민들의 반대도 극심하다. 게다가 해저 전선 설치는 첨단 기술과 막대한 자본이 요구되며 주변국과의 협력이 필수이다. 이는 정부의 개입 없이 민간 기업의 힘만으로는 해결하기 어렵다. 따라서 정부는 해저 전선 설치를 위한 법적·경제적·외교적 제도를 정비하는 등 해저 전선의 수를 늘리는 적극적인 방안을 마련해야 한다. 디지털 전환이 가속화되고 데이터 수요가 급증하는 오늘날, 해저 전선을 얼마나 보유하느냐에 따라 세계 통신망의 주역이 결정된다는 것을 명심해야 한다.","options":["해저 전선의 구조로 생길 부작용을 우려하고 있다.","해저 전선의 문제점과 위험성에 대해 역설하고 있다.","해저 전선에 대한 국가적 차원의 대응을 촉구하고 있다.","해저 전선이 세계정세에 미치는 영향을 부정하고 있다."],"answer":3,"explain":"✅ <b>③ Призывает к ответу на уровне государства по поводу подводных кабелей.</b> — «정부는 … 적극적인 방안을 마련해야 한다».<br>✖️ ① опасается побочных эффектов конструкции, ② настаивает на проблемах и опасности, ④ отрицает влияние на мировую обстановку — автор именно ПРИЗЫВАЕТ государство действовать.<br>🧩 해저 전선 = «подводный кабель»; 촉구하다 = «настоятельно призывать»."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"전 세계 바다 밑에는 400개가 넘는 해저 전선이 대양과 연안을 따라 설치돼 있다. 나라 간 정보 통신의 99%가 이 해저 전선을 통해 이루어진다. 하지만 한국은 급증하는 정보 전송량에 비해 해저 전선이 턱없이 부족하다. 여기에는 여러 원인이 있다. 우선 서해안의 경우 수심이 얕아 설치가 까다롭고 어업 피해를 우려한 어민들의 반대도 극심하다. 게다가 해저 전선 설치는 첨단 기술과 막대한 자본이 요구되며 주변국과의 협력이 필수이다. 이는 정부의 개입 없이 민간 기업의 힘만으로는 해결하기 어렵다. 따라서 정부는 해저 전선 설치를 위한 법적·경제적·외교적 제도를 정비하는 등 해저 전선의 수를 늘리는 적극적인 방안을 마련해야 한다. 디지털 전환이 가속화되고 데이터 수요가 급증하는 오늘날, 해저 전선을 얼마나 보유하느냐에 따라 세계 통신망의 주역이 결정된다는 것을 명심해야 한다.","options":["한국은 현재 충분한 수의 해저 전선을 보유하고 있다.","해저 전선을 통해 전송되는 국가 간 정보의 양이 매우 많다.","어민들은 인근 어장에 해저 전선을 설치하는 것을 환영한다.","해저 전선은 지형에 구애받지 않고 자유롭게 설치할 수 있다."],"answer":2,"explain":"✅ <b>② Объём межгосударственной информации, передаваемой по подводным кабелям, очень велик.</b> — «정보 통신의 99%가 이 해저 전선을 통해».<br>✖️ ① у Кореи достаточно кабелей — наоборот, «턱없이 부족», ③ рыбаки приветствуют установку — не упомянуто, ④ можно ставить свободно вне зависимости от рельефа — нет, нужны технологии/капитал/сотрудничество.<br>🧩 전송량 = «объём передачи»; 턱없이 부족하다 = «катастрофически не хватает»."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"퇴직 급여 제도 도입 후 20년 만에 개편안이 마련되고 있다. 그 배경에는 퇴직금 체불 문제가 있다. 회사가 퇴직금을 은행 같은 사외 기관에 맡기지 않고 자체 관리하다 보니 회사 사정에 따라 퇴직금 체불이 빈번히 발생해 왔다. 한편 퇴직 즉시 퇴직금 수령이 가능한 현행 제도는 근로자의 노후 소득 보장을 어렵게 한다는 문제의식도 개편안 마련의 배경이다. 이번 개편안은 퇴직금을 매달 외부 기관에 맡기는 것을 의무화해 퇴직금 체불의 위험성을 줄이고 퇴직금 수령 시기를 55세로 정해 고질적인 노인 빈곤 문제의 해결을 꾀하고 있다. 그러나 이 개편안이 시행될 경우 퇴직금 명목으로 일정 금액을 의무적으로 매달 납입하게 한 조항은 영세 사업장에 부담이 된다. 또 퇴직금을 조기 수령할 수 없게 한 조항은 근로자의 선택권을 침해한다는 반론이 있다. 따라서 이번 개편안의 성공 여부는 기업의 현실적인 부담과 개인의 선택권 침해라는 변수를 두고 어떻게 균형을 잡을 것인지에 달려 있다.","options":["제도의 긍정적인 사례를 제시하려고","제도 적용의 범위를 제한하도록 요구하려고","제도 도입을 위해 근로자의 관심을 유도하려고","제도 개편의 취지와 예상되는 문제점을 알리려고"],"answer":4,"explain":"Текст объясняет ПРИЧИНУ/смысл реформы (борьба с невыплатой пособий, бедность пожилых) И её ожидаемые ПРОБЛЕМЫ (нагрузка на малый бизнес, ущемление выбора работника).<br>✅ <b>④ Сообщить о цели реформы и ожидаемых проблемах.</b><br>✖️ ① привести позитивные примеры, ② требовать ограничить применение, ③ привлечь интерес работников — текст и про смысл, и про минусы.<br>🧩 퇴직금 = «выходное пособие»; 개편안 = «проект реформы»; 체불 = «невыплата»."},{"n":49,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"퇴직 급여 제도 도입 후 20년 만에 개편안이 마련되고 있다. 그 배경에는 퇴직금 체불 문제가 있다. 회사가 퇴직금을 은행 같은 사외 기관에 맡기지 않고 자체 관리하다 보니 회사 사정에 따라 퇴직금 체불이 빈번히 발생해 왔다. 한편 퇴직 즉시 퇴직금 수령이 가능한 현행 제도는 근로자의 노후 소득 보장을 어렵게 한다는 문제의식도 개편안 마련의 배경이다. 이번 개편안은 퇴직금을 매달 외부 기관에 맡기는 것을 의무화해 (        ) 줄이고 퇴직금 수령 시기를 55세로 정해 고질적인 노인 빈곤 문제의 해결을 꾀하고 있다. 그러나 이 개편안이 시행될 경우 퇴직금 명목으로 일정 금액을 의무적으로 매달 납입하게 한 조항은 영세 사업장에 부담이 된다. 또 퇴직금을 조기 수령할 수 없게 한 조항은 근로자의 선택권을 침해한다는 반론이 있다. 따라서 이번 개편안의 성공 여부는 기업의 현실적인 부담과 개인의 선택권 침해라는 변수를 두고 어떻게 균형을 잡을 것인지에 달려 있다.","options":["경영 업체의 수를","퇴직금의 수령액을","노령 근로자의 비중을","퇴직금 체불의 위험성을"],"answer":4,"explain":"Реформа обязывает ежемесячно сдавать пособие во внешнюю организацию → значит, СНИЖАЕТ риск невыплаты пособия (именно «퇴직금 체불» названо проблемой).<br>✅ <b>④ 퇴직금 체불의 위험성을</b> (줄이고) — снижает риск невыплаты.<br>✖️ ① число управляющих фирм, ② сумму получаемого пособия, ③ долю пожилых работников — не вяжутся с «외부 기관에 맡기는 것을 의무화».<br>🧩 체불 = «задержка/невыплата»; 위험성 = «риск»."},{"n":50,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"퇴직 급여 제도 도입 후 20년 만에 개편안이 마련되고 있다. 그 배경에는 퇴직금 체불 문제가 있다. 회사가 퇴직금을 은행 같은 사외 기관에 맡기지 않고 자체 관리하다 보니 회사 사정에 따라 퇴직금 체불이 빈번히 발생해 왔다. 한편 퇴직 즉시 퇴직금 수령이 가능한 현행 제도는 근로자의 노후 소득 보장을 어렵게 한다는 문제의식도 개편안 마련의 배경이다. 이번 개편안은 퇴직금을 매달 외부 기관에 맡기는 것을 의무화해 퇴직금 체불의 위험성을 줄이고 퇴직금 수령 시기를 55세로 정해 고질적인 노인 빈곤 문제의 해결을 꾀하고 있다. 그러나 이 개편안이 시행될 경우 퇴직금 명목으로 일정 금액을 의무적으로 매달 납입하게 한 조항은 영세 사업장에 부담이 된다. 또 퇴직금을 조기 수령할 수 없게 한 조항은 근로자의 선택권을 침해한다는 반론이 있다. 따라서 이번 개편안의 성공 여부는 기업의 현실적인 부담과 개인의 선택권 침해라는 변수를 두고 어떻게 균형을 잡을 것인지에 달려 있다.","options":["퇴직 급여 제도가 도입된 것은 최근의 일이다.","현행 제도에서는 55세가 돼야 퇴직금을 수령할 수 있다.","이번 개편안은 퇴직금을 외부 기관에 맡기게 하는 안을 포함한다.","이번 개편안이 시행되면 영세 사업장의 부담을 덜어 줄 수 있게 된다."],"answer":3,"explain":"✅ <b>③ Реформа включает обязанность сдавать пособие во внешнюю организацию.</b> — «외부 기관에 맡기는 것을 의무화».<br>✖️ ① систему ввели недавно — нет, «20년 만에 개편» (ввели 20 лет назад), ② по нынешней системе пособие в 55 лет — нет, сейчас можно сразу; 55 лет — это НОВАЯ норма, ④ облегчит нагрузку на малый бизнес — наоборот, «영세 사업장에 부담».<br>🧩 현행 = «действующий»; 영세 사업장 = «малое предприятие»."}]
      },
      writing: {"durationMin":50,"label":"제102회 · 쓰기 (51~54)","tasks":[{"n":51,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Это электронное письмо председателя кружка — формальный стиль -습니다/-십시오.","passage":"✉️ Email — 제목: 개인 물건 정리 요청  (2025.10.10.(금))\n\n안녕하세요. 동아리 회장 흐엉입니다.\n학생회관 공사 때문에 동아리 방을 옮기게 되었습니다.\n그런데 현재 개인 물건들이 너무 많습니다.\n동아리 방을 옮기려면 이 물건들부터 먼저 ( ㉠ ).\n방학을 하자마자 공사가 시작됩니다.\n방학이 ( ㉡ ) 개인 물건을 모두 가져가 주십시오.","blanks":[{"slot":"㉠","model":"정리해야 합니다","check":"«동아리 방을 옮기려면 이 물건들부터 먼저 ( )» → чтобы переехать, личные вещи надо СНАЧАЛА разобрать: 정리해야 합니다 (нужно прибрать/убрать). Стиль -습니다."},{"slot":"㉡","model":"시작되기 전에","check":"«방학을 하자마자 공사가 시작됩니다. 방학이 ( ) 개인 물건을 모두 가져가 주십시오» → ремонт начнётся, как только начнутся каникулы → забрать вещи ДО того, как (каникулы/ремонт) начнутся: 시작되기 전에."}]},{"n":52,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст о самолётах — письменный стиль -다.","passage":"큰 항공기는 주로 고도가 높은 하늘에서 비행을 한다. 높이 올라가면 날씨의 영향을 별로 ( ㉠ ) 흔들림이 적다. 반면 작은 항공기는 날씨의 영향을 받더라도 낮은 고도에서 비행을 해야 한다. 왜냐하면 높은 고도에서 ( ㉡ ) 항공기의 엔진이 크고 좋아야 하며 연료도 많이 필요하기 때문이다.","blanks":[{"slot":"㉠","model":"받지 않아서","check":"«높이 올라가면 날씨의 영향을 별로 ( ) 흔들림이 적다» → высоко погода почти не влияет, поэтому меньше тряски: (영향을) 받지 않아서. Связка причины -아서."},{"slot":"㉡","model":"비행을 하기 위해서는 / 날기 위해서는","check":"«왜냐하면 높은 고도에서 ( ) 항공기의 엔진이 크고 좋아야 하며 …» → чтобы ЛЕТАТЬ на большой высоте, нужен мощный двигатель и много топлива: 비행을 하기 위해서는 / 날기 위해서는. Цель -기 위해서는."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음은 「한국 캠핑 인구의 변화」에 대한 자료이다. 이 내용을 200~300자의 글로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные об изменении числа любителей кемпинга в Корее (한국관광공사) текстом 200–300 знаков. Сравните общий рост и смену возрастного рейтинга, укажите причины. Письменный стиль -다, без заголовка.","image":"assets/topik2/exams/img/102-w53.png","model":"한국관광공사에서 한국 캠핑 인구의 변화에 대해 조사한 자료에 따르면 캠핑 인구는 2019년에 340만 명이었던 것이 2024년에 650만 명으로 약 2배나 증가하였다. 이용 연령별 순위 변화로 보면 2019년에는 20대~30대가 1위를 차지하였고 2위는 40대~50대로 나타났다. 이와 달리 2024년에는 40대~50대가 1위로 가장 많았고 2위는 20대~30대로 나타났다. 이렇게 변화한 것은 캠핑 장비의 고급화와 캠핑장 대여료 증가로 인해 경제력이 요구되고 자녀와의 여가 활동을 위한 가족 단위 캠핑이 증가하였기 때문으로 나타났다.","check":"① Назван источник и предмет (한국관광공사 · 캠핑 인구 변화)? ② Общий рост с цифрами (2019년 340만 → 2024년 650만, 약 2배)? ③ Смена возрастного рейтинга (2019: 20~30대 1위 → 2024: 40~50대 1위) со связкой 이와 달리? ④ Указаны причины (장비 고급화·캠핑장 대여료 증가 → 경제력 요구; 가족 단위 캠핑 증가)? ⑤ Стиль -다, 200~300 знаков, без заголовка?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 참고하여 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков на тему «디지털 소외 문제와 해결 방안» (цифровое неравенство и пути решения). Раскройте все три вопроса, разбейте на абзацы, письменный стиль -다.","passage":"최근에는 식당에서부터 은행, 병원에 이르기까지 많은 곳에서 다양한 디지털 기기를 사용하고 있다. 하지만 디지털 기기를 활용하지 못해서 소외되는 사람들도 있다. 아래의 내용을 중심으로 「디지털 소외 문제와 해결 방안」에 대한 자신의 생각을 쓰라.\n• 디지털 기술은 우리 생활에서 어떻게 활용되고 있는가?\n• 디지털 사회에서 소외되는 사람들은 누구이며, 어떤 문제를 겪을 수 있는가?\n• 디지털 소외 문제를 해결하기 위해 개인과 사회는 어떻게 해야 하는가?","model":"과학 기술이 빠르게 발달하면서 과거와는 달리 일상생활에서 디지털 기술의 활용이 일반화되고 있다. 식당에서는 대면을 하지 않아도 키오스크로 음식을 주문할 수 있게 되었고 관공서나 금융 기관을 직접 방문하지 않아도 컴퓨터나 스마트폰으로 서비스를 이용할 수 있게 되었다. 또한 병원의 진료 예약이나 공연, 기차표 등의 예매도 인터넷으로 손쉽게 할 수 있다.\n그러나 이러한 편의를 모든 사람들이 동일하게 누리는 것은 아니다. 고령층의 경우 디지털 기기가 익숙하지 않아 금융·의료 서비스를 이용하는 데에 어려움이 따른다. 그리고 경제적인 여건이 되지 않아 디지털 기기를 구입하거나 사용하는 것이 부담이 되는 사람들도 있을 것이다. 또한 디지털 인프라가 부족한 지역에서 거주하는 사람들은 온라인으로 제공 받을 수 있는 서비스가 제한적이다.\n이러한 문제를 해결하기 위해서는 개인과 사회 모두가 노력해야 한다. 개인의 경우 처음에는 익숙하지 않더라도 변화하는 시대에 뒤처지지 않게 디지털 기기의 사용법을 익히도록 해야 한다. 이를 위해서 정부에서는 디지털 소외 계층을 위한 지원 정책을 마련해 모든 국민들이 일상에서 디지털 기술을 활용할 수 있게 하여 소외되는 사람들이 없도록 해야 한다. 그리고 디지털 인프라를 확충하여 지역과 계층에 무관하게 모든 사람들이 디지털 기술 발달의 혜택을 고르게 누릴 수 있도록 해야 한다.","check":"① Раскрыт 1-й вопрос — как используется (키오스크 주문, 온라인 금융·관공서, 예약·예매)? ② Раскрыт 2-й вопрос — кто исключён и какие проблемы (고령층·저소득층·디지털 인프라 부족 지역, ограниченный доступ к услугам)? ③ Раскрыт 3-й вопрос — решения личное (освоить устройства) + общественное (господдержка соц. групп, расширение инфраструктуры)? ④ Структура: использование / проблемы / решения, связки 그러나·또한·이러한 문제를 해결하기 위해서는·그리고? ⑤ Стиль -다, объём 600~700 знаков, без дословного переписывания задания?"}]}
    },
    96: {
      listening: {
        durationMin: 60, total: 100, label: '제96회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/96/96-TOPIK-II-Listening-Audio-File.mp3',
        questions: [{"n":1,"points":2,"image":"assets/topik2/exams/img/96-l-q1.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":1,"explain":"🎧 여자: 손님, 수박 보고 가세요. 아주 맛있어요.<br>남자: 여기 접시 위에 있는 거 한번 먹어 봐도 돼요?<br>여자: 그럼요. 드셔 보세요.<br><br>У прилавка с арбузами продавщица зазывает покупателя, он просит попробовать образец с тарелки.<br>✅ <b>①</b> — фруктовый прилавок (수박), продавщица и покупатель, который тянется к пробнику.<br>🧩 드셔 보세요 = «попробуйте» (вежл.); 접시 위에 있는 거 = «то, что на тарелке»."},{"n":2,"points":2,"image":"assets/topik2/exams/img/96-l-q2.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 의자에 앉아 보니까 어때?<br>여자: 오, 잘 만들었다. 그런데 나한텐 좀 높은 거 같아.<br>남자: 그래? 그럼 이 부분을 조금 더 잘라야겠다.<br><br>Мужчина сделал стул, женщина садится и говорит, что высоковато; мужчина решает подрезать.<br>✅ <b>②</b> — женщина сидит на стуле, мужчина наклонился, чтобы подправить/срезать ножку.<br>🧩 좀 높은 거 같아 = «кажется высоковато»; 자르다 = «отрезать»."},{"n":3,"points":2,"image":"assets/topik2/exams/img/96-l-q3.png","instr":"Прослушайте и выберите подходящий график.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 채소, 달걀 등의 식품을 정기적으로 배달 받는 서비스가 인기를 끌며 최근 4년간 이용자가 꾸준히 증가하고 있습니다. 이 서비스를 이용하는 이유는 '신선하고 품질이 좋아서'가 가장 많았으며, '가격이 합리적이어서', '편리해서'가 그 뒤를 이었습니다.<br><br>Число пользователей сервиса доставки продуктов 4 года РОВНО растёт; причины: «свежесть/качество» (больше всего) > «разумная цена» > «удобство».<br>✅ <b>②</b> — линия, СТАБИЛЬНО идущая вверх 2020→2023.<br>✖️ ① линия с провалом в 2022 (не «꾸준히 증가»), ③④ круговые диаграммы, где «편리해서» больше «가격», что противоречит порядку в тексте.<br>🧩 꾸준히 증가 = «неуклонно растёт»; 그 뒤를 잇다 = «следовать за…»."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그러다가 감기 걸릴 거예요.","이제 다 나아서 다행이에요.","병원에 한번 가 보지 그래요?","약을 안 먹어서 그런 거 아니에요?"],"answer":3,"explain":"🎧 남자: 감기는 좀 어때요?<br>여자: 약국에서 약을 사다 먹었는데 잘 안 나아요.<br>남자: ____<br><br>Лекарство из аптеки не помогает → логичный совет.<br>✅ <b>③ 병원에 한번 가 보지 그래요?</b> (сходили бы вы в больницу?).<br>✖️ ① «так и простудитесь» (она уже болеет), ② «выздоровели — и хорошо» (наоборот, не проходит), ④ «не потому ли, что не пили лекарство?» — она же пила.<br>🧩 -지 그래요? = мягкий совет «почему бы не…»."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그럼 일요일로 예약할게.","아직 약속을 하지도 않았어.","이미 도자기 수업을 시작했어.","우선 오후 두 시에 만나기로 했어."],"answer":1,"explain":"🎧 여자: 이번 주말에 도자기 체험 가기로 한 거, 언제 갈까?<br>남자: 토요일은 약속이 있고 일요일은 괜찮아.<br>여자: ____<br><br>У мужчины суббота занята, воскресенье свободно → бронируют на воскресенье.<br>✅ <b>① 그럼 일요일로 예약할게.</b><br>✖️ ② «ещё и не договаривались» (уже решают день), ③ «уже начали занятия по керамике» (только собираются), ④ про «два часа дня» — речь о ДНЕ недели, а не о времени.<br>🧩 예약하다 = «бронировать»; 체험 = «мастер-класс, проба»."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["아니야. 그건 내가 준비할게.","그러네. 얼른 마시고 들어가자.","아니야. 전시장이 멀지는 않아.","그러네. 먼저 음료수부터 사자."],"answer":2,"explain":"🎧 남자: 저기 전시장이 있네. 한번 들어가 보자.<br>여자: (놀라며) 어, 근데 음료수는 못 갖고 들어가나 봐.<br>남자: ____<br><br>В зал с напитками нельзя → надо допить и зайти.<br>✅ <b>② 그러네. 얼른 마시고 들어가자.</b> (и правда, допьём поскорее и зайдём).<br>✖️ ① «это я подготовлю», ③ «зал недалеко», ④ «сначала купим напитки» — наоборот, напитки нельзя проносить.<br>🧩 못 갖고 들어가다 = «нельзя пронести»; 얼른 = «поскорее»."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["오늘 면접시험 잘 봐야 돼.","벌써 취업했다니 정말 축하해.","회사에 도착하기 전에 연락 줘.","아직 시간이 있으니까 기다려 봐."],"answer":4,"explain":"🎧 여자: 지난주에 면접 본 회사에서 연락 왔어?<br>남자: 아니. 오늘까지 알려 준다고 했는데 소식이 없네. 벌써 세 시인데…….<br>여자: ____<br><br>Ответ обещали «до конца дня», ещё только 3 часа → подбодрить.<br>✅ <b>④ 아직 시간이 있으니까 기다려 봐.</b> (время ещё есть, подожди).<br>✖️ ① «надо хорошо пройти собеседование» (оно уже прошло), ② «поздравляю с трудоустройством» (ответа ещё нет), ③ «свяжись до прихода в офис».<br>🧩 소식이 없다 = «нет вестей»."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["너무 짧게 줄인 것 같아요.","수선을 잘해 주셔서 감사해요.","혹시 모양이 많이 이상해질까요?","이 바지로 한 치수 큰 거 없어요?"],"answer":3,"explain":"🎧 여자: 사장님, 이 바지, 길이를 좀 줄여 주실 수 있나요?<br>남자: 이런 바지는 줄이면 아랫부분 모양이 좀 달라지는데, 괜찮으세요?<br>여자: ____<br><br>Мастер предупредил, что форма низа изменится → клиентка уточняет последствие.<br>✅ <b>③ 혹시 모양이 많이 이상해질까요?</b> (а форма сильно не испортится?).<br>✖️ ① «слишком коротко укоротили» (ещё не укорачивали), ② благодарность за готовую работу, ④ «нет ли на размер больше» — она хочет укоротить ЭТИ.<br>🧩 수선하다 = «подшивать, ремонтировать (одежду)»."},{"n":9,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["여행을 간다.","수업을 듣는다.","가방을 꺼낸다.","가방을 가지러 간다."],"answer":4,"explain":"🎧 여자: 민수야, 나 내일 여행 가는데 가방 좀 빌려줄 수 있어?<br>남자: 그래. 그런데 내가 수업이 있어서 곧 나가야 하는데 지금 올래?<br>여자: 응. 지금 바로 가지러 갈게. 고마워.<br>남자: 그럼 가방 꺼내 놓을게.<br><br>Мужчина скоро уходит на пару → женщина прямо сейчас ИДЁТ ЗА сумкой.<br>✅ <b>④ 가방을 가지러 간다.</b> — «지금 바로 가지러 갈게».<br>✖️ ① в поездку — завтра, ② на пару идёт мужчина, ③ достаёт сумку — действие мужчины (가방 꺼내 놓을게).<br>🧩 가지러 가다 = «идти забрать»."},{"n":10,"points":2,"instr":"Прослушайте и выберите действие, которое женщина (продавец) совершит далее.","options":["로션을 바른다.","계산을 해 준다.","로션을 포장한다.","아버지께 선물을 드린다."],"answer":2,"explain":"🎧 남자: 아버지께 로션을 하나 선물하려고 하는데 어떤 게 좋아요?<br>여자: 이게 요즘 많이 팔리는 건데 한번 발라 보세요.<br>남자: 음, 향기도 좋고 부드럽네요. 이걸로 하나 포장해 주세요.<br>여자: 네, 계산 먼저 해 드릴 테니까 이쪽으로 오세요.<br><br>Покупатель выбрал лосьон → продавщица СНАЧАЛА пробивает покупку.<br>✅ <b>② 계산을 해 준다.</b> — «계산 먼저 해 드릴 테니까».<br>✖️ ① наносит лосьон — это делал покупатель (발라 보세요), ③ упаковка — ПОСЛЕ оплаты, ④ дарит отцу — это сделает покупатель.<br>🧩 계산하다 = «рассчитать, пробить покупку»; 먼저 = «сначала»."},{"n":11,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["대회장에 간다.","일정을 확인한다.","일정표를 출력한다.","수잔에게 연락한다."],"answer":4,"explain":"🎧 여자: 한국어 토론 대회에 나가려면 한 명 더 필요한데 누가 좋을까?<br>남자: 수잔 어때? 수잔이 한국어를 잘하잖아.<br>여자: 좋아. 내가 수잔한테 연락할게. 넌 대회 일정 좀 확실히 알아봐 줘.<br>남자: 응. 확인하고 일정표 출력해 놓을게.<br><br>Они распределили дела: женщина СВЯЖЕТСЯ с Сьюзен.<br>✅ <b>④ 수잔에게 연락한다.</b> — «내가 수잔한테 연락할게».<br>✖️ ① на площадку конкурса не идут сейчас, ②③ проверить расписание и распечатать — задачи мужчины.<br>🧩 토론 대회 = «дискуссионный конкурс»; 연락하다 = «связаться»."},{"n":12,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["회의에 참석한다.","보고서를 작성한다.","설문 조사를 한다.","보고서를 제출한다."],"answer":2,"explain":"🎧 여자: 부장님, 신제품 소비자 설문 결과입니다. 확인 부탁드립니다.<br>남자: 음. 제품 크기를 줄인 것에 대한 반응이 좋군요.<br>여자: 네. … 설문 결과를 가지고 바로 보고서 작성하겠습니다.<br>남자: 그렇게 하세요. 금요일이 부서장 회의니까 그 전까지 주세요.<br><br>Результаты опроса готовы → женщина СРАЗУ пишет отчёт.<br>✅ <b>② 보고서를 작성한다.</b> — «바로 보고서 작성하겠습니다».<br>✖️ ① совещание — в пятницу, ③ опрос уже проведён (결과 готов), ④ сдать отчёт — позже, до пятницы.<br>🧩 보고서를 작성하다 = «составлять отчёт»; 제출하다 = «сдавать»."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 내일 혼자 캠핑을 가려고 한다.","여자는 내일 날씨에 대해 듣지 못했다.","남자는 비가 올 때 하는 캠핑을 좋아한다.","여자는 비가 오는 날 캠핑을 한 적이 있다."],"answer":3,"explain":"🎧 여자: 내일 비가 온다던데 캠핑하기로 한 거 취소할까?<br>남자: 그러지 말고 가자. 저번에 비 올 때 가 봤는데 분위기가 좋더라고.<br>여자: 정말? 난 비 오는 날 캠핑은 안 해 봤는데…….<br>남자: 텐트 안에서 듣는 빗소리가 얼마나 좋은데. 너도 분명 좋아할 거야.<br><br>✅ <b>③ Мужчина любит кемпинг под дождём.</b> — «비 올 때 … 분위기가 좋더라고».<br>✖️ ① один — нет, «가자» (вместе), ② женщина знает прогноз («비가 온다던데»), ④ под дождём она ещё не была («안 해 봤는데»).<br>🧩 빗소리 = «шум дождя»; -던데 = «слышал(а), что…»."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["마트는 올해 처음 문을 열었다.","일주일 동안 영업시간이 늘어난다.","식품 코너는 할인 행사에서 제외된다.","마트를 방문한 모든 사람들에게 선물을 준다."],"answer":2,"explain":"🎧 (안내방송) 저희 누리마트가 개업 10주년을 맞이하여 오늘부터 일주일 동안 식품 코너에서 특별 할인 행사를 진행합니다. 마트에서 5만 원 이상 구매하신 고객님들께 선물을 드립니다. 이 기간에는 영업시간도 한 시간 연장하니…….<br><br>✅ <b>② В течение недели режим работы продлевается.</b> — «영업시간도 한 시간 연장».<br>✖️ ① открылись впервые — нет, 10-летие, ③ продуктовый отдел ИСКЛЮЧЁН — наоборот, скидки именно там, ④ подарок ВСЕМ — только купившим на 5만 원 이상.<br>🧩 개업 10주년 = «10-летие открытия»; 연장하다 = «продлевать»."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 대회는 시민들의 참가율이 저조했다.","이 대회는 오늘부터 다음 주까지 진행된다.","이 대회는 모든 참가자들에게 메달을 준다.","이 대회는 경쟁하지 않고 경기를 즐길 수 있다."],"answer":4,"explain":"🎧 남자: 오늘 인주시청이 개최한 '인주자전거대회'가 이천 명 이상의 많은 시민이 참가한 가운데 성공적으로 마무리되었습니다. … 정해진 시간 안에 들어오면 순위와 관계없이 메달을 받을 수 있었는데요. 경쟁 없이 운동을 즐길 수 있어서 …….<br><br>✅ <b>④ На этом конкурсе можно наслаждаться без соревнования.</b> — «경쟁 없이 운동을 즐길 수».<br>✖️ ① участие низкое — наоборот, «이천 명 이상», ② идёт до след. недели — нет, «오늘 마무리», ③ медали ВСЕМ — только тем, кто уложился в «정해진 시간».<br>🧩 순위와 관계없이 = «вне зависимости от места»; 저조하다 = «низкий, вялый»."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["화재의 원인을 찾으면 여자의 업무는 끝난다.","화재의 피해 금액 계산은 여자의 업무가 아니다.","여자는 최초 신고자를 만난 후에 현장을 방문한다.","여자는 현장에서 불이 처음 나기 시작한 곳을 찾는다."],"answer":4,"explain":"🎧 남자: 화재 현장에서 … 어떤 일을 하시나요?<br>여자: 화재가 발생하면 바로 현장에 가서 최초 신고자에게 상황 설명을 듣습니다. 그리고 화재의 시작점을 찾아 흔적을 살피고 … 원인을 밝힙니다. 이후에는 … 피해 금액도 계산하고요.<br><br>✅ <b>④ Она ищет на месте точку, где начался пожар.</b> — «화재의 시작점을 찾아».<br>✖️ ① после причины работа кончается — нет, ещё считает ущерб, ② подсчёт ущерба не её дело — наоборот, её, ③ сначала встречает заявителя, потом едет — наоборот, едет на место и там слушает.<br>🧩 시작점 = «точка начала»; 피해 금액 = «сумма ущерба»."},{"n":17,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["영화를 혼자 보러 가고 싶다.","다양한 종류의 팝콘을 먹고 싶다.","영화관에서 팝콘을 먹는 것이 좋다.","집에서 영화 보는 것을 더 좋아한다."],"answer":3,"explain":"🎧 남자: 영화 보기 전에 팝콘 사야겠다. 수미 너도 먹을 거지?<br>여자: 아니. 난 아까 저녁을 많이 먹어서 배가 부르거든.<br>남자: 그래? 난 먹을래. 팝콘이 있어야 영화관에 온 것 같지.<br><br>✅ <b>③ В кинотеатре хорошо есть попкорн.</b> — «팝콘이 있어야 영화관에 온 것 같지».<br>✖️ ① смотреть одному, ② разные виды попкорна, ④ дома смотреть приятнее — он как раз в кино и с попкорном.<br>🧩 -아야 … 같지 = «только с … и чувствуешь, что…»."},{"n":18,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["사과를 빨리하는 것이 좋다.","친구들과 자주 연락해야 한다.","고민의 해결 방법을 찾고 싶다.","사람들에게 말을 거는 것이 힘들다."],"answer":1,"explain":"🎧 남자: 민수 씨한테 아직도 사과를 안 했어요?<br>여자: 네. 저도 사과하고 싶은데 먼저 말 걸기가 힘드네요.<br>남자: 메시지라도 보내 보세요. 시간이 지나면 오해가 더 커질 수도 있어요.<br><br>✅ <b>① Извиниться лучше поскорее.</b> — «시간이 지나면 오해가 더 커질 수도».<br>✖️ ② чаще созваниваться с друзьями, ③ хочет найти способ решить проблему (это про женщину), ④ трудно заговаривать с людьми (это слова женщины, а не главная мысль мужчины).<br>🧩 사과하다 = «извиняться»; 오해 = «недопонимание»."},{"n":19,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["여행은 유명한 곳으로 가야 한다.","여행지에서 여유롭게 지내면 좋겠다.","여행은 멀지 않은 곳으로 가고 싶다.","여행지에 대해 많이 알고 가려고 한다."],"answer":4,"explain":"🎧 여자: 무슨 자료를 그렇게 열심히 보고 있어?<br>남자: 여행 갈 곳에 대해 찾아보고 있어. 자세히 공부하고 가려고.<br>여자: 여행지에 가도 자료가 다 있을 텐데. 그렇게까지 준비해야 해?<br>남자: 난 아는 만큼 즐길 수 있다고 생각해서. 최대한 조사해서 가고 싶어.<br><br>✅ <b>④ Хочет поехать, многое узнав о месте.</b> — «아는 만큼 즐길 수 있다 … 최대한 조사해서».<br>✖️ ① ехать в знаменитые места, ② проводить отпуск неспешно, ③ ехать недалеко — об этом речи нет.<br>🧩 아는 만큼 = «насколько знаешь»; 조사하다 = «изучать»."},{"n":20,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["아이들이 독서를 즐겁게 생각하면 좋겠다.","아이들을 위한 책을 많이 출판해야 한다.","아이들을 위해 다양한 동화가 나와야 한다.","아이들이 독서할 수 있는 공간이 늘어나면 좋겠다."],"answer":1,"explain":"🎧 여자: 이전에 발표하셨던 동요의 가사를 이야기로 만들어 책으로 내셨는데요.<br>남자: 네. 요즘 책을 읽기 싫어하는 아이들이 많잖아요. … 부담 없이, 재미있게 책을 읽을 수 있을 것 같았어요. … 독서의 즐거움을 느낄 수 있으면 좋겠고요. 어렸을 때 독서에 대한 흥미를 갖는 것이 중요하니까요.<br><br>✅ <b>① Хочется, чтобы дети считали чтение приятным.</b> — «독서의 즐거움을 느낄 수 있으면 좋겠고».<br>✖️ ② больше издавать детских книг, ③ больше разных сказок, ④ больше мест для чтения — он именно про РАДОСТЬ чтения.<br>🧩 동요 = «детская песенка»; 흥미 = «интерес»."},{"n":21,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["게임의 캐릭터를 귀엽게 만들면 좋겠다.","캐릭터의 디자인을 전문 업체에 요청해야 한다.","캐릭터를 결정해서 빨리 게임을 출시해야 한다.","가능하면 현재의 캐릭터 디자인을 유지하고 싶다."],"answer":4,"explain":"🎧 여자: … 게임의 캐릭터 디자인을 좀 더 귀엽게 변경하면 좋겠다는 거, 어떻게 생각하세요?<br>남자: 지금 디자인이 현실감 있고 좋은데요. … 수정하는 문제는 좀 신중해야 할 것 같아요. … 많은 변화를 주는 건 부담이 클 것 같아요.<br><br>✅ <b>④ По возможности хочет сохранить нынешний дизайн персонажа.</b><br>✖️ ① сделать милее (это мнение женщины), ② заказать у спец. фирмы, ③ скорее выпустить игру — мужчина за осторожность и сохранение.<br>🧩 현실감 있다 = «реалистичный»; 신중하다 = «осторожный»."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 게임은 얼마 전에 출시되었다.","이 게임의 캐릭터는 매우 사실적이다.","캐릭터에 대한 회의는 아직 진행되지 않았다.","여자는 캐릭터가 이 게임과 어울린다고 생각한다."],"answer":2,"explain":"🎧 여자: 우리 게임은 만화 같은 분위기인데 캐릭터가 너무 사실적이라서 좀 안 어울리지 않아요? 아직 출시도 좀 남았는데…….<br><br>✅ <b>② Персонаж этой игры очень реалистичен.</b> — «캐릭터가 너무 사실적이라서».<br>✖️ ① недавно вышла — нет, «출시도 좀 남았는데» (ещё не вышла), ③ совещание ещё не было — наоборот, «오늘 아침 회의에서 나온 의견», ④ женщина считает, что персонаж ПОДХОДИТ — наоборот, «안 어울리지 않아요?».<br>🧩 사실적 = «реалистичный»; 출시 = «выпуск (на рынок)»."},{"n":23,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["박물관 단체 관람을 예약하고 있다.","박물관 관람 시간에 대해 문의하고 있다.","상설 전시회가 열리는 장소를 확인하고 있다.","전시실의 설명을 수정해 달라고 요청하고 있다."],"answer":4,"explain":"🎧 남자: 방금 3층 상설 전시관에서 … 설명 내용에 잘못된 게 있어서요. … 첫 번째 전시실을 소개하는 영어 설명 중에 틀린 단어가 하나 있더라고요. … 빨리 고쳐 주시면 좋겠어요.<br>여자: 말씀해 주셔서 감사합니다. 바로 올라가서 확인해 보겠습니다.<br><br>✅ <b>④ Просит исправить описание в зале.</b> — «틀린 단어 … 고쳐 주시면».<br>✖️ ① бронирует групповой осмотр, ② спрашивает часы работы, ③ уточняет место выставки — он указывает на ОШИБКУ.<br>🧩 상설 전시관 = «постоянная экспозиция»; 수정하다 = «исправлять»."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자는 지금 박물관 3층에 있다.","남자는 박물관에서 상설 전시회를 관람했다.","이 박물관에는 전시실에 영어 설명이 없다.","이 박물관에는 외국인들이 많이 오지 않는다."],"answer":2,"explain":"🎧 남자: 방금 3층 상설 전시관에서 관람하고 내려왔는데요. … 박물관에 외국인도 많은데 빨리 고쳐 주시면 좋겠어요.<br>여자: … 바로 올라가서 확인해 보겠습니다.<br><br>✅ <b>② Мужчина осмотрел постоянную экспозицию.</b> — «상설 전시관에서 관람하고 내려왔는데요».<br>✖️ ① женщина на 3-м этаже — нет, она ещё «올라가서» (поднимется), ③ нет английских описаний — есть, но с ошибкой, ④ иностранцев мало — наоборот, «외국인도 많은데».<br>🧩 관람하다 = «осматривать (выставку)»."},{"n":25,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["실제 상황을 가정한 반복 훈련이 중요하다.","사고가 많은 지역에는 인력이 충분해야 한다.","훈련은 자유로운 분위기에서 실시되어야 한다.","사건이 발생할 때 팀원 간의 협력이 필요하다."],"answer":1,"explain":"🎧 남자: 무엇보다 현장 대응력을 높이기 위한 훈련 덕분이라고 생각합니다. … 다양한 모의 상황을 만들어 현장 대응력을 강화하는 훈련을 반복해서 했습니다. 그렇게 하니까 실제 상황에서도 효과가 있었던 것 같습니다.<br><br>✅ <b>① Важны повторяющиеся тренировки, имитирующие реальные ситуации.</b><br>✖️ ② хватало бы людей в опасных районах, ③ тренировки в свободной атмосфере, ④ нужна командная слаженность — главное у него — «모의 상황 … 반복 훈련».<br>🧩 모의 상황 = «имитация ситуации»; 현장 대응력 = «реакция на месте»."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 경찰서가 있는 지역은 사건이 자주 발생한다.","이 경찰서에는 경험이 많은 경찰들이 대부분이다.","이 경찰서는 다른 곳에 비해 범인 검거율이 낮다.","이 경찰서에서 실시한 훈련은 효과를 보지 못했다."],"answer":1,"explain":"🎧 남자: 이 지역은 … 사건, 사고가 많지요. 그래서 다른 곳에 비해 인력도 많은데 대부분 젊은 경찰관들입니다. … (인주경찰서가) 전국에서 범인 검거율이 가장 높은 곳으로 선정 …….<br><br>✅ <b>① В районе этого участка часто случаются происшествия.</b> — «사건, 사고가 많지요».<br>✖️ ② большинство опытных — наоборот, «대부분 젊은 경찰관», ③ раскрываемость низкая — наоборот, «가장 높은», ④ тренировки не помогли — наоборот, «효과가 있었던».<br>🧩 검거율 = «раскрываемость»; 인력 = «кадры»."},{"n":27,"points":2,"instr":"Прослушайте и выберите намерение мужчины.","options":["대학 축제의 필요성을 설명하려고","대학 축제의 문제점에 대해 지적하려고","대학 축제에 대한 반응을 알려 주려고","대학 축제에 출연하는 가수를 홍보하려고"],"answer":2,"explain":"🎧 남자: 언제부턴가 대학 축제가 가수 콘서트처럼 변해 가는 거 같아. … 관심이 공연에만 집중되는 거 같아서 좀 씁쓸해. … 올해는 작년보다 학생이 직접 참여하고 교류하는 행사가 더 줄어들었어. 그건 좀 잘못된 것 같아.<br><br>✅ <b>② Указать на проблемы университетского фестиваля.</b><br>✖️ ① объяснить нужность фестиваля, ③ рассказать о реакции на фестиваль, ④ прорекламировать певца — мужчина именно КРИТИКУЕТ.<br>🧩 씁쓸하다 = «горьковато (на душе)»; 지적하다 = «указывать (на недостаток)»."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자는 김민수 씨의 콘서트에 간 적이 있다.","남자가 다니는 대학은 올해 축제를 열지 않는다.","여자는 축제에 유명 가수를 섭외하는 것에 찬성한다.","작년 축제 때 학과 행사에 학생들이 많이 참여했다."],"answer":3,"explain":"🎧 여자: 난 좋은데. 김민수 씨 팬인데 표가 비싸서 콘서트에 못 갔거든. … 유명 가수가 오면 학교 홍보도 되고 좋은 면도 있을 거야.<br><br>✅ <b>③ Женщина — за приглашение известных певцов на фестиваль.</b> — «좋은 면도 있을 거야».<br>✖️ ① была на концерте — нет, «못 갔거든», ② фестиваля в этом году нет — наоборот, Ким Минсу приедет, ④ многие участвовали в факультетских мероприятиях — наоборот, «참여하지 않고 공연만».<br>🧩 섭외하다 = «приглашать, договариваться»; 홍보 = «реклама»."},{"n":29,"points":2,"instr":"Прослушайте и выберите, кто такой мужчина.","options":["해양 생태계를 연구하는 사람","해양 구조물을 설치하는 사람","해양 스포츠를 홍보하는 사람","해양 에너지를 개발하는 사람"],"answer":1,"explain":"🎧 여자: 박사님께서는 … 제주 바다의 해양 상태는 어떤가요?<br>남자: 해조류가 줄어들고 야열대 해양 생물들이 늘어나고 있습니다. 기후 변화 때문이죠. … 수온 변화와 생태계의 관계에 대한 논문을 많이 발표 … 태평양의 어종 분포에 대해 조사 …….<br><br>✅ <b>① Человек, изучающий морские экосистемы.</b><br>✖️ ② устанавливает морские сооружения, ③ рекламирует морской спорт, ④ разрабатывает морскую энергетику — он исследователь (논문, 조사).<br>🧩 해양 생태계 = «морская экосистема»; 어종 분포 = «распределение видов рыб»."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["제주 바다에는 야열대 생물이 감소하고 있다.","남자는 다른 나라와 팀을 만들어 일하고 있다.","남자는 바다와 관련된 일을 작년부터 시작했다.","제주 바다의 해조류가 줄어든 원인이 밝혀지지 않았다."],"answer":2,"explain":"🎧 남자: 작년부터 다른 국가와 공동으로 팀을 꾸려서 태평양의 어종 분포에 대해 조사하고 있습니다.<br><br>✅ <b>② Мужчина работает в команде с другими странами.</b> — «다른 국가와 공동으로 팀을 꾸려서».<br>✖️ ① субтропические виды уменьшаются — наоборот, «늘어나고 있습니다», ③ работу с морем начал в прошлом году — нет, с морем уже 20 лет (с прошлого года — лишь тихоокеанское исследование), ④ причина уменьшения водорослей неизвестна — известна: «기후 변화 때문».<br>🧩 공동으로 = «совместно»; 꾸리다 = «формировать (команду)»."},{"n":31,"points":2,"instr":"Прослушайте и выберите центральную мысль мужчины.","options":["오토바이의 교통 법규 위반은 강하게 처벌해야 한다.","오토바이 사고 예방을 위해 단속 장비를 늘려야 한다.","오토바이 운전자를 대상으로 안전 교육을 실시해야 한다.","오토바이 사고를 줄이려면 번호판 부착 제도를 개선해야 한다."],"answer":4,"explain":"🎧 남자: 현재 단속 시스템으로는 번호판이 아무리 커도 뒷면에 있어서 식별이 어렵습니다. 앞에도 번호판을 달아야 합니다. … 앞면에 스티커로 된 번호판을 부착한 해외의 사례도 있습니다. … 더 이상 미룰 수만은 없는 문제입니다.<br><br>✅ <b>④ Чтобы снизить аварийность, надо улучшить систему крепления номеров.</b><br>✖️ ① строже наказывать за нарушения, ② больше техники контроля, ③ обучать водителей — он именно про номерной знак (спереди).<br>🧩 번호판 부착 = «крепление номерного знака»; 식별 = «опознание»."},{"n":32,"points":2,"instr":"Прослушайте и выберите, как ведёт себя мужчина (его отношение).","options":["문제 해결 방안에 일부 동의하고 있다.","상대방과 협의하여 타협점을 찾고 있다.","상대방의 주장을 일관되게 반박하고 있다.","상대방에게 명확한 근거를 요구하고 있다."],"answer":3,"explain":"🎧 여자: 뒷면 번호판을 더 크게 … 단속을 강화 …. → 남자: 뒷면에 있어서 식별이 어렵습니다. 앞에도 달아야 …. → 여자: 앞면은 부착하기 어려운 구조입니다. → 남자: 스티커로 된 번호판을 부착한 해외 사례도 있습니다 …….<br><br>✅ <b>③ Последовательно опровергает доводы собеседницы.</b> — на каждый аргумент женщины у мужчины контрдовод.<br>✖️ ① частично соглашается, ② ищет компромисс, ④ требует чётких оснований — он именно ВОЗРАЖАЕТ.<br>🧩 반박하다 = «опровергать»; 일관되게 = «последовательно»."},{"n":33,"points":2,"instr":"Прослушайте и выберите, о чём идёт речь.","options":["정신 건강을 위협하는 환경","뇌 성장과 발달의 결정적 시기","불편한 피부 자극에 대한 신경학적 설명","촉각 방어 증상을 완화하기 위한 치료법"],"answer":3,"explain":"🎧 여자: 목까지 올라오는 옷이나 넥타이를 … 불편해하는 사람들이 … 뇌의 신경망이 피부를 압박하는 자극을 위험한 신호로 과도하게 인식해서 나타나는 증상입니다. 이걸 '촉각 방어'라고 하죠. …<br><br>✅ <b>③ Неврологическое объяснение неприятного раздражения кожи.</b> — мозг воспринимает давление на кожу как угрозу.<br>✖️ ① среда, угрожающая психике, ② критический период развития мозга, ④ методы ЛЕЧЕНИЯ — речь об объяснении самого явления.<br>🧩 촉각 방어 = «тактильная защита»; 신경망 = «нейронная сеть»."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 증상은 뇌와 관련되어 있다.","이 증상은 성인에게 발생하지 않는다.","이 증상은 목 주변에서 드물게 나타난다.","이 증상은 저절로 좋아지는 경우가 적다."],"answer":1,"explain":"🎧 여자: … 뇌의 신경망이 … 인식해서 나타나는 증상입니다. … 특히 목에 많이 나타나는데요. … 보통 성장하면서 자연스럽게 없어집니다. 하지만 성인이 되고도 남아 있거나 악화되는 경우도 있습니다.<br><br>✅ <b>① Этот симптом связан с мозгом.</b> — «뇌의 신경망이 …».<br>✖️ ② у взрослых не бывает — наоборот, «성인이 되고도 남아 있거나», ③ на шее редко — наоборот, «특히 목에 많이», ④ редко проходит сам — наоборот, «자연스럽게 없어집니다».<br>🧩 저절로 = «само собой»; 악화되다 = «ухудшаться»."},{"n":35,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["선수 생활을 마치면서 소감을 밝히고 있다.","올림픽 출전에 대한 포부를 드러내고 있다.","대표 선수를 선발하는 절차를 소개하고 있다.","경기를 하기 전에 선수를 대표로 선서하고 있다."],"answer":1,"explain":"🎧 남자: 오늘 이렇게 배구 선수로서의 마지막 경기를 마련해 주신 … 감사드립니다. 고등학교 때 처음 국가 대표 유니폼을 입고 17년 동안 … 출전하여 우리나라를 대표할 수 있어 영광이었습니다. … 저는 코트를 떠나지만 …….<br><br>✅ <b>① Завершая карьеру, делится впечатлениями.</b> — «마지막 경기», «코트를 떠나지만».<br>✖️ ② выражает амбиции перед Олимпиадой, ③ описывает отбор сборной, ④ даёт клятву перед игрой — это прощальная речь.<br>🧩 소감을 밝히다 = «высказывать впечатления»; 코트를 떠나다 = «уходить с площадки»."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 아시안게임에 나가지 못했다.","남자는 2년 전 올림픽 경기에서 우승했다.","남자는 오늘 해외에서 열린 경기에 출전했다.","남자는 고등학생 때 처음 국가 대표가 되었다."],"answer":4,"explain":"🎧 남자: 고등학교 때 처음 국가 대표 유니폼을 입고 17년 동안 네 번의 올림픽과 네 번의 아시안게임에 출전 …. 다만 2년 전 올림픽에서 우승하지 못한 것이 조금 아쉽 …….<br><br>✅ <b>④ Впервые попал в сборную ещё школьником.</b> — «고등학교 때 처음 국가 대표».<br>✖️ ① не был на Азиатских играх — наоборот, четырежды, ② победил 2 года назад — наоборот, «우승하지 못한», ③ сегодня играл за границей — сегодня его ПОСЛЕДНИЙ матч (фанаты приехали из-за рубежа).<br>🧩 국가 대표 = «член сборной»; 출전하다 = «выступать»."},{"n":37,"points":2,"instr":"Прослушайте и выберите центральную мысль женщины.","options":["공원에 다양한 놀이 시설을 확충할 필요가 있다.","공원에 예쁜 꽃과 나무를 더 많이 심는 것이 좋다.","공원을 찾아오는 사람의 상황을 고려해 조성해야 한다.","공원은 지속적이고 체계적으로 관리하는 것이 중요하다."],"answer":3,"explain":"🎧 여자: 최근의 공원을 보면 그곳을 주로 찾는 사람들의 생활을 분석하여 반영했음을 알 수 있습니다. 인주시 병원에 있는 공원이 좋은 예죠. … 환자들이 혼자만의 시간을 갖기도 하고, … 보호자나 의료진이 … 아늑함을 느끼며 쉴 수 있도록 …….<br><br>✅ <b>③ Парк надо создавать с учётом положения тех, кто в него приходит.</b><br>✖️ ① расширять игровые площадки, ② сажать больше цветов и деревьев, ④ важно системно управлять парком — у неё главное «사람들의 생활을 분석하여 반영».<br>🧩 조성하다 = «создавать (парк)»; 아늑함 = «уют»."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 공원에는 나무가 많지 않다.","인주시에서 이 공원을 만들었다.","이 공원은 의료진만 이용할 수 있다.","최근에 도심 속 공원이 줄어들고 있다."],"answer":2,"explain":"🎧 여자: 인주시는 이 공원을 조성하면서 주변이 보이지 않을 정도로 빽빽하게 나무를 심어 숲을 만들었는데요. …<br><br>✅ <b>② Этот парк создал город Инджу.</b> — «인주시는 이 공원을 조성하면서».<br>✖️ ① деревьев немного — наоборот, «빽빽하게 나무를 심어», ③ только для медперсонала — нет, для пациентов, опекунов и медперсонала, ④ парков в центре становится меньше — наоборот, «공원을 늘리는 추세».<br>🧩 빽빽하게 = «густо»; 조성하다 = «создавать»."},{"n":39,"points":2,"instr":"Прослушайте и выберите содержание, которое было ДО этого диалога.","options":["보호자 없이 생활하고 있는 청소년의 수가 감소했다.","청년의 주거 마련을 위한 정부의 경제적 지원이 줄었다.","청소년의 심리를 상담할 수 있는 전문가를 충원하고 있다.","보호자가 없는 청소년이 보육원에서 지낼 수 있는 기간이 연장됐다."],"answer":4,"explain":"🎧 여자: 그럼 본인이 희망하면 성인이 된 후에도 보육원에서 지낼 수 있게 된 거네요. 보육원 퇴소 시기가 만 18세에서 24세까지로 늦춰진 거죠?<br><br>Первая реплика «그럼 …» подытоживает только что сказанное → ранее говорили об увеличении срока пребывания в детдоме.<br>✅ <b>④ Срок, который дети без опекунов могут жить в приюте, продлили.</b> — «퇴소 시기가 18세에서 24세까지로 늦춰진».<br>✖️ ① число таких подростков сократилось, ② поддержка на жильё уменьшилась, ③ нанимают психологов — это идёт ПОСЛЕ, в словах мужчины.<br>🧩 퇴소 시기 = «срок выписки/выхода»; 늦춰지다 = «отодвигаться»."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["자립 정착금은 내년부터 지급할 예정이다.","자립 준비 청년을 담당하는 부서가 신설되었다.","자립 준비 청년을 대상으로 심리 상담을 진행하고 있다.","올해부터 자립 준비 청년을 지원하는 사업비가 축소됐다."],"answer":3,"explain":"🎧 남자: 기존 담당 부서에 심리 상담이 가능한 전담 인력도 보충해 상담 서비스를 지원하고 있고요. …<br><br>✅ <b>③ Для готовящейся к самостоятельности молодёжи проводят психологические консультации.</b><br>✖️ ① деньги на обустройство начнут платить со след. года — нет, уже «지급하고 있습니다», ② создан НОВЫЙ отдел — нет, кадры добавили в «기존 부서», ④ бюджет урезали — наоборот, «사업비 규모를 늘려».<br>🧩 자립 = «самостоятельность»; 전담 인력 = «выделенный персонал»."},{"n":41,"points":2,"instr":"Прослушайте и выберите центральное содержание лекции.","options":["돈덕전 건축에 특별한 기법이 적용되었다.","돈덕전은 외국 자본을 유치하여 건설되었다.","돈덕전은 근대 국가의 위상을 보여 주는 외교 공간이었다.","돈덕전은 철저한 관리를 통해 원형 그대로를 유지하고 있다."],"answer":3,"explain":"🎧 여자: … 이곳은 바로 '돈덕전'입니다. 서양 열강에 근대화된 나라의 위상을 보여 주고 싶었던 고종은 … 이곳을 만들었습니다. … 외교 사절을 접견하고 … 연회를 베푸는 장소이자 국빈급 외국인의 숙소로 사용됐습니다. 이렇게 돈덕전은 근대 국가로서의 위상을 국제 사회에 한껏 드러내고자 한 곳이었습니다.<br><br>✅ <b>③ Деондеокчжон был дипломатическим пространством, показывавшим статус современного государства.</b><br>✖️ ① особая техника строительства, ② построен на иностранный капитал, ④ сохранён в первозданном виде — лектор о его ДИПЛОМАТИЧЕСКОЙ роли.<br>🧩 위상 = «статус, престиж»; 외교 사절 = «дипмиссия»."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이곳은 완공되는 데 40년이 걸렸다.","이곳은 연회장으로 사용되었던 곳이었다.","이곳은 한국의 전통 건축 양식을 보여 준다.","이곳은 국내 고위 관리를 위한 숙소로 활용됐다."],"answer":2,"explain":"🎧 여자: … 고종이 외교 사절을 접견하고 국외 주요 인사들과 연회를 베푸는 장소이자 국빈급 외국인의 숙소로 사용됐습니다.<br><br>✅ <b>② Это место использовалось как банкетный зал.</b> — «연회를 베푸는 장소».<br>✖️ ① строили 40 лет — нет, 40 лет — это юбилей восшествия; строили 4 года, ③ традиционный корейский стиль — нет, «프랑스풍의 서양식» (французский западный стиль), ④ жильё для отечественных чиновников — нет, для «국빈급 외국인».<br>🧩 연회 = «банкет»; 국빈급 = «уровня госгостя»."},{"n":43,"points":2,"instr":"Прослушайте и выберите, о чём идёт речь.","options":["소금을 생산하는 과정","소금을 관리하는 방법","소금이 지닌 경제적 가치","소금이 건강에 미치는 영향"],"answer":1,"explain":"🎧 남자: … 이곳 염전. 드넓은 갯벌에 칸막이를 만들고 바닷물을 가둬 놓았다. 바닷물이 증발하면서 … 하얀 정육면체 결정이 생겨나기 시작한다. … 이제 소금을 수확할 시간. … 자연과 인간이 빚어낸 소금이 탄생한다.<br><br>✅ <b>① Процесс производства соли.</b> — от заливки морской воды до сбора кристаллов.<br>✖️ ② способы хранения соли, ③ экономическая ценность соли, ④ влияние соли на здоровье — описывается именно ПРОЦЕСС.<br>🧩 염전 = «соляное поле»; 증발하다 = «испаряться»; 결정 = «кристалл»."},{"n":44,"points":2,"instr":"Прослушайте и выберите причину, по которой соль складывают в одном месте.","options":["염전을 홍보하기 위해","다른 염전으로 옮기기 위해","소금 생산량을 확인하기 위해","소금에 남아 있는 물기를 없애기 위해"],"answer":4,"explain":"🎧 남자: 염전 일꾼은 끌개로 … 소금 결정을 모아 한데 쌓아 놓는다. 포장하기 전 소금에 남아 있는 수분을 조금이라도 더 제거하기 위함이다.<br><br>✅ <b>④ Чтобы убрать оставшуюся в соли влагу.</b> — «남아 있는 수분을 … 제거하기 위함».<br>✖️ ① прорекламировать соляное поле, ② перевезти на другое поле, ③ подсчитать объём — соль складывают именно для удаления влаги перед упаковкой.<br>🧩 수분/물기 = «влага»; 제거하다 = «удалять»."},{"n":45,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["가마솥 바닥은 중앙 부분이 가장 얇다.","가마솥의 솥뚜껑이 가벼울수록 밥맛이 좋다.","가마솥으로 밥을 지으면 쌀이 천천히 익는다.","가마솥 뚜껑은 솥 내부의 압력을 높이는 역할을 한다."],"answer":4,"explain":"🎧 여자: … 솥뚜껑으로 솥을 덮으면 공기와 수증기가 빠져나가지 못하도록 밀폐할 수 있죠. 덕분에 내부 압력이 올라가고 고온 상태가 유지돼 …. … 중앙 부분은 두껍고 가장자리로 갈수록 얇아지는데요.<br><br>✅ <b>④ Крышка котла повышает давление внутри.</b> — «내부 압력이 올라가고».<br>✖️ ① центр дна самый тонкий — наоборот, «중앙 부분은 두껍고», ② чем легче крышка, тем вкуснее — наоборот, тяжёлая крышка, ③ рис варится медленно — наоборот, «익는 속도가 빨라집니다».<br>🧩 밀폐하다 = «герметизировать»; 압력 = «давление»."},{"n":46,"points":2,"instr":"Прослушайте и выберите способ изложения, который использует женщина.","options":["데이터를 통해 결과를 예상하고 있다.","자료를 분석해 개념을 규정하고 있다.","이유를 나열하며 원리를 알려 주고 있다.","설정한 기준에 따라 문제점을 지적하고 있다."],"answer":3,"explain":"🎧 여자: 왜 그런 걸까요? 첫째, 솥뚜껑 무게 때문입니다. … 둘째, 솥 바닥의 두께 때문에 밥맛이 깊어집니다. …<br><br>✅ <b>③ Перечисляя причины, объясняет принцип.</b> — «첫째 … 둘째 …».<br>✖️ ① прогнозирует результат по данным, ② анализирует материалы и даёт определение, ④ по заданным критериям указывает на проблемы — она именно ПЕРЕЧИСЛЯЕТ причины вкуса риса.<br>🧩 나열하다 = «перечислять»; 원리 = «принцип»."},{"n":47,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 제도는 시행된 지 얼마 되지 않았다.","사외 이사는 이사회에 참여할 자격이 없다.","경영진은 사외 이사를 직접 추천할 수 있다.","이 제도로 사외 이사의 자격 논란이 해소되었다."],"answer":3,"explain":"🎧 남자: … 경영진에게도 사외 이사 추천권이 있어서 자신들과 친분이 있는 인물을 추천하고, 그러다 보니 이들이 경영진을 견제하기란 쉽지 않습니다. …<br><br>✅ <b>③ Руководство может само рекомендовать независимых директоров.</b> — «경영진에게도 사외 이사 추천권이 있어서».<br>✖️ ① введён недавно — нет, «25년이 지났는데», ② независимые директора не вправе участвовать в совете — наоборот, участвуют, ④ споры о квалификации улажены — наоборот, «전문성이 검증되지 않은 인물이 선임».<br>🧩 사외 이사 = «независимый директор»; 견제하다 = «сдерживать»."},{"n":48,"points":2,"instr":"Прослушайте и выберите, как ведёт себя мужчина (его отношение).","options":["제도의 필요성과 의의를 강조하고 있다.","제도의 지나친 확대 적용을 경계하고 있다.","제도의 한계를 지적하며 개선책을 촉구하고 있다.","제도의 내용을 언급하며 사회적 관심을 호소하고 있다."],"answer":3,"explain":"🎧 남자: … 이들이 경영진을 견제하기란 쉽지 않습니다. 또 전문성이 검증되지 않은 인물이 선임되기도 해 제도의 취지를 무색하게 하죠. 후보 추천 방법을 개선하고 자격 검증을 강화하는 등의 대책 마련이 시급합니다.<br><br>✅ <b>③ Указывает на пределы системы и требует мер по улучшению.</b> — «대책 마련이 시급합니다».<br>✖️ ① подчёркивает нужность и значение, ② предостерегает от чрезмерного расширения, ④ взывает к вниманию общества — он именно КРИТИКУЕТ и требует реформ.<br>🧩 한계 = «предел»; 촉구하다 = «настоятельно требовать»."},{"n":49,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이번 위성에는 태양 전지를 부착하지 않았다.","누리호는 우주 관측을 위해 곧 발사될 예정이다.","위성에 탑재된 영상 레이더는 전력 소비가 적은 편이다.","위성이 안착한 이 궤도에서는 항상 태양 빛을 받을 수 있다."],"answer":4,"explain":"🎧 남자: … 24시간 내내 태양을 볼 수 있는 궤도 안에 위성을 안착시켜야 했습니다. …<br><br>✅ <b>④ На орбите, куда вышел спутник, всегда есть солнечный свет.</b> — «24시간 내내 태양을 볼 수 있는 궤도».<br>✖️ ① без солнечных батарей — наоборот, «태양 전지를 부착해», ② вот-вот запустят — уже «발사됐는데요», ③ радар потребляет мало энергии — наоборот, «전력 소비가 굉장해».<br>🧩 궤도 = «орбита»; 안착하다 = «благополучно выйти/сесть»."},{"n":50,"points":2,"instr":"Прослушайте и выберите способ изложения, который использует мужчина.","options":["발사 시각이 정해진 배경을 과학적으로 설명하고 있다.","우주선 발사의 과학사적 의미를 새롭게 정의하고 있다.","위성이 우주에서 일으킬 수 있는 문제를 예측하고 있다.","천문학적 지식을 토대로 문제 해결 방법을 제시하고 있다."],"answer":1,"explain":"🎧 남자: 그 시각이 꼭 … 6시 24분이었습니다. 왜 발사 시각을 분 단위까지 철저히 계산했을까요? 이는 … 위성 때문이었습니다. … 태양 전지를 부착해 충전 … 24시간 태양을 볼 수 있는 궤도 … 시점을 계산하니 그 시각이 딱 6시 24분이었던 겁니다.<br><br>✅ <b>① Научно объясняет, почему был выбран именно такой момент запуска.</b><br>✖️ ② по-новому определяет научно-историческое значение запуска, ③ прогнозирует проблемы спутника в космосе, ④ предлагает решение проблемы — он именно ОБЪЯСНЯЕТ причину времени запуска.<br>🧩 분 단위까지 = «вплоть до минут»; 궤도 진입 = «выход на орбиту»."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제96회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"감기약을 (        ) 열이 내렸다.","options":["먹느라고","먹더라도","먹을 텐데","먹고 나서"],"answer":4,"explain":"«Приняв лекарство от простуды, (я почувствовал, что) температура спала».<br>✅ <b>④ 먹고 나서</b> — «-고 나서» = «после того как сделал» (последовательность).<br>✖️ ① 먹느라고 — «из-за того что принимал» (причина-помеха), ② 먹더라도 — «даже если приму», ③ 먹을 텐데 — «наверное, приму, а…».<br>🧩 -고 나서 = «сделав и затем»; 열이 내리다 = «температура спадает»."},{"n":2,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"내일 김밥을 만들려고 재료를 미리 (        ).","options":["준비해 놓았다","준비하곤 했다","준비하면 된다","준비하는 법이다"],"answer":1,"explain":"«Чтобы завтра сделать кимпап, я заранее подготовил продукты».<br>✅ <b>① 준비해 놓았다</b> — «-아/어 놓다» = сделать заранее и оставить (результат сохраняется).<br>✖️ ② 준비하곤 했다 — «бывало, готовил» (повтор в прошлом), ③ 준비하면 된다 — «достаточно подготовить», ④ 준비하는 법이다 — «принято/положено готовить».<br>🧩 미리 = «заранее»; -아 놓다 хорошо сочетается с «미리»."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"버스를 잘못 <u>타는 바람에</u> 수업에 늦었다.","options":["탄 탓에","타는 김에","탄 반면에","타는 대신에"],"answer":1,"explain":"«Из-за того что сел не на тот автобус, опоздал на занятие».<br>✅ <b>① 탄 탓에</b> — «-는 바람에» (по причине нежелательного) ≈ «-(으)ㄴ 탓에» (по вине чего-то).<br>✖️ ② 타는 김에 — «заодно, раз уж сел», ③ 탄 반면에 — «тогда как сел», ④ 타는 대신에 — «вместо того чтобы сесть».<br>🧩 -는 바람에 / -(으)ㄴ 탓에 — обе про причину негативного результата."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"회의가 길어져서 약속 시간을 <u>미뤄야만 했다</u>.","options":["미루기만 했다","미룰 줄 몰랐다","미루기가 어려웠다","미룰 수밖에 없었다"],"answer":4,"explain":"«Совещание затянулось, и время встречи пришлось перенести».<br>✅ <b>④ 미룰 수밖에 없었다</b> — «-아/어야만 했다» (вынужден был) ≈ «-(으)ㄹ 수밖에 없었다» (не оставалось ничего, кроме как).<br>✖️ ① 미루기만 했다 — «только и делал, что откладывал», ② 미룰 줄 몰랐다 — «не думал, что придётся отложить», ③ 미루기가 어려웠다 — «было трудно отложить».<br>🧩 -아야만 하다 / -ㄹ 수밖에 없다 — обе про вынужденность."},{"n":5,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"🛏️ 덮자마자 꿈나라로~\n아침까지 포근하고 따뜻하게!","options":["장갑","이불","화장품","손수건"],"answer":2,"explain":"«Накрылся — и сразу в страну снов~ Тепло и уютно до самого утра!»<br>✅ <b>② 이불</b> (одеяло) — «덮다» (накрываться), «포근하고 따뜻하게» (уютно и тепло) до утра.<br>✖️ ① 장갑 (перчатки), ③ 화장품 (косметика), ④ 손수건 (платок) — не про «накрыться и спать».<br>🧩 덮다 = «накрывать(ся)»; 꿈나라 = «страна снов»."},{"n":6,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"📷 오늘의 추억을 한 장에\n아름다운 모습 그대로 남기세요.","options":["서점","은행","빨래방","사진관"],"answer":4,"explain":"«Сегодняшние воспоминания — в одном кадре. Сохраните свой прекрасный облик как есть».<br>✅ <b>④ 사진관</b> (фотоателье) — «한 장», «모습 그대로 남기세요» (запечатлеть образ).<br>✖️ ① 서점 (книжный), ② 은행 (банк), ③ 빨래방 (прачечная) — не про фото.<br>🧩 한 장 = «один лист/кадр»; 남기다 = «оставлять, сохранять»."},{"n":7,"points":2,"instr":"Выберите, о чём этот текст (призыв).","passage":"🚸 학교 앞 천천히!\n아이들이 있는지 한 번 더 살피세요.","options":["안전 운전","건강 관리","전기 절약","환경 보호"],"answer":1,"explain":"«Перед школой — медленно! Ещё раз проверьте, нет ли детей».<br>✅ <b>① 안전 운전</b> (безопасное вождение) — «천천히», «아이들이 있는지 살피세요».<br>✖️ ② 건강 관리 (забота о здоровье), ③ 전기 절약 (экономия электричества), ④ 환경 보호 (защита природы) — мимо.<br>🧩 살피다 = «осматриваться, проверять»; 천천히 = «медленно»."},{"n":8,"points":2,"instr":"Выберите, о чём этот текст (инструкция).","passage":"📝 ❶ 식사를 원하는 날짜와 시간, 인원수를 선택하십시오.\n❷ 연락 받을 분의 성함과 연락처를 입력하십시오.","options":["예약 방법","일정 문의","이용 후기","제품 소개"],"answer":1,"explain":"«① Выберите желаемую дату, время и число гостей для трапезы. ② Введите имя и контакт того, с кем связаться».<br>✅ <b>① 예약 방법</b> (как забронировать) — выбор даты/времени/числа людей и контакт = шаги брони.<br>✖️ ② 일정 문의 (запрос расписания), ③ 이용 후기 (отзыв), ④ 제품 소개 (описание товара).<br>🧩 예약 = «бронь»; 인원수 = «число человек»."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"📢 제3회 인주시 영상 노래 대회\n· 제출 방법: 노래하는 영상과 신청서를 이메일(norae@inju.go.kr)로 전송\n  ※ 신청서는 인주시청 홈페이지 게시판에서 다운로드 가능\n· 제출 기간: 2024년 11월 1일(금) ~ 15일(금)\n· 결과 발표: 11월 29일(금), 인주시청 홈페이지 게시","options":["결과는 이메일로 알려 준다.","11월 29일까지 신청서를 내야 한다.","신청서는 홈페이지에서 내려받을 수 있다.","노래하는 영상은 직접 가서 제출해야 한다."],"answer":3,"explain":"✅ <b>③ Заявку можно скачать с сайта.</b> — «신청서는 … 홈페이지 게시판에서 다운로드 가능».<br>✖️ ① результаты сообщат по e-mail — нет, их «вывесят на сайте» (홈페이지 게시), ② подать заявку до 29 ноября — нет, приём 1–15 ноября (29-е — объявление итогов), ④ видео сдать лично — нет, по e-mail.<br>🧩 다운로드 = «скачивание»; 게시 = «размещение, вывешивание»."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с данными графика.","passage":"📊 «택배로 가장 많이 배송되는 물건은?» (인주택배, 2023년)\n식품 31% · 의류 25% · 화장품 19% · 전자 제품 13% · 운동 용품 8% · 기타 4%.","options":["택배로 배송되는 물건 중 의류가 가장 많다.","택배로 화장품이 배송되는 비율이 식품보다 낮다.","택배로 운동 용품이 배송되는 비율은 10%가 넘는다.","택배로 전자 제품이 배송되는 비율이 두 번째로 높다."],"answer":2,"explain":"✅ <b>② Доля косметики ниже, чем продуктов.</b> — 화장품 19% &lt; 식품 31%.<br>✖️ ① больше всего одежды — нет, лидер «식품» 31% (одежда 25%), ③ спорттовары больше 10% — нет, 8%, ④ электроника на 2-м месте — нет, 13% (2-е место у одежды 25%).<br>🧩 비율 = «доля, процент»; 식품 = «продукты питания»."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"인주로봇연구소는 작년에 이어 올해에도 겨울 방학을 맞은 인주시 초등학생들을 대상으로 교육 프로그램을 운영한다. 여기에 참여하는 학생들은 연구소에서 직접 로봇을 만들어 보고 조종하는 체험을 할 수 있다. 이 프로그램은 로봇 과학자가 되기를 희망하는 학생들에게 특히 반응이 좋다. 연구소는 내년 겨울 방학에도 이 프로그램을 진행할 예정이다.","options":["이 프로그램은 올해 처음 시작됐다.","내년에는 이 프로그램이 학기 중에 진행된다.","연구소의 과학자가 학교로 직접 가서 교육을 해 준다.","이 프로그램은 로봇 과학자를 꿈꾸는 학생들에게 인기가 많다."],"answer":4,"explain":"✅ <b>④ Программа популярна у школьников, мечтающих стать робототехниками.</b> — «로봇 과학자가 되기를 희망하는 학생들에게 특히 반응이 좋다».<br>✖️ ① началась впервые в этом году — нет, «작년에 이어» (продолжая прошлый год), ② в следующем году пройдёт в учебное время — нет, «겨울 방학» (на каникулах), ③ учёные сами приходят в школу — наоборот, дети приходят в институт.<br>🧩 -에 이어 = «вслед за, продолжая»; 반응이 좋다 = «хороший отклик»."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"지난 23일, 한 차량이 산길에서 미끄러지는 사고가 발생했다. 이 사고로 차를 운전하던 김 씨가 의식을 잃자 함께 있던 김 씨의 개가 차에서 빠져나와 근처 마을로 달려갔다. 주인 없는 개가 계속 짖는 것을 이상하게 여긴 마을 사람들이 개를 따라가 김 씨를 발견했다. 사람들의 신고로 김 씨는 병원으로 옮겨져 치료 중이다.","options":["김 씨는 개를 근처 마을로 보냈다.","김 씨는 등산을 하다가 사고를 당했다.","마을 사람들이 키우던 개가 김 씨를 발견했다.","사람들은 개를 따라가 사고가 난 것을 알게 되었다."],"answer":4,"explain":"✅ <b>④ Люди пошли за собакой и узнали об аварии.</b> — «개를 따라가 김 씨를 발견했다».<br>✖️ ① Ким отправил собаку в село — нет, пёс сам выбрался и побежал, ② Ким пострадал на восхождении — нет, за рулём (운전하던), ③ собака сельчан нашла Кима — это была собака самого Кима.<br>🧩 의식을 잃다 = «терять сознание»; 짖다 = «лаять»."},{"n":13,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 대학생 때 처음으로 해외여행을 가게 되었다.\n(나) 가족들은 그 엽서를 받고 아주 감동적이었다고 했다.\n(다) 여행지에서 가족들을 위한 선물을 사고 싶었는데 돈이 별로 없었다.\n(라) 고민하다가 그 나라 풍경이 담긴 엽서에 여행 이야기를 담아 보냈다.","options":["(가)-(나)-(라)-(다)","(가)-(다)-(라)-(나)","(다)-(나)-(가)-(라)","(다)-(라)-(나)-(가)"],"answer":2,"explain":"✅ <b>② (가)-(다)-(라)-(나)</b>: студентом впервые поехал за границу → хотел купить семье подарок, но денег было мало → подумав, послал открытку с видами страны и рассказом → семья, получив открытку, была очень тронута.<br>🧩 «그 엽서» в (나) отсылает к открытке из (라), значит (나) идёт в конце."},{"n":14,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 고리 모양의 반죽은 기름에 골고루 튀겨져 전체가 잘 익었다.\n(나) 그런데 동그란 반죽의 가운데 부분이 익지 않는 경우가 많았다.\n(다) 도넛은 원래 밀가루를 동그랗게 반죽해 기름에 튀겨서 만들었다.\n(라) 어떤 사람이 도넛 반죽의 가운데를 파내 고리 모양으로 만들었다.","options":["(가)-(다)-(나)-(라)","(가)-(라)-(다)-(나)","(다)-(나)-(라)-(가)","(다)-(라)-(가)-(나)"],"answer":3,"explain":"✅ <b>③ (다)-(나)-(라)-(가)</b>: пончик делали круглым и жарили → но середина часто не прожаривалась → кто-то вырезал середину, сделав кольцо → кольцо прожаривалось равномерно.<br>🧩 «그런데» в (나) вводит проблему, (라) — решение (кольцо), (가) — результат."},{"n":15,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 또한 고양이는 수염으로 기분을 드러내기도 한다.\n(나) 고양이는 높고 좁은 담 위에서도 흔들림 없이 걷는다.\n(다) 수염으로 바람의 방향을 느끼며 몸의 균형을 잡기 때문이다.\n(라) 두려울 때는 수염을 뒤쪽으로 당기고, 편안할 때는 아래로 내린다.","options":["(나)-(다)-(가)-(라)","(나)-(라)-(가)-(다)","(라)-(가)-(나)-(다)","(라)-(나)-(다)-(가)"],"answer":1,"explain":"✅ <b>① (나)-(다)-(가)-(라)</b>: кошка уверенно ходит даже по узкой стене → потому что усами чувствует ветер и держит баланс → «также» усами кошка выражает настроение → когда страшно — отводит усы назад, когда спокойна — опускает.<br>🧩 «때문이다» в (다) объясняет (나); «또한» в (가) добавляет вторую функцию усов, (라) её раскрывает."},{"n":16,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"영화 속 장면에서 전화번호가 나오는 경우가 있다. 이때 실제 전화번호를 사용하면 호기심에 전화하는 사람이 생겨서 이 번호를 사용하는 사람은 일상생활이 힘들어질 수 있다. 영화진흥위원회에서는 이와 같은 (        ) 영화에 나와도 상관없는 전화번호를 확보해 두고 이를 영화 제작사에 제공해 주고 있다.","options":["피해를 막기 위해","사실을 화면에 담고자","관객 요구를 반영하고자","제작 방법을 알리기 위해"],"answer":1,"explain":"Если в фильме звучит реальный номер, его владельцу названивают из любопытства → совет по кино держит «нейтральные» номера, чтобы этого избежать.<br>✅ <b>① 피해를 막기 위해</b> (чтобы предотвратить вред).<br>✖️ ② чтобы запечатлеть факт на экране, ③ чтобы отразить запрос зрителей, ④ чтобы рассказать о методе съёмки — не вяжутся с «일상생활이 힘들어질 수 있다».<br>🧩 피해 = «ущерб, вред»; 확보하다 = «обеспечивать, припасать»."},{"n":17,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"30년 전 에너지 전문가들은 그로부터 40년 후에는 지구에 사용할 수 있는 석유가 남아 있지 않을 거라고 경고했다. 그러나 현재의 전문가들은 앞으로도 50년 이상은 계속해서 석유를 사용할 수 있을 거라고 예측한다. 이렇게 석유의 (        ) 이유는 석유를 찾는 기술이 발전했기 때문이다. 이 기술로 석유가 있는 곳을 더 많이 발견하게 된 것이다.","options":["품질이 더 좋아진","가격이 상승하고 있는","사용 가능 기간이 늘어난","가치가 계속해서 떨어지는"],"answer":3,"explain":"Раньше пугали, что нефть кончится; теперь говорят, что её хватит ещё на 50+ лет, ведь технология поиска улучшилась.<br>✅ <b>③ 사용 가능 기간이 늘어난</b> (срок возможного использования увеличился).<br>✖️ ① качество стало лучше, ② цена растёт, ④ ценность падает — не объясняются «더 많이 발견하게 된» (стали находить больше).<br>🧩 사용 가능 기간 = «срок, в течение которого можно использовать»."},{"n":18,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"수표교는 홍수 피해에 대비하기 위해 만든 조선 시대의 다리이다. 돌로 된 수표교의 기둥에는 일정한 간격마다 표시가 되어 있어서 (        ) 쉽게 알 수 있었다. 수표교를 관리하는 담당자는 비가 오면 강물이 높아지는지를 수시로 확인하고, 홍수가 날 것 같으면 사람들에게 알려 대피하도록 했다.","options":["강물의 높이 변화를","강물의 속도 차이를","다리 기둥의 간격을","다리를 만든 재료를"],"answer":1,"explain":"На столбах через равные промежутки были метки → ответственный «수시로 강물이 높아지는지 확인» — по меткам легко определял уровень воды.<br>✅ <b>① 강물의 높이 변화를</b> (изменение уровня реки).<br>✖️ ② разницу в скорости воды, ③ интервал между столбами, ④ материал моста — не связаны с «강물이 높아지는지».<br>🧩 간격 = «промежуток»; 수시로 = «то и дело, постоянно»."},{"n":19,"points":2,"instr":"Выберите подходящее слово для пропуска ( ).","passage":"좋은 생각을 끌어내려면 질문을 어떻게 할지 잘 고민해야 한다. 어떤 회사에서 신제품을 만들고자 직원에게 질문을 한다고 치자. \"어떤 물건이 잘 팔릴까?\"라고 막연하게 질문하면 대답이 잘 나오지 않는다. 좋은 질문이 아니기 때문이다. (        ) \"지금까지의 제품에서 무엇을 개선할까?\"라고 질문하면 도움이 되는 구체적인 답이 나온다.","options":["결코","특히","비록","반면"],"answer":4,"explain":"Расплывчатый вопрос ответа не даёт ↔ конкретный вопрос даёт полезный ответ. Нужна связка-противопоставление.<br>✅ <b>④ 반면</b> (с другой стороны, напротив).<br>✖️ ① 결코 (отнюдь, никогда), ② 특히 (особенно), ③ 비록 (хотя) — не передают контраст «плохой вопрос ↔ хороший вопрос».<br>🧩 반면 = «тогда как, напротив»; 막연하게 = «расплывчато»."},{"n":20,"points":2,"instr":"Выберите главную мысль текста.","passage":"좋은 생각을 끌어내려면 질문을 어떻게 할지 잘 고민해야 한다. … \"어떤 물건이 잘 팔릴까?\"라고 막연하게 질문하면 대답이 잘 나오지 않는다. … 반면 \"지금까지의 제품에서 무엇을 개선할까?\"라고 질문하면 도움이 되는 구체적인 답이 나온다.","options":["질문을 한 후에 생각할 시간을 줘야 한다.","도움이 되는 답을 얻으려면 질문을 잘해야 한다.","질문하기 전에 예상되는 답을 미리 생각해야 한다.","추상적인 질문으로 자유로운 생각을 끌어내야 한다."],"answer":2,"explain":"✅ <b>② Чтобы получить полезный ответ, нужно правильно задать вопрос.</b> — конкретный вопрос → конкретный ответ.<br>✖️ ① давать время подумать после вопроса, ③ заранее продумывать ожидаемый ответ — в тексте этого нет, ④ абстрактным вопросом раскрывать свободную мысль — наоборот, расплывчатый вопрос плох.<br>🧩 막연한/추상적인 질문 ↔ 구체적인 질문."},{"n":21,"points":2,"instr":"Выберите подходящее выражение (идиому) для пропуска ( ).","passage":"학생 수 감소로 폐교가 될 뻔한 산골 초등학교가 위기에서 벗어나 화제이다. 이 학교 선생님들은 (        ) 학교를 살릴 방법을 고민했다. 그러다 찾은 것이 '음악 특성화 학교'였다. 선생님들은 예술대학교에 협조를 요청해 학생들에게 다양한 악기를 가르칠 전문가를 구했다. 또 기업의 기부를 받아 유명 음악가와 함께하는 음악회도 개최했다. 이런 소문을 듣고 음악을 배우러 오는 학생들이 생기면서 이 학교는 폐교 위기에서 벗어났다.","options":["눈을 딱 감고","머리를 맞대고","손에 땀을 쥐고","목에 힘을 주고"],"answer":2,"explain":"Учителя вместе искали способ спасти школу.<br>✅ <b>② 머리를 맞대고</b> — «сдвинув головы», т.е. сообща обдумывать.<br>✖️ ① 눈을 딱 감고 — «зажмурившись» (решиться, закрыть глаза на риск), ③ 손에 땀을 쥐고 — «сжав от волнения» (затаив дыхание), ④ 목에 힘을 주고 — «важничать».<br>🧩 머리를 맞대다 = «совещаться, ломать голову вместе»."},{"n":22,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"학생 수 감소로 폐교가 될 뻔한 산골 초등학교가 위기에서 벗어나 화제이다. … 선생님들은 예술대학교에 협조를 요청해 학생들에게 다양한 악기를 가르칠 전문가를 구했다. 또 기업의 기부를 받아 유명 음악가와 함께하는 음악회도 개최했다. 이런 소문을 듣고 음악을 배우러 오는 학생들이 생기면서 이 학교는 폐교 위기에서 벗어났다.","options":["이 초등학교는 기업에 요청해 악기 전문가를 구했다.","이 초등학교는 선생님들의 노력에도 학생 수가 줄었다.","이 초등학교에서 개최한 음악회에 유명 음악가가 참여했다.","이 초등학교 선생님들이 학생들에게 직접 악기를 가르쳤다."],"answer":3,"explain":"✅ <b>③ В концерте, устроенном школой, участвовал известный музыкант.</b> — «유명 음악가와 함께하는 음악회도 개최».<br>✖️ ① просили эксперта у компании — нет, у художественного вуза (예술대학교), ② несмотря на старания, число учеников упало — наоборот, ученики стали приходить, ④ учителя сами учили игре — нет, нашли экспертов (전문가).<br>🧩 협조 = «содействие»; 기부 = «пожертвование»."},{"n":23,"points":2,"instr":"Выберите чувство героя («나») в подчёркнутой части.","passage":"퇴직한 아빠는 매일 아침 운전을 해서 나를 직장까지 데려다주셨다. … 출근할 때마다 잔소리를 듣는 것도 싫고 운전도 하고 싶어서 운전면허를 땄다. … 당분간 아빠의 차를 빌려 쓰기로 했다. \"사방을 잘 살피면서 운전해야 한다.\" 아빠에게 나도 그 정도는 안다고 큰소리를 치고 출발했다. <u>그러나 운전하는 내내 다리가 후들후들 떨렸다. 옆자리에 앉아 있을 때와는 달랐다. 운전대를 꼭 붙든 채 앞만 보고 도로를 달렸다.</u> 퇴근하고 집에 무사히 돌아왔을 땐 안도감에 눈물이 날 정도였다.","options":["기대되다","긴장되다","뿌듯하다","창피하다"],"answer":2,"explain":"Хвасталась, что всё умеет, но за рулём «ноги дрожали», «вцепилась в руль, глядя только вперёд» — это сильное напряжение.<br>✅ <b>② 긴장되다</b> (нервничать, быть в напряжении).<br>✖️ ① 기대되다 (предвкушать), ③ 뿌듯하다 (быть полным гордости), ④ 창피하다 (стыдно) — не передают «후들후들 떨렸다».<br>🧩 후들후들 떨리다 = «трястись, дрожать»; 운전대를 붙들다 = «вцепиться в руль»."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"퇴직한 아빠는 매일 아침 운전을 해서 나를 직장까지 데려다주셨다. 출근길 대중교통이 불편했기 때문이다. … 운전도 하고 싶어서 운전면허를 땄다. … 새 차를 샀다가 긁히기라도 할까 봐 당분간 아빠의 차를 빌려 쓰기로 했다. … 퇴근하고 집에 무사히 돌아왔을 땐 안도감에 눈물이 날 정도였다.","options":["나는 아빠의 차를 운전해서 회사에 다녀왔다.","나는 운전면허를 따기 전에 대중교통으로 출근했다.","나는 운전면허를 따자마자 자동차를 새로 구매했다.","나는 아빠의 조언 덕분에 운전하는 것이 어렵지 않았다."],"answer":1,"explain":"✅ <b>① Я съездила на работу и обратно, ведя машину отца.</b> — «아빠의 차를 빌려 … 무사히 돌아왔을 땐».<br>✖️ ② до прав ездила на транспорте — нет, её возил отец на машине, ③ сразу купила новую машину — наоборот, побоялась поцарапать и одолжила отцовскую, ④ благодаря совету вести было легко — наоборот, «다리가 후들후들 떨렸다».<br>🧩 무사히 = «благополучно»; 안도감 = «облегчение»."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 모처럼의 황금연휴, 여행사 예약 문의 「껑충」","options":["연휴가 짧아서 여행 상품을 찾는 예약 문의가 줄어들었다.","값이 비싸더라도 연휴 기간에 여행을 가려는 사람이 많아졌다.","오랜만에 오는 긴 연휴를 맞아 여행사에 예약 상담이 대폭 늘었다.","매년 돌아오는 연휴를 앞두고 여행사마다 적극적인 홍보를 시작했다."],"answer":3,"explain":"«Долгожданные „золотые“ выходные — запросы на бронь в турагентствах „подскочили“».<br>✅ <b>③ С приходом редких длинных выходных консультаций по броням в турагентствах резко прибавилось.</b> — «모처럼», «껑충».<br>✖️ ① выходные короткие, запросов меньше — наоборот, ② поедут даже за дорого — заголовок про рост спроса, не про цену, ④ турагентства начали активную рекламу — не о рекламе, а о спросе.<br>🧩 모처럼 = «впервые за долгое время»; 껑충 = «скачок вверх»; 대폭 = «значительно»."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 김민수 「올해의 선수상」 수상 유력, 야구팬들 기대 고조","options":["김민수가 상을 받아서 야구팬들이 매우 기뻐하고 있다.","김민수가 야구팬들의 큰 기대에도 불구하고 상을 받지 못했다.","김민수가 상을 받을 가능성이 많아 야구팬들의 기대가 높아지고 있다.","김민수가 상을 받는 데 실패했지만 야구팬들에게 많은 응원을 받았다."],"answer":3,"explain":"«Ким Минсу — вероятный лауреат „Игрока года“, ожидания фанатов растут».<br>✅ <b>③ Велики шансы, что Ким получит приз, и ожидания фанатов растут.</b> — «수상 유력» (вероятно получит), «기대 고조».<br>✖️ ① уже получил — нет, пока лишь «유력» (вероятно), ② и ④ не получил/провалился — наоборот, шансы высоки.<br>🧩 유력하다 = «иметь хорошие шансы»; 고조 = «нарастание, подъём»."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 지지부진한 태풍 피해 복구, 속 터지는 인주 주민들","options":["태풍 피해가 매년 발생해 인주 주민들이 대책을 요구했다.","태풍 피해를 복구하는 일에 인주 주민들의 참여가 저조하다.","태풍 피해를 막기 위한 방안이 인주 주민들에게 호응을 얻고 있다.","태풍 피해 복구가 잘 진행되지 않아 인주 주민들이 답답해하고 있다."],"answer":4,"explain":"«Вялое устранение последствий тайфуна — жители Инджу „кипят от досады“».<br>✅ <b>④ Восстановление идёт плохо, и жители Инджу в досаде.</b> — «지지부진한», «속 터지는».<br>✖️ ① тайфун каждый год, требуют мер — заголовок про конкретный медленный ремонт, ② участие жителей низкое — речь о ходе ремонта, не об участии, ③ меры нашли отклик — наоборот, недовольство.<br>🧩 지지부진하다 = «топтаться на месте»; 속(이) 터지다 = «лопаться от досады»."},{"n":28,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"특정 장소를 실시간으로 비추어 주는 인터넷 방송 채널인 '지금 거기'가 최근 인기를 끌고 있다. 이 방송에서는 남산에서 내려다보는 서울 풍경, 창밖으로 보이는 뉴욕 타임스퀘어 거리 등 하나의 장소를 편집 없이 그대로 보여 준다. 화면 앞에 있는 시청자들은 현장감 있는 풍경에 빠져들어 마치 (        ) 것처럼 느끼게 된다.","options":["오래된 영상을 보는","전혀 가 본 적이 없는","연예인과 방송에 출연하는","직접 그곳에 가서 바라보는"],"answer":4,"explain":"Канал без монтажа показывает место «как есть», зритель «погружается в живой пейзаж».<br>✅ <b>④ 직접 그곳에 가서 바라보는</b> (будто сам пришёл туда и смотрит).<br>✖️ ① смотрит старое видео — нет, «실시간» (в реальном времени), ② никогда там не бывал, ③ снимается в передаче со звёздами — не вяжутся с «현장감 있는 풍경에 빠져들어».<br>🧩 현장감 = «эффект присутствия»; 편집 없이 = «без монтажа»."},{"n":29,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"'산조'는 한 명의 연주자가 악기 하나를 가지고 다채로운 가락과 장단을 즉흥적으로 표현하는 한국 전통 음악의 한 갈래이다. 산조의 독특한 특성은 연주자가 악보대로 연주하는 것이 아니라 무대마다 다른 독주를 선보인다는 데 있다. 현장 분위기에 맞춰 (        ) 연주하기 때문에 같은 연주자의 공연을 여러 번 보아도 그때마다 새로운 감동을 받을 수 있다.","options":["여러 사람이 동시에","다양한 변화를 주면서","새로운 악기를 더하여","악보를 보면서 그대로"],"answer":2,"explain":"Сандо играют импровизированно, «не по нотам», каждый раз по-новому, под атмосферу зала.<br>✅ <b>② 다양한 변화를 주면서</b> (внося разнообразные изменения).<br>✖️ ① несколько человек одновременно — нет, «한 명의 연주자», ③ добавляя новый инструмент — «악기 하나», ④ по нотам как есть — наоборот, «악보대로 … 아니라».<br>🧩 즉흥적 = «импровизационный»; 가락과 장단 = «мелодия и ритм»."},{"n":30,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"치킨을 먹을 때 기름이 손에 묻는 게 싫어서 비닐장갑을 사용하는 사람들이 많다. 그런데 비닐장갑을 끼고 치킨을 먹더라도 여전히 기름이 손에 묻는다. 이는 비닐이 기름에 친화적인 폴리에틸렌으로 만들어져 비닐장갑에 기름이 잘 스며들기 때문이다. 게다가 비닐장갑의 두께가 매우 얇아 기름이 (        ) 수 있다.","options":["손에 전혀 묻지 않을","치킨의 맛을 떨어뜨릴","비닐을 부드럽게 만들","장갑을 더 쉽게 통과할"],"answer":4,"explain":"Плёнка «дружит» с маслом и тонкая → масло легко проходит сквозь перчатку и пачкает руку.<br>✅ <b>④ 장갑을 더 쉽게 통과할</b> (легче проходит сквозь перчатку).<br>✖️ ① совсем не пачкает руку — противоречит «여전히 기름이 손에 묻는다», ② портит вкус курицы, ③ делает плёнку мягче — не про это.<br>🧩 스며들다 = «впитываться»; 통과하다 = «проходить насквозь»."},{"n":31,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"상품의 종류와 유통 방식이 다양해지면서 물건을 고르는 것도 어려워졌다. 그러다 보니 선택에 들이는 시간을 줄이면서도 실패 없는 구매를 하려는 경향이 생겼다. 그중 하나가 유명인이 추천하는 물건을 고민 없이 따라 사는 것이다. 영향력 있는 인물이 (        ) 짧은 시간 안에 최선의 선택을 할 수 있을 것이라는 믿음이 이러한 소비에 반영된 것이다.","options":["직접 물건을 보내 주면","높은 가격으로 판매하면","선택한 것을 그대로 따르면","상품을 생산하도록 도와주면"],"answer":3,"explain":"Люди без раздумий покупают то, что советует знаменитость, веря, что так быстро сделают лучший выбор.<br>✅ <b>③ 선택한 것을 그대로 따르면</b> (если просто последовать его выбору).<br>✖️ ① если он сам пришлёт товар, ② если продаст дорого, ④ если поможет произвести товар — не вяжутся с «추천하는 물건을 … 따라 사는».<br>🧩 영향력 있는 인물 = «влиятельная персона»; 따르다 = «следовать»."},{"n":32,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"한 연구팀이 10년간 기린을 촬영하고 분석했다. 이 연구에서는 암컷 기린이 4~5세가 되면 몸 전체의 길이에서 목이 차지하는 비율이 이전보다 더 커지는 것을 발견했다. 기린이 임신으로 영양이 많이 필요한 나이에 더 높이 있는 나뭇잎까지 먹으려고 하면서 목이 길어지는 것이다. 연구팀은 이를 바탕으로 기린의 목 길이 변화가 먹이를 찾기 위해 노력하는 것과 밀접한 관계가 있다고 주장했다.","options":["연구팀은 올해부터 기린을 촬영하기 시작했다.","암컷 기린은 4~5세부터 먹이를 먹는 양을 줄인다.","암컷 기린은 임신을 하는 시기에 목이 더 길어진다.","연구팀은 기린의 목 길이가 먹이와 관련이 없다고 보았다."],"answer":3,"explain":"✅ <b>③ У самки жирафа в период беременности шея удлиняется.</b> — «임신으로 영양이 많이 필요한 나이에 … 목이 길어지는».<br>✖️ ① снимали с этого года — нет, «10년간», ② с 4–5 лет ест меньше — наоборот, тянется к листьям повыше, ④ длина шеи не связана с едой — наоборот, «밀접한 관계가 있다».<br>🧩 임신 = «беременность»; 비율 = «доля»."},{"n":33,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"19세기에는 위생에 대한 사람들의 인식이 높지 않았다. 그때 병원의 보건 위생 환경을 개선하는 데 기여한 사람이 바로 간호사였던 나이팅게일이다. 그는 매일 군 병원에서 사망 환자 수와 사망 원인을 기록하여 부상으로 죽는 병사보다 위생 문제로 감염되어 사망하는 병사가 더 많다는 것을 통계로 입증했다. 그리고 이 결과를 도표로 만들어 관계자들을 설득함으로써 의료 환경을 개선해 나갔다.","options":["나이팅게일은 통계 자료를 근거로 관계자들을 설득했다.","나이팅게일은 부상으로 죽는 병사가 가장 많다는 것을 밝혀냈다.","나이팅게일의 기록에는 병원 내 감염자 수가 포함되어 있지 않았다.","나이팅게일이 일을 시작했을 당시에는 병원의 위생 관리가 철저했다."],"answer":1,"explain":"✅ <b>① Найтингейл убедила ответственных лиц на основании статистики.</b> — «도표로 만들어 관계자들을 설득».<br>✖️ ② больше всего гибнут от ран — наоборот, от заражения из-за антисанитарии, ③ заражённых не учитывала — наоборот, именно их статистику собрала, ④ тогда гигиена была строгой — наоборот, «인식이 높지 않았다».<br>🧩 통계 = «статистика»; 입증하다 = «доказывать»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"스케이트의 날은 종목의 특성에 따라 차이가 있다. 쇼트 트랙은 스케이트의 날을 살짝 왼쪽으로 기울여서 고정시킨다. 코너를 도는 선수들이 몸을 왼쪽으로 기울여도 넘어지지 않게 한 것이다. 반면 피겨 스케이트는 날의 앞쪽을 큰 톱니 모양으로 만든다. 그래서 선수들이 공중으로 뛰어오를 때 날의 앞쪽을 사용해 빙판을 찍으면 더 높이 뛸 수 있다.","options":["쇼트 트랙은 스케이트의 날이 톱니 모양으로 되어 있다.","피겨 선수들은 높이 뛰어오르기 위해 날의 앞부분을 사용한다.","피겨에서는 선수가 넘어지지 않도록 스케이트의 날 앞쪽을 둥글게 했다.","쇼트 트랙에서는 스케이트 날을 똑바로 달아 코너를 잘 돌 수 있게 했다."],"answer":2,"explain":"✅ <b>② Фигуристы используют переднюю часть лезвия, чтобы прыгнуть выше.</b> — «날의 앞쪽을 사용해 … 더 높이 뛸 수 있다».<br>✖️ ① у шорт-трека лезвие зубчатое — нет, это у фигурного, ③ переднюю часть закруглили, чтобы не падать — нет, у фигурного она зубчатая, ④ в шорт-треке лезвие ставят прямо — нет, «왼쪽으로 기울여».<br>🧩 톱니 모양 = «зубчатая форма»; 기울이다 = «наклонять»."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"메타세쿼이아는 위로 쭉쭉 뻗은 모양이 아름다워서 가로수로 선호된다. 그런데 메타세쿼이아를 심을 때는 장소에 유의해야 한다. 메타세쿼이아는 생장이 빠른 특성이 있어서 건물이 늘어선 도로에 심어서는 안 된다. 뿌리가 빠르게 자라 주변 건물의 벽을 갈라지게 하기 때문이다. 또 키가 크고 잎이 무성해서 건물의 채광을 가리는 등 피해를 주기도 한다.","options":["메타세쿼이아는 생장이 느려 가로수로 적절하지 않다.","메타세쿼이아를 도로에 심으면 도시 경관을 개선할 수 있다.","메타세쿼이아는 적합한 장소에 심지 않으면 문제가 될 수 있다.","메타세쿼이아가 자라는 높이는 뿌리 내리는 장소에 따라 달라진다."],"answer":3,"explain":"✅ <b>③ Если метасеквойю посадить в неподходящем месте, могут быть проблемы.</b> — корни рушат стены, крона закрывает свет.<br>✖️ ① растёт медленно, не годится — наоборот, «생장이 빠른», ② посадка у дороги улучшит вид — наоборот, вредит зданиям, ④ высота зависит от места корней — это деталь, не тема.<br>🧩 생장 = «рост»; 채광 = «освещённость, доступ света»."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"미세 먼지 문제를 해결하기 위한 인공 강우 실험이 활발히 이뤄지고 있다. 인공적으로 비를 내리게 해서 대기 중의 미세 먼지 수치를 낮춘다는 계획이다. 그러나 현재의 인공 강우 기술은 구름이 있는 지역에서만 활용할 수 있고, 만들 수 있는 비의 양도 많지 않다. 이러한 점에서 인공 강우 기술은 미세 먼지 문제를 해결할 수 있는 근본적인 대책이라고 보기는 어렵다.","options":["인공 강우 기술이 상용화되도록 실험을 지속해야 한다.","미세 먼지를 줄이기 위해서는 국가 간 협력이 필수적이다.","미세 먼지 문제를 해결하기 위해서는 재정적인 지원이 중요하다.","인공 강우 기술은 미세 먼지를 줄이는 해결책으로는 한계가 있다."],"answer":4,"explain":"✅ <b>④ У технологии искусственного дождя есть пределы как у решения проблемы пыли.</b> — «근본적인 대책이라고 보기는 어렵다».<br>✖️ ① продолжать опыты до коммерциализации, ② нужна межгосударственная кооперация, ③ важна финансовая поддержка — текст не об этом, а об ОГРАНИЧЕНИЯХ метода.<br>🧩 인공 강우 = «искусственный дождь»; 근본적 = «коренной»."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"건강세는 설탕이나 가공 식품 등 건강에 해로운 식품에 부과하는 세금이다. 건강세를 걷으면 비만, 당뇨와 같은 질병을 유발하는 식품의 가격이 올라 소비가 억제된다. 이는 성인병 환자의 감소로 이어질 수 있다. 또한 걷은 세금으로 국민 건강 증진을 위한 재원을 확보하는 것도 기대할 수 있다. 물론 건강세가 소비자의 부담을 높인다는 비판도 있다. 하지만 건강세로 얻게 될 효과가 분명한 이상, 도입을 긍정적으로 검토해야 할 때다.","options":["건강세는 소비자의 부담을 최소화하는 선에서 부과되어야 한다.","건강세를 도입하기 전에 국민의 의견을 파악하는 것이 중요하다.","건강세는 국민의 건강 증진에 도움이 되므로 도입할 필요가 있다.","건강세를 부과할 식품을 선정할 때는 명확한 기준이 있어야 한다."],"answer":3,"explain":"✅ <b>③ Налог на нездоровье полезен для здоровья граждан, поэтому его стоит ввести.</b> — «효과가 분명한 이상 … 긍정적으로 검토».<br>✖️ ① вводить с минимальной нагрузкой на потребителя, ② сперва узнать мнение граждан, ④ нужны чёткие критерии выбора продуктов — частности, а вывод текста — «нужно вводить».<br>🧩 부과하다 = «облагать (налогом)»; 억제 = «сдерживание»."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"국회는 다양한 세대의 국회 의원들로 구성되어야 한다. 특히 청년 세대들은 새로운 기술이나 가치관을 빠르게 받아들여 사회 변화에 부합하는 정책을 제안할 수 있다. 또 취업 등 청년 정책에 적극적으로 목소리를 낼 수 있는 것도 청년 자신이다. 그런데 정치적 기반이 부족한 청년이 선거를 통해 국회에 진출하기란 쉽지 않다. 따라서 청년 국회 의원의 비율을 확보해 주는 등 청년들의 정치 활동을 보장할 필요가 있다.","options":["청년들이 국회에 활발하게 진출하도록 해야 한다.","청년 세대의 문제에 대해 정치권의 관심이 필요하다.","청년들이 제안하는 정책을 채택하는 비율을 높여야 한다.","청년 정치인은 정치적 기반을 갖추기 위해 노력해야 한다."],"answer":1,"explain":"✅ <b>① Нужно сделать так, чтобы молодёжь активно проходила в парламент.</b> — «청년 국회 의원의 비율을 확보 … 정치 활동을 보장».<br>✖️ ② политикам нужен интерес к проблемам молодёжи (мягче, чем вывод), ③ повышать долю принятия их политик, ④ молодым политикам надо нарабатывать базу — наоборот, текст просит обеспечить им доступ.<br>🧩 진출하다 = «выходить, пробиваться»; 보장 = «гарантия»."},{"n":39,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"고대 이집트에서는 물에 푼 섬유질을 틀에 올려 건조하는 방식으로 종이를 만들었다. (㉠) 이후 제지업자들이 틀에 고유의 문양을 새겨 자신만의 워터 마크를 남기기 시작했다. (㉡) 이것이 이어져 저작권을 표시하거나 위조를 막기 위해 문서나 지폐 등에 워터 마크를 넣게 되었다. (㉢) 지금도 이 워터 마크는 사진이나 영상 등의 저작권을 보호하는 용도로 널리 활용되고 있다. (㉣)\n\n<보기> 섬유질이 마르는 과정에서 자연스레 틀의 자국이 남았는데, 이를 워터 마크라고 불렀다.","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"<보기> объясняет ПРОИСХОЖДЕНИЕ слова «водяной знак»: при сушке волокон на рамке оставался её след. Идёт сразу после описания сушки бумаги на рамке (㉠), до «이후 제지업자들이…».<br>✅ <b>① ㉠</b>.<br>🧩 «섬유질이 마르는 과정 … 틀의 자국» прямо продолжает «건조하는 방식으로 종이를 만들었다»."},{"n":40,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"콘크리트를 만들기 위해서는 모래나 자갈 같은 골재가 필요하다. (㉠) 천연 모래와 자갈이 풍부한 바다에서는 질 좋은 골재를 쉽게 얻을 수 있다. (㉡) 그러다 보니 과다한 골재 채취로 바닷속 지형이 바뀌는 경우가 많다. (㉢) 이에 채취량을 제한하고 해당 구역의 복구를 의무화하는 등의 규제를 엄격히 시행하여 해양 생태계를 보호하려는 노력이 이어지고 있다. (㉣)\n\n<보기> 해양 생물이 서식하던 바닷속 모래 언덕이나 골짜기가 파괴되는 것이다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기> «-이다» конкретизирует, ЧТО именно происходит при «바닷속 지형이 바뀌는» (рушатся подводные дюны и впадины). Идёт сразу после «바닷속 지형이 바뀌는 경우가 많다» (㉢).<br>✅ <b>③ ㉢</b>.<br>🧩 «파괴되는 것이다» поясняет предыдущее «지형이 바뀌는», поэтому стоит за ним, перед «이에 … 규제»."},{"n":41,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"수많은 독자의 사랑을 받아 온 소설 『이상한 편의점』이 해외에서도 호평받고 있다. (㉠) 이 책은 우연한 기회로 한 편의점에서 일하게 된 노숙자 상철과 편의점을 찾은 손님들의 일화를 담고 있다. (㉡) 이 책이 한국을 넘어 해외 독자들의 마음까지 울리는 이유가 바로 이 따뜻함에 있다. (㉢) 지친 삶에 응원이 필요한 모든 이에게 이 책을 권한다. (㉣)\n\n<보기> 상철은 저마다의 사연을 안고 편의점을 찾은 손님들에게 따스한 위로를 건넨다.","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"<보기> (Санчхоль дарит тёплое утешение посетителям) раскрывает «이 따뜻함», о котором говорится далее. Идёт после знакомства с Санчхолем и посетителями (㉡), перед «바로 이 따뜻함에 있다».<br>✅ <b>② ㉡</b>.<br>🧩 «따스한 위로» в <보기> = источник «이 따뜻함» в следующем предложении."},{"n":42,"points":2,"instr":"Выберите чувство героя (재헌) в подчёркнутой части.","passage":"⚠️ Оригинальный литературный отрывок (рассказ о герое по имени 재헌) защищён авторским правом, и Государственный институт (NIIED) НЕ публикует его в открытых материалах 96-го экзамена: «저작권 관련 법령에 따라 본 문항의 지문은 공개하지 않습니다». Полный текст здесь не приводится — ответ дан по официальному ключу.\n\nКонтекст (восстанавливается по вопросам): у 재헌 рождается ребёнок (출산); его жена (아내) находится со своей младшей сестрой (처제).","options":["대견하다","허전하다","못마땅하다","감격스럽다"],"answer":3,"explain":"Литературный отрывок не опубликован институтом, поэтому точную подчёркнутую фразу процитировать нельзя. По официальному ключу верный ответ — <b>③ 못마땅하다</b> (быть недовольным, считать что-то неподобающим).<br>🧩 Значения вариантов: ① 대견하다 — «горд( за кого-то), молодец», ② 허전하다 — «пусто, одиноко на душе», ③ 못마땅하다 — «недоволен, не по душе», ④ 감격스럽다 — «растроган, переполнен чувствами».<br>📌 Тип задания: определить 심정 (чувство героя) по выделенной фразе художественного текста."},{"n":43,"points":2,"instr":"Выберите вариант, который можно понять из текста.","passage":"⚠️ Тот же отрывок, что и в задании 42, официально не публикуется по авторскому праву («본 문항의 지문은 공개하지 않습니다»). Ответ приведён по официальному ключу.\n\nКонтекст: 재헌 ждёт рождения ребёнка; его жена (아내) сейчас вместе с младшей сестрой жены (처제).","options":["아내는 지금 처제와 함께 있다.","처제는 아내와 성격이 비슷하다.","아내의 출산 예정 시간이 이미 지났다.","재헌은 아내가 있는 곳에 막 도착했다."],"answer":1,"explain":"По официальному ключу верный ответ — <b>① 아내는 지금 처제와 함께 있다</b> (жена сейчас находится вместе с младшей сестрой).<br>✖️ ② у 처제 похожий с женой характер, ③ срок родов уже прошёл, ④ 재헌 только что прибыл туда, где жена — эти утверждения текстом не подтверждаются.<br>📌 Тип задания: 내용으로 알 수 있는 것 (что можно вывести из художественного текста). Полный отрывок не опубликован NIIED."},{"n":44,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"그라피티는 길거리 여기저기 벽면에 낙서처럼 그리거나 스프레이 페인트를 뿌려서 그리는 그림을 말한다. 지하철, 공공장소의 벽면 등에 주로 그려진 그라피티는 사회 비판적인 메시지를 표현하는 경우가 많았다. 권력에 대한 (        ) 소수와 약자의 목소리를 담은 것이다. 이 때문에 그라피티는 주류 문화에서 벗어나 있는 것으로 여겨졌다. 그러나 오늘날 그라피티는 더 이상 변방의 문화에 머물러 있지 않다. … 이에 사람들은 그간 폄하당해 왔던 그라피티의 예술적 가치에도 주목하기 시작했다.","options":["불신을 없애며","저항 정신을 드러내며","태도를 수동적으로 취하며","우호적 반응을 이끌어 내며"],"answer":2,"explain":"Граффити несло «사회 비판적인 메시지», голос меньшинств против власти.<br>✅ <b>② 저항 정신을 드러내며</b> (проявляя дух сопротивления).<br>✖️ ① устраняя недоверие, ③ занимая пассивную позицию, ④ вызывая дружелюбный отклик — противоречат «권력에 대한 … 비판적인 메시지».<br>🧩 저항 정신 = «дух сопротивления»; 약자 = «слабые, уязвимые»."},{"n":45,"points":2,"instr":"Выберите главную тему текста.","passage":"그라피티는 길거리 벽면에 낙서처럼 그리거나 스프레이로 그리는 그림을 말한다. … 사회 비판적인 메시지를 표현하는 경우가 많아 주류 문화에서 벗어나 있는 것으로 여겨졌다. 그러나 오늘날 그라피티는 더 이상 변방의 문화에 머물러 있지 않다. 친숙함을 무기로 일상생활 속에 스며들어 … 인식을 바꾸어 놓았기 때문이다. 이에 사람들은 그라피티의 예술적 가치에도 주목하기 시작했다. 이제 그라피티는 … 현대 미술에서 제자리를 확고히 하고 있다.","options":["그라피티는 도시 환경을 훼손하는 문제점을 가지고 있다.","그라피티는 길거리 낙서로서의 한계를 뛰어넘지 못하고 있다.","과거의 그라피티는 주류 문화의 중심에서 대중의 사랑을 받았다.","오늘날의 그라피티는 과거와 달리 예술적 가치를 인정받고 있다."],"answer":4,"explain":"✅ <b>④ Сегодняшнее граффити, в отличие от прошлого, признаётся как искусство.</b> — «예술적 가치에 … 주목», «현대 미술에서 제자리를 확고히».<br>✖️ ① портит городскую среду — наоборот, «다채롭게 장식», ② не вышло за рамки уличных каракулей — наоборот, вышло, ③ в прошлом было в центре мейнстрима — наоборот, «변방의 문화».<br>🧩 변방 = «окраина»; 주목 = «внимание»."},{"n":46,"points":2,"instr":"Выберите отношение автора, выраженное в тексте.","passage":"현행 문화재 보호법에서는 역사적·예술적으로 가치가 높은 음악, 무용, 공예 기능 등을 국가 무형 문화재로 규정하고 있다. … 이 무형 문화재는 형체가 없으므로 기능을 보유한 사람을 인간문화재로 지정해 이들을 통해 문화재가 보존되도록 한다. 그런데 이 무형 문화재를 전수받으려는 사람이 줄고 있어 문화재 보존에 비상등이 켜졌다. … 전통문화는 그 민족의 자긍심과도 밀접하게 관련되어 있는 것인데, 이렇게 가다가는 무형 문화재의 명맥이 끊이는 일이 생길 수 있을 것이다.","options":["인간문화재가 앞으로 더 많이 배출될 것을 기대하고 있다.","국가 무형 문화재의 전수가 단절되어 가는 것을 우려하고 있다.","인간문화재가 되기 위해 노력하는 사람의 자세에 감탄하고 있다.","국가 무형 문화재의 선정 절차를 투명하게 할 것을 요구하고 있다."],"answer":2,"explain":"✅ <b>② Опасается, что передача нематериального наследия прерывается.</b> — «비상등이 켜졌다», «명맥이 끊이는 일이 생길 수 있을 것이다».<br>✖️ ① ждёт, что «человеков-сокровищ» станет больше — наоборот, желающих всё меньше, ③ восхищается старанием — текст тревожен, ④ требует прозрачности отбора — об этом не говорится.<br>🧩 전수 = «передача (мастерства)»; 우려하다 = «опасаться»; 명맥 = «нить преемственности»."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"… 이에 따라 여러 세대에 걸쳐 전승되어 온 무형의 문화유산 중 원형 그대로 계승될 만한 가치가 있는 것을 국가 무형 문화재로 지정한다. 이 무형 문화재는 형체가 없으므로 기능을 보유한 사람을 인간문화재로 지정해 이들을 통해 문화재가 보존되도록 한다. 그런데 … 오랜 시간 어렵게 기능을 전수받더라도 무조건 인간문화재로 지정되는 것도 아니고, 기능을 연마하는 동안에는 국가의 경제적 지원도 없기 때문이다.","options":["국가 무형 문화재에 대한 법적 근거가 존재하지 않는다.","국가 무형 문화재는 그 기능을 보유한 인간문화재를 통해 전수된다.","국가 무형 문화재 기능을 전수받는 동안 경제적 지원을 받을 수 있다.","국가 무형 문화재로 인정받으려면 원형을 시대에 맞게 변형해야 한다."],"answer":2,"explain":"✅ <b>② Нематериальное наследие передаётся через «человеков-сокровищ», владеющих мастерством.</b> — «기능을 보유한 사람을 인간문화재로 지정해 이들을 통해 … 보존».<br>✖️ ① нет правовой базы — наоборот, есть «문화재 보호법», ③ во время обучения дают деньги — наоборот, «경제적 지원도 없기», ④ нужно видоизменять под эпоху — наоборот, «원형 그대로».<br>🧩 원형 = «первозданная форма»; 계승 = «преемство»."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"도심의 교통 혼잡 문제가 심화되면서 새로운 건축물을 짓는 경우 사전에 교통 영향 평가를 받도록 하고 있다. … 또한 교통 혼잡을 유발하는 시설의 소유자에게 교통 유발 부담금을 부과하는 제도도 시행하고 있다. 그러나 이와 같은 방법만으로는 그 효과가 제한적이라는 평가가 대부분이다. … 따라서 보다 전방위적으로 여러 정책을 시행함으로써 도심 교통 문제 해결에 나설 필요가 있다. … 여러 방안을 병행한다면 도심의 교통 환경을 점차 개선해 나갈 수 있을 것이다.","options":["교통 영향 평가의 부정적 효과를 강조하기 위해서","교통 유발 부담금 제도를 도입한 취지를 알리기 위해서","교통 문제 해결을 위한 방안의 다각화를 주장하기 위해서","교통 상황을 개선한 경우 받게 되는 혜택을 소개하기 위해서"],"answer":3,"explain":"Автор: одних оценок и сборов мало → нужно сочетать множество мер.<br>✅ <b>③ Чтобы доказать необходимость диверсификации мер решения транспортных проблем.</b> — «전방위적으로 여러 정책을 … 병행».<br>✖️ ① подчеркнуть негатив оценки воздействия, ② рассказать о смысле сбора, ④ познакомить с льготами — лишь части текста, а цель — «нужно много мер вместе».<br>🧩 다각화 = «диверсификация»; 병행하다 = «совмещать»."},{"n":49,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"… 이 평가 결과를 반영해 건축물과 지하철, 버스 등 대중교통 수단의 연계성을 높여 대중교통 이용을 유도함으로써 (        ) 것이 대표적인 사례이다. 또한 교통 혼잡을 유발하는 시설의 소유자에게 교통 유발 부담금을 부과하는 제도도 시행하고 있다.","options":["건축 기간이 연장된","교통 정체가 유발된","주차장 규모를 확대한","주변 교통량을 감축한"],"answer":4,"explain":"Усилили связь с метро/автобусами → побуждают пользоваться общественным транспортом → значит, снизили поток машин вокруг.<br>✅ <b>④ 주변 교통량을 감축한</b> (сократили окрестный трафик).<br>✖️ ① продлили срок стройки, ② вызвали затор, ③ расширили парковку — противоречат цели «대중교통 이용을 유도» (пересадить на общественный транспорт).<br>🧩 감축 = «сокращение»; 연계성 = «связанность»."},{"n":50,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"도심의 교통 혼잡 문제가 심화되면서 새로운 건축물을 짓는 경우 사전에 교통 영향 평가를 받도록 하고 있다. … 또한 교통 혼잡을 유발하는 시설의 소유자에게 교통 유발 부담금을 부과하는 제도도 시행하고 있다. 그러나 이와 같은 방법만으로는 그 효과가 제한적이라는 평가가 대부분이다. … 문제 해결을 위한 실질적인 노력을 하는 시설의 소유자에게 여러 혜택을 주고 … 등의 여러 방안을 병행한다면 …","options":["교통 영향 평가는 도심에 건축물을 짓고 난 후에 시행한다.","교통 영향 평가는 도심에 유입되는 인구를 늘리기 위해 실시한다.","교통 혼잡 해결을 위해 노력하는 건축물의 소유자는 혜택을 받고 있다.","교통 혼잡을 일으키는 시설의 소유자는 그에 따른 부담금을 내야 한다."],"answer":4,"explain":"✅ <b>④ Владельцы объектов, создающих заторы, должны платить соответствующий сбор.</b> — «교통 혼잡을 유발하는 시설의 소유자에게 … 부담금을 부과».<br>✖️ ① оценку проводят после стройки — нет, «사전에» (заранее), ② чтобы увеличить население — наоборот, смягчить последствия, ③ старающиеся уже получают льготы — это пока ПРЕДЛОЖЕНИЕ автора («주고 … 병행한다면»), а не действующая практика.<br>🧩 사전에 = «заранее»; 부담금 = «сбор, пошлина»."}]
      },
      writing: {"durationMin":50,"label":"제96회 · 쓰기 (51~54)","tasks":[{"n":51,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Это пост иностранного студента на форуме университета — вежливый стиль -습니다.","passage":"💬 자유 게시판 · 인주대학교\n제목: 어디로 이사하는 것이 좋을까요?  (작성자: 애르덴)\n\n안녕하세요. 외국인 유학생입니다.\n기숙사 생활이 불편해서 이번 방학에 이사를 ( ㉠ ).\n집값이 싸고 좀 깨끗한 동네면 좋겠습니다.\n그런데 어느 ( ㉡ ) 잘 모르겠습니다.\n좋은 곳을 아시면 추천 부탁드립니다.","blanks":[{"slot":"㉠","model":"하려고 합니다 / 하고 싶습니다","check":"«기숙사 생활이 불편해서 … 이사를 ( )» → автор объявляет о НАМЕРЕНИИ переехать на каникулах: 이사를 하려고 합니다 / 하고 싶습니다 (собираюсь / хочу переехать). Вежливый стиль -습니다."},{"slot":"㉡","model":"동네가 좋은지 / 동네가 좋을지 / 곳으로 갈지","check":"«그런데 어느 ( ) 잘 모르겠습니다» → косвенный вопрос «не знаю, какой район/куда лучше»: 어느 동네가 좋은지 / 동네가 좋을지 / 곳으로 갈지. Косвенный вопрос на -ㄴ지/-ㄹ지."}]},{"n":52,"points":10,"korInstr":"다음 글의 ㉠과 ㉡에 들어갈 말을 각각 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст о лягушках — письменный стиль -다.","passage":"개구리가 겨울에 추위를 피해 겨울잠을 잔다는 것은 잘 알려져 있다. 그런데 개구리가 꼭 추운 겨울에만 긴 잠을 ( ㉠ ). 더운 지역에 사는 개구리는 기온이 매우 높은 기간에 긴 잠을 자기도 한다. 왜냐하면 개구리는 사람과 달리 체내에서 체온 조절을 ( ㉡ ). 개구리처럼 체온 조절을 못하는 동물에게는 추위뿐만 아니라 더위도 생존에 위협이 되는 것이다.","blanks":[{"slot":"㉠","model":"자는 것은 아니다","check":"«꼭 추운 겨울에만 긴 잠을 ( )» + следующее предложение «더운 지역 개구리는 더울 때도 잠을 잔다» → значит, спят НЕ только зимой: (긴 잠을) 자는 것은 아니다. «꼭 … 만 … 것은 아니다» (не обязательно только…). Письменный стиль -다."},{"slot":"㉡","model":"못하기 때문이다 / 하지 못하기 때문이다","check":"«왜냐하면 … 체온 조절을 ( )» → конструкция «왜냐하면 ~기 때문이다»; лягушки спят и в жару, потому что НЕ умеют регулировать температуру тела: 체온 조절을 못하기 때문이다 / 하지 못하기 때문이다."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음은 「인주시 마라톤 대회 참가자 수의 변화」에 대한 자료이다. 이 내용을 200~300자의 글로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные об изменении числа участников марафона в г. Инджу (한국스포츠연구소) текстом 200–300 знаков. Сравните общий рост и динамику по возрастам, укажите причины. Письменный стиль -다, без заголовка.","image":"assets/topik2/exams/img/96-w53.png","model":"한국스포츠연구소에서 인주시 마라톤 대회 참가자 수의 변화를 조사하였다. 그 결과 인주시 마라톤 대회 참가자 수는 2013년 40만 명에서 2023년 100만 명으로 2.5배 증가한 것으로 나타났다. 이를 연령별로 살펴보면 20~30대는 지난 10년간 4배 증가한 반면 40~50대는 같은 기간에 1.3배 증가하는 데에 그쳤다. 이러한 변화의 원인은 건강 관리에 대한 관심이 높아져 달리기 문화가 확산되었고 SNS를 통한 마라톤 모임이 활성화되어 20~30대 참가자가 증가하였기 때문인 것으로 보인다.","check":"① Назван источник и предмет (한국스포츠연구소 · 마라톤 참가자 수 변화)? ② Общий рост с цифрами (2013년 40만 → 2023년 100만, 2.5배)? ③ Сравнение по возрастам (20~30대 4배 ↔ 40~50대 1.3배) со связкой 반면? ④ Указаны причины (건강 관심↑ → 달리기 문화 확산; SNS 마라톤 모임 활성화 → 20~30대 참가자↑)? ⑤ Стиль -다, 200~300 знаков, без заголовка?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 참고하여 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков на тему «직장과 개인의 자율성» (рабочее место и личная автономия). Раскройте все три вопроса, разбейте на абзацы, письменный стиль -다.","passage":"오늘날 직장 내에서 복장, 출퇴근 시간, 업무 방식 등에 대해 개인의 자율성을 원하는 사람들이 많아진다. 회사에서 이런 개인의 자율성이 보장될 때 얻는 장점이 있다. 그러나 개인의 자율성을 중시하는 사람이 많아지면 여러 문제가 발생할 우려도 있다. 아래의 내용을 중심으로 「직장과 개인의 자율성」에 대한 자신의 생각을 쓰라.\n• 직장에서 개인의 자율성이 보장될 때의 장점은 무엇인가?\n• 직장 내 사람들이 개인의 자율성을 중요시할 때 생기는 문제는 무엇인가?\n• 이런 문제를 해결하기 위해서는 어떻게 해야 하는가?","model":"사회의 변화로 개인의 자율성을 중시하는 사람들이 많아졌다. 이에 따라 기업에서도 유연근무제를 실시하는 등 직장 내 자율성을 높이고자 노력하고 있다. 직장에서 개인의 자율성이 보장되면 직장 내 문화가 유연해져 개인이 창의성을 발휘할 수 있는 근무 환경이 만들어진다. 또한 개인이 자신에게 적합한 근무 여건을 조성하여 일할 수 있어 일과 삶의 균형이 생긴다. 이것이 구성원의 업무 효율을 높이는 데 기여하여 조직의 목표를 달성하는 데에 도움이 된다.\n그러나 직장 내 사람들이 개인의 자율성만 중시하면 부작용이 발생할 수 있다. 먼저, 개인이 공동의 목표보다는 자신의 입장만을 생각하다 보면 자율성이 이기주의로 변질될 수 있다. 이러한 상황이 계속되면 책임자와 팀원 간 갈등, 세대 간 갈등이 발생할 수도 있다. 또한 업무의 자율성이 높아져 개별적으로 일할 수 있는 환경이 익숙해지면 소통이 부재하여 합의점을 찾기 어렵고 협력을 통한 성과를 내기 어려울 수 있다.\n이러한 문제를 해결하기 위해서는 직장 내 개개인이 자율성을 가지면서도 업무를 수행할 때는 최대한 동료와 협업하고 서로를 배려하는 마음을 가질 필요가 있다. 또한 조직은 구성원의 자율성을 높이면서 조직의 목표를 성취하는 데 도움이 되는 방안을 고민해야 한다. 나아가 효율적인 의사소통 방안을 마련하여 구성원 간 원활한 협력이 가능하도록 해야 할 것이다.","check":"① Раскрыт 1-й вопрос — плюсы автономии (유연한 문화·창의성, 일과 삶의 균형, 업무 효율↑ → 조직 목표 달성)? ② Раскрыт 2-й вопрос — проблемы (자율성→이기주의 변질, 책임자·팀원·세대 간 갈등, 소통 부재로 협력 약화)? ③ Раскрыт 3-й вопрос — решения (협업·배려, 조직 차원의 방안 고민, 효율적 의사소통)? ④ Структура: вступление-плюсы / проблемы / решения, связки 그러나·먼저·또한·이러한 문제를 해결하기 위해서는·나아가? ⑤ Стиль -다, объём 600~700 знаков, без дословного переписывания задания?"}]}
    },
    41: {
      listening: {
        durationMin: 60, total: 100, label: '제41회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/41/41st%20TOPIK%20II%20-%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"image":"assets/topik2/exams/img/41-l-q1.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":2,"explain":"🎧 여자: 어, 왜 밥이 안 됐지?<br>남자: 어디 봐. 밥솥 버튼을 안 눌렀나 보네.<br>여자: 이상하다. 분명히 눌렀는데…….<br><br>Рис не сварился — мужчина заглядывает в рисоварку и замечает, что кнопка не нажата.<br>✅ <b>②</b> — двое у рисоварки (밥솥), мужчина проверяет кнопку.<br>🧩 안 눌렀나 보네 = «похоже, не нажал(а)» (предположение -나 보다)."},{"n":2,"points":2,"image":"assets/topik2/exams/img/41-l-q2.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":1,"explain":"🎧 여자: 민수 씨, 이거 여기에 심을 거예요?<br>남자: 네. 조금만 더 파면 되니까 잠깐만 들고 계세요.<br>여자: 알았어요. 그런데 다 심고 나면 물 좀 많이 줘야겠어요.<br><br>Сажают растение: мужчина копает ямку, женщина держит саженец.<br>✅ <b>①</b> — мужчина копает (파다), женщина держит растение в руках.<br>🧩 심다 = «сажать»; 파다 = «копать»."},{"n":3,"points":2,"image":"assets/topik2/exams/img/41-l-q3.png","instr":"Прослушайте и выберите подходящий график.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: …비행기 수하물 사고 수는 2010년에 최고였다가 감소하고 있습니다. 사고 종류로는 짐이 늦게 도착하는 지연 사고가 가장 많았고 가방 안의 물건이 깨지는 파손 그리고 분실이 각각 그 뒤를 이었습니다.<br><br>Число багажных инцидентов: пик в 2010-м, затем спад; по видам — 지연(задержка) > 파손(поломка) > 분실(пропажа).<br>✅ <b>②</b> — линия с пиком в 2010 и спадом + столбцы в порядке 지연>파손>분실.<br>🧩 그 뒤를 잇다 = «следовать за…» (по порядку)."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["발표회는 언제 시작해요?","꼭 가려고 했는데 못 갔어요.","도저히 시간이 안 될 것 같아요.","갑자기 무슨 일이 있었던 거예요?"],"answer":2,"explain":"🎧 여자: 영수 씨, 발표회 잘 끝났어요? 못 가서 미안해요.<br>남자: 아니에요. 급한 일이 있었다면서요.<br>여자: ____<br><br>Женщина извиняется, что не смогла прийти; мужчина её успокаивает.<br>✅ <b>② 꼭 가려고 했는데 못 갔어요.</b> (очень хотела прийти, но не получилось).<br>✖️ ① «когда начинается?» (презентация уже прошла), ③ «никак не успеваю» (о будущем), ④ это слова мужчины, а не извиняющейся женщины."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["앞으로는 아껴 쓰면 좋겠는데요.","용돈을 많이 주셔서 충분했어요.","아직 남기는 했는데 살 게 있어서요.","필요하면 언제든지 달라고 말할게요."],"answer":3,"explain":"🎧 남자: 엄마, 저 용돈이 부족한데 좀 더 주시면 안 될까요?<br>여자: (놀란 어조로) 아니, 지난주에 준 건 벌써 다 쓴 거야?<br>남자: ____<br><br>Мама удивлена: «уже всё потратил?» → сын объясняет.<br>✅ <b>③ 아직 남기는 했는데 살 게 있어서요.</b> (немного осталось, но нужно кое-что купить).<br>✖️ ① совет экономить (его дала бы мама), ② «хватало» (тогда не просил бы), ④ не отвечает на вопрос «уже потратил?»."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["이번에도 내가 이겼지?","내가 언제 그랬다고 그래?","배드민턴 치는 건 재미가 없어.","계속 화내면 다시는 안 칠 거다."],"answer":2,"explain":"🎧 남자: 누나, 뭐 해? 심심한데 나가서 배드민턴 치자.<br>여자: 좋아. 그런데 지난번처럼 졌다고 화내기 없기다.<br>남자: ____<br><br>Сестра ставит условие: «не злись, если проиграешь, как в прошлый раз»; брат отнекивается.<br>✅ <b>② 내가 언제 그랬다고 그래?</b> (когда это я такое делал?).<br>✖️ ① «я ведь снова выиграл?» (игра ещё не была), ③ «бадминтон скучный» (сам же позвал), ④ это сказала бы сестра."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["너무 바쁘셔서 그랬겠지요.","준비하느라 많이 바빴겠어요.","이렇게 초대해 주셔서 감사해요.","집들이가 있는지 모르고 안 갔어요."],"answer":1,"explain":"🎧 남자: 지영 씨, 다음 주 김민호 씨 집들이에 초대 받았지요?<br>여자: 어, 맞다. 민호 씨 집들이 하죠? 깜박 잊고 있었어요.<br>남자: ____<br><br>Женщина совсем забыла про новоселье; мужчина мягко её оправдывает.<br>✅ <b>① 너무 바쁘셔서 그랬겠지요.</b> (наверное, потому что вы очень заняты).<br>✖️ ② «вы устали, готовясь» (готовит хозяин Минхо), ③ благодарность за приглашение, ④ «не знал и не пошёл» — новоселье ещё впереди."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그럼 언제쯤 신청서가 완성될까요?","그래요? 대회가 잘 끝나서 다행이군요.","그래요? 학생들이 신청을 많이 했군요.","그럼 기간이 좀 남았으니까 기다려 볼까요?"],"answer":4,"explain":"🎧 남자: 이 선생님, 바둑 대회 신청은 많이 들어왔습니까?<br>여자: 아니요, 원장님. … 아직까지는 많지 않은데요.<br>남자: ____<br><br>Заявок пока мало → директор предлагает подождать, ведь срок ещё есть.<br>✅ <b>④ 그럼 기간이 좀 남았으니까 기다려 볼까요?</b><br>✖️ ① «когда заполнится заявление?», ② «соревнование удачно завершилось» (ещё не было), ③ «много подали» — наоборот, мало."},{"n":9,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["단추를 단다.","셔츠를 준다.","셔츠를 입는다.","넥타이를 맨다."],"answer":1,"explain":"🎧 남자: …넥타이 매는 것 좀 도와줘요.<br>여자: 알겠어요. 어? 근데 셔츠에 단추가 떨어졌네요. 금방 달아 줄 테니까 줘 봐요.<br>… 여자: 지금 바로 돼요. 잠깐만 기다려 봐요.<br><br>Женщина заметила оторванную пуговицу и собирается её ПРИШИТЬ прямо сейчас.<br>✅ <b>① 단추를 단다.</b> (пришивает пуговицу).<br>✖️ ② рубашку отдаёт мужчина, ③ надевать рубашку — не она, ④ галстук завязывает сам мужчина.<br>🧩 단추를 달다 = «пришивать пуговицу»."},{"n":10,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["책을 읽는다.","커피를 산다.","산책을 한다.","기숙사에 간다."],"answer":3,"explain":"🎧 여자: 너무 졸리다. …<br>남자: 졸리면 기숙사에 들어가서 일찍 자고….<br>여자: 전 아침잠이 많아서…. 잠 좀 깨게 잠깐 나가서 산책해야겠어요. …<br>남자: 아니야, 됐어. 좀 전에 마셨어.<br><br>Чтобы прогнать сон, женщина выйдет ПРОГУЛЯТЬСЯ (кофе мужчине не нужен — уже пил).<br>✅ <b>③ 산책을 한다.</b><br>✖️ ① читать (как раз сонная), ② купить кофе — мужчина отказался, ④ идти в общежитие и спать — она рано не встаёт."},{"n":11,"points":2,"instr":"Прослушайте и выберите действие, которое женщина совершит далее.","options":["서류를 복사한다.","홍보부에 다녀온다.","부장에게 연락한다.","사진을 거래처에 보낸다."],"answer":3,"explain":"🎧 남자: 부장님께서 계속 찾으시던데요. … 빨리 연락부터 드려 보세요.<br>여자: 알겠어요. 그럼 이 서류 복사 좀 부탁 드릴게요.<br><br>Начальник искал её по срочному делу → сначала женщина СВЯЖЕТСЯ с начальником (копирование она поручает собеседнику).<br>✅ <b>③ 부장에게 연락한다.</b><br>✖️ ① копировать документы — она просит сделать это мужчину, ② в отдел рекламы уже сходила, ④ фото отправлять не она.<br>🧩 연락부터 = «сначала связаться» (-부터 = «начиная с»)."},{"n":12,"points":2,"instr":"Прослушайте и выберите действие, которое женщина (шеф-повар) совершит далее.","options":["업체에 전화한다.","주문서를 확인한다.","재료를 창고로 옮긴다.","빠진 재료를 알려 준다."],"answer":2,"explain":"🎧 남자: 정리하다 보니 안 들어온 것들이 있는데 어떻게 할까요?<br>여자(주방장): 빠진 걸 알려 주면 제가 주문서를 다시 확인하고 업체에 전화해 보겠습니다.<br>남자: 네. 그럼 … 재료들은 먼저 보관 창고로 옮기겠습니다.<br><br>Шеф-повар (여자) сначала ПЕРЕПРОВЕРИТ бланк заказа, а уже потом позвонит поставщику.<br>✅ <b>② 주문서를 확인한다.</b> — «제가 주문서를 다시 확인하고 …».<br>✖️ ① звонит поставщику — это её следующий шаг ПОСЛЕ проверки заказа, ③ переносит продукты на склад — действие мужчины, ④ сообщает, чего не хватает — тоже делает мужчина."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 어머니의 블라우스를 산 적이 있다.","남자는 오늘 어머니와 백화점에 갔다 왔다.","여자는 상품권을 선물로 드리고 싶어 한다.","여자는 오늘 어머니 선물을 사러 갈 것이다."],"answer":1,"explain":"🎧 남자: 지난번에 사 드린 블라우스는 잘 안 입으시던데. 옷보다 상품권을 드리는 건 어때?<br>여자: 엄마가 직접 고르시는 게 제일 좋은데…….<br>남자: 그럼 다음 주말에 모시고 가자.<br><br>✅ <b>① Мужчина уже покупал матери блузку.</b> — «지난번에 사 드린 블라우스».<br>✖️ ② сегодня в универмаг не ходили (пойдут «다음 주말»), ③ подарочный сертификат хочет мужчина, а женщина — нет, ④ сегодня за подарком не идут."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["첫 번째 일정은 도서관 방문이다.","마지막으로 갈 곳은 체육관이다.","식사 후에 기념품을 받을 수 있다.","기숙사를 둘러본 후 동영상을 본다."],"answer":3,"explain":"🎧 여자: 먼저 강당에서 … 동영상을 보신 후에 도서관과 체육관 그리고 기숙사 순으로 … 학생 식당에서 식사를 하시면 일정이 모두 끝납니다. 돌아가실 때에는 … 기념품을 꼭 받아 가시기 바랍니다.<br><br>✅ <b>③ После еды можно получить сувенир.</b> — еда последняя, сувениры дают на выходе.<br>✖️ ① первый пункт — видео в зале, не библиотека, ② последнее — столовая (식사), а не спортзал, ④ видео смотрят ДО осмотра, а не после общежития."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["다친 사람은 치료를 받고 귀가했다.","승용차 두 대가 충돌해 사고가 났다.","안개 때문에 사고가 난 것으로 보인다.","사고 운전자들에 대한 조사는 끝났다."],"answer":3,"explain":"🎧 남자: …경찰은 짙은 안개로 앞이 보이지 않아 사고가 난 것으로 보고 있습니다. 보다 정확한 사고 원인을 파악하기 위해 운전자들을 상대로 조사 중입니다.<br><br>✅ <b>③ Авария, видимо, произошла из-за тумана.</b><br>✖️ ① пострадавший лечится в больнице (не вернулся домой), ② столкнулись грузовик и легковушка (не две легковые), ④ расследование ещё идёт («조사 중»)."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자의 아들은 이 일을 하는 것에 반대했다.","여자는 30년 동안 문화재 알리는 일을 했다.","여자는 퇴직하기 전부터 이 일을 하고 있었다.","여자는 지역 문화 센터에서 매주 강의를 한다."],"answer":4,"explain":"🎧 여자: 30년 동안 교직에 있으면서 역사를 가르쳤습니다. … 지난달부터 일요일마다 문화센터에서 우리 지역 문화재를 소개하는 강의를 하고 있죠.<br><br>✅ <b>④ Женщина каждую неделю читает лекции в местном культурном центре.</b> — «일요일마다».<br>✖️ ① сын, наоборот, активно советовал (적극 권했습니다), ② 30 лет она преподавала историю (а не рассказывала о памятниках), ③ это занятие началось ПОСЛЕ выхода на пенсию (지난달부터)."},{"n":17,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["아이들은 다치면서 크기 마련이다.","놀이터 시설을 관리할 필요가 있다.","아이들은 놀이터에서 뛰어 놀아야 한다.","아이에게는 조심하라고 주의를 줘야 한다."],"answer":1,"explain":"🎧 남자: 놀다가 다친 건데 뭘 그래요. 그렇게 넘어지고 다쳐 봐야 다음에 안 넘어지려고 조심하죠. 그러면서 크는 거 아니겠어요?<br><br>Мужчина считает: дети взрослеют, набивая шишки.<br>✅ <b>① Дети неизбежно растут, получая ушибы.</b> (-기 마련이다 = «непременно так бывает»).<br>✖️ ② управлять площадкой, ③ детям надо бегать на площадке, ④ предупреждать об осторожности — это не его главная мысль."},{"n":18,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["대중교통을 자주 이용하도록 해야 한다.","대중교통을 이용할 때는 불편해도 참아야 한다.","대중교통 안에서는 다른 사람에게 피해를 주면 안 된다.","대중교통에서 물건을 잃어버리지 않도록 잘 챙겨야 한다."],"answer":3,"explain":"🎧 남자: 배낭 가방을 메고 다니는 사람들은 조심할 필요가 있어. 대중교통을 이용할 때는 가방을 돌려서 앞으로 안는다든지 … 두면 좋잖아.<br><br>Рюкзак за спиной мешает другим — в транспорте нельзя причинять неудобства окружающим.<br>✅ <b>③ В общественном транспорте нельзя доставлять неудобства другим.</b><br>✖️ ① чаще пользоваться транспортом, ② терпеть неудобства, ④ не терять вещи — мимо темы (речь о вреде окружающим)."},{"n":19,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["공중전화의 설치를 늘려야 한다.","휴대 전화 사용 시간을 줄여야 한다.","휴대 전화가 있으면 급할 때 사용할 수 있다.","공중전화는 급할 때 필요하므로 없애면 안 된다."],"answer":4,"explain":"🎧 남자: 급할 때 써야 하는데 없으면 안 되지. 휴대 전화가 없는 사람도 있을 텐데. … 빌려 쓸 수 없는 상황도 있을 수 있잖아.<br><br>Мужчина защищает таксофоны: в экстренном случае они нужны, убирать нельзя.<br>✅ <b>④ Таксофоны нужны в экстренных случаях, поэтому их нельзя убирать.</b><br>✖️ ① увеличивать число таксофонов (он лишь против их ликвидации), ② сократить время мобильного, ③ это довод женщины."},{"n":20,"points":2,"instr":"Прослушайте интервью и выберите главную мысль мужчины (переводчика).","options":["번역할 때는 한국의 정서를 반영해야 한다.","번역은 원작의 표현을 그대로 옮겨야 한다.","주인공의 성격에 중점을 두고 번역해야 한다.","번역가는 높은 수준의 어휘력을 갖춰야 한다."],"answer":1,"explain":"🎧 남자: 정확하게 옮기는 것 못지않게 번역한 느낌이 나지 않도록 하는 것을 중요하게 … 한국 정서에 맞게 표현하려고 많은 애를 썼습니다.<br><br>Переводчик стремился передать роман в духе корейского менталитета.<br>✅ <b>① При переводе надо отражать корейский менталитет (정서).</b><br>✖️ ② переносить выражения дословно — наоборот, чтобы «не пахло переводом», ③ упор на характер героя — лишь пример, ④ про богатый словарь — не сказано как главное."},{"n":21,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["매년 고객들의 반응을 살펴야 한다.","이벤트 행사 준비는 빠를수록 좋다.","반응이 좋은 행사는 반복하는 것이 좋다.","전과 다른 새로운 행사를 기획해야 한다."],"answer":4,"explain":"🎧 남자: 그 행사는 … 몇 년째 하고 있는 행사 아닙니까? 올해도 똑같이 하지 말고 새로운 행사를 기획해 보세요.<br><br>✅ <b>④ Нужно придумать новое мероприятие, отличное от прежних.</b><br>✖️ ① следить за реакцией клиентов, ② чем раньше готовить, тем лучше (это сказал о сроках), ③ повторять успешное — наоборот, он против повторения."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["여자는 새로운 행사를 기획했다.","작년 추석에 한 행사는 효과적이었다.","남자는 다음 주까지 보고를 해야 한다.","올해도 작년과 같은 행사를 할 것이다."],"answer":2,"explain":"🎧 여자: 작년에 고객들의 반응이 꽤 괜찮았거든요.<br><br>✅ <b>② Прошлогоднее чхусок-мероприятие было эффективным.</b> — «반응이 꽤 괜찮았거든요».<br>✖️ ① новое мероприятие она ещё не придумала (сделает к след. неделе), ③ отчитываться будет женщина, а не мужчина, ④ так же, как в прошлом году, делать не будут (велено придумать новое)."},{"n":23,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["회의 장소를 추천하고 있다.","회의장 시설을 점검하고 있다.","호텔 위치에 대해 알아보고 있다.","회의장을 빌리려고 문의하고 있다."],"answer":4,"explain":"🎧 남자: 거기 서울호텔이죠? 회의장 좀 예약하려고 하는데요. … 100명 정도 들어갈 수 있으면 되는데요. … 컴퓨터와 마이크가 설치되어 있지요?<br><br>Мужчина звонит, чтобы забронировать конференц-зал и уточнить условия.<br>✅ <b>④ Узнаёт об аренде конференц-зала.</b><br>✖️ ① рекомендует место — наоборот, спрашивает, ② проверяет оборудование (это делает сотрудник), ③ выясняет местоположение отеля — не об этом речь."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["회의장을 이용하면 음료가 할인된다.","대규모 회의장에만 컴퓨터가 설치되어 있다.","100명 이상이 들어갈 수 있는 회의장은 없다.","직접 방문하면 더 자세한 설명을 들을 수 있다."],"answer":4,"explain":"🎧 여자: 장소를 둘러보실 겸 직접 방문해 주시면 자세하게 상담해 드리겠습니다.<br><br>✅ <b>④ При личном визите можно получить более подробную консультацию.</b><br>✖️ ① напитки со скидкой — нет, они бесплатные (무료), ② компьютеры только в большом зале — «모든 회의장에 시설이 갖춰져», ③ залов на 100+ нет — есть до 150 человек."},{"n":25,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["자연 환경보다 사람의 안전이 우선이다.","자연과 사람이 어울려서 살아가야 한다.","안전을 우선하다 보면 환경이 훼손될 수도 있다.","사람이 자연을 즐길 수 있는 방법을 찾아야 한다."],"answer":1,"explain":"🎧 남자: … 등산객들의 사고 방지를 위해서는 사다리가 반드시 있어야 한다고 판단했어요. … 저희는 등산객의 안전을 최우선으로 생각했습니다.<br><br>Несмотря на экологические возражения, безопасность людей — приоритет.<br>✅ <b>① Безопасность людей важнее природной среды.</b><br>✖️ ② гармония природы и человека, ③ ради безопасности страдает среда (это довод против), ④ как людям наслаждаться природой — не главная мысль."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["사다리 설치 문제에 모두가 동의했다.","과거 인주산에서 안전사고가 발생했다.","경관을 위해 등산을 금지하자는 의견이 있었다.","앞으로 인주산을 찾는 등산객이 감소할 것이다."],"answer":2,"explain":"🎧 남자: 인주산 정상은 바위가 많고 경사가 심해서 미끄럼 사고가 자주 발생하는 곳입니다.<br><br>✅ <b>② Раньше на горе Инджу случались происшествия.</b> — «미끄럼 사고가 자주 발생».<br>✖️ ① все согласились — наоборот, были возражения экологов, ③ запрет восхождений ради вида — не предлагали, ④ туристов станет меньше — он ожидает БОЛЬШЕ («더욱 많은 등산객»)."},{"n":27,"points":2,"instr":"Прослушайте и выберите, с каким намерением мужчина говорит это женщине.","options":["정장 기증의 중요성을 알리기 위해","정장 기증 단체의 활동을 홍보하기 위해","정장 기증에 참여할 것을 권유하기 위해","정장 기증이 필요한 이유를 설명하기 위해"],"answer":3,"explain":"🎧 남자: 좋은 일이니까 너도 한번 해 보면 어때?<br><br>Мужчина рассказывает о пожертвовании костюмов и прямо предлагает женщине присоединиться.<br>✅ <b>③ Чтобы предложить поучаствовать в пожертвовании костюмов.</b> — «너도 한번 해 보면 어때?».<br>✖️ ① сообщить о важности, ② прорекламировать организацию, ④ объяснить, зачем это нужно — всё это лишь фон для главного: призыва присоединиться."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 정장을 기증해 본 적이 있다.","기증된 정장은 무료로 빌릴 수 있다.","정장을 기증하기 전에 세탁해야 한다.","여자는 정장이 없어서 빌리려고 한다."],"answer":1,"explain":"🎧 남자: 정장을 기증받는 단체가 있다고 해서 어제 한 벌 보냈어.<br><br>✅ <b>① Мужчина уже жертвовал костюм.</b> — «어제 한 벌 보냈어».<br>✖️ ② напрокат бесплатно — нет, дают «저렴하게 대여» (недорого), ③ стирать перед сдачей — стирку делает организация (수선과 세탁을 해서), ④ женщина хочет одолжить — наоборот, она думает пожертвовать."},{"n":29,"points":2,"instr":"Прослушайте и выберите, кто такой мужчина.","options":["축구 선수","축구 감독","축구 경기 심판","축구 경기 해설가"],"answer":3,"explain":"🎧 남자: 선수들의 움직임을 정확하게 보고 빨리 판단해야 … 반칙한 선수들에게는 그 자리에서 바로 벌칙을 줘야 경기가 원활하게 진행되니까요. … 중요한 순간에 결정을 잘못 내리면 양 팀의 승패가 바뀔 수도 있으니까요.<br><br>Бегает по полю, наказывает за фолы, его решения меняют исход — это судья (арбитр).<br>✅ <b>③ Судья футбольного матча.</b><br>✖️ ① игрок, ② тренер, ④ комментатор — никто из них не «даёт штрафы на месте».<br>🧩 반칙 = «фол»; 벌칙 = «наказание, штраф»."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 벌칙을 주지 않으려고 노력한다.","남자는 빠르고 정확한 판단을 해야 한다.","남자는 운동장을 뛰어다니는 것이 부담스럽다.","남자는 중요한 경기에서 뛸 때 보람을 느낀다."],"answer":2,"explain":"🎧 남자: 선수들의 움직임을 정확하게 보고 빨리 판단해야 하기 때문에 뛰어다닐 수밖에 없습니다.<br><br>✅ <b>② Мужчина должен принимать быстрые и точные решения.</b><br>✖️ ① старается не давать штрафы — наоборот, штрафует сразу, ③ бегать тяжело по нагрузке, но «부담» у него от важных матчей, а не от бега, ④ удовлетворение он чувствует, когда без ошибок ЗАВЕРШИЛ матч, а не «когда бежит»."},{"n":31,"points":2,"instr":"Прослушайте и выберите мысль мужчины.","options":["담뱃값 인상은 흡연율 감소에 도움이 된다.","금연은 흡연자들 스스로의 참여가 가장 중요하다.","흡연율 감소를 위해서 더 강력한 정책이 필요하다.","상담 센터보다 담뱃값 인상이 더 효과적인 정책이다."],"answer":2,"explain":"🎧 남자: 금연은 자발적인 참여가 있을 때만 가능하다고 봅니다. … 흡연자 스스로가 심각성을 깨닫고 금연을 해야 성공할 수 있습니다.<br><br>✅ <b>② Главное в отказе от курения — добровольное участие самих курильщиков.</b><br>✖️ ① повышение цен помогает — наоборот, «별로 영향을 주지 않는다», ③ нужна более жёсткая политика — это довод женщины, ④ повышение цен эффективнее центров — наоборот, он за центры."},{"n":32,"points":2,"instr":"Прослушайте и выберите, какова позиция (отношение) мужчины.","options":["연구 결과를 비판하고 있다.","금연 정책을 지지하고 있다.","흡연자들의 입장을 대변하고 있다.","상대방의 의견에 일부 동의하고 있다."],"answer":4,"explain":"🎧 여자: 담뱃값 인상은 별로 좋은 금연 정책이 아닌 것 같습니다.<br>남자: (동조하는 어투로) 네, 그렇습니다. … 하지만 강한 금연 정책은 오히려 부정적인 영향을 줄 수도 있습니다.<br><br>Мужчина сначала соглашается с женщиной («네, 그렇습니다»), но в части жёсткой политики расходится.<br>✅ <b>④ Частично соглашается с мнением собеседницы.</b><br>✖️ ① критикует исследование — наоборот, ссылается на него, ② поддерживает политику повышения цен — нет, ③ выступает от лица курильщиков — нет."},{"n":33,"points":2,"instr":"Прослушайте и выберите, о чём этот текст.","options":["올바른 수업 태도","교수법과 수업의 관계","적극적인 반응의 효과","교사와 학생의 대화 방식"],"answer":3,"explain":"🎧 여자: 듣는 사람의 태도가 얼마나 중요한지 보여 주는 실험 … 학생들이 경청하고, 미소·고개 끄덕임, 질문을 하자 … 교사의 수업 태도가 눈에 띄게 달라졌습니다.<br><br>Активная реакция слушателей (внимание, кивки, вопросы) изменила преподавателя — речь об эффекте активного отклика.<br>✅ <b>③ Эффект активной (положительной) реакции.</b><br>✖️ ① правильное поведение на уроке, ② связь методики и урока, ④ способ диалога — это смежные, но не тема всего отрывка."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["학생들은 교사에게 수업 방식에 대해 질문했다.","교사는 교수 방식을 바꾸기 위해 실험에 참가했다.","심리학자는 학생들에게 부정적인 행동을 지시했다.","학생들은 실험 후에 재미있는 수업을 듣게 되었다."],"answer":4,"explain":"🎧 여자: 교사의 수업 태도는 눈에 띄게 달라졌습니다. 다양한 교수 방법을 활용하여 재미있는 수업을 만들기 시작한 겁니다.<br><br>✅ <b>④ После эксперимента ученики стали получать интересные уроки.</b><br>✖️ ① спрашивали про методику урока — задавали вопросы по теме, а не о методике, ② учитель участвовал в эксперименте — ему НЕ сообщили (알리지 않고), ③ психолог велел НЕГАТИВНОЕ поведение — наоборот, позитивное (경청, 미소)."},{"n":35,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["연기의 가치를 평가하고 있다.","능력의 필요성을 역설하고 있다.","끊임없는 도전을 강조하고 있다.","기회의 중요성을 주장하고 있다."],"answer":3,"explain":"🎧 남자: 사회로 나가면 … 끊임없는 거절의 연속일 겁니다. … 수많은 거절에 좌절해서 도전을 포기했다면 저도 지금 이 자리에 없었을 겁니다. … 이제 용감하게 나가서 그 기회를 잡으십시오.<br><br>Напутствие выпускникам: не сдаваться, продолжать пробовать несмотря на отказы.<br>✅ <b>③ Подчёркивает важность непрерывных попыток (도전).</b><br>✖️ ① оценивает ценность актёрства, ② настаивает на необходимости таланта, ④ важность возможности — лишь финальный штрих, а суть — «не бросать перед отказами»."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["감독은 계속 도전하는 배우들을 찾는다.","자신의 개성에 맞는 배역을 기다려야 한다.","재학 중에는 다양한 오디션 과정을 거친다.","기회를 잡으려면 거절의 고통을 견뎌야 한다."],"answer":4,"explain":"🎧 남자: 거절 당하는 건 고통스럽겠죠. 하지만 … 여러분도 이러한 과정을 겪으면서 자신에게 맞는 배역을 찾을 수 있을 겁니다. 이제 … 기회를 잡으십시오.<br><br>✅ <b>④ Чтобы поймать возможность, надо вытерпеть боль отказов.</b><br>✖️ ① режиссёр ищет «постоянно пробующих» — он ищет актёра под СВОЁ произведение, ② просто ждать подходящей роли — наоборот, надо смело пробовать, ③ во время учёбы проходят прослушивания — речь о жизни ПОСЛЕ выпуска."},{"n":37,"points":2,"instr":"Прослушайте и выберите главную мысль женщины.","options":["식물화는 식물을 기록할 수 있는 적절한 방식이다.","식물세밀화는 식물학에서 큰 역할을 담당하고 있다.","식물학계는 식물의 형태를 식별하는 데 힘써야 한다.","식물의 아름다움을 보여주는 식물화가 많아져야 한다."],"answer":2,"explain":"🎧 여자: 식물세밀화는 감정을 배제한 채 식물의 형태를 있는 그대로 자세히 그려요. … 사진은 미세구조까지 표현하는 데 한계가 … 그래서 식물학계에서는 사진보다 식물세밀화를 중시합니다.<br><br>Ботаническая детальная иллюстрация фиксирует форму точнее фото — важна для ботаники.<br>✅ <b>② Ботаническая детальная иллюстрация играет большую роль в ботанике.</b><br>✖️ ① 식물화 (художественная) — подходящий способ записи (наоборот, у неё пределы), ③ ботаникам надо различать формы — не главная мысль, ④ нужно больше художественных рисунков — речь о научных."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["식물화와 식물세밀화는 그리는 목적이 다르다.","식물세밀화에는 작가의 주관적 감정이 들어 있다.","식물의 형태를 기록하기 위해서 사진을 이용한다.","식물학계에는 무수히 많은 식물세밀화가 존재한다."],"answer":1,"explain":"🎧 여자: 식물화는 화가가 감정을 넣어 … 아름다움을 표현 … 식물세밀화는 감정을 배제한 채 형태를 자세히 그려요.<br><br>✅ <b>① У художественного рисунка и детальной иллюстрации разные цели.</b> — одна про красоту, другая про точную форму.<br>✖️ ② в детальной иллюстрации есть субъективные чувства — наоборот, «감정을 배제», ③ для записи формы используют фото — у фото есть «한계», ④ детальных иллюстраций бесчисленно много — наоборот, «많지 않은 점은 아쉽습니다»."},{"n":39,"points":2,"instr":"Прослушайте и выберите, что было сказано ПЕРЕД этим диалогом.","options":["가슴을 편 자세는 업무 실적을 올린다.","가슴을 편 자세는 신체 건강에 도움이 된다.","가슴을 편 자세는 능동적인 행동을 유발한다.","가슴을 편 자세는 호르몬의 분비량을 변화시킨다."],"answer":2,"explain":"🎧 여자: 다리를 어깨 너비로 벌리고 가슴을 활짝 편 자세가 척추 건강에 많은 도움이 되고 있는 것 같은데요. … 이밖에 어떤 효과가 있습니까?<br><br>Фраза «이밖에 어떤 효과가?» (какие ещё эффекты?) опирается на уже сказанное: открытая поза полезна для здоровья тела.<br>✅ <b>② Поза с расправленной грудью полезна для здоровья тела.</b><br>✖️ ① повышает результаты работы, ③ вызывает активное поведение, ④ меняет выброс гормонов — это раскрывается ПОСЛЕ, в ответе мужчины."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["웅크린 자세는 위험에 맞서려는 자세이다.","가슴을 편 자세는 남성 호르몬과 관계가 없다.","웅크린 자세는 스트레스 호르몬의 분비량을 줄인다.","가슴을 편 자세는 면접시험에 긍정적 영향을 미친다."],"answer":4,"explain":"🎧 남자: 이런 자세가 업무의 성과를 높이거나 면접시험의 합격률에도 영향을 미치는 것으로 나타났습니다.<br><br>✅ <b>④ Поза с расправленной грудью положительно влияет на собеседование.</b><br>✖️ ① сжатая поза — для противостояния опасности (наоборот, открытая поза → готовность к риску), ② не связана с мужским гормоном — наоборот, повышает его, ③ сжатая поза снижает гормон стресса — это делает ОТКРЫТАЯ поза."},{"n":41,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["현재의 상황을 제대로 인식해야 한다.","심리적 고통에서 빨리 벗어나야 한다.","잘못된 결정을 반복하지 말아야 한다.","장래성이 있는 사업에 투자해야 한다."],"answer":1,"explain":"🎧 남자: …더 큰 손해를 피하려면 현실을 냉정히 직시하는 것이 무엇보다 중요합니다.<br><br>«Ошибка издержек Конкорда»: цепляясь за вложенное, теряют больше → надо трезво видеть текущую ситуацию.<br>✅ <b>① Нужно правильно осознавать текущую ситуацию.</b><br>✖️ ② быстрее уйти от душевной боли (это причина ошибки, а не вывод), ③ не повторять ошибочных решений, ④ вкладывать в перспективное — не главная мысль лекции."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["콩코드 사업은 투자한 원금을 되찾았다.","심리적 고통 때문에 잘못된 결정이 지속된다.","콩코드 비용은 개발을 시작할 때 드는 비용이다.","개발 비용을 정확히 파악하면 손해를 보지 않는다."],"answer":2,"explain":"🎧 남자: 기존의 잘못된 결정을 인정하는 데 심리적 고통이 따르기 때문 … 그래서 결정을 지연하다가 더 큰 손해를 보게 되는 겁니다.<br><br>✅ <b>② Из-за душевной боли ошибочное решение продолжается.</b><br>✖️ ① проект вернул вложенное — наоборот, «더 큰 손해», ③ «콩코드 비용» = стартовые затраты — это название ОШИБКИ (오류), а не определение затрат, ④ точный учёт затрат избавляет от убытка — в тексте этого нет."},{"n":43,"points":2,"instr":"Прослушайте и выберите главную мысль этого рассказа.","options":["신라 시대에는 다양한 계급이 존재했다.","신라 시대에는 다른 문화권과 교류가 있었다.","신라 시대에는 문화를 중시하는 사상이 있었다.","신라 시대에는 유리 제작 기술이 크게 발달하였다."],"answer":2,"explain":"🎧 남자: …1500년 전 이곳(동남아시아)의 구슬이 신라로 전해졌던 것이다. … 신라가 5300km나 떨어진 나라와 교역을 했다는 증거를 발견할 수 있었다.<br><br>Стеклянная бусина с «иностранным» лицом доказывает торговлю Силла с дальними странами.<br>✅ <b>② В эпоху Силла был обмен с другими культурами.</b><br>✖️ ① существовали разные сословия (лишь упомянуто 지배층), ③ почитали культуру, ④ технология стекла была развита — наоборот, «발달하지 않았는데»."},{"n":44,"points":2,"instr":"Прослушайте и выберите верное описание стеклянной бусины.","options":["이 유리구슬은 신라에서 만들어졌다.","이 유리구슬은 상위 계층이 사용했다.","이 유리구슬의 크기는 사람 얼굴만 하다.","이 유리구슬에 신라인의 모습이 새겨져 있다."],"answer":2,"explain":"🎧 남자: 이 유리구슬은 신라 시대의 지배층이 사용한 목걸이에 달려 있던 것이다. … 지름 1.8센티미터 … 신라인의 얼굴은 아니다. … 이국적이다.<br><br>✅ <b>② Бусину использовала высшая знать (지배층).</b><br>✖️ ① сделана в Силла — нет, привезена из Юго-Восточной Азии, ③ размером с лицо человека — диаметр всего 1.8 см, ④ вырезано лицо корейца Силла — наоборот, «이국적» (иностранное лицо)."},{"n":45,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["지진은 드물게 발생하는 자연재해이다.","대지진 이후에 인간은 무기력에 빠졌다.","지진에 대한 사람들의 인식은 바뀌지 않았다.","대지진 이전에는 과학적 조사를 하지 않았다."],"answer":4,"explain":"🎧 여자: 1755년 리스본 대지진은 과학적 연구가 이루어진 최초의 지진 … 그때 처음으로 지진 상황을 파악하기 위한 조사가 실시됐거든요.<br><br>✅ <b>④ До великого землетрясения научных исследований не проводили.</b> — оно стало «최초의 과학적 연구».<br>✖️ ① редкое явление — наоборот, «50만 번», ② люди впали в бессилие — наоборот, искали причины, ③ восприятие не изменилось — наоборот, изменилось."},{"n":46,"points":2,"instr":"Прослушайте и выберите, каким способом говорит женщина.","options":["지진 발생의 원인을 규명하고 있다.","지진학의 연구 성과를 분석하고 있다.","지진학의 유래에 대해 소개하고 있다.","지진 발생 과정을 단계별로 설명하고 있다."],"answer":3,"explain":"🎧 여자: …그런 노력이 지진학의 탄생을 가져왔고 현재 우리는 지진을 적극적으로 대비할 수 있게 된 것입니다.<br><br>Женщина рассказывает, КАК зародилась сейсмология (от лиссабонского землетрясения до рождения науки).<br>✅ <b>③ Знакомит с происхождением сейсмологии (유래).</b><br>✖️ ① выясняет причины землетрясений, ② анализирует достижения науки, ④ поэтапно описывает процесс землетрясения — она же излагает историю возникновения науки."},{"n":47,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 도시는 사회 기반 시설이 부족하다.","이 도시는 국제 행사를 개최한 경험이 없다.","이 도시는 국제 박람회 개최를 희망하고 있다.","이 도시의 박람회 개최 목적은 도시 홍보에 있다."],"answer":3,"explain":"🎧 여자: 이번 국제 박람회까지 개최하게 된다면 우리 시는 세계적인 도시로 우뚝 설 수 있을 텐데요. 어떻게 하면 … 선정될 수 있을까요?<br><br>✅ <b>③ Город хочет провести международную выставку.</b><br>✖️ ① не хватает инфраструктуры — наоборот, «풍부한 도시 기반 시설을 갖출 수 있었죠», ② нет опыта международных событий — наоборот, «성공적으로 치렀던», ④ цель выставки — реклама города: так было раньше, а мужчина предлагает изменить цель."},{"n":48,"points":2,"instr":"Прослушайте и выберите, каким способом говорит мужчина.","options":["사업의 추진 방향을 제시하고 있다.","사업 내용의 검토를 요구하고 있다.","사업 추진 방식에 반론을 제기하고 있다.","사업 실행 방법의 타당성을 증명하고 있다."],"answer":1,"explain":"🎧 남자: 박람회를 유치하기 위해서는 기존과 다른 목적을 설정해야 … 박람회가 소통과 축제의 장이 되도록 해야 합니다. … 먼저 모두가 공감하고 참여할 수 있는 방안을 모색해야겠지요.<br><br>Мужчина предлагает, в каком НАПРАВЛЕНИИ вести проект (новая цель — праздник и общение).<br>✅ <b>① Предлагает направление продвижения проекта.</b><br>✖️ ② требует пересмотра содержания, ③ выдвигает возражение, ④ доказывает обоснованность метода — он именно ПРЕДЛАГАЕТ курс."},{"n":49,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["최근 선거 운동은 개인의 성향을 반영한다.","같은 지역 사람들의 정치 성향은 비슷하다.","후보자를 평가할 수 있는 기회가 늘어나고 있다.","유권자는 후보자의 정보를 다각적으로 얻을 수 있다."],"answer":1,"explain":"🎧 여자: 최근에는 개인별 특성을 반영하는 방향으로 선거 운동이 변화하고 있습니다. … 유권자의 성별이나 직업, 관심사 등을 고려하여 그에 맞는 메일을 보내지요.<br><br>✅ <b>① Современная предвыборная кампания учитывает индивидуальные склонности.</b><br>✖️ ② у земляков схожие взгляды — это устаревшее представление («과거에는»), ③ возможностей оценить кандидата больше — наоборот, их «박탈», ④ избиратель получает информацию разносторонне — наоборот, «한쪽으로 치우친 정보»."},{"n":50,"points":2,"instr":"Прослушайте и выберите, какова позиция (отношение) женщины.","options":["이번 선거 운동의 결과를 낙관하고 있다.","선거 운동의 긍정적 변화를 기대하고 있다.","선거를 대하는 유권자의 태도에 실망하고 있다.","새로운 선거 전략의 부작용에 대해 우려하고 있다."],"answer":4,"explain":"🎧 여자: …유권자는 한쪽으로 치우친 정보에 노출될 가능성이 커집니다. … 후보자를 객관적으로 평가할 수 있는 기회 자체를 박탈당할 수밖에 없지요. … 과연 유권자는 올바른 선택을 할 수 있을까요?<br><br>Адресная рассылка лишает избирателя объективности — женщина встревожена побочным эффектом.<br>✅ <b>④ Обеспокоена побочными эффектами новой предвыборной стратегии.</b><br>✖️ ① оптимистична насчёт результата, ② ждёт позитивных перемен, ③ разочарована в избирателях — тон именно тревожный, риторический вопрос в конце."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제41회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"형은 차가워 (        ) 마음은 따뜻하다.","options":["보여도","보여야","보이다가","보이든지"],"answer":1,"explain":"«Брат хоть и кажется холодным, но сердцем тёплый».<br>✅ <b>① 보여도</b> — уступка «-아/어도» = «даже если/хотя».<br>✖️ ② 보여야 — «только если кажется» (условие), ③ 보이다가 — «казался, а потом…», ④ 보이든지 — «кажется или…».<br>🧩 -아/어도 связывает противопоставление «차갑다 ↔ 따뜻하다»."},{"n":2,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"집에 (        ) 비가 내리기 시작했다.","options":["도착하거나","도착하니까","도착하거든","도착하려고"],"answer":2,"explain":"«Как только я добрался домой, пошёл дождь».<br>✅ <b>② 도착하니까</b> — «-(으)니까» здесь = «когда сделал, и (обнаружилось/произошло)».<br>✖️ ① 도착하거나 — «или добраться», ③ 도착하거든 — «если/когда доберёшься» (повод к будущему), ④ 도착하려고 — «чтобы добраться».<br>🧩 -(으)니까 + неожиданный факт в прошлом = «и тут…»."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"아기가 자고 있어서 깨지 <u>않게</u> 조용히 방 안으로 들어갔다.","options":["않는지","않도록","않더니","않느라"],"answer":2,"explain":"«Чтобы не разбудить спящего малыша, тихо вошёл в комнату».<br>✅ <b>② 않도록</b> — «-게» (чтобы/так, чтобы) ≈ «-도록».<br>✖️ ① 않는지 — «не …ли» (вопрос), ③ 않더니 — «не …, и потом», ④ 않느라 — «из-за того что не…».<br>🧩 -게 / -도록 — обе передают цель «чтобы (не)…»."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"한국어 실력을 <u>늘리고자</u> 한국 신문과 방송을 자주 봤다.","options":["늘리기 위해서","늘리기 무섭게","늘리는 대신에","늘리는 반면에"],"answer":1,"explain":"«Чтобы улучшить корейский, часто смотрел газеты и передачи».<br>✅ <b>① 늘리기 위해서</b> — «-고자» (с намерением) ≈ «-기 위해서» (чтобы).<br>✖️ ② 늘리기 무섭게 — «едва …, как…», ③ 늘리는 대신에 — «вместо того чтобы», ④ 늘리는 반면에 — «тогда как, с другой стороны».<br>🧩 -고자 — книжный способ выразить цель."},{"n":5,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"🌬️ 시원한 바람을 만나다\n맑고 깨끗한 자연 느낌 그대로!","options":["청소기","선풍기","세탁기","전화기"],"answer":2,"explain":"«Встречайте прохладный ветер! Чистое, свежее ощущение природы!»<br>✅ <b>② 선풍기</b> (вентилятор) — «시원한 바람» (прохладный ветер).<br>✖️ ① 청소기 (пылесос), ③ 세탁기 (стиралка), ④ 전화기 (телефон) — не «дарят ветер».<br>🧩 바람 = «ветер»; 그대로 = «как есть, без изменений»."},{"n":6,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"💰 안정된 내일을 위하여!\n고객님의 지금을 소중히 생각하겠습니다.","options":["병원","은행","가게","학원"],"answer":2,"explain":"«Ради стабильного завтра! Мы ценим ваше «сегодня».»<br>✅ <b>② 은행</b> (банк) — «안정된 내일», «고객님» (клиент) о финансовом будущем.<br>✖️ ① 병원 (больница), ③ 가게 (магазин), ④ 학원 (курсы) — не про сбережения/стабильность.<br>🧩 안정된 = «стабильный»; 소중히 = «бережно»."},{"n":7,"points":2,"instr":"Выберите, о чём этот текст (призыв).","passage":"🏫 「엄마, 잘 다녀왔습니다.」 참 반가운 한마디!\n우리 아이 학교 다니는 길을 지켜 주세요.","options":["교통 안전","전기 절약","예절 교육","환경 보호"],"answer":1,"explain":"«„Мама, я благополучно вернулся!“ — какая отрадная фраза! Берегите дорогу, по которой наши дети ходят в школу».<br>✅ <b>① 교통 안전</b> (безопасность движения) — призыв беречь дорогу детей.<br>✖️ ② экономия электричества, ③ обучение этикету, ④ защита природы — мимо.<br>🧩 지키다 = «беречь, охранять»."},{"n":8,"points":2,"instr":"Выберите, о чём этот текст (объявление).","passage":"🚗 세계로! 미래로!\n대한자동차와 함께 세상에 나갈 여러분을 기다립니다.","options":["사원 모집","여행 소개","제품 설명","판매 안내"],"answer":1,"explain":"«В мир! В будущее! Daehan Motors ждёт тех, кто выйдет в мир вместе с нами».<br>✅ <b>① 사원 모집</b> (набор сотрудников) — компания «ждёт вас», зовёт работать.<br>✖️ ② рассказ о путешествии, ③ описание товара, ④ информация о продаже.<br>🧩 모집 = «набор, приём»; 함께 나가다 = «выходить вместе»."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"📋 2015 청소년 과학 동아리 지원 사업\n· 신청 대상: 중·고등학생 5명 이상의 동아리 ※ 교사 1명이 포함되어야 함\n· 지원 금액: 최대 200만 원\n· 사업 기간: 2015년 7월 1일 ~ 12월 31일","options":["동아리 지원은 일 년 동안 계속된다.","동아리는 고등학생들로만 구성되어야 한다.","동아리 활동비는 이백만 원까지 받을 수 있다.","동아리 인원이 두세 명인 경우에도 신청할 수 있다."],"answer":3,"explain":"✅ <b>③ Средства на деятельность кружка можно получить до 2 миллионов вон.</b> — «최대 200만 원».<br>✖️ ① поддержка длится год — нет, июль–декабрь (полгода), ② только старшеклассники — «중·고등학생» (и средняя, и старшая школа), ④ можно подать кружком из 2–3 человек — нужно «5명 이상».<br>🧩 이상 = «и больше»; 최대 = «максимум»."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с данными графика.","passage":"📊 «면세점에서 많이 팔리는 상품» (2013년 vs 2014년).\n화장품 — самый высокий столбец в оба года; затем 의류, 식품, 가방류 заметно ниже.","options":["식료품 구입이 2013년보다 늘었다.","가방류 판매가 2013년에 비해 줄었다.","두 해 모두 화장품이 가장 많이 판매되었다.","2014년에는 의류가 먹을 것보다 많이 팔렸다."],"answer":3,"explain":"✅ <b>③ В оба года больше всего продавалась косметика.</b> — 화장품 — самый высокий столбец и в 2013, и в 2014.<br>✖️ ① продажи продуктов выросли, ② продажи сумок упали, ④ в 2014 одежды продали больше еды — все эти сравнения график не подтверждает (косметика доминирует).<br>🧩 면세점 = «дьюти-фри»; 판매되다 = «продаваться»."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 초록 콩나물을 찾는 주부들이 늘고 있다. 노란 콩나물은 보통 검은색 천으로 덮어 어두운 곳에서 기른다. 그러나 초록 콩나물은 천으로 가리지 않고 밝은 곳에서 자라게 한다. 햇빛을 받아 초록색으로 변한 콩나물은 노란 콩나물보다 영양가가 높다. 특히 초록 콩나물은 노란 콩나물보다 비타민이 많이 들어 있어서 피로 회복에 좋다.","options":["노란 콩나물은 햇빛을 받고 자란다.","초록 콩나물은 검은색 천을 덮어서 키운다.","노란 콩나물은 초록 콩나물보다 피로 회복에 좋다.","초록 콩나물은 노란 콩나물에 비해 영양가가 많다."],"answer":4,"explain":"✅ <b>④ Зелёная соевая проростка питательнее жёлтой.</b> — «초록색으로 변한 콩나물은 … 영양가가 높다».<br>✖️ ① жёлтая растёт на солнце — наоборот, в темноте под чёрной тканью, ② зелёную накрывают чёрной тканью — наоборот, выращивают на свету, ③ жёлтая лучше для снятия усталости — наоборот, зелёная (больше витаминов).<br>🧩 영양가 = «питательность»; 피로 회복 = «восстановление от усталости»."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"손을 움직이는 것은 뇌와 관련이 있다. 그래서 손을 자주 움직이면 뇌 기능이 좋아질 수 있다. 특히 자주 사용하지 않는 손을 움직일 때 뇌가 더 효과적으로 자극될 수 있다. … 문을 열고 닫는 일처럼 간단한 일을 그렇게 하는 것만으로도 뇌 기능을 유지하는 데 도움이 된다.","options":["뇌 건강과 손을 움직이는 것은 서로 관계가 없다.","우리 몸과 달리 뇌는 간단한 일로 자극받지 않는다.","뇌 활동을 위해 익숙한 방법으로 손을 쓰는 것이 더 좋다.","자주 사용하지 않던 손을 사용하면 뇌 움직임이 활발해진다."],"answer":4,"explain":"✅ <b>④ Если двигать «непривычной» рукой, активность мозга повышается.</b> — «자주 사용하지 않는 손을 움직일 때 뇌가 더 효과적으로 자극».<br>✖️ ① мозг и движение рук не связаны — наоборот, связаны, ② мозг не стимулируется простыми делами — наоборот, даже открывание двери помогает, ③ лучше пользоваться привычным способом — наоборот, непривычной рукой.<br>🧩 자극되다 = «стимулироваться»."},{"n":13,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 이것으로 만든 차는 여름철에 마시면 특히 좋다.\n(나) 오미자는 다섯 가지 맛이 난다고 붙여진 이름이다.\n(다) 땀이 나지 않게 하고 배탈을 낫게 하는 효과가 있어서이다.\n(라) 또한 무더위에 지친 사람에게 입맛이 나게 하는 데도 도움이 된다.","options":["(가)-(라)-(다)-(나)","(가)-(다)-(라)-(나)","(나)-(가)-(다)-(라)","(나)-(다)-(가)-(라)"],"answer":3,"explain":"✅ <b>③ (나)-(가)-(다)-(라)</b>: что такое омиджа (название от пяти вкусов) → чай из неё хорош летом → потому что не даёт потеть и лечит живот («있어서이다» объясняет предыдущее) → «또한» вдобавок улучшает аппетит.<br>🧩 «있어서이다» в (다) — причинная отсылка к (가), поэтому идёт сразу после неё."},{"n":14,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 이런 행복을 느낄 때도 있지만 가끔 힘들고 어려울 때도 있다.\n(나) 하지만 나는 그들을 가르칠 때마다 내가 국가대표라고 생각한다.\n(다) 한국어로 다른 문화권의 학생들과 교류하는 것은 참 행복한 일이다.\n(라) 나는 그들을 통해 세상을 보고 그들은 나를 통해 한국을 보기 때문이다.","options":["(다)-(가)-(나)-(라)","(다)-(나)-(가)-(라)","(라)-(가)-(다)-(나)","(라)-(다)-(가)-(나)"],"answer":1,"explain":"✅ <b>① (다)-(가)-(나)-(라)</b>: обучать студентов разных культур — счастье → «이런 행복» бывает, но порой и трудно → «하지만» я чувствую себя «национальной сборной» → потому что я вижу мир через них, а они Корею через меня.<br>🧩 «이런 행복» в (가) подхватывает «행복한 일» из (다); «때문이다» в (라) — вывод-причина в конце."},{"n":15,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 정부에 건의할 내용이 있을 때 이곳을 활용할 수 있다.\n(나) 오늘날에는 「인터넷 신문고」가 이러한 역할을 하고 있다.\n(다) 과거에는 「신문고」라는 북을 설치해서 국민의 생각을 들었다.\n(라) 이렇게 시대는 달라져도 국가가 국민의 생각을 들으려는 노력은 계속된다.","options":["(나)-(다)-(가)-(라)","(나)-(라)-(다)-(가)","(다)-(나)-(가)-(라)","(다)-(라)-(나)-(가)"],"answer":3,"explain":"✅ <b>③ (다)-(나)-(가)-(라)</b>: в прошлом был барабан «синмунго» → сегодня его роль играет «интернет-синмунго» → им можно пользоваться для обращений к правительству → «이렇게» как ни меняется эпоха, государство продолжает слушать народ.<br>🧩 (다) задаёт прошлое, (나) — настоящее, (라) с «이렇게» обобщает в конце."},{"n":16,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"막대에 학생들의 이름을 써서 통에 꽂아 놓고 하나씩 뽑아서 발표를 시키는 수업 방식이 있다. 이것은 (        ) 방식이다. 적극적인 학생들이 먼저 손을 들고 질문에 대답하면 소극적인 학생들이 대답할 기회를 놓치게 된다. 이 방식은 모든 학습자들에게 골고루 수업에 참여할 수 있게 한다는 긍정적인 면이 있다.","options":["학생들의 이름을 빨리 기억하기 위한","수업의 단계를 동일하게 맞추기 위한","수업의 진행을 좀 더 부드럽게 하기 위한","적극성이 떨어지는 학생에게도 기회를 주기 위한"],"answer":4,"explain":"Палочки с именами вытягивают наугад — чтобы и пассивные ученики не упустили шанс ответить.<br>✅ <b>④ Чтобы дать шанс и менее активным ученикам.</b><br>✖️ ① быстро запомнить имена, ② выровнять этапы урока, ③ сделать урок плавнее — не объясняют проблему «소극적인 학생들이 기회를 놓치게 된다».<br>🧩 골고루 = «равномерно, всем поровну»."},{"n":17,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"…「디지털 원어민」… 유행에 뒤떨어지는 것을 두려워한다. 그래서 (        ) 못할 경우에 불안해하기도 한다.","options":["부모의 관심을 받지","학업 성적이 오르지","모르는 사람의 정보를 얻지","새로 출시된 신제품을 사지"],"answer":4,"explain":"«Цифровые аборигены» боятся отстать от моды → тревожатся, если не могут ( ).<br>✅ <b>④ 새로 출시된 신제품을 사지</b> (купить новинку) — прямое следствие страха «отстать от моды».<br>✖️ ① получить внимание родителей, ② повысить оценки, ③ получить информацию у незнакомца — не связаны с «유행에 뒤떨어지는 것».<br>🧩 출시되다 = «выходить в продажу»."},{"n":18,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"…한의학에서는 기가 잘 흐르는 사람을 건강한 사람으로 생각한다. … 기가 막혀 병에 걸린 사람들을 한의학에서는 바늘처럼 생긴 침을 이용하여 치료한다. 침은 기가 막힌 곳을 자극해 (        ) 한다.","options":["기의 흐름을 원활하게","기의 방향을 확인하게","환자의 질병을 예방하게","환자의 통증을 진단하게"],"answer":1,"explain":"Иглоукалывание стимулирует место, где «기» застоялась, → восстанавливает её свободное течение.<br>✅ <b>① 기의 흐름을 원활하게</b> (сделать течение «ки» плавным).<br>✖️ ② проверить направление «ки», ③ предотвратить болезнь, ④ диагностировать боль — иглы именно лечат застой, восстанавливая поток.<br>🧩 원활하게 = «плавно, гладко»."},{"n":19,"points":2,"instr":"Выберите подходящее слово для пропуска ( ).","passage":"활쏘기는 쉬워 보이지만 판단력과 인내심이 필요한 운동이다. 활쏘기에서는 활을 쏘는 순간이 제일 중요하다. (        ) 언제 활을 쏘아야 할지 판단하는 것이 핵심이다. …","options":["특히","또는","역시","과연"],"answer":1,"explain":"«Момент выстрела важнее всего. ( ) определить, КОГДА стрелять, — это ключевое». Нужна частица усиления-выделения.<br>✅ <b>① 특히</b> (особенно).<br>✖️ ② 또는 (или), ③ 역시 (тоже, как и ожидалось), ④ 과연 (действительно ли / в самом деле) — не дают усиления «именно это ключевое».<br>🧩 특히 = «в особенности»."},{"n":20,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"활쏘기는 쉬워 보이지만 판단력과 인내심이 필요한 운동이다. … 활을 쏘는 그 순간까지 숨을 멈추고 기다리는 인내심이 요구된다. 그렇기 때문에 판단력이 부족한 사람이나 인내심이 필요한 사람에게 매우 좋은 운동이라고 할 수 있다.","options":["활쏘기로 판단력을 높일 수 있다.","활쏘기의 핵심은 숨을 참는 것이다.","활쏘기로 참을성을 기르기가 어렵다.","활쏘기는 단순한 운동이라 주목을 받았다."],"answer":1,"explain":"✅ <b>① Стрельбой из лука можно развить рассудительность.</b> — «판단력이 부족한 사람 … 에게 매우 좋은 운동».<br>✖️ ② суть — задержка дыхания (это лишь часть, а ключ — выбор момента), ③ терпение развить трудно — наоборот, лук этому учит, ④ простой вид спорта — текст говорит, что «쉬워 보이지만» на деле непрост.<br>🧩 인내심 = «терпение, выдержка»."},{"n":21,"points":2,"instr":"Выберите подходящую пословицу для пропуска ( ).","passage":"최근 한 할아버지가 거리를 청소하면서 모은 돈 100여 만 원을 장학금으로 내놓았다. (        )이라고 지난 5년 동안 바닥에 버려진 10원짜리 동전을 하나하나씩 주워 모은 것이다. …","options":["제 눈의 안경","엎질러진 물","싼 게 비지떡","티끌 모아 태산"],"answer":4,"explain":"Дедушка пять лет собирал по 10 вон — и накопил больше миллиона.<br>✅ <b>④ 티끌 모아 태산</b> — «пылинка к пылинке — и вырастет гора» (с миру по нитке).<br>✖️ ① 제 눈의 안경 — «на вкус и цвет», ② 엎질러진 물 — «пролитую воду не соберёшь», ③ 싼 게 비지떡 — «дёшево да гнило».<br>🧩 티끌 = «пылинка»; 태산 = «огромная гора»."},{"n":22,"points":2,"instr":"Выберите главную мысль текста.","passage":"…사람들은 큰돈이 있어야만 다른 사람을 도와 줄 수 있다고 생각한다. 하지만 참된 기부란 돈의 액수가 중요한 것이 아니라 다른 사람을 향한 사랑의 마음이다.","options":["생활 속에서 동전의 활용성을 높여야 한다.","다른 사람을 도와주려면 큰돈을 모아야 한다.","참된 기부는 자신보다 남을 먼저 생각해야 한다.","큰돈을 모으려면 아끼고 절약하는 습관을 길러야 한다."],"answer":3,"explain":"✅ <b>③ Истинное пожертвование — это думать о других прежде себя.</b> — «참된 기부란 … 다른 사람을 향한 사랑의 마음».<br>✖️ ① повышать пользу монет, ② нужны большие деньги, чтобы помочь — наоборот, «돈의 액수가 중요한 것이 아니라», ④ копить деньги бережливостью — не главная мысль.<br>🧩 참된 = «истинный, настоящий»; 액수 = «сумма»."},{"n":23,"points":2,"instr":"Выберите чувство героя («나») в подчёркнутой части.","passage":"…할머니는 청소며 빨래며 … 온갖 집안일들을 찾아서 하기 시작했다. <u>그냥 쉬다가 내려가시라고 아무리 말해도 들은 척도 하지 않았다.</u> … 친구를 따라 시장에 갔다가 넘어지시고 말았다. … 할머니는 같은 병실 사람들을 모아 놓고 환하게 웃으며 이야기하고 있었다. … 난 할 말을 잃었다.","options":["답답하다","후련하다","민망하다","번거롭다"],"answer":1,"explain":"Как ни уговаривает внук бабушку отдыхать — она и слушать не хочет, берётся за все дела, потом ещё и падает — а внук бессилен что-то изменить.<br>✅ <b>① 답답하다</b> (тяжело на душе от бессилия, «как об стенку»).<br>✖️ ② 후련하다 (с облегчением), ③ 민망하다 (неловко), ④ 번거롭다 (хлопотно) — не передают это «достучаться не могу».<br>🧩 들은 척도 하지 않다 = «даже виду не подать, что слышал»."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"…할머니는 날마다 전화를 하더니 급기야 서울로 올라오시고 말았다. … 그냥 쉬다가 내려가시라고 아무리 말해도 들은 척도 하지 않았다. … 낯선 동네에서 친구까지 사귄 할머니는 친구를 따라 시장에 갔다가 넘어지시고 말았다.","options":["할머니께서는 내 말에 자주 귀를 기울이셨다.","할머니께서는 시장에 갔다가 다리를 다치셨다.","할머니께서는 나에게 온갖 집안일을 시키셨다.","할머니께서는 친구를 만나려고 서울에 올라오셨다."],"answer":2,"explain":"✅ <b>② Бабушка упала, сходив на рынок (повредила ногу).</b> — «시장에 갔다가 넘어지시고 … 다리에 붕대를 감고서».<br>✖️ ① часто прислушивалась к моим словам — наоборот, «들은 척도 하지 않았다», ③ заставляла меня делать всю работу по дому — она делала её сама, ④ приехала в Сеул, чтобы встретить друга — приехала из любви к внуку (손자 사랑).<br>🧩 넘어지다 = «упасть»."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 낮에는 화창, 밤부터 곳에 따라 빗방울 「뚝뚝」","options":["낮에는 흐리고 밤부터 전국에 비가 내리겠다.","낮에는 맑겠으나 밤부터 전국에 비가 내리겠다.","낮에는 맑겠으나 밤부터 일부 지역에는 비가 오겠다.","낮에는 흐리고 밤부터 일부 지역에는 비가 쏟아지겠다."],"answer":3,"explain":"«Днём ясно, с ночи местами закапает дождь».<br>✅ <b>③ Днём прояснится, а с ночи в НЕКОТОРЫХ районах пойдёт дождь.</b> — «곳에 따라» = «местами».<br>✖️ ① и ④ днём пасмурно — нет, «화창» (ясно), ② по всей стране — нет, «곳에 따라» (местами), и «빗방울 뚝뚝» ≠ «쏟아지다» (ливень).<br>🧩 화창 = «ясно, погоже»; 곳에 따라 = «местами»."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 불황에도 포도주 소비 「껑충」, 불붙은 판매 경쟁","options":["불황에도 업체 간 경쟁 때문에 포도주의 소비가 늘었다.","불황에도 포도주 판매 감소 때문에 포도주의 소비가 줄었다.","불황에도 과도한 판매 경쟁 때문에 포도주의 공급이 증가했다.","불황에도 포도주 소비 증가 때문에 포도주의 판매 경쟁이 심해졌다."],"answer":4,"explain":"«Несмотря на кризис, потребление вина „скакнуло“, разгорелась борьба за продажи».<br>✅ <b>④ Из-за роста потребления вина обострилась конкуренция за продажи.</b> (потребление↑ → конкуренция↑).<br>✖️ ① конкуренция → потребление (перепутана причина и следствие), ② потребление снизилось — наоборот, «껑충», ③ про рост предложения — заголовок про спрос и конкуренцию.<br>🧩 껑충 = «скачок (вверх)»; 불붙다 = «разгораться»."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 마을 어르신들이 「지킴이」 역할 톡톡히, 주민 얼굴에 웃음 가득","options":["노인들은 마을 주민들의 도움에 만족해하고 있다.","노인들은 마을 주민들의 도움으로 즐겁게 일하고 있다.","주민들은 안전을 위해 애쓰는 마을 노인들 덕에 기분이 좋다.","주민들은 일을 잘하려고 노력하는 노인들에게 감사해하고 있다."],"answer":3,"explain":"«Старейшины села исправно играют роль „хранителей“ — у жителей лица в улыбках».<br>✅ <b>③ Жители рады благодаря старикам села, что стараются ради безопасности.</b> — «지킴이 역할» + «웃음 가득».<br>✖️ ① и ② про то, что старикам помогают жители — наоборот, старики помогают, ④ про благодарность за хорошую работу — акцент на «безопасности» и радости жителей.<br>🧩 지킴이 = «страж, хранитель»; 톡톡히 = «как следует, сполна»."},{"n":28,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"동화는 어린이가 읽는 책이라는 인식이 지배적이었다. 그러나 요즘은 동화를 통해 (        ) 어른들이 늘고 있다. 동화 속 이야기는 지난 기억과 소중한 것들을 다시 일깨워 어른들을 동심의 세계로 인도한다. …","options":["아이들을 교육하려는","어린 시절을 되돌아보려는","가족 사랑을 확인해 보려는","아이를 위한 글을 써 보려는"],"answer":2,"explain":"Сказки пробуждают прежние воспоминания и ведут взрослых в мир детского сердца → взрослые читают, чтобы оглянуться на детство.<br>✅ <b>② 어린 시절을 되돌아보려는</b> (чтобы оглянуться на детство).<br>✖️ ① чтобы учить детей, ③ чтобы проверить семейную любовь, ④ чтобы писать для детей — не вяжется с «지난 기억 … 동심의 세계».<br>🧩 동심 = «детское сердце/наивность»; 되돌아보다 = «оглядываться назад»."},{"n":29,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"…화가들에게 (        )은 「독」이라기보다 「약」이었다. 손이 떨려 그릴 수 없었던 한 화가는 종이를 잘라 물감을 칠해 붙이는 방법으로 새로운 작품 세계를 열었다. 또 가난해서 그림 재료를 살 수 없었던 어떤 화가는 담배 포장지에 스케치를 했다. …","options":["재료의 부족과 호기심","경제적 빈곤과 예술성","신체적 장애와 열악한 환경","예술적 한계와 정신적 고통"],"answer":3,"explain":"Примеры: дрожащие руки (физический недуг) и бедность (плохие условия) стали не «ядом», а «лекарством».<br>✅ <b>③ 신체적 장애와 열악한 환경</b> (физический недостаток и тяжёлые условия).<br>✖️ ① нехватка материалов и любопытство, ② бедность и художественность, ④ художественный предел и душевная боль — не охватывают оба примера (дрожь рук + бедность).<br>🧩 「독」/「약」 = «яд» / «лекарство» (метафора)."},{"n":30,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"지우개는 다른 문구류와 오래 닿으면 그것에 달라붙는 성질이 있다. … 지우개의 재료인 고무에 약품을 넣으면 고무 분자들이 결합하게 된다. 그런데 고무에 넣은 약품은 플라스틱에 들어가면 (        ) 한다. 이 때문에 지우개와 플라스틱 문구류를 함께 두면 잘 붙는다.","options":["고무를 달라붙게","고무를 딱딱하게","문구류와 붙지 않게","문구류에 닿지 않게"],"answer":1,"explain":"Вещество из ластика, проникая в пластик, заставляет резину ПРИЛИПАТЬ — поэтому ластик липнет к пластиковым канцтоварам.<br>✅ <b>① 고무를 달라붙게</b> (заставляет резину прилипать).<br>✖️ ② делает резину твёрдой, ③ не даёт прилипать к канцтоварам, ④ не даёт касаться канцтоваров — противоречат «함께 두면 잘 붙는다».<br>🧩 달라붙다 = «прилипать, приклеиваться»."},{"n":31,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"힙합은 자아도취적인 형식으로 나타나기도 하고 집단적 형태를 취하기도 한다. 힙합은 함께 노래를 부르고 춤을 추는 사이에 개인의 아픔도 서로 격려하고 위로하는 (        ) 나타난다. … 그들에게 힙합은 자신의 존재 가치를 확인하게 해 주는 의식과도 같다.","options":["형식적 몸짓으로","집단적 의식으로","다양한 모습으로","발전적인 미래로"],"answer":2,"explain":"Вместе поют и танцуют, поддерживая друг друга; хип-хоп для них — как «의식» (ритуал) подтверждения ценности своего существования.<br>✅ <b>② 집단적 의식으로</b> (как коллективный ритуал).<br>✖️ ① как формальный жест, ③ в разных образах, ④ как развивающееся будущее — слабее связаны с «함께 … 격려하고 위로하는 … 의식».<br>🧩 의식 = «ритуал, обряд»; 집단적 = «коллективный»."},{"n":32,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"보자기는 물건을 싸는 실용적인 용도로 사용된다. 그중에서 쓰고 남은 천 조각으로 만든 것을 조각보라고 한다. 이 조각보를 만들 때는 쓰는 사람이 복을 받기를 바라는 마음으로 바느질을 한다. … 색도, 모양도, 크기도 서로 다른 조각들을 이어 만든 조각보에는 자유분방한 아름다움과 조화로움이 살아 있기 때문이다.","options":["조각보는 실용성보다 예술성이 강조되어 있다.","조각보는 큰 천을 여러 조각으로 잘라서 만들었다.","조각보는 색이 같고 모양이 다른 조각이 이어져 있다.","조각보에는 복을 기원하는 정성스러운 마음이 담겨 있다."],"answer":4,"explain":"✅ <b>④ В чогакпо вложено старательное пожелание счастья.</b> — «복을 받기를 바라는 마음으로 바느질».<br>✖️ ① художественность важнее практичности — текст не противопоставляет, ② из большого полотна нарезали куски — наоборот, из ОСТАТКОВ ткани (쓰고 남은 천 조각), ③ куски одного цвета — наоборот, «색도 … 서로 다른».<br>🧩 조각보 = «лоскутное покрывало»; 복 = «счастье, благополучие»."},{"n":33,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"조선 시대에는 역사를 기록하는 사관이 있었다. 왕의 주변에서 일어나는 모든 일을 기록하는 사관은 누구의 간섭도 받지 않았다. 심지어 왕이라도 자신과 관련된 기록조차 절대로 볼 수 없었다. 또한 사관은 기록에 자신의 이름을 남기지 않아 … 어떠한 책임도 지지 않았다. … 왕이 스스로 자신의 언행을 조심하게 하였고 … 왕이 권력을 마음대로 쓰지 못하게 하는 장치로서 기능을 하였다.","options":["역사를 기록하는 책에는 사관의 이름이 적혀 있었다.","왕은 필요할 때 사관의 기록 내용을 찾아볼 수 있었다.","사관의 기록 때문에 왕은 자신의 언행을 조심하게 되었다.","왕은 주변에서 일어나는 모든 일들을 사관에게 보고를 받았다."],"answer":3,"explain":"✅ <b>③ Из-за записей историографа король стал осторожнее в словах и поступках.</b> — «왕이 스스로 자신의 언행을 조심하게».<br>✖️ ① имя сагвана было в записях — наоборот, «이름을 남기지 않아», ② король мог посмотреть записи — наоборот, «절대로 볼 수 없었다», ④ король получал доклады обо всём — записи вёл сагван, не докладывал королю.<br>🧩 사관 = «историограф (хронист при дворе)»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"북극곰은 고지방 식사에 빨리 적응한 동물이다. 북극곰은 몸의 50%가 지방이며 … 사람이 이만큼의 지방을 가지고 있으면 심혈관 질환과 같은 성인병으로 목숨을 잃을 수도 있다. 그러나 북극곰은 피 속에 지방을 걸러 내는 유전자가 있어 지방으로 인한 부작용을 막아 주는 것으로 알려졌다. …","options":["북극곰은 심혈관 질환에 잘 걸리지 않는다.","북극곰은 지방이 적은 음식을 주로 섭취한다.","북극곰의 몸은 27%가 지방으로 이루어져 있다.","북극곰 연구로 인간의 성인병을 치료하고 있다."],"answer":1,"explain":"✅ <b>① Белый медведь редко страдает сердечно-сосудистыми болезнями.</b> — ген отфильтровывает жир и «부작용을 막아».<br>✖️ ② питается маложирной пищей — наоборот, «고지방 식사», ③ тело на 27% из жира — это про жир в МОЛОКЕ; тело на 50%, ④ уже лечат болезни человека — пока лишь «기대된다» (ожидается).<br>🧩 심혈관 질환 = «сердечно-сосудистые болезни»."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"…1980년대 초 이모티콘이 처음 생긴 이래 끊임없이 진화를 계속하고 있는 것이다. 언어 표현력을 퇴보시킨다는 일부의 비판에도 불구하고 이제 이모티콘은 없어서는 안 될 또 하나의 언어로 자리매김 되었다고 할 수 있다.","options":["초창기 이모티콘은 대부분 얼굴 표정을 나타내는 것이었다.","이모티콘은 감정을 표현하는 또 하나의 언어로 자리 잡았다.","이모티콘의 지속적인 사용은 언어 표현력을 떨어뜨릴 수 있다.","이제는 이모티콘이 없으면 메시지를 주고받기 어려울 정도이다."],"answer":2,"explain":"Тема — итог: эмодзи стали ещё одним полноценным языком для передачи чувств.<br>✅ <b>② Эмодзи закрепились как ещё один язык для выражения эмоций.</b><br>✖️ ① ранние эмодзи были мимикой — деталь, ③ ухудшают речь — это критика, которую автор оспаривает, ④ без них трудно переписываться — преувеличение-частность.<br>🧩 자리매김(자리 잡다) = «закрепиться, занять место»."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"…새의 입장에서 진정으로 필요한 것이 무엇인지 배려하지 않아서 생긴 결과이다. 그러나 … 상대방의 입장을 고려해야 한다는 것은 말처럼 쉬운 일이 아니다. … 따라서 어설픈 배려가 오히려 상대에게 상처를 줄 수 있다는 깨달음이 선행되어야 한다.","options":["상대를 완벽하게 이해하는 것은 사실상 거의 불가능하다.","서투른 배려는 상대에게 상처를 줄 수 있음을 알아야 한다.","우리는 우화를 통해 진정한 배려가 무엇인지 배울 수 있다.","배려할 때 상대방의 입장을 고려하는 것은 큰 의미가 없다."],"answer":2,"explain":"Тема-вывод: сперва осознать, что неумелая забота может ранить.<br>✅ <b>② Надо понимать, что неловкая забота способна ранить другого.</b> — «어설픈 배려가 오히려 상처».<br>✖️ ① полностью понять другого почти невозможно — это посылка, не вывод, ③ басня учит истинной заботе — про средство, ④ учитывать чужую позицию бессмысленно — противоречит тексту.<br>🧩 어설픈/서투른 = «неумелый, неловкий»."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"사람들은 꿀이 건강에 좋은 식품이라고 생각한다. … 꿀에는 영양소가 풍부하지만 혈당을 높이기 때문에 당뇨병 환자들에게 설탕보다 더 나은 것은 결코 아니다. 우리가 생각하는 꿀의 장점은 대부분 과학적으로 증명되지 않았다. …","options":["꿀은 설탕보다 건강에 좋은 대체 식품이다.","당뇨병 환자는 설탕 대신에 꿀을 섭취해야 한다.","꿀에 대해 믿고 있는 장점이 사실이 아닐 수 있다.","꿀이 건강에 미치는 영향은 과학적으로 증명되었다."],"answer":3,"explain":"Тема: приписываемые мёду достоинства могут быть мифом.<br>✅ <b>③ Достоинства мёда, в которые мы верим, могут быть неправдой.</b> — «대부분 과학적으로 증명되지 않았다».<br>✖️ ① мёд полезнее сахара, ② диабетикам есть мёд вместо сахара — наоборот, «설탕보다 더 나은 것은 결코 아니다», ④ влияние доказано научно — наоборот, «증명되지 않았다».<br>🧩 혈당 = «сахар в крови»."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"…이와 같이 동의하는 글을 「규약문」이라 하는데 … 인터넷으로 소통하고자 하는 사람들은 규약문을 정확히 파악하고 그것이 공정하고 합리적인지 평가해야 한다. 그래야 자신의 권리가 부당하게 침해받지 않는다.","options":["규약문의 공정성에 유의해서 읽어야 한다.","규약문은 정확한 내용 파악이 가장 중요하다.","규약문의 내용을 정확히 이해하고 따져 봐야 한다.","규약문을 사용하기 위해서는 자신의 정보를 제공해야 한다."],"answer":3,"explain":"Тема: соглашение надо точно понять И оценить его справедливость.<br>✅ <b>③ Содержание соглашения нужно точно понять и критически взвесить.</b> — «정확히 파악하고 … 평가해야».<br>✖️ ① обращать внимание только на справедливость, ② важнее всего точно понять — каждый берёт лишь ПОЛОВИНУ (понять ИЛИ оценить), а нужно и то, и другое, ④ для пользования надо дать свои данные — это лишь фон.<br>🧩 규약문 = «соглашение/правила (которые принимаешь)»; 따져 보다 = «разбирать, взвешивать»."},{"n":39,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"인주상사가 이번 달부터 「자율근무제」를 도입한다. (㉠) 이 제도는 … 기존의 출퇴근 시간이 사라지게 된다. (㉡) 이 회사에서는 오는 10월까지 … 시범 운영할 예정이다. (㉢) 시범 운영 기간이 끝나면 … 정식으로 도입할 예정이다. (㉣) 다른 기업들도 이러한 인주상사의 자율근무제 시행에 큰 관심을 가지고 있다.\n\n<보기> 나아가 이 제도의 도입을 계기로 조직 문화의 개선을 위하여 다양한 유형의 시도를 계속할 것이라고 밝혔다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"<보기> с «나아가» (более того) — о дальнейших планах самой компании, продолжает её слова о внедрении. Ставится после «정식으로 도입할 예정이다» (㉣) и перед переходом к другим фирмам.<br>✅ <b>④ ㉣</b>.<br>🧩 «나아가 … 밝혔다» завершает изложение планов компании, поэтому идёт перед «다른 기업들도…»."},{"n":40,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"(㉠) 「메디치 효과」는 서로 관련 없는 분야가 결합해 … 창의적인 결과를 창출하는 현상을 말한다. (㉡) 당시 메디치 가문은 … 예술가와 학자들의 공동 작업을 후원했다. … (㉢) 혁신적인 기술과 예술가의 … 디자인이 만나는 사례는 국내에서도 찾아볼 수 있다. (㉣) 그 예로 인주전자의 … 「엔젤폰」이 있다.\n\n<보기> 이 용어는 르네상스의 탄생과 발전에 큰 역할을 했던 메디치라는 가문의 이름에서 유래되었다.","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"<보기> объясняет ПРОИСХОЖДЕНИЕ термина (от фамилии Медичи). Идёт после определения «메디치 효과» (㉡), до «당시 메디치 가문은…», которое уже опирается на знание о семье.<br>✅ <b>② ㉡</b>.<br>🧩 «이 용어는 … 유래되었다» связывает название с семьёй Медичи, упоминаемой далее."},{"n":41,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"정지우 교수의 「영화, 물리를 말하다」에서는 영화 속 과학 이야기를 … 보여 준다. (㉠) 물리학자인 작가가 … 그 속에 숨어 있는 과학을 설명한다. (㉡) 이 책에서는 영화에 등장하는 투명인간이나 인공지능 로봇 등을 다루고 있다. (㉢) 이 책을 통해 과학의 원리를 이해하게 된다면 더욱 흥미롭게 영화를 관람할 수 있을 것이다. (㉣) 또한 과학이 주는 신비로운 세상도 경험할 수 있을 것이다.\n\n<보기> 이러한 소재들은 과학적 지식을 바탕으로 인간의 상상력을 영화에 구체화한 것이다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기> «이러한 소재들» (такие сюжеты) отсылает к «투명인간이나 인공지능 로봇». Поэтому идёт сразу после их перечисления (㉢).<br>✅ <b>③ ㉢</b>.<br>🧩 «이러한 소재들» = указатель на только что названные примеры (человек-невидимка, ИИ-робот)."},{"n":42,"points":2,"instr":"Выберите чувство хозяйки (여주인) в подчёркнутой части.","passage":"…“자, 뭘로 하실까요?” … “난, 마르그리타로 주세요.” “저두요. 근데 치즈는 넣지 마세요.” 큰딸아이가 말한다. <u>“피자에다가 치즈를 안 넣어요?” 여주인은 한 방 맞은 기분인가 보다.</u> “왜요, 불가능한가요?” … “불가능한 게 아니라 맛이 없죠!” …","options":["난처하다","황당하다","서먹하다","안타깝다"],"answer":2,"explain":"Заказать пиццу БЕЗ сыра — для хозяйки это нечто несуразное, она «как будто получила удар».<br>✅ <b>② 황당하다</b> (опешила, ошарашена нелепостью).<br>✖️ ① 난처하다 (в затруднении), ③ 서먹하다 (неловко-отчуждённо), ④ 안타깝다 (досадно-жаль) — не передают «한 방 맞은 기분» от абсурдной просьбы.<br>🧩 한 방 맞은 기분 = «как будто получил(а) удар» (от неожиданности)."},{"n":43,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"…내가 시키는 건 정해져 있다. 아이들도 마찬가지다. … 큰딸아이: “치즈는 넣지 마세요.” … 작은딸은 바질향 소스를 넣은 파스타를 주문한다. 근데 바질은 넣지 말란다. … 치즈 빼고, 바질 빼고, 왜 이렇게들 삐딱할까.","options":["나는 같은 피자를 주문하지 않는다.","큰딸은 바질향이 나는 빵을 좋아한다.","나는 아이들의 행동이 이해가 안 된다.","작은딸은 바삭바삭한 피자를 주문했다."],"answer":3,"explain":"✅ <b>③ Я не понимаю поведение детей.</b> — «왜 이렇게들 삐딱할까» (и почему они такие «наперекосяк»).<br>✖️ ① я заказываю не одно и то же — наоборот, «내가 시키는 건 정해져 있다» (всегда одно), ② старшая любит хлеб с базиликом — базилик заказала младшая (и просит без него), ④ младшая заказала хрустящую пиццу — она заказала ПАСТУ.<br>🧩 삐딱하다 = «делать наперекор, выпендриваться»."},{"n":44,"points":2,"instr":"Выберите главную тему текста.","passage":"…「빨리빨리」 문화는 참을성이 없고 급한 성격의 부정적인 의미로 여겨져 왔다. 그러나 현대 사회에서는 이것이 오히려 강점이 될 수 있다. 즉, 현대 사회가 하루가 다르게 변화하고 있어 「빨리빨리」 적응하는 것이 성공에 유리하기 때문이다.","options":["한국 기업들은 급변하는 시대에 잘 적응하고 있다.","「빨리빨리」 문화는 한국인에게만 나타나는 국민성이다.","한국 기업은 단점을 드러내지 않으려고 하는 경향이 있다.","한국인의 「빨리빨리」 문화는 기업 발전의 긍정적 요인이 될 수 있다."],"answer":4,"explain":"Тема: «ппалли-ппалли» из недостатка превращается в плюс для развития бизнеса.<br>✅ <b>④ Корейская культура «ппалли-ппалли» может стать позитивным фактором развития компаний.</b><br>✖️ ① фирмы хорошо адаптируются (частный вывод), ② это черта только корейцев (не главная мысль), ③ фирмы скрывают недостатки — об этом речи нет.<br>🧩 빨리빨리 = «быстро-быстро»; 강점 = «сильная сторона»."},{"n":45,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"…한국 기업들이 앞으로도 … 발전해 나가기 위해서는 한국인이 가진 장점을 최대화하고 약점을 보완할 수 있는 경영 방식이 필요하다. 즉, 한국인만이 가질 수 있는 (        ) 필요가 있다. 그렇다면 한국인의 고유한 특성은 무엇인가? …","options":["상징적 의미를 만들","부정적 인식을 바꿀","차별적 경쟁력을 갖출","보편적 리더십을 추구할"],"answer":3,"explain":"Нужен стиль управления, использующий то, что есть ТОЛЬКО у корейцев → обрести отличительную (уникальную) конкурентоспособность.<br>✅ <b>③ 차별적 경쟁력을 갖출</b> (обрести отличительную конкурентоспособность).<br>✖️ ① создать символический смысл, ② изменить негативное восприятие, ④ стремиться к универсальному лидерству — «보편적» противоречит «한국인만이 가질 수 있는» (только у корейцев).<br>🧩 차별적 = «отличительный, выделяющий»; 고유한 = «самобытный»."},{"n":46,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"…공이 상하좌우로 강하게 휘어 들어가는 장면 … 이건 단지 만화라서 가능한 일일까? (㉠) 아니다. 실제로도 … 공이 회전하기 때문이다. (㉡) 공은 회전을 주는 방향에 따라 … 다르다. (㉢) 야구에서 투수들은 … 다양한 공을 던진다. 가끔 공이 … 자기 앞에서 떠오르는 것 같다는 타자들도 있다. (㉣) 그런데도 그렇게 착각하는 것은 공에 회전을 주어 공이 가라앉는 정도를 줄였기 때문이다. …\n\n<보기> 사실 투수가 던진 공은 중력으로 인해 절대로 위로 올라갈 수 없다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"<보기>: «на самом деле из-за гравитации мяч НЕ может подняться вверх». Ставится после слов о том, что бьющим КАЖЕТСЯ, будто мяч взмывает (㉣), и перед «그런데도 그렇게 착각하는 것은…» (и всё же эта иллюзия…).<br>✅ <b>④ ㉣</b>.<br>🧩 <보기> задаёт факт (мяч не поднимается), на контрасте с которым объясняется иллюзия «떠오르는 것»."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"…공은 회전을 주는 방향에 따라 회전하는 방향과 떨어지는 정도가 다르다. 야구에서 투수들은 이런 방법을 사용해 공을 치는 타자가 쉽게 예측할 수 없는 다양한 공을 던진다. … 공이 회전을 받아 거의 직선으로 날아오니까 떠오르는 것처럼 보이는 것이다.","options":["중력의 영향으로 회전 방향이 달라진다.","회전을 이용하면 공을 떠오르게 할 수 있다.","회전되어 날아오는 공은 타자가 예측하기 쉽다.","투수는 공에 회전을 주어서 다양한 공을 던진다."],"answer":4,"explain":"✅ <b>④ Питчер придаёт мячу вращение и бросает разные мячи.</b> — «이런 방법을 사용해 … 다양한 공을 던진다».<br>✖️ ① гравитация меняет направление вращения — нет, направление задаёт сам бросок, ② вращением можно поднять мяч — нет, лишь КАЖЕТСЯ (떠오르는 것처럼), ③ закрученный мяч легко предсказать — наоборот, «쉽게 예측할 수 없는».<br>🧩 회전 = «вращение»; 예측하다 = «предсказывать»."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"현대 사회는 … 많은 사회적 갈등이 존재한다. … 이러한 사회적 갈등이 타협을 통해 합리적으로 조정된다면 사회를 통합하는 동력으로 작용할 수 있을 것이다. 따라서 사회적 갈등을 합리적으로 해결하기 위해 사회 구성원 모두가 합의할 수 있는 해결 원칙을 세울 필요가 있다. 먼저 … 다음으로 … 또한 …","options":["공통된 갈등 해결의 원칙이 필요함을 주장하기 위해","국가의 지지를 받는 갈등 해결 방안을 요청하기 위해","현대 사회의 다양한 사회적 갈등에 대해 설명하기 위해","갈등 당사자 모두에게 이익이 돌아가도록 촉구하기 위해"],"answer":1,"explain":"Автор обосновывает: нужны ОБЩИЕ принципы решения конфликтов, и перечисляет их (먼저/다음으로/또한).<br>✅ <b>① Чтобы доказать необходимость общих принципов разрешения конфликтов.</b> — «모두가 합의할 수 있는 해결 원칙을 세울 필요가 있다».<br>✖️ ② просить о методе с господдержкой, ③ описать виды конфликтов (это лишь введение), ④ призвать к взаимной выгоде (один из принципов, не цель текста).<br>🧩 합의 = «согласие, консенсус»; 원칙 = «принцип»."},{"n":49,"points":2,"instr":"Выберите подходящее слово для пропуска ( ).","passage":"…먼저 (        ) 해결하는 것이 중요하다. 즉 당사자 간의 자유로운 대화와 협상을 통해 쟁점을 해결하려는 노력이 우선되어야 한다. …","options":["자율적으로","중립적으로","독창적으로","창의적으로"],"answer":1,"explain":"Пояснение «즉 당사자 간의 자유로운 대화와 협상» (свободный диалог и переговоры самих сторон) → решать САМОСТОЯТЕЛЬНО, своими силами.<br>✅ <b>① 자율적으로</b> (самостоятельно, по собственной воле).<br>✖️ ② нейтрально, ③ оригинально, ④ креативно — не соответствуют «자유로운 대화와 협상».<br>🧩 자율적 = «автономный, по своей воле»."},{"n":50,"points":2,"instr":"Выберите отношение автора в подчёркнутой части.","passage":"…그런데 이러한 사회적 갈등이 <u>타협을 통해 합리적으로 조정된다면 사회를 통합하는 동력으로 작용할 수 있을 것이다.</u> 따라서 … 해결 원칙을 세울 필요가 있다. …","options":["사회적 갈등 발생에 대해 경계하고 있다.","타협을 통한 갈등 해결에 대해 회의적이다.","사회 통합의 어려움에 대해 공감하고 있다.","사회적 갈등의 긍정적인 측면을 인정하고 있다."],"answer":4,"explain":"Автор видит в конфликте потенциал: при разумном урегулировании он становится «동력» (движущей силой) для объединения общества.<br>✅ <b>④ Признаёт положительную сторону социальных конфликтов.</b><br>✖️ ① настораживается из-за возникновения конфликтов, ② скептичен к решению через компромисс — наоборот, верит в него, ③ сочувствует трудностям интеграции — тон позитивный, а не «о трудностях».<br>🧩 동력 = «движущая сила»; 통합 = «интеграция, объединение»."}]
      },
      writing: {"durationMin":50,"label":"제41회 · 쓰기 (51~54)","tasks":[{"n":51,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 한 문장씩 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Это электронное письмо учителю — формальный стиль -습니다.","passage":"✉️ E-mail — 제목: 선생님, 샤오위입니다.\n이재정 선생님께\n안녕하세요? 샤오위입니다.\n지난주에 댁으로 초대해 주셔서 감사합니다.\n선생님 덕분에 재미있는 시간을 보냈습니다.\n이번에는 ( ㉠ ).\n다음 주 월요일과 수요일 중에 언제가 좋으십니까?\n저는 ( ㉡ ).\n편하신 오후 시간을 말씀해 주시면 감사하겠습니다. 샤오위 올림","blanks":[{"slot":"㉠","model":"제가 선생님을 집으로 초대하고 싶습니다","check":"Учитель пригласил Сяовэя на прошлой неделе; теперь Сяовэй хочет позвать учителя в ответ. Дальше «언제가 좋으십니까?» подтверждает приглашение → 초대하고 싶다 (хочу пригласить), стиль -습니다."},{"slot":"㉡","model":"오후에는 / 언제든지 다 괜찮습니다","check":"«편하신 오후 시간을 말씀해 주시면» → Сяовэю удобно во второй половине дня / в любое время: 오후에는/언제든지 다 괜찮습니다."}]},{"n":52,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 한 문장씩 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст — письменный стиль -ㄴ다.","passage":"머리는 언제 감는 것이 좋을까? 사람들은 보통 아침에 머리를 감는다. 그러나 더러워진 머리는 감고 자야 머릿결에 좋기 때문에 ( ㉠ ). 그런데 젖은 머리로 자면 머릿결이 상하기 쉽다. 따라서 ( ㉡ ). 만약 머리를 말리기 어려우면 아침에 감는 것이 더 낫다.","blanks":[{"slot":"㉠","model":"머리는 저녁에 감는 것이 좋다","check":"«더러워진 머리는 감고 자야 머릿결에 좋기 때문에» → вывод: голову лучше мыть ВЕЧЕРОМ (저녁에 감는 것이 좋다). Письменный стиль -ㄴ다."},{"slot":"㉡","model":"자기 전에 머리를 말리고 자야 한다","check":"«젖은 머리로 자면 머릿결이 상하기 쉽다. 따라서 ( )» → надо высушить волосы ПЕРЕД сном: 자기 전에 머리를 말리고 자야 한다."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음은 「글쓰기 능력을 향상시키는 방법」에 대해 교사와 학생을 대상으로 실시한 설문 조사이다. 그래프를 보고, 조사 결과를 비교하여 200~300자로 쓰시오. (30점)","instr":"Сравните результаты опроса учителей и учеников о способах улучшить навык письма (글쓰기 능력 향상 방법) текстом 200–300 знаков. Письменный стиль -ㄴ다/-는다.","image":"assets/topik2/exams/img/41-w53.png","model":"교사와 학생 300명을 대상으로 글쓰기 능력을 향상시키는 방법에 대해 설문 조사를 실시하였다. 그 결과 교사와 학생의 생각이 다르다는 것을 알 수 있었다. 교사의 경우 글을 잘 쓰려면 책을 많이 읽어야 한다가 45%로 가장 높게 나타났지만 학생의 경우에는 다양한 주제로 연습하기가 65%로 가장 높았다. 다음으로 교사는 좋은 글을 따라 써야 한다가 30%, 다양한 주제로 연습해야 한다가 25%를 차지했다. 반면에 학생들은 책을 많이 읽어야 한다가 25%로 나타났고, 좋은 글을 따라 써야 한다는 10%에 그쳤다.","check":"① Назван опрос (교사·학생 300명, 글쓰기 능력 향상 방법)? ② Указан 1-й по популярности ответ у обеих групп с цифрами (교사 책 많이 읽기 45% ↔ 학생 다양한 주제 연습 65%)? ③ Приведены остальные доли (교사 30%/25%, 학생 25%/10%)? ④ Есть связка-сравнение (반면에/그러나) и вывод о различии? ⑤ Стиль -ㄴ다, объём 200–300 знаков?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 주제로 하여 600~700자로 글을 쓰시오. (50점)","instr":"Эссе 600–700 знаков на тему «역사» (история): зачем нам знать историю и чему она учит. Раскройте оба вопроса, приведите примеры/доводы, разбейте на абзацы.","passage":"세계 어느 나라에서나 역사를 가르칩니다. 이는 지나간 일을 기록한 역사가 오늘날의 우리에게 주는 가치가 분명히 있기 때문일 것입니다.\n• 우리는 왜 역사를 알아야 합니까?\n• 그 역사를 통해서 무엇을 배울 수 있습니까?","model":"지난날에 대한 반성 또는 위대한 업적 등이 후대에게 전해지기를 바라는 마음이 기록으로 이어지고 그것이 바로 우리가 지금 「역사」라고 부르는 것이다. 우리가 역사를 기록하는 이유는 지금 일어나는 사실을 다음 세대에게 전달하는 데 그 목적이 있다.\n이러한 역사는 우리에게 지금의 「나」를 이해할 수 있는 기회를 제공해 준다. 현재는 과거에서 비롯된 것이므로 과거를 살펴봄으로써 현재 일어나고 있는 일에 대해 이해하도록 돕는다. 그리고 역사는 과거에 있었던 가슴 아픈 사건이 다시 반복되지 않도록 우리에게 교훈을 주기도 한다.\n더불어 역사의 기록을 통해 우리는 앞으로 일어날 일을 예측하고 이를 준비할 수도 있다. 얼마 전 신문 기사에 따르면 한 연구자가 옛 문서에 기록된 역사적인 사실을 분석하여 오늘날의 우리가 겪고 있는 심한 가뭄을 미리 알리면서 대비를 경고한 바 있다. 이는 역사의 가치를 보여 주는 한 예라 할 수 있을 것이다.\n이렇듯 역사는 과거의 사실을 아는 데에서 출발하여 현재의 「나」를 이해하고 더 나은 미래를 향한 방향을 제시해 줄 수 있다는 점에서 중요하다. 결국 과거의 역사는 현재로, 현재는 다시 미래의 역사로 이어지는 연속적인 관계 속에 존재하기 때문이다.","check":"① Раскрыты оба вопроса (зачем знать историю / чему она учит)? ② Есть вступление (что такое история) и вывод? ③ Приведены конкретные доводы/пример (понимание настоящего, урок прошлого, прогноз будущего)? ④ Связки уровня (이러한, 더불어, 이렇듯, 결국)? ⑤ Письменный стиль -ㄴ다, объём 600–700 знаков?"}]}
    },
    47: {
      listening: {
        durationMin: 60, total: 100, label: '제47회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/47/47th%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"image":"assets/topik2/exams/img/47-l-q1.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 어서 오십시오. 무엇을 도와드릴까요?<br>여자: 저, 신입 사원 지원 서류를 내러 왔는데요.<br>남자: 3층으로 가시면 됩니다. 저쪽 엘리베이터를 이용하세요.<br><br>Женщина пришла сдать документы на стойку, мужчина-сотрудник показывает на лифт.<br>✅ <b>②</b> — приём документов у стойки + жест в сторону лифта.<br>🧩 -(으)러 오다 = «прийти, чтобы (сделать)»."},{"n":2,"points":2,"image":"assets/topik2/exams/img/47-l-q2.png","instr":"Прослушайте и выберите подходящую картинку.","options":["①","②","③","④"],"answer":1,"explain":"🎧 남자: 넌 뭐 마실래? 커피?<br>여자: 응, 난 따뜻한 커피 한 잔 마실래.<br>남자: 그럼 먼저 가서 자리 잡고 앉아 있어, 내가 가지고 갈게.<br><br>В кафе: мужчина заказывает у стойки, женщина идёт занять столик.<br>✅ <b>①</b> — мужчина у прилавка делает заказ, женщина проходит к столу.<br>🧩 자리(를) 잡다 = «занять место»."},{"n":3,"points":2,"image":"assets/topik2/exams/img/47-l-q3.png","instr":"Прослушайте и выберите подходящий график.","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 출판 시장의 소비층이 변하고 있습니다. 지난 10년간 연령별 도서 구매율에 따르면 가장 많은 비중을 차지했던 20대의 구매율은 감소하고 40대의 경우는 높아진 것으로 나타났습니다. 분야별로는 '문학'이 가장 많았으며 '자기 계발', '유아'가 그 뒤를 이었습니다.<br><br>По возрасту: доля 20-летних СНИЖАЕТСЯ, 40-летних — РАСТЁТ (линии пересекаются).<br>✅ <b>②</b> — график, где 20대 идёт вниз, 40대 вверх.<br>✖️ ① — обе линии растут; ③/④ — это «분야별 판매율» (продажи по жанрам), а не «구매율 по возрасту».<br>🧩 비중을 차지하다 = «занимать долю»."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["점심시간이 몇 시예요?","점심 맛있게 드셨어요?","빨리 정리하고 나가죠.","지금은 배가 안 고픈데요."],"answer":3,"explain":"🎧 남자: 점심시간인데 식사하러 갑시다.<br>여자: 벌써 시간이 그렇게 됐어요? 그러고 보니 배가 고프네요.<br>남자: ____<br><br>Мужчина зовёт на обед, женщина проголодалась → логично «давай быстро приберёмся и выйдем».<br>✅ <b>③ 빨리 정리하고 나가죠.</b><br>✖️ ① спрашивать, во сколько обед, ② «вкусно поели?» (обед ещё не был), ④ «сейчас не голоден» — противоречит словам женщины."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["농구 경기 보러 꼭 오면 좋겠어요.","잘할 수 있을 테니까 걱정하지 마세요.","바빠서 연습 경기에 많이 못 갔거든요.","체육 대회가 끝나고 나니까 피곤하네요."],"answer":2,"explain":"🎧 여자: 민수 씨, 이번 체육 대회에 농구 선수로 나간다면서요?<br>남자: 네. 그런데 연습을 많이 못 해서 잘할 수 있을지 모르겠어요.<br>여자: ____<br><br>Мужчина переживает, что мало тренировался → женщина ободряет.<br>✅ <b>② 잘할 수 있을 테니까 걱정하지 마세요.</b> (всё получится, не волнуйтесь)<br>✖️ ① приглашение прийти на игру, ③ от лица женщины «я не ходила» — нелогично, ④ «устала после соревнований» (они ещё не прошли)."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["네. 일할 곳을 찾고 있어요.","네. 제가 대신 해 드릴게요.","네. 좀 알아봐 주면 좋겠어요.","네. 그 친구는 아르바이트해요."],"answer":3,"explain":"🎧 남자: 지영 씨, 혹시 친구 중에 아르바이트할 만한 사람이 있을까요?<br>여자: 글쎄요. 잘 모르겠는데 친구들한테 한번 물어볼까요?<br>남자: ____<br><br>Женщина предлагает поспрашивать у друзей → мужчина просит её разузнать.<br>✅ <b>③ 네. 좀 알아봐 주면 좋겠어요.</b> (да, было бы хорошо, если бы вы поспрашивали)<br>✖️ ① «я ищу работу» (ищет не он), ② «я сделаю вместо вас», ④ «тот друг подрабатывает» — не подходят."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["그래요? 그럼 창문을 닫아야겠네요.","정말요? 그럼 에어컨 좀 켜 주세요.","맞아요. 많이 덥지 않아서 다행이에요.","글쎄요. 아마 사무실은 열려 있을 거예요."],"answer":1,"explain":"🎧 여자: 지금 사무실이 많이 더운 것 같지 않아요? 에어컨 좀 켤까요?<br>남자: 에어컨은 켰어요. 제가 환기하려고 좀 전에 창문을 열어 놔서 그런가 봐요.<br>여자: ____<br><br>Кондиционер уже включён, но окно открыто для проветривания → отсюда жарко, значит надо закрыть окно.<br>✅ <b>① 그래요? 그럼 창문을 닫아야겠네요.</b><br>✖️ ② просить включить кондиционер (он уже включён), ③ «не жарко, к счастью» (а женщине жарко), ④ нелогично."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите подходящее продолжение.","options":["참석자 명단은 아까 드렸는데요.","회의에 참석해 주셔서 감사해요.","이쪽 자리로 와서 앉으시면 돼요.","그럼 확실히 정해지면 알려 주세요."],"answer":4,"explain":"🎧 여자: 김 선생님, 이번 회의 참석자 명단 좀 주시겠어요? 자리 배치표를 만들어야 해서요.<br>남자: 아, 네. 그런데 아직 참석 인원이 확실하지 않은데요.<br>여자: ____<br><br>Список участников ещё не окончателен → попросить сообщить, когда определится.<br>✅ <b>④ 그럼 확실히 정해지면 알려 주세요.</b><br>✖️ ① «список я уже отдал» (его как раз просят), ② благодарность за участие, ③ «садитесь сюда» — не к месту."},{"n":9,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","options":["사무실에 전화한다.","컴퓨터를 확인한다.","장학금을 신청한다.","학교 홈페이지를 본다."],"answer":1,"explain":"🎧 여자: 컴퓨터가 안 되네. 오늘까지 장학금을 신청해야 하는데.<br>남자: 뭐라고? 장학금 신청이 오늘까지였어? 정확한 거야?<br>여자: 학교 홈페이지에서 그렇게 봤어. 내가 사무실에 전화해 볼까?<br>남자: 그래, 해 봐. 컴퓨터는 내가 확인해 볼게.<br><br>Женщина предлагает позвонить в офис, мужчина соглашается («해 봐») и берёт на себя компьютер.<br>✅ <b>① 사무실에 전화한다.</b><br>✖️ ② проверит компьютер — это сделает мужчина, ③ подать заявку нельзя (컴퓨터가 안 됨), ④ сайт она уже посмотрела."},{"n":10,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","options":["집에 간다.","자료를 만든다.","상품을 정리한다.","두통약을 사러 간다."],"answer":4,"explain":"🎧 여자: 잠깐 약국 좀 다녀올게요. 두통약 좀 먹어야겠어요.<br>남자: 몸이 안 좋으면 빨리 집에 가서 쉬세요. 나머지 전시회 상품은 제가 정리할 테니까요.<br>여자: 아니에요. 아직 설명 자료도 못 만들었는데요.<br>남자: 네, 그럼 다녀오세요. 이건 제가 정리하고 있을게요.<br><br>Женщина идёт в аптеку за лекарством от головной боли; домой не пойдёт (работа не доделана), товар разложит мужчина.<br>✅ <b>④ 두통약을 사러 간다.</b><br>✖️ ① домой не идёт, ② материалы ещё не делает (сначала аптека), ③ товар разложит мужчина."},{"n":11,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","options":["자전거를 꺼낸다.","옷을 갈아입는다.","공원에서 운동한다.","동생과 같이 나간다."],"answer":1,"explain":"🎧 여자: 준기야, 자전거 어디에 뒀니?<br>남자: 베란다에 있는데……. 누나, 자전거 타려고? 꺼내 줄까?<br>여자: 아니. 내가 꺼낼게. 너도 같이 안 나갈래? 날씨도 좋은데 공원에서 같이 운동하자.<br>남자: 그래. 그럼 옷 좀 갈아입고 나올게.<br><br>На предложение брата достать велосипед женщина отвечает «아니, 내가 꺼낼게» (нет, я сама достану).<br>✅ <b>① 자전거를 꺼낸다.</b><br>✖️ ② переодевается брат, ③ зарядка в парке — позже, ④ выйти вместе — тоже потом."},{"n":12,"points":2,"instr":"Прослушайте диалог и выберите действие, которое женщина совершит далее.","options":["카드로 계산한다.","안내 센터에 간다.","배달 신청을 한다.","집에서 물건을 받는다."],"answer":2,"explain":"🎧 남자: 손님, 모두 12만 원입니다.<br>여자: 여기 이 카드로 계산해 주세요. 그런데 집까지 배달도 해 주시나요?<br>남자: 물론이죠. 여기 영수증 있습니다. 이거 가지고 안내 센터에 가서 신청하면 됩니다.<br>여자: 아, 네. 고맙습니다. 그런데 언제쯤 물건을 받을 수 있을까요?<br>남자: 보통 두세 시간 정도 걸립니다.<br><br>Оплата уже сделана; продавец велит с чеком идти в инфоцентр оформить доставку → следующий шаг женщины.<br>✅ <b>② 안내 센터에 간다.</b><br>✖️ ① оплата уже произошла, ③ заявку на доставку оформит позже (в инфоцентре), ④ получит товар через 2–3 ч."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием.","options":["여자는 현재 구청에서 일하고 있다.","남자는 프로그램에 대해 알아볼 것이다.","여자는 이 프로그램에 참여한 적이 있다.","남자는 이 프로그램에 대해 들은 적이 없다."],"answer":2,"explain":"🎧 여자: 구청에서 진로 상담 프로그램을 운영한대.<br>남자: 응. 나도 들었어. 무료로 적성 검사도 해 준다고 그러던데.<br>여자: 그래? 한번 해 볼 만하겠다. 어떻게 신청하면 되는 거지?<br>남자: 음. 내가 문의해 보고 알려 줄게.<br><br>✅ <b>② Мужчина наведёт справки о программе</b> — «내가 문의해 보고 알려 줄게».<br>✖️ ① женщина не работает в управе, ③ она ещё не участвовала (только собирается), ④ мужчина тоже слышал о программе («나도 들었어»)."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием (объявление в поезде).","options":["이 열차는 현재 멈춰 있다.","이 열차는 서울역에서 출발했다.","이 열차는 잠시 후에 대전역에 도착한다.","부산으로 가는 KTX 열차가 고장이 났다."],"answer":3,"explain":"🎧 남자: 안내 말씀드리겠습니다. 서울로 가는 우리 열차는 지금 공사 구간을 지나가고 있어서 천천히 운행하고 있습니다. 그리고 우리 열차는 부산으로 가는 KTX 열차를 먼저 보내기 위해 잠시 후 다음 정차역인 대전역에서 10분간 더 정차하겠습니다. 손님 여러분께 불편을 드려 죄송합니다.<br><br>✅ <b>③ Поезд вскоре прибудет на станцию Тэджон</b> — «잠시 후 다음 정차역인 대전역».<br>✖️ ① он не стоит, а медленно едет; ② поезд идёт В Сеул (서울로 가는), а не из Сеула; ④ KTX не сломан — его просто пропускают вперёд."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием (информационное объявление).","options":["오늘부터 한 달 동안 입장 요금을 반값에 판매한다.","작년에도 가족을 위한 할인 티켓을 판매했다.","올해는 작년보다 일찍 야외 수영장을 이용할 수 있다.","티켓을 한 장 사면 티켓 한 장을 더 주는 행사를 한다."],"answer":3,"explain":"🎧 남자: 다음은 생활 정보입니다. 요즘 날이 많이 더우시죠? 때 이른 더위로 한강 공원의 야외 수영장이 작년보다 일주일 빨리 개장한다는 소식입니다. 개장 후 일주일 동안은 정상가의 50%로 이용이 가능합니다. 또한 올해부터 가족 티켓 판매를 시작한다고 하는데요. 4인 가족 방문 시 1명은 무료로 입장이 가능하다고 하니 이번 기회에 미리 휴가 다녀오시는 게 어떨까요?<br><br>✅ <b>③ В этом году открытым бассейном можно пользоваться раньше, чем в прошлом</b> — «작년보다 일주일 빨리 개장».<br>✖️ ① скидка 50% — первую неделю, а не месяц; ② семейные билеты — впервые в этом году; ④ не «купи один — получи второй», а 1 из 4 членов семьи бесплатно."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием.","options":["정오의 콘서트는 올해 처음 시작되었다.","극장을 찾는 사람들의 수가 줄어서 걱정이다.","금요일에 카페에서 커피를 마시면 콘서트 티켓을 준다.","한 달에 한 번 지휘자가 음악에 대해 설명하는 시간이 있다."],"answer":4,"explain":"🎧 여자: 서울아트센터에서 하는 '정오의 콘서트'가 요즘 큰 인기를 얻고 있다고 들었는데요.<br>남자: 네. 관객을 위해 다양한 서비스를 마련한 것이 효과적이었다고 생각합니다. 매달 마지막 목요일에는 지휘자가 관객들에게 음악에 대해 해설해 주는 '음악 이야기' 시간을 갖습니다. 그리고 금요일 공연을 관람하는 경우 1층 카페에서 무료로 커피를 제공하고 있습니다. 그래서 작년에 비해 '정오의 콘서트' 관람객 수가 많이 늘어난 것 같습니다.<br><br>✅ <b>④ Раз в месяц дирижёр объясняет музыку</b> — «매달 마지막 목요일에는 지휘자가 … 해설».<br>✖️ ① концерт начался не в этом году (есть сравнение с прошлым годом), ② число зрителей выросло, а не упало, ③ кофе бесплатно дают зрителям пятничного концерта (а не наоборот)."},{"n":17,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","options":["여행 갈 때는 새 옷을 사야 한다.","쇼핑할 때 가격을 따져 봐야 한다.","옷은 직접 입어 보고 사는 게 좋다.","쇼핑으로 시간을 낭비하면 안 된다."],"answer":3,"explain":"🎧 여자: 아, 다음 주에 여행 가는데 인터넷으로 옷 하나 사려고요. 백화점이나 쇼핑몰에 직접 가는 것보다 시간도 아낄 수 있고 가격도 저렴하거든요.<br>남자: 저는 인터넷으로 사는 것이 시간이 꽤 걸리던데요. 그리고 아무래도 옷은 가서 입어 보고 고르는 게 좋지 않아요? 색깔이나 모양이 화면으로 보는 것과 다른 경우도 많잖아요.<br><br>Мужчина: цвет/фасон на экране часто отличаются → лучше примерить вживую.<br>✅ <b>③ Одежду лучше покупать, примерив лично.</b><br>✖️ ① «новую одежду для поездки», ② «сверять цену», ④ «не тратить время на шопинг» — это не его позиция (он как раз против онлайна)."},{"n":18,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","options":["어릴 때는 여러 번 실수해도 괜찮다.","아이들이 잘못을 해도 예뻐해야 한다.","아이들에게 심하게 말을 하면 안 된다.","아이들에게 자기 잘못을 알게 해야 한다."],"answer":4,"explain":"🎧 남자: 요즘 부모들은 아이들이 잘못해도 왜 아무 말도 안 하지? 무조건 예뻐만 하는 건 문제인 것 같아.<br>여자: 아이들이 어려서 그러는 건데 그때마다 뭐라고 하는 건 안 좋은 거 아니야?<br>남자: 아무리 어려도 자기가 무엇을 잘못했는지는 바로 알려 줘야지. 그래야 다음에 같은 실수를 반복하지 않지.<br><br>✅ <b>④ Детям нужно давать понять, в чём их ошибка.</b> (иначе повторят)<br>✖️ ① и ② — это позиция, которую мужчина критикует, ③ «нельзя резко говорить» — он, наоборот, за то, чтобы указывать на ошибку."},{"n":19,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","options":["연휴에는 여행을 가는 것이 좋다.","기차를 타면 이동 시간을 줄일 수 있다.","차가 많은 연휴에는 조심해서 운전해야 한다.","차로 가면 짐을 많이 실을 수 있어서 편하다."],"answer":2,"explain":"🎧 여자: 어휴, 연휴라 그런지 차가 많이 막히네.<br>남자: 그래서 내가 기차 타자고 했잖아. 기차 타면 여행 기분도 더 날 텐데 말이야.<br>여자: 하지만 애들 짐도 많고 부모님 선물도 있고 하니까 차가 편하지 않아?<br>남자: 그거야 내가 들면 되지. 잘못하다가는 부모님 뵙는 시간보다 차 안에 있는 시간이 더 많겠어.<br><br>Мужчина против машины: в пробке проведёшь больше времени, чем с родителями; поездом — лучше.<br>✅ <b>② На поезде можно сократить время в пути.</b><br>✖️ ① «в праздники лучше путешествовать», ③ про осторожное вождение, ④ про багаж в машине — не его главная мысль."},{"n":20,"points":2,"instr":"Прослушайте интервью и выберите главную мысль мужчины (владельца ресторана).","options":["끊임없이 노력하는 자세가 중요하다.","최고가 되기 위해서는 자신을 믿어야 한다.","성공을 위해서는 창의적인 생각이 필요하다.","식당에 오는 손님들을 첫 번째로 생각해야 한다."],"answer":1,"explain":"🎧 여자: '세상에서 두 번째로 맛있는 집'이라는 식당 이름이 참 재미있는데요. 사장님, 가게 이름을 이렇게 지으신 특별한 이유가 있으신가요?<br>남자: 요즘 사람들은 무엇이든지 1등이 되고 싶어 하는 것 같습니다. 하지만 저는 최고가 되기보다는 계속 최고를 향해 가는 사람이 되고 싶습니다. 내가 최고라고 생각하는 순간 거기에 만족하게 되니까요. 나보다 더 나은 사람이 있을 거라 생각하며 저는 앞으로도 항상 최선을 다할 겁니다.<br><br>Назвал ресторан «вторым по вкусу в мире»: быть «лучшим» = успокоиться, поэтому всегда стремится к лучшему.<br>✅ <b>① Важен настрой на непрерывные усилия.</b><br>✖️ ② про веру в себя, ③ про креативность, ④ про клиентов — этого как главной мысли нет."},{"n":21,"points":2,"instr":"Прослушайте диалог и выберите главную мысль мужчины.","options":["피자 가게의 성공은 맛에 달려 있다.","치킨 가게가 잘되려면 위치가 중요하다.","퇴직 후에도 할 수 있는 일을 찾아야 한다.","여러 사람의 의견을 들어야 성공할 수 있다."],"answer":2,"explain":"🎧 여자: 여보, 당신 퇴직하면 우리 치킨 가게 하나 해 볼까요?<br>남자: 우리 가게라……. 좋지요. 하지만 만만하게 생각해서는 안 될 것 같은데요. 그런 가게는 사람들이 많이 오가는 곳에 차려야 성공할 수 있는데 그런 데는 가게도 비싸고요.<br>여자: 시장에서 피자 가게 하는 친구가 그러는데 맛만 좋으면 가게가 어디에 있든지 손님들이 다 알아서 찾아온대요.<br>남자: 그래도 손님들이 쉽게 가게를 찾을 수 있는 곳이어야 하지 않을까요?<br><br>Мужчина: магазин надо открывать там, где много прохожих и куда легко добраться.<br>✅ <b>② Чтобы курятня преуспела, важно расположение.</b><br>✖️ ① про вкус (это мнение жены), ③ про занятость после выхода на пенсию, ④ про мнения многих — не его мысль."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 회사를 퇴직했다.","남자는 시장에서 가게를 운영한다.","여자는 치킨 가게를 하고 싶어 한다.","여자의 친구는 시장에서 치킨 가게를 한다."],"answer":3,"explain":"✅ <b>③ Женщина хочет открыть курятню</b> — «당신 퇴직하면 우리 치킨 가게 하나 해 볼까요?».<br>✖️ ① муж ещё не на пенсии («퇴직하면» = когда/если выйдешь), ② у мужчины нет магазина на рынке, ④ <b>ловушка</b>: подруга держит на рынке <b>피자</b> (пиццерию), а не курятню.<br>🧩 Внимательно различайте 치킨 ↔ 피자 — на этом и построен дистрактор ④."},{"n":23,"points":2,"instr":"Прослушайте и выберите, что сейчас делает мужчина.","options":["등산로의 위치를 확인하고 있다.","호텔까지 가는 길에 대해 묻고 있다.","여행하려는 곳에 숙박 예약을 하고 있다.","호텔에서 진행하는 프로그램에 대해 문의하고 있다."],"answer":4,"explain":"🎧 남자: 다음 주 토요일에 3명, 1박 예약했는데요. 호텔에서 진행하는 자연 체험 교육을 예약하고 싶어서요.<br>여자: 자연 체험 교육은 20명 이상 단체만 가능합니다.<br>남자: 그러면 아이하고 할 수 있는 가족 체험 프로그램은 없나요?<br><br>Номер уже забронирован; мужчина расспрашивает о программах отеля (체험 교육, 가족 체험).<br>✅ <b>④ Спрашивает о программах, проводимых отелем.</b><br>✖️ ① проверяет расположение тропы (это предлагает женщина в конце), ② спрашивает дорогу до отеля, ③ бронирует ночлег — бронь уже сделана («예약했는데요»).<br>🧩 -고 싶어서요 = «потому что хочу…» (мягкое объяснение причины)."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["「숲속놀이터」는 단체만 이용이 가능하다.","남자는 가족과 3일간 호텔에서 묵을 예정이다.","호텔에서는 가족을 위한 체험 활동을 계획 중이다.","자연 체험 교육은 최대 20명까지 수강이 가능하다."],"answer":3,"explain":"🎧 여자: 가족을 위한 체험 프로그램은 현재 준비 중에 있습니다. 대신 … 「숲속놀이터」를 새로 만들었는데요.<br><br>✅ <b>③ Отель готовит программу для семей.</b> — «현재 준비 중» (сейчас в разработке).<br>✖️ ① 「숲속놀이터」 — новая площадка для всех, не только групп, ② бронь на <b>1 ночь</b> (1박), а не 3 дня, и про семью речи нет, ④ 자연 체험 교육 — от <b>20 человек и больше</b> (20명 이상 단체), а не «до 20».<br>🧩 Ловушка ④: 이상 (от и выше) ↔ «최대 …까지» (максимум до) — противоположный смысл."},{"n":25,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["장애인을 위한 시설을 늘려야 한다.","장애인들에게 세금을 깎아 줘야 한다.","정부는 운동선수의 재활을 도와야 한다.","장애인의 자립을 위한 일자리가 필요하다."],"answer":4,"explain":"🎧 남자: 정부에서 … 여러 가지 지원을 해 주고 있지만 무엇보다도 장애인들이 자립할 수 있어야 한다고 생각했습니다. 그래서 … 장애인을 고용하는 회사를 차리게 됐습니다.<br><br>Бывший футболист открыл компанию, нанимающую людей с инвалидностью, ради их самостоятельности.<br>✅ <b>④ Нужны рабочие места для самостоятельности людей с инвалидностью.</b><br>✖️ ① увеличивать число учреждений, ② снижать налоги (он говорит, что льготы уже есть, но главное — не это), ③ реабилитация спортсменов — не его мысль.<br>🧩 무엇보다도 = «прежде всего, важнее всего» — маркер главной мысли."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 장애를 극복하고 국가대표가 되었다.","남자는 사고를 당해 축구를 할 수 없게 되었다.","남자는 사업가가 되기 위해 운동을 그만두었다.","남자는 정부 지원을 받기 위해 회사를 설립했다."],"answer":2,"explain":"🎧 남자: 저는 교통사고로 장애를 입어 축구를 그만두게 됐습니다.<br><br>✅ <b>② Из-за аварии мужчина больше не смог играть в футбол.</b> — «교통사고로 … 축구를 그만두게».<br>✖️ ① он был игроком сборной <b>до</b> травмы, а не «преодолел инвалидность и стал», ③ спорт бросил из-за аварии, а не «чтобы стать бизнесменом», ④ компанию открыл ради самостоятельности инвалидов, а не «ради господдержки».<br>🧩 -게 되다 = «(так вышло, что) стало…» — результат под влиянием обстоятельств."},{"n":27,"points":2,"instr":"Прослушайте и выберите, с каким намерением женщина говорит это мужчине.","options":["기부에 동참한 것에 감사하려고","가족의 소중함을 일깨워 주려고","신발 구매의 의미를 알려 주려고","자부심을 높이는 방법에 대해 조언하려고"],"answer":3,"explain":"🎧 남자: 겨우 신발 한 켤레 준다고 아이들의 삶이 얼마나 달라지겠어.<br>여자: … 새 신발을 갖게 된 아이들은 스스로에 대한 자부심이 높아지게 되는 거지. … 이 신발이 아이들에게는 그런 사건이 될 수도 있다는 거야.<br><br>Мужчина обесценивает покупку; женщина объясняет, какой смысл стоит за этими ботинками.<br>✅ <b>③ Объяснить смысл покупки обуви.</b><br>✖️ ① благодарить за участие в благотворительности, ② напомнить о ценности семьи, ④ советовать, как повысить самооценку — это не цель её слов.<br>🧩 -다는 거야 = «я о том, что…» — приём пояснения/раскрытия своей мысли."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 신발 한 켤레를 사면 한 켤레를 더 준다.","이 신발을 가난한 아이들에게 싸게 판매한다.","여자는 남자에게 이 신발을 선물한 적이 있다.","여자는 신문을 통해서 이 신발에 대해 알게 되었다."],"answer":4,"explain":"🎧 여자: 어제 신문에서 읽었는데 이 회사는 신발이 한 켤레 팔릴 때마다 가난한 아이에게 신발 한 켤레씩을 기부한대.<br><br>✅ <b>④ Женщина узнала об этой обуви из газеты.</b> — «신문에서 읽었는데».<br>✖️ ① за пару дарят пару — нет, пару <b>жертвуют</b> бедному ребёнку (기부), ② детям продают дёшево — нет, дарят, ③ женщина дарила обувь мужчине — такого не было.<br>🧩 -ㄴ대 = стяжение косвенной речи -ㄴ다고 해 («говорят, что…»)."},{"n":29,"points":2,"instr":"Прослушайте и выберите, кто такой мужчина (по роду деятельности).","options":["라면을 개발하는 사람","라면을 광고하는 사람","라면을 판매하는 사람","라면을 홍보하는 사람"],"answer":1,"explain":"🎧 남자: 맛있는 국물을 만들기 위해 전국의 유명한 식당을 찾아다녔습니다. … 그 비결들을 가지고 실험실에서 다양한 실험을 수없이 반복했습니다.<br><br>Ищет рецепт бульона, ставит опыты в лаборатории → он создаёт (разрабатывает) рамён.<br>✅ <b>① Человек, который разрабатывает рамён.</b><br>✖️ ② рекламирует, ③ продаёт, ④ занимается продвижением — он же сам разработчик вкуса.<br>🧩 -기 위해 = «чтобы (сделать)»; 찾아다니다 = «ходить и искать, обходить»."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["남자는 평소에도 라면을 즐겨 먹었다.","남자는 유명한 식당에서 요리를 배웠다.","국물 맛의 비결을 알아내기가 쉽지 않았다.","「왕라면」은 이번 달에 처음으로 판매 1위를 했다."],"answer":3,"explain":"🎧 남자: 맛의 비밀은 쉽게 가르쳐 주지 않더군요. 한 식당의 경우는 한 달 넘게 찾아가서 가르쳐 달라고 매달린 적도 있었습니다.<br><br>✅ <b>③ Узнать секрет вкуса бульона было непросто.</b><br>✖️ ① обычно любил рамён — наоборот, «라면을 좋아하는 편은 아닌데», ② учился готовить в ресторане — он лишь выпытал секрет, ④ впервые занял 1-е место в этом месяце — «지난달에 이어» (второй месяц подряд), а не впервые.<br>🧩 -더군요 = личное наблюдение/удивление в прошлом; 매달리다 = «упрашивать, цепляться»."},{"n":31,"points":2,"instr":"Прослушайте и выберите мысль мужчины.","options":["「좌석별 가격 차등제」로 영화 관람의 불편이 줄어들었다.","「좌석별 가격 차등제」로 관객들은 선택의 기회가 늘었다.","「좌석별 가격 차등제」는 관객 입장에서 합리적인 제도이다.","「좌석별 가격 차등제」는 극장의 수익을 높이기 위한 제도이다."],"answer":4,"explain":"🎧 남자: 저 같은 사람들은 돈을 더 내더라도 편안한 자리에 앉을 것 같은데 이건 결국 극장이 돈을 더 벌기 위해 만든 제도 아닌가요?<br><br>Дифференцированные цены по местам мужчина считает уловкой кинотеатра ради прибыли.<br>✅ <b>④ Это система ради повышения дохода кинотеатра.</b><br>✖️ ① уменьшила неудобства, ② дала зрителю больше выбора, ③ разумна для зрителя — это доводы <b>женщины</b>, мужчина против.<br>🧩 -더라도 = «даже если»; 아닌가요? = риторический вопрос «разве не…?»."},{"n":32,"points":2,"instr":"Прослушайте и выберите, какова позиция (отношение) мужчины.","options":["새로운 제도의 확대를 염려하고 있다.","새로운 제도의 시행을 촉구하고 있다.","새로운 제도의 문제점을 비판하고 있다.","새로운 제도의 필요성에 공감하고 있다."],"answer":3,"explain":"🎧 남자: 전 이 제도가 문제가 있다고 생각합니다. … 극장이 돈을 더 벌기 위해 만든 제도 아닌가요?<br><br>✅ <b>③ Критикует недостатки новой системы.</b><br>✖️ ① тревожится о её расширении (об этом речи нет), ② призывает ввести, ④ согласен с необходимостью — наоборот, он против.<br>🧩 Вопрос на 태도 (отношение): ищите оценочные слова — «문제가 있다», риторические «아닌가요?»."},{"n":33,"points":2,"instr":"Прослушайте и выберите, о чём этот текст.","options":["기록의 보존 방법","기록연구사의 역할","역사적 기록물의 가치","기록을 해야 하는 이유"],"answer":2,"explain":"🎧 남자: 이런 수많은 기록 중에서 남길 것과 버릴 것을 결정하는 것은 기록연구사가 해야 하는 중요한 일 … 기록연구사는 … 기록물의 수명을 결정하는 아주 중요한 일을 합니다.<br><br>Весь текст — о том, чем занимается 기록연구사 (архивист-исследователь).<br>✅ <b>② Роль архивиста-исследователя.</b><br>✖️ ① способ хранения записей, ③ ценность исторических документов (повод, а не тема), ④ зачем вести записи.<br>🧩 무엇에 대한 내용 = вопрос на тему всего отрывка → ищите, что повторяется и обобщается."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["기록연구사는 기록의 보존 여부를 결정한다.","모든 기록물은 중요하므로 없애서는 안 된다.","기록물은 수백 년이 지나도 그대로 보존된다.","사라진 자료를 찾아내는 것도 기록연구사의 일이다."],"answer":1,"explain":"🎧 남자: 남길 것과 버릴 것을 결정하는 것은 기록연구사가 해야 하는 중요한 일 …<br><br>✅ <b>① Архивист решает, сохранять запись или нет.</b> — «남길 것과 버릴 것을 결정».<br>✖️ ② все документы важны и их нельзя уничтожать — нет, «없애도 되는 것도 있지만», ③ хранятся неизменными столетиями — речь о труде людей, а не о само-сохранности, ④ поиск утраченных материалов — об этом не говорилось.<br>🧩 보존 여부 = «сохранять или нет» (여부 = «да/нет, наличие/отсутствие»)."},{"n":35,"points":2,"instr":"Прослушайте и выберите, что делает мужчина.","options":["시에서 만든 편의 시설을 소개하고 있다.","시민이 원하는 것이 무엇인지 조사하고 있다.","시민을 위한 정책을 펼칠 것을 다짐하고 있다.","시의 발전을 위해 자신을 지지해 달라고 부탁하고 있다."],"answer":3,"explain":"🎧 남자: 또 한 번의 기회를 주신 것은 … 정책을 완성하라는 뜻 … 빠른 시일 내에 공사를 마무리 지어 … 약속드립니다. 앞으로도 … 열심히 일하는 시장이 되겠습니다.<br><br>Переизбранный мэр обещает довести политику до конца — это клятва/обещание.<br>✅ <b>③ Обещает проводить политику в интересах горожан.</b><br>✖️ ① представляет удобства, ② изучает запросы жителей, ④ просит о поддержке — выборы уже выиграны, он благодарит и обещает.<br>🧩 -겠습니다 / 약속드립니다 = формулы обещания и решимости (다짐)."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 도시는 전국에서 가장 큰 의료원을 짓고 있다.","이 도시는 이번에 살기 좋은 도시로 선정되었다.","이 남자는 추진 중이던 정책을 모두 마무리 지었다.","이 남자는 여러 번의 도전 끝에 시장으로 선출되었다."],"answer":1,"explain":"🎧 남자: 첫 번째 과제는 현재 건립 중에 있는 전국 최대 규모의 의료원을 완공하는 것입니다.<br><br>✅ <b>① Город строит крупнейший в стране медцентр.</b> — «건립 중 … 전국 최대 규모의 의료원».<br>✖️ ② выбран «городом, где приятно жить» — это пока <b>цель</b> («목표를 향해»), ③ всю политику уже завершил — наоборот, её надо «완성하라», ④ стал мэром после многих попыток — «지난 선거에 이어» = переизбран подряд.<br>🧩 건립 중 / 완공 = «в процессе строительства» / «завершение строительства»."},{"n":37,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины.","options":["기업은 신입 사원의 능력 개발을 장려해야 한다.","입사하고 싶은 기업의 선발 기준을 파악하고 있어야 한다.","이력서에 있는 개인 정보가 공정한 선발을 방해할 수 있다.","능력 있는 인재가 되기 위해서는 노력하는 자세가 필요하다."],"answer":3,"explain":"🎧 남자: 인사 담당자들이 이 사진을 보고 전혀 영향을 받지 않는다는 건 아주 힘든 일 … 「익명이력서」는 … 개인 정보를 전혀 기재하지 않는 건데요. 능력 있는 인재를 공정하게 선발할 수 있는 좋은 대안 …<br><br>Личные данные (фото, имя, пол) мешают честному отбору, поэтому появляются анонимные резюме.<br>✅ <b>③ Личные данные в резюме могут мешать честному отбору.</b><br>✖️ ① поощрять развитие новичков, ② знать критерии отбора компании, ④ нужно трудиться, чтобы стать ценным кадром — не его главная мысль.<br>🧩 대안 = «альтернатива»; 공정한 선발 = «справедливый отбор»."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["이 남자는 「익명이력서」에 대해 부정적이다.","이 남자는 이력서에 사진이 있어야 한다고 본다.","기업들이 사진 없는 이력서 도입을 계속 미루고 있다.","「익명이력서」로는 지원자의 성별과 나이를 알 수 없다."],"answer":4,"explain":"🎧 남자: 「익명이력서」는 사진은 물론이고 이름, 성별, 생년월일 같은 개인 정보를 전혀 기재하지 않는 건데요.<br><br>✅ <b>④ По анонимному резюме нельзя узнать пол и возраст кандидата.</b> — 성별·생년월일 не указываются.<br>✖️ ① относится к анонимным резюме негативно — наоборот, «좋은 대안», ② считает, что фото нужно — против, ③ компании откладывают внедрение — наоборот, «늘고 있는데요».<br>🧩 물론이고 = «не говоря уже о…, само собой»; 기재하다 = «вписывать, указывать»."},{"n":39,"points":2,"instr":"Прослушайте и выберите, что было сказано ПЕРЕД этим фрагментом.","options":["다양한 공공장소에 태양광 시설을 설치하고 있다.","많은 기업들이 태양광 시설에 적극적으로 투자하고 있다.","태양광 발전소의 생산성이 생각보다 낮아 문제가 되고 있다.","태양광 발전소 사업자와 주민 사이에 마찰이 빚어지고 있다."],"answer":4,"explain":"🎧 여자: 이런 갈등은 개인 사업자가 태양광 발전소를 주거 지역 근처에 세우면서 시작되었는데요. … 지역 주민들이 반대를 하고 나선 거죠.<br><br>Слово «이런 갈등» (этот конфликт) отсылает к ранее упомянутому трению между бизнесом и жителями.<br>✅ <b>④ Между владельцами солнечных станций и жителями возникают трения.</b><br>✖️ ① установка панелей в общественных местах, ② активные инвестиции компаний, ③ низкая производительность станций — это не предмет «이런 갈등».<br>🧩 «이런/그런 + сущ.» в начале реплики = ключ к вопросу «что было раньше»."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["태양광 발전소를 세우는 개인 사업자가 많아지고 있다.","태양광 발전소가 생긴 후 농작물의 생산성이 향상되었다.","태양광 발전소의 설치를 원하는 지역 주민들이 늘고 있다.","태양광 발전소로 인한 갈등을 해결해 줄 방안이 마련되었다."],"answer":1,"explain":"🎧 남자: 태양광 발전소를 설립하는 개인 사업자가 늘어나면서 이런 상황은 점점 심각해지고 있는데요.<br><br>✅ <b>① Частных предпринимателей, строящих солнечные станции, становится больше.</b> — «개인 사업자가 늘어나면서».<br>✖️ ② урожайность выросла — наоборот, «생산성에도 좋지 않은 영향», ③ растёт число жителей, желающих установки — наоборот, протестуют, ④ решение уже найдено — лишь «마련되어야 할 것» (должно быть выработано).<br>🧩 -(으)면서 = одновременность/сопутствие: «по мере того как…»."},{"n":41,"points":2,"instr":"Прослушайте и выберите главную мысль женщины.","options":["석빙고에 대한 역사적 기록을 찾아야 한다.","석빙고는 과학적인 원리를 활용해 설계되었다.","석빙고의 우수성을 밝히려는 노력이 필요하다.","석빙고에 얼음을 보관하던 문화를 지켜야 한다."],"answer":2,"explain":"🎧 여자: 특별한 냉동 장치가 없었는데도 … 0도 이하로 유지 … 과학적인 구조가 가장 큰 역할 … 반은 지하에, 반은 지상에 … 지붕에 구멍 … 바닥은 경사지게 …<br><br>Всё объяснение — про научно продуманное устройство ледника 석빙고.<br>✅ <b>② 석빙고 спроектирован с использованием научных принципов.</b><br>✖️ ① нужно искать исторические записи, ③ нужны усилия, чтобы доказать превосходство, ④ нужно беречь культуру хранения льда — это не главная мысль, а лишь фон.<br>🧩 -았/었는데도 = «несмотря на то что…» (уступка)."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["석빙고의 경사진 바닥은 온도 유지에 도움이 된다.","지붕에 구멍을 만들어 석빙고를 아름답게 장식했다.","더운 공기를 빼기 위해 석빙고에 차가운 물을 공급했다.","석빙고에는 얼음을 녹지 않게 해 주는 장치가 달려 있다."],"answer":1,"explain":"🎧 여자: 바닥은 경사지게 만들어 얼음이 녹으면서 생긴 물을 밖으로 흘려보내 영하의 온도를 유지했던 겁니다.<br><br>✅ <b>① Наклонный пол 석빙고 помогает удерживать температуру.</b><br>✖️ ② отверстие в крыше — для красоты — нет, для выхода тёплого воздуха, ③ подавали холодную воду — нет такого, ④ есть устройство, не дающее льду таять — спец-устройств не было («특별한 냉동 장치가 없었는데도»).<br>🧩 경사지다 = «иметь уклон, быть наклонным»; 흘려보내다 = «спускать, отводить (воду)»."},{"n":43,"points":2,"instr":"Прослушайте и выберите главную мысль этого рассказа.","options":["판의 충돌이 인류의 역사를 발전시켰다.","판의 움직임이 자원의 이동을 초래했다.","인류는 판의 경계에 고대 문명을 건설했다.","인류는 판의 충돌로 인한 위험을 극복해 왔다."],"answer":1,"explain":"🎧 남자: 이 충돌이 인류에게 필요한 자원을 안겨 주기도 했다. … 구리 등을 이용하여 단단한 연장을 만들었고 이것은 인류 문명을 급격하게 발달시켰다.<br><br>Столкновение плит дало ресурсы → орудия → бурное развитие цивилизации.<br>✅ <b>① Столкновение плит развило историю человечества.</b><br>✖️ ② движение плит вызвало перемещение ресурсов (часть аргумента, не итог), ③ цивилизации построены на границах плит (факт-иллюстрация), ④ человечество преодолело опасность — текст про пользу+риск вместе, итог — про развитие.<br>🧩 역설적이게도 = «как это ни парадоксально»; 안겨 주다 = «принести, даровать»."},{"n":44,"points":2,"instr":"Прослушайте и выберите, почему многие крупные города расположены на границах плит.","options":["다른 도시 문명과 가까웠기 때문에","자연 재해를 피할 수 있었기 때문에","지각이 바뀌면서 경계로 밀려났기 때문에","문명 발달에 필요한 자원을 얻기 쉬웠기 때문에"],"answer":4,"explain":"🎧 남자: 판이 충돌하면서 … 구리나 금, 석유 등의 자원이 지표면으로 올라왔기 때문이다. 인간은 구리 등을 이용하여 … 문명을 … 발달시켰다.<br><br>На границах плит ресурсы выходят к поверхности → их легко добывать → там и города.<br>✅ <b>④ Потому что там легко получить ресурсы, нужные для развития цивилизации.</b><br>✖️ ① близость к другим городам, ② можно избежать стихийных бедствий (наоборот, там землетрясения), ③ оттеснены к границе при сдвиге коры — не названо причиной.<br>🧩 -기 때문이다 = «потому что…» — прямой маркер причины."},{"n":45,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["4차 산업혁명은 인공지능을 기반으로 한다.","4차 산업혁명은 유통 시스템의 자동화를 말한다.","4차 산업혁명 시대는 전문가들의 예상대로 진행될 것이다.","4차 산업혁명에서 전문 지식 서비스는 인간이 담당할 것이다."],"answer":1,"explain":"🎧 여자: 4차 산업혁명은 기계와 제품에 인공 지능을 부여해서 새로운 가치를 창출하는 것을 말합니다.<br><br>✅ <b>① 4-я промышленная революция основана на ИИ.</b> — «인공 지능을 부여해서».<br>✖️ ② автоматизация системы сбыта — это <b>3-я</b> революция, ③ пойдёт так, как предсказывают эксперты — наоборот, «예측이 불가능», ④ экспертные услуги возьмёт человек — их будут оказывать <b>роботы</b>.<br>🧩 부여하다 = «придавать, наделять»; 창출하다 = «создавать (новое)»."},{"n":46,"points":2,"instr":"Прослушайте и выберите, какова позиция (отношение) женщины.","options":["미래 세대의 활약에 기대를 걸고 있다.","산업혁명의 부작용에 대해 반성하고 있다.","전문가들의 상황 인식에 우려를 표하고 있다.","산업의 미래에 대해 긍정적으로 전망하고 있다."],"answer":4,"explain":"🎧 여자: 분명한 것은 이것이 새로운 성장 동력으로 국가 경쟁력 강화의 주요한 기반이 될 거라는 점입니다.<br><br>Женщина видит в этом «двигатель роста» и «основу конкурентоспособности» → оптимистичный прогноз.<br>✅ <b>④ Положительно оценивает будущее этой отрасли.</b><br>✖️ ① возлагает надежды на будущее поколение, ② раскаивается в побочных эффектах, ③ выражает тревогу — этого в её словах нет.<br>🧩 전망하다 = «прогнозировать, видеть перспективу»; 긍정적 = «положительный»."},{"n":47,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["전승자들은 대학에서 재교육을 받을 예정이다.","기존의 정책은 전승 종목을 사유화할 우려가 있다.","전승자들의 작품을 인증하는 제도가 사라질 것이다.","젊은 사람들은 전승자와의 일대일 교육을 선호한다."],"answer":2,"explain":"🎧 남자: 이런 방식은 전승 종목이 사유화될 우려가 있을 뿐더러 요즘 젊은이들이 별로 선호하지 않는다는 단점이 있었죠.<br><br>✅ <b>② Прежняя политика рискует «приватизировать» передаваемое ремесло.</b> — «사유화될 우려».<br>✖️ ① мастера пройдут переобучение в вузе — они будут <b>преподавать</b> (출강), ③ сертификация работ исчезнет — наоборот, её <b>вводят</b>, ④ молодёжь предпочитает обучение «один на один» — наоборот, «별로 선호하지 않는다».<br>🧩 -(으)ㄹ 뿐더러 = «мало того что…, к тому же…»; 사유화 = «приватизация»."},{"n":48,"points":2,"instr":"Прослушайте и выберите, каким способом говорит мужчина (манера изложения).","options":["새로운 정책의 문제점을 예측하고 있다.","기존 정책의 개선 방향을 제시하고 있다.","새로운 정책의 시행 결과를 분석하고 있다.","기존 정책의 내용을 기준별로 분류하고 있다."],"answer":2,"explain":"🎧 남자: 이런 방식은 … 단점이 있었죠. 그래서 좀 더 새로운 전승 정책이 필요하다고 봅니다. 예를 들면 대학에 … 강의를 개설하고 …<br><br>Сначала недостатки старого, затем — конкретные предложения, как улучшить.<br>✅ <b>② Предлагает направление улучшения прежней политики.</b><br>✖️ ① предсказывает проблемы новой политики, ③ анализирует результаты внедрения (её ещё нет), ④ классифицирует по критериям — он не сортирует, а предлагает.<br>🧩 «예를 들면» + перечисление мер = приём «제시» (выдвижение предложения)."},{"n":49,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с услышанным.","options":["개인들의 관계는 힘의 논리에 의해 결정된다.","도덕적 사회를 이루려면 개인의 도덕이 중요하다.","집단에 속한 개인은 비도덕적으로 변할 수 있다.","집단 간의 충돌을 조정할 도덕적 기준이 필요하다."],"answer":3,"explain":"🎧 여자: 개인적으로는 도덕적인 사람도 집단 속에서는 이기적이고 폭력적으로 변할 수 있다고 말합니다.<br><br>✅ <b>③ Человек в составе группы может стать аморальным.</b><br>✖️ ① отношения между <b>индивидами</b> определяются логикой силы — речь о <b>межгрупповых</b> отношениях, ② для морального общества важна личная мораль — наоборот, личной морали недостаточно, ④ нужен моральный критерий — наоборот, «도덕보다 힘의 역학 관계에 따라 정치적으로 조정».<br>🧩 비도덕성 = «аморальность»; -ㄹ 수 있다 = «может (стать)»."},{"n":50,"points":2,"instr":"Прослушайте и выберите, каким способом говорит женщина (манера изложения).","options":["발생 가능한 문제를 제기하고 있다.","사회 현상을 논리적으로 분석하고 있다.","예를 들어 자신의 주장을 증명하고 있다.","구체적인 사례에서 결론을 유도하고 있다."],"answer":2,"explain":"🎧 여자: 집단에서는 … 누가 누구에게 책임을 물을 수도 없는 복잡한 관계가 되죠. 그래서 … 비도덕성에 합류하게 됩니다. 이것이 폭력이 구조화되는 이유와 과정입니다.<br><br>Женщина шаг за шагом разбирает причины и механизм явления (почему насилие «структурируется»).<br>✅ <b>② Логически анализирует общественное явление.</b><br>✖️ ① поднимает возможную проблему, ③ доказывает тезис на примере, ④ выводит вывод из конкретного случая — она именно <b>анализирует</b> причинно-следственную цепочку.<br>🧩 구조화되다 = «структурироваться»; «이유와 과정» = «причины и процесс» — маркер аналитического разбора."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제47회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"내일 친구와 함께 놀이공원에 (        ).","options":["가는 편이다","가는 중이다","가기로 했다","간 적이 있다"],"answer":3,"explain":"«내일» (завтра) → это запланированное будущее действие.<br>✅ <b>③ 가기로 했다</b> — «-기로 하다» = «договориться/решить (сделать)».<br>✖️ ① 가는 편이다 — «скорее обычно хожу» (склонность), ② 가는 중이다 — «нахожусь в процессе» (сейчас), ④ 간 적이 있다 — «доводилось ходить» (прошлый опыт) — не сочетаются с «내일».<br>🧩 -기로 하다 = принятое решение/уговор о будущем."},{"n":2,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"혼자 살다 보니 시간이 (        ) 가족이 그리워진다.","options":["지나거나","지나도록","지나거든","지날수록"],"answer":4,"explain":"«Чем больше времени проходит, тем сильнее скучаю по семье».<br>✅ <b>④ 지날수록</b> — «-(으)ㄹ수록» = «чем более…, тем более…».<br>✖️ ① 지나거나 — «или проходит» (перечисление), ② 지나도록 — «так, чтобы прошло / до тех пор пока», ③ 지나거든 — «если/когда пройдёт» (условие-повод).<br>🧩 -(으)ㄹ수록 часто в паре с «더/점점»: усиление по мере роста."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"아침에 늦게 <u>일어나는 바람에</u> 기차를 놓쳤다.","options":["일어난 탓에","일어난 김에","일어나는 대신","일어나는 대로"],"answer":1,"explain":"«Из-за того что поздно встал утром, опоздал на поезд».<br>✅ <b>① 일어난 탓에</b> — «-는 바람에» (неожиданная негативная причина) ≈ «-(으)ㄴ 탓에» (по вине/из-за).<br>✖️ ② 일어난 김에 — «раз уж встал, заодно», ③ 일어나는 대신 — «вместо того чтобы вставать», ④ 일어나는 대로 — «как только встанешь».<br>🧩 -는 바람에 / -(으)ㄴ 탓에 — обе указывают причину нежелательного исхода."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"경기에서 이기고 지는 것은 <u>연습하기에 달려 있다</u>.","options":["연습할 따름이다","연습할 모양이다","연습하기 나름이다","연습하기 십상이다"],"answer":3,"explain":"«Победа или поражение в матче зависит от тренировки».<br>✅ <b>③ 연습하기 나름이다</b> — «-기에 달려 있다» (зависит от…) ≈ «-기 나름이다» (зависит от того, как…).<br>✖️ ① 연습할 따름이다 — «остаётся только тренироваться», ② 연습할 모양이다 — «похоже, будет тренироваться», ④ 연습하기 십상이다 — «легко может выйти, что…» (о нежелательном).<br>🧩 -기 나름이다 = «всё зависит от того, как это делать»."},{"n":5,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"💧 비타민이 가득!\n하루 필요한 이것 한 병에!","options":["주스","콜라","우유","커피"],"answer":1,"explain":"«Полно витаминов! Дневная норма — в одной бутылке!»<br>✅ <b>① 주스</b> (сок) — «비타민» + «한 병» указывают на фруктовый напиток.<br>✖️ ② 콜라 (кола) и ④ 커피 (кофе) — не про витамины, ③ 우유 (молоко) — обычно «잔/팩», и не подаётся как «витамины в бутылке».<br>🧩 가득 = «полно, до краёв»."},{"n":6,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"🏖️ 물놀이 용품 할인 행사!\n이 기회를 놓치지 마세요!","options":["학원","마트","사진관","세탁소"],"answer":2,"explain":"«Распродажа товаров для купания! Не упустите шанс!»<br>✅ <b>② 마트</b> (супермаркет) — продаёт «물놀이 용품» (круги, товары для воды) со скидкой.<br>✖️ ① 학원 (курсы), ③ 사진관 (фотоателье), ④ 세탁소 (прачечная) — не торгуют пляжными товарами.<br>🧩 할인 행사 = «акция/распродажа со скидкой»."},{"n":7,"points":2,"instr":"Выберите, о чём этот текст (призыв).","passage":"🔥 살펴봐요, 숨은 불씨!\n다시 봐요, 꺼진 불씨!","options":["전기 절약","날씨 정보","건강 관리","화재 예방"],"answer":4,"explain":"«Проверьте скрытые угольки! Ещё раз взгляните на потухший огонь!»<br>✅ <b>④ 화재 예방</b> (предотвращение пожара) — «불씨» (тлеющий уголёк), призыв перепроверять огонь.<br>✖️ ① 전기 절약 (экономия электричества), ② 날씨 정보 (погода), ③ 건강 관리 (здоровье) — ни при чём.<br>🧩 불씨 = «искра, тлеющий уголёк» — частая причина пожара."},{"n":8,"points":2,"instr":"Выберите, о чём этот текст (объявление).","passage":"1. 기한: 2016년 8월 19일(금) 17:00까지\n2. 서류: 원서 1부, 사진 2장\n3. 관련 서류는 이메일로 보내 주십시오.","options":["구입 안내","접수 방법","등록 문의","주의 사항"],"answer":2,"explain":"«Срок: до 19.08; документы: заявление + 2 фото; присылайте по эл. почте».<br>✅ <b>② 접수 방법</b> (порядок подачи) — указаны срок, нужные документы и способ отправки.<br>✖️ ① 구입 안내 (как купить), ③ 등록 문의 (вопросы по регистрации), ④ 주의 사항 (меры предосторожности) — здесь именно инструкция, КАК подать.<br>🧩 접수 = «приём (заявок/документов)»; 원서 = «заявление-анкета»."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"📣 제8회 음식문화축제\n· 기간: 2016년 8월 20일(토) ~ 8월 21일(일)\n· 장소: 인주 시청 앞 광장\n· 행사 내용: 한국 전통 요리 무료 시식 및 체험 행사\n※ 체험을 원하시는 분은 행사 현장에서 직접 신청하시기 바랍니다.","options":["축제는 올해 처음 열린다.","축제는 주말 이틀 동안 진행된다.","축제에서 체험을 하려면 예약해야 한다.","축제에서 전통 요리를 사 먹을 수 있다."],"answer":2,"explain":"✅ <b>② Фестиваль идёт два выходных дня.</b> — «8월 20일(토) ~ 21일(일)» (суббота–воскресенье).<br>✖️ ① впервые в этом году — нет, это <b>8-й</b> (제8회), ③ для участия нужна предварительная запись — нет, «현장에서 직접 신청» (на месте), ④ можно купить блюда — нет, «무료 시식» (бесплатная дегустация).<br>🧩 무료 시식 = «бесплатная проба»; 현장 신청 = «запись на месте»."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с данными графика.","passage":"📊 «세대별 매체 이용 현황» (ТВ vs газета по поколениям).\nТВ: 20대 — низко, 40대 — выше, 60대 — выше всех (растёт с возрастом).\nГазета (신문): 20대 — низко, 40대 — пик, 60대 — ниже 40대.","options":["신문을 보는 사람의 비율은 20대와 60대가 같다.","모든 세대가 텔레비전보다 신문을 더 많이 본다.","신문을 보는 사람의 비율은 60대가 40대보다 낮다.","텔레비전을 보는 사람의 비율은 20대가 40대보다 높다."],"answer":3,"explain":"✅ <b>③ Доля читающих газеты у 60-летних ниже, чем у 40-летних.</b> — пик газеты приходится на 40대.<br>✖️ ① доли у 20대 и 60대 равны — нет, разные, ② все поколения читают газеты больше, чем смотрят ТВ — наоборот, ТВ везде выше, ④ доля ТВ у 20대 выше, чем у 40대 — наоборот, ТВ растёт с возрастом.<br>🧩 비율 = «доля, процент»; 세대별 = «по поколениям»."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"만화방이 단순히 만화를 보는 공간에서 벗어나 볼거리, 먹을거리를 함께 즐길 수 있는 「만화카페」로 다시 태어나고 있다. 이 만화카페는 「만화를 보는 공간」이라는 점에서 만화방과 비슷하다. 그러나 밝은 조명과 세련된 분위기에서 고급 커피까지 마실 수 있다는 점이 다르다. 만화방이 주로 남자들에게 인기가 많았다면 만화카페는 10, 20대 여성들에게 인기가 많다.","options":["만화카페는 만화방과 실내 분위기가 비슷하다.","만화카페는 주로 남성들에게 인기를 끌고 있다.","만화카페는 커피를 마시기 위한 곳으로 새롭게 태어났다.","만화카페는 볼거리와 먹을거리를 모두 즐길 수 있는 곳이다."],"answer":4,"explain":"✅ <b>④ Манга-кафе — место, где можно наслаждаться и зрелищами, и едой.</b> — «볼거리, 먹을거리를 함께 즐길 수 있는».<br>✖️ ① атмосфера как у манга-комнаты — наоборот, «분위기가 다르다», ② популярно у мужчин — наоборот, у девушек 10–20 лет, ③ возникло как место для кофе — кофе лишь одно из отличий, а «переродилось» оно ради 볼거리+먹을거리.<br>🧩 다시 태어나다 = «переродиться, обрести новый облик»."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"카카오가 건강에 도움이 된다는 사실이 새롭게 알려졌다. 카카오에 있는 단백질, 지방, 칼슘과 같은 영양 성분이 감기 예방, 집중력 향상 등에 효과가 있다는 것이다. 그러나 카카오는 그 자체로 먹기가 어려워 일반적으로 초콜릿 형태로 먹는다. 그런데 너무 단 초콜릿은 오히려 건강을 해칠 수 있어 많이 먹는 것은 피해야 한다.","options":["카카오를 먹으면 집중력을 높일 수 있다.","초콜릿은 영양 성분이 풍부해서 많이 먹어야 한다.","카카오보다 초콜릿 형태로 먹는 것이 건강에 더 좋다.","초콜릿의 재료가 카카오라는 사실이 처음으로 알려졌다."],"answer":1,"explain":"✅ <b>① Какао помогает повысить концентрацию.</b> — «집중력 향상 등에 효과».<br>✖️ ② шоколад богат витаминами, надо есть много — наоборот, «많이 먹는 것은 피해야», ③ есть в форме шоколада полезнее — нет, слишком сладкий шоколад вредит, ④ впервые узнали, что сырьё шоколада — какао — новость в другом: что какао полезно для здоровья.<br>🧩 영양 성분 = «питательные вещества»; 해치다 = «вредить»."},{"n":13,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 요즘 꽃차를 즐겨 마시는 사람들이 늘고 있다.\n(나) 마음을 안정시키는 효과를 얻을 수 있기 때문이다.\n(다) 깨끗하게 재배한 꽃으로 차를 만들어 마시는 것이 좋다.\n(라) 그런데 길가에 피어 있는 꽃으로 차를 만드는 것은 피해야 한다.","options":["(가)-(나)-(라)-(다)","(가)-(라)-(나)-(다)","(다)-(라)-(가)-(나)","(다)-(가)-(라)-(나)"],"answer":1,"explain":"✅ <b>① (가)-(나)-(라)-(다)</b>: тема (всё больше пьют цветочный чай) → причина (успокаивает, «때문이다») → «그런데» оговорка (нельзя придорожные цветы) → вывод (используйте чисто выращенные).<br>🧩 Связки-указатели: «때문이다» отсылает к предыдущему утверждению; «그런데» вводит оговорку."},{"n":14,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 이불을 세탁해서 밖에 널어 두고 장을 보러 나갔다.\n(나) 비가 오는 것을 보고 이웃이 대신 이불을 걷어 준 것이었다.\n(다) 갑자기 비가 내려서 이불이 걱정되어 집으로 서둘러 돌아왔다.\n(라) 도착해 보니 이불을 보관하고 있다는 메모가 문 앞에 붙어 있었다.","options":["(가)-(다)-(나)-(라)","(가)-(다)-(라)-(나)","(다)-(나)-(가)-(라)","(다)-(라)-(가)-(나)"],"answer":2,"explain":"✅ <b>② (가)-(다)-(라)-(나)</b>: постирал и развесил, ушёл за покупками → вдруг дождь, забеспокоился, вернулся → у двери записка «храню одеяло» → оказалось, сосед снял его вместо хозяина.<br>🧩 «것이었다» в (나) — итоговое объяснение, поэтому стоит в конце."},{"n":15,"points":2,"instr":"Выберите правильный порядок предложений.","passage":"(가) 회의 결과 쓰레기 주소 실명제를 실시하기로 의견을 모았다.\n(나) 시청 직원들이 쓰레기를 줄이는 방안에 대해 회의를 열었다.\n(다) 그러나 주민들은 개인 정보 유출 가능성 때문에 반대하고 있다.\n(라) 주소를 써서 버리면 책임 의식이 생길 것이라고 보았기 때문이다.","options":["(가)-(나)-(다)-(라)","(가)-(다)-(나)-(라)","(나)-(가)-(라)-(다)","(나)-(라)-(가)-(다)"],"answer":3,"explain":"✅ <b>③ (나)-(가)-(라)-(다)</b>: сотрудники мэрии собрали совещание → итог: ввести «адресную систему» → причина (адрес создаёт чувство ответственности, «때문이다») → «그러나» жители против из-за утечки данных.<br>🧩 (나) задаёт ситуацию, (라) объясняет решение из (가), (다) с «그러나» — контраргумент в конце."},{"n":16,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"악보 없이 공연하는 것은 피아니스트들의 오랜 전통이다. 이에 대해 일부 사람들은 악보를 외우는 것보다는 (        ) 시간을 써야 한다고 말한다. 그러나 악보를 외우면 작곡가를 좀 더 이해하게 되어 결국 작품에 대한 표현력이 풍성해질 수 있다.","options":["전통을 이해하는 데에","표현력을 높이는 데에","공연을 기획하는 데에","장단점을 설명하는 데에"],"answer":2,"explain":"Часть людей: вместо заучивания нот лучше тратить время на ( ). Контраст «그러나 … 표현력이 풍성해질 수 있다» подсказывает противопоставление по выразительности.<br>✅ <b>② 표현력을 높이는 데에</b> (на повышение выразительности).<br>✖️ ① понимание традиции, ③ планирование концерта, ④ объяснение плюсов и минусов — не образуют контраста с «외우면 … 표현력».<br>🧩 -는 데에 시간을 쓰다 = «тратить время на (что-то)»."},{"n":17,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"자신에게 필요하지 않은 물건을 봉사단체에 기증하는 시민들이 늘고 있다. 그런데 이러한 물건 중에 (        ) 많다. 그래서 쓸 만한 물건을 골라내는 데 많은 인력과 비용이 소모된다. 물건을 기증할 때에는 다른 사람들이 다시 사용할 것이라는 점을 고려해야 할 것이다.","options":["구입하기 어려운 것이","보관이 쉽지 않은 것이","재사용하기 곤란한 것이","용도가 다양하지 않은 것이"],"answer":3,"explain":"Дальше: «쓸 만한 물건을 골라내는 데 인력과 비용이 소모» и «다시 사용할 것이라는 점을 고려» — значит среди пожертвованного много непригодного для повторного использования.<br>✅ <b>③ 재사용하기 곤란한 것이</b> (того, что трудно использовать заново).<br>✖️ ① что трудно купить, ② что трудно хранить, ④ что не универсально — не объясняют затраты на отбор «쓸 만한 물건».<br>🧩 기증 = «дарение, пожертвование»; 소모되다 = «расходоваться»."},{"n":18,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"한 가전 업체에서 옷을 태우지 않는 다리미를 내놓았다. 작동 원리는 다림질하다 손을 떼면 다리미 밑판 앞뒤에서 다리가 튀어나와 옷과 다리미 사이에 간격이 생기는 방식이다. 다리미를 다시 잡으면 다리가 들어간다. 별것 아닌 듯한 이 다리미에 시장의 반응은 뜨거웠다. 많은 사람들이 고민하던 (        ) 때문이다.","options":["가격을 저렴한 수준으로 낮추었기","모양을 적절한 방법으로 바꾸었기","내용을 합리적인 방식으로 설명했기","문제를 새로운 아이디어로 해결했기"],"answer":4,"explain":"Утюг, который не прожигает одежду (выдвижные ножки) — решена давняя проблема (прожог) свежей идеей.<br>✅ <b>④ 문제를 새로운 아이디어로 해결했기</b> (решил проблему новой идеей).<br>✖️ ① снизил цену, ② изменил форму, ③ удачно объяснил — рынок отреагировал именно на остроумное решение проблемы прожога.<br>🧩 -기 때문이다 = «потому что…»; 내놓다 = «выпустить (товар)»."},{"n":19,"points":2,"instr":"Выберите подходящее слово для пропуска ( ).","passage":"요즘 아빠들은 아이들에게 친구 같은 존재가 되고 싶어한다. (        ) 아이가 어릴 때는 친구 같은 아빠가 필요하다. … 그런데 아이의 인성이 완성되는 청소년기에는 「권위 있는 아빠」의 역할도 중요하다.","options":["반면","물론","차라리","그러면"],"answer":2,"explain":"«( ) когда ребёнок мал, нужен папа-друг … 그런데 в подростковом возрасте важна и роль авторитетного отца». Связка вводит уступку «конечно, … но…».<br>✅ <b>② 물론</b> (конечно) — парно с последующим «그런데».<br>✖️ ① 반면 (с другой стороны), ③ 차라리 (уж лучше), ④ 그러면 (тогда) — не дают связку «물론 … 그런데».<br>🧩 물론 ~ 그런데 = «разумеется …, однако …»."},{"n":20,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"요즘 아빠들은 아이들에게 친구 같은 존재가 되고 싶어한다. 물론 아이가 어릴 때는 친구 같은 아빠가 필요하다. 서로 사랑하는 마음을 표현하는 과정을 통해 부모와 자식 간의 신뢰가 깊어질 수 있기 때문이다. 그런데 아이의 인성이 완성되는 청소년기에는 「권위 있는 아빠」의 역할도 중요하다. 아빠의 권위 있는 말과 행동은 아이의 삶에 판단 기준이 되어 아이가 바른 길로 가는 데 도움을 줄 수 있기 때문이다.","options":["아이들은 자기 스스로 인성을 완성할 수 있다.","청소년기에는 친구 같은 아빠의 역할이 더 중요하다.","친구 같은 아빠는 아이가 바른 길로 가도록 도움을 준다.","권위 있는 아빠는 아이에게 삶의 판단 기준을 제시할 수 있다."],"answer":4,"explain":"✅ <b>④ Авторитетный отец задаёт ребёнку критерии оценки в жизни.</b> — «권위 있는 말과 행동은 … 판단 기준이 되어».<br>✖️ ① ребёнок сам формирует характер — нет, важна роль отца, ② в подростковом возрасте важнее папа-друг — наоборот, авторитетный, ③ «бар길» помогает папа-друг — это про авторитетного отца.<br>🧩 판단 기준 = «критерий суждения»."},{"n":21,"points":2,"instr":"Выберите подходящее выражение для пропуска ( ).","passage":"최근 동물 대신 식물을 키우려는 사람들이 늘고 있다. … 또한 식물은 이웃과 (        ) 지내는 많은 현대인들에게 외로움을 달래 주거나 정서적으로 위안을 주기도 한다.","options":["담을 쌓고","못을 박고","머리를 맞대고","고개를 숙이고"],"answer":1,"explain":"Смысл — современники, живущие «отгородившись» от соседей, страдают от одиночества.<br>✅ <b>① 담을 쌓고</b> — идиома 담을 쌓다 = «возвести стену, прекратить общение».<br>✖️ ② 못을 박다 — «вбить гвоздь / сказать резко», ③ 머리를 맞대다 — «собраться вместе, обсуждать», ④ 고개를 숙이다 — «склонить голову» — по смыслу не подходят.<br>🧩 이웃과 담을 쌓고 지내다 = «жить, отгородившись от соседей»."},{"n":22,"points":2,"instr":"Выберите главную мысль текста.","passage":"최근 동물 대신 식물을 키우려는 사람들이 늘고 있다. 동물은 돌보려면 많은 시간과 비용이 드는 데 비해 식물은 키우기도 쉽고 실내 공기도 깨끗하게 해 준다. 또한 식물은 이웃과 담을 쌓고 지내는 많은 현대인들에게 외로움을 달래 주거나 정서적으로 위안을 주기도 한다. 이처럼 식물을 삶의 동반자로 생각하는 사람들이 늘면서 「반려식물」이라는 신조어까지 생겼다.","options":["동물을 돌보는 데에 시간과 비용이 많이 든다.","삶의 반려자로 식물을 찾는 사람들이 늘고 있다.","식물을 키우면 실내 공기를 깨끗하게 할 수 있다.","정서적 안정을 위해 반려동물을 키우는 것이 좋다."],"answer":2,"explain":"✅ <b>② Всё больше людей выбирают растения как спутника жизни.</b> — вывод «삶의 동반자 … 「반려식물」이라는 신조어».<br>✖️ ① затраты на животных, ③ растения очищают воздух — это лишь доводы, ④ ради покоя держать домашних <b>животных</b> — наоборот, речь о растениях.<br>🧩 반려식물 = «растение-компаньон» (по аналогии с 반려동물)."},{"n":23,"points":2,"instr":"Выберите чувство героини («나») в подчёркнутой части.","passage":"계산원으로 일하러 오라는 소식을 듣고 고민에 빠졌다. … 일을 시작한 첫날, 아침부터 밀려드는 손님들로 인해 등에서 땀이 흘렀다. 모든 게 미숙했다. … 외국인 손님이 왔을 때였다. 서투른 영어를 총동원해서 말을 건네려고 하자, 그가 <u>\"봉투 하나 주세요.\"라며 한국말을 하는 게 아닌가.</u> 순간 놀라면서도 속으로 웃음이 났다.","options":["짜증스럽다","실망스럽다","불만스럽다","당황스럽다"],"answer":4,"explain":"Героиня, собрав весь свой ломаный английский, вдруг слышит от иностранца чистое корейское «봉투 하나 주세요» — застигнута врасплох.<br>✅ <b>④ 당황스럽다</b> (растеряна, смущена) — «순간 놀라면서도».<br>✖️ ① 짜증스럽다 (раздражена), ② 실망스럽다 (разочарована), ③ 불만스럽다 (недовольна) — ситуация скорее забавная («속으로 웃음이 났다»), а не злая.<br>🧩 -는 게 아닌가 = «как вдруг (оказывается)…» — выражение неожиданности."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"계산원으로 일하러 오라는 소식을 듣고 고민에 빠졌다. 마흔을 넘은 늦은 나이 때문이었다. 격려해 주는 남편 덕분에 용기를 냈다. … 신입 직원 교육을 받는데 주의 사항을 수첩에 적어 가며 외워도 금방 잊어버리기 일쑤였다. … 일을 시작한 첫날 … 외국인 손님이 왔을 때 … 그가 한국말을 하는 게 아닌가.","options":["나는 남편의 격려 덕분에 계산 실력이 늘었다.","나는 외국인 손님이 왔을 때 영어로 대화했다.","나는 늦은 나이였지만 용기를 내어 일을 시작했다.","나는 신입 직원 교육을 받을 때 수첩을 잃어버렸다."],"answer":3,"explain":"✅ <b>③ Несмотря на немолодой возраст, я набралась смелости и начала работать.</b> — «마흔을 넘은 … 남편 덕분에 용기를 냈다».<br>✖️ ① благодаря мужу выросло мастерство счёта — не сказано, ② говорила с иностранцем по-английски — он ответил по-корейски, ④ потеряла блокнот — наоборот, записывала в него (수첩에 적어 가며).<br>🧩 용기를 내다 = «набраться смелости»."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 한류 배우 인기 폭발, 해외 광고 요청 줄 이어","options":["한류 배우는 떨어진 인기로 해외 광고에 출연할 기회가 줄어들었다.","한류 배우가 인기를 끌기 위해서는 해외 광고에 많이 출연해야 한다.","한류 배우는 인기에 상관없이 해외에서 광고 출연 요청을 받고 있다.","한류 배우가 큰 인기를 얻으면서 해외 광고 출연 요청이 잇따르고 있다."],"answer":4,"explain":"«Популярность звезды халлю взлетела — поток запросов на зарубежную рекламу».<br>✅ <b>④ С ростом популярности предложения сниматься в зарубежной рекламе следуют одно за другим.</b><br>✖️ ① упавшая популярность, ② чтобы стать популярным, нужно сниматься, ③ независимо от популярности — все искажают связь «인기 폭발 → 광고 요청 줄 이어».<br>🧩 줄(을) 잇다 = «следовать чередой, не прекращаться»."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 황금연휴, 여행 업계 오랜만에 웃어","options":["긴 연휴로 여행 업계가 오랜만에 활기를 찾았다.","짧은 연휴에도 여행을 하려는 사람이 여전히 많다.","연휴가 길지 않아 여행을 예약하는 사람이 많지 않다.","연휴 기간 동안 업계는 만족할 만한 여행 상품을 준비했다."],"answer":1,"explain":"«Золотые длинные выходные — туриндустрия наконец улыбнулась».<br>✅ <b>① Из-за длинных праздников турбизнес впервые за долгое время оживился.</b> — «웃어» = дела пошли хорошо.<br>✖️ ② короткие выходные, ③ выходные недлинные — противоречат «황금연휴» (длинные), ④ про подготовку турпродуктов — заголовок про оживление спроса.<br>🧩 황금연휴 = «золотые (длинные) праздники»; 활기를 찾다 = «ожить»."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет газетный заголовок.","passage":"📰 배추 생산 과잉, 농민들 한숨","options":["배추의 생산량이 부족하여 농민들이 실망했다.","배추 농사가 잘 되어 농민들이 희망에 차 있다.","배추가 적게 생산되어 농민들의 기대감이 낮아졌다.","배추가 필요 이상으로 생산되어 농민들이 힘들어한다."],"answer":4,"explain":"«Перепроизводство пекинской капусты — фермеры вздыхают».<br>✅ <b>④ Капусты произведено сверх нужного, и фермерам тяжело.</b> — 과잉 (избыток) + 한숨 (вздох) = цены падают.<br>✖️ ① и ③ — про нехватку (반대), ② урожай хорош, фермеры полны надежд — «한숨» говорит об обратном.<br>🧩 과잉 = «избыток, перепроизводство»; 한숨(을) 쉬다 = «вздыхать (от досады)»."},{"n":28,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"아이에게 맞는 색이 있다. 그래서 색을 (        ) 활용하는 것이 좋다. 예를 들어 소극적인 아이에게는 밝고 따뜻한 색으로 방을 꾸며 주는 것이 좋다. … 반대로 아이의 성격이 공격적이라면 초록색이 잘 맞는다. 초록색은 … 마음을 차분하게 가라앉혀 줄 수 있다.","options":["방의 구조에 맞게","장식에 따라 다르게","아이의 성향에 맞게","그림의 특성이 나타나게"],"answer":3,"explain":"Примеры (пассивному — тёплые цвета, агрессивному — зелёный) показывают: цвет подбирают под характер ребёнка.<br>✅ <b>③ 아이의 성향에 맞게</b> (в соответствии со складом ребёнка).<br>✖️ ① под структуру комнаты, ② по-разному в зависимости от декора, ④ так, чтобы проявились черты рисунка — не объясняют примеры про 소극적/공격적.<br>🧩 성향 = «склонность, темперамент»."},{"n":29,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"각 분야의 (        ) 「사람도서관」이 등장해 화제다. 사람도서관은 표현 그대로 사람을 책처럼 대출할 수 있는 도서관이다. 도서관이 전문적인 지식과 경험을 가진 사람을 「사람책」으로 등록하면 독자는 관심 있는 분야의 사람책을 대출하면 된다.","options":["전문가를 활용하는","전문가를 양성하는","기술자를 교육하는","기술자를 파견하는"],"answer":1,"explain":"«Человек-книга» = регистрируют людей с профессиональными знаниями, читатель их «берёт напрокат» → библиотека ИСПОЛЬЗУЕТ экспертов.<br>✅ <b>① 전문가를 활용하는</b> (использующая специалистов).<br>✖️ ② воспитывающая экспертов, ③ обучающая техников, ④ командирующая техников — нет ни обучения, ни подготовки, лишь «대출» уже готовых знатоков.<br>🧩 활용하다 = «задействовать, использовать (по назначению)»."},{"n":30,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"보통 소비자들은 「햄버거 1개가 550칼로리를 함유하고 있다」는 것의 의미를 정확하게 이해하지 못한다. … 그러나 햄버거 겉면에 「햄버거 1개를 먹을 경우 9km 정도 달려야 한다」고 쓰여 있다면 … 열량이 어느 정도인지 체감하게 될 것이다. 이처럼 식품의 겉면에 열량을 소모하기 위해 (        ) 하는지 표시하면 소비자들의 음식에 대한 생각을 변화시킬 수 있을 것이다.","options":["무슨 음식을 선택해야","얼마나 몸을 움직여야","어떤 행동에 신중해야","언제 열량에 신경 써야"],"answer":2,"explain":"Пример «надо пробежать 9 км» показывает: на упаковке указывают, СКОЛЬКО нужно двигаться, чтобы сжечь калории.<br>✅ <b>② 얼마나 몸을 움직여야</b> (сколько надо двигаться).<br>✖️ ① какую еду выбрать, ③ в каких действиях быть осторожным, ④ когда следить за калориями — не соответствуют примеру про «9 км бега».<br>🧩 열량을 소모하다 = «сжигать калории»; 체감하다 = «ощущать на себе»."},{"n":31,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"기한이 정해져 있는 티켓의 경우 기간이 지나면 사용하지 못하게 된다. 그런데 기한이 얼마 남지 않은 티켓이라도 모바일 시장을 이용하면 판매할 수 있다. … 이 시장을 통해 판매자는 기간이 지나면 (        ) 상품을 판매할 수 있고, 소비자는 필요한 시점에 싼 가격으로 상품을 구매할 수 있는 것이다.","options":["가치가 사라지는","가격이 올라가는","수요가 많아지는","생산이 줄어드는"],"answer":1,"explain":"Билет после срока бесполезен → продавец сбывает товар, который по истечении срока ТЕРЯЕТ ценность.<br>✅ <b>① 가치가 사라지는</b> (теряющий ценность).<br>✖️ ② дорожает, ③ растёт спрос, ④ сокращается производство — противоречат сути «기간이 지나면 사용하지 못하게 된다».<br>🧩 가치가 사라지다 = «ценность исчезает»; 기한 = «срок годности/действия»."},{"n":32,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"동물원의 동물들은 빠른 번식으로 인해 개체 수 조절이 어렵다. 그러다 보면 한정된 공간에 너무 많은 동물들이 함께 있게 되어 스트레스를 많이 받게 된다. 그래서 서울의 한 동물원에서는 사자의 개체 수를 줄이기 위해 … 낙타를 들여오는 방법을 썼다. 그 결과 개체 수가 줄어든 사자들은 스트레스를 덜 받게 되었다. …","options":["동물원의 동물들은 번식으로 개체 수를 조절한다.","동물원 간의 교류를 통해 동물의 개체 수를 늘린다.","서식 환경 개선을 위해 많은 새로운 동물을 들여와야 한다.","좁은 공간에 개체 수가 많으면 동물의 스트레스가 증가한다."],"answer":4,"explain":"✅ <b>④ В тесном пространстве при большом числе особей у животных растёт стресс.</b> — «한정된 공간에 너무 많은 동물 … 스트레스를 많이».<br>✖️ ① размножением регулируют число — наоборот, размножение мешает регулировать, ② обмен увеличивает число — наоборот, сокращает, ③ надо ввозить много новых животных — речь о замене, а не о наращивании.<br>🧩 개체 수 = «численность особей»; 번식 = «размножение»."},{"n":33,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 … 집에서의 휴식을 중요하게 생각하는 사람들이 늘고 있다. 이러한 사람들은 휴식의 편의를 위해 거실이나 욕실을 새롭게 고쳐 쓰는 등 집을 휴식의 공간으로 꾸미는 데 관심이 많다. 그리고 … 고가의 안락의자나 침대를 구입하는 데도 지출을 아끼지 않는다. …","options":["사람들은 휴식의 질보다는 휴식의 편의를 추구한다.","휴식을 위해 여행을 떠나는 사람들이 증가하고 있다.","사람들은 가구를 구입하는 데에 큰 비용을 들이지 않는다.","휴식을 위해 집의 공간을 고쳐 쓰는 사람들이 많아지고 있다."],"answer":4,"explain":"✅ <b>④ Всё больше людей переделывают пространство дома ради отдыха.</b> — «거실이나 욕실을 새롭게 고쳐 쓰는».<br>✖️ ① гонятся за удобством, а не качеством — текст про «질 높은 휴식», ② уезжают в путешествия — наоборот, отдыхают дома, ③ не тратятся на мебель — наоборот, «지출을 아끼지 않는다».<br>🧩 지출을 아끼지 않다 = «не жалеть денег»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"문화와 역사적 가치가 높지만 국가에서 관리하지 못하고 있는 토지, 자연, 건물 등이 많이 있다. 이를 관리하고 보존하려는 시민운동이 새롭게 시작되고 있다. … 시민들이 자발적으로 모금에 나선 것이다. 이러한 시민의 노력으로 최근 희귀식물인 「매화마름」이 보존되는 등 가시적인 성과가 나타나고 있다. …","options":["시민들은 국가의 지원을 받아 모금 활동을 했다.","시민들이 국가 토지 관리에 적극 참여하고 있다.","시민들이 역사적 가치가 높은 자산을 보존하기 시작했다.","시민운동이 희귀식물 보존에까지는 미치지 못하고 있다."],"answer":3,"explain":"✅ <b>③ Граждане начали сохранять активы высокой исторической ценности.</b> — «보존하려는 시민운동이 새롭게 시작».<br>✖️ ① собирали деньги при господдержке — наоборот, «자발적으로», ② участвуют в гос. управлении землёй — нет, действуют сами, ④ движение не дотягивает до сохранения редких растений — наоборот, «매화마름이 보존되는» (уже есть результат).<br>🧩 자발적으로 = «по собственной инициативе»; 모금 = «сбор средств»."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"유무선의 통신 수단이 없던 시대에 위급한 상황이 생기면 불이나 연기로 정보를 주고받았다. … 이 방법은 비, 구름, 안개 등의 기상 상태에 영향을 받는다는 문제점이 있었다. 그러나 이러한 한계에도 불구하고 당시에는 국가적인 긴급 상황에 대처하는 데 중요한 역할을 담당했다.","options":["불이나 연기는 위험 상황을 알리는 주요 통신 수단이었다.","불이나 연기를 쓰는 통신 수단은 날씨의 영향을 많이 받았다.","긴급 상황에는 날씨에 따라 다섯 단계로 나누어 연기를 피웠다.","과거의 통신 수단으로는 국가적 긴급 상황에 대처하기 어려웠다."],"answer":1,"explain":"Тема (주제) — итог: огонь и дым были важнейшим средством оповещения об опасности.<br>✅ <b>① Огонь и дым были основным средством связи для оповещения об опасности.</b><br>✖️ ② зависимость от погоды — это лишь «문제점» (деталь), ③ деление на 5 ступеней — деталь, ④ справляться было трудно — текст подчёркивает «중요한 역할을 담당했다» (играли важную роль).<br>🧩 -에도 불구하고 = «несмотря на…»; различайте тему и второстепенный факт."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"숫자 활용 능력은 비즈니스 성패에 중요한 영향을 끼친다. … 신제품 발표회에서 숫자를 활용한 데이터를 제시하면 고객에게 신뢰감을 줄 수 있고, 이 신뢰를 바탕으로 경쟁에서 유리한 위치를 차지할 수 있는 것이다. 비즈니스에서 성공하고 싶다면 숫자 활용 감각을 키우라고 제안하는 이유가 바로 여기에 있다.","options":["숫자를 활용하는 능력은 비즈니스 현장에서 배워야 한다.","매출 실적을 높이기 위해 숫자를 체계적으로 정리해야 한다.","신제품 발표회에서는 제품의 우수성을 데이터로 제시해야 한다.","성공적인 비즈니스를 위해 숫자를 잘 활용하는 연습을 해야 한다."],"answer":4,"explain":"Тема — призыв: для успеха в бизнесе развивайте умение работать с числами.<br>✅ <b>④ Для успешного бизнеса нужно тренировать умение хорошо использовать числа.</b> — «숫자 활용 감각을 키우라».<br>✖️ ① учиться этому на рабочем месте, ② систематизировать числа ради продаж, ③ показывать достоинства товара данными — это частности, а не главный посыл.<br>🧩 성패 = «успех или провал»; 감각을 키우다 = «развивать чутьё»."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"혼자 사는 사람들이 많아지면서 외로움을 이겨내는 「고독력」이 주목을 끌고 있다. 고독력이란 홀로 있는 시간을 즐기고 창의적으로 활용하는 능력을 말한다. 이러한 능력을 기르기 위해서는 … 외로움과 마주 서는 연습을 해야 한다. … 따라서 무엇보다 외로움을 두려워하지 않는 태도가 우선되어야 한다.","options":["남의 시선이 두려워 홀로 지내면 우울증에 걸릴 수 있다.","혼자 사는 것이 시간을 창의적으로 활용할 수 있는 방법이다.","고독력을 기르기 위해서는 외로움을 받아들이는 연습이 필요하다.","혼자 사는 사람들은 분노와 적개심이 쌓이는 것을 주의해야 한다."],"answer":3,"explain":"Тема — как развивать «고독력»: учиться принимать одиночество, не боясь его.<br>✅ <b>③ Чтобы развить «силу одиночества», нужна практика принятия одиночества.</b> — «외로움과 마주 서는 연습».<br>✖️ ① можно заболеть депрессией, ④ копятся гнев и враждебность — это риски-детали, ② одиночное проживание — способ творчества — частное утверждение.<br>🧩 고독력 = «способность переносить/использовать одиночество»."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"일반적으로 공짜로 끼워 주는 경품이 있을 경우 소비자들은 구매의 유혹을 더 받게 된다. 그러나 때로 무료 경품은 판매에 도움이 되기보다 오히려 역효과를 낼 수도 있다. … 소비자들은 공짜로 주는 물건은 별 가치가 없다고 생각하기도 한다. 이런 인식은 … 판매에도 부정적인 영향을 미칠 수 있다.","options":["소비자들은 무료로 주는 경품의 품질을 믿지 않는다.","무료 경품이 제품 판매에 나쁜 영향을 줄 수도 있다.","소비자들은 보통 무료 경품이 있는 제품을 선호한다.","무료 경품 때문에 제품 가격이 비합리적으로 책정된다."],"answer":2,"explain":"Тема — бесплатные подарки иногда вредят продажам.<br>✅ <b>② Бесплатные подарки могут негативно влиять на продажи.</b> — «역효과를 낼 수도 있다 … 판매에도 부정적인 영향».<br>✖️ ① не доверяют качеству подарка — частный факт, ③ предпочитают товары с подарком — это вводная мысль, опровергаемая далее, ④ из-за подарка цена нерациональна — лишь следствие-деталь.<br>🧩 역효과 = «обратный эффект»."},{"n":39,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"옛날에는 책을 눈으로만 읽지 않고 몸을 움직이며 가락에 맞추어 소리 높여 읽었다. (㉠) 그런데 현대 정보화 사회에 이르러서는 독서 방식이 획기적으로 변하였다. (㉡) 다 같이 소리를 내서 읽는 방식 대신 혼자 읽는 방식을 선호하게 되었다. (㉢) 다양한 연결망을 통해 개인적으로 읽을 글을 선택·변경하고, 자유롭게 영역을 이동하는 검색형 독서 방식이 생겨난 것이다. (㉣) 이와 같이 시대에 따라 독서의 방식은 변화한다.\n\n<보기> 또한 글의 흐름에 따라 처음부터 끝까지 순서대로 읽던 과거의 독서 방식도 바뀌고 있다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기> начинается с «또한» (к тому же) и говорит, что меняется и линейное чтение «по порядку». Логично перед предложением про «검색형 독서» (нелинейное, поисковое чтение), которое это иллюстрирует.<br>✅ <b>③ ㉢</b> — после смены «вслух → про себя» и перед раскрытием «검색형 독서».<br>🧩 «또한» = маркер добавления ещё одного аспекта того же изменения."},{"n":40,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"소설가 김병용 씨가 … 산문집 「길 위의 풍경」을 펴냈다. (㉠) 작가는 길이 자신과 세상을 이어 주는 통로이며 … 자신도 변화하고 성장한다고 말한다. (㉡) 여기에서 소개하는 길을 따라 그곳 사람들의 … 일상을 들여다보고 있으면 포기하고 좌절했던 나의 모습들이 부끄러워진다. (㉢) 길이 주는 떨림을 느끼면서 … 변화·성장하고 싶다면 주저 없이 이 책을 읽기를 권한다. (㉣)\n\n<보기> 그리고 깨닫지 못하는 사이에 다시 일어나 걸을 수 있는 용기를 받는다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기> с «그리고» добавляет: «и незаметно получаешь смелость снова встать и идти». Идёт сразу после «좌절했던 나의 모습들이 부끄러워진다» (㉢) — пристыжённость сменяется обретённой смелостью.<br>✅ <b>③ ㉢</b>.<br>🧩 «그리고 … 용기를 받는다» логически продолжает эмоциональный отклик читателя."},{"n":41,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"어떤 역사적 사건이나 실존 인물의 실화에 작가의 상상력을 보태어 새로운 이야기로 풀어내는 글쓰기 방식이 있다. (㉠) 사실과 허구가 결합되는 이런 방식은 처음에는 주로 소설 쓰기의 한 기법으로 사용되었는데 이제는 영화, 드라마 등 대중문화계 전체로 확산되어 큰 인기를 끌고 있다. (㉡) 그런데 한편에서는 역사적 사실에 허구를 덧붙이는 것에 대해 우려를 표시하고 있다. (㉢) 상상력으로 표현된 허구를 실제 역사라고 믿을 수 있기 때문이다. (㉣)\n\n<보기> 딱딱한 역사를 허구가 더해진 이야기로 풀어내 쉽고 재미있게 대중들에게 다가갈 수 있었던 것이다.","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"<보기> объясняет ПРИЧИНУ популярности: «сухую историю подали как занимательную историю с вымыслом — и она легко дошла до публики». Ставится сразу после «큰 인기를 끌고 있다» (㉡), до «그런데 … 우려» (поворот).<br>✅ <b>② ㉡</b>.<br>🧩 <보기> раскрывает «큰 인기» перед противопоставлением «그런데»."},{"n":42,"points":2,"instr":"Выберите чувство отца в подчёркнутой части.","passage":"… \"올 테냐?\" 수화기 저편의 아버지가 내 대답을 기다렸다. … 머릿속은 오늘 일정들을 체크해 보느라 분주하게 움직였다. … \"눈이 많이 오네요, 아버지.\" 수화기 저편의 아버지 목소리에서 힘이 빠졌다. <u>\"못 오겠냐아?\"</u> 이번에는 내 몸에서 힘이 빠졌다. 당신과 뜻이 달라 실망을 할 때면 … 힘이 빠진 목소리로 그러냐며 곧 수납 태세로 들어가는 아버지 …","options":["서운하다","억울하다","조급하다","괘씸하다"],"answer":1,"explain":"Отец надеялся, что сын приедет; услышав уклончивое «много снега», он упавшим голосом спрашивает «못 오겠냐아?» — он огорчён и задет.<br>✅ <b>① 서운하다</b> (обиженно-грустно, досадно от разочарования).<br>✖️ ② 억울하다 (несправедливо обижен), ③ 조급하다 (нетерпелив), ④ 괘씸하다 (возмутительно-обидно на чьё-то поведение) — слишком резкие; здесь тихое разочарование («힘이 빠진 목소리»).<br>🧩 서운하다 = «грустно и обидно оттого, что не оправдалось ожидание»."},{"n":43,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"낙천이 아저씨가 돌아가셨다는 소식을 … 아버지에게서 듣는 순간 … 아버지가 \"올 테냐?\" 하고 물었다. … 지금 열한 시. K와 점심. 한 시 부서 회의. 세 시에 전체 회의. … 여섯 시에는 인터뷰 약속이 잡혀 있었다. … \"눈이 많이 오네요, 아버지.\"","options":["눈이 많이 오자 아버지는 내가 걱정돼서 전화를 하셨다.","나는 오늘 일이 많아서 시골집에 가는 것이 망설여진다.","나는 지난 가을 시골집에 갔을 때 낙천 아저씨를 만났다.","낙천 아저씨가 돌아가셨다는 소식에 나는 몸에 힘이 빠졌다."],"answer":2,"explain":"✅ <b>② У меня сегодня много дел, поэтому я колеблюсь, ехать ли в деревню.</b> — герой перебирает плотное расписание (обед, совещания, интервью).<br>✖️ ① отец позвонил из-за снега, тревожась за меня — звонил он о смерти 낙천 아저씨, ③ прошлой осенью встретил 낙천 아저씨 — наоборот, не зашёл (о чём сожалеет), ④ силы покинули из-за вести о смерти — силы «빠졌다» от упавшего голоса отца.<br>🧩 망설여지다 = «колебаться, не решаться»."},{"n":44,"points":2,"instr":"Выберите главную тему текста.","passage":"추상 활동이란 어떤 대상의 특성을 뽑아내어 파악하는 활동이다. 이러한 추상 활동은 피카소의 창작 과정을 통해 쉽게 이해할 수 있다. 피카소는 「황소」 연작물을 시작했을 때 제일 먼저 황소의 모습을 주의 깊게 살펴보고 이를 바탕으로 … 사실적으로 묘사했다. 그러다가 … 간단한 외곽선 몇 개로 황소를 그렸다. … 마지막에 가서는 … 머리의 특징을 잡아내어 강조했다. …","options":["추상 활동은 관찰을 바탕으로 대상을 이해하는 것이다.","추상 활동은 외관의 세부적 기술에서 시작되는 것이다.","추상 활동의 단계는 추상화의 창작 과정에 잘 나타난다.","추상 활동의 결과에는 대상의 새로운 측면이 드러난다."],"answer":1,"explain":"Определение в начале: абстрагирование — это «выделить особенности объекта и понять его»; Пикассо сперва «주의 깊게 살펴보고» (внимательно наблюдает).<br>✅ <b>① Абстрагирование — это понимание объекта на основе наблюдения.</b><br>✖️ ② начинается с детального описания внешности — это лишь первый шаг примера, ③ этапы хорошо видны в процессе — про иллюстрацию, ④ раскрываются новые стороны — не главная мысль.<br>🧩 추상(抽象) = «абстрагирование»: 뽑아내다 = «вытягивать, выделять»."},{"n":45,"points":2,"instr":"Выберите наиболее подходящее содержание для пропуска ( ).","passage":"… 피카소는 … 마지막에 가서는 황소의 몸을 이루는 요소들을 대부분 제거하고, 머리의 특징을 잡아내어 강조했다. 이 그림은 몸을 이루는 요소가 과도하게 사라졌음에도 실체를 토대로 했기 때문에 「황소다움」의 본질을 잘 보여 준다. 이처럼 추상 활동의 결과물은 (        ) 대상의 특징을 포착하는 데에서 얻어진다.","options":["본질의 왜곡을 통해","실체의 강조를 통해","형태적 단순화를 통해","사실적 묘사법을 통해"],"answer":3,"explain":"Пикассо убирает почти все детали тела и оставляет несколько линий/голову — то есть упрощает форму, схватывая суть.<br>✅ <b>③ 형태적 단순화를 통해</b> (через упрощение формы).<br>✖️ ① через искажение сути — наоборот, суть сохранена, ② через подчёркивание реальности, ④ через реалистичное изображение — это ранние стадии, а результат — в упрощении.<br>🧩 단순화 = «упрощение»; 포착하다 = «улавливать, схватывать»."},{"n":46,"points":2,"instr":"Выберите место, куда лучше всего вставить предложение из <보기>.","passage":"무인 소형 비행기 「드론」의 … 우려의 목소리에도 불구하고, 국토교통부는 최근 드론을 활용하는 신산업 분야에 투자하기로 결정하였다. (㉠) 정부에서 … 드론 산업을 적극 지원하는 이유는 … 분야가 무궁무진하기 때문이다. (㉡) 국토 조사를 비롯하여 … 여가 활동에 이르기까지 모두 드론 기술의 활용이 가능하다. (㉢) 그러나 이번 투자 결정에 따라 드론 산업이 정부 주도로 본격화됨으로써 드론의 대중화 시기가 한층 앞당겨질 것으로 기대된다. (㉣) …\n\n<보기> 이런 밝은 전망과 달리 사실 드론 산업은 드론 사용의 위험성에 대한 문제 제기로 인해 그동안 번번이 좌절을 겪어 왔다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"<보기>: «вопреки этим радужным прогнозам индустрия дронов то и дело сталкивалась с препятствиями». Ставится после перечня «светлых» применений (㉢) и перед «그러나 … 기대된다».<br>✅ <b>③ ㉢</b> — «이런 밝은 전망과 달리» подхватывает только что описанные перспективы.<br>🧩 «밝은 전망과 달리» = маркер контраста с предыдущим оптимизмом."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"… 그러나 이번 투자 결정에 따라 … 대중화 시기가 한층 앞당겨질 것으로 기대된다. 하지만 여전히 사생활 침해와 테러 위험 등의 보안 문제는 드론이 대중화되기 위해 넘어야 할 큰 산이다. 따라서 정부는 … 드론의 악용과 위험성을 최소화하는 기술에 대한 투자에도 소홀하지 않아야 한다.","options":["드론 활용 및 악용 방지 기술에 대한 투자가 병행되고 있다.","드론의 안전성 검증에 대한 필요성이 꾸준히 제기되어 왔다.","정부의 투자 결정으로 드론의 대중화를 둘러싼 논란이 잠잠해졌다.","정부가 드론 기술에 관심을 보임에 따라 드론 산업이 가속화되었다."],"answer":2,"explain":"✅ <b>② Потребность в проверке безопасности дронов поднимается постоянно.</b> — «우려의 목소리», «번번이 좌절», «보안 문제는 … 큰 산».<br>✖️ ① инвестиции в применение и в защиту идут параллельно — пока лишь «소홀하지 않아야 한다» (должны, не факт), ③ споры утихли — наоборот, «넘어야 할 큰 산», ④ индустрия уже ускорилась — пока «기대된다» (ожидается).<br>🧩 병행 = «параллельное ведение»; 제기되다 = «подниматься (о вопросе)»."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"젊은 인재들이 아이디어 하나로 세상을 바꿔 나가는 일이 거듭되면서, 미국의 실리콘밸리는 … 「창의적 기술 혁신」의 상징이 되었다. … 인주시의 경우, 첨단과학기술단지를 조성하여 … 투자 예산 확대나 세금 감면 혜택 등을 통해 창의적 기업 활동의 길을 활짝 열어 주었다. … 향후 여러 도시에서도 각자의 여건에 맞추어 창의적인 기업 활동 지원책을 마련할 필요가 있다.","options":["실리콘밸리의 주요 성장 동력을 분석하려고","기업의 역량적 활동을 지원하는 방안을 제시하려고","첨단과학 중심으로 조직된 기업 단지를 소개하려고","여건에 맞는 경제 환경 조성의 중요성을 제기하려고"],"answer":4,"explain":"Концовка-призыв: «각자의 여건에 맞추어 … 지원책을 마련할 필요가 있다» — автор поднимает важность создания экономической среды под местные условия.<br>✅ <b>④ Поднять важность создания экономической среды, отвечающей условиям.</b><br>✖️ ① анализ движущих сил Кремниевой долины, ② предложить меры поддержки фирм, ③ представить технопарк — это части, а цель — обосновать важность подхода «по условиям региона».<br>🧩 여건 = «условия, обстоятельства»; 조성하다 = «создавать, формировать»."},{"n":49,"points":2,"instr":"Выберите подходящее содержание для пропуска ( ).","passage":"… 미국의 실리콘밸리는 전 세계적으로 「창의적 기술 혁신」의 상징이 되었다. 이 모든 것이 한데 어우러져 (        ) 최적의 환경을 만들어 낸 것이다. …","options":["문화가 창출될 수 있는","실패가 용납될 수 있는","자본력이 형성될 수 있는","창의성이 발휘될 수 있는"],"answer":4,"explain":"Кремниевая долина — символ «창의적 기술 혁신» (творческих инноваций), значит среда, где может ПРОЯВЛЯТЬСЯ креативность.<br>✅ <b>④ 창의성이 발휘될 수 있는</b> (где может проявиться творческое начало).<br>✖️ ① где рождается культура, ② где допустима неудача, ③ где формируется капитал — рядом по теме, но напрямую перекликается с «창의적» именно «창의성».<br>🧩 발휘되다 = «проявляться, раскрываться (о способностях)»."},{"n":50,"points":2,"instr":"Выберите отношение автора в подчёркнутой части.","passage":"… 그런데 실리콘밸리의 모델을 한국의 여러 도시에서 다양한 형태로 적용하려는 움직임이 활발히 이루어지고 있어 <u>고무적이다</u>. 인주시의 경우 … 지역 경제 활성화와 일자리 창출에 핵심적 역할을 하고 있다. … 인주시의 첨단과학기술단지는 새로운 경제 성장 동력의 한 모델이 될 수 있을 것이다. …","options":["경제 활성화를 위한 다양한 시도의 긍정적 측면을 인정하고 있다.","경제 성장의 성공 사례가 활발히 도입되는 현상을 경계하고 있다.","경제의 성공 방식을 해외에서 찾으려는 노력에 대해 감탄하고 있다.","경제의 성공 요인을 다르게 파악하려는 자세에 대해 비판하고 있다."],"answer":1,"explain":"«고무적이다» (обнадёживающе) + «모델이 될 수 있을 것» — автор положительно оценивает разнообразные попытки оживить экономику.<br>✅ <b>① Признаёт положительную сторону разных попыток оживления экономики.</b><br>✖️ ② настороженно относится — наоборот, одобряет, ③ восхищается поиском успеха за рубежом — акцент на адаптацию под регион, а не на «иностранность», ④ критикует — тон позитивный.<br>🧩 고무적이다 = «вдохновляющий, обнадёживающий»."}]
      },
      writing: {"durationMin":50,"label":"제47회 · 쓰기 (51~54)","tasks":[{"n":51,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Это электронное письмо старшему (선배) — формальный стиль -습니다.","passage":"✉️ E-mail — 제목: 선배님, 빅토르입니다.\n선배님, 안녕하십니까? 빅토르입니다.\n부탁드릴 일이 있어 메일을 씁니다.\n제가 인터넷으로 ( ㉠ ).\n그런데 카메라가 이번 주 금요일에 배달된다고 합니다.\n제가 그날 고향에 가야 해서 카메라를 직접 받을 수 없을 것 같습니다.\n혹시 저 대신에 ( ㉡ )?\n어려운 부탁을 드려서 죄송합니다.\n그럼 답장 기다리겠습니다. 빅토르 드림","blanks":[{"slot":"㉠","model":"카메라를 주문했습니다 / 카메라를 구입했습니다 / 카메라를 샀습니다","check":"Дальше речь о том, что «카메라가 금요일에 배달된다» → ㉠ объясняет, что Виктор ЗАКАЗАЛ/КУПИЛ камеру через интернет: 주문하다/구입하다/사다 + формальное -았습니다."},{"slot":"㉡","model":"카메라를 받아 주실 수 있으십니까 / 받아 주시겠습니까","check":"«혹시 저 대신에 ( )?» — вежливая просьба получить камеру вместо него: 받아 주다 + почтительное -(으)시- + вопрос -ㄹ 수 있으십니까/-겠습니까."}]},{"n":52,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰십시오. (각 10점)","instr":"Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст — письменный стиль -ㄴ다.","passage":"사람의 손에는 눈에 보이지 않는 세균이 많다. 그래서 병을 예방하기 위해서는 자주 ( ㉠ ). 그런데 전문가들은 손을 씻을 때 꼭 ( ㉡ ). 비누 없이 물로만 씻으면 손에 있는 세균을 제대로 없애기 어렵기 때문이다.","blanks":[{"slot":"㉠","model":"손을 씻어야 한다","check":"«병을 예방하기 위해서는 자주 ( )» → надо часто МЫТЬ РУКИ: 손을 씻다 + долженствование -아야 한다. Письменный стиль -ㄴ다."},{"slot":"㉡","model":"비누를 사용해야 한다고 한다 / 비누로 씻으라고 한다","check":"«전문가들은 … 꼭 ( )» + причина «비누 없이 물로만 씻으면 …» → специалисты советуют ИСПОЛЬЗОВАТЬ МЫЛО: 비누를 사용하다/비누로 씻다, косвенная речь -다고 한다/-(으)라고 한다."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음을 참고하여 「국내 외국인 유학생 현황」에 대한 글을 200~300자로 쓰십시오. 단, 글의 제목을 쓰지 마십시오. (30점)","instr":"Опишите данные «국내 외국인 유학생 현황» (иностранные студенты в Корее) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.","image":"assets/topik2/exams/img/47-w53.png","model":"최근 국내에서 유학하는 외국인 유학생이 급증했다. 외국인 유학생 수는 2000년에 4천 명이었으나 가파른 상승세를 보이며 2016년에는 10만 명에 이르렀다. 이렇게 유학생이 증가한 원인으로는 우선 외국인들의 한국과 한국어에 대한 관심이 높아진 것을 들 수 있다. 또한 한국 대학들이 유학생을 유치하려고 노력한 것도 큰 영향을 미친 것으로 보인다. 이러한 추세가 계속 이어진다면 2023년에는 외국인 유학생이 20만 명에 이를 것으로 기대된다.","check":"① Описана динамика графика с цифрами (2000년 4천 명 → 2016년 10만 명)? ② Названы обе причины роста (관심 증가 / 대학의 유치 노력)? ③ Указан прогноз (2023년 20만 명, -(으)ㄹ 것으로 기대된다)? ④ Письменный стиль -ㄴ다, без заголовка, объём 200–300 знаков?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 주제로 하여 자신의 생각을 600~700자로 글을 쓰십시오. 단, 문제를 그대로 옮겨 쓰지 마십시오. (50점)","instr":"Эссе 600–700 знаков на тему «칭찬» (похвала). Раскройте все три вопроса задания — положительное влияние похвалы, отрицательное влияние, эффективный способ хвалить — каждый отдельным абзацем.","passage":"「칭찬은 고래도 춤추게 한다」는 말처럼 칭찬에는 강한 힘이 있습니다. 그러나 칭찬이 항상 긍정적인 영향을 주는 것은 아닙니다. 아래의 내용을 중심으로 칭찬에 대한 자신의 생각을 쓰십시오.\n• 칭찬이 미치는 긍정적인 영향은 무엇입니까?\n• 부정적인 영향은 무엇입니까?\n• 효과적인 칭찬의 방법은 무엇입니까?","model":"우리는 칭찬을 들으면 일을 더 잘하고 싶어질 뿐만 아니라 좀 더 나은 사람이 되고 싶은 마음이 든다. 그리고 자신감이 생겨 공부나 일의 성과에도 긍정적인 영향을 미친다. 그래서 자신이 가진 능력 이상을 발휘하고 싶어지는 도전 정신이 생기기도 하는 것이다. 한 마디로 말해 칭찬은 사람을 한 단계 더 발전시키는 힘을 가지고 있다.\n그런데 이러한 칭찬이 독이 되는 경우가 있다. 바로 칭찬이 상대에게 기쁨을 주는 것이 아니라 부담을 안겨 주는 경우이다. 칭찬을 들으면 그 기대에 부응해야 한다는 압박감 때문에 자신의 실력을 제대로 발휘하지 못하게 되는 일이 생기게 된다. 칭찬의 또 다른 부정적인 면은 칭찬 받고 싶다는 생각에 결과만을 중시하게 되는 점이다. 일반적으로 칭찬이 일의 과정보다 결과에 중점을 두고 행해지는 경우가 많기 때문이다.\n그래서 우리가 상대를 칭찬할 때에는 그 사람이 해낸 일의 결과가 아닌, 그 일을 해내기까지의 과정과 노력에 초점을 맞추는 것이 중요하다. 그래야 칭찬을 듣는 사람도 일 그 자체를 즐길 수 있다. 또한 칭찬을 듣고 잘 해내야 한다는 부담에서도 벗어날 수 있을 것이다. 우리는 보통 칭찬을 많이 해 주는 것이 중요하다고 생각하는데 칭찬은 그 방법 역시 중요하다는 것을 잊지 말아야 할 것이다.","check":"① Раскрыты все 3 вопроса (긍정적 영향 / 부정적 영향 / 효과적인 방법) — каждый своим абзацем? ② Есть вступление и вывод? ③ Связки уровня (뿐만 아니라, 그런데, 그래서, 또한)? ④ Письменный стиль -ㄴ다, без разговорных форм? ⑤ Объём 600–700 знаков, тема задания не переписана дословно?"}]}
    },
    52: {
      reading: {
        durationMin: 70, total: 100, label: '제52회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"해가 뜨는 것을 (        ) 아침 일찍 일어났다.","options":["보아야","보려고","보거나","보는데"],"answer":2,"explain":"«Рано встал утром, ЧТОБЫ увидеть восход солнца».<br>✅ <b>② 보려고</b> — цель «-(으)려고» (чтобы сделать).<br>✖️ ① 보아야 — «только если увидишь» (условие); ③ 보거나 — «или смотреть»; ④ 보는데 — «смотрю, но/а…» (фон).<br>🧩 -(으)려고 + главное действие = намерение, ради которого оно совершается."},{"n":2,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"무슨 일을 (        ) 열심히 하는 것이 중요하다.","options":["하든지","하도록","하다가","하더니"],"answer":1,"explain":"«КАКОЕ БЫ дело ты ни делал, важно делать его усердно».<br>✅ <b>① 하든지</b> — «-든지» после вопросительного слова (무슨) = «что бы ни…».<br>✖️ ② 하도록 — «чтобы/так, чтобы»; ③ 하다가 — «делая, переключился на…»; ④ 하더니 — «делал, и (вследствие)…».<br>🧩 무엇/무슨 + -든지 = уступка «всё равно что»."},{"n":3,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"계속 웃고 다니는 걸 보니 좋은 일이 <u>있나 보다</u>.","options":["있는 척한다","있을 뿐이다","있을 지경이다","있는 모양이다"],"answer":4,"explain":"«Раз всё время ходит улыбаясь, видимо, у него что-то хорошее».<br>✅ <b>④ 있는 모양이다</b> — «-나 보다» = «похоже/видимо», синоним «-는 모양이다» (предположение по наблюдению).<br>✖️ ① 있는 척한다 — «притворяется»; ② 있을 뿐이다 — «только и всего»; ③ 있을 지경이다 — «до такой степени, что».<br>🧩 -나 보다 / -는 모양이다 — вывод о чужой ситуации по внешним признакам."},{"n":4,"points":2,"instr":"Выберите выражение, близкое по смыслу к подчёркнутому.","passage":"다음 주가 개강이니 방학도 다 <u>끝난 거나 마찬가지이다</u>.","options":["끝난 셈이다","끝난 탓이다","끝나기 마련이다","끝나기 나름이다"],"answer":1,"explain":"«На следующей неделе начало семестра, так что каникулы, считай, уже закончились».<br>✅ <b>① 끝난 셈이다</b> — «-(으)ㄴ 거나 마찬가지이다» = «всё равно что…», синоним «-(으)ㄴ 셈이다» (фактически/считай).<br>✖️ ② 끝난 탓이다 — «по причине того, что закончились» (вина); ③ 끝나기 마련이다 — «непременно заканчиваются»; ④ 끝나기 나름이다 — «зависит от того, как закончатся».<br>🧩 -(으)ㄴ 셈이다 — «по сути, практически»."},{"n":5,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"눕는 순간 잠이 솔솔~\n아침까지 편안하게","options":["수건","침대","시계","신발"],"answer":2,"explain":"«Как только ляжешь — сон приходит~ Комфортно до самого утра».<br>✅ <b>② 침대</b> (кровать) — «눕다» (лечь), «잠» (сон), «아침까지 편안하게».<br>✖️ ① 수건 (полотенце), ③ 시계 (часы), ④ 신발 (обувь) — не связаны со сном.<br>🧩 솔솔 — звукоподражание: сон «накатывает» мягко."},{"n":6,"points":2,"instr":"Выберите, о чём этот текст (реклама).","passage":"신선한 재료! 부담 없는 가격!\n가족 모임, 단체 환영","options":["은행","식당","세탁소","편의점"],"answer":2,"explain":"«Свежие продукты! Необременительные цены! Семейные встречи, группы — добро пожаловать».<br>✅ <b>② 식당</b> (ресторан) — «재료» (ингредиенты), «가족 모임/단체» (застолья).<br>✖️ ① 은행 (банк), ③ 세탁소 (прачечная), ④ 편의점 (магазин у дома).<br>🧩 부담 없는 가격 = «цена, не бьющая по карману»."},{"n":7,"points":2,"instr":"Выберите, о чём этот текст (реклама/призыв).","passage":"푸른 숲, 맑은 강\n다 함께 지켜 가요!","options":["자연 보호","시간 절약","자리 양보","안전 관리"],"answer":1,"explain":"«Зелёные леса, чистые реки — давайте беречь их вместе!»<br>✅ <b>① 자연 보호</b> (охрана природы) — 숲(лес), 강(река), 지키다(беречь).<br>✖️ ② 시간 절약 (экономия времени), ③ 자리 양보 (уступить место), ④ 안전 관리 (контроль безопасности).<br>🧩 지켜 가다 = «продолжать оберегать»."},{"n":8,"points":2,"instr":"Выберите, о чём этот текст (объявление).","passage":"● 오후 1시까지 구매하면 그날 가져다 드립니다.\n● 주문이 많을 때는 늦어질 수 있습니다.\n(행복마트)","options":["사용 설명","배달 안내","이용 순서","교환 방법"],"answer":2,"explain":"«Купите до 13:00 — доставим в тот же день. При большом числе заказов возможна задержка. (마트 «Хэнбок»)».<br>✅ <b>② 배달 안내</b> (информация о доставке) — «가져다 드립니다» (привезём), «주문».<br>✖️ ① 사용 설명 (инструкция), ③ 이용 순서 (порядок пользования), ④ 교환 방법 (как обменять).<br>🧩 가져다 드리다 = вежл. «доставить/принести»."},{"n":9,"points":2,"instr":"Выберите вариант, совпадающий с содержанием объявления.","passage":"📚 2017 도서 신청 안내\n필요한 도서를 신청하십시오.\n▶ 신청 기간: 4월 17일(월) ~ 4월 30일(일)\n▶ 신청 방법: 도서관 홈페이지\n▶ 1인 10권 이내 신청 가능(잡지, 어학 교재 제외)\n※ 책이 도착하면 이메일로 알려 드립니다.","options":["신청할 수 없는 책 종류가 있다.","책이 도착하면 전화로 연락해 준다.","사월 한 달 동안 도서 신청을 받는다.","필요한 책은 이메일로 신청을 해야 한다."],"answer":1,"explain":"✅ <b>① Есть виды книг, которые нельзя заказать</b> — «잡지, 어학 교재 제외» (журналы и языковые учебники исключены).<br>✖️ ② Уведомляют не по телефону, а «이메일로 알려» (по эл. почте). ③ Приём заявок 17–30 апреля (≈2 недели), а не «весь апрель». ④ Способ подачи — «도서관 홈페이지» (сайт библиотеки), не e-mail.<br>🧩 -이내 = «в пределах»; 제외 = «за исключением»."},{"n":10,"points":2,"instr":"Выберите вариант, совпадающий с содержанием графика.","passage":"📊 직업 선택의 기준 (조사 대상: 20~30대 성인 남녀 15,000명)\n· 근무 조건: 48%\n· 직업의 안정성: 16%\n· 적성: 13%\n· 월급: 12%\n· 개인의 발전: 7%\n· 기타: 4%","options":["직업의 안정성을 중요하게 생각하는 사람이 가장 적다.","월급과 적성을 중요하게 생각하는 사람의 비율이 같다.","개인의 발전보다 월급을 중요하게 생각하는 사람이 더 많다.","근무 조건을 중요하게 생각하는 사람이 전체의 반을 넘는다."],"answer":3,"explain":"✅ <b>③ Людей, ценящих зарплату, больше, чем ценящих личное развитие</b> — 월급 12% > 개인의 발전 7%.<br>✖️ ① Меньше всего не «안정성» (16%), а «기타» (4%). ② 월급 12% ≠ 적성 13% — доли не равны. ④ 근무 조건 48% — не превышает половину (50%).<br>🧩 반을 넘다 = «превышать половину»."},{"n":11,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"지난 13일 인주경찰서에 편지 한 통이 배달되었다. 편지를 보낸 사람은 지난달 인주시를 방문했다가 지갑을 잃어버린 외국인 관광객 장 모 씨였다. 장 씨는 말이 통하지 않아 지갑을 찾는 데 어려움을 겪었다. 그때 한 경찰이 사진과 몸짓을 이용해 장 씨와 이야기하며 잃어버린 지갑을 찾는 데 도움을 주었다. 이에 장 씨가 고마움을 담은 감사 편지를 보낸 것이다.","options":["관광객이 경찰에게 감사하는 마음을 표현했다.","관광객이 잃어버린 지갑을 찾지 못하고 돌아갔다.","경찰이 지갑을 잃어버린 관광객에게 편지를 썼다.","경찰이 관광객의 말을 이해하지 못해 도와줄 수 없었다."],"answer":1,"explain":"Иностранный турист потерял кошелёк; полицейский с помощью фото и жестов помог найти его, и турист прислал благодарственное письмо.<br>✅ <b>① Турист выразил полиции благодарность</b> — «고마움을 담은 감사 편지를 보낸 것이다».<br>✖️ ② Кошелёк нашли (не «не нашёл»). ③ Письмо написал турист полиции, а не наоборот. ④ Полицейский смог помочь (через жесты).<br>🧩 -에 어려움을 겪다 = «испытывать трудности в чём-то»."},{"n":12,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"최근 공연을 혼자 보는 사람들이 많아졌다. 친구나 연인이 함께 보는 장르로 생각했던 뮤지컬, 연극 등도 혼자 보는 사람들이 늘어난 것이다. 한 조사 결과에 따르면 열 명 중 네 명이 혼자 공연을 관람하는 것으로 나타났다. 혼자 공연을 보는 사람들은 함께 간 사람에게 신경을 쓰지 않고 공연에만 집중할 수 있어서 좋다고 말한다.","options":["사람들은 연극과 뮤지컬을 혼자 보는 장르로 생각한다.","혼자 공연을 보면 공연에 집중할 수 있다는 장점이 있다.","사람들은 공연을 볼 때 다른 사람에게 신경을 쓰지 않는다.","조사 결과에 따르면 공연을 혼자 보는 사람들이 줄고 있다."],"answer":2,"explain":"Всё больше людей ходят на спектакли в одиночку; среди плюсов — возможность сосредоточиться на представлении.<br>✅ <b>② У просмотра в одиночку есть плюс — можно сосредоточиться на представлении</b> — «공연에만 집중할 수 있어서 좋다».<br>✖️ ① Мюзикл/театр СЧИТАЛИ жанром «для совместного просмотра» (함께 보는 장르로 생각했던). ③ Не «не обращают внимания вообще», а именно зрители-одиночки. ④ Число таких людей растёт (늘어난), а не падает.<br>🧩 열 명 중 네 명 = «4 из 10»."},{"n":13,"points":2,"instr":"Выберите вариант с правильным порядком предложений.","passage":"(가) 개와 고양이는 사이가 나쁜 것으로 유명하다.\n(나) 개가 앞발을 드는 행동은 함께 놀고 싶다는 의미이다.\n(다) 그런데 고양이는 이런 행동을 공격하는 것으로 오해하는 것이다.\n(라) 둘 사이가 안 좋은 이유는 표현을 서로 다르게 받아들이기 때문이다.","options":["(가)-(라)-(나)-(다)","(가)-(나)-(라)-(다)","(다)-(가)-(나)-(라)","(나)-(다)-(가)-(라)"],"answer":1,"explain":"✅ <b>① (가)-(라)-(나)-(다)</b>: (가) кошки и собаки знамениты плохими отношениями → (라) причина — по-разному воспринимают сигналы → (나) поднятая передняя лапа у собаки = «хочу играть» → (다) но кошка принимает это за нападение.<br>🧩 (라) даёт общую причину, (나)/(다) — конкретный пример с «그런데» (а вот) во главе (다)."},{"n":14,"points":2,"instr":"Выберите вариант с правильным порядком предложений.","passage":"(가) 시대가 변하면서 회식 문화가 바뀌고 있는 것이다.\n(나) 직장에서는 좋은 업무 분위기를 위해서 회식을 한다.\n(다) 예전에는 직장에서 회식을 할 때 주로 술을 많이 마셨다.\n(라) 그러나 요즘에는 회식 대신에 공연을 관람하거나 맛집을 탐방하는 경우가 늘고 있다.","options":["(나)-(다)-(가)-(라)","(나)-(다)-(라)-(가)","(다)-(가)-(나)-(라)","(다)-(나)-(라)-(가)"],"answer":2,"explain":"✅ <b>② (나)-(다)-(라)-(가)</b>: (나) на работе устраивают 회식 ради хорошей атмосферы → (다) раньше в основном много пили → (라) но сейчас вместо застолий ходят на спектакли/в рестораны → (가) с изменением времени меняется и культура 회식 (вывод).<br>🧩 (라) с «그러나» противопоставляет прошлому, (가) — обобщающий итог."},{"n":15,"points":2,"instr":"Выберите вариант с правильным порядком предложений.","passage":"(가) 아들은 보물을 찾기 위해 밭을 파 봤지만 아무것도 나오지 않았다.\n(나) 아들은 실망했지만 힘들게 밭을 판 것이 아까워서 밭에 씨를 뿌렸다.\n(다) 한 농부가 게으른 아들에게 밭에 보물을 숨겼다는 말을 남기고 죽었다.\n(라) 시간이 흘러 많은 열매가 맺혔고 아들은 그때서야 아버지의 뜻을 알게 되었다.","options":["(가)-(라)-(나)-(다)","(가)-(나)-(라)-(다)","(다)-(가)-(나)-(라)","(다)-(나)-(가)-(라)"],"answer":3,"explain":"✅ <b>③ (다)-(가)-(나)-(라)</b>: (다) крестьянин сказал ленивому сыну, что спрятал в поле клад, и умер → (가) сын перекопал поле, но ничего не нашёл → (나) расстроился, но, пожалев о труде, засеял поле → (라) со временем созрел богатый урожай, и тогда сын понял замысел отца.<br>🧩 Сюжет-притча: «клад» — это труд; (라) — мораль."},{"n":16,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"사람들은 일반적으로 쓴맛을 꺼린다. 이것은 (        ) 본능과 관계가 있다. 식물 중에는 독성이 있어 몸에 해로운 것들이 있다. 그런데 이런 독이 있는 식물은 보통 쓴맛이 난다. 따라서 사람들은 무의식적으로 쓴맛이 나는 것을 위험하다고 여기고 이를 거부하게 되는 것이다.","options":["지나친 과식을 피하려는","자신의 몸을 보호하려는","맛있는 음식을 멀리하려는","입맛이 변하는 것을 막으려는"],"answer":2,"explain":"Ядовитые растения обычно горькие; поэтому люди подсознательно избегают горького как опасного.<br>✅ <b>② стремление защитить собственное тело</b> — инстинкт уберечься от яда.<br>✖️ ① «избегать переедания», ③ «сторониться вкусной еды», ④ «не дать вкусу измениться» — текст об опасности яда, а не об этом.<br>🧩 -(으)려는 + 본능 = «инстинкт, направленный на то, чтобы…»."},{"n":17,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"대화를 원활하게 하기 위해서는 상대방에게 내가 그의 말을 잘 듣고 있다는 느낌을 주어야 한다. 이때 (        ) 행동을 하면 좋다. 대부분의 나라에서 이런 행동은 긍정을 나타낸다. 따라서 머리를 위아래로 움직이는 행동을 하면 상대방을 존중하고 이야기에 공감하고 있다는 인상을 줄 수 있다.","options":["손뼉을 치는","고개를 끄덕이는","질문하면서 듣는","들으면서 기록하는"],"answer":2,"explain":"Подсказка прямо в тексте: «머리를 위아래로 움직이는 행동» (двигать головой вверх-вниз) = кивать.<br>✅ <b>② 고개를 끄덕이는</b> (кивать) — выражает согласие/внимание в большинстве стран.<br>✖️ ① хлопать в ладоши, ③ слушать, задавая вопросы, ④ слушать, записывая — не совпадают с «движением головы».<br>🧩 고개를 끄덕이다 = «кивать (в знак согласия)»."},{"n":18,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"사용 여부에 관계없이 물건을 못 버리고 저장해 두는 사람들이 있다. 습관이나 취미로 수집하는 정도를 넘어 생활에 방해가 될 정도로 심할 경우 이는 치료가 필요한 행동 장애로 본다. 연구에 따르면 주변 사람들에게 사랑을 충분히 받지 못한 사람이 물건에 지나치게 집착한다고 한다. 따라서 인간관계에서 안정을 찾으면 (        ) 행동은 사라질 수 있다.","options":["사람들을 피하려고 하는","불필요한 물건을 사는","물건들을 집에 쌓아 두는","쓰레기를 함부로 버리는"],"answer":3,"explain":"Текст о патологическом накопительстве: люди не могут выбросить вещи и копят их; причина — нехватка любви от близких.<br>✅ <b>③ накапливать (складировать) вещи дома</b> — именно это поведение исчезнет, если человек обретёт стабильность в отношениях.<br>✖️ ① избегать людей, ② покупать ненужное, ④ разбрасывать мусор — не то поведение, что описано.<br>🧩 -에 집착하다 = «быть одержимым чем-то, цепляться за…»."},{"n":19,"points":2,"instr":"Выберите слово-связку, подходящее для пропуска ( ).","passage":"인터넷으로 회원 가입을 할 때 설정하는 비밀번호는 초기에는 숫자 네 개면 충분했다. 하지만 최근에는 보안 강화를 위해 특수 문자까지 넣어 만들어야 한다. (        ) 비밀번호 변경도 주기적으로 해야 한다. 이 때문에 가입자는 번거로운 것은 물론이고 자주 바뀌는 비밀번호를 기억하지 못해 스트레스를 받는다. 개인 정보 보호를 가입자에게만 요구하지 말고 기업도 보안 기술 개발에 적극 투자해야 한다.","options":["그러면","게다가","반면에","이처럼"],"answer":2,"explain":"Перед пропуском: пароль теперь должен содержать спецсимволы. После: его «вдобавок» нужно периодически менять — добавляется ещё одно требование.<br>✅ <b>② 게다가</b> (к тому же, вдобавок).<br>✖️ ① 그러면 (тогда — следствие), ③ 반면에 (зато — контраст), ④ 이처럼 (вот так — обобщение).<br>🧩 게다가 присоединяет ещё один однородный довод."},{"n":20,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"인터넷으로 회원 가입을 할 때 설정하는 비밀번호는 초기에는 숫자 네 개면 충분했다. 하지만 최근에는 보안 강화를 위해 특수 문자까지 넣어 만들어야 한다. (        ) 비밀번호 변경도 주기적으로 해야 한다. 이 때문에 가입자는 번거로운 것은 물론이고 자주 바뀌는 비밀번호를 기억하지 못해 스트레스를 받는다. 개인 정보 보호를 가입자에게만 요구하지 말고 기업도 보안 기술 개발에 적극 투자해야 한다.","options":["가입자는 비밀번호 변경으로 스트레스를 받는다.","초기의 비밀번호는 숫자 네 개로는 만들 수 없었다.","가입자는 기업에 비밀번호 설정을 까다롭게 요구한다.","비밀번호 설정 시에 숫자와 문자 중 하나를 선택해야 한다."],"answer":1,"explain":"✅ <b>① Пользователь испытывает стресс из-за смены пароля</b> — «자주 바뀌는 비밀번호를 기억하지 못해 스트레스를 받는다».<br>✖️ ② Сначала «숫자 네 개면 충분했다» (4 цифр хватало). ③ Наоборот — требования к пользователю предъявляют компании. ④ Нужны и цифры, и спецсимволы — не «одно из».<br>🧩 -은 물론이고 = «не говоря уже о…, к тому же»."},{"n":21,"points":2,"instr":"Выберите идиому, подходящую для пропуска ( ).","passage":"어떤 사람들은 연예인을 열광적으로 좋아하는 청소년들을 부정적으로 본다. 학교생활에는 소홀하면서 (        ) 무조건 연예인만 쫓아다닌다고 생각하기 때문이다. 하지만 청소년들이 연예인을 좋아하는 것을 그렇게 부정적으로만 볼 일은 아니다. 취향이 비슷한 친구들을 사귈 수도 있고 또 공부나 입시로 인한 부담감에서 벗어날 수도 있기 때문이다. 그들을 너무 부정적으로만 보지 말고 이해하려는 노력이 필요하다.","options":["앞뒤를 재고","발을 빼지 않고","발걸음을 맞추고","앞뒤를 가리지 않고"],"answer":4,"explain":"«Забросив учёбу и (        ) безоглядно бегают только за звёздами».<br>✅ <b>④ 앞뒤를 가리지 않고</b> — «не разбирая, что к чему» = безрассудно, очертя голову (сочетается с 무조건 «безусловно»).<br>✖️ ① 앞뒤를 재고 — наоборот, «всё взвесив»; ② 발을 빼지 않고 — «не выходя из дела»; ③ 발걸음을 맞추고 — «идти в ногу».<br>🧩 앞뒤를 가리지 않다 = действовать необдуманно."},{"n":22,"points":2,"instr":"Выберите главную мысль текста.","passage":"어떤 사람들은 연예인을 열광적으로 좋아하는 청소년들을 부정적으로 본다. 학교생활에는 소홀하면서 (        ) 무조건 연예인만 쫓아다닌다고 생각하기 때문이다. 하지만 청소년들이 연예인을 좋아하는 것을 그렇게 부정적으로만 볼 일은 아니다. 취향이 비슷한 친구들을 사귈 수도 있고 또 공부나 입시로 인한 부담감에서 벗어날 수도 있기 때문이다. 그들을 너무 부정적으로만 보지 말고 이해하려는 노력이 필요하다.","options":["청소년 시기에 인간관계를 넓히는 것이 좋다.","연예인을 좋아해도 성적에 영향을 주면 안 된다.","청소년들에게 입시의 부담감을 지나치게 주지 않아야 한다.","연예인을 좋아하는 청소년에 대해 이해하는 마음을 가져야 한다."],"answer":4,"explain":"Вывод автора: «그들을 너무 부정적으로만 보지 말고 이해하려는 노력이 필요하다».<br>✅ <b>④ К подросткам, любящим знаменитостей, нужно относиться с пониманием.</b><br>✖️ ① о расширении круга общения, ② о влиянии на оценки, ③ о давлении вступительных экзаменов — это лишь побочные доводы, а не главная мысль.<br>🧩 -려는 노력이 필요하다 = «нужны усилия, чтобы…»."},{"n":23,"points":2,"instr":"Выберите чувство «я» (рассказчицы), отражённое в подчёркнутой части.","passage":"친정아버지가 손자들이 보고 싶다며 오랜만에 우리 집에 오셨다. 내가 집안일을 하는 사이에 아버지는 큰애를 데리고 놀이터에 다녀온다며 나가셨다. 한 시간쯤 지났는데 아버지가 다급한 목소리로 전화를 하셨다. 아이가 다쳐서 병원 응급실로 데리고 가신다는 것이었다. 나는 너무 놀라 허둥지둥 응급실로 달려갔다. 아이는 이마가 찢어져 치료를 받고 있었다. 나도 모르게 \"아버지, 애 좀 잘 보고 계시지 그러셨어요?\"라며 퉁명스럽게 말했다. 아버지는 아무 말씀 없이 치료받는 아이의 손만 꼭 잡고 계셨다. 집에 와서 아이를 재우고 나서야 아버지 손등의 상처가 눈에 들어왔다. 아이의 상처에는 그렇게 가슴 아파하면서 아버지의 상처는 미처 살피지 못했다. <u>나는 아버지에게 홧김에 내뱉은 말을 생각하며 약을 발라 드렸다.</u>","options":["억울하다","허전하다","후회스럽다","부담스럽다"],"answer":3,"explain":"«Я» сгоряча упрекнула отца, не заметив, что он сам поранил руку, защищая ребёнка; потом, смазывая ему рану, вспоминает свои резкие слова.<br>✅ <b>③ 후회스럽다</b> (раскаяние, сожаление о сказанном).<br>✖️ ① 억울하다 (несправедливо обижена), ② 허전하다 (опустошённость), ④ 부담스럽다 (обременительно) — не подходят.<br>🧩 홧김에 = «сгоряча, в порыве гнева»."},{"n":24,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"친정아버지가 손자들이 보고 싶다며 오랜만에 우리 집에 오셨다. 내가 집안일을 하는 사이에 아버지는 큰애를 데리고 놀이터에 다녀온다며 나가셨다. 한 시간쯤 지났는데 아버지가 다급한 목소리로 전화를 하셨다. 아이가 다쳐서 병원 응급실로 데리고 가신다는 것이었다. 나는 너무 놀라 허둥지둥 응급실로 달려갔다. 아이는 이마가 찢어져 치료를 받고 있었다. 나도 모르게 \"아버지, 애 좀 잘 보고 계시지 그러셨어요?\"라며 퉁명스럽게 말했다. 아버지는 아무 말씀 없이 치료받는 아이의 손만 꼭 잡고 계셨다. 집에 와서 아이를 재우고 나서야 아버지 손등의 상처가 눈에 들어왔다. 아이의 상처에는 그렇게 가슴 아파하면서 아버지의 상처는 미처 살피지 못했다. 나는 아버지에게 홧김에 내뱉은 말을 생각하며 약을 발라 드렸다.","options":["나는 친정아버지를 모시고 살고 있다.","아버지는 다친 손녀를 데리고 응급실에 가셨다.","나는 병원에서 아이가 다쳤다는 전화를 받았다.","아버지는 매일 손녀를 놀이터에서 놀아 주셨다."],"answer":2,"explain":"✅ <b>② Дедушка отвёз пораненного ребёнка в неотложку</b> — «아이가 다쳐서 병원 응급실로 데리고 가신다».<br>✖️ ① Отец приехал «오랜만에» (давно не виделись), а не живёт с ней. ③ Звонок «я» получила дома (во время домашних дел), а не в больнице. ④ Не «каждый день» — он приехал в гости впервые за долгое время.<br>🧩 모시고 살다 = «жить вместе (со старшим), заботясь о нём»."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 소비 심리 '봄바람', 백화점 매출 기지개","options":["소비자들의 구매 욕구가 살아나 백화점 매출이 늘어나고 있다.","날씨의 영향으로 백화점에서 물건을 구입하는 사람들이 많아졌다.","백화점에서 매출을 늘리기 위해 행사를 하자 사람들이 모여들었다.","소비자들의 심리를 반영한 백화점의 매출 전략이 호응을 얻고 있다."],"answer":1,"explain":"«Потребительские настроения — „весенний ветерок“, продажи универмагов „потягиваются“ (просыпаются)».<br>✅ <b>① Желание покупать ожило, и продажи универмагов растут.</b> 봄바람 = оживление, 기지개(를) 켜다 = «начать оживать».<br>✖️ ② про погоду, ③ про акции/мероприятия, ④ про маркетинговую стратегию — заголовок не об этом.<br>🧩 기지개를 켜다 (потягиваться) — метафора пробуждения, оживления."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 연휴 마지막 날 교통 체증, 고속도로 몸살 앓아","options":["연휴의 마지막 날에 고속도로에서 심각한 교통사고가 발생했다.","연휴에 실시한 고속도로 공사 때문에 사람들이 큰 불편을 겪었다.","연휴가 끝나는 날 고속도로에 몰린 차들로 인해 길이 많이 막혔다.","연휴 때마다 발생하는 교통 혼잡을 해결하기 위해 고속도로를 확장했다."],"answer":3,"explain":"«В последний день праздников — пробки, скоростные трассы „мучаются (몸살 앓아)“».<br>✅ <b>③ В день окончания праздников из-за хлынувших машин дороги сильно встали.</b><br>✖️ ① про серьёзную аварию, ② про дорожные работы, ④ про расширение трассы — этого в заголовке нет.<br>🧩 몸살(을) 앓다 — «изнемогать», образно о перегруженных дорогах."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок газетной статьи.","passage":"📰 시청자 사로잡는 드라마 음악, 시청률 상승 효과 '톡톡'","options":["시청자에게 익숙한 음악을 활용해 드라마의 시청률을 높이려고 했다.","시청자들은 시청률이 높은 드라마에 더 많은 음악이 나오기를 원했다.","드라마 음악을 시청자와 함께 만들어 시청률에 긍정적인 영향을 주었다.","드라마 음악이 시청자에게 사랑을 받으며 시청률을 높이는 역할을 했다."],"answer":4,"explain":"«Музыка из сериалов покоряет зрителей, эффект роста рейтинга — „ощутимый (톡톡)“».<br>✅ <b>④ Музыка сериалов полюбилась зрителям и сыграла роль в росте рейтинга.</b><br>✖️ ① «использовали знакомую музыку», ② «зрители хотели больше музыки», ③ «делали музыку вместе со зрителями» — это домыслы, не следующие из заголовка.<br>🧩 효과를 톡톡히 보다 = «получить заметный эффект»."},{"n":28,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"한 연구에 따르면 과거에 비해 요즘 사람들의 손톱이 더 빨리 자란다고 한다. 80년 전 사람들은 손톱이 한 달에 3mm 정도 자랐지만 최근에는 그보다 길게 3.5mm 정도 자란다는 것이다. 손톱 주변을 (        ) 세포 활동이 활발해져 손톱이 더 빨리 자란다. 연구팀은 최근 컴퓨터나 휴대전화의 자판을 누르는 등 손가락 끝을 사용하는 일이 많아지면서 손톱이 자라는 것에 영향을 준 것으로 보았다.","options":["깨끗하게 관리하면","감싸서 보호해 주면","자극하는 활동을 하면","건조하지 않게 해 주면"],"answer":3,"explain":"Логика текста: набор на клавиатуре/телефоне = частое использование кончиков пальцев → активизируется деятельность клеток у ногтей → ногти растут быстрее.<br>✅ <b>③ если совершать действия, стимулирующие (область вокруг ногтей)</b> — «세포 활동이 활발해져».<br>✖️ ① чисто ухаживать, ② оборачивать и защищать, ④ не давать пересыхать — не объясняют ускоренный рост.<br>🧩 자극하다 = «раздражать, стимулировать»."},{"n":29,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"한국에서는 보통 명절에 여러 가지 나물을 만들어 먹는다. 집집마다 조금씩 다르지만 뿌리채소, 줄기채소, 잎채소를 재료로 해서 세 가지 종류의 나물을 만드는 것이 기본이다. 이 세 가지 나물은 (        ) 상징적 의미를 담고 있다. 뿌리는 조상, 줄기는 부모, 잎은 자손을 뜻하기 때문이다. 뿌리, 줄기, 잎이 어우러져 하나의 나물이 되듯 한 집안도 이러한 결합을 통해 이루어짐을 나타내는 것이다.","options":["식물의 성장과 번식이라는","조상과 후손의 연결이라는","자연과 인간의 화합이라는","음식의 장만과 나눔이라는"],"answer":2,"explain":"Корень = предки, стебель = родители, лист = потомки; вместе они образуют одно блюдо — как и семья объединяет поколения.<br>✅ <b>② символический смысл «связи предков и потомков»</b>.<br>✖️ ① рост и размножение растений, ③ гармония природы и человека, ④ приготовление и совместная трапеза — не отражают объяснение «뿌리=조상…».<br>🧩 어우러지다 = «гармонично сочетаться, сливаться»."},{"n":30,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"전자레인지는 보통 음식을 따뜻하게 데울 때 사용된다. 그런데 전자레인지는 직접 열을 가하는 것이 아니라 음식에 포함된 물 분자의 움직임을 이용하여 음식을 데운다. 음식물에 전자레인지의 전자파가 닿으면 음식물 안에 있는 물 분자들이 진동하면서 열이 발생하는 것이다. 한편 얼음은 전자레인지의 전자파가 닿아도 녹지 않는다. 얼음 속의 물 분자가 얼어 있어서 (        ) 때문이다.","options":["부피가 커지기","결합이 안 되기","움직이지 못하기","열을 모두 반사하기"],"answer":3,"explain":"Микроволновка греет за счёт колебания молекул воды. Во льду молекулы воды заморожены и потому не могут двигаться — тепло не выделяется, лёд не тает.<br>✅ <b>③ не могут двигаться</b>.<br>✖️ ① увеличиваются в объёме, ② не соединяются, ④ полностью отражают тепло — текст об отсутствии колебаний.<br>🧩 진동하다 = «вибрировать, колебаться»."},{"n":31,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"최근 일부 대기업을 중심으로 '기업 쪼개기'가 이루어지고 있다. 이는 (        ) 의도에서 비롯된 것이다. 그동안 대기업들은 큰 몸집 탓에 복잡한 결재 절차를 거쳐야 했다. 그런데 최근 시장 환경이 급변하면서 의사 결정 속도가 곧 기업의 경쟁력인 시대가 되었다. 이에 기업들은 계열사를 독립적인 회사로 분리하고 각 회사에 최종 결정 권한을 넘김으로써 시장 변화에 신속히 대처하고 있다.","options":["회사의 이미지를 바꾸려는","시장의 흐름을 변화시키려는","기업 간에 정보를 공유하려는","의사 결정 단계를 단순화하려는"],"answer":4,"explain":"Из-за громоздкости крупные компании проходили сложные процедуры согласования; разделение на самостоятельные фирмы с правом окончательного решения ускоряет реакцию на рынок.<br>✅ <b>④ намерение упростить этапы принятия решений</b>.<br>✖️ ① сменить имидж, ② изменить рыночные тренды, ③ обмениваться информацией — не объясняют «기업 쪼개기».<br>🧩 비롯되다 = «брать начало, проистекать из…»."},{"n":32,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"물감은 섞거나 덧칠할수록 색이 탁해진다. 그래서 19세기 화가들은 점을 찍어 색을 표현하는 점묘법을 생각해 냈다. 이 기법은 예를 들어 빨간색과 파란색의 작은 점들을 촘촘히 찍어서, 조금 떨어진 곳에서 볼 때 점들이 섞여 보라색으로 보이도록 한 것이다. 이렇게 표현한 색은 물감을 섞어서 만든 색보다 훨씬 더 맑고 부드러운 느낌을 준다. 이 때문에 점묘법은 회화의 대표적인 표현 기법으로 자리 잡게 되었고 현재 화가들도 즐겨 사용하고 있다.","options":["이 기법으로 그림을 그리면 그림이 부드럽게 느껴진다.","이 기법은 19세기 이후에는 화가들의 외면을 받게 되었다.","이 기법은 가까운 곳에서 봐야 색이 섞여 보이는 효과가 있다.","이 기법으로 그림을 그릴 때는 넓은 간격으로 점을 찍어야 한다."],"answer":1,"explain":"Пуантилизм: мелкие точки разных цветов; издали они смешиваются в глазу, цвет выходит чище и мягче, чем при смешивании красок.<br>✅ <b>① С этой техникой картина воспринимается мягко</b> — «훨씬 더 맑고 부드러운 느낌을 준다».<br>✖️ ② технику не «отвергли» — её охотно используют и сейчас. ③ смешение видно ИЗДАЛИ (조금 떨어진 곳), а не вблизи. ④ точки ставят «촘촘히» (плотно), а не с широкими промежутками.<br>🧩 점묘법 = пуантилизм; 촘촘히 = «плотно, часто»."},{"n":33,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"생물들은 환경 변화에 민감하게 반응하기 때문에 환경오염을 나타내는 지표 역할을 한다. 예로 나팔꽃은 대기 오염의 지표가 된다. 나팔꽃에 흰색 반점이 생기면 공기가 오염되었다는 것을 알 수 있다. 또 물고기는 수질 오염 정도를 보여 준다. 은어가 살면 깨끗한 1급수의 물이라는 것을, 미꾸라지가 살면 깨끗하지 않은 3급수의 물이라는 것을 뜻한다. 이처럼 복잡한 측정 장비 없이도 지표 생물로 그 지역 환경의 오염 정도를 알 수 있다.","options":["대기 오염의 여부는 지표 생물로 판별하기 어렵다.","자연 환경이 깨끗한 곳에서는 미꾸라지를 발견할 수 없다.","물속에 사는 물고기의 종류로 물이 오염되었는지 파악할 수 있다.","나팔꽃의 크기의 변화를 통해 환경 변화를 알 수 있다."],"answer":3,"explain":"Организмы-индикаторы: ипомея (나팔꽃) — для воздуха, рыбы — для воды (은어 = 1-й класс/чистая, 미꾸라지 = 3-й класс/грязная).<br>✅ <b>③ По виду рыб в воде можно определить, загрязнена ли вода.</b><br>✖️ ① воздух как раз определяют по индикаторам (나팔꽃). ② слишком категорично — текст про классы воды, а не про «нигде не найти». ④ судят по белым пятнам (흰색 반점), а не по «размеру» ипомеи.<br>🧩 지표 생물 = «биоиндикатор»."},{"n":34,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"정부는 환자의 의약품 처방 이력을 제공하는 '의약품 안전 사용 서비스'를 실시하고 있다. 이 제도는 의료 기관에서 의약품을 처방하기 전에 환자가 다른 기관에서 어떤 약을 처방받았는지 온라인으로 검색하도록 하는 것이다. 함께 먹으면 안 되는 약이나 같은 약이 여러 번 처방될 경우 생기는 부작용을 방지하려는 목적이며, 이 제도를 통해 적절한 의약품 처방이 국민의 건강 증진에 도움이 될 것으로 기대된다.","options":["이 제도는 온라인에서 이용할 수 있도록 할 예정이다.","환자들은 의약품을 처방받기 전에 이 제도를 이용해야 한다.","환자들은 의료 기관에 방문하지 않고 의약품을 처방받을 수 있다.","의약품의 부작용을 예방하기 위해 이 제도가 시행되고 있다."],"answer":4,"explain":"«Сервис безопасного приёма лекарств» позволяет мед. учреждению до выписки проверить историю назначений пациента — чтобы избежать опасных сочетаний и дублирования.<br>✅ <b>④ Система введена для предотвращения побочных эффектов лекарств</b> — «부작용을 방지하려는 목적».<br>✖️ ① уже действует (실시하고 있다) и уже онлайн — не «планируется». ② проверку делает мед. учреждение, не пациент. ③ получить рецепт без визита в клинику нельзя.<br>🧩 처방 이력 = «история назначений (рецептов)»."},{"n":35,"points":2,"instr":"Выберите тему (главную мысль) текста.","passage":"현대인들은 통계를 이용해 실상을 파악하는 경우가 많다. 하지만 통계가 절대적인 사실을 반영하는 것만은 아니다. 예컨대 오이의 가격이 1월에 1,000원이고 2월에 3,000원이며 현재 2,000원이라고 가정해 보자. 현재의 오이 값을 통계에 근거해서 평가할 때 1월을 기준으로 하면 물가가 큰 폭으로 오른 것이 되고 2월을 기준으로 삼으면 대폭 하락한 것으로 이해될 수 있는 것이다.","options":["통계 수치에 근거해야 실상을 파악할 수 있다.","현실이 반영되지 않는 통계는 무의미하다.","통계를 통해 물가 상승률과 하락률을 알 수 있다.","통계는 기준 설정에 따라 다양하게 해석될 수 있다."],"answer":4,"explain":"Цена огурца: январь 1000 ₩, февраль 3000 ₩, сейчас 2000 ₩. Относительно января — рост, относительно февраля — падение: одни и те же данные толкуются по-разному.<br>✅ <b>④ Статистику можно по-разному интерпретировать в зависимости от выбранной точки отсчёта.</b><br>✖️ ① «только по цифрам можно понять реальность» — противоречит тексту. ② «бессмысленна» — слишком категорично. ③ про конкретные темпы цен — это пример, а не тема.<br>🧩 기준(을) 삼다 = «брать за точку отсчёта»."},{"n":36,"points":2,"instr":"Выберите тему (главную мысль) текста.","passage":"철새는 종에 따라 수만에서 수십만 개체가 무리를 지어 일정한 대형으로 이동한다. 이때 대형의 선두에서 나는 새가 무리의 리더인데, 이 새는 무리를 안전하게 이끄는 역할을 맡는다. 이를 위해서 이 새는 거친 바람을 맨 앞에서 맞서 비행하며 최적의 항로를 찾아낼 수 있는 경험을 두루 갖추고 있어야 한다. 또한 어떤 위기 상황이 발생하더라도 신속하게 대처할 수 있는 판단 능력도 있어야 한다.","options":["철새는 최적의 항로로 신속하게 이동해야 한다.","철새의 리더는 경험과 판단 능력을 갖춰야 한다.","철새는 위험에 대처하기 위해 무리를 지어야 한다.","철새의 리더가 무리의 대형의 선두에서 비행해야 한다."],"answer":2,"explain":"Текст о вожаке стаи: летит впереди, выбирает оптимальный маршрут, быстро реагирует на опасность — для этого нужны опыт и способность принимать решения.<br>✅ <b>② Вожаку перелётных птиц нужны опыт и способность к суждению.</b><br>✖️ ① и ③ — частные детали, ④ описывает лишь положение вожака, но тема — какие качества ему нужны.<br>🧩 두루 갖추다 = «обладать в полной мере»."},{"n":37,"points":2,"instr":"Выберите тему (главную мысль) текста.","passage":"어떤 사람들은 경제적 여유를 얻게 되면서 삶의 무료함을 느끼기도 한다. 그런데 사람들은 이런 무료함을 별것 아닌 사소한 것으로 여기는 경향이 있다. 하지만 무료함은 개인의 행복한 삶을 저해하는 하나의 요소가 될 수도 있다. 돈이나 명예로는 남부럽지 않을 것 같은 사람들이 무료함 때문에 사회적 일탈 행동을 하기도 하고 무료함이 심해져 우울증으로까지 발전하는 경우도 있기 때문이다. 무료함은 간과해도 되는 사소한 것이 아니다.","options":["경제적 여유가 있는 사람들이 무료함에 빠지기 쉽다.","사회적 일탈 행동은 돈과 명예가 없는 데에서 기인한다.","무료함을 가볍게 여기지 말고 그 심각성을 인식해야 한다.","행복한 삶을 위해서는 우울증을 예방하려고 노력해야 한다."],"answer":3,"explain":"Скуку часто считают пустяком, но она вредит счастливой жизни — может привести к девиантному поведению и даже депрессии.<br>✅ <b>③ Не стоит относиться к скуке легкомысленно — нужно осознавать её серьёзность.</b><br>✖️ ① и ② — частные наблюдения, ④ про депрессию — лишь следствие, а не главная мысль.<br>🧩 간과하다 = «упускать из виду, недооценивать»."},{"n":38,"points":2,"instr":"Выберите тему (главную мысль) текста.","passage":"사과를 할 때 진심 없이 건성으로 하는 사람들이 있다. 또한 어떤 사람들은 사과를 할 때 선한 의도로 행동한 것이었음을 강조하면서 행위에 대한 책임을 회피하려고 한다. 하지만 사과는 어떤 일의 결과에 책임을 지는 행위가 되어야 한다. 의도가 선한 것이었던 악한 것이었던 자신의 행위가 상대방에게 고통을 주었다면 그에 대한 책임을 져야 진정한 사과가 되는 것이다. 사과를 하는 사람들이 먼저 알아야 하는 것은 바로 이것이다.","options":["일의 결과를 책임지는 것이 진정한 사과이다.","잘못을 해도 의도가 선하다면 용서를 해야 한다.","사과는 잘못을 반복하지 않기 위해 하는 것이다.","악의적 의도로 상대방에게 고통을 주면 안 된다."],"answer":1,"explain":"Извинение — это не отговорки про «добрые намерения», а принятие ответственности за результат: если твой поступок причинил боль, нужно за это отвечать.<br>✅ <b>① Настоящее извинение — это принятие ответственности за результат.</b><br>✖️ ② оправдывает «добрыми намерениями» — текст это как раз отвергает. ③ про повторение ошибок, ④ про злой умысел — не главная мысль.<br>🧩 건성으로 = «спустя рукава, формально»."},{"n":39,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить предложение из <보기>.","passage":"<보기> 악취에 동일한 양의 다른 냄새들을 더해 악취를 느끼지 못하게 하는 것이 목표이다.\n\n한 연구팀이 냄새가 나지 않는 무취 상태의 조건을 알아냈다. ( ㉠ ) 사람의 코는 다양한 냄새 중에 농도가 짙은 것 위주로 냄새를 맡는다. ( ㉡ ) 그런데 서로 다른 냄새 입자를 동일한 양으로 섞으면 사람의 코는 냄새가 거의 나지 않는 것처럼 느낀다는 것이다. ( ㉢ ) 여기에 착안해 악취를 없애는 기술을 연구하고 있다. ( ㉣ ) 이 기술이 개발되면 심한 악취 환경에서 작업하는 사람들의 어려움을 줄여 줄 수 있을 것이다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"Предложение из <보기> формулирует ЦЕЛЬ технологии устранения зловония. Оно логично встаёт сразу после «여기에 착안해 악취를 없애는 기술을 연구하고 있다» (на основе этого исследуют технологию) и перед «이 기술이 개발되면…» (когда её разработают…).<br>✅ <b>④ ㉣</b>.<br>✖️ ㉠~㉢ стоят посреди объяснения принципа «무취», куда формулировка цели не подходит.<br>🧩 -에 착안하다 = «отталкиваться от чего-то, брать за основу идею»."},{"n":40,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить предложение из <보기>.","passage":"<보기> 작가는 따뜻한 한 끼의 음식과 그것을 만들기까지 수고한 사람들에 대한 이야기를 담고 싶었던 것이다.\n\n요리사 박찬일 씨가 에세이집 『미식가의 허기』를 펴냈다. ( ㉠ ) 이 책에는 서민들이 일상적으로 먹던 음식들이 계절별로 소개되어 있다. ( ㉡ ) 그러나 음식에 대한 내용만 담겨 있는 것은 아니다. ( ㉢ ) 산지에서 음식 재료를 생산하기 위해 애쓰는 사람들, 그 재료로 뜨거운 불 앞에서 음식을 준비하는 사람들에 대한 이야기도 있다. ( ㉣ ) 이 책은 미각을 자극하기보다는 한 끼 식사가 마련되는 과정의 어려움을 일깨운다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"Предложение из <보기> обобщает замысел автора: рассказать о тёплой еде и о людях, что её готовят. Оно встаёт сразу после абзаца про «사람들에 대한 이야기도 있다» и перед итоговым «이 책은 미각을 자극하기보다는…».<br>✅ <b>④ ㉣</b>.<br>✖️ ㉠~㉢ — внутри перечисления содержания книги, обобщающий вывод там преждевременен.<br>🧩 일깨우다 = «пробуждать осознание, заставлять задуматься»."},{"n":41,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить предложение из <보기>.","passage":"<보기> 산업 구조의 변화에 따라 당연히 일자리의 변동성도 커질 것이다.\n\n지금 우리는 기계가 인간의 인지적인 영역까지 대신하는 제2의 기계 시대로 접어들고 있다. ( ㉠ ) 이러한 비약적인 기계 발전의 시대가 인간의 삶을 더 윤택하게 할지 더 소외시킬지 단정 지을 수는 없다. ( ㉡ ) 하지만 급속한 기술의 발달로 현재의 산업 구조가 크게 바뀐다는 것만은 분명하다. ( ㉢ ) 그래서 지금 초등학교에 진학하는 아이들의 65%는 현재에는 없는 직업을 갖게 될 것으로 전망된다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"Предложение из <보기> («вслед за изменением структуры экономики вырастет и изменчивость рабочих мест») — логический мост между «산업 구조가 크게 바뀐다는 것만은 분명하다» и следствием «그래서 … 현재에는 없는 직업을 갖게 될 것».<br>✅ <b>③ ㉢</b>.<br>✖️ ㉠/㉡ — ещё до тезиса о смене структуры; ㉣ — уже после вывода про новые профессии.<br>🧩 변동성 = «изменчивость, волатильность»."},{"n":42,"points":2,"instr":"Выберите чувство «я» (рассказчика-школьника), отражённое в подчёркнутой части.","passage":"예쁘고 멋쟁이인 박영은 선생님을 새 담임으로 맞이한 것은 우리 모두에게 가슴 떨리는 일이었다. 멋쟁이 담임 선생님의 말은 죽어라고 안 듣던 말썽꾸러기들이 박 선생님 앞에서는 고개도 제대로 못 들고 수줍어했다. 우리 반은 당장 전교에서 제일 말 잘 듣고 가장 깨끗한 반이 되었다. 나도 박 선생님에게 잘 보이고 싶은 마음이 태산 같았지만 늘 그렇듯이 머리가 따라 주지를 않았다. 아마 이번 시험에서도 모든 과목이 50점을 넘지 못했을 것이다. 아이들이 모두 떠난 교실에서 나는 몸을 비비 꼬며 창밖에서 놀고 있는 아이들에게 시선을 주고 있었다. (중략) 선생님이 마침내 입을 연 것은 20분이나 시간이 지나서였다. (중략)\n\"동구를 가만히 보면, 아는데 말을 못하는 적도 많은 것 같아. 그러다 보니 자신감도 없어지고.\"\n<u>나의 간지럽고 아픈 부분을 이렇게나 간결하게 짚어 준 사람이 내 인생에 또 있으랴.</u> 공부 못하는 죄를 추궁당하는 것이 아니라 공부 못하는 서러움을 이해받는 것은 생애 처음 있는 일이었다. 안 그래도 물러 터진 내 마음은 완전히 물에 만 휴지처럼 흐물흐물해져서, 예쁘고 멋진 데다 현명하기까지 한 박 선생님 앞에서 때 아닌 눈물까지 한 방울 선을 보일 뻔했다.","options":["난처하다","담담하다","감격스럽다","의심스럽다"],"answer":3,"explain":"Учительница впервые поняла не «вину» мальчика за плохую учёбу, а его горечь; «я» растроган до слёз («내 인생에 또 있으랴» — никто прежде так не понимал).<br>✅ <b>③ 감격스럽다</b> (растроган, переполнен благодарностью).<br>✖️ ① 난처하다 (в затруднении), ② 담담하다 (невозмутим), ④ 의심스럽다 (с подозрением) — не подходят.<br>🧩 -(으)랴 — риторический вопрос со значением «разве был бы…?» (= не было)."},{"n":43,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"예쁘고 멋쟁이인 박영은 선생님을 새 담임으로 맞이한 것은 우리 모두에게 가슴 떨리는 일이었다. 멋쟁이 담임 선생님의 말은 죽어라고 안 듣던 말썽꾸러기들이 박 선생님 앞에서는 고개도 제대로 못 들고 수줍어했다. 우리 반은 당장 전교에서 제일 말 잘 듣고 가장 깨끗한 반이 되었다. 나도 박 선생님에게 잘 보이고 싶은 마음이 태산 같았지만 늘 그렇듯이 머리가 따라 주지를 않았다. 아마 이번 시험에서도 모든 과목이 50점을 넘지 못했을 것이다. 아이들이 모두 떠난 교실에서 나는 몸을 비비 꼬며 창밖에서 놀고 있는 아이들에게 시선을 주고 있었다. (중략) 선생님이 마침내 입을 연 것은 20분이나 시간이 지나서였다. (중략)\n\"동구를 가만히 보면, 아는데 말을 못하는 적도 많은 것 같아. 그러다 보니 자신감도 없어지고.\"\n나의 간지럽고 아픈 부분을 이렇게나 간결하게 짚어 준 사람이 내 인생에 또 있으랴. 공부 못하는 죄를 추궁당하는 것이 아니라 공부 못하는 서러움을 이해받는 것은 생애 처음 있는 일이었다. 안 그래도 물러 터진 내 마음은 완전히 물에 만 휴지처럼 흐물흐물해져서, 예쁘고 멋진 데다 현명하기까지 한 박 선생님 앞에서 때 아닌 눈물까지 한 방울 선을 보일 뻔했다.","options":["나는 담임 선생님께 인정을 받고 싶다.","반 아이들은 요즘 교실 청소를 잘 하지 않는다.","반 아이들은 예전 담임 선생님 말을 잘 들었다.","담임 선생님은 내가 공부를 못해서 화를 내셨다."],"answer":1,"explain":"✅ <b>① «Я» хочу, чтобы новый классный руководитель меня признал</b> — «박 선생님에게 잘 보이고 싶은 마음이 태산 같았지만».<br>✖️ ② класс стал «가장 깨끗한 반» (самым чистым). ③ прежде это были «말썽꾸러기» (озорники, что не слушались). ④ учительница не сердилась, а поняла его.<br>🧩 잘 보이고 싶다 = «хотеть произвести хорошее впечатление, заслужить одобрение»."},{"n":44,"points":2,"instr":"Выберите тему (главную мысль) текста.","passage":"보편적 디자인이란 성별, 연령, 장애의 유무 등에 관계없이 누구나 편리하게 이용할 수 있도록 제품이나 사용 환경을 만드는 것을 말한다. 산업혁명 시대에는 대량 생산을 목적으로 생산의 효율성을 추구하였다. 따라서 디자인을 할 때 (        ). 그러다 보니 여기에 속하지 못한 대상들은 불편을 겪을 수밖에 없었다. 이에 대한 비판과 반성에서 출발한 것이 보편적 디자인이다. 대표적인 예가 계단이 없는 저상 버스인데 이 버스는 타고 내리기 쉬워 어린이와 노인, 임산부와 장애인 등 모두가 편리하게 이용할 수 있다. 다양한 대상의 특성을 고려한 보편적 디자인은 최대한 많은 사람들이 차별 없이 생활할 수 있는 환경을 조성하는 데 큰 몫을 하고 있다.","options":["과거와는 다른 새로운 디자인의 개발이 요구된다.","보편적 디자인을 사용해야 제품의 대량 생산이 가능하다.","보편적 디자인은 사회의 여러 계층을 고려한 디자인이다.","제품을 디자인할 때 가장 중요한 것은 생산의 효율성이다."],"answer":3,"explain":"Универсальный дизайн делает товары/среду удобными для всех — независимо от пола, возраста, инвалидности (пример — низкопольный автобус).<br>✅ <b>③ Универсальный дизайн — это дизайн, учитывающий разные слои общества.</b><br>✖️ ① «новый дизайн» — слишком общо; ② путает причину со следствием; ④ эффективность производства — это как раз то, что критикуется.<br>🧩 -에 관계없이 = «независимо от…»."},{"n":45,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"보편적 디자인이란 성별, 연령, 장애의 유무 등에 관계없이 누구나 편리하게 이용할 수 있도록 제품이나 사용 환경을 만드는 것을 말한다. 산업혁명 시대에는 대량 생산을 목적으로 생산의 효율성을 추구하였다. 따라서 디자인을 할 때 (        ). 그러다 보니 여기에 속하지 못한 대상들은 불편을 겪을 수밖에 없었다. 이에 대한 비판과 반성에서 출발한 것이 보편적 디자인이다. 대표적인 예가 계단이 없는 저상 버스인데 이 버스는 타고 내리기 쉬워 어린이와 노인, 임산부와 장애인 등 모두가 편리하게 이용할 수 있다. 다양한 대상의 특성을 고려한 보편적 디자인은 최대한 많은 사람들이 차별 없이 생활할 수 있는 환경을 조성하는 데 큰 몫을 하고 있다.","options":["생산할 제품의 특성을 최대한 반영하였다","편리한 사용 환경을 마련해 주고자 하였다","당시 널리 퍼져 있던 유행의 흐름을 따랐다","표준이라 여기는 다수만을 기준으로 하였다"],"answer":4,"explain":"Ради эффективности массового производства проектировали под «среднего», стандартного человека — поэтому те, кто в эту норму не попадал, испытывали неудобства («여기에 속하지 못한 대상들은 불편을 겪을 수밖에 없었다»).<br>✅ <b>④ ориентировались лишь на большинство, принимаемое за стандарт</b>.<br>✖️ ① «учитывали свойства товара», ② «создавали удобную среду» (это уже универсальный дизайн), ③ «следовали моде» — не подходят по логике.<br>🧩 기준으로 하다 = «брать за критерий/норму»."},{"n":46,"points":2,"instr":"Выберите место (㉠~㉣), куда лучше всего вставить предложение из <보기>.","passage":"<보기> 경제적 관점에서 보수와 진보는 시장 경제를 조절하는 두 축인 시장과 국가의 역할에 대한 견해에 따라 구분된다.\n\n보수와 진보의 개념은 정치뿐만 아니라 경제 분야에서도 사용된다. ( ㉠ ) 자유를 중시하는 보수주의자들은 자유가 최대한 보장될 때 경제 성장이 가능하다고 본다. 그래서 경제를 시장의 자율에 맡기고 정부는 최소한의 역할만을 담당해야 한다고 주장한다. ( ㉡ ) 반면 평등을 우선시하는 진보주의자들은 시장을 자율에 맡기기보다 국가가 개입해야 한다고 생각한다. ( ㉢ ) 그래야 시장 경제 체제의 문제점인 불평등을 해소할 수 있다고 주장한다. 보수와 진보 중 어느 하나의 입장만이 옳다고 단정하기는 어렵다. 경제 발전을 위해서는 보수가 추구하는 바가 필요하며 경제 발전에 따른 문제점을 해결하기 위해서는 진보의 정책들이 요구된다. 보수와 진보가 서로 보완하여 상호 균형을 이룰 때 경제는 더 발전적인 방향으로 나아갈 수 있을 것이다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"Предложение из <보기> даёт ОПРЕДЕЛЕНИЕ: по чему различают консерваторов и прогрессистов в экономике (по взгляду на роль рынка и государства). Оно встаёт сразу после вводной фразы «보수와 진보의 개념은 … 경제 분야에서도 사용된다» и перед раскрытием каждой позиции.<br>✅ <b>① ㉠</b>.<br>✖️ ㉡~㉣ — уже внутри/после раскрытия конкретных взглядов, общее определение там запоздало.<br>🧩 -에 따라 구분되다 = «различаться в зависимости от…»."},{"n":47,"points":2,"instr":"Выберите вариант, совпадающий с содержанием текста.","passage":"보수와 진보의 개념은 정치뿐만 아니라 경제 분야에서도 사용된다. 자유를 중시하는 보수주의자들은 자유가 최대한 보장될 때 경제 성장이 가능하다고 본다. 그래서 경제를 시장의 자율에 맡기고 정부는 최소한의 역할만을 담당해야 한다고 주장한다. 반면 평등을 우선시하는 진보주의자들은 시장을 자율에 맡기기보다 국가가 개입해야 한다고 생각한다. 그래야 시장 경제 체제의 문제점인 불평등을 해소할 수 있다고 주장한다. 보수와 진보 중 어느 하나의 입장만이 옳다고 단정하기는 어렵다. 경제 발전을 위해서는 보수가 추구하는 바가 필요하며 경제 발전에 따른 문제점을 해결하기 위해서는 진보의 정책들이 요구된다. 보수와 진보가 서로 보완하여 상호 균형을 이룰 때 경제는 더 발전적인 방향으로 나아갈 수 있을 것이다.","options":["경제 성장을 위해서는 국가가 시장을 주도해야 한다.","시장 경제를 제어할 수 있는 주체는 시장이 유일하다.","진보주의자가 보수주의자에 비해 자유에 더 가치를 둔다.","경제 성장으로 인한 문제 해결에는 진보적 관점이 필요하다."],"answer":4,"explain":"✅ <b>④ Для решения проблем, порождённых экономическим ростом, нужен прогрессивный взгляд</b> — «경제 발전에 따른 문제점을 해결하기 위해서는 진보의 정책들이 요구된다».<br>✖️ ① рынком, по мнению консерваторов, должна управлять не власть, а сам рынок. ② прогрессисты считают, что должно вмешиваться государство. ③ свободу выше ставят консерваторы, прогрессисты — равенство.<br>🧩 상호 균형을 이루다 = «достигать взаимного равновесия»."},{"n":48,"points":2,"instr":"Выберите цель, с которой написан текст.","passage":"특허법은 독창적인 기술을 최초로 발명한 사람에게 기술에 대한 독점적 사용권을 부여하는 대신 그 기술을 사회에 공개할 의무를 부과한다. 공개된 기술 공유를 통해 사회 전체의 기술력을 높이는 것이 특허의 취지이다. <u>이런 취지에 부합하여 실제로 특허 제도는 기술 혁신과 산업 발전에 크게 이바지해 왔다.</u> 그런데 최근 들어 특허의 본래 취지가 변질되어 기술 개발보다 독점권 확보를 우선하는 현상이 두드러지게 나타나고 있다. (        ) 상태에서 마구잡이 특허 출원으로 권리부터 선점해 놓고 기술을 개발하려는 경우가 비일비재한 것이다. 이 때문에 정작 신기술 개발에 힘들게 성공한 사람들이 권리를 확보하지 못하는 경우가 자주 발생하곤 한다. 특허는 발명의 대가로 당연히 보호받을 가치가 있다. 하지만 그것은 기술 개발에 성공해 사회 발전에 공헌하는 경우에 한해서이다. 무분별한 특허 출원으로 기술 발전을 저해한다면 이는 특허가 가진 본래의 취지를 훼손하는 것이다.","options":["특허 심사 절차를 설명하기 위해서","특허권의 필요성을 역설하기 위해서","특허의 실질적 가치를 분석하기 위해서","특허 출원 남용의 문제를 제기하기 위해서"],"answer":4,"explain":"Автор показывает, что патент изначально служит обществу, но в последнее время его суть искажается: права захватывают через «마구잡이 특허 출원» (беспорядочными заявками), мешая реальным изобретателям.<br>✅ <b>④ чтобы поднять проблему злоупотребления патентными заявками.</b><br>✖️ ① процедура экспертизы, ② необходимость патентного права, ③ анализ реальной ценности — не основная цель текста.<br>🧩 문제를 제기하다 = «поднимать/ставить проблему»."},{"n":49,"points":2,"instr":"Выберите выражение, наиболее подходящее для пропуска ( ).","passage":"특허법은 독창적인 기술을 최초로 발명한 사람에게 기술에 대한 독점적 사용권을 부여하는 대신 그 기술을 사회에 공개할 의무를 부과한다. 공개된 기술 공유를 통해 사회 전체의 기술력을 높이는 것이 특허의 취지이다. <u>이런 취지에 부합하여 실제로 특허 제도는 기술 혁신과 산업 발전에 크게 이바지해 왔다.</u> 그런데 최근 들어 특허의 본래 취지가 변질되어 기술 개발보다 독점권 확보를 우선하는 현상이 두드러지게 나타나고 있다. (        ) 상태에서 마구잡이 특허 출원으로 권리부터 선점해 놓고 기술을 개발하려는 경우가 비일비재한 것이다. 이 때문에 정작 신기술 개발에 힘들게 성공한 사람들이 권리를 확보하지 못하는 경우가 자주 발생하곤 한다. 특허는 발명의 대가로 당연히 보호받을 가치가 있다. 하지만 그것은 기술 개발에 성공해 사회 발전에 공헌하는 경우에 한해서이다. 무분별한 특허 출원으로 기술 발전을 저해한다면 이는 특허가 가진 본래의 취지를 훼손하는 것이다.","options":["특허가 만료되지 않은","신기술을 특허로 인정받은","기술이 완벽하게 개발되지 않은","기존의 기술과 차별성을 확인한"],"answer":3,"explain":"После пропуска: «беспорядочно подают заявки, захватывая права ПЕРВЫМИ, а технологию собираются разрабатывать потом». Значит, на момент подачи технология ещё не доведена до конца.<br>✅ <b>③ когда технология не разработана полностью</b>.<br>✖️ ① срок патента не истёк, ② новая технология уже признана патентом, ④ подтверждена новизна — противоречат идее «сначала захватить право, потом разрабатывать».<br>🧩 권리부터 선점하다 = «первым делом застолбить право»."},{"n":50,"points":2,"instr":"Выберите отношение автора, отражённое в подчёркнутой части.","passage":"특허법은 독창적인 기술을 최초로 발명한 사람에게 기술에 대한 독점적 사용권을 부여하는 대신 그 기술을 사회에 공개할 의무를 부과한다. 공개된 기술 공유를 통해 사회 전체의 기술력을 높이는 것이 특허의 취지이다. <u>이런 취지에 부합하여 실제로 특허 제도는 기술 혁신과 산업 발전에 크게 이바지해 왔다.</u> 그런데 최근 들어 특허의 본래 취지가 변질되어 기술 개발보다 독점권 확보를 우선하는 현상이 두드러지게 나타나고 있다. (        ) 상태에서 마구잡이 특허 출원으로 권리부터 선점해 놓고 기술을 개발하려는 경우가 비일비재한 것이다. 이 때문에 정작 신기술 개발에 힘들게 성공한 사람들이 권리를 확보하지 못하는 경우가 자주 발생하곤 한다. 특허는 발명의 대가로 당연히 보호받을 가치가 있다. 하지만 그것은 기술 개발에 성공해 사회 발전에 공헌하는 경우에 한해서이다. 무분별한 특허 출원으로 기술 발전을 저해한다면 이는 특허가 가진 본래의 취지를 훼손하는 것이다.","options":["특허 출원 감소를 심각하게 우려하고 있다.","특허권자의 독점권을 강하게 옹호하고 있다.","특허 제도의 정책적 보완을 강력히 요구하고 있다.","특허 제도가 사회에 기여한 바를 높이 평가하고 있다."],"answer":4,"explain":"Подчёркнуто: «в соответствии с этим замыслом патентная система реально внесла большой вклад в технологические инновации и развитие промышленности» — это положительная оценка прошлых заслуг.<br>✅ <b>④ Автор высоко оценивает вклад патентной системы в общество.</b><br>✖️ ① об опасении спада заявок, ② защита монополии патентообладателя, ③ требование доработать политику — в подчёркнутой части этого нет.<br>🧩 이바지하다 = «вносить вклад, способствовать»."}]
      },
      writing: {
        durationMin: 50, label: '제52회 · 쓰기 (51~54)',
        tasks: [{"n":51,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. СМС-сообщение от 마이클 для 수미 — вежливый формальный стиль (-습니다/-ㅂ니까).","passage":"수미 씨,\n지난번에 책을 ( ㉠ ) 고맙습니다.\n수미 씨의 책 덕분에 과제를 잘할 수 있었습니다.\n그런데 책을 언제 ( ㉡ )?\n시간을 말씀해 주시면 찾아가겠습니다.\n그럼 답장 기다리겠습니다.","blanks":[{"slot":"㉠","model":"빌려줘서 / 빌려주셔서","check":"«지난번에 책을 ( ㉠ ) 고맙습니다» + «수미 씨의 책 덕분에 과제를 잘할 수 있었습니다» → благодарит за то, что ДАЛА книгу почитать. Конструкция «N을 V-아서 고맙습니다»: 빌려주다 + -아서. Вежливо — 빌려주셔서."},{"slot":"㉡","model":"돌려주면 될까요 / 돌려드리면 될까요 / 돌려드릴까요","check":"«그런데 책을 언제 ( ㉡ )?» (вопрос, конец на «?») + «시간을 말씀해 주시면 찾아가겠습니다» → спрашивает, КОГДА вернуть книгу (придёт сам). 책을 돌려주다 + вопрос: 돌려주면 될까요? / 돌려드리면 될까요? Формальный стиль."}]},{"n":52,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. Текст о связи мимики и эмоций — письменный стиль -ㄴ다/-는다.","passage":"우리는 기분이 좋으면 밝은 표정을 짓는다. 그리고 기분이 좋지 않으면 표정이 어두워진다. 왜냐하면 ( ㉠ ). 그런데 이와 반대로 표정이 우리의 감정에 영향을 주기도 한다. 그래서 기분이 안 좋을 때 밝은 표정을 지으면 기분도 따라서 좋아진다. 그러므로 우울할 때일수록 ( ㉡ ) 것이 좋다.","blanks":[{"slot":"㉠","model":"감정이 표정에 영향을 주기 때문이다 / 기분이 표정에 영향을 미치기 때문이다","check":"«기분이 좋으면 밝은 표정 … 좋지 않으면 표정이 어두워진다. 왜냐하면 ( ㉠ ).» Маркер 왜냐하면 → причина: настроение (감정/기분) влияет на мимику. Конструкция 왜냐하면 … -기 때문이다. Стиль -ㄴ다."},{"slot":"㉡","model":"밝은 표정을 짓는 / 일부러라도 밝은 표정을 짓는 / 밝게 웃는","check":"«그러므로 우울할 때일수록 ( ㉡ ) 것이 좋다.» Логика: мимика влияет на эмоции, улыбка поднимает настроение → чем грустнее, тем лучше сделать радостное лицо. Пропуск — определение к 것 на «-는»: 밝은 표정을 짓는 (것이 좋다)."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음을 참고하여 '아이를 꼭 낳아야 하는가'에 대한 글을 200~300자로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные опроса «아이를 꼭 낳아야 하는가» (обязательно ли иметь детей) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.","image":"assets/topik2/exams/img/52-w53.png","model":"결혼문화연구소에서 20대 이상 성인 남녀 3,000명을 대상으로 ‘아이를 꼭 낳아야 하는가’에 대해 조사하였다. 그 결과 ‘그렇다’라고 응답한 비율은 남자가 80%, 여자가 67%로 나타났으며, ‘아니다’라고 응답한 비율은 남자가 20%, 여자가 33%였다. ‘아니다’라고 답한 이유를 보면, 남자는 ‘양육비 부담’을 1위로, ‘자유로운 생활’을 2위로 꼽았다. 반면 여자는 ‘자유로운 생활’을 1위로, ‘직장 생활 유지’를 2위로 꼽아 남녀 간에 차이를 보였다.","check":"① 기관(결혼문화연구소)·대상(20대 이상 성인 남녀 3,000명)? ② 그렇다 남 80%/여 67%, 아니다 남 20%/여 33%? ③ 아니다 이유 — 남(양육비 부담→자유로운 생활), 여(자유로운 생활→직장 생활 유지)? ④ письменный стиль -ㄴ다, без заголовка, 200–300 знаков?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 주제로 하여 자신의 생각을 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков на тему «의사소통의 중요성과 방법» (важность и способы общения). Раскройте все три вопроса из задания, каждый — отдельным абзацем; задание дословно не переписывайте.","passage":"우리는 살면서 서로의 생각이 달라 갈등을 겪는 경우가 많다. 이러한 갈등은 의사소통이 부족해서 생기는 경우가 대부분이며, 의사소통은 서로의 관계를 유지하고 발전시키는 데 중요한 요인이 된다. 아래의 내용을 중심으로 '의사소통의 중요성과 방법'에 대해 자신의 생각을 쓰라.\n• 의사소통은 왜 중요한가?\n• 의사소통이 잘 이루어지지 않는 이유는 무엇인가?\n• 의사소통을 원활하게 하는 방법은 무엇인가?","model":"의사소통은 사람과 사람 사이의 관계를 이어 주는 다리와 같다. 우리는 의사소통을 통해 자신의 생각과 감정을 전달하고 상대방을 이해하게 된다. 의사소통이 원활하면 서로에 대한 오해가 줄고 신뢰가 쌓이지만, 그렇지 못하면 작은 일에도 갈등이 생기기 쉽다. 특히 가정이나 직장처럼 사람들이 함께 어울려 지내는 곳에서는 원활한 의사소통이 공동의 문제를 해결하는 바탕이 되기 때문에 그 중요성은 더욱 크다.\n\n그런데 의사소통은 생각만큼 쉽게 이루어지지 않는다. 가장 큰 이유는 사람들이 자신의 입장에서만 말하고 상대방의 말을 끝까지 듣지 않기 때문이다. 또한 같은 말이라도 사람마다 다르게 받아들이기 때문에 의도하지 않은 오해가 생기기도 한다. 자신의 감정을 솔직하게 표현하지 못하거나, 상대를 배려하지 않고 일방적으로 자기 주장만 내세우는 태도 역시 원활한 의사소통을 가로막는 원인이 된다.\n\n의사소통을 원활하게 하려면 무엇보다 상대방의 말을 끝까지 잘 듣는 자세가 필요하다. 상대의 입장에서 생각하며 그 마음을 헤아리려고 노력해야 한다. 그리고 자신의 생각은 상대가 기분이 상하지 않도록 분명하면서도 부드럽게 전달하는 것이 좋다. 이렇게 서로 존중하고 배려하는 태도로 꾸준히 대화한다면 갈등은 자연스럽게 줄어들고 사람들 사이의 관계는 더욱 깊어질 것이다.","check":"① Все 3 вопроса (왜 중요한가 / 잘 안 되는 이유 / 원활하게 하는 방법) — каждый отдельным абзацем? ② Вступление и вывод? ③ Связки уровня (그런데, 또한, 무엇보다, 그리고, 이렇게)? ④ Стиль -ㄴ다, без разговорных форм? ⑤ Объём 600–700 знаков, задание не переписано дословно?"}]
      },
      listening: {
        durationMin: 60, total: 100, label: '제52회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/52/52nd%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"instr":"Прослушайте диалог и выберите подходящую картинку. (2 балла)","image":"assets/topik2/exams/img/52-l-q1.png","options":["①","②","③","④"],"answer":2,"explain":"🎧 여자: 어디가 아파서 오셨어요? / 남자: 배가 아파서 왔는데요. / 여자: 그럼 여기 이름과 생년월일을 쓰시고 잠깐 기다리세요.<br>Сцена в больнице: сотрудница на стойке регистрации спрашивает, что болит, и просит записать имя и дату рождения и подождать.<br>✅ <b>②</b> — стойка приёма (접수처): женщина за стойкой, пациент стоит перед ней.<br>✖️ ① осмотр у врача на кушетке, ③ пациент уже лежит под капельницей, ④ зона ожидания — это всё ПОСЛЕ регистрации.<br>🧩 접수(приём), 생년월일=дата рождения, 잠깐 기다리세요=подождите немного."},{"n":2,"points":2,"instr":"Прослушайте диалог и выберите подходящую картинку. (2 балла)","image":"assets/topik2/exams/img/52-l-q2.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 남자: 청소 다 했는데 설거지 좀 도와줄까요? / 여자: 괜찮아요. 거의 다 했으니까 앉아서 좀 쉬어요. / 남자: 그럼 설거지 끝나면 차 한 잔 같이 마셔요.<br>Кухня: женщина моет посуду (거의 다 했으니까), мужчина закончил уборку и предлагает помочь, она отказывается.<br>✅ <b>①</b> — женщина у раковины моет посуду, мужчина рядом предлагает помощь.<br>✖️ Остальные картинки не отражают «женщина моет посуду / мужчина предлагает помощь».<br>🧩 설거지=мытьё посуды, 도와줄까요?=помочь?, 거의 다 했어요=почти закончила."},{"n":3,"points":2,"instr":"Прослушайте диалог и выберите подходящую картинку. (2 балла)","image":"assets/topik2/exams/img/52-l-q3.png","options":["①","②","③","④"],"answer":2,"explain":"🎧 남자: 여러분은 운동을 자주 하십니까? 문화체육관광부 조사 결과에 따르면 우리 국민의 주 1회 이상 생활체육에 참여하는 비율은 2014년 이후 계속해서 증가한 것으로 나타났습니다. 가장 많이 하는 운동은 ‘걷기’였으며 그 다음은 ‘등산’, 그리고 ‘헬스’가 그 뒤를 이었습니다.<br>✅ <b>②</b> — линейный график «생활체육 참여율», который НЕПРЕРЫВНО растёт с 2014 г. (계속해서 증가).<br>✖️ ① линия сначала падает, потом растёт — не «계속 증가». ③④ кольцевые диаграммы по видам спорта (걷기 60% / 등산 / 헬스) — это другой показатель, а не рост участия.<br>🧩 비율=доля, 증가하다=расти, 그 뒤를 잇다=следовать за."},{"n":4,"points":2,"instr":"Прослушайте диалог и выберите реплику, которая может его продолжить. (2 балла)","options":["찾아서 다행이네요.","천천히 잘 찾아봐요.","가방을 찾고 있는데요.","아무리 찾아도 없어서요."],"answer":2,"explain":"🎧 남자: 왜 그래요? 뭐 잃어버렸어요? / 여자: 제 가방이 어디에 있는지 모르겠어요. / 남자: ___<br>Женщина не знает, где её сумка. Естественный ответ — успокоить и предложить поискать.<br>✅ <b>②</b> 천천히 잘 찾아봐요 — «не спеши, поищи внимательно».<br>✖️ ① «хорошо, что нашлась» (ещё не нашлась), ③/④ говорил бы тот, кто сам ищет/не нашёл.<br>🧩 잃어버리다=терять, 아무리 ~아도=сколько бы ни."},{"n":5,"points":2,"instr":"Прослушайте диалог и выберите реплику, которая может его продолжить. (2 балла)","options":["점심 먹으러 갈래요?","점심시간이 언제예요?","식사 맛있게 하셨어요?","다른 데 가서 먹을까요?"],"answer":4,"explain":"🎧 남자: 점심시간이 지났는데 식당에 사람이 많네요. / 여자: 그러네요. 밥 먹으려면 한참 기다려야겠어요. / 남자: ___<br>Ресторан переполнен, ждать долго. Логичное предложение — поесть в другом месте.<br>✅ <b>④</b> 다른 데 가서 먹을까요? — «может, поедим в другом месте?»<br>✖️ ① зовёт на обед (они уже у ресторана), ② спрашивает время обеда, ③ «вкусно поели?» — не к месту.<br>🧩 한참=довольно долго, 다른 데=другое место."},{"n":6,"points":2,"instr":"Прослушайте диалог и выберите реплику, которая может его продолжить. (2 балла)","options":["다행히 잘 본 거 같아요.","생각보다 시험이 어렵네요.","떨지 말고 면접시험 잘 보세요.","열심히 준비했으니까 잘 될 거예요."],"answer":4,"explain":"🎧 남자: 수미 씨, 면접시험은 어땠어요? 잘 본 거 같아요? / 여자: 잘할 수 있을지는 몰랐는데 생각보다 잘 본 것 같아요. / 남자: ___<br>Женщина сдала собеседование лучше, чем ожидала. Мужчина подбадривает.<br>✅ <b>④</b> 열심히 준비했으니까 잘 될 거예요 — «ты усердно готовилась, всё будет хорошо».<br>✖️ ① так сказала бы сама женщина, ② про сложность экзамена, ③ совет ПЕРЕД собеседованием (оно уже прошло).<br>🧩 면접시험=собеседование, 떨다=волноваться/дрожать."},{"n":7,"points":2,"instr":"Прослушайте диалог и выберите реплику, которая может его продолжить. (2 балла)","options":["학교 홈페이지에 있던데요.","다음 학기에 신청하려고 해요.","이미 교환 학생 신청을 했어요.","벌써 학생 선발이 끝난 것 같아요."],"answer":1,"explain":"🎧 남자: 수미 씨, 다음 주까지 교환 학생 신청 기간이라던데 신청할 거예요? / 여자: 그래요? 어떻게 알았어요? / 남자: ___<br>Женщина спрашивает, ОТКУДА он узнал о сроках. Ответ — источник информации.<br>✅ <b>①</b> 학교 홈페이지에 있던데요 — «было на сайте школы».<br>✖️ ②③ про собственную подачу заявки, ④ «отбор уже закончился» — противоречит «기간이라던데».<br>🧩 교환 학생=студент по обмену, 신청 기간=срок подачи, -던데요=обнаруженный факт."},{"n":8,"points":2,"instr":"Прослушайте диалог и выберите реплику, которая может его продолжить. (2 балла)","options":["화장품 좀 주문하려고 하는데요.","그럼 언제쯤 다시 받을 수 있을까요?","이 화장품 써 보니까 정말 좋은데요.","주문하신 날짜를 말씀해 주시겠어요?"],"answer":2,"explain":"🎧 여자: 저, 화장품을 주문했었는데요. 제가 주문한 제품과 다른 게 와서요. / 남자: 아, 죄송합니다, 고객님. 물건을 저희에게 보내 주시면 확인하고 주문하신 제품으로 다시 보내 드리겠습니다. / 여자: ___<br>Пришёл не тот товар; продавец обещает выслать правильный после возврата. Покупательница уточняет срок.<br>✅ <b>②</b> 그럼 언제쯤 다시 받을 수 있을까요? — «когда я смогу получить заново?»<br>✖️ ① хочет заказать (она уже заказала), ③ хвалит товар, ④ это реплика продавца.<br>🧩 화장품=косметика, 환불/교환 контекст, 언제쯤=примерно когда."},{"n":9,"points":2,"instr":"Прослушайте диалог и выберите подходящее следующее действие женщины. (2 балла)","options":["옷을 맡긴다.","코트를 산다.","세탁소에 간다.","우편물을 가져온다."],"answer":3,"explain":"🎧 여자: 민수 씨, 지난번에 산 내 검은색 코트 못 봤어요? / 남자: 그거 월요일에 세탁소에 맡겼잖아요. 내가 찾아다 줄까요? / 여자: 괜찮아요. 그냥 내가 가서 찾아올게요. / 남자: 그럼 들어올 때 우편물도 좀 갖다 줘요.<br>Пальто сдано в химчистку; женщина решает САМА сходить и забрать его.<br>✅ <b>③</b> 세탁소에 간다 — идёт в химчистку.<br>✖️ ① сдаёт одежду (уже сдано), ② покупает пальто, ④ принести почту — это потом, на обратном пути.<br>🧩 세탁소=химчистка, 맡기다=сдавать, 찾아오다=забрать."},{"n":10,"points":2,"instr":"Прослушайте диалог и выберите подходящее следующее действие женщины. (2 балла)","options":["안내 책자를 꺼낸다.","안내 책자를 받는다.","거래처 직원을 만난다.","상자를 책상 밑에 둔다."],"answer":1,"explain":"🎧 여자: 여보세요? 민수 씨, 옆 사무실에서 안내 책자 받으러 왔는데요. / 남자: 아, 네. 제가 밖에서 거래처 직원을 만나고 있어서요. 미안하지만 수미 씨가 상자에서 좀 꺼내서 주시겠어요? / 여자: 네, 그럴게요. 그런데 상자는 어디에 있어요? / 남자: 제 책상 밑에 뒀어요.<br>Мужчина просит самой достать буклеты из коробки под его столом.<br>✅ <b>①</b> 안내 책자를 꺼낸다 — достаёт буклеты (из коробки).<br>✖️ ② получает буклеты (их пока надо достать), ③ встречу с клиентом ведёт мужчина, ④ коробку под стол поставил он.<br>🧩 안내 책자=буклет, 꺼내다=доставать, 거래처=деловой партнёр."},{"n":11,"points":2,"instr":"Прослушайте диалог и выберите подходящее следующее действие женщины. (2 балла)","options":["전등을 산다.","전등을 찾는다.","전등을 바꾼다.","전등을 가져온다."],"answer":2,"explain":"🎧 여자: 여보, 욕실 전등을 좀 바꿔야겠어요. / 남자: 그래요? 집에 전등 사다 놓은 거 있으면 가져와 봐요. / 여자: 잠깐만요. 어디 있는지 찾아볼게요. / 남자: 없으면 말해요. 내가 사러 갈게요.<br>Нужно заменить лампу в ванной; муж просит принести запасную, жена идёт ИСКАТЬ её.<br>✅ <b>②</b> 전등을 찾는다 — ищет лампочку (어디 있는지 찾아볼게요).<br>✖️ ① покупать пойдёт муж (если не найдётся), ③ заменить — это позже, ④ принести можно лишь после того, как найдёт.<br>🧩 전등=лампа, 욕실=ванная, 찾아보다=поискать."},{"n":12,"points":2,"instr":"Прослушайте диалог и выберите подходящее следующее действие женщины. (2 балла)","options":["현황을 확인한다.","부장님께 보고한다.","인사과에 연락한다.","지원자 명단을 본다."],"answer":3,"explain":"🎧 여자: 과장님, 여기 해외 파견 근무 지원자 명단입니다. 한번 보시겠어요? / 남자: 아, 네. 이번에는 지원 현황이 어떻게 되지요? / 여자: 확인해 봤는데 생각보다 지원자가 적습니다. / 남자: 그거 큰일이군요. 그럼 인사과에 연락해서 추가 지원을 받을 수 있는지 알아보세요. 전 부장님께 말씀드릴게요.<br>Кандидатов меньше, чем ожидалось; начальник поручает женщине связаться с отделом кадров.<br>✅ <b>③</b> 인사과에 연락한다 — связывается с отделом кадров.<br>✖️ ① статус она уже проверила, ② доложить начальнику пойдёт мужчина (전 부장님께), ④ список она уже принесла.<br>🧩 해외 파견=командировка за рубеж, 지원자=кандидат, 인사과=отдел кадров."},{"n":13,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["남자는 모임에 참석했다.","여자는 교통사고를 당했다.","여자는 어제 모임에 안 갔다.","남자는 얼마 전에 자동차를 샀다."],"answer":4,"explain":"🎧 여자: 어제 모임에 왜 안 왔어? 연락도 없어서 궁금했잖아. / 남자: 응, 어제 가족이 교통사고가 나서 처리하느라 시간이 오래 걸렸거든. / 여자: 정말? 자동차 산 지 얼마 안 됐는데 속상하겠다. 어디 다친 데는 없고? / 남자: 응, 다행히 다친 데는 없어.<br>✅ <b>④</b> 남자는 얼마 전에 자동차를 샀다 — «자동차 산 지 얼마 안 됐는데».<br>✖️ ① мужчина НЕ пришёл на встречу, ② аварию попала его семья, не женщина, ③ женщина как раз была на встрече (это она спрашивает, почему его не было).<br>🧩 모임=встреча, 교통사고가 나다=случается ДТП, 산 지 얼마 안 되다=недавно купил."},{"n":14,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["이 세일 행사는 어제부터 시작했다.","모든 고객에게 양말을 선물로 준다.","선물을 받으려면 행사장으로 가야 한다.","행사장에 가면 청바지를 만 원에 살 수 있다."],"answer":4,"explain":"🎧 (딩동댕) 고객님들께 쇼핑 안내드립니다. 행사장에서는 청바지를 만 원에 세일하고 있습니다. 이 행사는 오늘 하루만 진행되니 고객 여러분들의 많은 관심 부탁드립니다. 또한 오늘 저희 쇼핑몰에서 5만 원 이상 구매하신 분들께는 양말을 드립니다. 영수증을 가지고 고객센터로 오십시오.<br>✅ <b>④</b> 행사장에 가면 청바지를 만 원에 살 수 있다 — «청바지를 만 원에 세일».<br>✖️ ① акция только сегодня (오늘 하루만), ② носки — лишь покупателям от 50 000 вон, ③ за подарком надо идти в 고객센터, а не на 행사장.<br>🧩 세일=распродажа, 행사장=зона акции, 영수증=чек, 고객센터=сервисный центр."},{"n":15,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["비는 오늘 밤에 그칠 것이다.","제주 지역에는 눈이 내릴 것이다.","모레는 기온이 영하로 추워질 것이다.","내일 낮부터 전국적으로 비가 올 것이다."],"answer":3,"explain":"🎧 남자: 날씨 소식입니다. 현재 전국에 비가 내리고 제주도에는 폭우가 쏟아지고 있는데요. 이 비는 내일 아침에 대부분 그치겠고, 낮부터는 점차 맑아지겠습니다. 모레 아침에는 꽃샘추위가 찾아와 전국이 일시적으로 영하의 날씨를 보이겠는데요, 외출하실 때 따뜻하게 입으시는 것이 좋겠습니다.<br>✅ <b>③</b> 모레는 기온이 영하로 추워질 것이다 — «모레 아침 … 영하의 날씨».<br>✖️ ① дождь прекратится завтра утром, не сегодня ночью, ② на Чеджу — ливень (폭우), не снег, ④ с завтрашнего дня, наоборот, проясняется.<br>🧩 폭우=ливень, 그치다=прекращаться, 꽃샘추위=весеннее похолодание, 영하=ниже нуля."},{"n":16,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["여자는 한 달 전에 다리를 다쳤다.","여자는 운동을 시작한 지 1년이 됐다.","여자는 지금 다른 나라에서 선수 생활을 한다.","여자는 처음에 팀 동료들과 사이가 안 좋았다."],"answer":3,"explain":"🎧 남자: 국내 배구 선수로는 처음으로 해외 무대에 진출한 김미경 선수 나와 계시는데요. 지난 1년 어떠셨는지 말씀 좀 해 주시죠. / 여자: 처음에 말이 잘 안 통해서 힘들었는데요. 팀 동료들이 잘 챙겨 줘서 금방 적응할 수 있었습니다. 초반에 다리 부상으로 한 달간 경기에 못 나갔을 때 많이 답답했는데요. 복귀 후에는 팀이 우승하는 데 조금이나마 힘이 된 것 같아 기뻤습니다.<br>✅ <b>③</b> 여자는 지금 다른 나라에서 선수 생활을 한다 — «해외 무대에 진출».<br>✖️ ① травма была «в начале» (초반), не месяц назад, ② 1 год — это срок игры ЗА РУБЕЖОМ, а не начала спорта, ④ товарищи её хорошо приняли (잘 챙겨 줘서).<br>🧩 해외 무대 진출=выход на международную арену, 적응하다=адаптироваться, 복귀=возвращение."},{"n":17,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["결혼식을 하는 데 너무 많은 돈을 쓰면 안 된다.","결혼식은 많은 사람들이 축하해 줘야 한다.","결혼식 장소는 사람들이 찾아오기 편한 곳이 좋다.","결혼을 결정할 때 가족들의 의견을 고려해야 한다."],"answer":2,"explain":"🎧 남자: 친구 딸이 다음 달에 결혼한다며 가족들과 친한 친구들 몇몇만 부른다고 하더라고. 결혼식은 사람들 많이 초대하는 게 좋은 거 아니야? / 여자: 아니. 정말 가까운 사람들만 초대하는 거, 나는 좋은 것 같은데. 비용 부담도 적을 거고, 요즘 그런 작은 결혼식이 유행이더라. / 남자: 그래도, 평생에 한 번뿐인 결혼식인데 너무 작게 하면 서운할 것 같아.<br>✅ <b>②</b> 결혼식은 많은 사람들이 축하해 줘야 한다 — мужчина считает, что свадьбу должно праздновать много гостей.<br>✖️ ① про экономию говорит женщина, ③④ о месте/мнении семьи речи нет.<br>🧩 초대하다=приглашать, 평생에 한 번뿐=единственный раз в жизни, 서운하다=обидно/жаль."},{"n":18,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["회사 일을 혼자서 끝내면 안 된다.","소비자들의 의견을 잘 들어야 한다.","일을 같이 하는 사람들과 잘 지내야 한다.","발표 내용은 짧고 분명해야 하는 것이 좋다."],"answer":4,"explain":"🎧 남자: 수미 씨, 내일 신제품 발표 자료는 다 만들었어요? / 여자: 네, 여기 있습니다. 지난번에 말씀해 주신 부분 보충해서 준비했습니다. 과장님께서 먼저 한번 봐 주시겠어요? / 남자: 음, 내용이 너무 길고 복잡하네요. 제품의 특징을 짧지만 명확하게 소개해야 소비자들이 제품을 잘 이해할 수 있어요.<br>✅ <b>④</b> 발표 내용은 짧고 분명해야 한다 — «짧지만 명확하게 소개해야».<br>✖️ ① про «не делать в одиночку» речи нет, ② мнения потребителей здесь не слушают, ③ про отношения с коллегами не говорится.<br>🧩 발표 자료=материалы презентации, 명확하게=чётко, 특징=особенность."},{"n":19,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["물건은 마트에서 사는 것이 싸다.","물건은 조금만 사면 돈이 더 든다.","물건은 가격이 쌀 때 사 두어야 좋다.","물건은 필요할 때 조금씩 사는 게 좋다."],"answer":4,"explain":"🎧 여자: 어, 이 빵 지금 할인하네. 7개 묶어서 만 원밖에 안 하잖아. 우리도 사자. / 남자: 글쎄, 나는 마트에서 이렇게 파는 게 정말 싼 건지 잘 모르겠어. / 여자: 왜? 한 개씩 사면 비싼데 이럴 때 사면 싸게 살 수 있잖아. / 남자: 지난번에도 묶음으로 샀다가 다 못 먹고 반이나 버렸잖아. 그냥 먹고 싶을 때 조금씩 사서 먹는 게 오히려 돈을 아끼는 거라고.<br>✅ <b>④</b> 물건은 필요할 때 조금씩 사는 게 좋다 — покупать понемногу по мере надобности.<br>✖️ ①③ это позиция женщины (дешевле в маркете / брать про запас), ② противоречит словам мужчины.<br>🧩 할인=скидка, 묶음=набор/упаковка, 버리다=выбрасывать, 아끼다=экономить."},{"n":20,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["노래를 하는 사람은 정기적으로 앨범을 내야 한다.","음악을 만들 때는 여러 악기를 사용하는 것이 좋다.","악기 없이 가수의 목소리만으로 아름다운 음악을 만들 수 있다.","혼자 노래하는 것보다 여럿이 모여 노래하는 것이 좋다."],"answer":3,"explain":"🎧 여자: 이번 정규 앨범의 곡들 중 악기 없이 목소리만으로 노래한 곡들이 주목을 받고 있는데요. 이렇게 만드신 특별한 이유가 있나요? / 남자: 다양한 악기도 좋지만 저는 가수가 가진 목소리가 최고의 악기라고 생각합니다. 저희 4명만 모이면 악기가 없이도 멋있는 곡들을 언제 어디서나 사람들에게 들려 줄 수 있는데요. 저는 이렇게 가수들의 목소리만으로 아름다운 음악을 만들 수 있다고 생각합니다.<br>✅ <b>③</b> 악기 없이 목소리만으로 아름다운 음악을 만들 수 있다 — голос как «лучший инструмент».<br>✖️ ① про регулярность альбомов не сказано, ② наоборот, он за музыку БЕЗ инструментов, ④ речь не о числе исполнителей как принципе.<br>🧩 정규 앨범=полноформатный альбом, 악기=муз. инструмент, 목소리=голос."},{"n":21,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["우산이 홍보에 더 효과적이다.","우산은 만들 때 비용이 중요하다.","수첩에 학교 이름이 들어가야 한다.","수첩에 메모하는 습관을 길러야 한다."],"answer":1,"explain":"🎧 여자: 김 선생님, 올해 학교 홍보 용품은 뭐가 좋을까요? 작년처럼 우리 학교 이름이 들어간 수첩으로 할까요? / 남자: 글쎄요. 수첩은 학생들이 잘 사용하지 않아서 학교 홍보에 효과가 없는 것 같아요. 작년에 학생들 반응도 별로였고요. 이번에는 우산이 어떨까요? 우산은 자주 사용하는 거니까 우산에 학교 이름을 새기면 학교를 알리는 데 좋을 거예요. / 여자: 네, 알겠습니다. 그런데 무슨 색깔로 하는 게 좋을까요? / 남자: 글쎄요. 그건 다음에 다른 선생님들과 같이 결정하도록 하죠.<br>✅ <b>①</b> 우산이 홍보에 더 효과적이다 — блокнотами почти не пользуются, а зонт в ходу, потому зонт эффективнее для рекламы школы.<br>✖️ ② про стоимость изготовления не говорит, ③④ блокнот он как раз отвергает.<br>🧩 홍보 용품=рекламная продукция, 수첩=блокнот, 새기다=наносить/гравировать."},{"n":22,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["올해 처음으로 홍보 용품을 만들었다.","홍보 용품으로 수첩을 제작할 예정이다.","여자는 남자에게 홍보 용품을 보여 줬다.","홍보 용품의 색깔은 다음에 정하기로 했다."],"answer":4,"explain":"🎧 여자: 김 선생님, 올해 학교 홍보 용품은 뭐가 좋을까요? 작년처럼 우리 학교 이름이 들어간 수첩으로 할까요? / 남자: 글쎄요. 수첩은 학생들이 잘 사용하지 않아서 학교 홍보에 효과가 없는 것 같아요. 작년에 학생들 반응도 별로였고요. 이번에는 우산이 어떨까요? 우산은 자주 사용하는 거니까 우산에 학교 이름을 새기면 학교를 알리는 데 좋을 거예요. / 여자: 네, 알겠습니다. 그런데 무슨 색깔로 하는 게 좋을까요? / 남자: 글쎄요. 그건 다음에 다른 선생님들과 같이 결정하도록 하죠.<br>✅ <b>④</b> 홍보 용품의 색깔은 다음에 정하기로 했다 — «무슨 색깔로 … 그건 다음에 … 결정하도록 하죠».<br>✖️ ① в прошлом году уже делали (작년처럼), ② решили НЕ блокнот, а зонт, ③ женщина ничего не показывала — это разговор-обсуждение.<br>🧩 제작하다=изготавливать, 결정하다=решать, 색깔=цвет."},{"n":23,"points":2,"instr":"Прослушайте и выберите, что делает мужчина. (2 балла)","options":["박물관 관람 예약을 하고 있다.","박물관의 위치를 안내하고 있다.","박물관 이용에 대해 묻고 있다.","박물관에서 식사 예약을 확인하고 있다."],"answer":3,"explain":"🎧 남자: 여보세요. 어린이박물관이죠? 오늘 2시 표 예매했는데요. 혹시 일찍 도착하면 1시에도 들어갈 수 있는지 해서요. / 여자: 네, 안녕하세요? 그러시면 입구에서 2시 관람권은 환불 받으시고 1시 관람권을 새로 사시면 됩니다. / 남자: 네, 알겠습니다. 그런데 혹시 박물관 안에 식사가 가능한 곳이 있나요? / 여자: 따로 식당은 마련되어 있지 않습니다. 대신 3층에 가족 쉼터가 있는데요, 거기에서 준비해 오신 음식을 드실 수 있습니다.<br>✅ <b>③</b> 박물관 이용에 대해 묻고 있다 — спрашивает о раннем входе и о еде внутри.<br>✖️ ① бронь он уже сделал (예매했는데요), ② местоположение объясняет сотрудница, не он, ④ он не «подтверждает бронь столика».<br>🧩 예매=предварительная покупка билета, 환불=возврат, 쉼터=зона отдыха."},{"n":24,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["이 박물관은 관람권을 환불 받을 수 없다.","박물관에는 음식을 가지고 들어갈 수 없다.","이 박물관은 표를 예매하지 않아도 입장이 가능하다.","이 박물관은 자체적으로 식당을 운영하고 있다."],"answer":3,"explain":"🎧 남자: 여보세요. 어린이박물관이죠? 오늘 2시 표 예매했는데요. 혹시 일찍 도착하면 1시에도 들어갈 수 있는지 해서요. / 여자: 네, 안녕하세요? 그러시면 입구에서 2시 관람권은 환불 받으시고 1시 관람권을 새로 사시면 됩니다. / 남자: 네, 알겠습니다. 그런데 혹시 박물관 안에 식사가 가능한 곳이 있나요? / 여자: 따로 식당은 마련되어 있지 않습니다. 대신 3층에 가족 쉼터가 있는데요, 거기에서 준비해 오신 음식을 드실 수 있습니다.<br>✅ <b>③</b> 표를 예매하지 않아도 입장이 가능하다 — 1시 관람권을 입구에서 «새로 사시면 됩니다» (можно купить на месте).<br>✖️ ① возврат как раз возможен (환불 받으시고), ② еду пронести МОЖНО (준비해 오신 음식을 드실 수 있습니다), ④ своей столовой нет (따로 식당은 마련되어 있지 않습니다).<br>🧩 관람권=входной билет, 입장=вход, 마련되다=быть подготовленным."},{"n":25,"points":2,"instr":"Прослушайте и выберите главную мысль мужчины. (2 балла)","options":["기업은 시민 영웅을 채용해야 한다.","기업은 사회에 도움이 되는 일에 앞장서야 한다.","시민 영웅은 사회의 모범이 되도록 노력해야 한다.","언론은 숨어 있는 시민 영웅을 찾아 알려야 한다."],"answer":2,"explain":"🎧 여자: 사장님께서는 어려운 이웃을 돕고 가난한 학생들을 지원하는 등 훌륭한 일을 많이 하고 계시는데요. 최근에는 ‘시민 영웅상’을 만드셨다고 들었는데요. 그게 어떤 상인가요? / 남자: 네, 우리 주변에는 알려지지 않았지만 사회에 모범이 되는 분들이 있는데요, 그런 분들을 찾아서 상을 드리는 것입니다. 수상자가 원하지 않으면 시상식은 언론에 공개하지 않고 조용하게 진행합니다. 그동안 31명의 시민 영웅을 찾아 상장과 상금을 드렸는데요, 상금을 이웃을 위해 다시 기부하는 분도 계셨습니다. 또 화재 현장에서 아이를 구조한 대학생 수상자도 있었는데 졸업 후에 회사가 채용하기도 했습니다. 이렇게 사회로부터 받은 이익을 다시 사회로 돌려주는 것이 기업의 책임이라고 생각합니다.<br>✅ <b>②</b> 기업은 사회에 도움이 되는 일에 앞장서야 한다 — «받은 이익을 다시 사회로 돌려주는 것이 기업의 책임».<br>✖️ ① трудоустройство — лишь частный пример, ③ про усилия самих героев речи нет, ④ это не про роль СМИ.<br>🧩 시민 영웅=гражданский герой, 기부하다=жертвовать, 앞장서다=брать на себя инициативу."},{"n":26,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["이 기업에 입사한 시민 영웅이 있다.","이 상은 시상식을 하지 않는다.","이 상은 최근에 시민 영웅을 찾았다.","이 상은 시민들로부터 기부금을 모아 만들었다."],"answer":1,"explain":"🎧 여자: 사장님께서는 어려운 이웃을 돕고 가난한 학생들을 지원하는 등 훌륭한 일을 많이 하고 계시는데요. 최근에는 ‘시민 영웅상’을 만드셨다고 들었는데요. 그게 어떤 상인가요? / 남자: 네, 우리 주변에는 알려지지 않았지만 사회에 모범이 되는 분들이 있는데요, 그런 분들을 찾아서 상을 드리는 것입니다. 수상자가 원하지 않으면 시상식은 언론에 공개하지 않고 조용하게 진행합니다. 그동안 31명의 시민 영웅을 찾아 상장과 상금을 드렸는데요, 상금을 이웃을 위해 다시 기부하는 분도 계셨습니다. 또 화재 현장에서 아이를 구조한 대학생 수상자도 있었는데 졸업 후에 회사가 채용하기도 했습니다. 이렇게 사회로부터 받은 이익을 다시 사회로 돌려주는 것이 기업의 책임이라고 생각합니다.<br>✅ <b>①</b> 이 기업에 입사한 시민 영웅이 있다 — спасшего ребёнка студента «졸업 후에 회사가 채용».<br>✖️ ② церемония бывает (по желанию лауреата её просто не открывают прессе), ③ героев находят «그동안» (давно, 31 человек), ④ премию учредил сам предприниматель, а не на пожертвования граждан.<br>🧩 수상자=лауреат, 시상식=церемония награждения, 채용하다=нанимать."},{"n":27,"points":2,"instr":"Прослушайте и выберите намерение мужчины (зачем он это говорит женщине). (2 балла)","options":["임시 공휴일을 지정하게 된 이유를 알려 주기 위해","임시 공휴일에 못 쉬는 것에 대한 불만을 제기하기 위해","임시 공휴일이 회사 운영에 미치는 영향을 파악하기 위해","임시 공휴일 지정으로 연휴가 되는 점을 강조하기 위해"],"answer":2,"explain":"🎧 남자: 뉴스를 보니까 정부에서 다음 달 6일을 임시 공휴일로 지정했다던데. / 여자: 그래? 5일하고 7일이 쉬는 날이라서 그런 모양이구나. 그날 쉬는 사람들은 좋겠다. 지난번 임시 공휴일에도 놀러 가는 사람이 많았대. / 남자: 우리 회사도 쉬면 좋을 텐데. 임시 공휴일에는 우리도 쉬어야 하는 거 아냐? / 여자: 맞아. 그날 회사에 나와야 하는데 아이 유치원이 쉬니까 당장 아이 맡길 데를 알아봐야 해. / 남자: 우리처럼 못 쉬는 사람한테는 임시 공휴일이 별 소용이 없는 것 같아.<br>✅ <b>②</b> 못 쉬는 것에 대한 불만을 제기 — «우리처럼 못 쉬는 사람한테는 … 별 소용이 없는 것 같아».<br>✖️ ① причину назначения он не объясняет, ③ влияние на работу фирмы не выясняет, ④ длинные выходные он как раз НЕ получит.<br>🧩 임시 공휴일=временный праздничный (выходной) день, 불만을 제기하다=выражать недовольство, 소용이 없다=бесполезно."},{"n":28,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["유치원은 임시 공휴일에 쉬지 않는다.","남자는 임시 공휴일에 여행을 가려고 한다.","여자는 아이를 맡길 곳이 없어서 걱정하고 있다.","정부는 이번에 처음으로 임시 공휴일을 지정했다."],"answer":3,"explain":"🎧 남자: 뉴스를 보니까 정부에서 다음 달 6일을 임시 공휴일로 지정했다던데. / 여자: 그래? 5일하고 7일이 쉬는 날이라서 그런 모양이구나. 그날 쉬는 사람들은 좋겠다. 지난번 임시 공휴일에도 놀러 가는 사람이 많았대. / 남자: 우리 회사도 쉬면 좋을 텐데. 임시 공휴일에는 우리도 쉬어야 하는 거 아냐? / 여자: 맞아. 그날 회사에 나와야 하는데 아이 유치원이 쉬니까 당장 아이 맡길 데를 알아봐야 해. / 남자: 우리처럼 못 쉬는 사람한테는 임시 공휴일이 별 소용이 없는 것 같아.<br>✅ <b>③</b> 여자는 아이를 맡길 곳이 없어서 걱정 — «아이 유치원이 쉬니까 당장 아이 맡길 데를 알아봐야 해».<br>✖️ ① детсад как раз закрыт (유치원이 쉬니까), ② про поездку мужчины не сказано, ④ были и прошлые временные выходные (지난번 임시 공휴일에도).<br>🧩 유치원=детсад, 맡기다=оставлять (на попечение), 걱정하다=беспокоиться."},{"n":29,"points":2,"instr":"Прослушайте и выберите, кто такой мужчина. (2 балла)","options":["식물의 향기를 분석하는 사람","꽃을 잘 키우는 방법을 연구하는 사람","식물의 재배 방법을 연구하는 사람","식물을 활용해 사람들을 치료하는 사람"],"answer":4,"explain":"🎧 여자: 정원 꾸미기 좋은 계절인데요, 선생님은 여기에서 어떤 일을 하시나요? / 남자: 이곳은 제가 환자들에게 정원 가꾸기를 가르치고 있는 곳인데요, 저는 약을 사용하지 않고 식물을 이용해 그분들의 몸과 마음의 회복을 돕는 활동을 하고 있어요. 식물을 재배하면서 자연스럽게 치료 효과를 얻게 되는 거죠. / 여자: 구체적으로 어떤 활동을 통해서 치료가 이루어지나요? / 남자: 정원 가꾸기, 식물 재배하기, 꽃을 이용한 작품 만들기 등의 활동이 대표적인데요, 이런 크고 작은 신체 활동은 운동 능력을 향상시킬 수 있어요. 또한 식물의 향기를 맡으면서 느끼는 기쁨은 치료에 이용하는 것이죠. 정원에서 함께 재배한 식물을 판매함으로써 경제적으로 어려움을 겪는 환자들에게 작은 도움도 드리고 있고요.<br>✅ <b>④</b> 식물을 활용해 사람들을 치료하는 사람 — садовая (растительная) терапия: лечит без лекарств, через выращивание растений.<br>✖️ ①②③ он не «анализирует аромат», не «исследует методы выращивания» — он ЛЕЧИТ пациентов с помощью растений.<br>🧩 정원 가꾸기=уход за садом, 재배하다=выращивать, 회복=восстановление."},{"n":30,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["남자는 식물의 향기를 이용해 약을 만든다.","정원에서 재배하는 식물은 판매하지 않는다.","남자는 환자들에게 정원 가꾸는 법을 배웠다.","식물을 재배하는 활동은 운동 능력을 향상시킨다."],"answer":4,"explain":"🎧 여자: 정원 꾸미기 좋은 계절인데요, 선생님은 여기에서 어떤 일을 하시나요? / 남자: 이곳은 제가 환자들에게 정원 가꾸기를 가르치고 있는 곳인데요, 저는 약을 사용하지 않고 식물을 이용해 그분들의 몸과 마음의 회복을 돕는 활동을 하고 있어요. 식물을 재배하면서 자연스럽게 치료 효과를 얻게 되는 거죠. / 여자: 구체적으로 어떤 활동을 통해서 치료가 이루어지나요? / 남자: 정원 가꾸기, 식물 재배하기, 꽃을 이용한 작품 만들기 등의 활동이 대표적인데요, 이런 크고 작은 신체 활동은 운동 능력을 향상시킬 수 있어요. 또한 식물의 향기를 맡으면서 느끼는 기쁨은 치료에 이용하는 것이죠. 정원에서 함께 재배한 식물을 판매함으로써 경제적으로 어려움을 겪는 환자들에게 작은 도움도 드리고 있고요.<br>✅ <b>④</b> 식물 재배 활동은 운동 능력을 향상시킨다 — «이런 크고 작은 신체 활동은 운동 능력을 향상시킬 수 있어요».<br>✖️ ① он лекарств НЕ делает (약을 사용하지 않고), ② выращенные растения как раз продают (판매함으로써), ③ он сам УЧИТ пациентов, а не научился у них (가르치고 있는).<br>🧩 향상시키다=повышать, 판매하다=продавать, 가르치다=обучать."},{"n":31,"points":2,"instr":"Прослушайте и выберите мысль мужчины. (2 балла)","options":["유동 인구가 많은 곳에 매장을 만들어야 한다.","매장의 임대료가 매년 상승하는 것은 바람직하지 않다.","지역에 따라 동일 제품의 가격이 다른 것은 불합리하다.","매장의 관리 비용을 고려하여 커피 값을 책정해야 한다."],"answer":3,"explain":"🎧 남자: 같은 커피 전문점의 커피가 지역별로 가격이 다른 것에 소비자들이 불만을 표하고 있습니다. 동일한 재료와 방법으로 만드는데 왜 가격이 다른지 이해할 수가 없습니다. / 여자: 커피 값은 임대료 등 매장의 여건에 따라 가격이 다를 수 있다고 생각합니다. / 남자: 그렇다면 임대료가 낮은 지역의 커피 값이 비싼 이유는 뭡니까? / 여자: 임대료만이 커피 값의 가장 중요한 기준이 되는 건 아닙니다. 시설이나 관리 비용 등 다양한 요인이 있는 거지요. 예를 들어 휴게소처럼 커피를 매장에서 마시지 않고 그냥 사 가는 손님이 많은 곳은 다른 곳에 비해 커피 값을 싸게 받을 수 있는 것이지요.<br>✅ <b>③</b> 지역에 따라 동일 제품의 가격이 다른 것은 불합리하다 — «동일한 재료와 방법으로 만드는데 왜 가격이 다른지 이해할 수가 없습니다».<br>✖️ ①②④ это доводы/объяснения женщины (расположение, аренда, расходы), а не позиция мужчины.<br>🧩 임대료=арендная плата, 불합리하다=нерационально/несправедливо, 책정하다=устанавливать (цену)."},{"n":32,"points":2,"instr":"Прослушайте и выберите подходящее описание позиции (отношения) мужчины. (2 балла)","options":["현재의 상황을 비판하고 있다.","자신의 주장을 합리화하고 있다.","문제에 대한 해결책을 제시하고 있다.","상대방의 의견을 긍정적으로 평가하고 있다."],"answer":1,"explain":"🎧 남자: 같은 커피 전문점의 커피가 지역별로 가격이 다른 것에 소비자들이 불만을 표하고 있습니다. 동일한 재료와 방법으로 만드는데 왜 가격이 다른지 이해할 수가 없습니다. / 여자: 커피 값은 임대료 등 매장의 여건에 따라 가격이 다를 수 있다고 생각합니다. / 남자: 그렇다면 임대료가 낮은 지역의 커피 값이 비싼 이유는 뭡니까? / 여자: 임대료만이 커피 값의 가장 중요한 기준이 되는 건 아닙니다. 시설이나 관리 비용 등 다양한 요인이 있는 거지요. 예를 들어 휴게소처럼 커피를 매장에서 마시지 않고 그냥 사 가는 손님이 많은 곳은 다른 곳에 비해 커피 값을 싸게 받을 수 있는 것이지요.<br>✅ <b>①</b> 현재의 상황을 비판하고 있다 — мужчина критикует то, что цены на одинаковый кофе различаются.<br>✖️ ② он не «оправдывает свою выгоду», ③ решения не предлагает (только возражает), ④ мнение собеседницы он, наоборот, оспаривает.<br>🧩 비판하다=критиковать, 합리화=рационализация/оправдание, 해결책=решение."},{"n":33,"points":2,"instr":"Прослушайте и выберите, о чём идёт речь. (2 балла)","options":["지명이 만들어진 배경","지명을 연구하는 이유","지명을 보존하는 방법","지명이 변천하는 과정"],"answer":1,"explain":"🎧 여자: 제 고향에 ‘소목비’라고 부르는 곳이 있습니다. 좀 독특한 지명이죠? 지명이 소가 누워 있는 형상인데, 소의 목 부분에 있는 마을이라고 해서 그렇게 불린다고 하네요. 이렇게 지명을 들여다보면 그 마을의 특징을 알 수 있는 경우가 많습니다. 동네 뒷산에 토끼가 많이 산다고 해서 ‘토끼섬’이라 불리는 곳도 있습니다. ‘땅끝마을’은 우리나라의 육지 중 가장 남쪽 끝에 붙어 있는 마을이라서 그렇게 붙은 이름이고요. 그럼 ‘두물머리’라는 지명은 왜 나온 것일까요? (잠시 후) 네, 그렇습니다. 그곳은 한강의 두 물길이 하나로 만나는 곳에 위치한 마을이라서 그렇게 불립니다.<br>✅ <b>①</b> 지명이 만들어진 배경 — лектор объясняет, ПОЧЕМУ появились названия мест (토끼섬, 땅끝마을, 두물머리…).<br>✖️ ② причины изучать топонимы, ③ способы сохранять, ④ процесс изменения — этого в речи нет.<br>🧩 지명=топоним, 형상=форма/облик, 유래=происхождение."},{"n":34,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["토끼섬은 지명이 토끼의 귀 모양을 닮은 곳이다.","두물머리는 한강의 물길이 하나로 합쳐지는 곳이다.","소목비는 소를 많이 키우는 지역에서 붙여진 이름이다.","땅끝마을은 한국의 가장 남쪽 끝에 있는 섬 이름이다."],"answer":2,"explain":"🎧 여자: 제 고향에 ‘소목비’라고 부르는 곳이 있습니다. 좀 독특한 지명이죠? 지명이 소가 누워 있는 형상인데, 소의 목 부분에 있는 마을이라고 해서 그렇게 불린다고 하네요. 이렇게 지명을 들여다보면 그 마을의 특징을 알 수 있는 경우가 많습니다. 동네 뒷산에 토끼가 많이 산다고 해서 ‘토끼섬’이라 불리는 곳도 있습니다. ‘땅끝마을’은 우리나라의 육지 중 가장 남쪽 끝에 붙어 있는 마을이라서 그렇게 붙은 이름이고요. 그럼 ‘두물머리’라는 지명은 왜 나온 것일까요? (잠시 후) 네, 그렇습니다. 그곳은 한강의 두 물길이 하나로 만나는 곳에 위치한 마을이라서 그렇게 불립니다.<br>✅ <b>②</b> 두물머리는 한강의 물길이 하나로 합쳐지는 곳 — «두 물길이 하나로 만나는 곳».<br>✖️ ① «토끼섬» — потому что там много зайцев (귀 모양 ни при чём), ③ «소목비» — из-за формы лежащей коровы, не из-за разведения, ④ «땅끝마을» — это село (마을), а не остров (섬).<br>🧩 합쳐지다=сливаться, 육지=суша, 닮다=быть похожим."},{"n":35,"points":2,"instr":"Прослушайте и выберите, что делает мужчина. (2 балла)","options":["졸업생과 업적을 소개하고 있다.","전문 지식의 습득을 강조하고 있다.","인격 함양의 중요성을 당부하고 있다.","생명과학의 발전 가능성을 진단하고 있다."],"answer":3,"explain":"🎧 남자: 신입생 여러분, 입학을 축하합니다. 우리 대학은 지난 40여 년간 과학 기술 발전을 선도해 왔고, 작년에 생명과학 분야에서 세계 10위권에 진입하는 쾌거를 이뤘습니다. 이곳에서 여러분은 학업과 기업 활동 실습을 병행하며 전문가로 사회적 역할을 다하는 인재로 성장할 겁니다. 하지만 저는 훌륭한 인격을 갖추는 것이 전문 지식이나 실력보다 더 중요하다는 말씀을 드리고 싶습니다. 이 사회의 구성원으로서 기본적으로 갖추어야 할 도덕성과 타인을 배려하고 존중하는 마음을 갖춘 사람이 먼저 되십시오. 그리고 그 인격을 바탕으로 전문가로서의 역량을 키워 간다면 여러분들도 선배 졸업생들처럼 국내외에서 활발히 활동하며 각자의 분야에서 존경받는 전문가로 성장할 수 있을 겁니다.<br>✅ <b>③</b> 인격 함양의 중요성을 당부 — «훌륭한 인격을 갖추는 것이 전문 지식이나 실력보다 더 중요».<br>✖️ ① достижения упомянуты лишь вскользь, ② он как раз ставит знания НИЖЕ характера, ④ это не «диагноз перспектив биологии».<br>🧩 인격=характер/личность, 함양=воспитание (качеств), 당부하다=наставлять/просить."},{"n":36,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["이 학교의 졸업생은 해외 진출에 어려움을 겪고 있다.","이 학교는 설립 후 줄곧 어려움을 겪고 있다.","이 학교는 과학 분야에서 세계 10위권 안으로 진입했다.","이 학교의 학생들은 재학 중에 현장에서 실습할 기회가 있다."],"answer":4,"explain":"🎧 남자: 신입생 여러분, 입학을 축하합니다. 우리 대학은 지난 40여 년간 과학 기술 발전을 선도해 왔고, 작년에 생명과학 분야에서 세계 10위권에 진입하는 쾌거를 이뤘습니다. 이곳에서 여러분은 학업과 기업 활동 실습을 병행하며 전문가로 사회적 역할을 다하는 인재로 성장할 겁니다. 하지만 저는 훌륭한 인격을 갖추는 것이 전문 지식이나 실력보다 더 중요하다는 말씀을 드리고 싶습니다. 이 사회의 구성원으로서 기본적으로 갖추어야 할 도덕성과 타인을 배려하고 존중하는 마음을 갖춘 사람이 먼저 되십시오. 그리고 그 인격을 바탕으로 전문가로서의 역량을 키워 간다면 여러분들도 선배 졸업생들처럼 국내외에서 활발히 활동하며 각자의 분야에서 존경받는 전문가로 성장할 수 있을 겁니다.<br>✅ <b>④</b> 재학 중 현장 실습 기회가 있다 — «학업과 기업 활동 실습을 병행».<br>✖️ ① выпускники успешно работают «국내외에서», ② вуз 40 лет «선도해 왔고», ③ в топ-10 вошли именно по 생명과학 (а не вообще «науке»).<br>🧩 실습=практика, 병행하다=совмещать, 진입하다=войти/попасть."},{"n":37,"points":2,"instr":"Это познавательная передача. Прослушайте и выберите главную мысль женщины. (2 балла)","options":["숙면을 돕는 보조 용품이 다양해져야 한다.","수면 장애는 인간의 심리에 영향을 미친다.","불면증 치료법 개발에 적극적으로 나서야 한다.","수면 장애가 생긴 원인을 파악하는 것이 중요하다."],"answer":4,"explain":"🎧 남자: 요즘 수면 산업이 빠른 성장세를 보이고 있습니다. 입욕제나 수면 안대 같은 숙면을 도와주는 제품들도 많이 나오고 있는데요. 이런 제품들이 수면 장애의 진정한 해법이 될 수 있을까요? / 여자: 네, 불면증에 시달리는 사람들이 수면 보조 제품을 찾는 경우가 많죠. 그런데 무작정 이런 제품을 사용하기보다는 수면 장애가 왜 생겼는지 그 원인을 먼저 생각해 봐야 합니다. 그리고 그에 맞는 방법을 찾아 해결하려는 노력이 필요합니다. 수면 장애는 심리적인 상태나 생활 습관 같은 여러 가지 요인에 의해 발생하기 때문인데요. 문제의 근본을 모른 채 이런 제품에 의지하는 건 장기적으로 봤을 때 의미가 없습니다.<br>✅ <b>④</b> 수면 장애가 생긴 원인을 파악하는 것이 중요 — «원인을 먼저 생각해 봐야 합니다».<br>✖️ ① разнообразие товаров она не приветствует, ② это не её главная мысль, ③ про «разработку методов лечения» речи нет.<br>🧩 수면 장애=расстройство сна, 불면증=бессонница, 근본=корень/основа."},{"n":38,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["수면 보조 용품은 심리적인 문제를 해결해 준다.","수면 산업의 시장 규모가 빠르게 확대되고 있다.","불면증 환자는 생활 습관을 바꿀 필요가 없다.","수면 보조 용품 사용은 장기적인 측면에서 효과가 있다."],"answer":2,"explain":"🎧 남자: 요즘 수면 산업이 빠른 성장세를 보이고 있습니다. 입욕제나 수면 안대 같은 숙면을 도와주는 제품들도 많이 나오고 있는데요. 이런 제품들이 수면 장애의 진정한 해법이 될 수 있을까요? / 여자: 네, 불면증에 시달리는 사람들이 수면 보조 제품을 찾는 경우가 많죠. 그런데 무작정 이런 제품을 사용하기보다는 수면 장애가 왜 생겼는지 그 원인을 먼저 생각해 봐야 합니다. 그리고 그에 맞는 방법을 찾아 해결하려는 노력이 필요합니다. 수면 장애는 심리적인 상태나 생활 습관 같은 여러 가지 요인에 의해 발생하기 때문인데요. 문제의 근본을 모른 채 이런 제품에 의지하는 건 장기적으로 봤을 때 의미가 없습니다.<br>✅ <b>②</b> 수면 산업의 시장 규모가 빠르게 확대 — «수면 산업이 빠른 성장세».<br>✖️ ① товары психологические причины НЕ решают, ③ привычки как раз надо менять (원인을 해결), ④ в долгосрочной перспективе «의미가 없습니다».<br>🧩 시장 규모=объём рынка, 확대되다=расширяться, 의지하다=полагаться."},{"n":39,"points":2,"instr":"Это интервью-беседа. Прослушайте и выберите, о чём говорилось ПЕРЕД этим отрывком. (2 балла)","options":["서울시에서 차도를 줄이고 인도를 넓혔다.","서울시에서 불법 주차 단속을 강화하고 있다.","서울시가 주거 설명회에 소극적으로 임하고 있다.","서울시가 일방통행로를 양방향 도로로 변경하려고 했다."],"answer":1,"explain":"🎧 여자: 초기에 서울시에서 이 사업을 시작할 때에는 차량 정체 등의 이유로 주민들의 반대도 있었는데요. 지금은 어떤가요? / 남자: 앞에서 말씀드린 것과 같이 서울시는 2차선이었던 차도를 1차선으로 줄이고 차도는 한 방향으로만 통행하도록 바꿨습니다. 그렇게 해서 남는 공간은 주차장으로 활용해 주차 공간 부족 문제를 해결했습니다. 그동안 도로변에 주차된 차로 인해 막혔던 도로 상황도 이전보다 통행이 크게 나아졌고요. 또한 인도를 넓히고 도로의 제한 속도도 낮추면서 사고도 줄어들었습니다. 사전 설명회에서 나온 주민들의 의견을 사업에 적극 반영한 것도 호응을 얻었고요. 그래서 지금은 처음 우려했던 것과는 달리 만족도가 상당히 높습니다.<br>✅ <b>①</b> 차도를 줄이고 인도를 넓혔다 — мужчина говорит «앞에서 말씀드린 것과 같이 … 차도를 1차선으로 줄이고 … 인도를 넓히고», то есть об этом речь шла ранее.<br>✖️ ② про усиление контроля парковки не сказано, ③ мнения жителей наоборот «적극 반영», ④ дорогу сделали ОДНОсторонней, а не двусторонней.<br>🧩 차도=проезжая часть, 인도=тротуар, 일방통행=одностороннее движение."},{"n":40,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["이 사업으로 차량 흐름이 원활해진 곳이 있다.","이 사업의 시행에 반대하는 주민이 늘고 있다.","이 사업은 주차 공간 부족이라는 문제를 남겼다.","이 사업에서 도로의 제한 속도를 낮추는 방안을 검토 중이다."],"answer":1,"explain":"🎧 여자: 초기에 서울시에서 이 사업을 시작할 때에는 차량 정체 등의 이유로 주민들의 반대도 있었는데요. 지금은 어떤가요? / 남자: 앞에서 말씀드린 것과 같이 서울시는 2차선이었던 차도를 1차선으로 줄이고 차도는 한 방향으로만 통행하도록 바꿨습니다. 그렇게 해서 남는 공간은 주차장으로 활용해 주차 공간 부족 문제를 해결했습니다. 그동안 도로변에 주차된 차로 인해 막혔던 도로 상황도 이전보다 통행이 크게 나아졌고요. 또한 인도를 넓히고 도로의 제한 속도도 낮추면서 사고도 줄어들었습니다. 사전 설명회에서 나온 주민들의 의견을 사업에 적극 반영한 것도 호응을 얻었고요. 그래서 지금은 처음 우려했던 것과는 달리 만족도가 상당히 높습니다.<br>✅ <b>①</b> 차량 흐름이 원활해진 곳이 있다 — «막혔던 도로 상황도 이전보다 통행이 크게 나아졌고요».<br>✖️ ② недовольство было лишь в начале, теперь «만족도가 상당히 높습니다», ③ нехватку парковки как раз РЕШИЛИ, ④ ограничение скорости уже снижено (낮추면서), а не «рассматривается».<br>🧩 원활하다=плавный/беспрепятственный, 통행=движение/проезд, 만족도=уровень удовлетворённости."},{"n":41,"points":2,"instr":"Это лекция. Прослушайте и выберите её главное содержание. (2 балла)","options":["방백은 배우의 실력을 판단하는 중요한 요소이다.","관객들은 방백보다 배우의 연기에 집중해야 한다.","방백은 관객이 등장인물을 이해하는 데 도움이 된다.","관객들은 방백의 내용을 파악하려는 노력을 해야 한다."],"answer":3,"explain":"🎧 여자: 그럼 이 화면을 보시죠. 배우가 무대에서 관객들을 향해 혼잣말을 하고 있죠? 다른 배우들은 마치 이 배우의 말이 들리지 않는 것처럼 무대에서 자신의 연기를 계속하고요. 이렇게 무대 위의 인물에게는 들리지 않고 관객만 들을 수 있도록 약속된 대사가 ‘방백’입니다. 방백은 연극 공연 중에 배우가 관객에게 극의 흐름이나 등장인물의 의도를 알려 주기 위해 사용되는데요. 방백만큼 등장인물의 숨겨진 심리를 분명하게 보여 주는 것은 없습니다. 그래서 관객은 방백을 통해 등장인물을 더 깊이 이해하게 되죠. 한때 방백은 자연스럽지 못하다는 이유로 19세기 말에는 사용되지 않았습니다. 근래에 현대극에서는 필요에 따라 방백이 등장인물에 대한 공감을 이끌어 내고 있습니다.<br>✅ <b>③</b> 방백은 관객이 등장인물을 이해하는 데 도움이 된다 — «관객은 방백을 통해 등장인물을 더 깊이 이해하게 되죠».<br>✖️ ① оценкой мастерства актёра реплика-«방백» не служит, ② лектор не противопоставляет её игре актёра, ④ «приложить усилия, чтобы понять» — не главная мысль.<br>🧩 방백=реплика «в сторону» (aside), 혼잣말=речь про себя, 숨겨진 심리=скрытая психология."},{"n":42,"points":2,"instr":"Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["방백은 관객들의 반응을 유도하기 위해 사용된다.","현대극에서는 배우가 방백을 하는 것이 허용된다.","19세기 말에는 연극에서 방백이 활발히 활용되었다.","방백은 부자연스러워서 로마 시대에는 사용되지 않았다."],"answer":2,"explain":"🎧 여자: 그럼 이 화면을 보시죠. 배우가 무대에서 관객들을 향해 혼잣말을 하고 있죠? 다른 배우들은 마치 이 배우의 말이 들리지 않는 것처럼 무대에서 자신의 연기를 계속하고요. 이렇게 무대 위의 인물에게는 들리지 않고 관객만 들을 수 있도록 약속된 대사가 ‘방백’입니다. 방백은 연극 공연 중에 배우가 관객에게 극의 흐름이나 등장인물의 의도를 알려 주기 위해 사용되는데요. 방백만큼 등장인물의 숨겨진 심리를 분명하게 보여 주는 것은 없습니다. 그래서 관객은 방백을 통해 등장인물을 더 깊이 이해하게 되죠. 한때 방백은 자연스럽지 못하다는 이유로 19세기 말에는 사용되지 않았습니다. 근래에 현대극에서는 필요에 따라 방백이 등장인물에 대한 공감을 이끌어 내고 있습니다.<br>✅ <b>②</b> 현대극에서는 방백을 하는 것이 허용된다 — «근래에 현대극에서는 필요에 따라 방백이 … 사용».<br>✖️ ① её цель — донести до зрителя ход пьесы/намерения, а не «вызвать реакцию», ③ в конце 19 в. её как раз НЕ использовали, ④ речь о конце 19 века, а не о «римской эпохе».<br>🧩 허용되다=быть позволенным, 활발히=активно, 부자연스럽다=неестественный."},{"n":43,"points":2,"instr":"Это документальная передача. Прослушайте и выберите её главное содержание. (2 балла)","options":["나방에 대해 잘못 알려져 있는 부분이 많다.","사람들은 나방의 유해성에 관심을 가져야 한다.","나방과 나비가 다른 행동 양식을 가지고 있다.","나방의 애벌레는 생태계에서 중요한 역할을 한다."],"answer":1,"explain":"🎧 남자: 어두운 밤, 나방들이 빛을 향해 모여든다. 나비와 비슷하지만 나비와는 다른 대접을 받아 온 나방. 나방은 밤에만 나온다고 생각하지만 꽃에 앉아 꽃가루를 모으고 있는 이 나방처럼 낮에 활동하는 것들이 있고, 색깔이 칙칙하다는 것도 우리의 편견이다. 나비보다 색이 다양하고 무늬가 화려한 경우도 많다. 나방의 몸에 붙어 있는 가루도 사람들이 나방을 싫어하는 이유 중 하나인데, 인체에 해로운 성분이라는 오해 때문이다. 그러나 이것이 인체에 유해하거나 특별한 화학 작용을 일으키는 경우는 없다. 하지만 사실 숲의 생태계로 보면 그들은 없어서는 안 될 존재이다. 대량 번식하는 나방의 애벌레는 새들의 가장 중요한 먹이인 것이다.<br>✅ <b>①</b> 나방에 대해 잘못 알려져 있는 부분이 많다 — передача опровергает предрассудки (ночные, тусклые, «вредная пыльца»).<br>✖️ ② моли как раз НЕ вредны (오해 때문), ③ различие поведения — лишь один пример, ④ роль гусениц — тоже только один из аргументов, а не главная тема.<br>🧩 나방=мотылёк/моль, 편견=предрассудок, 오해=недоразумение, 애벌레=гусеница/личинка."},{"n":44,"points":2,"instr":"Прослушайте и выберите верное описание моли. (2 балла)","options":["나방의 애벌레는 새들에게 피해를 입힌다.","나방은 나비와 달리 꽃가루를 모으지 않는다.","나방의 몸에 있는 가루는 인체에 무해하다.","나방은 개체 수가 많아서 숲의 생태계를 위협한다."],"answer":3,"explain":"🎧 남자: 어두운 밤, 나방들이 빛을 향해 모여든다. 나비와 비슷하지만 나비와는 다른 대접을 받아 온 나방. 나방은 밤에만 나온다고 생각하지만 꽃에 앉아 꽃가루를 모으고 있는 이 나방처럼 낮에 활동하는 것들이 있고, 색깔이 칙칙하다는 것도 우리의 편견이다. 나비보다 색이 다양하고 무늬가 화려한 경우도 많다. 나방의 몸에 붙어 있는 가루도 사람들이 나방을 싫어하는 이유 중 하나인데, 인체에 해로운 성분이라는 오해 때문이다. 그러나 이것이 인체에 유해하거나 특별한 화학 작용을 일으키는 경우는 없다. 하지만 사실 숲의 생태계로 보면 그들은 없어서는 안 될 존재이다. 대량 번식하는 나방의 애벌레는 새들의 가장 중요한 먹이인 것이다.<br>✅ <b>③</b> 나방의 몸에 있는 가루는 인체에 무해하다 — «인체에 유해하거나 … 일으키는 경우는 없다».<br>✖️ ① гусеницы — корм птицам, а не вредят им, ② некоторые моли как раз собирают пыльцу (꽃가루를 모으고), ④ они не угрожают экосистеме, а необходимы ей (없어서는 안 될 존재).<br>🧩 무해하다=безвреден, 개체 수=численность особей, 생태계=экосистема."},{"n":45,"points":2,"instr":"Это лекция. Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["우유 단백질 포장재는 산소 차단율이 높다.","탄수화물 포장재는 환경오염의 주된 원인이다.","탄수화물 포장재는 미세 구멍이 없어 잘 썩는다.","우유 단백질 포장재는 음식으로 만든 최초의 포장재이다."],"answer":1,"explain":"🎧 여자: 비닐 포장재도 환경오염의 원인 중 하나입니다. 그래서 과학 기술 분야에서는 친환경적인 소재 개발에 몰두해 왔습니다. 그중 하나가 음식 포장에 이용하는 포장재입니다. 먼저 시도됐던 것은 탄수화물로 만든 포장재인데요. 미세한 구멍이 많은 이 포장재는 산소를 막아 내기 어려워 기존 포장재를 대체하기에는 역부족이었죠. 최근에는 우유로 만든 단백질로 포장재를 만드는 데 성공했습니다. 이건 미세한 구멍이 없고, 버려도 잘 썩을 뿐만 아니라 산소도 더 잘 차단합니다. 앞으로 대량으로 생산할 수 있는 기술력이 확보된다면 비닐 포장재로 인한 심각한 환경오염 문제가 크게 개선될 것입니다. 이렇게 과학 기술은 생활의 편리함을 가져올 뿐만 아니라 환경 문제를 해결하는 데도 적극 활용되고 있습니다.<br>✅ <b>①</b> 우유 단백질 포장재는 산소 차단율이 높다 — «산소도 더 잘 차단합니다».<br>✖️ ② источник загрязнения — это виниловая (пластиковая) упаковка, ③ у углеводной упаковки как раз МНОГО микропор (구멍이 많은), ④ «первая пищевая упаковка» не утверждается.<br>🧩 포장재=упаковочный материал, 차단하다=блокировать, 썩다=гнить/разлагаться."},{"n":46,"points":2,"instr":"Прослушайте и выберите наиболее подходящий способ изложения у женщины. (2 балла)","options":["친환경 제품의 효율을 비판하고 있다.","과학 기술의 시대적 한계점을 시사하고 있다.","환경오염 대상의 특성을 분석하고 있다.","과학 기술 분야의 노력을 예를 들어 설명하고 있다."],"answer":4,"explain":"🎧 여자: 비닐 포장재도 환경오염의 원인 중 하나입니다. 그래서 과학 기술 분야에서는 친환경적인 소재 개발에 몰두해 왔습니다. 그중 하나가 음식 포장에 이용하는 포장재입니다. 먼저 시도됐던 것은 탄수화물로 만든 포장재인데요. 미세한 구멍이 많은 이 포장재는 산소를 막아 내기 어려워 기존 포장재를 대체하기에는 역부족이었죠. 최근에는 우유로 만든 단백질로 포장재를 만드는 데 성공했습니다. 이건 미세한 구멍이 없고, 버려도 잘 썩을 뿐만 아니라 산소도 더 잘 차단합니다. 앞으로 대량으로 생산할 수 있는 기술력이 확보된다면 비닐 포장재로 인한 심각한 환경오염 문제가 크게 개선될 것입니다. 이렇게 과학 기술은 생활의 편리함을 가져올 뿐만 아니라 환경 문제를 해결하는 데도 적극 활용되고 있습니다.<br>✅ <b>④</b> 과학 기술 분야의 노력을 예를 들어 설명 — приводит примеры (углеводная, затем молочно-белковая упаковка).<br>✖️ ① она не критикует эко-продукты, ② на «пределы науки» не указывает, ③ свойства загрязнителя не анализирует.<br>🧩 예를 들다=приводить пример, 한계점=предел, 효율=эффективность."},{"n":47,"points":2,"instr":"Это интервью-беседа. Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["미래 사회를 위한 새로운 복지 모델을 찾았다.","기본 소득에 대해서는 두 가지 입장이 존재한다.","많은 나라에서 국민들에게 기본 소득을 지급하고 있다.","기본 소득은 노동에 대한 최소한의 대가로 보장하는 것이다."],"answer":2,"explain":"🎧 여자: 요즘 양극화를 해소하고 국가 경제력을 확대하기 위한 방안으로 기본 소득이 언급되고 있습니다. 국가가 조건 없이 모든 국민에게 매달 일정한 생활비를 준다는 건데요, 이게 효과가 있을까요? / 남자: 기본 소득은 사람들의 노동 의욕이 감소될 거라는 우려가 있는데요. 하지만 오히려 노동 의욕을 촉진할 거라는 입장도 있습니다. 최소한의 소득이 보장되면 생계에 대한 부담을 덜 수 있어 자기가 하고 싶은 일을 열심히 할 거라는 거죠. 그리고 소비가 촉진되면서 경제를 활성화시키는 데 도움이 될 수도 있고요. 최근 국가 단위로는 최초로 기본 소득 실험을 진행하고 있는 나라가 있는데요, 이 실험이 어떤 결과를 가져올지 지켜봐야 할 것 같습니다.<br>✅ <b>②</b> 기본 소득에 대해서는 두 가지 입장이 존재한다 — опасение «노동 의욕 감소» против мнения «노동 의욕을 촉진».<br>✖️ ① модель ещё только предстоит оценить (지켜봐야), ③ эксперимент пока «국가 단위로는 최초», ④ доход дают «조건 없이», а не как плату за труд.<br>🧩 기본 소득=базовый доход, 양극화=поляризация, 노동 의욕=мотивация к труду."},{"n":48,"points":2,"instr":"Прослушайте и выберите наиболее подходящее описание позиции мужчины. (2 балла)","options":["기본 소득의 효과에 대한 결론을 유보하고 있다.","기본 소득이 노동에 미칠 영향을 우려하고 있다.","기본 소득이 인간의 본성에 어긋남을 지적하고 있다.","기본 소득의 필요성에 대해 적극적으로 동의하고 있다."],"answer":1,"explain":"🎧 여자: 요즘 양극화를 해소하고 국가 경제력을 확대하기 위한 방안으로 기본 소득이 언급되고 있습니다. 국가가 조건 없이 모든 국민에게 매달 일정한 생활비를 준다는 건데요, 이게 효과가 있을까요? / 남자: 기본 소득은 사람들의 노동 의욕이 감소될 거라는 우려가 있는데요. 하지만 오히려 노동 의욕을 촉진할 거라는 입장도 있습니다. 최소한의 소득이 보장되면 생계에 대한 부담을 덜 수 있어 자기가 하고 싶은 일을 열심히 할 거라는 거죠. 그리고 소비가 촉진되면서 경제를 활성화시키는 데 도움이 될 수도 있고요. 최근 국가 단위로는 최초로 기본 소득 실험을 진행하고 있는 나라가 있는데요, 이 실험이 어떤 결과를 가져올지 지켜봐야 할 것 같습니다.<br>✅ <b>①</b> 효과에 대한 결론을 유보하고 있다 — приводит оба мнения и заключает «결과를 지켜봐야 할 것 같습니다».<br>✖️ ② он упоминает опасение, но не разделяет его как свою позицию, ③ про «противоречие природе человека» не говорит, ④ безоговорочно НЕ соглашается.<br>🧩 유보하다=откладывать/воздерживаться, 우려하다=опасаться, 본성=природа (человека)."},{"n":49,"points":2,"instr":"Это лекция. Прослушайте и выберите вариант, совпадающий с содержанием. (2 балла)","options":["붕당은 초반부터 심한 갈등을 겪었다.","현대의 정당 정치는 탕평책에서 비롯되었다.","탕평책은 여론을 효율적으로 모으기 위한 정책이다.","붕당 정치의 폐단을 해결하기 위해 탕평책이 나왔다."],"answer":4,"explain":"🎧 여자: 조선 시대에는 ‘탕평책’이라는 정책이 있었는데요. 조선 시대에도 오늘날의 정당 정치처럼 서로 입장을 같이 하는 사람들끼리 정치 세력을 형성하고, 반대되는 집단과 대립하기도 하는 정치 형태가 있었습니다. 이런 정치 세력을 ‘붕당’이라고 하는데요. 초반에는 붕당을 중심으로 여론을 모으고 서로를 견제하며 효율적인 국정 운영이 이루어졌습니다. 그런데 갈수록 붕당 간의 갈등이 심화되며 폐단이 생겼습니다. 이런 상황에서 모든 붕당이 정치에 골고루 참여할 수 있도록 만든 것이 탕평책입니다. 특정한 정치 이념을 떠나 인재를 고르게 등용함으로써 정치 세력의 균형을 이루고자 했던 것이죠. 붕당으로 인한 폐단만 일삼고 각자의 이익만을 추구하는 오늘날의 정치 상황에도 이런 균형을 위한 제도가 시행되어야 하지 않을까요?<br>✅ <b>④</b> 붕당 정치의 폐단을 해결하기 위해 탕평책이 나왔다 — «붕당 간의 갈등이 심화되며 폐단이 생겼습니다. 이런 상황에서 … 만든 것이 탕평책».<br>✖️ ① в начале 붕당 работали эффективно (초반에는 … 효율적), ② современную партийную политику с тханпхёнчхэк не связывают, ③ цель — баланс сил, а не «эффективный сбор мнений».<br>🧩 탕평책=политика беспристрастности, 붕당=политическая фракция, 폐단=злоупотребление/изъян."},{"n":50,"points":2,"instr":"Прослушайте и выберите наиболее подходящее описание позиции женщины. (2 балла)","options":["조선 시대 정치 형태의 문제점을 분석하고 있다.","정치 이념의 부재로 인한 혼란을 경계하고 있다.","정치적 균형을 위한 제도의 필요성을 제기하고 있다.","여론을 바탕으로 한 정치의 효율성을 역설하고 있다."],"answer":3,"explain":"🎧 여자: 조선 시대에는 ‘탕평책’이라는 정책이 있었는데요. 조선 시대에도 오늘날의 정당 정치처럼 서로 입장을 같이 하는 사람들끼리 정치 세력을 형성하고, 반대되는 집단과 대립하기도 하는 정치 형태가 있었습니다. 이런 정치 세력을 ‘붕당’이라고 하는데요. 초반에는 붕당을 중심으로 여론을 모으고 서로를 견제하며 효율적인 국정 운영이 이루어졌습니다. 그런데 갈수록 붕당 간의 갈등이 심화되며 폐단이 생겼습니다. 이런 상황에서 모든 붕당이 정치에 골고루 참여할 수 있도록 만든 것이 탕평책입니다. 특정한 정치 이념을 떠나 인재를 고르게 등용함으로써 정치 세력의 균형을 이루고자 했던 것이죠. 붕당으로 인한 폐단만 일삼고 각자의 이익만을 추구하는 오늘날의 정치 상황에도 이런 균형을 위한 제도가 시행되어야 하지 않을까요?<br>✅ <b>③</b> 정치적 균형을 위한 제도의 필요성을 제기 — завершает словами «이런 균형을 위한 제도가 시행되어야 하지 않을까요?»<br>✖️ ① проблемы она лишь упоминает, цель — урок для современности, ② «отсутствие идеологии» не обсуждает, ④ эффективность не «역설» — наоборот, предостерегает от перекоса.<br>🧩 균형=баланс, 제도=система/институт, 제기하다=поднимать (вопрос), 역설하다=настойчиво утверждать."}]
      },
    },
    60: {
      writing: {
        durationMin: 50, label: '제60회 · 쓰기 (51~54)',
        tasks: [{"n":51,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. Пост в разделе «Q & A» сайта библиотеки 한국대학교 — вежливый формальный стиль (-습니다/-ㅂ니까).","passage":"제목: 도서관을 이용하고 싶습니다.\n\n한국대학교를 졸업한 학생인데 도서관을 이용하고 싶습니다.\n선배에게 물어보니 졸업생이 도서관을 이용하려면 출입증이 ( ㉠ ).\n출입증을 만들려면 ( ㉡ )?\n방법을 알려 주시면 감사하겠습니다.","blanks":[{"slot":"㉠","model":"있어야 한다고 합니다 / 필요하다고 합니다 / 있어야 합니다","check":"«졸업생이 도서관을 이용하려면 출입증이 ( ㉠ ).» Подлежащее — 출입증이; условие «чтобы пользоваться … нужен пропуск». Это пересказ слов 선배 («선배에게 물어보니»), поэтому естественна косвенная речь: 있어야 한다고 합니다 / 필요하다고 합니다. Допустимо и прямое 있어야 합니다 / 필요합니다. Стиль -습니다."},{"slot":"㉡","model":"어떻게 해야 합니까 / 어떻게 해야 됩니까 / 어떻게 하면 됩니까","check":"«출입증을 만들려면 ( ㉡ )?» — предложение оканчивается на «?», автор спрашивает СПОСОБ изготовления пропуска. Вопрос: 어떻게 해야 합니까 / 어떻게 하면 됩니까. Формальный вопрос -ㅂ니까 (ср. «방법을 알려 주시면»)."}]},{"n":52,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. Научно-популярный текст о музыкальной терапии — письменный стиль -ㄴ다/-는다.","passage":"사람들은 음악 치료를 할 때 환자에게 주로 밝은 분위기의 음악을 들려줄 것이라고 생각한다. 그러나 환자에게 항상 밝은 분위기의 음악을 ( ㉠ ). 치료 초기에는 환자가 편안한 감정을 느끼는 것이 중요하다. 그래서 환자의 심리 상태와 비슷한 분위기의 음악을 들려준다. 그 이후에는 환자에게 다양한 분위기의 음악을 들려줌으로써 환자가 다양한 감정을 ( ㉡ ).","blanks":[{"slot":"㉠","model":"들려주는 것은 아니다 / 들려주지는 않는다","check":"«그러나 환자에게 항상 밝은 분위기의 음악을 ( ㉠ ).» Маркер 그러나 противопоставляет распространённому мнению (что играют только бодрую музыку). Частичное отрицание с 항상: «не всегда играют бодрую музыку» → 들려주는 것은 아니다 / 들려주지는 않는다. Стиль -ㄴ다."},{"slot":"㉡","model":"느끼게 된다 / 느낄 수 있게 된다 / 느끼게 한다","check":"«다양한 분위기의 음악을 들려줌으로써 환자가 다양한 감정을 ( ㉡ ).» Через 들려줌으로써 (благодаря тому что дают слушать) пациент приходит к разным эмоциям: 환자가 … 느끼게 된다 / 느낄 수 있게 된다 (либо каузатив 느끼게 한다). Стиль -ㄴ다."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음을 참고하여 '인주시의 자전거 이용자 변화'에 대한 글을 200~300자로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные «인주시의 자전거 이용자 변화» (изменение числа велосипедистов в г. Инджу) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.","image":"assets/topik2/exams/img/60-w53.png","model":"인주시의 자전거 이용자 수는 2007년부터 2017년까지 크게 증가하였다. 2007년에 4만 명이던 이용자는 2012년에 9만 명으로 늘었고, 2017년에는 21만 명에 이르러 10년 사이에 약 5배가 되었다. 이렇게 자전거 이용자가 늘어난 이유는 자전거 도로가 개발되고 자전거를 빌리는 곳이 확대되었기 때문이다. 이용 목적에도 변화가 나타났는데, 같은 기간 동안 운동 및 산책은 4배, 출퇴근은 14배, 기타는 3배로 늘어났다. 특히 출퇴근을 위한 이용이 가장 큰 폭으로 증가한 점이 두드러진다.","check":"① 이용자 수 4만→9만→21만, 약 5배 (2007~2017)? ② Причины — обе (자전거 도로 개발 + 빌리는 곳 확대)? ③ 이용 목적 변화: 운동·산책 4배, 출퇴근 14배, 기타 3배? ④ Письменный стиль -ㄴ다, без заголовка, объём 200–300 знаков?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 주제로 하여 자신의 생각을 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков на тему «조기 교육의 장점과 문제점» (плюсы и проблемы раннего образования). Раскройте все три вопроса из задания, каждый — отдельным абзацем; задание дословно не переписывайте.","passage":"요즘은 아이가 학교에 들어가기 전 어릴 때부터 악기나 외국어 등 여러 가지를 교육하는 경우가 많다. 이러한 조기 교육은 좋은 점도 있지만 문제점도 있다. 아래의 내용을 중심으로 '조기 교육의 장점과 문제점'에 대해 자신의 의견을 쓰라.\n• 조기 교육의 장점은 무엇인가?\n• 조기 교육의 문제점은 무엇인가?\n• 조기 교육에 찬성하는가, 반대하는가? 근거를 들어 자신의 의견을 쓰라.","model":"조기 교육이란 아이가 학교에 들어가기 전 어린 시기부터 악기나 외국어 등 여러 가지를 가르치는 것을 말한다. 이러한 조기 교육에는 분명한 장점이 있다. 어릴 때는 두뇌가 빠르게 발달하고 새로운 것을 받아들이는 능력이 뛰어나기 때문에, 이 시기에 배운 지식과 기술은 비교적 쉽게 익혀지고 오래 기억된다. 또한 어린 나이부터 다양한 분야를 경험하면 아이가 자신의 재능과 흥미가 무엇인지 일찍 발견할 수 있다는 점도 큰 장점이다.\n\n그러나 조기 교육에는 문제점도 있다. 아이가 감당하기 어려운 양의 학습을 강요받으면 큰 부담과 스트레스를 느끼게 된다. 이로 인해 공부 자체에 흥미를 잃거나 정서적으로 불안해지는 경우도 적지 않다. 또한 어릴 때부터 다른 아이와 끊임없이 비교를 당하면 자신감을 잃기 쉽다. 무엇보다 친구들과 어울려 놀면서 자연스럽게 길러야 할 사회성과 자율성을 충분히 키우지 못할 수도 있다.\n\n나는 지나친 조기 교육에는 반대한다. 물론 아이의 흥미와 발달 수준에 맞는 적절한 교육은 성장에 도움이 될 수 있다. 하지만 부모의 욕심만으로 아이에게 과도한 학습을 강요하는 것은 오히려 아이의 건강한 성장을 방해한다고 생각한다. 따라서 조기 교육은 무조건 일찍 많이 시키기보다 아이의 발달 단계와 흥미를 충분히 고려하여 신중하게 이루어져야 한다.","check":"① Все 3 вопроса раскрыты (장점 / 문제점 / 찬반 + 근거) — каждый отдельным абзацем? ② Есть вступление (определение 조기 교육) и вывод? ③ Связки уровня (또한, 그러나, 물론, 하지만, 따라서)? ④ Стиль -ㄴ다, без разговорных форм? ⑤ Объём 600–700 знаков, задание не переписано дословно?"}]
      },
      listening: {
        durationMin: 60, total: 100, label: '제60회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/60/60th%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/60-l-q1.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 여자: 무엇을 도와 드릴까요? 남자: 이 지갑, 누가 잃어버린 것 같아요. 이 앞에 있었어요. 여자: 네, 이쪽으로 주세요.<br>✅ <b>①</b>: мужчина нашёл чужой кошелёк и приносит его к стойке (бюро находок/информации, значок ⓘ), сотрудница принимает. На ① он один протягивает кошелёк через окошко.<br>✖️ ② рядом стоит ещё одна женщина с сумкой; ③④ — прилавок с товарами в магазине, а не бюро находок.<br>🧩 지갑 — кошелёк; 잃어버리다 — потерять; 도와 드리다 — помочь (вежл.); 이쪽으로 — сюда."},{"n":2,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/60-l-q2.png","options":["①","②","③","④"],"answer":3,"explain":"🎧 남자: 수미야, 괜찮아? 많이 아프겠다. 여자: 응, 다리가 아파서 못 일어나겠어. 남자: 그래? 내가 도와줄 테니까 천천히 일어나 봐.<br>✅ <b>③</b>: на спортплощадке девушка упала, повредила ногу и не может встать; парень наклоняется, чтобы помочь ей подняться. Это ③.<br>✖️ ① девушка бежит; ② он придерживает стоящую девушку; ④ девушка сидит, но парень не помогает встать.<br>🧩 다리 — нога; 아프다 — болеть; 일어나다 — вставать; 도와주다 — помогать."},{"n":3,"points":2,"instr":"Послушайте и выберите подходящий график.","image":"assets/topik2/exams/img/60-l-q3.png","options":["①","②","③","④"],"answer":4,"explain":"🎧 직장인들은 점심시간을 어떻게 보낼까요? 직장인의 점심시간은 한 시간이 70%였고, 한 시간 삼십 분은 20%, 한 시간 미만은 10%였습니다. 식사 후 활동은 '동료와 차 마시기'가 가장 많았고, '산책하기', '낮잠 자기'가 뒤를 이었습니다.<br>✅ <b>④</b>: график активности после обеда — 1위 동료와 차 마시기, 2위 산책하기, 3위 낮잠 자기, точно как в аудио.<br>✖️ ① 70% стоит на «1시간 30분» (неверно); ② 70% на «1시간 미만» (неверно, там 10%); ③ 1위 — «산책하기» (а должно быть «동료와 차 마시기»).<br>🧩 점심시간 — обеденное время; 동료 — коллега; 산책 — прогулка; 낮잠 — дневной сон."},{"n":4,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["장소를 다시 말해 주세요.","다음 모임은 안 갈 거예요.","이번 주에 만나면 좋잖아요.","정문 옆에 있는 식당이에요."],"answer":4,"explain":"🎧 여자: 민수 씨, 이번 주 모임 장소가 바뀌었대요. 남자: 그래요? 어디로 바뀌었어요? 여자: ____<br>✅ <b>④ 정문 옆에 있는 식당이에요</b>: на вопрос «куда поменялось место?» естественно назвать новое место — «ресторан рядом с главными воротами».<br>✖️ ① «скажите место ещё раз» — спрашивает-то он; ② «на следующую встречу не пойду» — не в тему; ③ «хорошо бы встретиться на этой неделе» — не ответ о месте.<br>🧩 모임 — встреча; 장소 — место; 바뀌다 — меняться; 정문 — главные ворота."},{"n":5,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["아침 일찍 기차를 탔어.","표가 없어서 아직 못 갔어.","표 있는지 한번 알아볼게.","금요일 오후 표는 취소하자."],"answer":3,"explain":"🎧 남자: 기차표 알아봤는데 금요일 오후 표는 없는 것 같아. 여자: 그럼 토요일 아침은 어때? 남자: ____<br>✅ <b>③ 표 있는지 한번 알아볼게</b>: на предложение «а как насчёт субботнего утра?» логичен ответ «проверю, есть ли билеты».<br>✖️ ① «сел на ранний поезд» — прошедшее, не к месту; ② «не смог поехать из-за билетов» — не о субботе; ④ «отменим билеты на пятницу» — их и так нет.<br>🧩 기차표 — билет на поезд; 알아보다 — выяснять; 취소하다 — отменять; 어때? — как насчёт?"},{"n":6,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["발표는 늘 어렵지요.","계획부터 세워 보세요.","외국어 공부를 좀 할까 해요.","학기가 시작되면 많이 바빠요."],"answer":3,"explain":"🎧 여자: 내일 발표만 끝나면 이제 이번 학기도 끝나네요. 남자: 그러게요. 수미 씨, 방학 계획은 세웠어요? 여자: ____<br>✅ <b>③ 외국어 공부를 좀 할까 해요</b>: на вопрос «строила ли планы на каникулы?» — «думаю немного позаниматься иностранным языком».<br>✖️ ① «доклады всегда трудные» — не о планах; ② «сначала составьте план» — спрашивают-то её; ④ «когда начнётся семестр, будет занято» — не план на каникулы.<br>🧩 발표 — доклад; 학기 — семестр; 방학 — каникулы; -(으)ㄹ까 하다 — намереваться."},{"n":7,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["응. 시골에서 산 적이 있어.","아니. 너무 지루해서 좋았어.","아니. 드라마 볼 시간이 없었어.","응. 두 사람 보면서 한참 웃었어."],"answer":4,"explain":"🎧 남자: 이번에 새로 시작한 드라마 말이야. 진짜 재미있더라. 여자: 아, 그 시골에서 할머니랑 사는 아이 이야기? 남자: ____<br>✅ <b>④ 응. 두 사람 보면서 한참 웃었어</b>: мужчина в восторге от сериала, женщина уточняет, тот ли это сериал. Логичен ответ-подтверждение с впечатлением: «да, долго смеялся, глядя на них двоих».<br>✖️ ① «жил в деревне» — не о сериале; ② «было так скучно, что понравилось» — противоречиво; ③ «не было времени смотреть» — противоречит «재미있더라».<br>🧩 드라마 — сериал; 시골 — деревня; 지루하다 — скучный; 한참 — долго."},{"n":8,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["만족도가 높은 편입니다.","조사 결과가 나왔습니다.","프로그램이 적은 것 같습니다.","질문을 다시 정리해 보겠습니다."],"answer":4,"explain":"🎧 여자: 팀장님, 프로그램 만족도 설문 조사를 만들어 봤는데요. 확인해 주시겠어요? 남자: 어디 봅시다. 음, 질문 수가 좀 많은 것 같네요. 여자: ____<br>✅ <b>④ 질문을 다시 정리해 보겠습니다</b>: руководитель замечает, что вопросов многовато, — подчинённая отвечает, что переработает/сократит вопросы.<br>✖️ ① «удовлетворённость высокая» — опрос ещё не проводился; ② «результаты вышли» — это только анкета; ③ «программ мало» — не о том.<br>🧩 만족도 — уровень удовлетворённости; 설문 조사 — анкетный опрос; 질문 수 — число вопросов; 정리하다 — упорядочить."},{"n":9,"points":2,"instr":"Выберите, что женщина будет делать дальше.","options":["그릇 색깔을 고른다.","그릇 가격을 물어본다.","전시할 그릇을 바꾼다.","남자에게 그릇을 준다."],"answer":2,"explain":"🎧 남자: 전시되어 있는 그릇들이 참 특이하고 멋지네요. 여자: 그렇죠? 판매도 한다니까 우리 하나 사 가요. 남자: 그럼 저 파란색 그릇은 어때요? 여자: 괜찮네요. 제가 가서 얼마인지 알아볼게요.<br>✅ <b>② 그릇 가격을 물어본다</b>: женщина говорит «제가 가서 얼마인지 알아볼게요» (пойду узнаю, сколько стоит) → спросит цену.<br>✖️ ① цвет уже выбрал мужчина; ③ «поменять выставленную посуду» — нет; ④ «отдать посуду мужчине» — нет.<br>🧩 그릇 — посуда; 전시되다 — быть выставленным; 판매 — продажа; 얼마 — сколько (цена)."},{"n":10,"points":2,"instr":"Выберите, что женщина будет делать дальше.","options":["서류를 찾는다.","신분증을 꺼낸다.","카드를 보여 준다.","신청서를 작성한다."],"answer":2,"explain":"🎧 남자: 고객님, 그럼 이 카드로 하실 거지요? 여자: 네. 그런데 카드는 바로 나오나요? 남자: 그럼요. 서류 작성은 제가 도와 드릴게요. 신분증 주시겠어요? 여자: 네, 잠깐만요.<br>✅ <b>② 신분증을 꺼낸다</b>: сотрудник просит «신분증 주시겠어요?» (дайте удостоверение), женщина отвечает «네, 잠깐만요» → достанет удостоверение личности.<br>✖️ ① «искать документы» — их заполняет сотрудник; ③ «показать карту» — карту ещё оформляют; ④ заявление заполнит сотрудник.<br>🧩 신분증 — удостоверение личности; 서류 작성 — заполнение документов; 신청서 — заявление; 꺼내다 — доставать."},{"n":11,"points":2,"instr":"Выберите, что женщина будет делать дальше.","options":["건전지를 가지러 간다.","현재 시간을 확인한다.","시계를 벽에서 내린다.","건전지를 서랍에 넣는다."],"answer":1,"explain":"🎧 남자: 누나, 벽시계가 안 가는 것 같은데. 건전지가 다 됐나 봐. 여자: 어, 그러네. 건전지가 어디 있었던 것 같은데……. 남자: 안방 서랍 안에 몇 개 있을 거야. 가져올게. 여자: 아니야, 내가 찾아올 테니까 너는 시계 좀 내려 줘.<br>✅ <b>① 건전지를 가지러 간다</b>: женщина говорит «내가 찾아올 테니까» (я схожу принесу) — то есть пойдёт за батарейками, а брату велит снять часы.<br>✖️ ② «проверить время» — часы стоят; ③ часы снимает брат; ④ «положить батарейки в ящик» — наоборот, она их достанет.<br>🧩 벽시계 — настенные часы; 건전지 — батарейка; 서랍 — ящик; 내리다 — снимать."},{"n":12,"points":2,"instr":"Выберите, что женщина будет делать дальше.","options":["회의 자료를 만든다.","회의 자료를 출력한다.","거래처 직원을 만난다.","거래처에 일정을 알린다."],"answer":2,"explain":"🎧 남자: 이수미 씨, 거래처랑 하는 회의, 자료는 다 준비됐어요? 회의 전에 먼저 보고 싶은데요. 여자: 지금 자료를 출력해 드릴까요? 남자: 네, 바로 뽑아 주세요. 거래처에 시간과 장소는 알려 줬죠? 여자: 어제 확인 이메일 보냈습니다.<br>✅ <b>② 회의 자료를 출력한다</b>: женщина предлагает «지금 자료를 출력해 드릴까요?», начальник просит «바로 뽑아 주세요» → распечатает материалы.<br>✖️ ① материалы уже готовы; ③ «встретить сотрудника партнёра» — нет; ④ о времени/месте она уже сообщила вчера письмом.<br>🧩 거래처 — деловой партнёр; 회의 자료 — материалы к совещанию; 출력하다 — распечатывать; 일정 — расписание."},{"n":13,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с содержанием.","options":["남자는 봉사 활동을 시작하려고 한다.","여자는 봉사 활동 때문에 고민하고 있다.","여자는 봉사 활동 검색 사이트를 이용해 봤다.","남자는 여자와 함께 봉사 활동을 한 적이 있다."],"answer":2,"explain":"🎧 여자: 봉사 활동을 해 보고 싶은데 처음이라 뭘 해야 할지 모르겠어요. 남자: 봉사 활동을 소개해 주는 인터넷 사이트가 있는데 알려 줄까요? 여자: 네, 좋아요. 민수 씨도 이용해 본 적이 있어요? 남자: 그럼요.<br>✅ <b>②</b>: женщина хочет заняться волонтёрством, но это впервые и она не знает, что выбрать (뭘 해야 할지 모르겠어요) — то есть раздумывает над этим.<br>✖️ ① начать собирается ЖЕНЩИНА, не мужчина; ③ сайтом пользовался мужчина, а женщина только спрашивает; ④ совместного волонтёрства в тексте нет.<br>🧩 봉사 활동 — волонтёрство; 처음 — впервые; 고민하다 — раздумывать; 검색 — поиск."},{"n":14,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с содержанием.","options":["점검은 내일 할 예정이다.","오전에 점검이 모두 끝난다.","비상벨이 여러 번 울릴 것이다.","점검이 시작되면 밖으로 나가야 한다."],"answer":3,"explain":"🎧 (объявление) 오늘은 아파트 소방 시설 점검이 있습니다. 1~5동은 오전 9~12시, 6~10동은 오후 1~4시 점검합니다. 점검 중에는 비상벨이 여러 번 울릴 예정이니 놀라지 마시고 하던 일을 계속하시기 바랍니다.<br>✅ <b>③</b>: «비상벨이 여러 번 울릴 예정» — во время проверки аварийный звонок будет звонить несколько раз.<br>✖️ ① проверка СЕГОДНЯ; ② после обеда тоже (6~10동 오후); ④ просят НЕ пугаться и продолжать свои дела, а не выходить.<br>🧩 점검 — проверка; 소방 시설 — противопожарное оборудование; 비상벨 — аварийный звонок; 울리다 — звонить."},{"n":15,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с содержанием.","options":["간판이 떨어져서 다친 사람이 있다.","태풍은 오늘 밤에 더 강해질 것이다.","이번 태풍의 특징은 비가 많이 오는 것이다.","제주도는 아직 태풍의 영향을 받고 있지 않다."],"answer":1,"explain":"🎧 (новости) 현재 태풍은 제주도를 지나고 있습니다. 이번 태풍은 특히 바람으로 인한 피해가 큽니다. 제주시에서는 간판이 떨어져 시민 두 명이 큰 부상을 입기도 했습니다. 태풍은 오늘 밤 늦게 동해를 지나 사라지겠습니다.<br>✅ <b>①</b>: в г. Чеджу с вывески сорвало, и два человека получили серьёзные травмы.<br>✖️ ② тайфун поздно ночью УЙДЁТ, а не усилится; ③ особенность — ущерб от ВЕТРА, не от дождя; ④ Чеджу уже под воздействием тайфуна (지나고 있습니다).<br>🧩 태풍 — тайфун; 간판 — вывеска; 부상을 입다 — получить травму; 피해 — ущерб."},{"n":16,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с содержанием.","options":["한국에는 이 일을 하는 사람이 많다.","꼼꼼한 사람은 이 일에 맞지 않는다.","이 일을 하는 데에 자격증은 필요 없다.","이 일을 할 때 예술적 감각이 도움이 된다."],"answer":4,"explain":"🎧 여자: 불꽃 연출가가 되려면 무엇이 필요한가요? 남자: 우선 자격증이 있어야 하고요. 위험물을 다루니까 꼼꼼하고 침착한 성격이 좋습니다. 요즘은 음악에 맞춰 불꽃을 터뜨리니까 예술적 감각이 있으면 더 좋고요.<br>✅ <b>④</b>: «예술적 감각이 있으면 더 좋고요» — для этой работы помогает художественное чутьё.<br>✖️ ① таких специалистов в Корее МАЛО (몇 분 안 계신데); ② аккуратность как раз ПОДХОДИТ (꼼꼼한 성격이 좋습니다); ③ нужен сертификат (자격증이 있어야).<br>🧩 불꽃 연출가 — пиротехник-постановщик; 자격증 — сертификат; 꼼꼼하다 — дотошный; 예술적 감각 — художественное чутьё."},{"n":17,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["오래 볼 수 있는 꽃이 좋다.","관리가 쉬운 식물을 사고 싶다.","식물은 집 밖에서 키워야 한다.","집에 꽃이 많은 화분이 있어야 한다."],"answer":2,"explain":"🎧 남자: 이거 어때요? 화분 크기도 적당하고 나무 모양도 예쁘고 물을 자주 안 줘도 된다니까 키우기 편할 거예요. 여자: 저는 꽃이 많이 있는 화분이 좋은데……. 남자: 꽃은 금방 지고 지저분해지죠. 이걸로 하는 게 어때요?<br>✅ <b>② 관리가 쉬운 식물을 사고 싶다</b>: мужчина хвалит растение за то, что его не надо часто поливать и легко содержать, а цветы быстро вянут и пачкаются.<br>✖️ ① «цветы, которые долго радуют» — это позиция женщины; ③ «выращивать вне дома» — нет; ④ «дома нужны цветы» — наоборот.<br>🧩 화분 — горшок с растением; 키우다 — выращивать; 관리 — уход; 지다 — увядать."},{"n":18,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["신청서에 쓸 정보를 줄이면 좋겠다.","신청서 쓰는 방법을 안내해야 한다.","신청자 요구에 맞는 수업을 해야 한다.","수업 내용을 미리 알려 주는 것이 좋다."],"answer":1,"explain":"🎧 남자: 신청서에 쓸 게 너무 많다. 문화 센터 수업을 신청하는 데 직업까지 쓸 필요가 있나? 여자: 요구에 맞는 수업을 해 줄 수 있으니까 그렇지. 남자: 그런 건 따로 물어보면 되지. 정보를 너무 많이 요구하는 것 같아.<br>✅ <b>① 신청서에 쓸 정보를 줄이면 좋겠다</b>: мужчина считает, что в анкете слишком много полей и запрашивают чересчур много информации.<br>✖️ ② «как заполнять» — не об этом; ③ «занятия под запросы» — это довод женщины; ④ «заранее сообщать содержание» — нет.<br>🧩 신청서 — заявление, анкета; 직업 — профессия; 요구하다 — требовать; 줄이다 — сокращать."},{"n":19,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["아이들 책은 무겁지 않아야 한다.","아이들 책은 온라인으로 사야 한다.","아이들 책은 전문가의 추천이 중요하다.","아이들 책은 직접 본 후에 사는 게 좋다."],"answer":4,"explain":"🎧 여자: 아이들 책 좀 온라인으로 주문해 줄래요? 남자: 직접 보고 사는 게 어때요? 여자: 전문가가 추천한 거예요. 남자: 그래도 애들이 볼 거니까 내용을 먼저 살펴보고 사야지요.<br>✅ <b>④ 아이들 책은 직접 본 후에 사는 게 좋다</b>: мужчина дважды настаивает — посмотреть содержание лично и только потом покупать.<br>✖️ ① про вес книг — это довод женщины; ② «покупать онлайн» — позиция женщины; ③ «рекомендация эксперта важна» — тоже довод женщины.<br>🧩 주문하다 — заказывать; 직접 — лично; 살펴보다 — осматривать; 추천 — рекомендация."},{"n":20,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["시사 프로그램은 일반인에게 인기를 얻기 어렵다.","일반인의 눈높이에서 시사 문제를 전달해야 한다.","청취자가 참여하는 시사 프로그램을 만들고 싶다.","시사 프로그램 진행자는 청취자의 질문에 답해야 한다."],"answer":2,"explain":"🎧 여자: 진행하시는 시사 프로그램이 인기를 끄는 이유는? 남자: 저는 청취자가 누구인가를 먼저 생각합니다. 듣는 분들은 보통 사람들이거든요. 그래서 일반인의 수준에서 전문가들에게 질문합니다. 어려운 표현이 나오면 다시 설명해 달라고 부탁하기도 하고요.<br>✅ <b>② 일반인의 눈높이에서 시사 문제를 전달해야 한다</b>: ведущий ориентируется на обычных слушателей и подаёт темы на их уровне.<br>✖️ ① «трудно стать популярным» — наоборот, программа популярна; ③ «участие слушателей» — речь не об этом; ④ «отвечать на вопросы слушателей» — вопросы задаёт сам ведущий экспертам.<br>🧩 시사 — текущие события; 청취자 — слушатель; 눈높이 — уровень (восприятия); 일반인 — обычный человек."},{"n":21,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["교실의 불편한 점을 고쳐야 한다.","빈 교실을 토론방으로 활용하는 게 좋다.","학생들의 팀별 과제를 늘릴 필요가 있다.","토론 수업을 위해 교실을 넓게 지어야 한다."],"answer":2,"explain":"🎧 여자: 지하에 있는 빈 교실을 창고나 토론방으로 이용하자는 의견이 있었습니다. 남자: 창고보다는 토론방이 더 낫지 않을까요? 학생들이 팀 과제를 준비하며 얘기 나눌 공간이 부족하다잖아요. 여자: 그 교실은 어둡고 환기가 잘 안되는데 괜찮을까요? 남자: 그건 해결이 가능하지 않을까요? 거기를 창고로 쓰긴 좀 아까워요.<br>✅ <b>② 빈 교실을 토론방으로 활용하는 게 좋다</b>: мужчина считает, что лучше сделать комнату для обсуждений, чем склад, — использовать её под склад «жалко».<br>✖️ ① «исправить недостатки» — лишь попутно; ③ «увеличить число командных заданий» — нет; ④ «строить класс попросторнее» — нет.<br>🧩 빈 교실 — пустой класс; 창고 — склад; 토론방 — комната для дискуссий; 아깝다 — жаль."},{"n":22,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["지하에 창고를 새로 만들었다.","남자는 빈 교실의 환기 문제를 해결했다.","여자는 지난주에 선생님들과 회의를 했다.","지하에 있는 교실에 에어컨은 모두 설치했다."],"answer":3,"explain":"🎧 여자: 교장 선생님, 지난주에 선생님들과 회의가 있었는데요…<br>✅ <b>③</b>: женщина прямо говорит, что на прошлой неделе было совещание с учителями.<br>✖️ ① склад ещё только предлагают сделать; ② мужчина лишь сказал, что проблему МОЖНО решить, а не решил; ④ кондиционер как раз НЕ установлен (에어컨도 설치가 안 돼 있고요).<br>🧩 회의 — совещание; 환기 — проветривание; 에어컨 — кондиционер; 설치하다 — устанавливать."},{"n":23,"points":2,"instr":"Выберите, что делает мужчина.","options":["정장 대여 방법을 알아보고 있다.","정장 대여 날짜를 문의하고 있다.","정장 대여 가격을 확인하고 있다.","정장 대여 예약을 변경하고 있다."],"answer":1,"explain":"🎧 남자: 거기 청년희망센터죠? 면접 때 입는 정장을 무료로 빌릴 수 있다고 해서 전화 드렸는데요. 어떻게 하면 되나요? 여자: 인주 시민이라면 누구나… 홈페이지에서 옷을 선택하고 예약한 날 신분증을 가지고 오시면 됩니다.<br>✅ <b>① 정장 대여 방법을 알아보고 있다</b>: мужчина звонит узнать, КАК взять костюм напрокат («어떻게 하면 되나요?»).<br>✖️ ② о дате не спрашивает; ③ услуга бесплатная — цену не уточняет; ④ брони ещё нет, менять нечего.<br>🧩 정장 — деловой костюм; 대여 — прокат; 면접 — собеседование; 빌리다 — брать напрокат."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["센터에서 신청자가 입을 옷을 골라 준다.","센터에 가서 정장 대여 신청서를 써야 한다.","이 서비스로 신청한 옷을 택배로 받기는 어렵다.","이 서비스는 인주시에 살고 있어야 이용할 수 있다."],"answer":4,"explain":"🎧 여자: 이 서비스는 인주시에 살고 있는 인주 시민이라면 누구나 이용할 수 있습니다.<br>✅ <b>④</b>: услугой может пользоваться лишь житель города Инджу.<br>✖️ ① одежду выбирает сам заявитель на сайте; ② заявка подаётся ОНЛАЙН, не в центре; ③ костюм МОЖНО получить курьером (택배로도 받을 수 있나요? — да).<br>🧩 신청자 — заявитель; 신청서 — заявление; 택배 — доставка курьером; 시민 — горожанин."},{"n":25,"points":2,"instr":"Выберите центральную мысль мужчины.","options":["아이들이 노는 놀이터는 공간이 넓을수록 좋다.","놀이터에 다양한 놀이 기구를 더 설치해야 한다.","놀이 기구가 없는 놀이터가 상상력을 기르기에 좋다.","놀이터에 있는 놀이 기구의 관리를 철저히 해야 한다."],"answer":3,"explain":"🎧 남자: 이곳은 미끄럼틀 같은 놀이 기구가 하나도 없습니다. 대신 모래밭과 개울, 언덕, 통나무가 있어요. 놀이 기구가 없기 때문에 아이들은 무한한 상상력을 발휘하게 되는 거죠.<br>✅ <b>③ 놀이 기구가 없는 놀이터가 상상력을 기르기에 좋다</b>: смысл слов мужчины — без игровых снарядов дети включают безграничное воображение.<br>✖️ ① «чем шире, тем лучше» — не главное; ② «добавить снаряды» — наоборот, их нет; ④ «тщательно обслуживать снаряды» — снарядов нет.<br>🧩 놀이터 — детская площадка; 놀이 기구 — игровой снаряд; 상상력 — воображение; 발휘하다 — проявлять."},{"n":26,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 놀이터는 기존 놀이터보다 자그맣다.","안전을 위해 놀이터의 통나무들을 치웠다.","이 놀이터에서 아이들이 물놀이를 할 수 있다.","놀이터 안에 모래밭을 없애고 언덕을 만들었다."],"answer":3,"explain":"🎧 남자: 작은 언덕도 있고… 이곳에 오면 아이들은 개울에서 물놀이를 하기도 해요.<br>✅ <b>③</b>: на этой площадке дети могут играть в воде (개울에서 물놀이).<br>✖️ ① площадка БОЛЬШЕ и просторнее обычной (크고 넓지만); ② брёвна как раз лежат там, их не убирали; ④ есть и песочница, и холм — песочницу не убирали.<br>🧩 개울 — ручей; 물놀이 — игры в воде; 모래밭 — песочница; 언덕 — холм."},{"n":27,"points":2,"instr":"Выберите намерение, с которым мужчина говорит женщине.","options":["단합 대회의 의의를 말하려고","단합 대회 참여를 부탁하려고","단합 대회의 방식을 바꾸려고","단합 대회의 문제를 지적하려고"],"answer":1,"explain":"🎧 남자: 이번 단합 대회 정말 좋지 않았어요? 운동도 하고 음식도 같이 해 먹으니까 더 친해진 것 같아요. 여자: 저는 좀 피곤했어요. 남자: 좀 피곤해도 서로 소통할 기회도 생기고, 가끔 교외로 나가 바람을 쐬는 것도 괜찮지 않아요?<br>✅ <b>① 단합 대회의 의의를 말하려고</b>: мужчина подчёркивает пользу/смысл корпоратива — сближение, общение, выезд на природу.<br>✖️ ② «попросить участвовать» — она уже участвовала; ③ «изменить формат» — это позиция женщины; ④ «указать на проблемы» — наоборот, он хвалит.<br>🧩 단합 대회 — корпоратив, тимбилдинг; 의의 — значение, смысл; 소통 — общение; 교외 — пригород."},{"n":28,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["단합 대회에서 음식을 만들어 먹었다.","여자는 단합 대회에 참석하지 않았다.","단합 대회는 회사 안에서 진행되었다.","남자는 단합 대회에서 운동을 안 했다."],"answer":1,"explain":"🎧 남자: 부서원들이랑 운동도 하고 음식도 같이 해 먹으니까…<br>✅ <b>①</b>: «음식도 같이 해 먹으니까» (해 먹다 — готовить и есть) — на корпоративе вместе готовили и ели еду.<br>✖️ ② женщина участвовала (устала, долго добиралась); ③ проходило ЗА городом, не в офисе (장소가 멀어서, 교외로 나가); ④ мужчина занимался спортом (운동도 하고).<br>🧩 해 먹다 — приготовить и съесть; 참석하다 — присутствовать; 진행되다 — проводиться; 부서원 — сотрудник отдела."},{"n":29,"points":2,"instr":"Выберите, кто такой мужчина.","options":["공연 장소를 섭외하는 사람","공연장 좌석을 안내하는 사람","공연장에서 안전을 관리하는 사람","공연장의 무대 시설을 고치는 사람"],"answer":3,"explain":"🎧 남자: 공연을 하는 동안 무대 아래에서 사람들이 안전선을 넘어가지 못하게 하고, 열성 팬들의 돌발 행동에도 대비해야 하는데요. … 사고가 발생하면 무대의 가수들을 먼저 이동시키고 상황별 행동 수칙에 따라 대처를 합니다.<br>✅ <b>③ 공연장에서 안전을 관리하는 사람</b>: следит за линией безопасности, готов к выходкам фанатов, действует при ЧП — это сотрудник по безопасности.<br>✖️ ① «подбирает площадки»; ② «провожает к местам»; ④ «чинит сцену» — речь о безопасности, а не об этом.<br>🧩 공연장 — концертная площадка; 안전선 — линия безопасности; 돌발 행동 — внезапная выходка; 대처하다 — реагировать."},{"n":30,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["오늘 공연은 실내에서 진행되었다.","비가 왔는데도 공연장에 사람들이 많았다.","오늘 공연 중 열성 팬으로 인한 사고가 있었다.","남자는 실내보다 야외에서 일할 때 마음이 편하다."],"answer":2,"explain":"🎧 여자: 오늘처럼 팬들로 가득 찬 야외 공연장… 남자: 오늘처럼 비가 오면 사람들 움직임도 잘 안 보이거든요.<br>✅ <b>②</b>: сегодня шёл дождь, и при этом площадка была полна фанатов (가득 찬).<br>✖️ ① концерт был на ОТКРЫТОМ воздухе (야외); ③ к счастью, сегодня обошлось без ЧП (사고가 없었지만); ④ на улице мужчина волнуется СИЛЬНЕЕ, чем в зале (훨씬 긴장됩니다).<br>🧩 야외 — открытый воздух; 실내 — помещение; 관중 — зрители; 긴장되다 — нервничать."},{"n":31,"points":2,"instr":"Выберите мысль мужчины.","options":["생계형 범죄 예방을 위한 대책이 효과가 없다.","생계형 범죄로 인한 피해를 보상해 주어야 한다.","생계형 범죄에 대한 사회적 인식 개선이 필요하다.","생계형 범죄도 다른 범죄와 동일하게 처벌해야 한다."],"answer":4,"explain":"🎧 남자: 생계형 범죄도 분명히 범죄입니다. 피해자도 존재하고요. 다른 범죄와 처벌을 달리할 필요가 없습니다. … 처벌이 약해지면 이를 악용하는 사람들이 나타날 것입니다.<br>✅ <b>④ 생계형 범죄도 다른 범죄와 동일하게 처벌해야 한다</b>: мужчина настаивает, что преступление «от нужды» — тоже преступление и наказывать надо так же.<br>✖️ ① про «неэффективность мер» — нет; ② «возместить ущерб» — нет; ③ «изменить общественное восприятие» — это ближе к позиции женщины.<br>🧩 생계형 범죄 — преступление ради выживания; 처벌 — наказание; 악용하다 — злоупотреблять; 동일하게 — одинаково."},{"n":32,"points":2,"instr":"Выберите отношение (позицию) мужчины.","options":["상대방 의견에 반대하고 있다.","제도의 문제점을 지적하고 있다.","문제 해결 방안에 공감하고 있다.","상대가 제시한 근거를 의심하고 있다."],"answer":1,"explain":"✅ <b>① 상대방 의견에 반대하고 있다</b>: женщина предлагает не ужесточать наказание, а давать шанс; мужчина прямо возражает — преступление есть преступление, наказывать одинаково.<br>✖️ ② «недостатки системы» — он их не разбирает; ③ «соглашается с решением» — наоборот, спорит; ④ «сомневается в доводах» — он не ставит под сомнение факты, а противопоставляет позицию.<br>🧩 반대하다 — возражать; 의견 — мнение; 공감하다 — соглашаться, сопереживать; 근거 — основание, довод."},{"n":33,"points":2,"instr":"Выберите, о чём идёт речь.","options":["우주 식품의 개발 배경","우주 식품을 먹는 방법","우주 식품 제조 시 고려 사항","우주 식품 운반 시 주의 사항"],"answer":3,"explain":"🎧 우주 식품은 장기 보관을 위해 미생물을 완전히 없애고 얼린 후 건조시켜 만듭니다. 무중력 공간에서는 국물·가루가 떠다녀 기계 고장을 일으킬 수 있어 피하고, 뼈·근육이 약해지니 칼슘·칼륨을 꼭 넣고, 미각·후각이 둔해져 음식을 더 자극적으로 만듭니다.<br>✅ <b>③ 우주 식품 제조 시 고려 사항</b>: весь текст — что учитывают при ИЗГОТОВЛЕНИИ космической еды.<br>✖️ ① «история разработки» — нет; ② «как есть» — нет; ④ «при транспортировке» — речь о производстве.<br>🧩 우주 식품 — космическая еда; 미생물 — микроорганизм; 건조시키다 — высушивать; 제조 — изготовление."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["우주 식품은 자극적이지 않게 만든다.","우주 식품에는 특정 미생물이 들어 있다.","우주 식품은 대부분 액체 형태로 만들어진다.","우주 식품에는 뼈와 근육에 좋은 성분이 포함된다."],"answer":4,"explain":"🎧 …뼈와 근육이 약해지니까 칼슘과 칼륨이 들어 있는 식품을 꼭 포함하고요.<br>✅ <b>④</b>: в космическую еду обязательно включают кальций и калий — полезные для костей и мышц.<br>✖️ ① еду делают БОЛЕЕ острой/яркой (자극적으로); ② микроорганизмы полностью УДАЛЯЮТ; ③ жидкости (국물) как раз ИЗБЕГАЮТ, еду высушивают.<br>🧩 자극적 — резкий, острый (по вкусу); 칼슘 — кальций; 칼륨 — калий; 성분 — компонент."},{"n":35,"points":2,"instr":"Выберите, что делает мужчина.","options":["제품의 완성 시기를 발표하고 있다.","최근에 출시된 제품을 홍보하고 있다.","제품 결함에 대해 사과의 말을 전하고 있다.","신제품 출시 지연에 대해 양해를 구하고 있다."],"answer":3,"explain":"🎧 남자: 최근 발생한 카메라 오작동 문제에 대해 말씀드리고자 합니다. 먼저 사용에 불편을 드려 진심으로 죄송합니다. … 특정 부품에서 하자가 발견되었습니다. … 새 제품으로 무상 교환해 드리겠습니다. 다시금 사죄의 말씀을 드립니다.<br>✅ <b>③ 제품 결함에 대해 사과의 말을 전하고 있다</b>: мужчина приносит извинения за брак (오작동·하자) и обещает бесплатную замену.<br>✖️ ① «сроки готовности» — нет; ② «реклама новинки» — наоборот, речь о браке; ④ «задержка выпуска» — нет.<br>🧩 결함 — дефект; 오작동 — сбой в работе; 하자 — брак; 사죄 — извинение."},{"n":36,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["소비자 과실로 제품에 문제가 발생하였다.","현재 제품에 대한 기능 점검이 진행 중이다.","이 회사는 처음으로 카메라를 출시할 예정이다.","지난해에 나온 제품은 무료로 교환해 줄 것이다."],"answer":4,"explain":"🎧 남자: 작년에 출고된 제품은 원하시는 경우 언제든 새 제품으로 무상 교환해 드리겠습니다.<br>✅ <b>④</b>: продукцию, выпущенную в прошлом году, бесплатно обменяют на новую.<br>✖️ ① брак из-за ПРОИЗВОДСТВА, не вины потребителя; ② проверку уже ПРОВЕЛИ (점검하였습니다); ③ компания давно выпускает камеры, не впервые.<br>🧩 과실 — вина, оплошность; 점검 — проверка; 출시하다 — выпускать в продажу; 무상 — бесплатно."},{"n":37,"points":2,"instr":"Выберите центральную мысль женщины.","options":["특수 목재는 건축 재료로서 이점이 많다.","목조 건물의 높이를 제한할 필요가 있다.","목조 건물을 짓는 것은 신중히 생각해야 한다.","특수 목재 가공 기술의 장단점을 파악해야 한다."],"answer":1,"explain":"🎧 여자: 압축된 특수 목재는 휘거나 틀어지지 않고, 강도도 전보다 훨씬 세졌습니다. 철근·콘크리트보다 가볍고 유연해서 지진에도 강하고요. 공사 기간 단축 효과도 있어 최근 18층짜리 목조 기숙사가 70일 만에 지어졌죠.<br>✅ <b>① 특수 목재는 건축 재료로서 이점이 많다</b>: женщина перечисляет сплошные плюсы — прочность, лёгкость, гибкость, сейсмостойкость, быстрая стройка.<br>✖️ ② «ограничить высоту» — нет; ③ «строить осторожно» — нет; ④ «оценить плюсы и МИНУСЫ» — о минусах речи нет.<br>🧩 목재 — древесина; 압축되다 — быть спрессованным; 강도 — прочность; 이점 — преимущество."},{"n":38,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["18층짜리 목조 건물이 현재 건설 중이다.","특수 목재에는 휘어지는 단점이 존재한다.","특수 목재로 건물을 지으면 공사 기간이 늘어난다.","특수 목재로 지은 건물은 지진의 영향을 덜 받는다."],"answer":4,"explain":"🎧 여자: 철근·콘크리트보다 가볍고 유연해서 지진에도 강하고요.<br>✅ <b>④</b>: здания из спецдревесины устойчивы к землетрясениям, то есть меньше страдают от них.<br>✖️ ① 18-этажное здание уже ПОСТРОЕНО (지어져), не строится; ② древесина как раз НЕ гнётся и не коробится (휘거나 틀어지지 않고); ③ срок стройки СОКРАЩАЕТСЯ (단축), а не растёт.<br>🧩 목조 건물 — деревянное здание; 휘다 — гнуться; 단축 — сокращение; 지진 — землетрясение."},{"n":39,"points":2,"instr":"Выберите, что было сказано ПЕРЕД этим разговором.","options":["원작자들이 야구단을 상대로 소송을 걸었다.","응원가에 대한 관중들의 선호도를 조사했다.","야구단에서 작곡가들에게 응원가 제작을 요청했다.","원작자들이 더 이상 곡을 바꾸지 않기로 결정했다."],"answer":1,"explain":"🎧 여자: 왜 작사가와 작곡가들이 야구단에 소송을 제기한 건가요? 그동안 야구단에서 곡에 대한 사용료를 지불해 온 것으로 알고 있는데요.<br>✅ <b>① 원작자들이 야구단을 상대로 소송을 걸었다</b>: ведущая спрашивает, ПОЧЕМУ авторы подали иск против бейсбольного клуба — значит, перед этим они подали иск.<br>✖️ ② «опрос предпочтений зрителей» — не было; ③ «клуб заказал песни» — нет; ④ «решили не менять песни» — наоборот, иск как раз из-за изменений.<br>🧩 작사가 — автор слов; 작곡가 — композитор; 소송을 제기하다 — подать иск; 사용료 — плата за использование."},{"n":40,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["원곡의 가사만 바꾸면 법적으로 문제가 없다.","야구단은 원곡을 바꿔 응원가를 자주 사용해 왔다.","앞으로 경기장에서 응원가가 더 많이 나올 것이다.","야구단에서 원작자의 허락을 받은 후에 곡을 수정했다."],"answer":2,"explain":"🎧 남자: 원작자 허락 없이 가사를 바꾸고 곡을 편집한 것에 대해서도 금액을 지불하라는 것이죠. 야구단에서 원곡을 그대로 사용했다면 이런 문제는 없었을 겁니다.<br>✅ <b>②</b>: клуб часто использовал песни, ИЗМЕНЯЯ оригиналы (менял слова, монтировал) — отсюда и спор.<br>✖️ ① менять даже только слова нужно с разрешения; ③ из-за спора пока РЕШИЛИ не включать песни; ④ изменяли БЕЗ разрешения автора (허락 없이).<br>🧩 원곡 — оригинальная песня; 가사 — текст песни; 편집하다 — монтировать; 허락 — разрешение."},{"n":41,"points":2,"instr":"Выберите центральную мысль лекции.","options":["수라상은 왕의 국정 운영에 활용되었다.","수라상의 음식 수는 왕의 권력을 나타냈다.","수라상은 조선 시대 음식 문화를 보여 준다.","수라상의 의미는 시대마다 다르게 해석된다."],"answer":1,"explain":"🎧 여자: 왕은 수라상에 올라오는 식재료를 보고 각 지방의 상황을 짐작했고, 가뭄·홍수 때는 반찬 수를 줄였으며, 신하들의 분쟁을 잠재우는 수단으로도 활용했습니다. 왕이 수라상을 정치에 적절히 이용했던 겁니다.<br>✅ <b>① 수라상은 왕의 국정 운영에 활용되었다</b>: главный смысл — королевский стол служил инструментом управления государством.<br>✖️ ② «число блюд = власть» — не главное; ③ «показывает кулинарную культуру» — лишь фон; ④ «толкуется по-разному по эпохам» — нет.<br>🧩 수라상 — королевский обеденный стол; 국정 운영 — управление государством; 분쟁 — раздор; 활용되다 — использоваться."},{"n":42,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["왕은 수라상의 반찬을 통해 지방 상황을 살폈다.","자연재해가 발생해도 수라상은 동일하게 구성됐다.","왕의 건강이 나빠지면 신하들은 반찬 수를 줄였다.","조선 시대 수라상에는 제철 특산품을 올리기 힘들었다."],"answer":1,"explain":"🎧 여자: 왕은 수라상에 올라오는 식재료를 보고 각 지방의 상황을 두루 짐작할 수 있었지요.<br>✅ <b>①</b>: по блюдам/продуктам на столе король оценивал положение в регионах.<br>✖️ ② при засухе/наводнении число блюд УМЕНЬШАЛИ; ③ это король сам объявлял о сокращении блюд, а министры из заботы о его здоровье прекращали распри; ④ сезонные деликатесы как раз ПОДАВАЛИ.<br>🧩 반찬 — гарнир, закуска; 제철 특산품 — сезонный деликатес; 자연재해 — стихийное бедствие; 살피다 — наблюдать."},{"n":43,"points":2,"instr":"Выберите центральную мысль рассказа.","options":["새끼 양육 방식이 오랑우탄의 식습관에 영향을 미쳤다.","나뭇잎 즙으로 통증을 치료하는 오랑우탄이 발견되었다.","사포닌이 든 나뭇잎의 맛을 즐기는 오랑우탄이 늘고 있다.","오랑우탄은 나뭇잎을 구하기 위해 서식지를 옮기기 시작했다."],"answer":2,"explain":"🎧 (документальный) 오랑우탄들이 나뭇잎을 씹어서 만든 즙을 팔에 바르는 모습이 자주 목격되었다. … 새끼를 안고 다니느라 생긴 통증을 줄이려는 것으로 보인다. 나뭇잎을 즙을 내어 바르는 모습이 목격된 것은 이번이 처음이다.<br>✅ <b>②</b>: главное — впервые замечены орангутаны, которые соком листьев лечат боль.<br>✖️ ① «способ выкармливания повлиял на рацион» — нет; ③ они НЕ наслаждаются вкусом (сапонин горький); ④ «переселяются ради листьев» — нет.<br>🧩 오랑우탄 — орангутан; 나뭇잎 — лист; 즙 — сок; 통증 — боль."},{"n":44,"points":2,"instr":"Выберите причину, по которой обычные животные избегают этих листьев.","options":["뜯기 힘들어서","건강에 좋지 않아서","사포닌의 맛을 싫어해서","새끼에게 먹이기 어려워서"],"answer":3,"explain":"🎧 일반적으로 동물들은 사포닌의 쓴맛을 꺼리는데…<br>✅ <b>③ 사포닌의 맛을 싫어해서</b>: обычно животные избегают этих листьев из-за горького вкуса сапонина.<br>✖️ ① «трудно срывать» — нет; ② «вредно для здоровья» — наоборот, у людей это обезболивающее; ④ «трудно кормить детёнышей» — нет.<br>🧩 사포닌 — сапонин; 쓴맛 — горький вкус; 꺼리다 — избегать, сторониться; 진통제 — обезболивающее."},{"n":45,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["호박은 광물로 만들어져 물에 뜰 수 없다.","호박은 다른 보석들처럼 흠집이 없는 게 좋다.","호박 내부의 불순물이 잘 보이면 가격이 비싸진다.","호박은 다이아몬드와 비슷한 물질로 구성되어 있다."],"answer":3,"explain":"🎧 여자: 호박은 워낙 투명하기 때문에 내부의 불순물이 그대로 보이는데, 불순물이 잘 보일수록 가치가 높습니다. 고대 곤충이나 식물의 잎이 들어가 있으면 다이아몬드만큼 비싸게 팔리기도 합니다.<br>✅ <b>③</b>: чем лучше видны включения (불순물) внутри янтаря, тем он дороже.<br>✖️ ① янтарь НЕ минерал и лёгкий — плавает в воде; ② у янтаря, в отличие от других камней, включения ЦЕНЯТСЯ; ④ из алмазного материала он не состоит.<br>🧩 호박 — янтарь; 불순물 — примесь, включение; 흠집 — изъян; 광물 — минерал."},{"n":46,"points":2,"instr":"Выберите способ изложения женщины.","options":["호박의 가공 과정을 살피고 있다.","호박의 개념을 다시 정의하고 있다.","호박의 유형을 파악해 비교하고 있다.","호박의 특징과 가치를 설명하고 있다."],"answer":4,"explain":"✅ <b>④ 호박의 특징과 가치를 설명하고 있다</b>: женщина описывает свойства янтаря (лёгкий, плавает, прозрачный, видны включения) и объясняет, что определяет его ценность.<br>✖️ ① «процесс обработки» — не разбирает; ② «заново определяет понятие» — нет; ③ «сравнивает типы янтаря» — типы не сравнивает.<br>🧩 특징 — особенность; 가치 — ценность; 설명하다 — объяснять; 가공 — обработка."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["적정 인구 관점에 삶의 질을 반영하기 어렵다.","적정 인구를 정한 후에 인구 대책 마련이 가능하다.","적정 인구 계산에 사회적 규모는 고려되지 않는다.","적정 인구 기준은 다른 나라에 동일하게 적용된다."],"answer":2,"explain":"🎧 남자: 적정 인구 규모가 정해져야 그에 따른 인구 대책을 세울 수 있게 됩니다.<br>✅ <b>②</b>: только определив оптимальную численность, можно выработать соответствующие демографические меры.<br>✖️ ① качество жизни как раз НАДО учитывать (함께 고려해야); ③ учитывают и масштаб общества (사회의 규모); ④ критерий РАЗЛИЧАется по странам (나라마다 차이가 있습니다).<br>🧩 적정 인구 — оптимальная численность населения; 대책 — мера; 규모 — масштаб; 삶의 질 — качество жизни."},{"n":48,"points":2,"instr":"Выберите отношение (позицию) мужчины.","options":["적정 인구의 계산 방식을 비판하고 있다.","적정 인구 관점의 어려움을 토로하고 있다.","적정 인구 논의의 영향에 대해 우려하고 있다.","적정 인구 논의의 적절한 방향을 제시하고 있다."],"answer":4,"explain":"✅ <b>④ 적정 인구 논의의 적절한 방향을 제시하고 있다</b>: мужчина объясняет, что такое оптимальная численность, и указывает, что при её расчёте надо учитывать и качество жизни населения — то есть задаёт верное направление обсуждения.<br>✖️ ① «критикует метод расчёта» — нет; ② «сетует на трудности» — нет; ③ «опасается последствий» — нет.<br>🧩 논의 — обсуждение; 방향 — направление; 제시하다 — предлагать, излагать; 고려하다 — учитывать."},{"n":49,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["현재 인공 장기 이식 연구가 진행 중에 있다.","면역력 해결을 위한 기술이 곧 개발될 것이다.","과거에는 장기 이식의 거부 반응이 많지 않았다.","장기 이식 중 폐를 이식하는 것은 아직 불가능하다."],"answer":1,"explain":"🎧 여자: 이를 해결하기 위해 현재 인공 장기를 이식하는 연구가 한창이라고 하니 장기 이식의 새로운 가능성이 열릴 것으로 기대됩니다.<br>✅ <b>①</b>: сейчас вовсю идёт исследование трансплантации искусственных органов.<br>✖️ ② технологию против отторжения разработали ещё в 1970-х; ③ в прошлом отторжение было ГЛАВНОЙ трудностью; ④ пересадка лёгких уже ВОЗМОЖНА (심장이나 폐, 피부까지도).<br>🧩 장기 이식 — трансплантация органов; 거부 반응 — реакция отторжения; 면역력 — иммунитет; 인공 장기 — искусственный орган."},{"n":50,"points":2,"instr":"Выберите отношение (позицию) женщины.","options":["장기 기증에 동참하기를 촉구하고 있다.","장기 이식 기술의 미래를 낙관하고 있다.","장기 기증으로 생길 문제를 예측하고 있다.","장기 이식 기술의 실패 원인을 진단하고 있다."],"answer":2,"explain":"✅ <b>② 장기 이식 기술의 미래를 낙관하고 있다</b>: женщина завершает позитивно — исследования искусственных органов в разгаре, и ожидается, что откроются новые возможности трансплантации.<br>✖️ ① «призывает участвовать в донорстве» — лишь упомянута нехватка органов, без призыва; ③ «прогнозирует проблемы» — наоборот, надежды; ④ «диагностирует причины неудач» — нет.<br>🧩 낙관하다 — смотреть с оптимизмом; 기증 — донорство; 촉구하다 — призывать; 예측하다 — прогнозировать."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제60회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"휴대 전화를 (        ) 내려야 할 역을 지나쳤다.","options":["보든지","보다가","보려면","보고서"],"answer":2,"explain":"✅ <b>② 보다가</b>: «засмотревшись в телефон, проехал(а) станцию, на которой нужно было выйти» — действие прервано другим → V-다가.<br>✖️ ① 보든지 — «смотри ли…»; ③ 보려면 — «если собираешься смотреть»; ④ 보고서 — «посмотрев (и затем)».<br>🧩 V-다가 — прерывание одного действия другим; 지나치다 — проехать мимо; 내리다 — выходить (из транспорта)."},{"n":2,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"한국 친구 덕분에 한국 문화를 많이 (        ).","options":["알게 되었다","알도록 했다","알아도 된다","알아야 한다"],"answer":1,"explain":"✅ <b>① 알게 되었다</b>: «благодаря корейскому другу я узнал(а) многое о корейской культуре» — естественно наступившее изменение/результат → V-게 되다.<br>✖️ ② 알도록 했다 — «сделал(а) так, чтобы знать»; ③ 알아도 된다 — «можно знать»; ④ 알아야 한다 — «нужно знать».<br>🧩 V-게 되다 — приход к состоянию/результату; N 덕분에 — благодаря N; 문화 — культура."},{"n":3,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"동생은 차를 <u>타기만 하면</u> 멀미를 한다.","options":["탈 만해서","타는 탓에","탈 때마다","타는 동안"],"answer":3,"explain":"✅ <b>③ 탈 때마다</b>: -기만 하면 здесь = «всякий раз, как…» → «каждый раз, когда садится в машину, младшего укачивает» = V-(으)ㄹ 때마다.<br>✖️ ① 탈 만해서 — «стоит того, чтобы ехать»; ② 타는 탓에 — «из-за того, что едет»; ④ 타는 동안 — «пока едет».<br>🧩 V-기만 하면 — «стоит только…, как»; V-(으)ㄹ 때마다 — каждый раз; 멀미를 하다 — укачивать."},{"n":4,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"이 컴퓨터는 낡아서 <u>수리해 봐야</u> 오래 쓰기 어렵다.","options":["수리해 보니까","수리하는 대로","수리하는 바람에","수리한다고 해도"],"answer":4,"explain":"✅ <b>④ 수리한다고 해도</b>: -아/어 봐야 здесь = «даже если попробовать…(всё равно бесполезно)» → «даже если починить, долго не прослужит» = V-ㄴ다고 해도.<br>✖️ ① 수리해 보니까 — «когда починил, оказалось»; ② 수리하는 대로 — «как только починю»; ③ 수리하는 바람에 — «из-за того что чинил».<br>🧩 V-아/어 봐야 — «сколько ни…, толку нет»; V-ㄴ다고 해도 — «даже если»; 낡다 — обветшать; 수리하다 — ремонтировать."},{"n":5,"points":2,"instr":"О чём этот текст?","passage":"몸에 좋은 영양소가 가득~\n매일 아침 신선함을 마셔요!","options":["과자","안경","우유","신발"],"answer":3,"explain":"✅ <b>③ 우유</b> (молоко): «полно полезных питательных веществ, пейте свежесть каждое утро» — это про напиток, молоко.<br>✖️ ① 과자 — печенье; ② 안경 — очки; ④ 신발 — обувь.<br>🧩 영양소 — питательные вещества; 신선하다 — свежий; 마시다 — пить."},{"n":6,"points":2,"instr":"О чём этот текст?","passage":"큰 이불도 깨끗하게\n세탁부터 건조까지 한 번에 해결!","options":["우체국","여행사","편의점","빨래방"],"answer":4,"explain":"✅ <b>④ 빨래방</b> (прачечная): «даже большое одеяло — начисто; от стирки до сушки за один раз» — это про прачечную самообслуживания.<br>✖️ ① 우체국 — почта; ② 여행사 — турагентство; ③ 편의점 — мини-маркет.<br>🧩 이불 — одеяло; 세탁 — стирка; 건조 — сушка; 해결하다 — решать."},{"n":7,"points":2,"instr":"О чём этот текст?","passage":"등산할 때 담배와 라이터는 두고 가세요.\n작은 실천이 아름다운 산을 지킵니다.","options":["건강 관리","전기 절약","화재 예방","교통 안전"],"answer":3,"explain":"✅ <b>③ 화재 예방</b> (профилактика пожаров): «в горы не берите сигареты и зажигалки; малое действие сохраняет красивые горы» — призыв не допускать лесных пожаров.<br>✖️ ① 건강 관리 — забота о здоровье; ② 전기 절약 — экономия электричества; ④ 교통 안전 — безопасность движения.<br>🧩 등산 — поход в горы; 담배 — сигареты; 라이터 — зажигалка; 지키다 — беречь."},{"n":8,"points":2,"instr":"О чём этот текст?","passage":"◼ 검사 전날 밤 9시 이후에는 아무것도 드시면 안 됩니다.\n◼ 정확한 검사를 위해 음주를 피하십시오.","options":["상품 안내","주의 사항","사용 순서","장소 문의"],"answer":2,"explain":"✅ <b>② 주의 사항</b> (меры предосторожности): «после 21:00 накануне обследования ничего не есть; ради точности избегайте алкоголя» — это предупреждения перед процедурой.<br>✖️ ① 상품 안내 — о товаре; ③ 사용 순서 — порядок использования; ④ 장소 문의 — вопрос о месте.<br>🧩 검사 — обследование; 음주 — употребление алкоголя; 피하다 — избегать."},{"n":9,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с объявлением.","passage":"🏕 인주시 캠핑장 이용 안내\n● 이용 기간: 3월 ~ 11월\n● 이용 방법: 홈페이지(www.injucamp.com)에서 예약 ※ 당일 예약 불가\n● 이용 요금(1박 2일): 평일 30,000원 / 주말 35,000원 (주차장·샤워장 이용료 포함)\n● 문의: 캠핑장 관리사무소 031) 234-1234","options":["주말에는 이용 요금을 더 받는다.","캠핑장은 1년 내내 이용할 수 있다.","예약은 이용 당일 홈페이지에서 하면 된다.","주차장을 이용하려면 돈을 따로 내야 한다."],"answer":1,"explain":"✅ <b>①</b>: будни 30 000원, выходные 35 000원 — в выходные берут больше.<br>✖️ ② работает только 3월~11월, не круглый год; ③ бронь в день посещения невозможна (당일 예약 불가); ④ парковка и душ уже включены в стоимость (주차장·샤워장 이용료 포함).<br>🧩 이용 요금 — плата за пользование; 평일/주말 — будни/выходные; 당일 — тот же день; 포함 — включено."},{"n":10,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с графиком.","passage":"📊 노후에 가장 하고 싶은 일 (조사 대상: 40~50대 남녀 각 500명)\n· 경제 활동: 남성 58%, 여성 35%\n· 취미 활동: 남성 27%, 여성 42%\n· 봉사 활동: 남성 9%, 여성 16%\n· 종교 활동: 남성 4%, 여성 6%\n· 기타: 남성 2%, 여성 1%","options":["여성은 봉사 활동보다 취미 활동을 더 하고 싶어 한다.","종교 활동을 하고 싶어 하는 비율은 남성이 여성보다 높다.","남녀 모두 경제 활동을 하고 싶다는 응답이 절반을 넘는다.","경제 활동보다 봉사 활동을 하고 싶어 하는 남성이 많다."],"answer":1,"explain":"✅ <b>①</b>: у женщин 취미 활동 42% &gt; 봉사 활동 16% — хобби хотят заниматься больше, чем волонтёрством.<br>✖️ ② религия: мужчины 4% &lt; женщины 6% — у женщин выше; ③ экономическую активность выбрали &gt;половины только мужчины (58%), у женщин 35%; ④ у мужчин экономическая (58%) намного больше волонтёрской (9%).<br>🧩 노후 — старость; 경제 활동 — трудовая деятельность; 취미 — хобби; 봉사 활동 — волонтёрство; 비율 — доля."},{"n":11,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"인주시의 한 고등학교는 올해부터 여름 교복으로 티셔츠와 반바지를 입고 있다. 기존 정장형 교복은 활동할 때 불편하다는 학생들의 의견이 많았기 때문이다. 몸이 편해지니 학생들은 다양한 활동에 적극적으로 참여하기 시작했고 공부에도 더 집중할 수 있어서 학습 효율이 올라갔다. 새 교복은 기존 교복보다 가격이 저렴해서 학부모에게도 인기다.","options":["학부모들은 정장형 교복을 더 좋아한다.","새 교복은 정장형 교복보다 가격이 비싸다.","기존 교복에 비해 새 교복은 활동할 때 불편하다.","학교는 학생들의 의견을 받아들여서 교복을 바꿨다."],"answer":4,"explain":"✅ <b>④</b>: форму сменили из-за мнений учеников (불편하다는 학생들의 의견이 많았기 때문) — школа учла их мнение.<br>✖️ ① родителям нравится новая форма (она дешевле), а не костюмная; ② новая форма ДЕШЕВЛЕ (저렴), а не дороже; ③ неудобной была СТАРАЯ костюмная форма, новая — удобная.<br>🧩 교복 — школьная форма; 정장형 — костюмного типа; 저렴하다 — дешёвый; 의견을 받아들이다 — принять мнение."},{"n":12,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"최근 한 아파트에서는 힘들게 일하는 택배 기사, 청소부 등을 위한 무료 카페를 열어서 화제가 되고 있다. 이 카페는 언제든 부담 없이 음료를 마시면서 쉴 수 있는 곳이어서 이용자들이 만족해하고 있다. 주민들은 처음에는 관심을 안 보였지만 지금은 카페에 음료와 간식을 제공하는 등 많은 도움을 주고 있다.","options":["이 카페에 간식을 가져다주는 주민들이 생겼다.","카페를 열 때 아파트 주민들이 적극적으로 도왔다.","이 카페는 아파트 주민들이 돈을 벌기 위해서 열었다.","택배 기사들이 카페의 운영에 참여해 화제가 되고 있다."],"answer":1,"explain":"✅ <b>①</b>: теперь жители приносят в кафе напитки и закуски (지금은 … 음료와 간식을 제공) — появились те, кто приносит снеки.<br>✖️ ② сначала жители не проявляли интереса (처음에는 관심을 안 보였지만); ③ кафе бесплатное (무료 카페), не ради заработка; ④ курьеры — это посетители, а не организаторы.<br>🧩 택배 기사 — курьер; 무료 — бесплатный; 부담 없이 — без стеснения; 제공하다 — предоставлять."},{"n":13,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 환경 보호를 위해 포장 없이 내용물만 판매하는 가게가 있다.\n(나) 사람들이 용기에 든 물품을 사려면 빈 통을 준비해 가야 한다.\n(다) 빈 통이 없는 사람들에게는 가게에서 통을 대여해 주기도 한다.\n(라) 이 가게에서는 밀가루나 샴푸 등을 커다란 용기에 담아 놓고 판매한다.","options":["(가)-(나)-(라)-(다)","(가)-(라)-(나)-(다)","(나)-(가)-(라)-(다)","(나)-(다)-(가)-(라)"],"answer":2,"explain":"✅ <b>② (가)-(라)-(나)-(다)</b>: (가) зачин — есть магазин, продающий товар без упаковки; (라) «이 가게에서는» поясняет — муку, шампунь и т. п. наливают/насыпают из больших ёмкостей; (나) чтобы купить, надо принести пустую тару; (다) у кого тары нет — магазин её одолжит.<br>✖️ начинать с (나)/(다) нельзя — они зависят от введённого в (가)/(라).<br>🧩 포장 — упаковка; 용기 — ёмкость; 빈 통 — пустая тара; 대여하다 — давать напрокат."},{"n":14,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 요금을 내려고 보니 가방 어디에서도 지갑을 찾을 수 없었다.\n(나) 감사의 인사를 전하는 나에게 아주머니는 환하게 웃어 주셨다.\n(다) 회사에 지각할 것 같아서 막 출발하려는 버스를 뛰어가서 탔다.\n(라) 그냥 내리려는데 뒤에 서 있던 아주머니가 대신 요금을 내 주셨다.","options":["(가)-(다)-(나)-(라)","(가)-(라)-(다)-(나)","(다)-(가)-(라)-(나)","(다)-(나)-(라)-(가)"],"answer":3,"explain":"✅ <b>③ (다)-(가)-(라)-(나)</b>: (다) опаздывал на работу — добежал и сел в отъезжающий автобус; (가) собрался платить — но в сумке нигде нет кошелька; (라) хотел просто выйти — стоявшая позади женщина заплатила за него; (나) в ответ на благодарность женщина светло улыбнулась.<br>✖️ начинать с (가)/(라)/(나) нельзя — нет завязки.<br>🧩 요금 — плата за проезд; 지갑 — кошелёк; 지각하다 — опаздывать; 대신 — вместо."},{"n":15,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 쉬어도 떨림이 계속된다면 마그네슘이 부족해서일 수도 있다.\n(나) 눈 밑 떨림의 주된 원인은 피로이므로 푹 쉬면 증상은 완화된다.\n(다) 이런 사람들은 마그네슘이 풍부한 견과류나 바나나를 먹으면 좋다.\n(라) 누구나 한 번쯤은 눈 밑이 떨리는 경험을 해 본 적이 있을 것이다.","options":["(나)-(다)-(라)-(가)","(나)-(라)-(다)-(가)","(라)-(가)-(다)-(나)","(라)-(나)-(가)-(다)"],"answer":4,"explain":"✅ <b>④ (라)-(나)-(가)-(다)</b>: (라) каждый хоть раз ощущал подёргивание под глазом; (나) главная причина — усталость, при хорошем отдыхе симптом проходит; (가) если и после отдыха не проходит — возможен дефицит магния; (다) таким людям полезны орехи и бананы, богатые магнием.<br>✖️ начинать с (가)/(다)/(나) нельзя — они продолжают введённую в (라) тему.<br>🧩 눈 밑 떨림 — подёргивание под глазом; 피로 — усталость; 마그네슘 — магний; 견과류 — орехи."},{"n":16,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"원래 악수는 상대를 안심시키기 위한 행동이었다. 중세 시대의 기사들은 칼과 같은 무기를 가지고 다니다가 적과 싸울 때 꺼내 들었다. 하지만 (        ) 때에는 악수를 하면서 손에 무기가 없음을 보여 주었다. 이렇게 안전을 확인시켜 주기 위한 행동이 오늘날에는 반가움과 존중을 표시하는 인사법이 되었다.","options":["싸울 생각이 없을","상대의 도움을 받았을","자신의 잘못을 사과할","무기를 새로 구해야 할"],"answer":1,"explain":"✅ <b>① 싸울 생각이 없을</b>: рыцари доставали оружие, когда дрались; «но когда драться не собирались, рукопожатием показывали, что в руке нет оружия».<br>✖️ ② «получив помощь» — нет; ③ «извиняясь за вину» — нет; ④ «надо добыть новое оружие» — противоречит смыслу.<br>🧩 악수 — рукопожатие; 안심시키다 — успокаивать; 무기 — оружие; 인사법 — способ приветствия."},{"n":17,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"특별한 사건 없이 주인공의 단순하고 반복적인 일상을 다룬 한 영화가 인기를 끌고 있다. 주인공이 하루하루를 평범하게 보낼 뿐 별다른 일을 하지 않는데도 관객들은 영화에 빠져든다. 관객들은 그동안 잊고 지냈던 일상의 기쁨을 새삼 깨닫는 것이다. 그리고 행복은 크고 거창한 꿈에만 있는 것이 아니라 (        ) 일에서도 찾을 수 있음을 발견한다.","options":["스스로 인정하지 않는","현실 속의 작고 소소한","평소 자주 하지 못하는","일상에서 하기 쉽지 않은"],"answer":2,"explain":"✅ <b>② 현실 속의 작고 소소한</b>: фильм о простой будничной жизни напоминает зрителям радость повседневности; счастье не только в больших мечтах, но и в «маленьких, обыденных делах реальности».<br>✖️ ① «которое сам не признаёшь» — нет; ③ «что нечасто делаешь» — наоборот; ④ «что трудно делать в быту» — противоречит идее обыденности.<br>🧩 일상 — повседневность; 평범하다 — обыкновенный; 새삼 — заново; 소소하다 — мелкий, незначительный."},{"n":18,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"'씨앗 저장고'는 미래의 식량 문제를 대비하기 위해 식물 자원을 영구적으로 보호하는 시설이다. 이곳의 연구원들은 보관 중인 씨앗을 연구하는 일뿐만 아니라 (        ) 활동도 한다. 이들은 씨앗 하나를 구하기 위해 전국 곳곳을 찾아다닌다. 연구원들이 직접 가서 보지 않으면 보관할 가치가 있는 씨앗인지 알 수 없기 때문이다.","options":["자원을 홍보하는","사람을 교육하는","씨앗을 수집하는","저장고를 관리하는"],"answer":3,"explain":"✅ <b>③ 씨앗을 수집하는</b>: сотрудники не только изучают хранящиеся семена, но и «собирают семена» — ради одного семени объезжают всю страну, ведь без личного осмотра не понять, стоит ли его хранить.<br>✖️ ① «рекламировать ресурсы» — нет; ② «обучать людей» — нет; ④ «управлять хранилищем» — не следует из текста про разъезды.<br>🧩 씨앗 — семя; 저장고 — хранилище; 식량 — продовольствие; 수집하다 — собирать, коллекционировать."},{"n":19,"points":2,"instr":"Выберите подходящее слово в пропуск ( ).","passage":"시각 장애인의 안내견은 주인과 있을 때 행인에게 관심을 두지 않는다. (        ) 안내견이 주인을 남겨 두고 행인에게 다가간다면 이는 주인이 위험에 처해 있다는 뜻이다. 안내견은 주인에게 문제가 발생하면 곧장 주변 사람에게 달려가 도움을 요청하도록 훈련을 받기 때문이다. 안내견이 행인의 주위를 맴돌면 안내견을 따라가 주인의 상태를 확인하고 구조 센터에 연락해야 한다.","options":["비록","물론","만약","과연"],"answer":3,"explain":"✅ <b>③ 만약</b>: пропуск открывает условие — «если (만약) собака-поводырь оставит хозяина и подойдёт к прохожему, это значит, что хозяин в опасности» (만약 … -다면).<br>✖️ ① 비록 — «хотя»; ② 물론 — «конечно»; ④ 과연 — «и впрямь».<br>🧩 안내견 — собака-поводырь; 시각 장애인 — незрячий; 만약 …-다면 — «если»; 위험에 처하다 — оказаться в опасности."},{"n":20,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"시각 장애인의 안내견은 주인과 있을 때 행인에게 관심을 두지 않는다. (만약) 안내견이 주인을 남겨 두고 행인에게 다가간다면 이는 주인이 위험에 처해 있다는 뜻이다. 안내견은 주인에게 문제가 발생하면 곧장 주변 사람에게 달려가 도움을 요청하도록 훈련을 받기 때문이다. 안내견이 행인의 주위를 맴돌면 안내견을 따라가 주인의 상태를 확인하고 구조 센터에 연락해야 한다.","options":["안내견이 주인 곁을 떠나는 경우는 없다.","안내견은 문제가 생기면 구조 센터로 달려간다.","안내견이 다가오는 것은 위급한 상황이 생겼다는 뜻이다.","안내견은 항상 주변의 사람들에게 관심을 갖도록 훈련을 받는다."],"answer":3,"explain":"✅ <b>③</b>: если поводырь подходит к прохожему — у хозяина опасная ситуация (주인이 위험에 처해 있다는 뜻).<br>✖️ ① собака ПОКИДАЕТ хозяина, когда тот в беде; ② при проблеме бежит к ОКРУЖАЮЩИМ ЛЮДЯМ, а не в спасательный центр (в центр звонит человек); ④ обычно к прохожим внимания НЕ проявляет (관심을 두지 않는다).<br>🧩 위급하다 — экстренный; 맴돌다 — кружить рядом; 구조 센터 — спасательный центр; 행인 — прохожий."},{"n":21,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"문자 교육은 빠를수록 좋다고 믿는 부모들이 있다. 이들은 자신의 아이가 또래보다 글자를 더 빨리 깨치기를 바라며 문자 교육에 (        ). 그런데 나이가 어린 아이들은 아직 다양한 능력들이 완전히 발달하지 못해 온몸의 감각을 동원하여 정보를 얻는다. 이 시기에 글자를 읽는 것에 집중하다 보면 다른 감각을 사용할 기회가 줄어 능력이 고르게 발달하는 데 어려움이 있을 수 있다.","options":["손을 뗀다","이를 간다","담을 쌓는다","열을 올린다"],"answer":4,"explain":"✅ <b>④ 열을 올린다</b>: идиома 열을 올리다 — «рьяно усердствовать». Родители хотят, чтобы ребёнок раньше сверстников освоил буквы, и потому усердствуют в обучении грамоте.<br>✖️ ① 손을 떼다 — «отстраниться, бросить»; ② 이를 갈다 — «точить зуб (затаить злобу)»; ③ 담을 쌓다 — «возвести стену (порвать связь)».<br>🧩 문자 교육 — обучение грамоте; 깨치다 — освоить; 열을 올리다 — рьяно браться."},{"n":22,"points":2,"instr":"Выберите главную мысль текста.","passage":"문자 교육은 빠를수록 좋다고 믿는 부모들이 있다. 이들은 자신의 아이가 또래보다 글자를 더 빨리 깨치기를 바라며 문자 교육에 (열을 올린다). 그런데 나이가 어린 아이들은 아직 다양한 능력들이 완전히 발달하지 못해 온몸의 감각을 동원하여 정보를 얻는다. 이 시기에 글자를 읽는 것에 집중하다 보면 다른 감각을 사용할 기회가 줄어 능력이 고르게 발달하는 데 어려움이 있을 수 있다.","options":["문자 교육을 하는 방법이 다양해져야 한다.","아이의 감각을 기르는 교육이 필요하다.","이른 문자 교육이 아이의 발달을 방해할 수 있다.","아이들은 서로 비슷한 시기에 글자를 배우는 것이 좋다."],"answer":3,"explain":"✅ <b>③</b>: у маленьких детей способности развиты не полностью, и они познают мир всеми чувствами; ранний упор на чтение букв сокращает использование других чувств и мешает равномерному развитию.<br>✖️ ① про «разнообразие методов» — не главная мысль; ② про «развитие чувств» — лишь деталь; ④ про «учить в одно время» — нет.<br>🧩 발달 — развитие; 감각 — чувство, восприятие; 방해하다 — мешать; 고르게 — равномерно."},{"n":23,"points":2,"instr":"Выберите чувство рассказчицы, переданное в подчёркнутой части.","passage":"고향에 사는 아버지가 오랜만에 우리 집에 오셨다. 나는 남편과 함께 아버지와 이런저런 이야기를 나누며 거실에 앉아 있었다. 그때 갑자기 남편이 아버지를 모시고 영화관에 가자고 했다. 그 말에 나는 \"영화관은 무슨? 아버지는 어둡고 갑갑해서 영화관 가는 거 안 좋아하셔.\" 하고 내뱉었다. 그래도 아버지에게 슬쩍 \"영화 보러 가실래요?\" 하고 물었는데 손사래를 치실 것 같던 아버지는 그저 가만히 계셨다. 그 순간 나는 아버지의 마음을 읽을 수 있었다. <u>나는 왜 아버지가 영화관에 가는 것을 안 좋아하실 거라고 생각했을까.</u> 지금껏 내 기준에서 판단한 일들이 얼마나 많을까 생각하니 마음이 무거워졌다. 영화관에 갈 준비를 하며 옷도 살피고 모자도 쓰고 벗기를 반복하시는 아버지의 얼굴에는 미소가 가득했다. 그런 아버지를 보며 나는 앞으로 아버지가 무엇을 좋아하시는지 관심을 가지기로 했다.","options":["부담스럽다","불만스럽다","짜증스럽다","죄송스럽다"],"answer":4,"explain":"✅ <b>④ 죄송스럽다</b> (чувствует себя виноватой): «почему я решила, что отец не любит ходить в кино?» — осознав, сколько всего судила по своим меркам, рассказчица ощущает тяжесть на душе и вину перед отцом.<br>✖️ ① 부담스럽다 — «обременительно»; ② 불만스럽다 — «недовольна»; ③ 짜증스럽다 — «раздражена».<br>🧩 심정 — чувство, состояние души; 마음이 무겁다 — на душе тяжело; 판단하다 — судить; 죄송스럽다 — испытывать вину."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"고향에 사는 아버지가 오랜만에 우리 집에 오셨다. 나는 남편과 함께 아버지와 이런저런 이야기를 나누며 거실에 앉아 있었다. 그때 갑자기 남편이 아버지를 모시고 영화관에 가자고 했다. 그 말에 나는 \"영화관은 무슨? 아버지는 어둡고 갑갑해서 영화관 가는 거 안 좋아하셔.\" 하고 내뱉었다. 그래도 아버지에게 슬쩍 \"영화 보러 가실래요?\" 하고 물었는데 손사래를 치실 것 같던 아버지는 그저 가만히 계셨다. 그 순간 나는 아버지의 마음을 읽을 수 있었다. 나는 왜 아버지가 영화관에 가는 것을 안 좋아하실 거라고 생각했을까. 지금껏 내 기준에서 판단한 일들이 얼마나 많을까 생각하니 마음이 무거워졌다. 영화관에 갈 준비를 하며 옷도 살피고 모자도 쓰고 벗기를 반복하시는 아버지의 얼굴에는 미소가 가득했다. 그런 아버지를 보며 나는 앞으로 아버지가 무엇을 좋아하시는지 관심을 가지기로 했다.","options":["나는 아버지와 자주 영화를 보러 다녔다.","아버지는 내 질문에 아무 말도 하지 않았다.","아버지는 영화를 보러 가기 위해 우리 집에 왔다.","나는 아버지가 외출 준비하는 모습이 마음에 들지 않았다."],"answer":2,"explain":"✅ <b>②</b>: на тихий вопрос «пойдёте в кино?» отец, вопреки ожиданию отказа, просто промолчал (그저 가만히 계셨다) — то есть ничего не ответил.<br>✖️ ① они НЕ ходили часто — рассказчица была уверена, что отец кино не любит; ③ отец приехал в гости, а не ради кино; ④ рассказчице, наоборот, было радостно: лицо отца сияло улыбкой.<br>🧩 손사래를 치다 — махать рукой (в знак отказа); 가만히 — тихо, не двигаясь; 외출 — выход из дома."},{"n":25,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок новости.","passage":"출산율 또 하락, 정부 대책 효과 없어","options":["정부가 대책을 세워 노력했으나 출산율은 다시 떨어졌다.","정부는 출산율이 낮아지지 않도록 효과적인 정책을 마련했었다.","정부의 정책 중 시급히 개선되어야 할 부분이 출산 관련 정책이다.","출산과 관련한 정부의 지원이 축소되자 출산율이 급격히 낮아졌다."],"answer":1,"explain":"✅ <b>①</b>: «출산율 또 하락» (рождаемость снова упала) + «정부 대책 효과 없어» (меры правительства не дали эффекта) → правительство старалось, принимало меры, но рождаемость опять снизилась.<br>✖️ ② меры как раз НЕ сработали; ③ заголовок не про «срочно улучшить политику»; ④ про «сокращение поддержки» не сказано.<br>🧩 출산율 — рождаемость; 대책 — мера; 효과 없다 — без эффекта; 하락 — падение."},{"n":26,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок новости.","passage":"놀이공원, 수익에만 치중 이용객 안전은 뒷전","options":["놀이공원의 이용객들은 놀이공원에 안전시설 점검을 요구했다.","놀이공원이 이용객의 안전을 중시하기 시작한 후 수익이 증가했다.","놀이공원이 수익은 중요시하고 이용객의 안전은 중요시하지 않고 있다.","놀이공원은 수익이 감소해 이용객의 안전에 더 이상 투자하기 어려워졌다."],"answer":3,"explain":"✅ <b>③</b>: «수익에만 치중» (упор только на прибыль) + «안전은 뒷전» (безопасность — на втором плане) → парк ценит прибыль и пренебрегает безопасностью посетителей.<br>✖️ ① про требования посетителей не сказано; ② прибыль выросла НЕ из-за внимания к безопасности; ④ про «снижение прибыли» речи нет.<br>🧩 수익 — прибыль; 치중하다 — делать упор; 뒷전 — задний план; 안전 — безопасность."},{"n":27,"points":2,"instr":"Выберите вариант, который лучше всего объясняет заголовок новости.","passage":"제2공장 정상 가동, 반도체 공급 안정은 미지수","options":["제2공장이 정상적으로 가동됨에 따라 반도체 공급이 안정되었다.","제2공장이 반도체 생산을 시작했지만 공급이 안정될지는 불확실하다.","반도체가 안정적으로 공급되기 위해서는 제2공장의 가동이 필수적이다.","반도체 공급이 안정적으로 이루어지면서 제2공장도 정상 가동될 수 있었다."],"answer":2,"explain":"✅ <b>②</b>: «제2공장 정상 가동» (второй завод заработал штатно) + «공급 안정은 미지수» (стабильность поставок — под вопросом) → производство началось, но стабилизируются ли поставки — неясно.<br>✖️ ① поставки ещё НЕ стабилизированы; ③ заголовок не про «необходимость» завода; ④ причинно-следственная связь перевёрнута.<br>🧩 가동 — работа (оборудования); 반도체 — полупроводник; 공급 — поставка; 미지수 — неизвестная величина, под вопросом."},{"n":28,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"수업에 게임 방식을 도입하면 열의를 갖고 참여하는 학생들이 많아진다. 학생들은 흥미진진한 퀴즈를 풀며 용어와 개념을 익힌다. 퀴즈의 정답을 맞힌 학생에게는 즉각적으로 점수가 부여되는데 어려운 문제를 빨리 맞힐수록 획득하는 점수가 크다. 이러한 방법을 활용하면 학생들이 (        ) 수 있다.","options":["교실 환경을 살필","수업에 보다 집중할","게임에 흥미를 느낄","친구들과 더 소통할"],"answer":2,"explain":"✅ <b>② 수업에 보다 집중할</b>: игровой формат увлекает, ученики через увлекательные квизы усваивают термины и понятия, получают очки за быстрые верные ответы → так они лучше сосредотачиваются на уроке.<br>✖️ ① «осмотреть обстановку класса» — не следует; ③ «интерес к игре» — лишь средство, не итог; ④ «больше общаться с друзьями» — нет.<br>🧩 도입하다 — вводить; 열의 — рвение; 부여되다 — присваиваться; 집중하다 — сосредотачиваться."},{"n":29,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"\"지구가 아파요!\"라는 문구가 새겨진 티셔츠나 잘려 나간 나무가 그려진 가방 등을 구매하는 사람들이 증가하고 있다. 사람들은 그 상품이 (        ) 때문에 구매를 한다. 그들은 구매한 물건을 일상에서 사용함으로써 사회 문제에 대한 입장을 표현한다. 그리고 주변 사람들이 그 상품을 보고 거기에 담긴 메시지에 대해 관심을 갖도록 한다.","options":["세련되게 디자인되었기","천연 소재로 만들어졌기","본인의 체형을 보완해 주기","자신의 가치관을 드러낼 수 있기"],"answer":4,"explain":"✅ <b>④ 자신의 가치관을 드러낼 수 있기</b>: люди покупают вещи с экологическими надписями/рисунками, чтобы, пользуясь ими, выражать свою позицию по социальным проблемам — то есть демонстрировать свои ценности.<br>✖️ ① «стильный дизайн» — не причина по тексту; ② «натуральные материалы» — нет; ③ «подчёркивает фигуру» — нет.<br>🧩 문구 — надпись; 새겨지다 — быть выгравированным; 입장 — позиция; 가치관 — система ценностей."},{"n":30,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"깨어져도 파편이 튀지 않는 안전유리는 한 과학자가 실험실 선반에서 떨어진 유리병에 주목하면서 발명되었다. 산산조각 난 다른 유리병과 달리 금이 간 채 형태를 유지하고 있는 유리병이 있었다. 이 병은 안에 담긴 용액이 마르면서 유리 표면에 생긴 막이 유리 조각을 붙잡고 있었다. 이 점에 착안하여 (        ) 안전유리를 제작하게 되었다.","options":["파편 조각을 붙인","유리에 막을 입힌","유리를 여러 장 겹친","깨지지 않는 재료를 사용한"],"answer":2,"explain":"✅ <b>② 유리에 막을 입힌</b>: учёный заметил, что в разбившейся бутылке плёнка от высохшего раствора удержала осколки. Взяв это за основу, безопасное стекло сделали, «нанеся на стекло плёнку».<br>✖️ ① «приклеить осколки» — не то; ③ «сложить несколько слоёв стекла» — это другой тип стекла; ④ «использовать небьющийся материал» — стекло как раз бьётся, но не разлетается.<br>🧩 안전유리 — безопасное стекло; 파편 — осколок; 막 — плёнка; 착안하다 — взять за основу идею."},{"n":31,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"보통 수학에서는 개념이 먼저 정립되고 기호가 등장한다. 그러나 수가 끝없이 커지는 상태를 가리키는 무한대의 경우에는 정반대이다. 무한대는 (        ) 후에도 한동안 개념이 정립되지 못했다. 왜냐하면 당시의 학자들은 무한대를 인간의 능력으로는 파악할 수 없다고 여겼기 때문이다. 그래서 수학계에서 무한대를 정의하는 것은 오랫동안 시도되지 않았다.","options":["기호가 만들어진","의미가 여러 번 바뀐","학계에서 활발히 연구된","반대되는 이론이 등장한"],"answer":1,"explain":"✅ <b>① 기호가 만들어진</b>: обычно в математике сначала складывается понятие, затем символ; у бесконечности — наоборот: даже «после того как был создан символ» понятие долго не оформлялось, ведь учёные считали бесконечность непостижимой.<br>✖️ ② «смысл менялся» — нет; ③ «активно изучали» — наоборот, определять не пытались; ④ «появилась противоположная теория» — нет.<br>🧩 개념 — понятие; 정립되다 — устанавливаться; 기호 — символ; 무한대 — бесконечность."},{"n":32,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"하루살이는 하루밖에 못 살 정도로 수명이 짧다고 해서 붙은 이름이다. 그러나 하루살이 애벌레는 성충이 되기 위해 약 1년을 물속에 살고 성충이 되어서는 1~2주 정도 산다. 하루살이 애벌레는 물속에 가라앉은 나뭇잎 등을 먹고 살지만 성충이 되면 입이 퇴화한다. 이런 까닭에 성충은 애벌레 때 물속에 저장해 둔 영양분을 소모할 뿐 따로 먹이를 섭취하지 못한다.","options":["하루살이의 수명은 하루를 넘지 않는다.","하루살이는 성충이 되는 데에 1~2주 정도 걸린다.","하루살이 성충은 애벌레 때 저장한 영양분으로 산다.","하루살이의 입은 성충이 되면서 기능이 더욱 발달한다."],"answer":3,"explain":"✅ <b>③</b>: у взрослой особи рот атрофируется (입이 퇴화), поэтому она лишь расходует питательные вещества, запасённые на стадии личинки.<br>✖️ ① личинка живёт в воде ~год, взрослая — 1~2 недели, то есть дольше дня; ② около ГОДА уходит, чтобы стать взрослой, а 1~2 недели — срок жизни взрослой; ④ рот не развивается, а атрофируется.<br>🧩 하루살이 — подёнка; 애벌레 — личинка; 성충 — имаго (взрослая особь); 퇴화하다 — атрофироваться."},{"n":33,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"눈물은 약 98%가 물로 이루어져 있다. 나머지 성분은 눈물을 흘리는 상황에 따라 달라진다. 먼지 같은 외부의 물리적 자극 때문에 흘리는 눈물에는 세균에 저항할 수 있는 단백질이 포함되어 있다. 슬플 때 흘리는 눈물에는 항균 물질뿐만 아니라 스트레스로 인해 체내에 쌓인 물질도 들어 있다. 그래서 슬플 때 울고 나면 신체에 해로운 물질이 몸 밖으로 나가 기분이 나아진 것 같은 느낌을 받는다.","options":["눈물 속에 있는 단백질은 기분을 좋게 만든다.","슬퍼서 흘리는 눈물에는 항균 물질이 빠져 있다.","슬플 때 흘리는 눈물 속에는 몸에 나쁜 물질이 포함되어 있다.","물리적 자극으로 흘리는 눈물이 슬플 때의 눈물보다 성분이 더 다양하다."],"answer":3,"explain":"✅ <b>③</b>: в слезах при грусти, кроме антибактериальных веществ, есть и накопленные из-за стресса вещества — вредные для тела (체내에 쌓인 물질 = 몸에 해로운 물질).<br>✖️ ① мысль про «белок улучшает настроение» — нет; ② в слезах грусти антибактериальные вещества ЕСТЬ; ④ наоборот, слёзы грусти богаче по составу.<br>🧩 눈물 — слёзы; 단백질 — белок; 항균 물질 — антибактериальное вещество; 해롭다 — вредный."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"19세기 중반까지는 태양의 위치를 기준으로 시간을 정해서 지역마다 시간이 달랐다. 이는 철도 이용이 활발해지면서 문제가 되었다. 철도 회사는 본사가 있는 지역의 시간을 기준으로 열차를 운행했다. 그래서 승객은 다른 지역에서 온 열차를 탈 때마다 자기 지역의 시간과 열차 시간이 달라 불편을 겪었다. 이를 해결하고자 캐나다의 한 철도 기사가 지구의 경도를 기준으로 하는 표준시를 제안하였고 이것이 현재의 표준시가 되었다.","options":["표준시 도입의 필요성은 철도 분야에서 제기되었다.","예전에는 철도 회사가 지역의 기준 시간을 결정했다.","캐나다에서는 19세기 이전부터 표준시를 사용해 왔다.","철도 승객들은 표준시의 적용으로 불편을 겪게 되었다."],"answer":1,"explain":"✅ <b>①</b>: разнобой во времени стал проблемой именно с распространением железных дорог, и стандартное время предложил канадский железнодорожник — то есть потребность возникла в железнодорожной сфере.<br>✖️ ② региональное время задавалось по солнцу, а не железной дорогой; ③ в Канаде до XIX в. стандартного времени не было; ④ неудобства были ДО введения стандартного времени, оно их и устранило.<br>🧩 표준시 — стандартное (поясное) время; 경도 — долгота; 운행하다 — курсировать; 제기되다 — быть поднятым (о вопросе)."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"초소형 카메라는 의료용 및 산업용으로 만들어져 각 현장에서 유용하게 사용되고 있다. 그러나 원래의 목적에 맞지 않게 타인의 신체를 몰래 촬영하는 용도로 악용되는 사례가 늘고 있다. 이러한 악용을 원천적으로 방지하기 위해서는 신상 정보를 등록해야만 카메라의 판매 및 유통이 가능하도록 법적 규제를 강화할 필요가 있다.","options":["의료용 및 산업용 초소형 카메라의 사용처를 확대해야 한다.","초소형 카메라가 더 유용하게 사용될 수 있도록 개발해야 한다.","초소형 카메라가 악용되는 것을 막기 위한 대책이 마련되어야 한다.","원활한 판매 및 유통을 위해 초소형 카메라의 등록 과정을 간소화해야 한다."],"answer":3,"explain":"✅ <b>③</b>: вывод текста — чтобы в корне пресечь злоупотребление микрокамерами (тайная съёмка), нужно усилить правовое регулирование; то есть требуются меры против злоупотребления.<br>✖️ ① «расширить сферы применения» — противоречит; ② «развивать ради полезности» — не тема; ④ «упростить регистрацию» — наоборот, её надо сделать обязательной.<br>🧩 초소형 카메라 — микрокамера; 악용되다 — использоваться во зло; 원천적으로 — в корне; 규제 — регулирование."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"정보의 양이 폭발적으로 증가하면서 핵심만 집어낸 요약형 정보를 찾는 사람들이 늘고 있다. 필요한 지식을 쉽고 빠르게 얻을 수 있기 때문이다. 그러나 짧게 정돈된 지식만을 취하다 보면 사물을 오랫동안 관찰하고 분석하는 능력이 떨어지거나 정보를 비판적으로 처리할 수 있는 능력이 무뎌질 수 있다.","options":["요약형 정보는 가장 효율적인 정보 습득 방식이다.","요약형 정보는 사람들의 사고력 저하를 초래할 수 있다.","사람들이 습득해야 할 지식의 양이 크게 증가하고 있다.","짧게 정돈된 지식 덕분에 정보 처리 시간을 줄일 수 있다."],"answer":2,"explain":"✅ <b>②</b>: автор предупреждает — если брать только кратко «упакованное» знание, слабеет способность долго наблюдать, анализировать и критически обрабатывать информацию, то есть страдает мышление.<br>✖️ ① «самый эффективный способ» — текст с этим спорит; ③ «растёт объём знаний» — лишь повод, не тема; ④ «экономия времени» — это плюс, но не главная мысль.<br>🧩 요약형 — сжатый, в виде резюме; 사고력 — мыслительные способности; 저하 — снижение; 비판적 — критический."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"유명 드라마가 소설책으로 출간되는 일이 많아졌다. 소설이 인기를 끌면 그 후에 영상물로 제작되던 것과는 반대되는 현상이 생긴 것이다. 이러한 현상의 영향 탓인지 처음부터 영상물을 염두에 두고 글을 쓰는 소설가들이 늘고 있다. 그러나 이와 같이 영상물 중심으로 창작과 출판이 이루어진다면 순수 문학이 가진 고유한 특성들이 하나둘씩 사라질지도 모른다.","options":["작가들의 창작열을 높이기 위한 보상 체계 마련이 시급하다.","출판물의 판매를 늘리기 위해 영상물을 활용한 홍보가 필요하다.","영상물이 책으로 출간되어야 출판 시장이 활성화될 수 있다.","영상물이 갖는 영향력이 커지면 순수 문학이 위기를 맞을 수 있다."],"answer":4,"explain":"✅ <b>④</b>: всё чаще пишут, изначально ориентируясь на экранизацию; если творчество и издание будут вращаться вокруг видео, уникальные черты чистой литературы могут постепенно исчезнуть — то есть ей грозит кризис.<br>✖️ ① про «систему вознаграждения» — нет; ② про «промо через видео» — нет; ③ «видео должно издаваться книгами» — противоречит тревоге автора.<br>🧩 출간되다 — выходить (о книге); 영상물 — видеопродукция; 순수 문학 — чистая литература; 위기 — кризис."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"분자 요리는 과학을 응용해 기존 식재료가 갖는 물리적인 제약에서 벗어나 새로운 형태와 식감의 음식을 만드는 요리법이다. 노란 망고 주스와 하얀 우유로 계란 모양의 요리를 만드는 것이 한 예다. 분자 요리는 식재료 고유의 맛과 향은 유지한 채 기존에는 볼 수 없었던 요리를 선보일 수 있다는 점에서 새로운 요리 문화를 이끌 것으로 기대하고 있다. 독특한 음식에 대한 설렘과 즐거움을 제공한다는 점도 이러한 기대감을 키운다.","options":["분자 요리가 과학의 연구 영역을 더 넓히고 있다.","독특한 음식에 대한 소비자들의 요구가 늘고 있다.","식재료가 갖는 제약 탓에 요리법 개발이 정체되고 있다.","새로운 요리 문화를 이끌 요리법으로 분자 요리가 주목받고 있다."],"answer":4,"explain":"✅ <b>④</b>: молекулярная кухня сохраняет вкус/аромат продуктов, но создаёт небывалые блюда и дарит радость от необычной еды — поэтому на неё возлагают надежды как на кулинарию, ведущую новую гастрокультуру.<br>✖️ ① «расширяет область науки» — не тема; ② «растёт спрос потребителей» — лишь штрих; ③ «развитие застопорилось» — противоречит тексту.<br>🧩 분자 요리 — молекулярная кухня; 식재료 — продукты; 식감 — текстура (во рту); 주목받다 — привлекать внимание."},{"n":39,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 상업적 공간으로 채워진 거리를 보며 눈살을 찌푸리는 이들도 많다.\n\n도시의 거리는 온통 상점으로 가득 차 있다. ( ㉠ ) 하지만 상점은 거리에 활력을 불어넣어 걷고 싶은 거리를 만드는 데 중요한 역할을 한다. ( ㉡ ) 상점은 단순히 물건을 파는 공간이 아니라 보행자들에게 볼거리와 잔재미를 끊임없이 제공하는 거대한 미술관이 되어 준다. ( ㉢ ) 또 밤거리를 밝히는 가로등이며 보안등이자 거리의 청결함과 쾌적함을 지켜 주는 파수꾼이 되기도 한다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: вставка — негативный взгляд («многие морщатся, глядя на улицы, заполненные коммерцией»). Сразу за ним идёт «하지만 상점은… 중요한 역할을 한다» («ОДНАКО магазины играют важную роль») — противопоставление возможно только если перед ним стоит та самая негативная оценка, то есть в ㉠.<br>✖️ ㉡㉢㉣ — там уже перечисляются положительные роли магазинов, «하지만» оказалось бы без antithesis.<br>🧩 상업적 — коммерческий; 눈살을 찌푸리다 — морщиться (от неодобрения); 활력 — оживление; 파수꾼 — страж."},{"n":40,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 무엇보다 독자들이 더 흥미롭게 읽을 수 있도록 문답의 형식으로 구성된 것이 돋보인다.\n\n『박철수의 거주 박물지』는 건축학자가 서울을 중심으로 한 거주 문화사를 소개한 책이다. ( ㉠ ) 아파트가 어떻게 중산층의 표준 욕망이 됐는가, 장독이 왜 아파트에서 사라졌는가와 같은 물음들을 도면과 신문 기사를 곁들여 풀어내는 식이다. ( ㉡ ) 그 과정에서 이웃과 정을 나누는 일 없이 각박하게 살아온 지난 수십 년의 세태를 지적하는 것도 놓치지 않고 있다. ( ㉢ ) 이웃과 정답게 살아가는 모습을 그려내고자 하는 미래의 건축학도에게 추천하고 싶다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: вставка хвалит книгу за форму «вопрос-ответ». Сразу после ㉠ как раз идёт описание этого приёма — «как апартаменты стали…, почему исчезли соевые горшки… — такие ВОПРОСЫ раскрываются с чертежами и статьями». Значит общая оценка (문답 형식) стоит перед этим описанием, в ㉠.<br>✖️ ㉡㉢㉣ — там уже про критику быта и рекомендацию, связь с «формой Q&A» теряется.<br>🧩 거주 — проживание; 문답 형식 — формат «вопрос-ответ»; 돋보이다 — выделяться; 세태 — нравы эпохи."},{"n":41,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그 효과는 기대 이상으로 빠르게 나타났다.\n\n최초의 동전은 값비싼 금과 은으로 제작되었다. ( ㉠ ) 이 동전의 가치가 매우 높았던 까닭에 주화를 조금씩 깎아 내서 이득을 보려는 사람들이 많았다. ( ㉡ ) 자연히 시장에서는 성한 금화나 은화를 찾아볼 수 없었고 주화를 발행하는 국가도 손실이 컸다. ( ㉢ ) 그래서 그 대안으로 주화들의 테두리에 톱니 모양을 새겨 훼손 여부가 잘 드러나도록 하였다. ( ㉣ ) 톱니 모양이 훼손된 주화는 육안으로 쉽게 구별할 수 있었고 그러한 돈은 사람들이 받지 않았기 때문이다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"✅ <b>④ ㉣</b>: вставка «эффект проявился быстрее ожиданий» относится к мере — насечкам на ребре монет (описана перед ㉣). Предложение после ㉣ начинается с объяснения «…때문이다» (потому что повреждённую насечку легко заметить и такие деньги не принимали), то есть поясняет, ПОЧЕМУ эффект был быстрым. Значит вставка идёт в ㉣.<br>✖️ ㉠㉡㉢ — там ещё описываются проблема и само решение, об «эффекте» говорить рано.<br>🧩 동전 — монета; 주화 — чеканная монета; 테두리 — край, ободок; 톱니 모양 — зубчатый узор (насечка); 훼손 — повреждение."},{"n":42,"points":2,"instr":"Выберите чувство «матери», переданное в подчёркнутой части.","passage":"어머니와 아버지가 프랜차이즈 빵집을 연다고 했을 때, 주영은 언젠가는 두 사람이 자기를 가게로 부를 것임을 알았다. 그러나 여름에 있을 지방직 9급 시험일까지는 기다려 줄 줄 알았다. (중략) 실제로 벌어진 일은 그런 예상과는 전혀 달랐다. 부모님이 주영에게 빵집으로 나와 일하라는 말을 한 것은 가게 문을 정식으로 연 당일 오후였다. 어머니는 주영에게 전화를 걸어 이렇게 말했다. <u>네가 우리 가족 맞냐?</u> 그러고는 바로 전화를 끊어 버렸다. (중략) 매장은 사람들로 북적였다. 개장 기념으로 식빵을 반값에 팔고, 어떤 제품을 사든지 아메리카노를 한 잔 무료로 제공하는 행사를 벌이는 중이었다. 프랜차이즈 본사에서 나온 지원 인력들이 손님을 맞고 질문에 답변하고 카드를 받고 계산을 했다. 아버지와 어머니는 하인들처럼 겁먹은 눈으로 에, 에, 굽실거리며 지원 인력들의 지시에 따랐다.","options":["억울하다","서운하다","걱정스럽다","혼란스럽다"],"answer":2,"explain":"✅ <b>② 서운하다</b> (обиженно-горько): сын не пришёл помочь в день открытия, и мать с упрёком бросает «네가 우리 가족 맞냐?» (ты вообще член нашей семьи?) и сразу кладёт трубку — это обида и разочарование.<br>✖️ ① 억울하다 — «несправедливо обижена (без вины)»; ③ 걱정스럽다 — «тревожно»; ④ 혼란스럽다 — «растеряна».<br>🧩 심정 — состояние души; 서운하다 — быть задетым, обиженным; 끊어 버리다 — резко прекратить; 가족 — семья."},{"n":43,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"어머니와 아버지가 프랜차이즈 빵집을 연다고 했을 때, 주영은 언젠가는 두 사람이 자기를 가게로 부를 것임을 알았다. 그러나 여름에 있을 지방직 9급 시험일까지는 기다려 줄 줄 알았다. (중략) 실제로 벌어진 일은 그런 예상과는 전혀 달랐다. 부모님이 주영에게 빵집으로 나와 일하라는 말을 한 것은 가게 문을 정식으로 연 당일 오후였다. 어머니는 주영에게 전화를 걸어 이렇게 말했다. 네가 우리 가족 맞냐? 그러고는 바로 전화를 끊어 버렸다. (중략) 매장은 사람들로 북적였다. 개장 기념으로 식빵을 반값에 팔고, 어떤 제품을 사든지 아메리카노를 한 잔 무료로 제공하는 행사를 벌이는 중이었다. 프랜차이즈 본사에서 나온 지원 인력들이 손님을 맞고 질문에 답변하고 카드를 받고 계산을 했다. 아버지와 어머니는 하인들처럼 겁먹은 눈으로 에, 에, 굽실거리며 지원 인력들의 지시에 따랐다. 주영의 아버지와 어머니는 카드 결제조차 제대로 하지 못했다. 빵에는 바코드가 없었다. 제품이 어느 카테고리에 속하는지, 이름이 뭔지를 전부 외워야 단말기에 가격을 입력할 수 있었다. 아버지는 단말기 앞에서 빵을 봉투에 담으며 로프, 깜파뉴, 치아바타, 푸가스 같은 낯선 이름들을 외우려 애썼다.","options":["빵 가게는 개업 첫 날 손님이 많지 않았다.","주영은 시험을 마치자마자 부모님께 연락을 받았다.","아버지는 여러 종류의 빵 이름을 모두 알고 있었다.","부모님은 직원이 시키는 일을 했다."],"answer":4,"explain":"✅ <b>④</b>: родители «дрожащими глазами, поддакивая, кланялись и следовали указаниям присланного персонала» (지원 인력들의 지시에 따랐다) — то есть делали то, что велели сотрудники.<br>✖️ ① в день открытия было МНОГО людей (매장은 사람들로 북적였다); ② родители позвали сына в день открытия, ДО летнего экзамена, а не «сразу после экзамена»; ③ отец, наоборот, с трудом заучивал незнакомые названия хлеба.<br>🧩 개업 — открытие (бизнеса); 북적이다 — быть многолюдным; 지시에 따르다 — следовать указаниям; 단말기 — терминал."},{"n":44,"points":2,"instr":"Выберите главную тему текста.","passage":"원고 마감이 임박하거나 시험공부 시간이 부족하면 사람은 본능적으로 놀라운 집중력을 발휘한다. 그래서 시간 부족 상태가 되어야만 일을 효율적으로 할 수 있다고 믿는 사람들이 많다. 그러나 효율성만 믿고 (무턱대고 일을 미루는) 것은 어리석은 일이다. 시간에 쫓기면 사람들은 한 가지에만 집중할 뿐 그 외에 다른 것에는 주의를 기울이지 못하게 되기 때문이다. 이런 상황은 실제로 상당히 위험할 수 있다. 단적인 예로 소방관들은 구조 현장으로 이동하는 과정에서 안전벨트를 매지 않아 사고를 당하는 경우가 매우 많다. 일 초가 급한 상황에서 인명 구조에만 집중한 나머지 차 문을 닫거나 안전벨트를 매는 기본적인 일을 잊어서 생긴 결과이다. 이처럼 시간적 여유가 부족해지면 집중했던 일은 성공적으로 처리할 수 있겠지만 나머지 많은 것들은 놓칠 수 있다.","options":["인간의 집중력은 시간적인 제약이 많을수록 높아진다.","인간에게 시간 부족은 효율적인 일 처리의 원동력이 된다.","단시간 내에 일을 처리해도 성공적으로 일을 마칠 수 있다.","시간 부족은 인간의 시야를 좁혀 부정적인 영향을 미칠 수 있다."],"answer":4,"explain":"✅ <b>④</b>: при нехватке времени человек концентрируется лишь на одном и упускает остальное (пример с пожарными, забывающими о ремне) — то есть дефицит времени сужает «поле зрения» и может навредить.<br>✖️ ① «чем больше ограничений, тем выше концентрация» — текст это оспаривает; ② «нехватка времени — двигатель эффективности» — это как раз заблуждение, против которого автор; ③ «и за короткое время можно всё успешно завершить» — противоречит выводу.<br>🧩 집중력 — концентрация; 효율성 — эффективность; 시야를 좁히다 — сужать кругозор; 놓치다 — упустить."},{"n":45,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"원고 마감이 임박하거나 시험공부 시간이 부족하면 사람은 본능적으로 놀라운 집중력을 발휘한다. 그래서 시간 부족 상태가 되어야만 일을 효율적으로 할 수 있다고 믿는 사람들이 많다. 그러나 효율성만 믿고 (        ) 것은 어리석은 일이다. 시간에 쫓기면 사람들은 한 가지에만 집중할 뿐 그 외에 다른 것에는 주의를 기울이지 못하게 되기 때문이다. 이런 상황은 실제로 상당히 위험할 수 있다. 단적인 예로 소방관들은 구조 현장으로 이동하는 과정에서 안전벨트를 매지 않아 사고를 당하는 경우가 매우 많다. 일 초가 급한 상황에서 인명 구조에만 집중한 나머지 차 문을 닫거나 안전벨트를 매는 기본적인 일을 잊어서 생긴 결과이다. 이처럼 시간적 여유가 부족해지면 집중했던 일은 성공적으로 처리할 수 있겠지만 나머지 많은 것들은 놓칠 수 있다.","options":["성급히 일을 처리하는","무턱대고 일을 미루는","관심사를 무한히 늘리는","전적으로 하나에만 매달리는"],"answer":2,"explain":"✅ <b>② 무턱대고 일을 미루는</b>: уверовав, что эффективны лишь под давлением срока, люди «бездумно откладывают дела» — и это глупо, ведь спешка заставляет сосредоточиться на одном и упустить важное (как ремень у пожарных).<br>✖️ ① «спешно выполнять» — наоборот, проблема в откладывании; ③ «бесконечно расширять круг интересов» — не из текста; ④ «целиком держаться за одно» — это следствие спешки, а не то, что «глупо делать, веря в эффективность».<br>🧩 효율성 — эффективность; 무턱대고 — наобум, бездумно; 미루다 — откладывать; 쫓기다 — быть гонимым (временем)."},{"n":46,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그러나 이 방법은 자칫하면 우주 쓰레기를 엉뚱한 곳으로 밀어낼 위험이 있었다.\n\n우주는 지구와 환경이 상이해 지구에서 쓰는 방법으로는 쓰레기를 수거하기가 어렵다. 처음에는 작살과 같이 물리적인 힘을 이용해서 쓰레기를 찍을 수 있는 도구가 거론되었다. ( ㉠ ) 이 때문에 테이프나 빨판같이 접착력이 있는 도구를 사용하자는 제안도 나왔다. ( ㉡ ) 점성이 강한 테이프의 경우는 우주에서의 극심한 온도 변화를 견디지 못했으며 빨판은 진공 상태에서는 소용이 없었다. ( ㉢ ) 그런데 최근 한 연구진이 도마뱀이 벽에 쉽게 달라붙어 떨어지지 않는 것에서 영감을 받아 접착력이 있는 도구를 개발하는 데 성공했다. ( ㉣ ) 도마뱀의 발바닥에 있는 수백만 개의 미세한 털들이 표면에 접촉할 때 생기는 힘을 응용한 것이다.","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: вставка «однако ЭТОТ метод рисковал оттолкнуть мусор не туда» относится к первому способу — гарпуну (физическая сила). Сразу за ㉠ идёт «이 때문에 (поэтому) предложили клейкие инструменты». Значит минус гарпуна (вставка) стоит в ㉠ и служит причиной перехода к клейким средствам.<br>✖️ ㉡㉢㉣ — там речь уже о клейких средствах и гекконе, «이 방법» не на что сослаться.<br>🧩 우주 쓰레기 — космический мусор; 작살 — гарпун; 엉뚱한 곳 — не то место; 자칫하면 — чуть что, при неосторожности."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"우주는 지구와 환경이 상이해 지구에서 쓰는 방법으로는 쓰레기를 수거하기가 어렵다. 처음에는 작살과 같이 물리적인 힘을 이용해서 쓰레기를 찍을 수 있는 도구가 거론되었다. 이 때문에 테이프나 빨판같이 접착력이 있는 도구를 사용하자는 제안도 나왔다. 점성이 강한 테이프의 경우는 우주에서의 극심한 온도 변화를 견디지 못했으며 빨판은 진공 상태에서는 소용이 없었다. 그런데 최근 한 연구진이 도마뱀이 벽에 쉽게 달라붙어 떨어지지 않는 것에서 영감을 받아 접착력이 있는 도구를 개발하는 데 성공했다. 도마뱀의 발바닥에 있는 수백만 개의 미세한 털들이 표면에 접촉할 때 생기는 힘을 응용한 것이다.","options":["테이프는 우주의 온도 변화 때문에 점성을 잃었다.","작살은 접착력을 이용한 도구의 좋은 대안이 되었다.","우주에서 쓰레기를 처리하는 방법은 지구와 유사하다.","접착력을 이용한 쓰레기 수거 방법은 결국 성공하지 못했다."],"answer":1,"explain":"✅ <b>①</b>: «테이프의 경우는 우주에서의 극심한 온도 변화를 견디지 못했으며» — клейкая лента не выдержала резких перепадов температуры, то есть утратила клейкость (점성).<br>✖️ ② гарпун был НЕ альтернативой клейким средствам, а наоборот предшествовал им; ③ способы для космоса как раз ОТЛИЧАются от земных (환경이 상이해); ④ метод на основе геккона в итоге УДАЛСЯ (성공했다).<br>🧩 점성 — вязкость, клейкость; 견디다 — выдерживать; 진공 — вакуум; 영감을 받다 — вдохновиться."},{"n":48,"points":2,"instr":"Выберите, с какой целью написан текст.","passage":"4차 산업은 그 분야가 다양하지만 연구 개발이 핵심 원동력이라는 점에서 공통점을 갖고 있다. 이러한 점을 고려하여 정부는 신성장 산업에 대한 세제 지원을 확대하기로 했다. 미래형 자동차, 바이오 산업 등 신성장 기술에 해당하는 연구를 할 경우 세금을 대폭 낮춰 준다는 점에서 고무적인 일이다. 하지만 현재의 지원 조건이라면 몇몇 대기업에만 유리한 지원이 될 수 있다. 해당 기술을 전담으로 담당하는 연구 부서를 두어야 하고 원천 기술이 국내에 있는 경우에만 지원이 가능하기 때문이다. 혜택이 큰 만큼 (일정한 제약을 두려는) 정부의 입장을 이해하지 못하는 것은 아니다. 그러나 이번 정책의 목적이 단지 연구 개발 지원에 있는 것이 아니라 연구 개발을 유도하고 독려하고자 하는 것이라면 해당 조건을 완화하거나 단계적으로 적용할 필요가 있다.","options":["투자 정책이 야기할 혼란을 경고하려고","세제 지원 조건의 문제점을 지적하려고","연구 개발에 적절한 분야를 소개하려고","신성장 산업 연구의 중요성을 강조하려고"],"answer":2,"explain":"✅ <b>②</b>: автор хвалит саму идею льгот, но указывает: при нынешних условиях (своё R&D-подразделение + отечественная базовая технология) выгоду получат лишь несколько крупных компаний; поэтому условия надо смягчить. Цель — указать на ПРОБЛЕМЫ условий налоговой поддержки.<br>✖️ ① «предупредить о хаосе» — слишком сильно; ③ «представить подходящие сферы» — не цель; ④ «подчеркнуть важность исследований» — лишь фон.<br>🧩 세제 지원 — налоговые льготы; 조건 — условие; 문제점 — недостаток; 지적하다 — указывать."},{"n":49,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"4차 산업은 그 분야가 다양하지만 연구 개발이 핵심 원동력이라는 점에서 공통점을 갖고 있다. 이러한 점을 고려하여 정부는 신성장 산업에 대한 세제 지원을 확대하기로 했다. 미래형 자동차, 바이오 산업 등 신성장 기술에 해당하는 연구를 할 경우 세금을 대폭 낮춰 준다는 점에서 고무적인 일이다. 하지만 현재의 지원 조건이라면 몇몇 대기업에만 유리한 지원이 될 수 있다. 해당 기술을 전담으로 담당하는 연구 부서를 두어야 하고 원천 기술이 국내에 있는 경우에만 지원이 가능하기 때문이다. 혜택이 큰 만큼 (        ) 정부의 입장을 이해하지 못하는 것은 아니다. 그러나 이번 정책의 목적이 단지 연구 개발 지원에 있는 것이 아니라 연구 개발을 유도하고 독려하고자 하는 것이라면 해당 조건을 완화하거나 단계적으로 적용할 필요가 있다.","options":["일정한 제약을 두려는","연구 기관을 늘리려는","투자 대상을 확대하려는","지원을 단계적으로 하려는"],"answer":1,"explain":"✅ <b>① 일정한 제약을 두려는</b>: «혜택이 큰 만큼…» (раз выгода велика) → понятно, что правительство хочет поставить определённые ограничения (своё R&D-подразделение, отечественная технология). Автор говорит, что «не то чтобы не понимает» эту позицию.<br>✖️ ② «увеличить число НИИ»; ③ «расширить объекты инвестиций»; ④ «вводить поддержку поэтапно» — это предложение автора в КОНЦЕ, а не позиция правительства в пропуске.<br>🧩 혜택 — льгота, выгода; 제약 — ограничение; 입장 — позиция; 이해하다 — понимать."},{"n":50,"points":2,"instr":"Выберите отношение автора, переданное в подчёркнутой части.","passage":"4차 산업은 그 분야가 다양하지만 연구 개발이 핵심 원동력이라는 점에서 공통점을 갖고 있다. 이러한 점을 고려하여 정부는 신성장 산업에 대한 세제 지원을 확대하기로 했다. <u>미래형 자동차, 바이오 산업 등 신성장 기술에 해당하는 연구를 할 경우 세금을 대폭 낮춰 준다는 점에서 고무적인 일이다.</u> 하지만 현재의 지원 조건이라면 몇몇 대기업에만 유리한 지원이 될 수 있다. 해당 기술을 전담으로 담당하는 연구 부서를 두어야 하고 원천 기술이 국내에 있는 경우에만 지원이 가능하기 때문이다. 혜택이 큰 만큼 (일정한 제약을 두려는) 정부의 입장을 이해하지 못하는 것은 아니다. 그러나 이번 정책의 목적이 단지 연구 개발 지원에 있는 것이 아니라 연구 개발을 유도하고 독려하고자 하는 것이라면 해당 조건을 완화하거나 단계적으로 적용할 필요가 있다.","options":["기술 발전이 산업 구조 변화에 미칠 영향을 인정하고 있다.","세제 지원의 변화가 투자 감소로 이어질 것을 우려하고 있다.","세금 정책이 연구 개발에 미치는 부정적 영향을 비판하고 있다.","신성장 기술에 대한 세제 지원 정책을 긍정적으로 평가하고 있다."],"answer":4,"explain":"✅ <b>④</b>: подчёркнутое «…세금을 대폭 낮춰 준다는 점에서 고무적인 일이다» (резкое снижение налога — обнадёживающе) — автор положительно оценивает саму политику налоговых льгот для новых технологий (критика идёт дальше, не в этой части).<br>✖️ ① про «влияние на структуру отрасли» — не здесь; ② «опасается снижения инвестиций» — нет; ③ критика звучит ПОСЛЕ, в подчёркнутой части её нет.<br>🧩 고무적이다 — обнадёживающий; 긍정적으로 평가하다 — оценивать положительно; 대폭 — значительно; 태도 — отношение."}]
      }
    },
    64: {
      writing: {
        durationMin: 50, label: '제64회 · 쓰기 (51~54)',
        tasks: [{"n":51,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. Прощальная записка коллеге 수미 — формальный стиль -습니다.","passage":"수미 씨, 그동안 고마웠습니다.\n저는 다음 달이면 홍콩으로 일을 ( ㉠ ).\n제가 원하는 회사에 취직을 해서 기쁘지만\n수미 씨를 자주 못 볼 것 같아 아쉽습니다.\n선물을 준비했는데 선물이 수미 씨 마음에 ( ㉡ ).","blanks":[{"slot":"㉠","model":"하러 갑니다 / 하러 가게 되었습니다 / 하러 떠나게 되었습니다","check":"«다음 달이면 … 홍콩으로 일을 ___» + «원하는 회사에 취직을 해서» → переезжает в Гонконг работать. Смысл «еду работать»: (일을) 하러 가다 в будущем. Формальный стиль -습니다, законченное предложение."},{"slot":"㉡","model":"들었으면 좋겠습니다 / 들면 좋겠습니다","check":"«선물을 준비했는데 선물이 … 마음에 ___» → идиома 마음에 들다 (нравиться). Пожелание «надеюсь, понравится»: 마음에 들다 + -았/었으면 좋겠습니다. Стиль -습니다."}]},{"n":52,"points":10,"korInstr":"다음을 읽고 ㉠과 ㉡에 들어갈 말을 각각 한 문장으로 쓰시오. (각 10점)","instr":"Прочитайте и впишите в ㉠ и ㉡ по одному законченному предложению. Научно-популярный текст о свете звёзд — письменный стиль -ㄴ다.","passage":"별은 지구에서 멀리 떨어져 있다. 그래서 별빛이 지구까지 오는 데 많은 시간이 걸린다. 지구와 가장 가까운 별의 빛도 지구까지 오는 데 4억 년이 걸린다. 만약 우리가 이 별을 본다면 우리는 이 별의 현재 모습이 아니라 4억 년 전의 ( ㉠ ). 이처럼 별빛은 오랜 시간이 지나야 지구에 도달한다. 그래서 어떤 별이 사라져도 우리는 그 사실을 바로 알지 못하고 아주 오랜 시간이 ( ㉡ ).","blanks":[{"slot":"㉠","model":"모습을 보는 것이다 / 모습을 보게 되는 것이다","check":"«현재 모습이 아니라 … 전의 ___» → конструкция «A이/가 아니라 B». B = «видим облик звезды 4억 년 назад»: 모습을 보다 + -는 것이다 (констатация). Письменный стиль -ㄴ다."},{"slot":"㉡","model":"지난 후에야 알게 된다 / 지나야 그 사실을 알 수 있다","check":"«아주 오랜 시간이 ___» (подлежащее — 시간이) → 시간이 지나다. Смысл «узнаём лишь спустя долгое время»: 지나다 + -(으)ㄴ 후에야 / -아야 + 알게 되다 / 알 수 있다."}]},{"n":53,"points":30,"min":200,"max":300,"korInstr":"다음을 참고하여 '온라인 쇼핑 시장의 변화'에 대한 글을 200~300자로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)","instr":"Опишите данные «온라인 쇼핑 시장의 변화» (изменение рынка онлайн-шопинга) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.","image":"assets/topik2/exams/img/64-w53.png","model":"온라인 쇼핑 시장은 최근 몇 년 사이에 빠르게 성장하였다. 전체 매출액은 2014년 46조 원에서 2018년 92조 원으로 두 배가 되었다. 사용 기기에 따른 매출액을 보면, 컴퓨터는 같은 기간 32조 원에서 39조 원으로 조금 늘어난 반면, 스마트폰은 14조 원에서 53조 원으로 크게 증가하여 컴퓨터를 앞질렀다. 이러한 변화가 나타난 원인은 온라인으로 다양한 상품을 구매할 수 있게 되었고, 스마트폰을 이용한 쇼핑의 접근성이 컴퓨터보다 높아졌기 때문이다.","check":"① 전체 매출액 46조→92조 (2배)? ② 컴퓨터 32조→39조 (소폭 증가)? ③ 스마트폰 14조→53조 (컴퓨터를 앞지름)? ④ Обе причины (다양한 상품 구매 가능 + 스마트폰 쇼핑 접근성↑)? ⑤ Стиль -ㄴ다, без заголовка, объём 200–300 знаков?"},{"n":54,"points":50,"min":600,"max":700,"korInstr":"다음을 주제로 하여 자신의 생각을 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)","instr":"Эссе 600–700 знаков на тему «청소년기의 중요성» (важность подросткового возраста). Раскройте все три вопроса из задания, каждый — отдельным абзацем.","passage":"사람은 누구나 청소년기를 거쳐 어른이 된다. 아동에서 어른으로 넘어가는 이 시기에 많은 청소년들은 혼란과 방황을 겪으며 성장한다. 아래의 내용을 중심으로 '청소년기의 중요성'에 대한 자신의 생각을 쓰라.\n• 청소년기가 중요한 이유는 무엇인가?\n• 청소년들은 이 시기에 주로 어떤 특징을 보이는가?\n• 청소년의 올바른 성장을 돕기 위해 어떤 노력이 필요한가?","model":"청소년기는 아이가 어른으로 성장해 가는 매우 중요한 시기이다. 이 시기를 어떻게 보내는지에 따라 한 사람의 가치관과 삶의 방향이 크게 달라지기 때문이다. 또한 청소년기에 형성된 생각과 습관은 어른이 된 뒤에도 오랫동안 영향을 미치므로, 이 시기는 인생의 기초를 다지는 때라고 할 수 있다.\n\n이 시기의 청소년들은 여러 가지 특징을 보인다. 우선 자신이 누구인지 찾는 과정에서 혼란과 방황을 겪으며, 부모나 사회가 정한 기준에 반항하기도 한다. 또한 친구 관계를 매우 중요하게 여기고 주변의 시선에 민감하게 반응한다. 감정의 변화가 크고 새로운 것에 대한 호기심이 강하여 다양한 경험을 시도하려는 모습도 자주 나타난다.\n\n청소년이 올바르게 성장하도록 돕기 위해서는 주위의 노력이 필요하다. 먼저 부모와 교사는 청소년을 하나의 인격체로 존중하고 그들의 이야기에 진심으로 귀를 기울여야 한다. 그리고 잘못을 무조건 꾸짖기보다는 스스로 생각하고 선택할 기회를 주어 책임감을 기르도록 해야 한다. 사회적으로도 청소년이 안전하게 다양한 경험을 쌓을 수 있는 환경을 마련해 주어야 한다. 이러한 노력이 함께할 때 청소년은 혼란의 시기를 잘 이겨 내고 건강한 어른으로 성장할 수 있을 것이다.","check":"① Все 3 вопроса раскрыты (почему важен / какие особенности проявляются / какие усилия нужны) — каждый отдельным абзацем? ② Есть вступление и вывод? ③ Связки уровня (우선, 또한, 그리고, 이러한, 따라서)? ④ Стиль -ㄴ다, без разговорных форм? ⑤ Объём 600–700 знаков, задание не переписано дословно?"}]
      },
      listening: {
        durationMin: 60, total: 100, label: '제64회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/64/64th%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/64-l-q1.png","options":["①","②","③","④"],"answer":2,"explain":"🎧 여자: 고객님, 어떤 문제가 있으세요? 남자: 노트북 화면이 안 나와서요. 여자: 네, 언제 구입하셨지요?<br>✅ <b>②</b>: сотрудница сервиса спрашивает, в чём проблема; у мужчины не работает экран ноутбука; она уточняет дату покупки. На ② — стойка обслуживания: сотрудница принимает ноутбук у клиента.<br>✖️ ① оба сидят за ноутбуками; ③ человек у стеллажа с техникой; ④ беседа за столиком — «сдаём ноутбук в ремонт» только на ②.<br>🧩 고객 — клиент; 노트북 — ноутбук; 화면 — экран; 구입하다 — покупать."},{"n":2,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/64-l-q2.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 남자: 공을 잘 들고 앞을 봐. 여자: 이렇게? 그다음에는 어떻게 해? 남자: 천천히 걸어가면서 공을 굴려 봐.<br>✅ <b>①</b>: мужчина учит женщину боулингу — «держи шар, смотри вперёд… иди не спеша и кати шар». На ① он показывает стойку, женщина с шаром готовится бросить.<br>✖️ ② он поправляет ей руки вплотную; ③ оба просто стоят; ④ женщина сидит на полу — обучения броску там нет.<br>🧩 공 — шар, мяч; 굴리다 — катить; 천천히 — медленно; 앞을 보다 — смотреть вперёд."},{"n":3,"points":2,"instr":"Послушайте и выберите подходящий график.","image":"assets/topik2/exams/img/64-l-q3.png","options":["①","②","③","④"],"answer":3,"explain":"🎧 2015년 이후 영화관 관객 수가 계속 감소하고 있다. 줄고 있는 이유로는 '여가 활동이 다양해져서'가 1위, '영화를 모바일로 보는 경우가 늘어서'가 2위, '관람료가 올라서'가 3위.<br>✅ <b>③</b>: вопрос про ПРИЧИНЫ снижения числа зрителей. На ③ места: 1) досуг стал разнообразнее, 2) кино смотрят на мобильном, 3) подорожали билеты — точно как в аудио.<br>✖️ ①② — это графики «число зрителей», а спрашивают причины; ④ — порядок мест перепутан.<br>🧩 관객 수 — число зрителей; 여가 활동 — досуг; 관람료 — цена билета; 감소하다 — снижаться."},{"n":4,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["모임 장소로 오세요.","내일은 갈 수 있어요.","고향에서 친구가 와서요.","못 만날까 봐 걱정했어요."],"answer":3,"explain":"🎧 여자: 저는 내일 모임에 못 갈 것 같아요. 남자: 왜요? 무슨 일이 있어요?<br>✅ <b>③ 고향에서 친구가 와서요</b>: на вопрос «почему не сможешь прийти?» естественно назвать причину — «ко мне приезжает друг из родного города».<br>✖️ ① «приходите на место встречи» — не ответ; ② «завтра смогу» — противоречит «못 갈 것 같아요»; ④ «боялась, что не встретимся» — не причина отсутствия.<br>🧩 모임 — встреча, собрание; 고향 — родной город; 무슨 일 — что случилось; -아/어서요 — причина (вежл.)."},{"n":5,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["아니, 머리는 괜찮아졌어.","응, 내가 약을 사다 줄게.","아니, 문은 안 열었더라고.","응, 늦게까지 하는 약국이 있어."],"answer":4,"explain":"🎧 남자: 약 좀 사 가지고 올게. 머리가 계속 아프네. 여자: 지금 이 시간에도 문을 연 약국이 있을까?<br>✅ <b>④ 응, 늦게까지 하는 약국이 있어</b>: на вопрос «открыта ли аптека в такой час?» логичен ответ «да, есть работающая допоздна».<br>✖️ ① «голова уже прошла» — противоречит «계속 아프네»; ② «я куплю тебе лекарство» — идёт-то ОН; ③ «дверь была закрыта» — он ещё не ходил.<br>🧩 약국 — аптека; 문을 열다 — быть открытым (работать); 늦게까지 — допоздна; 사다 주다 — купить кому-то."},{"n":6,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["그럼 토요일에 보자.","그럼 내가 가서 물어볼게.","연습실은 3층으로 가면 돼.","주말에 연습이 없는 줄 알았어."],"answer":2,"explain":"🎧 여자: 토요일에 3층 연습실 사용할 수 있어? 남자: 아직 관리실에 얘기를 못 해서 잘 모르겠어.<br>✅ <b>② 그럼 내가 가서 물어볼게</b>: раз он ещё не уточнил в управлении, естественно вызваться «тогда я схожу спрошу».<br>✖️ ① «увидимся в субботу» — рано, комната не подтверждена; ③ «практикуйся на 3 этаже» — не отвечает; ④ «думала, на выходных нет занятий» — не в тему.<br>🧩 연습실 — репетиционная; 관리실 — диспетчерская/администрация; 물어보다 — спрашивать; 사용하다 — пользоваться."},{"n":7,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["공사를 하면 깨끗해지겠어요.","공사는 내일부터 시작한대요.","공사를 해서 시끄러운 거예요.","공사가 빨리 끝났으면 좋겠어요."],"answer":4,"explain":"🎧 남자: 공사 소음 때문에 일에 집중이 안 되네요. 여자: 맞아요. 먼지도 심하고요.<br>✅ <b>④ 공사가 빨리 끝났으면 좋겠어요</b>: оба жалуются на шум и пыль от стройки — естественно «хоть бы стройка скорее закончилась».<br>✖️ ① «после стройки станет чисто» — не реакция на жалобу; ② «начнётся завтра» — она уже идёт; ③ «шумно из-за стройки» — лишь повтор, не продолжение.<br>🧩 공사 — стройка, ремонтные работы; 소음 — шум; 집중이 안 되다 — не сосредоточиться; 먼지 — пыль."},{"n":8,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["첫 방송이 정말 기대되네요.","시청자 의견을 못 들었어요.","장면들이 아름다웠다고 해요.","음악에 더 신경을 써야겠네요."],"answer":4,"explain":"🎧 여자: 첫 방송에 대한 시청자 의견은 어때요? 남자: 재미있다는 의견이 많았습니다. 그런데 음악이 장면에 안 어울린다는 의견도 있었습니다.<br>✅ <b>④ 음악에 더 신경을 써야겠네요</b>: раз зрители отметили, что музыка не подходит к сценам, логично «надо уделить музыке больше внимания».<br>✖️ ① «жду первого эфира» — он уже прошёл; ② «не слышала мнений» — она только что их узнала; ③ «сцены были красивы» — не та претензия.<br>🧩 시청자 — зритель; 장면 — сцена, кадр; 어울리다 — подходить, сочетаться; 신경을 쓰다 — уделять внимание."},{"n":9,"points":2,"instr":"Что женщина сделает следующим действием?","options":["꽃을 가져온다.","선물을 고른다.","생일 카드를 쓴다.","민수한테 전화한다."],"answer":3,"explain":"🎧 여자: 선물도 사고 꽃도 준비했고, 케이크는 어떻게 됐어? 남자: 케이크는 민수가 사 온다고 했어. 여자: 그럼 난 생일 카드 좀 쓰고 있어야겠다. 남자: 그래. 난 민수 어디쯤 왔는지 전화해 볼게.<br>✅ <b>③ 생일 카드를 쓴다</b>: подарок и цветы готовы, торт везёт Минсу — женщина говорит «тогда я пока напишу открытку».<br>✖️ ① цветы уже готовы; ② подарок уже куплен; ④ Минсу звонит МУЖЧИНА.<br>🧩 선물 — подарок; 케이크 — торт; 생일 카드 — открытка ко дню рождения; 준비하다 — готовить."},{"n":10,"points":2,"instr":"Что женщина сделает следующим действием?","options":["검사 예약을 한다.","옷을 갈아입으러 간다.","진료 시간을 확인한다.","탈의실 위치를 물어본다."],"answer":2,"explain":"🎧 여자: 오늘 두 시에 진료 예약했는데요. … 남자: 예약 확인되었고요. 검사 전에 옷을 갈아입으셔야 해요. 여자: 그래요? 어디로 가면 되지요? 남자: 오른쪽으로 가시면 탈의실이 있습니다.<br>✅ <b>② 옷을 갈아입으러 간다</b>: запись подтверждена, перед обследованием нужно переодеться; ей указали раздевалку справа → она идёт переодеваться.<br>✖️ ① запись уже сделана; ③ время не уточняет; ④ про местоположение она УЖЕ спросила — дальше именно идёт.<br>🧩 진료 — приём (врача); 검사 — обследование; 갈아입다 — переодеваться; 탈의실 — раздевалка."},{"n":11,"points":2,"instr":"Что женщина сделает следующим действием?","options":["화분에 물을 준다.","화분에 날짜를 붙인다.","화분에 토마토를 심는다.","화분을 베란다로 옮긴다."],"answer":1,"explain":"🎧 남자: 토마토 심은 날짜까지 붙였으니까 이제 다 끝났어. … 남자: 이제 화분을 베란다로 옮겨 놓을 테니까 네가 물을 좀 줘. 여자: 응, 알겠어.<br>✅ <b>① 화분에 물을 준다</b>: мужчина переставит горшок на балкон, а женщину просит полить — она соглашается.<br>✖️ ② дату уже наклеил мужчина; ③ томат уже посажен; ④ горшок переносит МУЖЧИНА.<br>🧩 화분 — горшок; 베란다 — балкон; 옮기다 — переставлять; 물을 주다 — поливать."},{"n":12,"points":2,"instr":"Что женщина сделает следующим действием?","options":["다른 강사를 찾아본다.","박 선생님에게 연락한다.","특강 자료를 정리한다.","연수 프로그램을 알아본다."],"answer":2,"explain":"🎧 남자: 직원 연수 프로그램은 확정됐나요? 여자: 아직 특강해 주실 분을 못 구했는데요. 오늘 박민석 선생님께 연락드려 보려고요. 남자: 그럼 좀 서둘러 주세요. … 여자: 네, 바로 알아보겠습니다.<br>✅ <b>② 박 선생님에게 연락한다</b>: лектор ещё не найден, женщина собирается связаться с г-ном Паком и обещает сделать это сразу.<br>✖️ ① другого лектора ищут лишь ЕСЛИ Пак не сможет; ③ материалы не упомянуты; ④ «узнать про программу» — слишком общо, конкретное действие — звонок Паку.<br>🧩 연수 — обучение; 특강 — спецлекция; 연락하다 — связываться; 서두르다 — торопиться."},{"n":13,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["여자는 심리학과 학생이다.","여자는 수강 신청을 하지 못했다.","남자는 심리학 개론 수업에 만족했다.","남자는 여자와 심리학 개론 수업을 들었다."],"answer":3,"explain":"🎧 여자: 민수야, 너 작년에 심리학 개론 수업 들었지? 남자: 응, 진짜 좋았어. … 남자: 그 수업, 내용도 재밌고 어렵지 않아서 괜찮을 거야.<br>✅ <b>③</b>: мужчина остался доволен курсом «введение в психологию» (진짜 좋았어, 내용도 재밌고).<br>✖️ ① женщина с ДРУГОЙ кафедры (다른 학과 수업이라); ② она УЖЕ записалась (수강 신청은 했는데); ④ мужчина слушал курс в ПРОШЛОМ году, не вместе с ней.<br>🧩 심리학 개론 — введение в психологию; 수강 신청 — запись на курс; 학과 — кафедра; 만족하다 — быть довольным."},{"n":14,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["노래자랑 대회는 오후에 한다.","어울림 축제는 저녁에 시작한다.","올해 처음으로 야시장이 열린다.","수영장은 놀이터 안에 설치됐다."],"answer":1,"explain":"🎧 (объявление) 오후 세 시, 노래자랑 대회를 시작으로 다양한 행사가 준비되어 있으니…<br>✅ <b>①</b>: конкурс песни проходит днём — в 3 часа дня (오후 세 시).<br>✖️ ② про «вечер» не сказано; ③ ночной рынок проводится «작년에 이어 올해도» — не впервые; ④ бассейн ещё только УСТАНОВЯТ рядом с площадкой (놀이터 옆에 … 설치될 예정).<br>🧩 어울림 축제 — фестиваль; 야시장 — ночной рынок; 노래자랑 — конкурс песни; 설치되다 — устанавливаться."},{"n":15,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 열차는 현재 운행 중이다.","이 열차는 인주역에 들어오지 못했다.","이 열차는 지난주에도 정전 사고가 있었다.","이 열차의 정전 사고는 늦은 밤에 발생했다."],"answer":3,"explain":"🎧 (новости) 이 열차는 지난주에도 정전 사고가 한 차례 있었는데요. 현재 운행을 중단하고 정밀 검사를 하고 있습니다.<br>✅ <b>③</b>: у этого поезда и на прошлой неделе уже было отключение питания.<br>✖️ ① сейчас движение ПРИОСТАНОВЛЕНО (운행을 중단); ② поезд встал на 10 минут на станции — он въехал; ④ авария была в 8 утра (오전 8시경), не поздней ночью.<br>🧩 정전 — отключение электричества; 열차 — поезд; 운행 — движение; 중단하다 — приостанавливать."},{"n":16,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["병든 나무에는 직접 약을 처방하지 않는다.","남자는 나무 치료를 시작한 지 얼마 안 됐다.","남자는 나무 치료를 위해 땅의 상태를 조사한다.","나무는 다른 식물에 비해 환경의 영향을 덜 받는다."],"answer":3,"explain":"🎧 남자: 병든 나무의 증상을 살피고, 땅의 상태나 주변 나무들도 조사해요. … 병이 생긴 원인에 따라 주변 환경을 개선하거나 직접 나무에 약을 처방합니다.<br>✅ <b>③</b>: для лечения деревьев мужчина исследует состояние почвы (땅의 상태 … 조사해요).<br>✖️ ① он КАК РАЗ прописывает лекарство прямо дереву (직접 약을 처방); ② лечит деревья ДАВНО (오랫동안); ④ деревья ЧУВСТВИТЕЛЬНЫ к среде, как и другие растения (민감하기 때문).<br>🧩 치료하다 — лечить; 증상 — симптом; 민감하다 — чувствительный; 처방하다 — прописывать."},{"n":17,"points":2,"instr":"Выберите главную мысль мужчины.","options":["운동을 제대로 배워서 하고 싶다.","인터넷의 운동 정보는 도움이 된다.","건강을 위해 꾸준히 운동을 해야 한다.","따라 하기 쉬운 요가 영상을 선택해야 한다."],"answer":1,"explain":"🎧 남자: 아무래도 요가 학원에 다녀야겠어. 혼자서 운동을 하니까 동작이 맞는지 모르겠고 효과도 없는 것 같아. … 영상만으로는 안 될 것 같아. 내 동작이 틀려도 알 수 없잖아.<br>✅ <b>①</b>: мужчина хочет учиться упражнениям как следует (в студии), чтобы знать, правильны ли движения.<br>✖️ ② «онлайн-инфо полезна» — это мысль женщины; ③ «регулярно заниматься ради здоровья» — не то; ④ «выбрать лёгкое видео» — наоборот, видео ему мало.<br>🧩 요가 — йога; 동작 — движение/поза; 효과 — эффект; 제대로 — как следует."},{"n":18,"points":2,"instr":"Выберите главную мысль мужчины.","options":["갈등이 생기면 빨리 해결해야 한다.","자신의 생각을 분명하게 말하면 좋겠다.","상대방이 원하는 것을 먼저 하는 게 좋다.","상대방의 입장을 이해하려면 대화가 필요하다."],"answer":2,"explain":"🎧 남자: 수미야, 왜 아무 말도 안 해? 너도 어디 가고 싶은지 말을 해. … 모두가 만족할 수 있는 결정을 하려면 네 생각도 정확하게 말해 줘야 돼.<br>✅ <b>②</b>: мужчина хочет, чтобы собеседница чётко высказала своё мнение.<br>✖️ ① про конфликт — нет; ③ «делать как хочет другой» — наоборот; ④ «диалог ради понимания» — не фокус.<br>🧩 상관없다 — без разницы; 만족하다 — быть довольным; 분명하게 — чётко; 결정 — решение."},{"n":19,"points":2,"instr":"Выберите главную мысль мужчины.","options":["이 명함은 디자인이 인상적이어서 좋다.","이 명함은 디자인에 더 신경을 써야 한다.","이 명함은 정보를 충분히 넣을 필요가 있다.","이 명함은 명함을 준 사람에 대해 알기 쉽다."],"answer":1,"explain":"🎧 여자: … 명함이라고 하기에는 정보가 좀 부족한 것 같지 않아요? 남자: 디자인 덕분에 이렇게 한 번 더 보게 되니까 전 좋은 것 같아요.<br>✅ <b>①</b>: мужчине визитка нравится — благодаря необычному дизайну на неё смотришь ещё раз.<br>✖️ ② «надо доработать дизайн» — дизайн уже хорош по его мнению; ③ «нужно больше информации» — это претензия ЖЕНЩИНЫ; ④ «легко узнать о владельце» — не его мысль.<br>🧩 명함 — визитка; 특이하다 — необычный; 인상적 — впечатляющий; 정보 — информация."},{"n":20,"points":2,"instr":"Выберите главную мысль мужчины.","options":["기업 행사는 분위기 연출이 가장 어렵다.","기업 행사는 행사의 목적을 고려해야 한다.","기업 행사는 프로그램이 다양할수록 좋다.","기업 행사는 직원들이 만족할 수 있어야 한다."],"answer":2,"explain":"🎧 남자: 행사의 목적이 무엇인지 잘 파악해야 합니다. 신제품 홍보를 위한 행사는 … 분위기를 연출해야 하고요. 송년회같이 직원들을 위한 행사는 친목을 위한 다양한 프로그램이 필요합니다.<br>✅ <b>②</b>: при планировании корпоратива нужно прежде всего учитывать ЦЕЛЬ мероприятия (от неё зависит формат).<br>✖️ ① «создание атмосферы — труднее всего» — не сказано; ③ «чем больше программ, тем лучше» — только для одного типа; ④ «удовлетворить сотрудников» — лишь для части мероприятий.<br>🧩 기업 행사 — корпоративное мероприятие; 목적 — цель; 연출하다 — создавать (атмосферу); 친목 — дружеское общение."},{"n":21,"points":2,"instr":"Выберите главную мысль мужчины.","options":["여행객들의 성향을 조사해야 한다.","고객 만족도를 높이는 것이 우선이다.","이용 후기를 늘릴 수 있도록 해야 한다.","후기 분석을 적극적으로 할 필요가 있다."],"answer":3,"explain":"🎧 남자: 여행객들이 호텔을 선택할 때 가장 많이 보는 게 이용 후기라고 해요. … 고객들에게 후기 작성에 대해 적극적으로 알려야 할 것 같아요. 후기를 많이 남길 수 있도록 하는 이벤트도 해 보고요.<br>✅ <b>③</b>: путешественники выбирают отель по отзывам, поэтому нужно добиться роста числа отзывов (поощрять их написание, проводить акции).<br>✖️ ① «изучать склонности туристов» — нет; ② «повышать удовлетворённость» — у них она уже высокая; ④ «анализировать отзывы» — речь об их КОЛИЧЕСТВЕ.<br>🧩 이용 후기 — отзыв; 고객 만족도 — удовлетворённость клиентов; 작성 — написание; 적극적 — активный."},{"n":22,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 호텔에서는 후기 작성 이벤트를 하고 있다.","남자는 호텔과 관련된 자료를 조사할 예정이다.","이 호텔을 이용한 고객들은 후기를 많이 남겼다.","여자가 일하는 호텔은 고객 만족도가 높은 편이다."],"answer":4,"explain":"🎧 여자: 우리 호텔은 고객 만족도는 높은 데 비해 이용 후기는 적은 편이잖아요.<br>✅ <b>④</b>: у отеля, где работает женщина, удовлетворённость клиентов высокая.<br>✖️ ① акция с отзывами только ПЛАНИРУЕТСЯ (해 보고요); ② мужчина ссылается на УЖЕ имеющиеся данные опроса; ③ отзывов у отеля как раз МАЛО (후기는 적은 편).<br>🧩 만족도 — удовлетворённость; 후기 — отзыв; 남기다 — оставлять; 적극적으로 — активно."},{"n":23,"points":2,"instr":"Что делает женщина (с какой целью говорит)?","options":["면허증 재발급 방법을 문의하고 있다.","면허증 재발급 기간을 확인하고 있다.","면허 시험장의 위치를 알아보고 있다.","면허증 발급에 필요한 서류를 요청하고 있다."],"answer":1,"explain":"🎧 여자: 제가 운전면허증을 잃어버려서 다시 발급을 받고 싶은데요. 어떻게 하면 되나요?<br>✅ <b>①</b>: женщина потеряла права и спрашивает, КАК их переоформить.<br>✖️ ② про срок она уточняет лишь попутно; ③ адрес автодрома не выясняет (он ей далеко); ④ перечень документов не запрашивает.<br>🧩 운전면허증 — водительские права; 재발급 — переоформление; 문의하다 — справляться; 신분증 — удостоверение."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["경찰서에서도 면허증을 받을 수 있다.","여자는 인터넷으로 신청서를 제출했다.","여자는 면허 시험장에서 가까운 곳에 있다.","인터넷을 이용하면 당일에 면허증 발급이 가능하다."],"answer":1,"explain":"🎧 남자: 인터넷으로도 가능합니다. 신청하실 때 가까운 경찰서를 지정해서 면허증을 받으시면 돼요.<br>✅ <b>①</b>: права можно получить и в полицейском участке (가까운 경찰서를 지정해서 받으시면).<br>✖️ ② она лишь СПРАШИВАЕТ, заявку не подавала; ③ автодром ей ДАЛЕКО (너무 멀어서요); ④ онлайн занимает ~2 недели (두 주 정도), в тот же день — только на автодроме.<br>🧩 경찰서 — полицейский участок; 신청서 — заявление; 발급 — выдача; 당일 — тот же день."},{"n":25,"points":2,"instr":"Выберите главную мысль мужчины.","options":["소방관의 근무 환경을 개선해야 한다.","사람들이 소방관에 대해 관심을 가지면 좋겠다.","사람들은 소방관의 희생정신을 본받아야 한다.","소방관의 안전을 보장하기 위한 대책이 필요하다."],"answer":2,"explain":"🎧 남자: 소방관들이 시민을 위해 얼마나 힘든 환경에서 일하고 있는지를 알리고 싶었어요. … 저희의 작은 노력이 소방관의 어려움을 한 번 더 떠올리는 계기가 되었으면 좋겠습니다.<br>✅ <b>②</b>: парень надеется, что благодаря их затее люди обратят внимание на пожарных и их трудности.<br>✖️ ① «улучшить условия труда» — не призыв; ③ «брать пример с самопожертвования» — нет; ④ «меры по безопасности пожарных» — нет.<br>🧩 소방복 — форма пожарного; 재활용 — переработка; 소방관 — пожарный; 관심을 가지다 — проявлять интерес."},{"n":26,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["남자는 소방관으로 일하고 있다.","이 가방은 사람들에게 판매되지 않는다.","이 가방은 소방복을 재활용해 만든 것이다.","남자가 만든 가방은 아직 알려지지 않았다."],"answer":3,"explain":"🎧 남자: 버려진 소방복을 재활용해 가방을 만들게 되었습니다. … 가방을 판매한 수익금을 소방관의 활동을 알리는 데에 사용하고 있습니다.<br>✅ <b>③</b>: сумку сделали из переработанной (списанной) формы пожарных.<br>✖️ ① мужчина — СТУДЕНТ, а не пожарный; ② сумки ПРОДАЮТСЯ (판매한 수익금); ④ сумки СТАЛИ темой обсуждения (화제가 된) — они известны.<br>🧩 재활용하다 — перерабатывать; 판매되다 — продаваться; 화제가 되다 — стать на слуху; 수익금 — выручка."},{"n":27,"points":2,"instr":"С какой целью мужчина это говорит?","options":["남성 육아의 필요성을 일깨우기 위해","남성 육아를 위한 제도를 설명하기 위해","남성 육아의 문제점에 대해 지적하기 위해","남성 육아에 대한 인식 변화를 말하기 위해"],"answer":4,"explain":"🎧 남자: 요즘 우리 회사 남자 직원들 중에 육아 휴직을 신청하는 사람들이 점점 많아지고 있어요. … 제 생각엔 남성 육아를 긍정적으로 보는 시각이 많아진 게 큰 이유인 것 같아요.<br>✅ <b>④</b>: мужчина говорит об ИЗМЕНЕНИИ восприятия мужского ухода за детьми (всё больше отцов берут отпуск, общество смотрит позитивно).<br>✖️ ① «пробудить необходимость» — нет; ② «объяснить систему» — лишь упоминается; ③ «указать на проблемы» — наоборот, говорит о позитиве.<br>🧩 육아 휴직 — отпуск по уходу за ребёнком; 인식 — восприятие; 권장하다 — поощрять; 시각 — взгляд."},{"n":28,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["남자의 회사에는 육아 휴직 신청자가 없다.","육아 휴직을 해도 경력을 인정받을 수 있다.","육아 휴직 기간에는 월급이 지급되지 않는다.","정부에서는 육아 휴직 제도의 시행을 준비하고 있다."],"answer":2,"explain":"🎧 여자: 제도가 바뀌면서 휴직 기간 동안 월급도 주고 경력 인정도 되니까 …<br>✅ <b>②</b>: даже взяв отпуск по уходу, можно сохранить (получить признание) трудового стажа (경력 인정도 되니까).<br>✖️ ① заявителей всё БОЛЬШЕ (없다 — неверно); ③ зарплата ВЫПЛАЧИВАЕТСЯ (월급도 주고); ④ система уже изменилась и действует, а не «готовится к внедрению».<br>🧩 경력 — стаж, опыт; 인정받다 — получать признание; 월급 — зарплата; 시행 — введение в действие."},{"n":29,"points":2,"instr":"Кто такая женщина (чем она занимается)?","options":["전자책을 조사하는 사람","전자책을 골라 주는 사람","전자책 구독 서비스에 가입한 사람","전자책 구독 서비스를 개발한 사람"],"answer":4,"explain":"🎧 남자: 사장님께서 만든 전자책 구독 서비스의 인기 비결이 뭐라고 생각하세요? 여자: 독서를 위한 다양한 서비스를 제공한다는 점이겠죠. …<br>✅ <b>④</b>: к ней обращаются как к «사장님», создавшей сервис подписки на электронные книги → она его разработчик/основатель.<br>✖️ ① «исследует э-книги» — нет; ② «подбирает книги» — нет; ③ «подписчик сервиса» — она его создала, а не просто пользуется.<br>🧩 전자책 — электронная книга; 구독 — подписка; 개발하다 — разрабатывать; 비결 — секрет."},{"n":30,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 서비스는 무료로 이용이 가능하다.","이 서비스는 아직 이용자가 많지 않다.","이 서비스는 책에 대한 해설도 제공한다.","이 서비스는 동영상 기능을 추가할 예정이다."],"answer":3,"explain":"🎧 여자: 어려운 책은 전문가의 해설을 들으면서 읽거나 요약본으로 볼 수도 있어요.<br>✅ <b>③</b>: сервис даёт и пояснения экспертов к книгам (전문가의 해설).<br>✖️ ① платно — ежемесячная плата (매달 이용료를 내면); ② речь о «секрете популярности» — пользователей много; ④ видео-функцию УЖЕ добавили (추가하셨다고요), не «планируют».<br>🧩 해설 — пояснение, комментарий; 이용료 — плата за пользование; 음성 지원 — голосовое сопровождение; 추가하다 — добавлять."},{"n":31,"points":2,"instr":"Выберите мысль мужчины.","options":["창업 사전 교육을 강화해야 한다.","학생들이 창업을 직접 해 보게 해야 한다.","학생들에게 창업 지원 사업을 홍보해야 한다.","창업 지원 사업의 시행 기간을 연장해야 한다."],"answer":2,"explain":"🎧 남자: 사전 교육과 함께 창업 지원금을 늘려서 더 많은 학생들이 실제로 창업을 해 보게 하는 건 어떨까요? … 직접 부딪혀 봐야 배울 수 있는 것도 있잖아요.<br>✅ <b>②</b>: мужчина за то, чтобы студенты пробовали открывать дело НА ПРАКТИКЕ.<br>✖️ ① «усилить предварительное обучение» — позиция женщины; ③ «рекламировать программу» — нет; ④ «продлить срок программы» — нет.<br>🧩 창업 — открытие бизнеса; 지원금 — субсидия; 사전 교육 — предварительное обучение; 부딪히다 — сталкиваться (на деле)."},{"n":32,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["사업의 효과를 회의적으로 바라보고 있다.","사례를 들어 상대방의 주장을 반박하고 있다.","상황을 분석하면서 발생할 문제를 염려하고 있다.","상대의 의견을 일부 인정하며 다른 주장을 하고 있다."],"answer":4,"explain":"🎧 (те же дебаты) мужчина соглашается с предварительным обучением («사전 교육과 함께…»), но добавляет, что студентам надо пробовать самим.<br>✅ <b>④</b>: частично признаёт мнение собеседницы и выдвигает своё, отличное.<br>✖️ ① «скептичен к эффекту» — нет; ② «опровергает примерами» — прямо не опровергает; ③ «анализирует и тревожится о проблемах» — это позиция женщины.<br>🧩 인정하다 — признавать; 주장 — довод; 반박하다 — опровергать; 염려하다 — опасаться."},{"n":33,"points":2,"instr":"О чём этот рассказ?","options":["질소의 활용 방법","질소의 생성 원리","비행기 타이어의 특징","비행기 타이어의 종류"],"answer":3,"explain":"🎧 여자: 비행기 타이어에는 산소가 혼합되지 않은 질소만을 주입합니다. … 비행기 타이어에는 단순한 세로 줄무늬를 사용하여 지면과의 마찰을 줄이고 착륙 시 발생하는 열을 최소화해 줍니다.<br>✅ <b>③</b>: тема — особенности авиашин (накачивают азотом, простой продольный протектор ради снижения трения и тепла).<br>✖️ ① «как применять азот» — частность; ② «как образуется азот» — нет; ④ «виды авиашин» — не классификация.<br>🧩 비행기 — самолёт; 타이어 — шина; 마찰 — трение; 질소 — азот; 산소 — кислород."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["질소는 자동차 타이어에 주로 사용된다.","비행기 타이어에는 복잡한 무늬를 새긴다.","단순한 무늬의 타이어는 잘 미끄러지지 않는다.","질소만 주입한 타이어는 폭발 위험이 줄어든다."],"answer":4,"explain":"🎧 여자: 공기에 포함된 산소가 자칫 폭발을 유도할 위험이 있습니다. 그래서 … 질소만을 주입합니다.<br>✅ <b>④</b>: шина, накачанная только азотом (без кислорода), имеет меньший риск взрыва.<br>✖️ ① азот — для АВИАшин (в авто — воздух); ② у авиашин ПРОСТОЙ продольный рисунок (단순한 세로 줄무늬); ③ от проскальзывания защищает СЛОЖНЫЙ протектор, а не простой.<br>🧩 질소 — азот; 주입하다 — накачивать; 폭발 — взрыв; 무늬 — узор, протектор."},{"n":35,"points":2,"instr":"Что делает мужчина (с какой целью говорит)?","options":["선배의 업적을 소개하고 있다.","선배의 영화를 홍보하고 있다.","선배가 만든 작품을 설명하고 있다.","선배에 대한 지지를 부탁하고 있다."],"answer":1,"explain":"🎧 남자: 아역 배우로 영화 인생을 시작해서 … 배우로서 백여 편의 영화에 출연 … 53세에는 감독으로서 첫 작품을 발표 … 감독상을 수상 … 영화 박물관의 대표로서 한국 영화의 역사를 기록하는 일에도 힘을 써 온 …<br>✅ <b>①</b>: мужчина в речи памяти перечисляет ЗАСЛУГИ ушедшего наставника (актёр, режиссёр, призёр, директор музея кино).<br>✖️ ② «рекламирует фильмы» — это дань памяти; ③ «объясняет его работы» — слишком узко; ④ «просит поддержки» — нет.<br>🧩 아역 배우 — актёр-ребёнок; 감독 — режиссёр; 업적 — заслуги, достижения; 소개하다 — представлять."},{"n":36,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["김민수는 배우이자 감독으로 활약했다.","김민수는 늦은 나이에 배우로 데뷔했다.","김민수는 백여 편이 넘는 영화를 연출했다.","김민수는 국제 영화제에서 상을 받지 못했다."],"answer":1,"explain":"🎧 남자: 배우로서 백여 편의 영화에 출연 … 53세에는 감독으로서 첫 작품을 발표하고 …<br>✅ <b>①</b>: Ким Минсу проявил себя и как актёр, и как режиссёр.<br>✖️ ② дебютировал ДЕТСКИМ актёром (아역 배우로 시작), не поздно; ③ СНЯЛ как режиссёр всего 4 фильма (первый + ещё 3), а в 100+ фильмах он СНИМАЛСЯ; ④ он ПОЛУЧИЛ приз за режиссуру на междунар. фестивале (감독상을 수상).<br>🧩 활약하다 — активно действовать; 데뷔하다 — дебютировать; 연출하다 — режиссировать; 수상하다 — получать награду."},{"n":37,"points":2,"instr":"Выберите главную мысль женщины.","options":["잇몸병의 원인을 명확하게 밝혀야 한다.","젊을 때부터 잇몸 관리에 신경을 써야 한다.","치매 예방을 위해서 잇몸 관리가 중요하다.","잇몸병에 대한 잘못된 정보를 바로잡아야 한다."],"answer":2,"explain":"🎧 여자: 손상된 잇몸은 원래대로 회복되지 않습니다. … 세균이 … 다른 신체 기관에 악영향을 … 건강할 때부터 잇몸을 잘 관리하는 것이 좋습니다.<br>✅ <b>②</b>: дёсны не восстанавливаются, поэтому заботиться о них нужно смолоду.<br>✖️ ① «выяснить причины» — не призыв; ③ профилактика деменции — лишь один из доводов; ④ «исправить ложную информацию» — нет.<br>🧩 잇몸병 — болезнь дёсен; 충치 — кариес; 세균 — бактерии; 관리하다 — следить, ухаживать."},{"n":38,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["잇몸은 손상되더라도 빠르게 회복된다.","잇몸병 환자의 절반 이상이 젊은 사람들이다.","젊은 층의 잇몸병 환자가 줄고 있는 추세이다.","잇몸병을 일으키는 세균은 다른 질환도 유발할 수 있다."],"answer":4,"explain":"🎧 여자: 잇몸병이 원인이 되는 세균이 혈관을 돌아다니며 … 심장병이나 치매를 유발할 수도 있어요.<br>✅ <b>④</b>: бактерии, вызывающие болезнь дёсен, могут провоцировать и другие заболевания (болезни сердца, деменцию).<br>✖️ ① повреждённые дёсны НЕ восстанавливаются (회복되지 않습니다); ② молодые — ТРЕТЬ пациентов (3분의 1), не больше половины; ③ молодых пациентов всё БОЛЬШЕ (60% 증가), не меньше.<br>🧩 손상되다 — повреждаться; 회복되다 — восстанавливаться; 질환 — заболевание; 유발하다 — провоцировать."},{"n":39,"points":2,"instr":"Что было сказано ДО этого разговора?","options":["민간 주도로 문화재 환수가 이루어지고 있다.","해외에 있는 문화재를 대여해서 전시하고 있다.","환수하지 못하고 해외에 남아 있는 문화재가 많다.","문화재 환수를 위해 다른 나라와 협정을 체결했다."],"answer":3,"explain":"🎧 여자: 국외로 유출된 문화재가 이렇게 많은데, 어떤 방법으로 이런 문화재들을 다시 본국으로 가져올 수 있을까요?<br>✅ <b>③</b>: «이렇게 많은데» («их так много») отсылает к ранее сказанному — что за рубежом остаётся много невозвращённых культурных ценностей.<br>✖️ ① про «частную инициативу» — нет; ② про «выставки по аренде» — это дальше в ответе; ④ про «заключённое соглашение» — нет.<br>🧩 문화재 — культурное достояние; 환수 — возврат; 유출되다 — утекать за рубеж; 본국 — родина."},{"n":40,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["각국의 법이 달라 문화재의 영구적 환수가 어렵다.","1970년대부터 문화재 환수가 활발해지기 시작했다.","문화재 환수는 주로 기증하는 방식으로 이루어진다.","문화재 환수와 관련된 국제 협약은 존재하지 않는다."],"answer":1,"explain":"🎧 남자: 기증을 통한 영구적 환수가 바람직하겠지만 나라마다 문화재 보호에 관한 법이 서로 달라서 이것이 쉽게 이루어지지는 않습니다.<br>✅ <b>①</b>: из-за различий в законах разных стран ПОСТОЯННЫЙ (окончательный) возврат труден.<br>✖️ ② интерес вырос с КОНЦА 1990-х (1970 — это год международной конвенции); ③ возврат идёт в основном через АРЕНДУ/временно (대여 … 일시적 환수), а дарение лишь желательно; ④ международная конвенция СУЩЕСТВУЕТ (1970년에 마련).<br>🧩 영구적 — постоянный; 기증 — дарение, передача; 대여 — аренда; 협약 — конвенция, соглашение."},{"n":41,"points":2,"instr":"О чём в основном эта лекция?","options":["감칠맛에 대한 연구가 새로이 시작되었다.","새로운 미각으로 깊은맛이 주목을 받고 있다.","한식의 조리 과정에서는 발효가 가장 중요하다.","음식의 풍미를 높이는 다양한 방법이 개발되었다."],"answer":2,"explain":"🎧 여자: 과학자들은 … '감칠맛'을 다섯 번째 미각으로 인정했습니다. 이제 과학자들은 여섯 번째 미각에 관심을 … '깊은맛'이 유력한 후보로 거론되고 있습니다.<br>✅ <b>②</b>: умами признан 5-м вкусом, а теперь как кандидат на 6-й вкус привлекает внимание «깊은맛» (глубокий вкус).<br>✖️ ① «исследование умами началось заново» — нет; ③ «брожение важнее всего в корейской кухне» — частность; ④ «разработаны способы усиления вкуса» — не суть.<br>🧩 미각 — вкус (чувство); 감칠맛 — умами; 깊은맛 — глубокий вкус; 발효 — ферментация."},{"n":42,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["감칠맛은 다른 맛과 결합해 풍미를 높인다.","감칠맛은 미각으로 인정을 받지 못하고 있다.","깊은맛은 식욕을 당기게 해 주는 특징이 있다.","깊은맛은 식재료를 오래 끓여서 낼 수 있는 맛이다."],"answer":4,"explain":"🎧 여자: '깊은맛'은 식재료를 오래 끓이거나 숙성, 발효시키는 과정에서 우러나는 맛인데요.<br>✅ <b>④</b>: «깊은맛» — вкус, который проявляется при долгой варке (выдержке, ферментации) ингредиентов.<br>✖️ ① усиливает вкус в сочетании именно «깊은맛», а не умами; ② умами КАК РАЗ признан 5-м вкусом; ③ возбуждает аппетит УМАМИ (감칠맛), а не «깊은맛».<br>🧩 끓이다 — варить, кипятить; 숙성 — выдержка; 우러나다 — настаиваться (о вкусе); 식욕 — аппетит."},{"n":43,"points":2,"instr":"О чём этот рассказ?","options":["황갈색우럭상어가 해양 생태계를 변화시키고 있다.","황갈색우럭상어의 서식 공간이 점점 좁아지고 있다.","황갈색우럭상어의 자궁은 인간의 자궁과 형태가 유사하다.","황갈색우럭상어의 새끼는 자궁 속에서 세상에 나올 준비를 한다."],"answer":4,"explain":"🎧 남자: 탯줄이 없어 움직임이 자유로운 새끼 상어는 이 알들을 찾아다니며 먹는다. … 헤엄치는 법과 먹이 찾는 법을 함께 익히고 있는 셈이다. 세상을 살아갈 만반의 준비를 모두 마친 후 … 자궁 밖으로 나온다.<br>✅ <b>④</b>: детёныш акулы в утробе ест яйца, учится плавать и искать корм — готовится к выходу в мир.<br>✖️ ① «меняет морскую экосистему» — нет; ② «ареал сужается» — нет; ③ «матка похожа на человеческую» — не тема (про 10 месяцев лишь сравнение срока).<br>🧩 새끼 — детёныш; 상어 — акула; 자궁 — утроба; 무정란 — неоплодотворённое яйцо; 익히다 — осваивать."},{"n":44,"points":2,"instr":"Почему детёныш акулы ест в утробе неоплодотворённые яйца?","options":["공간을 넓히기 위해서","영양분을 얻기 위해서","수분을 배출하기 위해서","움직임을 줄이기 위해서"],"answer":2,"explain":"🎧 남자: 영양분을 공급받아야 할 탯줄이 보이지 않는다. … 어미 상어는 … 무정란을 자궁 속에 가지고 있다. … 새끼 상어는 이 알들을 찾아다니며 먹는다.<br>✅ <b>② 영양분을 얻기 위해서</b>: пуповины нет, поэтому детёныш питается яйцами, чтобы получать питательные вещества.<br>✖️ ① «расширить пространство» — нет; ③ «вывести влагу» — нет; ④ «уменьшить движение» — наоборот, он свободно плавает.<br>🧩 영양분 — питательные вещества; 탯줄 — пуповина; 섭취하다 — усваивать; 공급받다 — получать (снабжение)."},{"n":45,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["색소폰은 다른 악기와의 합주에 적합했다.","색소폰은 19세기부터 활발하게 사용되었다.","색소폰은 재즈 덕분에 인기를 얻기 시작했다.","색소폰의 음색은 편안하고 안정된 느낌을 준다."],"answer":3,"explain":"🎧 여자: 색소폰이 인기를 얻기 시작한 건 20세기 들어 불기 시작한 재즈 열풍 덕분이었는데요.<br>✅ <b>③</b>: саксофон начал набирать популярность благодаря джазовому буму.<br>✖️ ① для ансамбля его тембр слишком ВЫДЕЛЯЛСЯ (조화 이루기 어려움); ② в 19 веке его как раз НЕ приняли; ④ его звук «흔들리듯 불안하게» (неустойчивый), а не спокойный.<br>🧩 색소폰 — саксофон; 음색 — тембр; 재즈 — джаз; 합주 — ансамбль, совместная игра."},{"n":46,"points":2,"instr":"Каким образом женщина подаёт материал?","options":["색소폰의 위상 변화를 설명하고 있다.","색소폰의 연주 방법을 비교하고 있다.","색소폰의 발명 과정을 요약하고 있다.","색소폰의 세부 형태를 묘사하고 있다."],"answer":1,"explain":"🎧 여자: … 당시 음악계에서 별로 환영을 받지 못했습니다. … 재즈 열풍 덕분에 … 독특한 음색으로 인정받게 된 것이죠.<br>✅ <b>①</b>: женщина объясняет ИЗМЕНЕНИЕ статуса саксофона — от непринятого инструмента до признанного благодаря джазу.<br>✖️ ② способы игры не сравнивает; ③ «процесс изобретения» — лишь упомянут; ④ детальную форму не описывает.<br>🧩 위상 — статус, положение; 변화 — изменение; 환영받다 — быть принятым; 인정받다 — получать признание."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 제도는 곧 시행될 예정이다.","이 제도는 신속한 구조를 위해 마련되었다.","이 제도는 국민 대상 홍보가 잘 이루어졌다.","이 제도는 예산 지원이 원활하게 진행되고 있다."],"answer":2,"explain":"🎧 남자: 이 제도는 2013년부터 신속한 구조를 목적으로 시행이 되었는데요.<br>✅ <b>②</b>: система создана ради БЫСТРОГО СПАСЕНИЯ (신속한 구조를 목적으로).<br>✖️ ① она УЖЕ действует с 2013 года; ③ она плохо известна (잘 알려지지도 않았습니다); ④ бюджета НЕ хватает (예산 부족을 핑계로).<br>🧩 국가지점번호 — система координатных номеров; 조난 — бедствие; 신속한 구조 — быстрое спасение; 시행 — введение."},{"n":48,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["제도에 대한 평가를 유보하고 있다.","제도의 긍정적인 효과를 기대하고 있다.","제도 시행을 위한 국민의 협조를 당부하고 있다.","제도 시행의 문제를 지적하며 시정을 촉구하고 있다."],"answer":4,"explain":"🎧 남자: 아직까지도 표지판이 설치되지 않은 지역이 많고 … 지방자치단체들이 … 예산 부족을 핑계로 설치를 미루고 있기 때문인데요. … 적극적인 노력이 있어야 하겠습니다.<br>✅ <b>④</b>: мужчина указывает на проблемы внедрения (знаки не установлены, муниципалитеты тянут) и призывает исправить.<br>✖️ ① оценку он не откладывает — он критичен; ② позитива не ждёт; ③ призывает не граждан, а МУНИЦИПАЛИТЕТЫ.<br>🧩 시정 — исправление; 촉구하다 — настойчиво призывать; 지방자치단체 — орган местного самоуправления; 미루다 — откладывать."},{"n":49,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 책은 왕의 업무 내용을 담고 있다.","이 책은 신하들에게 공개되지 않았다.","이 책은 백성의 관점에서 작성되었다.","이 책은 조선 시대 이전에 기록되었다."],"answer":1,"explain":"🎧 여자: … 왕의 소소한 일상에서부터 국정 업무 전반을 왕이 시점으로 기록한 것인데요.<br>✅ <b>①</b>: книга содержит и государственные дела короля (국정 업무 전반을 기록).<br>✖️ ② её ОТКРЫВАЛИ министрам (신하들이 볼 수 있게 하여); ③ написана с точки зрения КОРОЛЯ (왕이 시점으로), а не народа; ④ это ПОЗДНИЙ Чосон (조선 후기), не до эпохи Чосон.<br>🧩 일성록 — «Ильсонрок» (дневник королей); 국정 — государственные дела; 신하 — придворный; 시점 — точка зрения."},{"n":50,"points":2,"instr":"Выберите позицию (отношение) женщины.","options":["기록물의 가치를 높이 평가하고 있다.","기록물의 활용 방안을 강구하고 있다.","기록물에 대한 맹신을 경계하고 있다.","기록물의 훼손 가능성을 우려하고 있다."],"answer":1,"explain":"🎧 여자: '일성록'은 단순한 일기를 넘어 한국뿐만 아니라 세계 역사에도 매우 중요한 사료로 인정받고 있습니다.<br>✅ <b>①</b>: женщина высоко оценивает ценность памятника — это не просто дневник, а важный исторический источник.<br>✖️ ② способы использования не разрабатывает; ③ от слепой веры не предостерегает; ④ об угрозе порчи не тревожится.<br>🧩 기록물 — документальное наследие; 가치 — ценность; 높이 평가하다 — высоко оценивать; 사료 — исторический источник."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제64회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"나는 주말에는 보통 영화를 (        ) 운동을 한다.","options":["보지만","보거나","보려고","보더니"],"answer":2,"explain":"✅ <b>② 보거나</b>: «по выходным я обычно смотрю кино ИЛИ занимаюсь спортом» — выбор между действиями → -거나.<br>✖️ ① 보지만 — «хотя смотрю, но»; ③ 보려고 — «чтобы посмотреть»; ④ 보더니 — «смотрел(а), и (вдруг)…».<br>🧩 V-거나 — «или» (между действиями); 주말 — выходные; 보통 — обычно."},{"n":2,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"동생이 점점 아버지를 (        ).","options":["닮아 간다","닮기도 한다","닮았나 보다","닮은 적이 없다"],"answer":1,"explain":"✅ <b>① 닮아 간다</b>: «점점» (постепенно) + -아 가다 (нарастающее изменение) → младший брат/сестра всё больше становится похож(а) на отца.<br>✖️ ② 닮기도 한다 — «бывает, что похож»; ③ 닮았나 보다 — «кажется, похож»; ④ 닮은 적이 없다 — «никогда не был похож».<br>🧩 닮다 — быть похожим; V-아/어 가다 — постепенное изменение; 점점 — постепенно."},{"n":3,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"정부는 일자리를 <u>늘리고자</u> 새로운 정책을 수립했다.","options":["늘려서야","늘리더라도","늘리는 대신","늘리기 위해"],"answer":4,"explain":"✅ <b>④ 늘리기 위해</b>: -고자 выражает цель = «чтобы увеличить» = -기 위해.<br>✖️ ① 늘려서야 — «лишь увеличив»; ② 늘리더라도 — «даже если увеличить»; ③ 늘리는 대신 — «вместо увеличения».<br>🧩 V-고자 = V-기 위해 — «с целью, чтобы»; 일자리 — рабочие места; 정책을 수립하다 — разработать политику."},{"n":4,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"태어난 지 얼마 안 되어 서울로 왔으니 서울이 <u>고향인 셈이다</u>.","options":["고향일 뿐이다","고향이면 좋겠다","고향일 리가 없다","고향이나 마찬가지이다"],"answer":4,"explain":"✅ <b>④ 고향이나 마찬가지이다</b>: -(으)ㄴ 셈이다 «практически, всё равно что» = «(이)나 마찬가지이다». Привезли в Сеул вскоре после рождения — он фактически и есть родина.<br>✖️ ① 고향일 뿐이다 — «всего лишь родина»; ② 고향이면 좋겠다 — «хотелось бы, чтобы была родиной»; ③ 고향일 리가 없다 — «не может быть родиной».<br>🧩 N인 셈이다 — «можно считать N»; N(이)나 마찬가지이다 — «всё равно что N»; 고향 — родина."},{"n":5,"points":2,"instr":"О чём этот текст?","passage":"더위를 싹~\n자연 바람을 선물합니다.","options":["에어컨","청소기","냉장고","세탁기"],"answer":1,"explain":"✅ <b>① 에어컨</b> (кондиционер): «прогоним жару, дарим естественный ветерок» — это про кондиционер.<br>✖️ ② 청소기 — пылесос; ③ 냉장고 — холодильник; ④ 세탁기 — стиральная машина.<br>🧩 더위 — жара; 바람 — ветер; 선물하다 — дарить; 싹 — начисто, полностью."},{"n":6,"points":2,"instr":"О чём этот текст?","passage":"똑똑하게 모으자!\n매일매일 쌓여 가는 행복한 미래","options":["병원","은행","여행사","체육관"],"answer":2,"explain":"✅ <b>② 은행</b> (банк): «копи с умом, день за днём растёт счастливое будущее» — про накопления, банк.<br>✖️ ① 병원 — больница; ③ 여행사 — турагентство; ④ 체육관 — спортзал.<br>🧩 모으다 — копить; 쌓이다 — накапливаться; 미래 — будущее."},{"n":7,"points":2,"instr":"О чём этот текст?","passage":"추억은 마음속에, 쓰레기는 가방 안에\n건강한 산, 함께 만들어요.","options":["건강 관리","화재 예방","이웃 사랑","환경 보호"],"answer":4,"explain":"✅ <b>④ 환경 보호</b> (защита природы): «воспоминания — в сердце, мусор — в сумку; сделаем горы здоровыми вместе» — призыв не мусорить на природе.<br>✖️ ① 건강 관리 — забота о здоровье; ② 화재 예방 — профилактика пожаров; ③ 이웃 사랑 — любовь к ближнему.<br>🧩 추억 — воспоминания; 쓰레기 — мусор; 환경 보호 — охрана природы."},{"n":8,"points":2,"instr":"О чём этот текст?","passage":"· 자료실은 평일 오전 9시부터 오후 6시까지 문을 엽니다.\n· 책은 1인당 10권, 한 달 동안 빌릴 수 있습니다.","options":["이용 안내","구입 문의","사용 순서","교환 방법"],"answer":1,"explain":"✅ <b>① 이용 안내</b> (правила пользования): часы работы читального зала и условия выдачи книг — это руководство по пользованию.<br>✖️ ② 구입 문의 — вопросы покупки; ③ 사용 순서 — порядок использования; ④ 교환 방법 — способ обмена.<br>🧩 자료실 — читальный зал; 평일 — будни; 빌리다 — брать на время; 이용 — пользование."},{"n":9,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с объявлением.","passage":"🚶 제3회 한마음 걷기 대회\n● 일 시: 2019년 9월 14일(토) 09:00~13:00\n● 참가 대상: 제한 없음\n● 내 용: 3.8km 걷기 (시민공원부터 인주기념관까지)\n● 참 가 비: 무료","options":["이 대회는 이번에 처음으로 열린다.","이 대회에는 누구나 참가할 수 있다.","이 대회에 참가하려면 돈을 내야 한다.","이 대회의 출발 장소는 인주기념관이다."],"answer":2,"explain":"✅ <b>②</b>: «참가 대상: 제한 없음» — участвовать может любой.<br>✖️ ① это уже 3-е мероприятие (제3회), не первое; ③ участие бесплатное (참가비: 무료); ④ старт у Гражданского парка (시민공원부터), а 인주기념관 — финиш.<br>🧩 대회 — мероприятие, состязание; 제한 없음 — без ограничений; 참가비 — взнос; 무료 — бесплатно."},{"n":10,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с графиком.","passage":"📊 고등학생 희망 직업, 어떻게 달라졌을까? (고등학생 10,000명)\n2008년: 1위 교사 · 2위 회사원 · 3위 공무원 · 4위 간호사 · 5위 개인 사업\n2018년: 1위 교사 · 2위 간호사 · 3위 건축가 · 4위 공무원 · 5위 군인","options":["1위 순위의 직업이 바뀌었다.","공무원은 순위의 변화가 없었다.","군인이 새롭게 5위 안에 들었다.","간호사는 4위로 순위가 떨어졌다."],"answer":3,"explain":"✅ <b>③</b>: «군인» (военный) впервые попал в топ-5 — в 2018 он на 5-м месте, а в 2008 его в пятёрке не было.<br>✖️ ① на 1-м месте по-прежнему «교사» (учитель) — не изменилось; ② 공무원 переместился с 3-го (2008) на 4-е (2018) — изменение есть; ④ 간호사 ПОДНЯЛАСЬ с 4-го на 2-е, а не упала.<br>🧩 희망 직업 — желаемая профессия; 순위 — место в рейтинге; 공무원 — госслужащий; 간호사 — медсестра."},{"n":11,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"지난 24일에 '제7회 소비자 선정 최고 브랜드 대상' 시상식이 인주신문사 대강당에서 개최됐다. 이 상은 소비자의 온라인 투표로 수상 브랜드가 선정되어 의미가 크다. 지난해와 같이 100개 브랜드가 상을 받았는데 올해는 처음으로 친환경 화장품 브랜드 두 개가 포함되었다.","options":["소비자가 수상 브랜드를 선정했다.","기업들이 직접 온라인 투표에 참여했다.","지난해보다 더 많은 브랜드가 선정됐다.","친환경 화장품 브랜드는 상을 못 받았다."],"answer":1,"explain":"✅ <b>①</b>: лауреатов выбрали сами потребители онлайн-голосованием (소비자의 온라인 투표로 수상 브랜드가 선정).<br>✖️ ② голосовали потребители, а не компании; ③ как и в прошлом году — 100 брендов (지난해와 같이); ④ два эко-бренда косметики КАК РАЗ получили награду (포함되었다).<br>🧩 시상식 — церемония награждения; 수상 — награждение; 선정되다 — быть выбранным; 친환경 — экологичный."},{"n":12,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"최근 한 나라에서 4,800년 전에 만들어진 무덤이 발견됐다. 이 무덤의 주인은 당시 왕으로 밝혀졌으며 무덤 벽에는 고대 문자와 다양한 색의 그림이 가득했다. 이 무덤은 오랜 시간이 지났지만 색이 거의 그대로 보존되어 있어 역사적 가치가 높다고 전문가들은 전했다. 무덤의 일부는 일반인에게도 곧 공개될 예정이다.","options":["무덤의 주인이 누구인지 찾고 있다.","무덤 안을 구경하는 사람들이 많아졌다.","무덤 안의 그림은 색의 상태가 좋은 편이다.","무덤 바닥에서 다양한 문자와 그림이 발견됐다."],"answer":3,"explain":"✅ <b>③</b>: рисунки в гробнице хорошо сохранили цвет (색이 거의 그대로 보존되어 있어).<br>✖️ ① владелец УЖЕ установлен — это был ван (왕으로 밝혀졌으며); ② гробницу лишь СКОРО откроют для публики (곧 공개될 예정); ④ письмена и рисунки были на СТЕНАХ (무덤 벽에는), а не на полу.<br>🧩 무덤 — гробница; 발견되다 — быть найденным; 보존되다 — сохраняться; 고대 문자 — древние письмена."},{"n":13,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 회사의 1층 로비를 외부인에게 개방하는 회사가 많아졌다.\n(나) 사람들은 작품을 감상하고 커피를 마시면서 시간을 보낸다.\n(다) 미술관과 카페를 만들어 사람들이 와서 즐길 수 있게 한 것이다.\n(라) 이 공간을 이용하는 사람이 늘면서 회사의 이미지도 좋아지고 있다.","options":["(가)-(다)-(나)-(라)","(나)-(라)-(다)-(가)","(다)-(나)-(라)-(가)","(라)-(나)-(가)-(다)"],"answer":1,"explain":"✅ <b>① (가)-(다)-(나)-(라)</b>: (가) зачин — всё больше компаний открывают холл 1-го этажа для посторонних; (다) поясняет — устраивают галереи и кафе, чтобы люди заходили; (나) люди смотрят работы и пьют кофе; (라) с ростом посетителей улучшается имидж компании.<br>✖️ начинать с (다)/(라)/(나) нельзя — они опираются на введённое в (가).<br>🧩 개방하다 — открывать (доступ); 감상하다 — любоваться; 이미지 — имидж."},{"n":14,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 차에서 내려 앞차의 주인에게 사과하고 사정을 설명했다.\n(나) 앞차 주인은 큰 사고가 아니니 괜찮다며 그냥 가라고 했다.\n(다) 친절한 배려 덕분에 딸은 무사히 병원에 도착해 치료를 받았다.\n(라) 아픈 딸을 병원으로 급하게 데려가다가 앞차와 부딪쳐 사고를 냈다.","options":["(나)-(가)-(다)-(라)","(나)-(가)-(라)-(다)","(라)-(가)-(나)-(다)","(라)-(가)-(다)-(나)"],"answer":3,"explain":"✅ <b>③ (라)-(가)-(나)-(다)</b>: (라) завязка — вёз больную дочь в больницу и врезался в машину впереди; (가) вышел, извинился перед водителем; (나) тот сказал «ничего страшного, поезжайте»; (다) благодаря его доброте дочь добралась до больницы и получила лечение.<br>✖️ начинать с (나) нельзя — «앞차 주인» уже введён аварией.<br>🧩 앞차 — машина впереди; 사과하다 — извиняться; 배려 — забота; 부딪치다 — врезаться."},{"n":15,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 선택에 대한 부담으로 구매를 망설이다가 포기하기도 한다.\n(나) 선택에 대한 고객의 부담을 줄여 구매를 유도하려는 것이다.\n(다) 그래서 마트에서는 품목별로 몇 가지의 제품만 매장에 진열한다.\n(라) 소비자는 선택의 폭이 넓을수록 물건을 고를 때 어려움을 겪는다.","options":["(나)-(가)-(라)-(다)","(나)-(라)-(가)-(다)","(라)-(가)-(다)-(나)","(라)-(다)-(가)-(나)"],"answer":3,"explain":"✅ <b>③ (라)-(가)-(다)-(나)</b>: (라) общий тезис — чем шире выбор, тем труднее покупателю; (가) из-за бремени выбора человек медлит и даже отказывается от покупки; (다) поэтому магазины выкладывают лишь несколько товаров на категорию; (나) это чтобы снизить бремя выбора и побудить к покупке.<br>✖️ начинать с (나)/(가) нельзя — они опираются на тезис (라).<br>🧩 선택 — выбор; 부담 — бремя; 망설이다 — колебаться; 진열하다 — выкладывать (товар)."},{"n":16,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"상담을 통해 책을 추천해 주는 서점이 있어 화제가 되고 있다. 서점 주인은 손님과 오랜 시간 대화를 나눈 후 (        ) 책을 추천해 준다. 상처 받은 사람에게는 위로가 되는 책을, 자신감이 부족한 사람에게는 용기를 주는 책을 추천하는 방식으로 서비스를 제공한다.","options":["내용이 재미있는","지식을 전달하는","사람들이 많이 읽는","손님의 상황에 맞는"],"answer":4,"explain":"✅ <b>④ 손님의 상황에 맞는</b>: после долгой беседы советуют книгу под состояние клиента — раненому душой утешающую, неуверенному ободряющую.<br>✖️ ① «интересную по содержанию» — не критерий; ② «передающую знания» — нет; ③ «которую много читают» — наоборот, подбор индивидуальный.<br>🧩 상담 — консультация; 추천하다 — рекомендовать; 위로 — утешение; 상황 — ситуация."},{"n":17,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"샌드위치나 샐러드 등은 오래 보관할 수 없어 신선할 때 팔아야 한다. 이런 식품을 영업 마감 시간을 앞두고 사람들에게 할인된 가격으로 판매하는 서비스가 큰 호응을 얻고 있다. 음식점은 남은 음식을 팔아 수익을 얻을 수 있고, 소비자는 (        ) 이용자들의 만족도가 높다.","options":["자원을 아낄 수 있어서","식품을 저렴하게 살 수 있어서","요리법을 배울 수 있기 때문에","음식을 선택할 수 있기 때문에"],"answer":2,"explain":"✅ <b>② 식품을 저렴하게 살 수 있어서</b>: перед закрытием остатки продают со скидкой — кафе получает доход, а покупатель берёт еду дёшево, поэтому довольны.<br>✖️ ① «экономия ресурсов» — не главная выгода покупателя здесь; ③ «научиться готовить» — нет; ④ «выбор еды» — нет.<br>🧩 신선하다 — свежий; 할인된 가격 — со скидкой; 저렴하다 — дешёвый; 호응 — отклик."},{"n":18,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"뮤지컬은 보통 한 역할에 여러 명의 배우들이 출연한다. 배우에 따라 연기나 분위기가 다르기 때문에 같은 작품이라도 색다른 느낌을 받을 수 있다. 그래서 뮤지컬 팬들은 (        ) 작품을 즐기기 위해 공연을 반복해서 관람한다.","options":["입장료를 할인해 주는","공연장에서 인기가 있는","유행하는 노래가 나오는","각 배우들의 개성이 담긴"],"answer":4,"explain":"✅ <b>④ 각 배우들의 개성이 담긴</b>: одну роль играют разные актёры, и каждый придаёт свой оттенок; фанаты пересматривают, чтобы насладиться индивидуальностью каждого актёра.<br>✖️ ① про скидку на билет — нет; ② «популярный в зале» — не то; ③ «модные песни» — нет.<br>🧩 뮤지컬 — мюзикл; 출연하다 — выступать; 색다르다 — необычный; 개성 — индивидуальность."},{"n":19,"points":2,"instr":"Выберите подходящее слово в пропуск ( ).","passage":"해파리는 몸의 95%가 물로 구성되어 있어 열량이 낮다. 그래서 해파리를 먹고 사는 동물이 거의 없다고 알려져 있었다. 하지만 새나 펭귄, 뱀장어 등 많은 동물들에게 해파리는 좋은 먹잇감이다. 해파리에는 비타민이나 콜라겐 같은 영양 성분이 있기 때문이다. (        ) 해파리는 바다 어디에나 있고 도망치지 않아 사냥하기 쉽기 때문이다.","options":["과연","만약","게다가","이처럼"],"answer":3,"explain":"✅ <b>③ 게다가</b>: пропуск вводит ДОПОЛНИТЕЛЬНУЮ причину (медузы повсюду и не убегают — их легко ловить) к уже названной (питательность) → «к тому же».<br>✖️ ① 과연 — «и вправду»; ② 만약 — «если»; ④ 이처럼 — «таким образом» (вывод), а тут добавление причины.<br>🧩 게다가 — к тому же; 해파리 — медуза; 열량 — калорийность; 먹잇감 — добыча, корм."},{"n":20,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"해파리는 몸의 95%가 물로 구성되어 있어 열량이 낮다. 그래서 해파리를 먹고 사는 동물이 거의 없다고 알려져 있었다. 하지만 새나 펭귄, 뱀장어 등 많은 동물들에게 해파리는 좋은 먹잇감이다. 해파리에는 비타민이나 콜라겐 같은 영양 성분이 있기 때문이다. (게다가) 해파리는 바다 어디에나 있고 도망치지 않아 사냥하기 쉽기 때문이다.","options":["해파리는 바다 생태계에 피해를 준다.","해파리는 잡기 어려운 먹이 자원이다.","해파리는 여러 동물의 먹이가 되고 있다.","해파리는 대부분 콜라겐으로 이루어져 있다."],"answer":3,"explain":"✅ <b>③</b>: медузы служат кормом многим животным (새, 펭귄, 뱀장어 등에게 좋은 먹잇감).<br>✖️ ① про вред экосистеме не сказано; ② медуз КАК РАЗ легко ловить (사냥하기 쉽기); ④ на 95% они состоят из ВОДЫ (몸의 95%가 물), а не из коллагена.<br>🧩 생태계 — экосистема; 먹이 자원 — кормовой ресурс; 콜라겐 — коллаген; 이루어지다 — состоять."},{"n":21,"points":2,"instr":"Выберите подходящее выражение (идиому) в пропуск ( ).","passage":"내비게이션은 목적지까지 길을 안내해 주는 기기이다. 내비게이션이 없어 낯선 곳에 갔다가 길을 못 찾아 (        ) 본 적이 있는 사람이라면 내비게이션이 얼마나 편리한지 느꼈을 것이다. 그러나 우리의 뇌는 스스로 정보를 찾았을 때 그 정보를 오래 기억하는 특성이 있다. 따라서 지나치게 디지털 기기에만 의존하다 보면 정보를 찾고 기억하는 능력이 점점 줄어들어 결국 그 능력을 사용할 수 없게 될지도 모른다.","options":["얼굴을 재어","진땀을 흘려","발목을 잡아","귀를 기울여"],"answer":2,"explain":"✅ <b>② 진땀을 흘려</b>: идиома 진땀을 흘리다 — «обливаться потом, намучиться». «길을 못 찾아 진땀을 흘려 본 적이 있는 사람» — кто плутал, не находя дорогу, и измучился.<br>✖️ ① 얼굴을 재어 — не идиома; ③ 발목을 잡다 — тормозить; ④ 귀를 기울이다 — внимательно слушать.<br>🧩 진땀을 흘리다 — обливаться потом (мучиться); 내비게이션 — навигатор; 낯설다 — незнакомый; 의존하다 — зависеть."},{"n":22,"points":2,"instr":"Выберите главную мысль текста.","passage":"내비게이션은 목적지까지 길을 안내해 주는 기기이다. … 그러나 우리의 뇌는 스스로 정보를 찾았을 때 그 정보를 오래 기억하는 특성이 있다. 따라서 지나치게 디지털 기기에만 의존하다 보면 정보를 찾고 기억하는 능력이 점점 줄어들어 결국 그 능력을 사용할 수 없게 될지도 모른다.","options":["디지털 기기는 편리한 생활을 위해 필요하다.","운전자에게 내비게이션은 활용도가 매우 높다.","스스로 정보를 찾고 기억하려는 노력을 해야 한다.","내비게이션을 잘 활용하면 기억력 향상에 도움이 된다."],"answer":3,"explain":"✅ <b>③</b>: чрезмерная зависимость от гаджетов снижает способность находить и запоминать; мозг лучше помнит найденное самостоятельно — значит надо стараться искать и запоминать самому.<br>✖️ ① «гаджеты нужны для удобства» — не вывод; ② «навигатор полезен водителю» — частность; ④ «навигатор улучшает память» — противоречит тексту.<br>🧩 의존하다 — зависеть; 기억력 — память; 노력 — усилие; 줄어들다 — уменьшаться."},{"n":23,"points":2,"instr":"Выберите чувство «я» в подчёркнутой части.","passage":"놀이공원 매표소에서 아르바이트를 했다. 아르바이트가 처음이라 실수를 하지 않으려고 늘 긴장하면서 일을 했다. 어느 날, 놀러 온 한 가족에게 인원수만큼 표를 줬다. 그런데 그 가족을 보내고 나서 이용권 한 장의 값이 더 결제된 것을 알아차렸다. 바로 카드사로 전화해 고객의 전화번호를 물었지만 상담원은 알려 줄 수 없다고 했다. 하지만 내 연락처를 고객에게 전달해 주겠다고 했다. <u>일을 하는 내내 일이 손에 잡히지 않았다.</u> 퇴근 시간 무렵 드디어 그 가족에게서 전화가 왔다. 내가 한 실수에 화를 낼지도 모른다는 생각에 떨리는 목소리로 상황을 설명하자 그 가족은 \"놀이 기구를 타고 노느라 문자 메시지가 온 줄 몰랐어요. 많이 기다렸겠어요.\"라며 따뜻하게 말해 주었다.","options":["걱정스럽다","불만스럽다","후회스럽다","당황스럽다"],"answer":1,"explain":"✅ <b>① 걱정스럽다</b> (тревожно): рассказчик переплатно списал деньги клиента и весь день не может сосредоточиться на работе («일이 손에 잡히지 않았다»), волнуясь, как всё разрешится.<br>✖️ ② 불만스럽다 (недовольство) — нет; ③ 후회스럽다 (раскаяние) — оттенок не тот; ④ 당황스럽다 (растерянность) — момент уже прошёл, тут именно тревога ожидания.<br>🧩 일이 손에 잡히지 않다 — работа не идёт (из-за тревоги); 결제되다 — списываться (об оплате); 긴장하다 — нервничать; 걱정스럽다 — тревожный."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"놀이공원 매표소에서 아르바이트를 했다. … 그 가족을 보내고 나서 이용권 한 장의 값이 더 결제된 것을 알아차렸다. 바로 카드사로 전화해 고객의 전화번호를 물었지만 상담원은 알려 줄 수 없다고 했다. 하지만 내 연락처를 고객에게 전달해 주겠다고 했다. … 그 가족에게서 전화가 왔다. … 그 가족은 … 따뜻하게 말해 주었다.","options":["그 가족은 나에게 화를 냈다.","카드 회사는 그 가족에게 연락을 했다.","나는 그 가족에게 직접 전화를 걸었다.","나는 그 가족을 찾아다니느라 일을 못 했다."],"answer":2,"explain":"✅ <b>②</b>: карт-компания передала контакт рассказчика клиенту (внутренний контакт), после чего семья позвонила → компания связалась с семьёй.<br>✖️ ① семья ответила ТЕПЛО, не сердилась (따뜻하게 말해 주었다); ③ рассказчик звонил в КАРТ-КОМПАНИЮ, номер семьи ему не дали; ④ он продолжал работать (일을 하는 내내), а не искал семью.<br>🧩 카드사 — компания-эмитент карты; 연락처 — контакт; 전달하다 — передавать; 결제 — оплата."},{"n":25,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 관광버스 추락, 안전벨트로 승객 전원 목숨 건져","options":["관광버스가 추락했지만 승객들이 안전벨트 덕분에 모두 살았다.","관광버스 추락 사고 이후 안전벨트를 하는 승객이 더 많아졌다.","관광버스가 추락하자 일부 승객이 안전벨트를 풀고 탈출하였다.","관광버스가 추락하면서 안전벨트를 한 일부 승객이 크게 다쳤다."],"answer":1,"explain":"✅ <b>①</b>: «추락» — упал/сорвался, «안전벨트로 승객 전원 목숨 건져» — все пассажиры спаслись благодаря ремням → автобус сорвался, но все выжили благодаря ремням.<br>✖️ ② про рост числа пристёгивающихся — нет; ③ «отстегнулись и выбрались» — наоборот, спасли именно ремни; ④ «серьёзно пострадали» — нет, все спаслись.<br>🧩 추락 — падение, срыв; 안전벨트 — ремень безопасности; 전원 — все до одного; 목숨을 건지다 — спастись."},{"n":26,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 침묵 깬 김민수 의원, 대통령 선거 출마설 부인","options":["김 의원이 대통령 선거에 나가느냐는 질문에 계속 답하지 않고 있다.","김 의원이 마음을 바꿔 대통령 선거에 나가겠다고 최종 발표하였다.","김 의원이 대통령 선거에 나간다고 선언하자 사람들이 열렬히 환영했다.","김 의원이 대통령 선거에 나간다는 것이 사실이 아니라고 입장을 밝혔다."],"answer":4,"explain":"✅ <b>④</b>: «침묵 깬» — прервав молчание, «출마설 부인» — ОПРОВЕРГ слух о выдвижении → заявил, что не пойдёт на президентские выборы.<br>✖️ ① «продолжает молчать» — наоборот, нарушил молчание; ② «решил баллотироваться» — противоположно; ③ «объявил, что идёт» — противоположно.<br>🧩 침묵을 깨다 — нарушить молчание; 의원 — депутат; 출마설 — слух о выдвижении; 부인하다 — отрицать."},{"n":27,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 민간 우주선 무사 귀환, 우주여행 시대 '성큼'","options":["사람들의 응원 속에 민간 우주선이 긴 우주여행을 마치고 돌아왔다.","사람들은 민간 우주선이 우주여행에서 무사히 돌아오기를 기대했다.","민간 우주선이 무사히 돌아오면서 우주여행의 가능성이 더욱 높아졌다.","민간 우주선이 돌아오지 않자 우주여행에 대한 우려의 목소리가 커졌다."],"answer":3,"explain":"✅ <b>③</b>: «무사 귀환» — благополучно вернулся, «우주여행 시대 성큼» — эра космотуризма приблизилась → благополучное возвращение повысило реалистичность космических путешествий.<br>✖️ ① «после долгого полёта» — акцент заголовка на перспективе, а не на длительности; ② «надеялись на возвращение» — оно уже состоялось; ④ «не вернулся, тревога выросла» — противоположно.<br>🧩 민간 — частный; 우주선 — космический корабль; 귀환 — возвращение; 성큼 — большим шагом (приближаться)."},{"n":28,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"새해에 세운 목표를 효과적으로 이루려면 한 주 단위로 계획을 세우는 것이 좋다. 주마다 계획을 세우면 (        ) 때문이다. '건강한 식습관 기르기'라는 새해 결심이 한 주 단위가 되면 '라면 안 먹기', '채소 챙겨 먹기'처럼 구체적인 계획으로 바뀐다. 이렇게 하면 작은 목표들을 달성하는 횟수가 늘어 한 해의 목표에 가까워진다.","options":["한 해의 목표를 확인하기","계획을 세우는 데 집중하기","자신의 능력을 보여 줄 수 있기","실천 가능한 계획을 세울 수 있기"],"answer":4,"explain":"✅ <b>④ 실천 가능한 계획을 세울 수 있기</b>: при недельном горизонте расплывчатая цель («питаться здорово») превращается в конкретные выполнимые шаги («не есть рамён», «есть овощи»).<br>✖️ ① «проверить годовую цель» — не причина; ② «сосредоточиться на планировании» — пустая формулировка; ③ «показать свои способности» — нет.<br>🧩 목표 — цель; 단위 — единица (периода); 구체적 — конкретный; 실천 가능하다 — выполнимый."},{"n":29,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"무지개는 빛이 공기 중의 물방울을 통과할 때 굴절되어 나타나는 현상이다. 그래서 비가 그친 직후 해가 들 때 무지개가 잘 생긴다. 이때 (        ) 않으면 무지개가 만들어지기 어렵다. 공기에 먼지 등의 오염 물질이 섞이면 물방울들이 먼지 주위로 모여 빛이 통과하는 것을 막기 때문이다.","options":["해가 뜨지","비가 그치지","빛이 약하지","공기가 깨끗하지"],"answer":4,"explain":"✅ <b>④ 공기가 깨끗하지 (않으면)</b>: радуга образуется при преломлении света в каплях; если воздух грязный, капли собираются вокруг пыли и не пропускают свет → нужно, чтобы воздух был чистым.<br>✖️ ① «солнце не взойдёт» — про солнце уже сказано (해가 들 때); ② «дождь не прекратится» — наоборот, радуга после дождя; ③ «свет слабый» — причина в чистоте воздуха.<br>🧩 무지개 — радуга; 굴절되다 — преломляться; 물방울 — капля; 오염 물질 — загрязнители."},{"n":30,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"취재 경계선은 취재가 과열되어 발생할 수 있는 부상자를 예방하기 위해 설정한 것이다. 수백 명의 취재진이 화제의 인물에게 몰려들 경우 사고가 발생해 취재를 망칠 수 있다. 그래서 선을 그어 놓고 그 바깥에서 취재하자는 합의를 본 것이다. 비록 법으로 정해져 있지 않지만 언론계가 이 선을 지키려고 노력하는 것은 (        ) 순간 원활한 보도가 어려워진다는 것을 누구보다 잘 알고 있기 때문이다.","options":["취재 정보를 공유하는","취재 경계선이 무너지는","취재 내용을 잘못 해석하는","취재 경계선이 새로 설정되는"],"answer":2,"explain":"✅ <b>② 취재 경계선이 무너지는</b>: журналисты соблюдают линию, ведь знают: как только она рухнет — толпа репортёров создаст хаос и нормальный репортаж станет невозможен.<br>✖️ ① «делиться информацией» — не то; ③ «неверно истолковать» — нет; ④ «линия заново установлена» — нелогично.<br>🧩 취재 — сбор материала; 경계선 — граница; 무너지다 — рушиться; 원활하다 — беспрепятственный."},{"n":31,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"병원의 규모에 따라 개인이 부담해야 하는 약값을 달리하는 제도가 생겼다. 감기와 같이 비교적 가벼운 병에 걸렸을 때 종합병원에서 진료를 받으면 (        ) 만든 것이다. 같은 약을 동네 의원에서 받은 처방전으로 사면 약값이 더 적게 나온다. 이 제도를 통해 환자들이 진료에 대한 신뢰 때문에 종합병원으로만 몰리는 현상을 줄일 수 있을 것으로 예상된다.","options":["환자가 약값을 조금 더 내게","개인이 약값을 비교할 수 있게","병원에서 병원비를 올리지 못하게","병원비의 일부를 병원에서 지원하게"],"answer":1,"explain":"✅ <b>① 환자가 약값을 조금 더 내게</b>: при лёгкой болезни (простуда) лечение в крупной больнице делают дороже по лекарствам; то же лекарство по рецепту из районной поликлиники стоит дешевле.<br>✖️ ② «сравнивать цены» — не цель; ③ «не повышать счёт больницы» — нет; ④ «больница оплачивает часть» — наоборот, пациент платит больше.<br>🧩 약값 — стоимость лекарств; 종합병원 — крупная больница; 처방전 — рецепт; 몰리다 — стекаться."},{"n":32,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"나비 박사 석주명은 나비의 종류를 분류하고 이름을 지어 준 생물학자이다. 1931년부터 나비를 연구한 그는 한국의 나비가 총 844종이라는 당시의 분류를 248종으로 수정하였다. 날개 무늬나 모양이 조금만 달라도 다른 종이라고 판단한 기존의 분류가 틀렸음을 밝혀낸 것이다. 또한 그때까지 한자어나 외래어로 명명된 나비에 '떠들썩팔랑나비' 같은 고유어 이름을 지어 주는 데 앞장섰다.","options":["석주명은 한국의 나비를 총 844종으로 분류하였다.","석주명은 나비 이름을 고유어로 바꾸려고 노력하였다.","석주명은 자신의 배추흰나비 연구에 문제가 있음을 알았다.","석주명은 나비의 날개 모양이 다르면 종이 달라짐을 밝혔다."],"answer":2,"explain":"✅ <b>②</b>: Сок Чумён давал бабочкам исконно корейские названия вместо иероглифических/заимствованных (고유어 이름을 지어 주는 데 앞장섰다).<br>✖️ ① он СОКРАТИЛ прежнюю классификацию с 844 до 248 видов, а не насчитал 844; ③ про проблему его исследования капустницы — нет; ④ он, наоборот, ОПРОВЕРГ, что «разные крылья = разные виды».<br>🧩 분류하다 — классифицировать; 수정하다 — исправлять; 고유어 — исконное слово; 앞장서다 — браться первым, возглавлять."},{"n":33,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"저축의 방식은 가로 저축과 세로 저축으로 나눠 비유하여 설명할 수 있다. 차량 구입이나 주택 마련과 같이 특정 목적을 위해 한 통장에 집중하여 저축하는 것이 세로 저축이다. 반면 장기적으로 다양한 목적에 따라 자금을 여러 통장에 분산하여 저축하는 것을 가로 저축이라고 한다. 따라서 저축의 목적이 다양하면 가로 저축이, 목적이 하나로 분명하면 세로 저축이 알맞다.","options":["노후 준비에는 세로 저축이 유리하다.","세로 저축보다 가로 저축을 하는 것이 더 좋다.","저축의 목적이 다양하면 가로 저축이 유용하다.","가로 저축은 단기적인 계획이 있을 때 효과적이다."],"answer":3,"explain":"✅ <b>③</b>: при разных целях накопления полезно «горизонтальное» сбережение (가로 저축 — деньги по нескольким счетам под разные цели).<br>✖️ ① про пенсию конкретно не сказано; ② текст не утверждает, что один способ вообще лучше; ④ «горизонтальное» — для ДОЛГОсрочных разных целей (장기적으로), а не для краткосрочного плана.<br>🧩 저축 — сбережения; 통장 — банковский счёт; 분산하다 — распределять; 장기적 — долгосрочный."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"'책가도'는 책장과 책을 중심으로 하여 각종 문방구 등을 그린 그림이다. 학문을 중요시하는 양반의 마음이 더해져 책가도는 궁중과 사대부를 중심으로 발전하였다. 19세기에는 상인과 농민 계층으로도 확산되면서 그 형식도 자유로워졌다. 그림에서 책장 대신 작은 탁자가 활용되기도 하고 일상 용품이 함께 그려지기도 했다.","options":["왕은 책가도에 대해 부정적 인식이 강했다.","점차 다양한 계층에서 책가도를 즐기게 되었다.","초기의 책가도에는 일상 용품이 주로 그려졌다.","책가도는 왕의 바람으로 그림의 형식이 바뀌었다."],"answer":2,"explain":"✅ <b>②</b>: со временем чхэккадо распространился и в среду торговцев и крестьян (19세기에는 상인과 농민 계층으로도 확산) — им стали наслаждаться разные слои.<br>✖️ ① про негативное отношение вана — нет; ③ бытовые предметы появились ПОЗЖЕ (с упрощением формы), а вначале — книжные шкафы и книги; ④ форму изменило распространение в народ, а не «желание вана».<br>🧩 책가도 — чхэккадо (живопись с книжными полками); 계층 — слой; 확산되다 — распространяться; 사대부 — знать."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"문화재 복원 작업은 복원될 부분이 자연스러워야 하고 그 과정에서 문화재가 추가로 손상되지 않아야 한다. 이 때문에 정확한 측정으로 복원할 부분을 원래 모습과 동일하게 만들어 내는 것은 복원의 성공을 결정하는 중요한 요건이다. 최근 3D 스캐너와 프린터가 등장하여 이러한 요건을 충족할 수 있게 되면서 정밀하고 안전한 문화재 복원이 가능해졌다.","options":["첨단 장비 덕분에 문화재 복원이 수월해졌다.","문화재는 손상 예방을 위한 사전 관리가 중요하다.","복원 환경 탓에 원본이 변형되는 경우가 많아지고 있다.","복원 기술자를 대상으로 한 3D 장치 사용 교육이 필요하다."],"answer":1,"explain":"✅ <b>①</b>: точное воспроизведение оригинала без новых повреждений — ключ к реставрации; 3D-сканеры и принтеры это обеспечили → благодаря передовой технике реставрация стала проще и точнее.<br>✖️ ② «профилактика повреждений» — не тема; ③ «оригиналы деформируются» — наоборот; ④ «обучение реставраторов 3D» — не сказано.<br>🧩 문화재 — культурное наследие; 복원 — реставрация; 측정 — измерение; 첨단 장비 — передовое оборудование."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"아기는 주변 사물을 손으로 더듬고 만지면서 지각 능력을 발달시킨다. 그런데 이렇게 능동적인 경험뿐만 아니라 사람, 햇빛, 바람 등에 의한 접촉도 주요한 촉각 경험이 된다. 그중 주변 인물과의 피부 접촉은 사랑, 유대감, 신뢰감 등 유아의 정서 발달과 사회성 발달에 매우 중요하다. 연구에 따르면 아기가 태어난 후 몇 년 사이에 이루어진 피부 접촉은 정서 발달에 필수적인 호르몬 분비를 촉진할 뿐만 아니라 지능 발달에도 영향을 미친다고 한다.","options":["인간은 촉각을 통해 주변 사물을 이해한다.","정서 발달과 지능 발달은 상관관계가 높다.","촉각 경험의 중요성에 대한 연구가 필요하다.","유아의 발달을 위해서는 피부 접촉이 중요하다."],"answer":4,"explain":"✅ <b>④</b>: тактильный контакт в первые годы жизни критичен для эмоционального, социального и даже интеллектуального развития ребёнка.<br>✖️ ① «осязанием понимаем предметы» — частность; ② «связь эмоц. и интеллект. развития» — не главная мысль; ③ «нужны исследования» — нет.<br>🧩 촉각 — осязание; 접촉 — контакт; 유대감 — привязанность; 정서 발달 — эмоциональное развитие."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"나무에 붙어 자라는 버섯을 보면 나무로부터 양분을 받으며 별다른 노력 없이 살아간다고 생각하기 쉽다. 하지만 버섯은 나무에게 없어서는 안 될 중요한 존재이다. 나무들은 위기 상황이 발생해도 자리를 옮겨 이를 알릴 수 없기 때문에 뿌리로 소통하며 위험에 대비한다. 이때 뿌리가 닿지 않는 나무들 사이에서는 실처럼 뻗은 버섯 균사체가 메시지 전달을 대신한다. 그래서 학자들은 버섯 균류를 '숲의 통신망'이라고 부른다.","options":["버섯은 다른 식물이 있어야 자랄 수 있다.","나무의 뿌리가 숲에서 하는 기능은 다양하다.","버섯은 숲에서 나무들의 정보 교환을 돕는 역할을 한다.","나무의 생활환경에 대한 학자들의 관심이 높아지고 있다."],"answer":3,"explain":"✅ <b>③</b>: грибной мицелий передаёт «сообщения» между деревьями, чьи корни не соприкасаются — учёные зовут грибы «лесной сетью связи».<br>✖️ ① «грибу нужны другие растения» — частность, не суть; ② «функции корней разнообразны» — не тема; ④ «растёт интерес учёных» — нет.<br>🧩 버섯 — гриб; 균사체 — мицелий; 통신망 — сеть связи; 양분 — питательные вещества."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"음주 운전으로 인명 피해를 낸 사람에 대한 처벌 강화 법안이 국회에서 통과되었다. 하지만 새 법안은 원래 안건보다 처벌의 강도는 낮춘 것이라는 점에서 반쪽짜리 법안에 불과하다. 이 법안에 따르면 여전히 음주 운전 가해자의 처벌이 미흡하거나 일정 기간이 지난 후 효력이 없어질 수도 있다. 이는 음주 운전에 대한 경각심을 높이고 재발 위험성을 낮추려던 본래의 취지에는 맞지 않는 것이다.","options":["법안이 가진 본래의 취지를 널리 알려야 한다.","피해 정도에 따라 처벌의 수위를 조절해야 한다.","새 법안의 통과가 더 이상 미루어져서는 안 된다.","새 법안은 실질적 효과를 거두는 데 미흡한 점이 있다."],"answer":4,"explain":"✅ <b>④</b>: новый закон ослабил наказание относительно исходного проекта — «половинчатый», не отвечает цели снизить пьяное вождение → у него есть недостатки для реального эффекта.<br>✖️ ① «шире разъяснять цель закона» — нет; ② «регулировать наказание по тяжести вреда» — не главная мысль; ③ «нельзя откладывать принятие» — закон уже принят.<br>🧩 음주 운전 — вождение в нетрезвом виде; 법안 — законопроект; 미흡하다 — недостаточный; 경각심 — бдительность."},{"n":39,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그래서 백성들이 구하기 힘든 매우 귀하고 값비싼 재료로 만들어졌다.\n\n왕관은 과거 지배 계층이 착용했던 대표적인 장신구이다. ( ㉠ ) 장식도 화려하게 더해져 그것을 쓴 왕의 지위를 더욱 돋보이게 했다. ( ㉡ ) 오늘날 왕관이 가졌던 힘과 지위의 의미는 약화되었으나 고귀한 이미지는 남아 여러 디자인에서 발견된다. ( ㉢ ) 아름다움이 강조되어야 할 신부의 머리 장식이나 여러 액세서리에 왕관이 활용되고 있는 것이다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: вставка с «그래서» (поэтому) объясняет следствие из «корона — атрибут правящего класса» → её делали из дорогих, редких материалов. Дальше «장식도 화려하게 더해져» («украшения ТОЖЕ добавляли») — «도» подразумевает, что о роскоши уже сказано, значит вставка идёт перед этим, в ㉠.<br>✖️ ㉡㉢㉣ — уже про ослабление значения и современное использование, связь с «дорогими материалами» теряется.<br>🧩 왕관 — корона; 지배 계층 — правящий класс; 장신구 — украшение; 귀하다 — ценный, редкий."},{"n":40,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그들은 못생기고 혐오감을 준다는 이유만으로 외면당한 동물들을 대중에게 알리는 활동을 한다.\n\n멸종 위기에 처한 동물을 보호하려는 노력이 계속되고 있으나 주된 연구와 지원이 몇몇 동물에 쏠리고 있어 문제가 되고 있다. ( ㉠ ) 한 조사에 따르면 동물 보호 기금의 모금 액수도 북극곰, 판다같이 인기 있는 동물들에게 편중되었다고 한다. ( ㉡ ) 이런 가운데 그간 관심을 받지 못했던 동물들을 보호하기 위한 단체가 등장했다. ( ㉢ ) 이러한 노력은 동물 보호를 위한 마음에도 편견이 깃들어 있음을 일깨우고 있다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b>: вставка начинается с «그들» (они) — это та самая организация, появление которой описано перед ㉢ («단체가 등장했다»); а следующее «이러한 노력은…» («такие усилия…») обобщает их деятельность.<br>✖️ ㉠㉡ — организация ещё не введена, «그들» не на что опереться; ㉣ — уже после обобщающего вывода.<br>🧩 멸종 위기 — угроза вымирания; 편중되다 — быть смещённым/однобоким; 외면당하다 — быть отвергнутым; 편견 — предвзятость."},{"n":41,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 일곱 편의 단편에는 오래전 잘못으로 멀어진 사람들에 대한 이야기가 담겨 있다.\n\n'젊은 작가상'을 수상한 최은영이 두 번째 소설집 『내게 무해한 사람』을 펴냈다. ( ㉠ ) 2년여에 걸쳐 여러 지면에 발표했던 작품들을 한 권에 모은 것이다. ( ㉡ ) 그들처럼 누군가에 대한 배반, 원치 않았던 이별 등 매듭짓지 못한 일들을 다시 떠올린다는 것은 괴로운 과정일 것이다. ( ㉢ ) 그러나 작가는 이미 지나간 시간에 대해 후회할 필요는 없으며 상처도 힘이 될 수 있다는 메시지로 독자의 마음을 움직인다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"✅ <b>② ㉡</b>: вставка вводит «사람들» — людей, отдалившихся из-за давних ошибок (содержание семи рассказов); следующее «그들처럼…» («как они…») прямо ссылается на этих людей.<br>✖️ ㉠ — ещё не сказано, что в книге; ㉢㉣ — после «그들처럼», ссылка разрывается.<br>🧩 단편 — рассказ; 멀어지다 — отдаляться; 배반 — предательство; 매듭짓다 — завершить, разрешить."},{"n":42,"points":2,"instr":"Выберите чувство «Сохи» в подчёркнутой части.","passage":"그때 소희네는 이사를 앞두고 있었는데 엄마는 그렇게 집을 나가 돌아오지 않았다. 작별 인사는커녕 아무 신호도 쪽지도 없이 휙 사라졌다. (중략) 엄마가 집 나가고 열흘쯤 지났을 때, 소희가 텔레비전을 보고 있는데 본희가 현관에서 신을 신으며 잠깐 나갔다 오겠다고 했다. '잠깐 어디?' '친구네.' '친구 누구?' 소희가 눈을 맞추려 했지만 본희는 돌아보지 않았다. '늦으면 친구네서 자고 올지도 몰라. 기다리지 말고 자.' 돌아서 나가는 본희가 멘 가방이 이상하게 커 보여 <u>소희는 자리에서 벌떡 일어났다.</u> 가만히 서 있다가 갑자기 현관문을 열고 맨발로 뛰어나가 계단을 올라가는 본희 뒷모습에 대고 외쳤다. '언니야, 올 거지?' 본희는 멈춰 섰지만 돌아보지 않았다. 소희는 묻고 또 물었다.","options":["불안하다","흡족하다","실망스럽다","감격스럽다"],"answer":1,"explain":"✅ <b>① 불안하다</b> (тревога): мать ушла из дома навсегда, а теперь и старшая сестра уходит с подозрительно большой сумкой — Сохи вскакивает и в панике кричит вслед «вернёшься ведь?», боясь, что сестра тоже не вернётся.<br>✖️ ② 흡족하다 (довольство), ④ 감격스럽다 (растроганность) — противоположны; ③ 실망스럽다 (разочарование) — тут именно страх потери, тревога.<br>🧩 작별 인사 — прощание; 멘 가방 — сумка (на плече); 벌떡 일어나다 — вскочить; 불안하다 — тревожный."},{"n":43,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"엄마는 그렇게 집을 나가 돌아오지 않았다. … 엄마가 집 나가고 열흘쯤 지났을 때, … 본희가 … 잠깐 나갔다 오겠다고 했다. … 돌아서 나가는 본희가 멘 가방이 이상하게 커 보여 소희는 자리에서 벌떡 일어났다. … (중략) 한참 있다가 … 한밤중에 언니가 문자를 했다. 소희는 언니가 올 때까지 휴대 전화를 손에 꼭 쥐고 문자를 보고 또 보았다. … '삼겹살 사 가지고 갈게. 라면 끓여 먹지 말고 기다려.'","options":["본희는 밤늦게 소희에게 연락을 했다.","엄마는 이사하는 날에 집으로 돌아왔다.","본희는 소희를 데리고 친구 집에 놀러 갔다.","소희는 엄마를 기다리며 휴대 전화를 놓지 못했다."],"answer":1,"explain":"✅ <b>①</b>: поздно ночью старшая сестра Понхи написала Сохи сообщение (한밤중에 언니가 문자를 했다).<br>✖️ ② мама ушла и НЕ вернулась (돌아오지 않았다); ③ Понхи ушла одна, Сохи смотрела телевизор; ④ Сохи сжимала телефон, ожидая СЕСТРУ (언니), а не маму.<br>🧩 연락하다 — связываться; 문자 — СМС; 한밤중 — глубокая ночь; 쥐다 — сжимать (в руке)."},{"n":44,"points":2,"instr":"Выберите главную тему текста.","passage":"성대하고 까다로운 제사 준비 탓에 유교 예법을 비판하는 사람들이 많다. 하지만 현재 우리가 지키고 있는 예법은 (        ) 잘못된 예법이 전해져 온 것이다. 유교 전문가들은 제사든 차례든 조상을 공경하는 마음과 자손들의 화목이 중요하다고 말한다. 선조들은 제사를 드릴 때 좋은 음식을 많이 준비하는 것보다 그 음식을 준비하는 마음과 정성을 중시했던 것이다. 유서 깊은 집안에서는 이러한 제사의 본질을 제대로 이해하여 상차림은 간소하게 하되 집안사람들이 모두 모여 함께 제사를 드리는 경우가 많다. 형식보다 정성이 중요하다는 유교의 가르침을 지키고 있는 것이다.","options":["조상을 모시는 제사상 차림은 점차 간소화되고 있다.","유교 문화는 후손들에 의해 능동적으로 변화되고 있다.","명절에 제사를 드리는 전통은 예법에 맞게 유지되고 있다.","유교 예법에서 중요한 것은 정성을 다해 예를 갖추는 것이다."],"answer":4,"explain":"✅ <b>④</b>: суть конфуцианского обряда — не пышная форма, а искренность (정성); важны почтение к предкам и согласие в семье.<br>✖️ ① «упрощение стола» — частность; ② «активно меняется потомками» — не тема; ③ «традиция сохраняется по правилам» — не главная мысль.<br>🧩 제사 — поминальный обряд; 예법 — обряд, этикет; 정성 — искренность, усердие; 본질 — суть."},{"n":45,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"성대하고 까다로운 제사 준비 탓에 유교 예법을 비판하는 사람들이 많다. 하지만 현재 우리가 지키고 있는 예법은 (        ) 잘못된 예법이 전해져 온 것이다. … 선조들은 … 음식을 준비하는 마음과 정성을 중시했던 것이다. … 형식보다 정성이 중요하다는 유교의 가르침을 지키고 있는 것이다.","options":["상차림이 간소화된","후손들의 바람이 반영된","유교의 본뜻을 살리지 못한","현실에 맞게 축소되지 않은"],"answer":3,"explain":"✅ <b>③ 유교의 본뜻을 살리지 못한</b>: люди критикуют пышные хлопоты, но нынешний «обряд» — это искажённая версия, НЕ сохранившая истинный смысл конфуцианства (важна искренность, а не форма).<br>✖️ ① «упрощённая сервировка» — наоборот; ② «отражающий желания потомков» — нет; ④ «не сокращённый под реальность» — не вяжется с «잘못된».<br>🧩 본뜻 — истинный смысл; 살리다 — сохранять; 전해지다 — передаваться; 형식 — форма."},{"n":46,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 이와 같은 시장 형태가 전체 소비 시장에 미치는 영향력은 아직 미미하다.\n\n1인 미디어 시대가 되면서 개인 방송을 이용한 새로운 시장 형태가 등장해 주목받고 있다. 이 시장은 SNS를 통해 제품이 유통되고 판매된다는 특징이 있다. ( ㉠ ) 대표적인 판매 방식은 1인 미디어 운영자가 방송 중에 특정 물건을 의도적으로 노출하여 구매를 유도하는 것이다. 이때 관심이 생긴 시청자는 그 운영자에게서 물건을 산다. ( ㉡ ) SNS 계정만 있으면 누구든지 판매를 시작할 수 있으며 제품 홍보부터 구매까지 모든 과정이 SNS상에서 이루어진다. ( ㉢ ) 덕분에 초기 사업 비용이 거의 들지 않는다는 장점이 있다. ( ㉣ ) 하지만 개별 시장의 수가 무한하게 늘 수 있기 때문에 향후 경제 변화를 이끌 핵심 시장으로의 성장이 예상된다.","options":["㉠","㉡","㉢","㉣"],"answer":4,"explain":"✅ <b>④ ㉣</b>: вставка говорит, что СЕЙЧАС влияние такого рынка на общий рынок ещё мало; следующее предложение начинается с «하지만… 성장이 예상된다» («однако ожидается рост») — противопоставление. Значит вставка стоит прямо перед ним, в ㉣.<br>✖️ ㉠㉡㉢ — там идёт описание механизма продаж и преимуществ, контраст «мало сейчас → но вырастет» не складывается.<br>🧩 미미하다 — незначительный; 영향력 — влияние; 유통되다 — распространяться; 1인 미디어 — персональные медиа."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"1인 미디어 시대가 되면서 개인 방송을 이용한 새로운 시장 형태가 등장했다. … 대표적인 판매 방식은 1인 미디어 운영자가 방송 중에 특정 물건을 의도적으로 노출하여 구매를 유도하는 것이다. 이때 관심이 생긴 시청자는 그 운영자에게서 물건을 산다. SNS 계정만 있으면 누구든지 판매를 시작할 수 있으며 … 덕분에 초기 사업 비용이 거의 들지 않는다는 장점이 있다.","options":["1인 미디어 운영자는 이 시장의 운영에 참여할 수 없다.","이 시장의 운영자들은 시장 경제에 부정적인 영향을 미친다.","1인 미디어 시청자는 방송을 보다가 제품을 구매할 수 있다.","이 시장을 처음 시작할 때는 충분한 자본 투자가 필수적이다."],"answer":3,"explain":"✅ <b>③</b>: заинтересованный зритель покупает товар прямо у ведущего во время трансляции (관심이 생긴 시청자는 그 운영자에게서 물건을 산다).<br>✖️ ① ведущие как раз и ВЕДУТ этот рынок; ② ожидается рост, а не негативное влияние; ④ начальные затраты почти НУЛЕВЫЕ (초기 사업 비용이 거의 들지 않는다).<br>🧩 시청자 — зритель; 운영자 — ведущий/оператор; 자본 투자 — вложения капитала; 유도하다 — побуждать."},{"n":48,"points":2,"instr":"С какой целью написан текст?","passage":"올해 '자치경찰제'가 전국으로 확대될 예정이다. 자치경찰제는 지방자치 단체가 경찰의 운영 및 관리를 담당하도록 하는 제도를 말한다. 이 제도가 실시되면 경찰이 지역 주민의 삶에 밀착해 다양한 서비스를 제공할 수 있을 것으로 보인다. 그러나 제도적 취약점과 예측되는 부작용이 있을 수 있다. 무엇보다 현장에서의 혼선이 예상된다. … 영역 구분이 애매한 사건이 발생하면 자치경찰과 국가경찰이 함께 출동하거나 사건을 서로 떠넘기다가 신속하고 치밀한 대응이 이뤄지지 않을 수 있다. … 새 제도의 시행 의의가 퇴색될 수 있을 것이다.","options":["제도 확대 시행의 의의를 강조하기 위해서","제도 시행의 구체적 방안을 제시하기 위해서","제도의 취지와 주민 요구의 차이를 설명하기 위해서","제도 시행 후 생길 수 있는 문제를 지적하기 위해서"],"answer":4,"explain":"✅ <b>④</b>: текст в основном указывает на возможные проблемы после введения автономной полиции (путаница на местах, двойная структура, медленное реагирование).<br>✖️ ① «подчеркнуть значимость» — текст скорее критичен; ② «конкретные методы» — нет; ③ «разница цели и требований жителей» — нет.<br>🧩 자치경찰제 — система автономной полиции; 취약점 — слабое место; 혼선 — путаница; 지적하다 — указывать (на проблему)."},{"n":49,"points":2,"instr":"Выберите подходящее содержание в пропуск ( ).","passage":"… 영역 구분이 애매한 사건이 발생하면 자치경찰과 국가경찰이 함께 출동하거나 사건을 서로 떠넘기다가 신속하고 치밀한 대응이 이뤄지지 않을 수 있기 때문이다. (        ) 치안의 질이 떨어진다면 새 제도의 시행 의의가 퇴색될 수 있을 것이다.","options":["경찰들의 업무 과다로","업무의 충돌과 혼선으로","자치경찰의 배치 감소로","제도의 단계적 시행으로"],"answer":2,"explain":"✅ <b>② 업무의 충돌과 혼선으로</b>: при неясном разграничении две полиции либо выезжают вместе, либо перекидывают дело друг другу → именно из-за столкновения и путаницы в обязанностях падает качество правопорядка.<br>✖️ ① «перегрузка полицейских» — не названо; ③ «сокращение штата автополиции» — нет; ④ «поэтапное внедрение» — нет.<br>🧩 충돌 — столкновение; 혼선 — путаница; 치안 — правопорядок, безопасность; 퇴색되다 — блёкнуть, утрачиваться."},{"n":50,"points":2,"instr":"Выберите отношение автора в подчёркнутой части.","passage":"올해 '자치경찰제'가 전국으로 확대될 예정이다. 자치경찰제는 지방자치 단체가 경찰의 운영 및 관리를 담당하도록 하는 제도를 말한다. <u>이 제도가 실시되면 경찰이 지역 주민의 삶에 밀착해 지역 특성에 맞는 다양한 서비스를 주민들에게 제공할 수 있을 것으로 보인다.</u> 그러나 제도적 취약점과 예측되는 부작용이 있을 수 있다. …","options":["자치경찰과 지역 주민의 관계 변화에 대해 예상하고 있다.","자치경찰제가 주민에게 미칠 긍정적 영향을 기대하고 있다.","자치경찰제가 제공해야 할 서비스의 조건을 강조하고 있다.","지역 문화적 서비스가 특정 지역에 쏠릴까 우려하고 있다."],"answer":2,"explain":"✅ <b>②</b>: в подчёркнутом автор ОЖИДАЕТ позитивного эффекта для жителей — полиция станет ближе к их жизни и даст услуги под особенности района.<br>✖️ ① «изменение отношений» — не про это; ③ «условия услуг» — не подчёркнутая мысль; ④ «опасение перекоса услуг» — это про другую (критическую) часть текста, не про подчёркнутую.<br>🧩 밀착하다 — тесно прилегать, быть рядом; 지역 특성 — особенности района; 기대하다 — ожидать, надеяться; 긍정적 — положительный."}]
      }
    },
    91: {
      listening: {
        durationMin: 60, total: 100, label: '제91회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/91/91st%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/91-l-q1.png","options":["①","②","③","④"],"answer":2,"explain":"🎧 여자: 손님, 마음에 드는 넥타이 있으세요? 남자: 제일 오른쪽에 있는 줄무늬 넥타이가 괜찮아 보이네요. 여자: 그럼 이걸로 꺼내서 보여 드릴까요?<br>✅ <b>②</b>: продавщица спрашивает, какой галстук нравится; покупатель указывает на полосатый справа; продавщица предлагает достать и показать. На ② — сцена в магазине галстуков: сотрудница показывает галстук покупателю у витрины.<br>✖️ ① у кассы передают покупку; ③ человек стоит один; ④ другая сцена — «выбор галстука у витрины» там не показан.<br>🧩 넥타이 — галстук; 줄무늬 — полоска; 꺼내다 — доставать; 마음에 들다 — нравиться."},{"n":2,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/91-l-q2.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 남자: 음, 이 사과 정말 달고 맛있네요. 여자: 그러네요. 하나 더 깎을까요? 남자: 네, 좋아요. 수미 씨는 먹고 있어요. 제가 할게요.<br>✅ <b>①</b>: двое едят яблоки за столом; женщина предлагает почистить ещё одно, мужчина говорит «ты ешь, я сам почищу». На ① мужчина берётся чистить яблоко, женщина ест за столом.<br>✖️ ② женщина наливает/делает что-то стоя; ③ другая поза за столом; ④ оба стоят у стола — «он чистит, она ест» только на ①.<br>🧩 사과 — яблоко; 깎다 — чистить (фрукт, ножом); 달다 — сладкий; 제가 할게요 — я сделаю."},{"n":3,"points":2,"instr":"Послушайте и выберите подходящий график.","image":"assets/topik2/exams/img/91-l-q3.png","options":["①","②","③","④"],"answer":3,"explain":"🎧 성인 독서율이 계속 감소하고 있다. 독서를 하지 않는 이유로는 '일 때문에 시간이 없어서'가 1위, '책 대신 다른 매체를 이용해서'가 2위, '책 읽는 습관이 안 들어서'가 3위.<br>✅ <b>③</b>: вопрос про ПРИЧИНЫ отказа от чтения. На ③ места: 1) нет времени из-за работы, 2) вместо книг — другие медиа, 3) нет привычки читать — точно как в аудио.<br>✖️ ①② — это графики «доля читающих взрослых», а спрашивают причины; ④ — 2-е и 3-е места переставлены местами.<br>🧩 독서율 — доля читающих; 매체 — медиа, носитель; 습관 — привычка; 감소하다 — снижаться."},{"n":4,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["그래? 안 나와서 걱정했어.","무슨 학원에 다니고 있어?","그래? 할머니 댁에 언제 가?","부모님과 함께 가기로 했거든."],"answer":1,"explain":"🎧 남자: 어제 요가 학원에 왜 안 나왔어? 여자: 할머니 생신이라 부모님하고 할머니 댁에 갔다 왔어.<br>✅ <b>① 그래? 안 나와서 걱정했어</b>: она объяснила, почему не пришла на йогу; естественная реакция — «правда? я волновался, что тебя не было».<br>✖️ ② «на какие курсы ходишь?» — он и так знает (йога); ③ «когда поедешь к бабушке?» — она уже съездила; ④ «решил поехать с родителями» — не его реплика.<br>🧩 학원 — курсы; 생신 — день рождения (вежл. о старших); 걱정하다 — беспокоиться; 댁 — дом (вежл.)."},{"n":5,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["그럼 거기로 다시 가 볼까요?","아직 한 곳밖에 안 가 봤는데요.","그럼 이 소파를 사는 게 어때요?","집 근처에 있는 가게에서 샀어요."],"answer":1,"explain":"🎧 여자: 우리가 둘러본 가게들 중에 어느 가게의 소파가 괜찮았어요? 남자: 저는 처음에 갔던 가게의 소파들이 제일 나은 것 같아요.<br>✅ <b>① 그럼 거기로 다시 가 볼까요?</b>: он назвал лучший магазин (первый), логично предложить «тогда сходим туда ещё раз?».<br>✖️ ② «были только в одном месте» — обошли несколько; ③ «купить ЭТОТ диван» — они не у дивана сейчас; ④ «купил в магазине у дома» — они ещё выбирают.<br>🧩 둘러보다 — обойти, осмотреть; 소파 — диван; 낫다 — лучше; -(으)ㄹ까요? — может, …?"},{"n":6,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["면접 날짜를 다시 확인하고 알려 줘.","준비 많이 했으니까 잘할 수 있을 거야.","면접 보기 전인데 아주 떨린다니 대단하다.","생각하지 못한 질문을 받아서 정말 놀랐겠다."],"answer":2,"explain":"🎧 남자: 수미야, 오늘 면접 있지? 면접 잘 봐. 여자: 어쩌지? 벌써부터 너무 떨려서 아무 생각이 안 나.<br>✅ <b>② 준비 많이 했으니까 잘할 수 있을 거야</b>: она нервничает перед собеседованием — естественно подбодрить: «ты много готовилась, у тебя получится».<br>✖️ ① про дату собеседования — не в тему; ③ «удивительно, что нервничаешь» — неуместно; ④ «получил неожиданный вопрос» — собеседование ещё не было.<br>🧩 면접 — собеседование; 떨리다 — нервничать; 면접을 보다 — проходить собеседование; 잘하다 — справиться."},{"n":7,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["맞아요. 이전 작품은 내용이 별로였어요.","그래요? 이 드라마 다 보면 다른 작품도 봐야겠어요.","맞아요. 이 드라마는 몇 번을 다시 봐도 재미있네요.","그래요? 이 작가가 처음으로 쓴 작품인 줄 몰랐어요."],"answer":2,"explain":"🎧 남자: 이 드라마 처음 보는데 내용도 좋고 대사도 재미있네요. 여자: 그렇죠? 이 드라마 쓴 작가의 작품들은 다 재미있어요.<br>✅ <b>② 그래요? 이 드라마 다 보면 다른 작품도 봐야겠어요</b>: ему сказали, что все работы этого автора хороши — логично «надо будет посмотреть и другие после этой».<br>✖️ ① «прежняя работа была так себе» — противоречит «다 재미있어요»; ③ «пересматриваю много раз» — он смотрит ВПЕРВЫЕ; ④ «не знал, что это первая работа» — речь не о том.<br>🧩 대사 — реплики; 작가 — автор; 작품 — произведение; -아/어야겠다 — надо бы."},{"n":8,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["얼룩이 잘 지워진 것 같아요.","운동화를 깨끗하게 신으셨네요.","해 봐야 알겠지만 최대한 없애 볼게요.","집에 돌아가서 다시 한번 지워 보려고요."],"answer":3,"explain":"🎧 여자: 손님, 운동화에 얼룩이 많네요. 생긴 지 꽤 오래된 거 같은데요. 남자: 네, 제가 집에서 해 봤는데 안 지워지더라고요. 깨끗하게 될까요?<br>✅ <b>③ 해 봐야 알겠지만 최대한 없애 볼게요</b>: клиент спрашивает, отчистятся ли пятна; работница химчистки отвечает «точно скажу, только попробовав, но постараюсь убрать по максимуму».<br>✖️ ① «пятна уже отчистились» — их ещё не чистили; ② «чисто носили обувь» — наоборот, пятна; ④ «дома сам попробую ещё раз» — это реплика клиента, а ответ за работницей.<br>🧩 얼룩 — пятно; 지워지다 — отчищаться; 최대한 — максимально; 없애다 — устранять."},{"n":9,"points":2,"instr":"Что женщина сделает следующим действием?","options":["김밥을 산다.","기차를 탄다.","자리에 앉는다.","카페로 들어간다."],"answer":1,"explain":"🎧 여자: 기차 탈 때까지 시간이 좀 남았네. 남자: 그러네. 저 카페에서 커피 한잔 마시자. 여자: 응. 난 기차에서 먹을 김밥 좀 사서 갈 테니까 먼저 들어가 있어. 남자: 알았어. 카페에 앉아 있을게.<br>✅ <b>① 김밥을 산다</b>: до поезда есть время; женщина говорит, что купит кимпап в дорогу, а мужчина пусть идёт в кафе первым → дальше она идёт за кимпапом.<br>✖️ ② на поезд сядут позже; ③ садится мужчина в кафе; ④ в кафе первым идёт мужчина.<br>🧩 김밥 — кимпап; 먼저 — сначала; 들어가다 — заходить; -(으)ㄹ 테니까 — раз я (сделаю), то…"},{"n":10,"points":2,"instr":"Что женщина сделает следующим действием?","options":["고객 대기실로 간다.","남자에게 열쇠를 준다.","차의 상태를 확인한다.","차를 수리하려고 예약한다."],"answer":1,"explain":"🎧 여자: 자동차 수리하러 왔는데요. 김수미로 예약했어요. 남자: 네, 차 열쇠 주시고 고객 대기실에서 잠깐 기다려 주세요. 여자: 열쇠는 차 안에 두었어요. 대기실은 이쪽으로 가면 되나요? 남자: 네, 자동차 상태 확인하고 말씀드리겠습니다.<br>✅ <b>① 고객 대기실로 간다</b>: ключ уже в машине, осталось пройти в комнату ожидания (она уточняет дорогу «이쪽으로 가면 되나요?»).<br>✖️ ② ключ уже оставлен в машине; ③ состояние машины проверит мужчина; ④ она уже записана.<br>🧩 수리하다 — ремонтировать; 대기실 — комната ожидания; 열쇠 — ключ; 상태 — состояние."},{"n":11,"points":2,"instr":"Что женщина сделает следующим действием?","options":["물감을 찾아본다.","미술 연필을 고른다.","직원에게 물어본다.","남자에게 제품 이름을 말한다."],"answer":3,"explain":"🎧 남자: 수미 씨, 미술 연필은 골랐어요. 더 살 게 있어요? 여자: 물감을 사야 하는데 찾는 게 안 보이네요. 남자: 제품 이름 알려 줘요. 직원한테 그 제품이 있는지 물어볼게요. 여자: 아니에요. 제가 물어보고 올 테니까 민수 씨는 여기에서 기다려요.<br>✅ <b>③ 직원에게 물어본다</b>: нужной краски не видно; женщина отказывается от помощи мужчины и говорит «я сама схожу спрошу» → дальше идёт спросить у сотрудника.<br>✖️ ① краску она уже искала (안 보이네요); ② карандаши выбрал мужчина; ④ она как раз отказалась называть название мужчине.<br>🧩 물감 — краски; 직원 — сотрудник; 물어보다 — спрашивать; 제품 — товар."},{"n":12,"points":2,"instr":"Что женщина сделает следующим действием?","options":["촬영팀에게 연락한다.","진행 순서를 설명한다.","공연 무대를 점검한다.","공연팀을 데리러 간다."],"answer":4,"explain":"🎧 여자: 무대 점검 끝났습니다. 이제 무대 연습 진행할까요? 남자: 네. 지금 무대 앞으로 공연팀들을 데리고 와 줄래요? … 여자: 알겠습니다. 촬영팀한테 연습 시작할 거라고 연락할까요? 남자: 그건 제가 할게요. 얼른 다녀오세요.<br>✅ <b>④ 공연팀을 데리러 간다</b>: мужчина просит привести команды к сцене, а звонок съёмочной группе берёт на себя → женщина идёт за выступающими.<br>✖️ ① съёмочной группе позвонит мужчина; ② порядок объясняет мужчина; ③ проверку сцены уже закончили.<br>🧩 무대 — сцена; 점검 — проверка; 공연팀 — команда выступающих; 데리러 가다 — идти за (кем-то)."},{"n":13,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["길이 예전에 비해 좁아졌다.","여자는 이곳에 처음 와 봤다.","남자는 인주서점에 간 적이 없다.","인주서점은 지금까지 같은 자리에 있다."],"answer":4,"explain":"🎧 여자: 와, 10년 만에 와 보니까 여기 많이 변했다. 남자: 응, … 길도 넓어지고 가게도 많아지고. 여자: 어, 그런데 저기 인주서점은 아직도 그대로 있어. 남자: 정말이네. 우리 대학 다닐 때 전공 책 사러 자주 갔었잖아.<br>✅ <b>④</b>: книжный «Инджу» по-прежнему на том же месте (아직도 그대로 있어).<br>✖️ ① дороги РАСШИРИЛИСЬ (넓어지고), не сузились; ② женщина была здесь и 10 лет назад (10년 만에 와 보니까), не впервые; ③ мужчина ЧАСТО туда ходил (자주 갔었잖아).<br>🧩 변하다 — меняться; 그대로 — как есть, без изменений; 전공 책 — учебники по специальности; 넓어지다 — расширяться."},{"n":14,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["분실물은 구두 매장에 있었다.","오후 8시에 지갑이 발견되었다.","고객 센터는 구두 매장 옆에 있다.","지갑을 잃어버린 사람은 1층으로 가면 된다."],"answer":1,"explain":"🎧 (объявление) 고객 센터에 빨간색 지갑을 보관하고 있습니다. 지갑은 조금 전에 1층 구두 매장에서 발견되었습니다. … 여덟 시에 백화점이 문을 닫으니 … 5층에 있는 고객 센터로 와 주시기 바랍니다.<br>✅ <b>①</b>: потерянный кошелёк нашли в обувном отделе (1층 구두 매장에서 발견).<br>✖️ ② 8 часов — это время ЗАКРЫТИЯ, а нашли «조금 전» (недавно); ③ центр на 5 этаже, обувной на 1 — не рядом; ④ владельцу нужно на 5 этаж (고객 센터), а не на 1.<br>🧩 분실물 — потерянная вещь; 보관하다 — хранить; 발견되다 — быть найденным; 문을 닫다 — закрываться."},{"n":15,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 사고는 어젯밤에 발생했다.","이 사고로 인해 사람들이 크게 다쳤다.","경찰은 사고 원인에 대해 조사하고 있다.","낚싯배가 다른 배와 충돌하는 사고가 났다."],"answer":3,"explain":"🎧 (новости) 오늘 새벽 네 시경, 인주 앞바다에서 낚싯배가 바위에 부딪치는 사고가 발생했습니다. … 다친 사람은 없었습니다. 현재 경찰은 … 정확한 사고 원인을 파악하고 있습니다.<br>✅ <b>③</b>: полиция расследует причину аварии (사고 원인을 파악하고 있습니다).<br>✖️ ① авария произошла СЕГОДНЯ на рассвете (오늘 새벽), не вчера ночью; ② пострадавших НЕТ (다친 사람은 없었습니다); ④ лодка ударилась о СКАЛУ (바위에 부딪치는), а не столкнулась с другой лодкой.<br>🧩 낚싯배 — рыбацкая лодка; 부딪치다 — врезаться; 구조되다 — быть спасённым; 사고 원인 — причина происшествия."},{"n":16,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["여자는 수술 과정에 참여한다.","여자는 보호자의 집에서 동물을 돌본다.","여자의 직업은 사람들에게 잘 알려져 있다.","동물의 상태를 관찰하는 일은 여자의 업무가 아니다."],"answer":1,"explain":"🎧 여자: 저는 동물 병원에서 아픈 동물을 돌보는 일을 하는데요. … 수의사가 진찰을 하거나 수술할 때 옆에서 돕는 일도 하죠. 그리고 보호자가 동물을 집에서 돌볼 때 주의할 사항을 알려 드리기도 합니다.<br>✅ <b>①</b>: женщина участвует в процессе операции (수술할 때 옆에서 돕는 일도 하죠).<br>✖️ ② она ухаживает за животными в ветклинике, а хозяевам лишь даёт советы; ③ её профессию многие НЕ знают (직업을 모르는 분들이 많은데요); ④ осмотр состояния животного КАК РАЗ её работа (상태도 살피고).<br>🧩 동물보건사 — ветеринарный ассистент; 수의사 — ветеринар; 처방 — рецепт; 보호자 — хозяин животного."},{"n":17,"points":2,"instr":"Выберите главную мысль мужчины.","options":["저녁 식사를 미리 준비해 두어야 한다.","음식을 한꺼번에 많이 먹지 않는 것이 좋다.","건강을 위해서 식사를 규칙적으로 해야 한다.","피곤할 때는 저녁을 밖에서 사 먹는 것이 좋다."],"answer":4,"explain":"🎧 남자: 피곤한데 오늘 저녁은 밖에서 먹고 들어가요. 여자: 그냥 집에 가서 먹어요. … 남자: 피곤해서 집에 갈 힘도 없어요. 이럴 땐 그냥 밖에서 사 먹어요.<br>✅ <b>④</b>: мужчина устал и настаивает поесть вне дома — «когда устал, лучше поужинать в кафе».<br>✖️ ① «заранее готовить ужин» — наоборот; ② про переедание — нет; ③ про режим питания — нет.<br>🧩 피곤하다 — уставший; 사 먹다 — поесть готовое (купить); 식사 준비 — готовка; 힘이 없다 — нет сил."},{"n":18,"points":2,"instr":"Выберите главную мысль мужчины.","options":["친구가 힘들 때는 옆에 있어 줘야 한다.","여러 사람과 잘 지내기 위해 노력할 필요가 있다.","다른 사람과 함께 있을 때는 말을 조심해야 한다.","친구와 문제가 생겼을 때는 빨리 해결하는 것이 좋다."],"answer":1,"explain":"🎧 남자: 민수가 여자 친구랑 헤어져서 힘든가 봐. 우리 만나서 위로해 주자. 여자: … 혼자 있게 해 주는 게 좋지 않을까? 남자: 지금이 바로 우리가 같이 있어 줘야 할 때지. 그것만으로도 큰 힘이 될 거야.<br>✅ <b>①</b>: мужчина считает, что другу в трудный момент нужно быть рядом.<br>✖️ ② про общение со многими людьми — нет; ③ про осторожность в словах — нет; ④ про «быстро решить проблему» — речь о поддержке, а не о решении.<br>🧩 헤어지다 — расставаться; 위로하다 — утешать; 옆에 있어 주다 — быть рядом; 힘이 되다 — поддерживать."},{"n":19,"points":2,"instr":"Выберите главную мысль мужчины.","options":["여행은 여유롭게 하는 것이 좋다.","여행을 자주 가는 것은 좋지 않다.","여행에서 다양한 경험을 해 봐야 한다.","여행에 필요한 예산을 정해 놓을 필요가 있다."],"answer":1,"explain":"🎧 여자: 오늘 여행 일정이 많아서 서둘러야 해요. … 남자: 일정이 너무 많아요. 전 좀 여유롭게 여행하고 싶어요. … 남자: 그래도 시간을 갖고 천천히 보면 좋겠어요. 일정을 좀 줄이죠.<br>✅ <b>①</b>: мужчина хочет не спешить и сократить плотный план — «путешествовать лучше неспешно».<br>✖️ ② про частоту поездок — нет; ③ «разнообразный опыт» — это позиция женщины; ④ про бюджет — нет.<br>🧩 일정 — план, расписание; 여유롭게 — неспешно; 서두르다 — торопиться; 줄이다 — сокращать."},{"n":20,"points":2,"instr":"Выберите главную мысль мужчины.","options":["광고를 짧게 만드는 것이 효과적이다.","광고는 대중의 호기심을 자극해야 한다.","광고는 제품의 정보를 사실대로 전달해야 한다.","광고는 보는 사람이 쉽게 이해할 수 있어야 한다."],"answer":2,"explain":"🎧 남자: … 저는 호기심을 자극하는 것에 중점을 둡니다. … 무엇을 광고하는 것인지 끝까지 봐야 알 수 있도록 숨기는 거죠. 이렇게 대중의 궁금증을 유발하는 겁니다.<br>✅ <b>②</b>: режиссёр делает упор на любопытство — «реклама должна возбуждать любопытство публики».<br>✖️ ① про краткость рекламы — нет; ③ «честно передавать инфо о товаре» — это про обычные ролики, не его подход; ④ «лёгкость понимания» — наоборот, он СКРЫВАЕТ суть.<br>🧩 광고 — реклама; 호기심 — любопытство; 자극하다 — стимулировать; 궁금증을 유발하다 — вызывать интерес."},{"n":21,"points":2,"instr":"Выберите главную мысль мужчины.","options":["회의 내용을 빠짐없이 기록해야 한다.","회의 때 낭비되는 종이를 줄이는 것이 좋다.","회의실을 지금보다 더 큰 장소로 바꿔야 한다.","발표 자료는 알아보기 쉽게 만드는 것이 좋다."],"answer":2,"explain":"🎧 남자: 그건 참석자들에게 미리 이메일로 보냈죠. 회의 때마다 낭비되는 종이가 너무 많은 것 같아서. … 앞으로는 발표 자료도 필요한 경우에만 복사하죠. … 굳이 종이를 사용할 필요 없잖아요.<br>✅ <b>②</b>: мужчина хочет сократить расход бумаги на совещаниях (рассылает по почте, копирует только при необходимости).<br>✖️ ① про подробную запись — нет; ③ менять зал он не предлагает; ④ про «понятность материалов» — нет.<br>🧩 낭비되다 — растрачиваться; 종이 — бумага; 줄이다 — сокращать; 복사하다 — копировать."},{"n":22,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이번 회의는 발표 자료 없이 진행된다.","여자는 회의에서 쓸 자료를 복사할 예정이다.","남자는 회의 때 대형 화면을 사용한 적이 있다.","여자는 참석자들에게 참고할 자료를 이미 이메일로 보내 놓았다."],"answer":3,"explain":"🎧 여자: 지난번 회의처럼 대형 화면을 사용하실 거지요? 남자: 네.<br>✅ <b>③</b>: «как в прошлый раз» — мужчина уже пользовался большим экраном на совещании.<br>✖️ ① совещание идёт С материалами (大형 화면, скопированные материалы); ② презентацию она УЖЕ скопировала (복사해서 갖다 놓았습니다); ④ справочные материалы по почте разослал МУЖЧИНА (그건 … 이메일로 보냈죠), а не женщина.<br>🧩 대형 화면 — большой экран; 참석자 — участник; -(으)ㄴ 적이 있다 — доводилось; 미리 — заранее."},{"n":23,"points":2,"instr":"Что делает мужчина (с какой целью говорит)?","options":["가게의 위치를 확인하고 있다.","가게 운영에 대해 조언을 구하고 있다.","구매할 물건의 사용 방법을 물어보고 있다.","원하는 조건의 물건이 있는지 알아보고 있다."],"answer":4,"explain":"🎧 남자: 카페에서 케이크 보관용으로 사용할 냉장고를 찾고 있는데요. 사용 기간이 얼마 안 된 중고 냉장고 있을까요? … 안이 안 보여도 돼요. … 사이즈가 컸으면 좋겠어요.<br>✅ <b>④</b>: мужчина перечисляет условия (б/у, без стеклянной дверцы, большой) и узнаёт, есть ли подходящий товар.<br>✖️ ① адрес магазина не уточняет; ② совета по бизнесу не просит; ③ способ использования не спрашивает.<br>🧩 보관용 — для хранения; 중고 — б/у; 유리문 — стеклянная дверца; 조건 — условие."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["여자의 가게에는 크기가 큰 냉장고가 없다.","남자는 카페에서 케이크를 팔지 않기로 했다.","남자의 카페에는 유리문이 달린 냉장고가 있다.","여자의 가게에서는 새로 나온 제품만 판매한다."],"answer":3,"explain":"🎧 여자: 유리문이 달린 걸 찾으시는 거지요? 남자: 아니요. 그건 이미 설치돼 있어요. 주방에서 쓸 거라서…<br>✅ <b>③</b>: холодильник со стеклянной дверцей у него в кафе УЖЕ есть (그건 이미 설치돼 있어요).<br>✖️ ① у женщины как раз ЕСТЬ большой (크기도 크고); ② он продаёт торты (손님들이 보고 살 수 있게); ④ магазин торгует и б/у (6개월 정도 사용한 거), не только новым.<br>🧩 설치되다 — быть установленным; 주방 — кухня; 중고 — б/у; 판매하다 — продавать."},{"n":25,"points":2,"instr":"Выберите главную мысль мужчины.","options":["마을 축제에 대한 주민들의 관심이 필요하다.","마을의 특징을 활용한 것이 축제의 성공 비결이다.","축제에서 판매할 기념품을 새로 제작하는 것이 좋다.","축제를 기획할 때 성공 사례를 충분히 검토해야 한다."],"answer":2,"explain":"🎧 남자: 마을의 장점을 살린 것이 좋은 결과로 이어졌다고 생각합니다. … 이런 특색을 활용해서 축제를 기획한 것이 관광객의 발길을 이끌었죠.<br>✅ <b>②</b>: успех фестиваля — в том, что использовали особенность деревни (поля подсолнухов).<br>✖️ ① про «интерес жителей» — нет; ③ про новые сувениры — нет; ④ про «изучение чужих успехов» — нет.<br>🧩 해바라기 — подсолнух; 특색 — особенность; 활용하다 — использовать; 비결 — секрет."},{"n":26,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 마을을 아는 사람이 거의 없다.","이 마을에서 축제가 올해 처음으로 열렸다.","이 마을의 해바라기 들판은 최근에 만들어졌다.","이 마을의 특산품이 관광객에게 좋은 반응을 얻었다."],"answer":4,"explain":"🎧 남자: 특히 해바라기 씨로 만든 기름이 관광객들에게 인기가 좋습니다.<br>✅ <b>④</b>: местный продукт (масло из семян подсолнуха) хорошо принят туристами.<br>✖️ ① деревня — «자랑», известна благодаря фестивалю; ② фестивалю уже 3 года (3주년), не первый; ③ поля подсолнухов «оригинально_давно» (오래전부터), не недавно.<br>🧩 특산품 — местный специалитет; 반응을 얻다 — получить отклик; 들판 — поле; 자랑 — гордость."},{"n":27,"points":2,"instr":"С какой целью говорит мужчина?","options":["이 과자의 맛이 달라진 것을 지적하려고","이 과자를 생산하게 된 이유를 알려 주려고","이 과자의 생산이 중단될 것이라는 소식을 전하려고","이 과자를 구하기 어려운 것에 대한 불만을 말하려고"],"answer":4,"explain":"🎧 남자: … 맛있다고 해서 한번 먹어 보고 싶은데 살 수가 없네. 여기저기 다 품절이래. … 이렇게까지 사기 어려운 게 말이 돼?<br>✅ <b>④</b>: мужчина хочет попробовать новинку, но её нигде не купить — он выражает недовольство тем, что её так трудно достать.<br>✖️ ① про изменение вкуса — нет; ② причину выпуска не сообщает; ③ об остановке производства речи нет.<br>🧩 품절 — распродано; 수요 — спрос; 불만 — недовольство; 말이 되다 — быть логичным."},{"n":28,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 회사는 작업 시간을 늘렸다.","남자는 이 과자를 구입한 적이 있다.","이 과자는 사람들의 관심을 끌지 못했다.","여자는 남자에게 이 과자에 대해 처음 들었다."],"answer":1,"explain":"🎧 여자: 평소보다 네 시간이나 더 작업해서 생산량을 두 배나 늘렸대.<br>✅ <b>①</b>: компания увеличила рабочее время (на 4 часа больше обычного, удвоив выпуск).<br>✖️ ② мужчина как раз НЕ может купить (살 수가 없네); ③ печенье очень популярно (수요가 많아서); ④ женщина узнала о нём из НОВОСТЕЙ (뉴스에서 들었는데), а не от мужчины.<br>🧩 작업 시간 — рабочее время; 늘리다 — увеличивать; 생산량 — объём выпуска; 수요 — спрос."},{"n":29,"points":2,"instr":"Кто такой мужчина (чем он занимается)?","options":["도로를 정비하는 사람","교통 상황을 촬영하는 사람","도로에 CCTV를 설치하는 사람","방송에서 교통 상황을 알려 주는 사람"],"answer":4,"explain":"🎧 남자: 저는 매일 … 30분마다 교통 정보를 안내하고 있는데요. 도로에 설치된 여러 대의 CCTV와 시민들이 보낸 문자를 보고 교통 상황을 분석해 시민들에게 전달합니다.<br>✅ <b>④</b>: каждые 30 минут он сообщает в эфире дорожную обстановку → ведущий, информирующий о трафике.<br>✖️ ① дороги не ремонтирует; ② сам не снимает обстановку (смотрит CCTV); ③ камеры не устанавливает.<br>🧩 교통 정보 — дорожная информация; 방송 — эфир; 분석하다 — анализировать; 전달하다 — передавать."},{"n":30,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["남자는 매일 오후에 근무를 시작한다.","남자는 이 일을 할 때 긴장하지 않는다.","남자는 CCTV를 분석하는 일을 하지 않는다.","남자의 일에는 시민들이 보낸 문자를 보는 것이 포함된다."],"answer":4,"explain":"🎧 남자: … CCTV와 시민들이 보낸 문자를 보고 교통 상황을 분석해 …<br>✅ <b>④</b>: в его работу входит чтение СМС от граждан.<br>✖️ ① он начинает в 6 УТРА (오전 여섯 시부터); ② расслабиться нельзя (긴장을 늦출 수 없죠); ③ он КАК РАЗ анализирует CCTV.<br>🧩 근무 — работа, дежурство; 긴장 — напряжение; 포함되다 — включаться; 문자 — СМС."},{"n":31,"points":2,"instr":"Выберите главную мысль мужчины.","options":["시설을 다른 지역으로 옮겨서 설치해야 한다.","시설의 설치 효과에 대한 명확한 검증이 필요하다.","시설 설치에 대한 반대는 홍보를 통해 해결할 수 있다.","시설의 설치 사실을 주민들에게 바로 알리지 않는 것이 좋다."],"answer":3,"explain":"🎧 남자: 지속적으로 주민 설명회를 열어 … 안전성을 충분히 설명하고 … 사례를 적극적으로 알리면 우려하는 부분은 곧 해결될 겁니다. … 보상 … 사실도 대대적으로 알리면 주민들의 인식도 분명히 바뀔 겁니다.<br>✅ <b>③</b>: мужчина считает, что сопротивление жителей снимается информированием/PR (разъяснения, реклама, примеры).<br>✖️ ① переносить объект он не предлагает; ② «проверка эффекта» — не его мысль; ④ «не сообщать жителям» — наоборот, он за активное информирование.<br>🧩 폐기물 처리 시설 — объект переработки отходов; 반발 — протест; 홍보 — информирование, PR; 인식 — восприятие."},{"n":32,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["앞으로 일어날 문제에 대해 걱정하고 있다.","자신의 의견대로 될 것임을 확신하고 있다.","상대방에게 객관적인 근거를 요구하고 있다.","상황이 심각해진 것에 대한 책임을 묻고 있다."],"answer":2,"explain":"🎧 (те же дебаты) мужчина повторяет «곧 해결될 겁니다», «분명히 바뀔 겁니다» — уверенно утверждает, что всё выйдет по его плану.<br>✅ <b>②</b>: уверен, что будет так, как он считает.<br>✖️ ① опасения высказывает женщина; ③ объективных доказательств он не «требует»; ④ ответственность ни с кого не спрашивает.<br>🧩 확신하다 — быть уверенным; 분명히 — определённо; 근거 — основание; 책임을 묻다 — призывать к ответу."},{"n":33,"points":2,"instr":"О чём этот рассказ?","options":["음악을 감상하는 올바른 방법","음악적 재능이 발달하는 결정적 시기","노인을 대상으로 하는 연구에서 주의할 점","음악 활동이 노인의 인지 기능에 미치는 영향"],"answer":4,"explain":"🎧 여자: … 음악 활동이 … 인지 기능이 떨어지는 것을 막는 데 도움이 될 거라는 가설 … 피아노를 배운 집단은 인지 기능이 떨어지지 않았습니다. … 긍정적으로 작용한 거죠.<br>✅ <b>④</b>: тема — как музыкальные занятия влияют на когнитивные функции пожилых.<br>✖️ ① «как правильно слушать музыку» — нет; ② «критический период развития таланта» — нет; ③ «на что обращать внимание в исследованиях» — нет.<br>🧩 노화 — старение; 인지 기능 — когнитивная функция; 가설 — гипотеза; 저하 — снижение."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 연구를 위한 실험은 1년 동안 진행됐다.","이 실험의 결과는 연구팀의 예상과 같았다.","이 실험에서 두 집단은 동일한 결과를 보였다.","이 실험은 음악을 전공한 사람들을 대상으로 했다."],"answer":2,"explain":"🎧 여자: 연구팀의 예상대로 음악 활동이 인지 기능의 저하를 막는 데 긍정적으로 작용한 거죠.<br>✅ <b>②</b>: результат совпал с ожиданием исследователей.<br>✖️ ① эксперимент длился 6 месяцев (6개월간), не год; ③ группы дали РАЗНЫЕ результаты (контрольная — снижение, «пианино» — нет); ④ участники — пожилые БЕЗ музыкального образования (전문적으로 배운 적이 없는 노인들).<br>🧩 예상 — ожидание; 집단 — группа; 동일하다 — одинаковый; 전공하다 — специализироваться."},{"n":35,"points":2,"instr":"Что делает мужчина (с какой целью говорит)?","options":["이 편지가 가지는 가치와 의의를 알리고 있다.","이 편지의 보존 상태에 대해 아쉬움을 표하고 있다.","이 편지가 발견된 장소와 발굴 과정을 보고하고 있다.","이 편지를 연구하는 데 도움을 준 사람들에게 감사하고 있다."],"answer":1,"explain":"🎧 남자: … 평범한 사람이 쓴 일상적인 내용의 편지지만 학술적, 역사적 가치는 매우 큽니다. … 언어생활 … 생활상과 복식 문화 등을 알 수 있기 때문입니다.<br>✅ <b>①</b>: мужчина рассказывает о ценности и значимости письма (ставшего нац. сокровищем).<br>✖️ ② сожаления о сохранности нет; ③ место находки/раскопок не докладывает; ④ благодарностей исследователям нет.<br>🧩 보물 — сокровище, реликвия; 지정되다 — быть присвоенным (статус); 학술적 — научный; 의의 — значимость."},{"n":36,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 편지는 곧 박물관에 전시될 것이다.","이 편지는 군인인 남편이 아내에게 쓴 것이다.","이 편지가 어느 시대의 것인지 밝혀지지 않았다.","이 편지를 보물로 지정하기 위한 논의가 진행 중이다."],"answer":2,"explain":"🎧 남자: 이 편지는 조선 초기 한 군인이 아내에게 보낸 것인데요.<br>✅ <b>②</b>: письмо написал муж-военный своей жене.<br>✖️ ① оно УЖЕ выставлено (전시되어 있는); ③ известно, что это ранний Чосон (조선 초기); ④ статус сокровища УЖЕ присвоен (국가 보물로 지정된).<br>🧩 군인 — военный; 남편 — муж; 당부 — наказ; 복식 문화 — культура одежды."},{"n":37,"points":2,"instr":"Выберите главную мысль женщины.","options":["목재를 수출하기 위한 경로를 확보해야 한다.","산림 순환 경영을 통해 좋은 효과를 얻을 수 있다.","좋은 목재를 얻을 수 있는 나무를 심는 것이 좋다.","산림 순환 경영이 정착될 때까지 시간이 필요하다."],"answer":2,"explain":"🎧 여자: … 오래된 나무를 베어 내고 어린나무를 심는 방식의 산림 순환 경영을 도입해 관리해야 합니다. … 목재 수입량을 크게 줄일 수 있습니다.<br>✅ <b>②</b>: циклическое лесное хозяйство даёт двойную пользу — поглощение углерода и сокращение импорта древесины.<br>✖️ ① про экспорт древесины — нет; ③ «сажать деревья ради хорошей древесины» — не суть; ④ про «время на внедрение» — нет.<br>🧩 산림 — лес; 순환 경영 — циклическое управление; 탄소 흡수 — поглощение углерода; 목재 — древесина."},{"n":38,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["한국은 목재 수입 비중이 낮은 편이다.","한국은 산림 순환 경영을 시행하고 있다.","나무가 30년 이상 되면 탄소 흡수 능력이 떨어진다.","한국의 산에는 심은 지 얼마 안 된 어린나무가 많다."],"answer":3,"explain":"🎧 여자: 나무가 30년 이상 되면 탄소를 흡수하고 저장하는 능력이 현저히 떨어지기 때문이죠.<br>✅ <b>③</b>: у деревьев старше 30 лет резко падает способность поглощать углерод.<br>✖️ ① доля импорта древесины в Корее ВЫСОКА (상당히 높은데); ② это ещё нужно ВНЕДРИТЬ (도입해 관리해야), не делают; ④ в лесах много СТАРЫХ деревьев (30년 이상, 72%).<br>🧩 목재 수입 — импорт древесины; 시행하다 — осуществлять; 탄소 흡수 능력 — способность поглощать углерод; 고령화 — старение."},{"n":39,"points":2,"instr":"Что было сказано ДО этого разговора?","options":["인공위성을 관측하는 신기술이 개발되었다.","대기권에서 인공위성이 폭발하는 사고가 있었다.","우주 조약을 개정하기 위해 여러 나라 사람들이 모였다.","우주 탐사를 위한 인력을 양성하는 것은 쉬운 일이 아니다."],"answer":2,"explain":"🎧 여자: 박사님, 대기권에서 그런 위험한 사고가 발생했었군요. … 남자: … 앞서 말씀드린 것과 같은 폭발 사고는 더 많아질 겁니다.<br>✅ <b>②</b>: реплика подытоживает «оказывается, в атмосфере произошла такая опасная авария», а мужчина ссылается на «упомянутую ранее аварию со взрывом» → до этого речь шла о взрыве спутника в атмосфере.<br>✖️ ① про новую технологию наблюдения — нет; ③ про собрание стран — нет; ④ про подготовку кадров — нет.<br>🧩 대기권 — атмосфера; 인공위성 — спутник; 폭발 — взрыв; 조약 — договор."},{"n":40,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["얼마 전에 국제 우주법이 제정되었다.","우주 조약은 구체적인 내용으로 구성되어 있다.","우주 조약은 강제적인 효력을 가지고 있지 않다.","인공위성으로 인한 전파 방해 문제는 일어나지 않을 것이다."],"answer":3,"explain":"🎧 남자: 문제는 내용이 구체적이지 않고 꼭 지켜야 한다는 강제성이 없다는 거죠.<br>✅ <b>③</b>: космический договор не имеет обязательной (принудительной) силы.<br>✖️ ① международный космический закон ещё нужно ПРИНЯТЬ (제정해야), не принят; ② содержание договора как раз НЕ конкретно (구체적이지 않고); ④ радиопомехи МОГУТ возникать (전파 방해 같은 사고도 일어날 수 있고요).<br>🧩 강제성 — обязательность; 효력 — юридическая сила; 제정하다 — принимать (закон); 전파 방해 — радиопомехи."},{"n":41,"points":2,"instr":"О чём в основном эта лекция?","options":["제품의 품질은 부품의 질에 의해 결정된다.","제조업은 일자리 창출에 크게 기여하고 있다.","제품에 대한 고객의 의견을 반영하는 것이 중요하다.","제조업이 사업 영역 확장을 통해 발전을 도모하고 있다."],"answer":4,"explain":"🎧 여자: 제조업체들이 서비스업을 병행하며 사업 영역을 확장해 나가고 있습니다. … 엔진 판매와 함께 엔진 상태를 실시간으로 점검해 주는 서비스 사업도 … 이러한 방식을 통해 제조업이 한 단계 진화하고 있습니다.<br>✅ <b>④</b>: производство развивается, расширяя сферу деятельности (продажа + сервис).<br>✖️ ① «качество зависит от деталей» — нет; ② «создание рабочих мест» — нет; ③ «учёт мнения клиентов» — не суть.<br>🧩 제조업 — производство; 서비스업 — сфера услуг; 병행하다 — совмещать; 사업 영역 확장 — расширение сферы деятельности."},{"n":42,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 업체는 엔진 판매에 어려움을 겪고 있다.","조선업이 경제적으로 힘든 상황에 놓여 있다.","이 업체는 안정적인 수입을 얻지 못하고 있다.","이 업체는 실시간 엔진 점검 서비스 시스템을 마련했다."],"answer":4,"explain":"🎧 여자: 이 업체는 엔진 판매와 함께 엔진 상태를 실시간으로 점검해 주는 서비스 사업도 하고 있습니다. 서비스 시스템 구축에 많은 비용이 들어갔지만…<br>✅ <b>④</b>: компания создала систему сервиса по проверке двигателей в реальном времени.<br>✖️ ① продажи двигателей как раз ВЫРОСЛИ (판매가 활발해졌는데); ② судостроение ОЖИВАЕТ (경기가 살아나면서); ③ компания получает стабильный доход (안정적인 수입원이 되고 있고요).<br>🧩 실시간 — реальное время; 점검 — проверка; 마련하다 — создать, наладить; 수입원 — источник дохода."},{"n":43,"points":2,"instr":"О чём этот рассказ?","options":["종묘 정전의 건축미","종묘 정전의 건립 과정","종묘 정전의 관리 방법","종묘 정전의 현대적 기능"],"answer":1,"explain":"🎧 남자: … 그중 단연 눈에 띄는 것은 지붕이다. 가로길이만 101미터다. … 좌우가 완벽하게 대칭을 이룬 모습 … 단아한 기둥들이 절묘한 균형을 이루며 … 절제된 아름다움으로 신성하고 장엄한 분위기를 자아낸다.<br>✅ <b>①</b>: рассказ — об архитектурной красоте главного зала Чонмё (крыша 101 м, симметрия, сдержанная гармония).<br>✖️ ② процесс постройки не описан; ③ способ ухода — нет; ④ современная функция — нет.<br>🧩 종묘 — святилище Чонмё; 정전 — главный зал; 건축미 — архитектурная красота; 대칭 — симметрия."},{"n":44,"points":2,"instr":"Выберите верное описание главного зала Чонмё.","options":["지붕이 곡선 형태로 휘어 있다.","기둥에 화려한 색이 사용되었다.","도심에서 멀리 떨어진 곳에 있다.","왕과 왕비의 제사를 지내는 공간이다."],"answer":4,"explain":"🎧 남자: 조선의 역대 왕과 왕비의 제사를 모시는 종묘의 정전이다.<br>✅ <b>④</b>: это место, где совершают обряды поминовения королей и королев.<br>✖️ ① крыша вытянута ПРЯМОЙ линией (수평선처럼 일직선), не изогнута; ② на колоннах НЕТ ярких красок (화려한 색깔 하나 없는); ③ находится в самом ЦЕНТРЕ Сеула (서울 도심 한가운데), не вдали.<br>🧩 제사 — поминальный обряд; 지붕 — крыша; 기둥 — колонна; 도심 — центр города."},{"n":45,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["충수에는 염증이 잘 생기지 않는다.","충수는 소화가 잘되도록 돕는 일을 한다.","충수에는 유익한 미생물이 서식하고 있다.","충수를 제거하는 수술이 최근에 가능해졌다."],"answer":3,"explain":"🎧 여자: 충수가 장내 미생물을 비축해 두는 창고 역할을 한다는 것이죠. … 유산균 같은 미생물들이 대장으로 이동해 회복을 돕는다…<br>✅ <b>③</b>: в аппендиксе живут полезные микробы (он — «склад» кишечной микрофлоры, лактобактерий).<br>✖️ ① воспаление возникает ЛЕГКО (걸핏하면 염증을 일으켜); ② в пищеварении НЕ участвует (전혀 관여하지 않고); ④ удаление делали и раньше — наоборот, СЕЙЧАС исследуют, как СОХРАНИТЬ аппендикс.<br>🧩 충수 — аппендикс; 염증 — воспаление; 미생물 — микроорганизм; 서식하다 — обитать."},{"n":46,"points":2,"instr":"Каким образом женщина подаёт материал?","options":["유사한 사례들을 묶어 비교 분석하고 있다.","대상이 가진 문제의 주요 원인을 유추하고 있다.","대상의 역할에 대해 밝혀진 사실을 설명하고 있다.","다양한 연구를 바탕으로 자신만의 기준을 제시하고 있다."],"answer":3,"explain":"🎧 여자: 그런데 충수가 면역 기능을 강화하는 데 기여한다는 사실이 밝혀졌습니다. 충수가 장내 미생물을 비축해 두는 창고 역할을 한다는 것이죠.<br>✅ <b>③</b>: женщина объясняет выясненные факты о роли аппендикса (хранилище микробов, поддержка иммунитета).<br>✖️ ① похожие случаи не сравнивает; ② причину проблемы не выводит; ④ собственных критериев на основе исследований не предлагает.<br>🧩 충수 — аппендикс; 면역 기능 — иммунная функция; 밝혀지다 — выясняться; 역할 — роль."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["인건비와 임대료는 고정 비용에 포함되지 않는다.","소상공인의 경영난은 일률적 방식으로 해결할 수 있다.","대출 의존도가 높은 경우 채무를 조정해 주면 안 된다.","영업 비용 때문에 빚을 지는 소상공인이 많아지고 있다."],"answer":4,"explain":"🎧 여자: 수익이 줄면서 부족해진 영업 비용을 메우려고 불가피하게 빚을 내는 소상공인이 늘고 있습니다.<br>✅ <b>④</b>: растёт число мелких предпринимателей, влезающих в долги из-за операционных расходов.<br>✖️ ① зарплаты и аренда КАК РАЗ постоянные издержки (고정 비용); ② поддержка должна РАЗЛИЧАТЬСЯ по ситуации (지원 방식이 달라야), не единообразно; ③ при высокой долговой нагрузке долг как раз НАДО реструктурировать (채무를 조정해 줘야).<br>🧩 소상공인 — мелкий предприниматель; 영업 비용 — операционные расходы; 빚을 내다 — брать в долг; 고정 비용 — постоянные издержки."},{"n":48,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["소상공인계의 태도 변화를 기대하고 있다.","경제 위기 극복을 위한 소상공인의 노력에 감탄하고 있다.","소상공인에 대한 실효성 있는 지원 방안을 제안하고 있다.","소상공업의 활성화가 가져올 경제적 효과를 낙관하고 있다."],"answer":3,"explain":"🎧 남자: … 지원 방식이 달라야 … 채무를 조정해 줘야 … 고정 비용을 지원하는 게 효과적이고요. 이처럼 … 실질적인 도움이 되는 지원책이 하루빨리 마련되면 좋겠습니다.<br>✅ <b>③</b>: мужчина предлагает действенные меры поддержки (реструктуризация долга, помощь с постоянными издержками).<br>✖️ ① смены настроя предпринимателей не ждёт; ② их усилиями не «восхищается»; ④ об экономическом эффекте оптимистично не рассуждает.<br>🧩 실효성 — действенность; 지원 방안 — меры поддержки; 제안하다 — предлагать; 경영난 — трудности бизнеса."},{"n":49,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 철학자는 도덕성에 대해 일반적인 견해를 따르고 있다.","이 철학자는 도덕성을 평가하는 기준에서 감정을 배제했다.","이 철학자에 따르면 출근 시간을 지키는 것은 도덕적 의무가 아니다.","이 철학자에 따르면 어떤 상황에서도 다른 사람을 돕는 것이 최우선이다."],"answer":2,"explain":"🎧 남자: … 도덕적 의무만을 기준으로 … 동정심과 같은 행위자의 감정은 배제한 거죠.<br>✅ <b>②</b>: философ исключил эмоции из критерия оценки нравственности.<br>✖️ ① он идёт ВРАЗРЕЗ с общепринятым взглядом (보편적 견해와 달리); ③ соблюдение рабочего времени подаётся как нравственный выбор; ④ помощь из жалости он НЕ считает нравственно оправданной (정당한 행위가 아니라는).<br>🧩 도덕성 — нравственность; 감정 — эмоции; 배제하다 — исключать; 의무 — долг."},{"n":50,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["도덕적 행위의 당위성을 강조하고 있다.","도덕적 행위의 가치를 과대평가하고 있다.","도덕성에 대한 섣부른 판단을 경계하고 있다.","도덕성에 대한 연구의 필요성을 제기하고 있다."],"answer":3,"explain":"🎧 남자: … 어느 한 면만을 보고 누군가의 도덕성을 판단하는 걸 자제해야 한다는 점을 다시 생각하게 합니다.<br>✅ <b>③</b>: мужчина предостерегает от поспешных суждений о нравственности (по одной лишь стороне).<br>✖️ ① «должность» нравственного поступка не подчёркивает; ② ценность не «переоценивает»; ④ о необходимости исследований не заявляет.<br>🧩 섣부른 — поспешный; 판단 — суждение; 경계하다 — остерегаться; 자제하다 — воздерживаться."}]
      },
      reading: {
        durationMin: 70, total: 100, label: '제91회 · 읽기 (1~50)',
        questions: [{"n":1,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"나는 오래전에 설악산을 (        ).","options":["등산하고 싶다","등산해도 된다","등산할 것 같다","등산한 적이 있다"],"answer":4,"explain":"✅ <b>④ 등산한 적이 있다</b>: «오래전에» (давно) указывает на прошлый опыт → -(으)ㄴ 적이 있다 «доводилось, было дело».<br>✖️ ① 등산하고 싶다 — «хочу подняться» (желание); ② 등산해도 된다 — «можно подняться» (разрешение); ③ 등산할 것 같다 — «наверное, поднимусь» (предположение о будущем). С «давно» сочетается только опыт.<br>🧩 V-(으)ㄴ 적이 있다 — «доводилось делать»; 오래전에 — давным-давно; 등산하다 — ходить в горы."},{"n":2,"points":2,"instr":"Выберите подходящую форму в пропуск ( ).","passage":"새집으로 (        ) 가구를 새로 샀다.","options":["이사한 지","이사하거든","이사하려면","이사하고 나서"],"answer":4,"explain":"✅ <b>④ 이사하고 나서</b>: «переехав в новый дом, купил новую мебель» — действие ПОСЛЕ переезда → -고 나서 «после того как».<br>✖️ ① 이사한 지 — «с тех пор как переехал» (нужна длительность + 되다); ② 이사하거든 — «если/когда переедешь»; ③ 이사하려면 — «чтобы переехать».<br>🧩 V-고 나서 — «после того как сделал»; 이사하다 — переезжать; 가구 — мебель."},{"n":3,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"어려운 이웃을 <u>돕고자</u> 매년 봉사 활동에 참여하고 있다.","options":["돕기 위해서","돕는 대신에","돕기 무섭게","돕는 바람에"],"answer":1,"explain":"✅ <b>① 돕기 위해서</b>: -고자 выражает цель/намерение = «чтобы помочь» = -기 위해서.<br>✖️ ② 돕는 대신에 — «вместо того чтобы помогать»; ③ 돕기 무섭게 — «едва начав помогать»; ④ 돕는 바람에 — «из-за того что помог» (непреднамеренная причина).<br>🧩 V-고자 = V-기 위해서 — «с целью, чтобы»; 봉사 활동 — волонтёрство; 이웃 — сосед, ближний."},{"n":4,"points":2,"instr":"Выберите выражение, ближайшее по смыслу к подчёркнутому.","passage":"지난 3년 동안 영화를 한 편 봤으니 거의 안 <u>본 셈이다</u>.","options":["본 척했다","보기 나름이다","볼 수밖에 없었다","본 거나 마찬가지이다"],"answer":4,"explain":"✅ <b>④ 본 거나 마찬가지이다</b>: -(으)ㄴ 셈이다 «практически, всё равно что» = «거나 마찬가지이다» (то же самое, что). За 3 года один фильм — всё равно что не смотрел.<br>✖️ ① 본 척했다 — «сделал вид, что смотрел»; ② 보기 나름이다 — «смотря как смотреть»; ③ 볼 수밖에 없었다 — «не оставалось ничего, кроме как смотреть».<br>🧩 V-(으)ㄴ 셈이다 — «фактически, можно считать»; V-(으)ㄴ 거나 마찬가지이다 — «всё равно что»."},{"n":5,"points":2,"instr":"О чём этот текст?","passage":"입속 치아 사이를 깨끗이! 부드럽게 잘 닦여요~","options":["비누","칫솔","안경","수건"],"answer":2,"explain":"✅ <b>② 칫솔</b> (зубная щётка): «дочиста между зубами во рту, мягко и хорошо чистит» — это про зубную щётку.<br>✖️ ① 비누 — мыло; ③ 안경 — очки; ④ 수건 — полотенце. «치아 사이» (между зубами) указывает именно на щётку.<br>🧩 치아 — зуб; 닦이다 — чиститься (страдат. от 닦다); 부드럽게 — мягко."},{"n":6,"points":2,"instr":"О чём этот текст?","passage":"아이들의 예쁜 꿈과 희망을 키워 주는 곳, 부모의 마음으로 보살핍니다.","options":["은행","서점","유치원","우체국"],"answer":3,"explain":"✅ <b>③ 유치원</b> (детский сад): «место, что растит мечты и надежды детей, заботится с родительским сердцем».<br>✖️ ① 은행 — банк; ② 서점 — книжный; ④ 우체국 — почта. «아이들… 키워 주는 곳» — про детский сад.<br>🧩 키우다 — растить, воспитывать; 보살피다 — заботиться; 꿈과 희망 — мечты и надежды."},{"n":7,"points":2,"instr":"О чём этот текст?","passage":"계단으로 다니기! 하루 30분 운동하기! 우리 몸을 위해 실천하세요.","options":["건강 관리","안전 운전","전화 예절","절약 습관"],"answer":1,"explain":"✅ <b>① 건강 관리</b> (забота о здоровье): «ходите по лестнице! 30 минут зарядки в день! делайте это для тела».<br>✖️ ② 안전 운전 — безопасное вождение; ③ 전화 예절 — телефонный этикет; ④ 절약 습관 — привычка экономить. Речь о здоровье.<br>🧩 계단 — лестница; 실천하다 — претворять, делать на практике; 몸 — тело."},{"n":8,"points":2,"instr":"О чём этот текст?","passage":"· 공연장 내에서는 사진 촬영을 금지합니다.\n· 휴대 전화는 전원을 끄거나 진동으로 해 주십시오.","options":["관람 규칙","제품 소개","사용 방법","예약 문의"],"answer":1,"explain":"✅ <b>① 관람 규칙</b> (правила просмотра): «в зале запрещена фотосъёмка; телефоны выключите или переведите на вибро» — это правила поведения зрителей.<br>✖️ ② 제품 소개 — описание товара; ③ 사용 방법 — инструкция; ④ 예약 문의 — вопросы по брони.<br>🧩 공연장 — концертный зал; 금지하다 — запрещать; 진동 — вибрация; 관람 — просмотр (зрелища)."},{"n":9,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с объявлением.","passage":"🚌 인주시 야경 관광버스 운행 안내 — 10월의 아름다운 밤을 즐겨 보세요.\n● 관람 장소: 인주역 광장 출발 → 인주시 전망대 → 별빛공원\n● 출발 시간: 매일 18:00\n● 이용 요금: 성인 10,000원 / 학생 5,000원 (7세 이하 무료)\n● 예약 방법: 출발 하루 전까지 홈페이지(www.inju-tour.com)에서 신청","options":["성인과 학생의 버스 요금이 같다.","이 버스는 별빛공원에서 출발한다.","매일 오전에 이 버스를 탈 수 있다.","이 버스를 타려면 미리 신청해야 한다."],"answer":4,"explain":"✅ <b>④</b>: «예약 방법: 출발 하루 전까지 … 신청» — нужно записаться заранее (за день до отправления).<br>✖️ ① взрослый 10 000, школьник 5 000 — тарифы разные; ② отправление с площади у вокзала (인주역 광장), а не из 별빛공원; ③ отправление ежедневно в 18:00 (вечер), не утром.<br>🧩 야경 — ночной вид; 운행 — движение (транспорта); 미리 신청하다 — записаться заранее; 무료 — бесплатно."},{"n":10,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с графиком.","passage":"📊 인주시 직장인, 출근길 이동 수단은? (직장인 1,000명 · 단위 %)\n· 자가용: 2012년 31 → 2022년 39\n· 버스: 28 → 21\n· 지하철: 24 → 27\n· 걸어서: 11 → 6\n· 기타: 5 → 8","options":["자가용으로 출퇴근한다고 응답한 직장인들의 비율이 줄었다.","걸어서 출퇴근하는 직장인은 2012년보다 2022년이 더 적었다.","2022년에는 지하철을 타고 출퇴근하는 직장인이 가장 많았다.","2012년에 직장인들은 출퇴근할 때 버스를 제일 많이 이용했다."],"answer":2,"explain":"✅ <b>②</b>: пешком — 11% (2012) → 6% (2022), значит в 2022 пеших стало меньше.<br>✖️ ① на авто 31→39 — доля ВЫРОСЛА, не упала; ③ в 2022 больше всего — авто (39%), а не метро (27%); ④ в 2012 чаще всего тоже авто (31%), а не автобус (28%).<br>🧩 출퇴근 — дорога на работу и с работы; 이동 수단 — средство передвижения; 자가용 — личный автомобиль; 줄다 — уменьшаться."},{"n":11,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"인주시가 작년에 이어 올해도 10월 한 달간 '찾아가는 자전거 수리 센터'를 운영한다. 평일에는 여러 지역을 직접 방문해 고쳐 주고 주말에는 인주공원에서 수리 서비스를 제공한다. 전문 수리 기사가 자전거를 무료로 고쳐 주고 부품 교체가 필요한 경우에는 저렴한 가격으로 바꿔 준다. 시는 시민들의 자전거 타기 생활화를 위해 이 수리 센터를 운영하는 것이라고 밝혔다.","options":["이 서비스는 일 년 내내 운영된다.","올해 처음으로 이 센터가 운영되기 시작했다.","주말에는 인주공원에서 수리를 받을 수 있다.","이 수리 센터에서는 무료로 부품을 교체해 준다."],"answer":3,"explain":"✅ <b>③</b>: «주말에는 인주공원에서 수리 서비스를 제공» — по выходным ремонт делают в парке Инджу.<br>✖️ ① работает только месяц в октябре (10월 한 달간), не круглый год; ② работает «작년에 이어 올해도» — не впервые; ④ сам ремонт бесплатный, но замена деталей — за небольшую плату (저렴한 가격으로).<br>🧩 찾아가다 — выезжать (к людям); 수리 — ремонт; 부품 교체 — замена деталей; 저렴하다 — недорогой."},{"n":12,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"피자 가게를 운영하는 김민수 씨의 사연이 잔잔한 감동을 주고 있다. 최근 김 씨는 피자를 배달하러 가다가 오토바이가 빗길에 미끄러지는 사고를 당했다. 다행히 사람이 다치는 피해는 없었지만 피자가 망가져서 배달에 문제가 생겼다. 배달이 늦어지는 것에 대해 김 씨가 고객에게 연락하자 고객은 \"천천히 오셔도 돼요. 몸은 괜찮으세요?\"라며 따뜻한 말부터 전했다고 한다.","options":["고객은 주문한 피자를 취소하겠다고 말했다.","사고가 생겨서 배달 중이던 피자가 망가졌다.","오토바이가 빗길에 미끄러져서 김 씨가 다쳤다.","김 씨는 피자를 시킨 고객에게 연락하다 사고가 났다."],"answer":2,"explain":"✅ <b>②</b>: из-за аварии доставляемая пицца испортилась (피자가 망가져서 배달에 문제).<br>✖️ ① клиент сказал «не спешите», заказ не отменял; ③ люди НЕ пострадали (사람이 다치는 피해는 없었지만) — Ким не ранен; ④ авария случилась по дороге на доставку (배달하러 가다가), а не во время звонка клиенту.<br>🧩 미끄러지다 — поскользнуться; 망가지다 — сломаться; 다행히 — к счастью; 사연 — история, случай."},{"n":13,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 짧게는 하루, 길게는 한 달 정도 반짝 운영하는 임시 매장이다.\n(나) 사람이 붐비는 장소에서 짧은 기간 동안 운영하는 매장이 유행이다.\n(다) 기업은 이 임시 매장을 이용해 주로 특정 제품을 팔거나 홍보를 한다.\n(라) 또 기업 이미지를 알리려고 재미있는 행사를 열기도 한다.","options":["(가)-(다)-(라)-(나)","(나)-(가)-(다)-(라)","(가)-(라)-(나)-(다)","(나)-(다)-(라)-(가)"],"answer":2,"explain":"✅ <b>② (나)-(가)-(다)-(라)</b>: (нА) общий зачин — «магазины на короткий срок в людных местах сейчас в моде»; (가) определение — «это временный магазин, работающий от дня до месяца» (이 매장 → отсылка к (나)); (다) «компании через него продают/рекламируют товар»; (라) «а ещё устраивают весёлые мероприятия».<br>✖️ (가) не может быть первым — начинается с определения «…임시 매장이다», которому нужен введённый ранее предмет.<br>🧩 임시 매장 — временный магазин (pop-up); 붐비다 — быть многолюдным; 홍보 — реклама; 유행이다 — в моде."},{"n":14,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 그런데 전화를 끊고 뒤늦게 미안한 마음이 들었다.\n(나) 친구는 나의 합격 소식을 듣고 자신의 일처럼 기뻐했다.\n(다) 얼마 전 나는 회사 합격 소식을 듣고 친한 친구에게 전화했다.\n(라) 아직 취업 못 한 친구를 내가 배려하지 못했다는 생각 때문이었다.","options":["(나)-(다)-(라)-(가)","(나)-(라)-(가)-(다)","(다)-(나)-(가)-(라)","(다)-(가)-(라)-(나)"],"answer":3,"explain":"✅ <b>③ (다)-(나)-(가)-(라)</b>: (다) завязка — «недавно я узнал, что прошёл в компанию, и позвонил другу»; (나) реакция — «друг обрадовался как своему»; (가) перелом — «но, положив трубку, я почувствовал вину»; (라) причина — «потому что не подумал о друге, который ещё не нашёл работу».<br>✖️ (가) с «그런데» (но) не может быть в начале.<br>🧩 합격 — успешное прохождение; 뒤늦게 — с запозданием; 배려하다 — проявлять заботу/такт; 취업 — трудоустройство."},{"n":15,"points":2,"instr":"Расставьте части в правильном порядке.","passage":"(가) 빵이나 고기를 구울 때 갈색으로 바뀌는 것이 그 예이다.\n(나) 갈색으로 바뀌면서 빵이나 고기의 맛도 더 깊어지고 풍부해진다.\n(다) 이 식품에 들어 있는 당과 단백질이 열을 만나면 색깔이 바뀌게 된다.\n(라) 만약 열이 너무 가해져서 검게 타게 되면 그런 맛을 낼 수가 없다.","options":["(가)-(나)-(라)-(다)","(가)-(다)-(나)-(라)","(가)-(다)-(라)-(나)","(다)-(라)-(나)-(가)"],"answer":2,"explain":"✅ <b>② (가)-(다)-(나)-(라)</b>: (가) пример — «потемнение при выпечке хлеба/жарке мяса — пример этого»; (다) механизм — «сахар и белок в продукте при нагреве меняют цвет»; (нА) следствие — «вместе с потемнением вкус становится глубже и богаче»; (라) оговорка — «но если перегреть и сжечь дочерна, такого вкуса уже не выйдет».<br>✖️ (다) с «이 식품» (этот продукт) опирается на (가), значит идёт после.<br>🧩 굽다 — печь, жарить; 당과 단백질 — сахар и белок; 가해지다 — прилагаться (о тепле); 풍부하다 — обильный, богатый."},{"n":16,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"타조는 멀리서 적이 다가와도 머리를 모래에 파묻고 있다. 그래서 위험이나 위기를 모르는 척 피하는 사람을 타조에 비유하곤 한다. 그런데 사실 타조는 (        ) 위해 이런 행동을 한다. 시각보다 청각이 발달한 타조는 땅에서 울리는 발소리를 듣고 적이 오는지를 파악하려는 것이다.","options":["적의 움직임을 알기","먹이를 빨리 구하기","머리를 깨끗이 씻기","다른 타조를 공격하기"],"answer":1,"explain":"✅ <b>① 적의 움직임을 알기</b>: страус прячет голову в песок, чтобы по звуку шагов в земле уловить приближение врага (청각이 발달… 발소리를 듣고 적이 오는지 파악) → «чтобы узнать движение врага».<br>✖️ ② про добычу не говорится; ③ «помыть голову» — нелепо; ④ «напасть на другого страуса» — нет.<br>🧩 타조 — страус; 청각 — слух; 발소리 — звук шагов; 파악하다 — улавливать, понимать."},{"n":17,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"섬유 유연제는 섬유에 막을 씌워 옷감을 부드럽게 하고 향기도 남긴다. 그래서 세탁할 때 유연제를 넣는 사람들이 많다. 그런데 수건처럼 물기를 빠르게 흡수해야 하는 소재에는 유연제를 넣는 것이 좋은 것만은 아니다. 유연제가 만든 막이 오히려 섬유의 (        ) 때문이다.","options":["향기를 없애기","색깔을 변형시키기","흡수력을 떨어뜨리기","촉감을 거칠게 만들기"],"answer":3,"explain":"✅ <b>③ 흡수력을 떨어뜨리기</b>: плёнка от кондиционера мешает впитывать воду — для полотенец это плохо → «снижает впитываемость волокон».<br>✖️ ① запах он как раз оставляет (향기도 남긴다); ② про изменение цвета не сказано; ④ ткань он делает мягче (부드럽게), а не грубее.<br>🧩 섬유 유연제 — кондиционер для белья; 막 — плёнка; 흡수력 — впитываемость; 떨어뜨리다 — снижать."},{"n":18,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"디지털 기기에 대한 의존도가 높아지면서 사람들이 무언가 직접 기억해야 할 일은 줄었다. 그래서 이전보다 (        ) 생각할 수 있다. 그런데 뇌를 사용하는 방식이 이전과 달라졌을 뿐 사용량이 줄어든 것이 아니다. 과거에는 단순히 정보를 기억하는 데 뇌를 썼다면 이제는 과거보다 압도적으로 많아진 정보를 처리하는 데 뇌를 사용하고 있는 것이다.","options":["뇌를 덜 사용한다고","기억력이 좋아졌다고","저장해야 할 정보가 많다고","디지털 기기를 많이 쓴다고"],"answer":1,"explain":"✅ <b>① 뇌를 덜 사용한다고</b>: раз запоминать приходится меньше, можно ПОДУМАТЬ, что мозг работает меньше; но дальше текст возражает — изменился лишь способ, не объём.<br>✖️ ② про улучшение памяти — нет; ③ «много информации хранить» — противоречит «기억할 일이 줄었다»; ④ про частое использование гаджетов — не то, что подставляется в «можно подумать, что…».<br>🧩 의존도 — степень зависимости; 덜 — меньше; 처리하다 — обрабатывать; 압도적으로 — подавляюще, в разы."},{"n":19,"points":2,"instr":"Выберите подходящее слово в пропуск ( ).","passage":"매서운 남극의 겨울, 황제펭귄들은 겹겹이 붙어 서로의 체온으로 추위를 견딘다. 무리 전체가 돌면서 바깥쪽과 안쪽에 있는 펭귄들이 계속 서로의 위치를 바꾼다. 안에서 몸을 데운 펭귄은 밖으로 나가고 밖에서 추위에 떨던 펭귄은 안으로 들어오는 것이다. (        ) 그 움직임은 아주 느리지만 쉬지 않고 이루어져 한 마리의 펭귄이 줄곧 찬바람을 맞고 서 있는 일이 없다. 그렇게 쉼 없이 둥글게 돌면서 펭귄들은 다 함께 살아남는다.","options":["혹시","또는","비록","만약"],"answer":3,"explain":"✅ <b>③ 비록</b>: дальше идёт «그 움직임은 아주 느리지만» (движение очень медленное, НО…). Связка 비록 …-지만 — «хотя …, но».<br>✖️ ① 혹시 — «вдруг, случайно»; ② 또는 — «или»; ④ 만약 — «если» (требует -(으)면).<br>🧩 비록 -지만 — «хотя, но»; 체온 — температура тела; 견디다 — терпеть, выдерживать; 무리 — стая."},{"n":20,"points":2,"instr":"Выберите главную тему текста.","passage":"매서운 남극의 겨울, 황제펭귄들은 겹겹이 붙어 서로의 체온으로 추위를 견딘다. 무리 전체가 돌면서 바깥쪽과 안쪽에 있는 펭귄들이 계속 서로의 위치를 바꾼다. 안에서 몸을 데운 펭귄은 밖으로 나가고 밖에서 추위에 떨던 펭귄은 안으로 들어오는 것이다. (비록) 그 움직임은 아주 느리지만 쉬지 않고 이루어져 한 마리의 펭귄이 줄곧 찬바람을 맞고 서 있는 일이 없다. 그렇게 쉼 없이 둥글게 돌면서 펭귄들은 다 함께 살아남는다.","options":["황제펭귄은 서로 도우면서 추위에 맞서 생존해 왔다.","황제펭귄은 둥글게 돌면서 날씨에 대한 정보를 알린다.","황제펭귄은 추위에서 살아남기 위해 움직임이 느려졌다.","황제펭귄은 무리 생활을 통해 경쟁에서 이기는 법을 배운다."],"answer":1,"explain":"✅ <b>①</b>: пингвины греют друг друга, меняясь местами по кругу, чтобы никто не мёрз на ветру, — и так выживают ВМЕСТЕ. Тема — выживание через взаимопомощь против холода.<br>✖️ ② про «оповещение о погоде» — нет; ③ замедление движения — не цель и не тема; ④ речь о СОТРУДНИЧЕСТВЕ и выживании, а не о «победе в конкуренции».<br>🧩 생존하다 — выживать; 맞서다 — противостоять; 체온 — температура тела; 살아남다 — уцелеть."},{"n":21,"points":2,"instr":"Выберите подходящее выражение (идиому) в пропуск ( ).","passage":"최근 미술 전시회 수요가 증가하면서 돈벌이에 급급한 전시회가 늘고 있다. 일부 전시 관계자들이 전시 포스터 등 홍보 자료에 복제품 전시임을 밝히지 않고 입장료 수입만을 챙기는 것이다. 전시장을 찾아와서야 이런 사실을 알게 된 관람객들은 불만을 쏟아 내고 있다. 전문가들은 이런 전시 행태가 미술계 발전의 (        ) 수 있다고 우려한다. 전시회에 실망한 사람들이 미술에 대한 관심을 아예 끊을 수 있기 때문이다.","options":["입맛에 맞을","가슴을 울릴","발목을 잡을","손을 맞잡을"],"answer":3,"explain":"✅ <b>③ 발목을 잡을</b>: идиома 발목을 잡다 — «связывать руки, тормозить». «미술계 발전의 발목을 잡을 수 있다» — может затормозить развитие арт-сферы.<br>✖️ ① 입맛에 맞다 — быть по вкусу; ② 가슴을 울리다 — трогать за душу; ④ 손을 맞잡다 — взяться за руки.<br>🧩 발목을 잡다 — тормозить, мешать; 행태 — манера поведения; 우려하다 — опасаться; 복제품 — копия."},{"n":22,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"최근 미술 전시회 수요가 증가하면서 돈벌이에 급급한 전시회가 늘고 있다. 일부 전시 관계자들이 전시 포스터 등 홍보 자료에 복제품 전시임을 밝히지 않고 입장료 수입만을 챙기는 것이다. 전시장을 찾아와서야 이런 사실을 알게 된 관람객들은 불만을 쏟아 내고 있다. 전문가들은 이런 전시 행태가 미술계 발전의 (발목을 잡을) 수 있다고 우려한다. 전시회에 실망한 사람들이 미술에 대한 관심을 아예 끊을 수 있기 때문이다.","options":["복제품 전시회는 입장료를 받지 않는다.","최근 미술 전시회를 찾는 사람들이 많지 않다.","전시회에서 복제품을 전시하는 일이 점점 줄고 있다.","복제품 전시회인지 모르고 전시회를 방문한 관람객들이 있다."],"answer":4,"explain":"✅ <b>④</b>: «전시장을 찾아와서야 이런 사실을 알게 된 관람객들» — есть посетители, которые узнали о том, что это выставка копий, только придя туда.<br>✖️ ① такие выставки как раз БЕРУТ плату (입장료 수입만을 챙기는); ② спрос РАСТЁТ (수요가 증가); ③ такие выставки УВЕЛИЧИВАЮТСЯ (늘고 있다), не уменьшаются.<br>🧩 복제품 — копия; 입장료 — входная плата; 챙기다 — прибирать; 찾아와서야 — лишь придя."},{"n":23,"points":2,"instr":"Выберите чувство «я» в подчёркнутой части.","passage":"꽃집을 지나다가 꽃밭에 이끌려 금잔화 꽃씨를 샀다. 화분에 심어 사무실의 내 책상 위에 두었더니 어느 날 싹이 텄다. 때맞춰 물도 주며 나는 수시로 들여다보았다. 신기했다. 작고 여린 싹은 눈에 띄게 쑥쑥 자랐다. 그런데 내가 상상한 모습이 아니었다. 도대체 여기서 어떻게 꽃이 핀다는 건지, 무처럼 길쭉하게 위로만 자라는 것이었다. 하루는 출근해 보니 금잔화가 쓰러져 있었다. <u>그럼 그렇지. 내가 무슨 식물을 키우나.</u> 그냥 나는 화분을 창가로 옮겨 놓았다. 죽을 것 같은 모습을 눈앞에서 보고 싶지 않았다. 그런데 어느 날부턴가 점점 줄기가 굵어지더니 잎도 제법 풍성해지기 시작했다. 어느 날에는 꽃망울도 올라와 있었다. 금잔화는 창문으로 들어오는 풍성한 햇볕 속에서 스스로 튼튼해졌다. 금잔화에게는 햇볕이 더 많이 필요했었나 보다. 사람도 식물도 사랑하면서 그 대상을 제대로 알아야 하는 건 똑같구나 싶었다.","options":["의심스럽다","고통스럽다","조심스럽다","부담스럽다"],"answer":1,"explain":"✅ <b>① 의심스럽다</b> (сомнение в себе): увидев упавший цветок, рассказчик с досадой думает «그럼 그렇지. 내가 무슨 식물을 키우나» — «ну конечно, куда мне растить растения» — он не верит, что у него получится.<br>✖️ ② 고통스럽다 (мучительно) — слишком сильно; ③ 조심스럽다 (осторожно) — не подходит; ④ 부담스럽다 (в тягость) — нет.<br>🧩 그럼 그렇지 — «ну так и знал»; 키우다 — растить; 쓰러지다 — падать, валиться; 의심스럽다 — сомнительно."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"꽃집을 지나다가 꽃밭에 이끌려 금잔화 꽃씨를 샀다. 화분에 심어 사무실의 내 책상 위에 두었더니 어느 날 싹이 텄다. 때맞춰 물도 주며 나는 수시로 들여다보았다. 작고 여린 싹은 눈에 띄게 쑥쑥 자랐다. … 하루는 출근해 보니 금잔화가 쓰러져 있었다. 그냥 나는 화분을 창가로 옮겨 놓았다. 그런데 어느 날부턴가 점점 줄기가 굵어지더니 잎도 제법 풍성해졌다. 금잔화는 창문으로 들어오는 풍성한 햇볕 속에서 스스로 튼튼해졌다. 금잔화에게는 햇볕이 더 많이 필요했었나 보다.","options":["내 책상 위에 둔 금잔화는 금방 말라 죽었다.","나는 금잔화 화분에 물을 제대로 주지 못했다.","나는 꽃집에서 금잔화가 피어 있는 화분을 샀다.","내가 금잔화 화분을 옮긴 곳은 햇빛이 잘 들어왔다."],"answer":4,"explain":"✅ <b>④</b>: горшок переставили к окну (창가로 옮겨), и там календула окрепла «창문으로 들어오는 풍성한 햇볕 속에서» — туда хорошо попадало солнце.<br>✖️ ① цветок не засох — он окреп и дал бутоны; ② рассказчик поливал вовремя (때맞춰 물도 주며); ③ купил СЕМЕНА (꽃씨), а не цветущий горшок.<br>🧩 금잔화 — календула; 창가 — у окна; 햇볕 — солнце, солнечный свет; 옮기다 — переставлять."},{"n":25,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 가수 진영, 3년 만의 콘서트에 구름 관중","options":["가수 진영이 3년 만에 콘서트를 열자 수많은 관중이 몰렸다.","가수 진영이 3년 내에 다시 콘서트를 열기로 관중에게 약속했다.","가수 진영이 3년간 준비한 콘서트를 열었으나 관중의 호응이 적었다.","가수 진영이 3년 만에 하는 콘서트에 많은 관중을 모으려고 홍보했다."],"answer":1,"explain":"✅ <b>①</b>: «구름 관중» — «толпа как туча», огромное число зрителей; «3년 만의 콘서트» — концерт впервые за 3 года → собралось множество зрителей.<br>✖️ ② «обещал снова дать концерт» — нет; ③ «отклик был слабым» — наоборот; ④ «рекламировал, чтобы собрать» — заголовок о результате, а не о рекламе.<br>🧩 구름 관중 — огромная толпа зрителей; 3년 만에 — впервые за 3 года; 몰리다 — стекаться."},{"n":26,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 한국 탁구의 간판 김수미, 올해 국제 대회 금메달 싹쓸이","options":["올해 국제 탁구 대회에서 한국 대표 김수미의 금메달 가능성이 높아졌다.","한국 탁구계가 김수미를 내세워 올해 국제 대회의 금메달을 노리고 있다.","한국의 대표 탁구 선수 김수미가 올해 국제 대회에서 모두 금메달을 땄다.","한국 탁구 선수 김수미가 올해 국제 대회에서 금메달을 따고자 훈련 중이다."],"answer":3,"explain":"✅ <b>③</b>: «간판» — звезда, лицо команды; «싹쓸이» — «подмела всё», забрала все золотые медали → на международных турнирах этого года выиграла все золото.<br>✖️ ① «возможность повысилась» — она уже выиграла; ② «нацелились» — уже сделано; ④ «тренируется, чтобы выиграть» — нет.<br>🧩 간판 — лицо, звезда; 싹쓸이 — забрать всё подчистую; 금메달을 따다 — завоевать золото."},{"n":27,"points":2,"instr":"Выберите, что лучше всего объясняет заголовок.","passage":"📰 대출 금리 하락세, 부동산 시장 기지개","options":["대출 금리가 떨어지면서 부동산 시장이 살아나기 시작했다.","부동산 시장에 대한 규제가 대출 금리 하락에 영향을 미쳤다.","대출 금리가 하락했지만 부동산 시장의 거래는 줄어들고 있다.","부동산 시장을 활성화하려고 대출 금리 안정 대책이 논의되고 있다."],"answer":1,"explain":"✅ <b>①</b>: «하락세» — тенденция к снижению (ставок); «기지개» — «потягиваться», то есть оживать → со снижением кредитных ставок рынок недвижимости начал оживать.<br>✖️ ② про регулирование рынка — нет; ③ «сделки сокращаются» — наоборот, рынок оживает; ④ про «обсуждение мер» — нет.<br>🧩 대출 금리 — кредитная ставка; 하락세 — тренд снижения; 기지개를 켜다 — оживать, расправляться; 살아나다 — оживать."},{"n":28,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"선글라스는 보통 햇빛이 강할 때 눈 건강을 위해 쓴다. 그런데 선글라스의 렌즈는 사용 기한이 있다. 선글라스의 렌즈에는 자외선 차단을 위한 얇은 막이 입혀져 있는데 햇빛에 계속 노출되면 자외선 차단 기능이 점점 떨어지게 된다. 자외선 차단 기능이 약해진 선글라스로는 눈을 보호하기 어려우므로 5년 정도 쓰고 나면 (        ) 것이 좋다.","options":["렌즈를 바꿔 주는","렌즈를 꼼꼼히 잘 닦는","렌즈의 색을 어둡게 하는","렌즈의 엷은 막을 벗겨 내는"],"answer":1,"explain":"✅ <b>① 렌즈를 바꿔 주는</b>: УФ-плёнка со временем теряет защиту, защищать глаза такие очки уже не могут → примерно через 5 лет линзы лучше заменить.<br>✖️ ② просто протереть — не вернёт защиту; ③ затемнить цвет — не про УФ-фильтр; ④ снять плёнку — она и есть защита, снимать нельзя.<br>🧩 자외선 차단 — защита от УФ; 사용 기한 — срок службы; 노출되다 — подвергаться; 바꾸다 — менять."},{"n":29,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"사진에서 구도는 전체적인 분위기를 살리는 중요한 요소이다. 보통 동적인 느낌을 주고 싶을 때는 대각선 구도를 쓰는데 도로나 폭포 등의 풍경 사진 등에 쓰여 생동감을 표현한다. 한편 전통적인 가족사진은 (        ) 위해서 삼각형 구도를 가장 많이 활용한다. 이 구도는 연장자를 중심으로 가족 구성원이 옆이나 뒤에 배치되어 전체적으로 편안하고 균형 잡힌 분위기를 만들어 낸다.","options":["동적인 효과를 살리기","안정적인 느낌을 주기","풍경을 중앙에 배치하기","긴장된 분위기를 연출하기"],"answer":2,"explain":"✅ <b>② 안정적인 느낌을 주기</b>: треугольная композиция (старший в центре, остальные по бокам/сзади) создаёт спокойную, уравновешенную атмосферу → её используют ради ощущения стабильности.<br>✖️ ① динамику даёт ДИАГОНАЛЬНАЯ композиция; ③ «поместить пейзаж в центр» — не про семейное фото; ④ напряжённость — противоположность.<br>🧩 구도 — композиция кадра; 대각선 — диагональ; 삼각형 — треугольник; 안정적 — стабильный, спокойный."},{"n":30,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"풍부한 자원은 경제 성장의 필요조건이지 충분조건은 아니다. 풍부한 천연자원을 갖추고 있음에도 (        ) 경우도 있다. 풍부한 자원에만 의존해 경제 성장의 중심 산업인 제조업이나 서비스업 등에 투자를 하지 않게 되는 것이다. 반면에 천연자원이 빈약해도 새로운 기술 개발이나 교육을 통해 생산 능력을 높이는 나라도 있다.","options":["제조업에 의존하려는","자원을 생산하지 못하는","경제 발전을 이루지 못하는","기술 개발에 무리하게 투자하는"],"answer":3,"explain":"✅ <b>③ 경제 발전을 이루지 못하는</b>: богатые ресурсы — необходимое, но не достаточное условие; полагаясь только на них и не вкладываясь в промышленность/услуги, страна может и не добиться развития.<br>✖️ ① «полагаться на промышленность» — наоборот, в неё не вкладываются; ② «не могут производить ресурсы» — ресурсы как раз есть; ④ «чрезмерно вкладывать в технологии» — противоречит «투자를 하지 않게».<br>🧩 자원 — ресурсы; 필요조건/충분조건 — необходимое/достаточное условие; 의존하다 — зависеть; 빈약하다 — скудный."},{"n":31,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"의사의 모습을 생각하면 우리는 보통 흰색 가운을 떠올리게 된다. 그런데 의사 가운이 처음부터 흰색이었던 것은 아니다. 중세 시대에는 성직자가 의사를 겸하는 경우가 많아 성직자용 검은색 가운을 입고 진료를 했다. 그런데 검은색 옷은 세균으로 오염된 얼룩이 잘 보이지 않았다. 이후 세균 감염의 위험성에 대한 인식이 높아지면서 (        ) 가운의 색이 흰색으로 바뀌었다.","options":["염색이 편하게","환자와 구분이 되도록","오염이 쉽게 눈에 띄도록","밝은 이미지를 줄 수 있게"],"answer":3,"explain":"✅ <b>③ 오염이 쉽게 눈에 띄도록</b>: на чёрном халате пятна от микробов не видны; с ростом осознания риска заражения цвет сменили на белый, чтобы загрязнение было заметно.<br>✖️ ① удобство покраски — нет; ② отличие от пациентов — не названо причиной; ④ «светлый образ» — текст про гигиену, а не имидж.<br>🧩 가운 — халат; 성직자 — священнослужитель; 세균 감염 — бактериальная инфекция; 눈에 띄다 — бросаться в глаза."},{"n":32,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"당뇨 환자들을 위해 고추 품종인 '살리초'가 개발되었다. 고추는 보통 열매를 얻기 위해 재배하지만 살리초는 열매가 없고 잎을 먹는 품종이다. 잎이 고추에 비해 혈당을 낮추는 성분이 10배 이상 많이 함유돼 있어 당뇨병, 비만증 등 성인병의 예방과 치료에 이용될 수 있다. 또한 살리초에는 칼슘, 비타민 등 각종 영양 성분이 풍부하다. 병해충에도 강하고 생육 기간도 짧아서 농가의 고소득 작물로 주목받고 있다.","options":["살리초는 해충에 취약하다는 단점이 있다.","살리초의 열매는 크고 영양 성분이 풍부하다.","살리초는 생육 기간이 길어 관심을 받지 못하고 있다.","살리초의 잎에는 혈당을 떨어뜨리는 성분이 들어 있다."],"answer":4,"explain":"✅ <b>④</b>: листья «салличо» содержат компоненты, снижающие сахар в крови (혈당을 낮추는 성분이 10배 이상 함유).<br>✖️ ① он УСТОЙЧИВ к вредителям (병해충에도 강하고); ② у него НЕТ плодов (열매가 없고) — едят листья; ③ срок роста КОРОТКИЙ (생육 기간도 짧아서), и культура как раз популярна.<br>🧩 당뇨 — диабет; 혈당 — сахар крови; 함유되다 — содержаться; 병해충 — болезни и вредители."},{"n":33,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"『임원경제지』는 조선 시대 서유구가 쓴 백과사전이다. 선비가 시골에서 살아가는 데 필요한 지식을 탐구한 것으로 농업, 건축, 의학 등 16개 분야를 정리했다. 서유구는 이 책을 쓸 때 조선의 생활상을 직접 관찰하고 여러 서적들을 참고했으며 거기에 자신의 논평을 붙였다. 이 과정에서 인용한 책들을 밝혀 놓아 서지학의 가치도 크다. 총 52권인 이 책은 개인이 완성했다고 보기 어려울 만큼 방대하고 전문적인 지식이 담겨 있다.","options":["이 책은 각 분야의 전문가가 모여 만든 책이다.","서유구는 집필하면서 참고한 문헌을 이 책에 기록해 놓았다.","서유구는 객관적인 책을 쓰기 위해 자신의 의견은 배제했다.","이 책은 내용이 특정 분야에 한정되어 서지학적 가치는 크지 않다."],"answer":2,"explain":"✅ <b>②</b>: Со Ю-гу указал в книге использованные источники (인용한 책들을 밝혀 놓아 서지학의 가치도 크다).<br>✖️ ① её написал ОДИН человек (개인이 완성), не коллектив; ③ он ДОБАВЛЯЛ свои комментарии (자신의 논평을 붙였다), а не исключал мнение; ④ охватывает 16 областей и имеет высокую библиографическую ценность.<br>🧩 백과사전 — энциклопедия; 집필 — написание; 문헌 — источник; 인용하다 — цитировать; 서지학 — библиография."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"코알라는 유칼립투스 나뭇잎을 먹고 산다. 이 나뭇잎은 독성이 강해서 일반적인 동물들은 먹을 수 없다. 하지만 코알라는 유칼립투스의 독을 해독하는 효소가 있어서 다른 동물들과 경쟁할 필요 없이 유칼립투스 잎을 충분히 먹을 수 있다. 다만 새끼 코알라는 독성을 분해하는 효소가 없어서 유칼립투스 잎 대신 어미의 배설물을 먹는다. 이를 통해 새끼 코알라의 몸속에도 유칼립투스의 독을 해독하는 효소가 생기게 된다.","options":["다양한 동물들이 유칼립투스 잎을 차지하기 위해 경쟁한다.","어미 코알라는 유칼립투스의 독성을 분해하는 효소를 가지고 있다.","코알라는 태어난 직후부터 많은 양의 유칼립투스 나뭇잎을 먹는다.","새끼 코알라는 유칼립투스의 독성 때문에 어미의 배설물을 먹지 않는다."],"answer":2,"explain":"✅ <b>②</b>: взрослая коала имеет фермент, расщепляющий яд эвкалипта (독을 해독하는 효소가 있어서).<br>✖️ ① другие животные есть его НЕ могут (먹을 수 없다) — конкуренции нет; ③ детёныш сразу после рождения эвкалипт НЕ ест (효소가 없어서); ④ детёныш КАК РАЗ ест помёт матери (배설물을 먹는다), потому что у него нет фермента.<br>🧩 유칼립투스 — эвкалипт; 독성 — ядовитость; 해독하다 — обезвреживать; 효소 — фермент; 배설물 — экскременты."},{"n":35,"points":2,"instr":"Выберите главную тему текста.","passage":"태양계에 존재하는 수많은 소행성은 천문학적인 가치를 지닌 광물이 있는 것으로 예상된다. 그래서 많은 나라들이 이에 관심을 가지고 있다. 실제로 최근 몇몇 국가에서는 소행성에 있는 광물 시추를 채취하는 데 성공하기도 했다. 하지만 대부분의 나라들에서는 소행성 탐사가 아직 논의 단계에 머무르고 있다. 미래 자원을 확보하기 위해서 적극적으로 소행성 탐사에 대한 투자와 기술 개발에 나설 필요가 있다.","options":["태양계에는 아직 발견되지 않은 소행성이 많이 존재한다.","소행성에서 자원을 가져오는 것은 실현 가능성이 희박하다.","소행성 탐사를 성공시키기 위해 국제 협력을 확대해야 한다.","미래 자원 확보를 위해 소행성 탐사에 대한 노력을 기울여야 한다."],"answer":4,"explain":"✅ <b>④</b>: вывод текста — ради будущих ресурсов нужно активно вкладываться в разведку астероидов и развивать технологии.<br>✖️ ① «много необнаруженных астероидов» — частность; ② «нереалистично» — наоборот, уже есть успехи; ③ про «международное сотрудничество» текст не говорит.<br>🧩 소행성 — астероид; 광물 — минерал; 자원 확보 — обеспечение ресурсами; 노력을 기울이다 — прилагать усилия."},{"n":36,"points":2,"instr":"Выберите главную тему текста.","passage":"경기 침체에 빠지면 사람들은 소비보다는 저축을 늘리려고 한다. 그런데 저축이 언제나 긍정적인 것만은 아니다. 소비가 줄면 기업의 매출이 감소해서 생산과 고용이 줄 수밖에 없고 결국 근로자들의 소득도 줄어들게 된다. 그러면 미래가 불확실해진 사람들이 더욱 소비를 줄여 전체 경기가 다시 침체에 빠지는 악순환이 되풀이된다. 개인 차원에서는 저축이 합리적인 행동이지만 경제 전체적으로는 비합리적인 상황을 초래하게 되는 것이다.","options":["불경기에는 비합리적인 소비로 인해 근로자들의 저축이 줄어든다.","경기가 침체하면 개인의 소득이 줄어들지 않도록 투자를 늘려야 한다.","경제 상황을 고려해서 생산과 고용을 적절히 조절하는 것이 중요하다.","경기 침체 시에는 저축이 국가 경제 전체에 부정적 영향을 줄 수 있다."],"answer":4,"explain":"✅ <b>④</b>: в спад люди копят (рационально для каждого), но падение спроса → меньше продаж, производства, доходов → новый виток спада: для экономики в целом это вредно.<br>✖️ ① «저축이 줄어든다» — наоборот, сбережения растут; ② «увеличить инвестиции» — текст этого не советует; ③ про регулирование производства/занятости — не главная мысль.<br>🧩 경기 침체 — экономический спад; 저축 — сбережения; 악순환 — порочный круг; 초래하다 — вызывать."},{"n":37,"points":2,"instr":"Выберите главную тему текста.","passage":"참치 어획 할당제는 참치의 무분별한 포획을 막기 위해 어획량을 국가별로 정해 놓은 제도이다. 한국은 참치 어획량이 매우 적게 배정돼 있는데 이는 한국 연안에서는 참치가 거의 잡히지 않았기 때문이다. 최근 수온이 상승함에 따라 한국 연안에 유입되는 참치가 급격히 늘어나고 있지만 어획량 때문에 그물에 걸린 참치를 대부분 바다에 버리고 있다. 이 제도의 필요성은 인정하지만 국가별 어획량을 개정할 때 증감을 반영한 유동성 있는 조정이 필요하다.","options":["국가별 상황에 따라 참치 어획량을 현실에 맞게 수정해야 한다.","참치의 무분별한 포획을 방지하기 위해 어획제를 도입해야 한다.","수온 상승으로부터 참치를 보호하기 위한 대책을 마련해야 한다.","참치의 유입량을 늘리기 위한 실질적인 연구가 이루어져야 한다."],"answer":1,"explain":"✅ <b>①</b>: квота для Кореи мала, но из-за потепления тунца стало много — однако его выбрасывают из-за лимита; вывод — квоты нужно пересматривать гибко, под реальную ситуацию каждой страны.<br>✖️ ② «ввести квоты» — система уже есть; ③ «защищать тунца от потепления» — не тема; ④ «исследования ради увеличения захода тунца» — нет.<br>🧩 어획량 — объём вылова; 무분별한 — безрассудный; 유동성 — гибкость; 수정하다 — корректировать."},{"n":38,"points":2,"instr":"Выберите главную тему текста.","passage":"기업은 기술 혁신을 통해 고객에게 편의와 혜택을 제공하려고 한다. 하지만 아무리 획기적인 혁신이라도 고객에게 낯설고 커다란 행동 변화를 요구한다면 외면당하기 쉽다. 예를 들어 초창기 전기 자동차는 전기로 오래 충전을 해야 하는 것이 낯설고 불편해서 큰 관심을 끌지 못했다. 반대로 전자 칠판과 전자 펜처럼 대단한 혁신은 아니어도 사용하는 방법이 고객에게 익숙하고 간단해서 환영받는 경우도 있다.","options":["고객들의 무리한 요구 때문에 기술 혁신에 어려움을 겪게 된다.","혁신적인 기업은 고객들에게 신기술의 사용 방법을 잘 설명해 준다.","기술 혁신에 실패한 기업은 자연스럽게 고객들의 외면을 받게 된다.","기술 혁신은 고객이 쉽게 받아들일 수 있을 때 성공할 가능성이 높다."],"answer":4,"explain":"✅ <b>④</b>: даже прорывная новинка отвергается, если требует непривычных усилий; а привычное и простое в использовании — принимается. Значит инновация успешна, когда её легко принять.<br>✖️ ① «из-за чрезмерных требований клиентов» — нет; ② «хорошо объясняют» — не вывод; ③ «отвергнут естественно» — частный случай, не главная мысль.<br>🧩 혁신 — инновация; 획기적 — революционный; 외면당하다 — быть отвергнутым; 익숙하다 — привычный."},{"n":39,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그런데 심판이 아무리 위치 선정을 잘해도 필연적으로 선수의 몸에 가려서 볼 수 없는 사각지대가 생긴다.\n\n스포츠 경기를 진행할 때 득점이나 반칙 등의 판정은 심판에 의해서 이루어진다. ( ㉠ ) 이렇게 눈에 보이지 않는 곳에서 벌어진 상황에 대해서는 심판도 정확한 판단을 하기 어렵다. ( ㉡ ) 비디오 판독은 이런 스포츠 경기에서 초소형 카메라를 판정의 근거로 사용하는 기술이다. ( ㉢ ) 이처럼 비디오 판독을 활용하면 심판이 판단하기 어려운 부분을 객관적으로 확인할 수 있어 판정에 대한 신뢰도를 높일 수 있다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b>: вставка вводит «слепую зону» (사각지대), которую загораживают тела игроков; следующее предложение «이렇게 눈에 보이지 않는 곳에서…» («в таких невидимых местах…») прямо ссылается на эту зону → значит вставка стоит перед ним, в ㉠.<br>✖️ ㉡㉢㉣ идут после ввода видеоповтора и разрывают связь «слепая зона → невидимое место».<br>🧩 심판 — судья; 사각지대 — слепая зона; 비디오 판독 — видеопросмотр; 필연적으로 — неизбежно."},{"n":40,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 그 증거로 지중해 전역에서 발견되고 있는 소금 퇴적층을 들 수 있다.\n\n유럽과 아시아, 아프리카 대륙으로 둘러싸인 바다를 지중해라고 한다. ( ㉠ ) 오늘날 지중해 연안은 기후가 온화해서 살기 좋은 곳으로 손꼽힌다. ( ㉡ ) 그런데 지중해는 오래전 사막이었던 적이 있었다. ( ㉢ ) 이 소금 퇴적층은 바닷물이 증발되고 남은 소금이 쌓여 만들어진 것으로 지중해가 이전에는 사막이었음을 보여 준다. ( ㉣ ) 사막이었던 지중해에 이후 큰 홍수가 발생하면서 다시 오늘날과 같은 바다가 되었다.","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b>: вставка приводит «в качестве доказательства» соляные отложения того, что Средиземное море было пустыней; перед ней должно стоять «지중해는 오래전 사막이었던 적이 있었다», а после — «이 소금 퇴적층은…» («эти соляные отложения…»), что прямо ссылается на вставку.<br>✖️ ㉠㉡ — ещё нет тезиса о пустыне; ㉣ — уже после объяснения отложений.<br>🧩 지중해 — Средиземное море; 소금 퇴적층 — соляные отложения; 증발되다 — испаряться; 증거 — доказательство."},{"n":41,"points":2,"instr":"Куда лучше всего вставить предложение из рамки <보기>?","passage":"<보기> 이런 상소문들을 저자는 왕을 향한 깨우침의 죽비 소리로 비유하고 있다.\n\n최근 역사학자 김경민 씨가 『응답하라, 조선』을 펴냈다. ( ㉠ ) 이 책은 왕과 신하의 소통을 다루고 있어 사람들의 관심을 끌었다. ( ㉡ ) 그 소통의 내용 중에서 특히 왕의 노여움을 무릅쓰고 신하가 왕의 잘못을 지적한 상소문을 다룬 부분이 주목받고 있다. ( ㉢ ) 『응답하라, 조선』은 눈치를 살피며 윗사람의 잘못을 모르는 척 넘기곤 하는 현대인들을 깨우는 죽비인 것이다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b>: вставка вводит метафору «죽비» (бамбуковая палка пробуждения) применительно к «상소문» (челобитным); перед ней — абзац про эти челобитные, а после — предложение, которое разворачивает ту же метафору «죽비» уже на современников.<br>✖️ ㉠㉡ — челобитные ещё не введены; ㉣ — после развития метафоры, связь рвётся.<br>🧩 상소문 — челобитная государю; 죽비 — бамбуковая палка (пробуждения); 비유하다 — уподоблять; 깨우침 — вразумление."},{"n":42,"points":2,"instr":"Выберите чувство «Миён» в подчёркнутой части.","passage":"민욱이 주말에 친구 부부를 초대해도 되느냐고 물었을 때, <u>미연은 말없이 한참 뜸을 들였다.</u> 그녀는 그날 민욱과 함께 아파트의 발코니 벽을 페인트칠할 계획이었다. (중략) 그들은 육 개월 전에 E시의 아파트를 사서 이사했다. 지은 지 이십 년도 더 된 낡은 아파트였지만, 누구의 도움도 받지 않고 그들 스스로 이룬 일이었다. 미연은 직접 발품을 팔아 수도부터 새시까지 새로 손을 보았다. 하지만 집수리는 대강 되었다고 해도, 미연이 생각해 둔 대로 인테리어가 완성되려면 아직 부족했다.\n\"손님 초대는 좀 이르지 않아? 집 단장도 덜 되었는데……\"\n\"성재가 한국에 왔대.\"\n민욱이 무거운 목소리로 말했다.","options":["후련하다","불만스럽다","허전하다","자랑스럽다"],"answer":2,"explain":"✅ <b>② 불만스럽다</b> (недовольство): на предложение позвать гостей Миён долго молчит и мнётся, ведь ремонт ещё не доведён до задуманного — «손님 초대는 좀 이르지 않아? 집 단장도 덜 되었는데» → ей не нравится идея звать гостей сейчас.<br>✖️ ① 후련하다 (с облегчением) — наоборот; ③ 허전하다 (опустошённость) — не про этот момент; ④ 자랑스럽다 (гордость) — нет.<br>🧩 뜸을 들이다 — медлить, мяться; 집 단장 — обустройство дома; 덜 되다 — быть недоделанным; 불만스럽다 — недовольный."},{"n":43,"points":2,"instr":"Выберите то, что можно понять из текста.","passage":"그들은 육 개월 전에 E시의 아파트를 사서 이사했다. … 누구의 도움도 받지 않고 그들 스스로 이룬 일이었다. … 미연이 생각해 둔 대로 인테리어가 완성되려면 아직 부족했다. … 민욱과 성재는 고등학교 동창이고, 그들을 통해 만난 미연과 연주도 십여 년이 넘는 인연이었다. 꽤나 가까운 사이였지만 성재가 사업 실패로 한국을 떠나면서 연락이 끊겼다. 미연은 자신이 연주의 이름을 오랫동안 잊고 있었다는 사실을 깨달았다.","options":["미연은 민욱과 성재를 통해 연주와 알게 되었다.","민욱은 주변 도움을 받아 E시의 새 아파트를 샀다.","미연은 육 개월 전에 산 아파트로 이사 갈 계획이다.","민욱은 인테리어를 완성한 후에 마트로 장을 보러 갔다."],"answer":1,"explain":"✅ <b>①</b>: «민욱과 성재… 그들을 통해 만난 미연과 연주» — Миён и Ёнджу познакомились через Минука и Сонджэ.<br>✖️ ② квартиру купили БЕЗ чьей-либо помощи (누구의 도움도 받지 않고); ③ они уже переехали полгода назад (이사했다), а не собираются; ④ интерьер ещё НЕ завершён (완성되려면 아직 부족했다).<br>🧩 동창 — однокашник; 인연 — связь, знакомство; 연락이 끊기다 — потерять связь; 발품을 팔다 — обивать пороги, хлопотать."},{"n":44,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"'수로왕 신화'는 왕이 알에서 탄생하는 여느 건국 신화와 유사하다. 고대에 아직 나라가 없던 낙동강 하류에 황금알 여섯 개가 하늘에서 내려왔다. 그중 맨 먼저 알을 깨고 나온 아이를 '수로'라 하였고 하늘의 뜻에 따라 수로는 지상의 첫 번째 왕이 되었다. (        ) 다섯 아이 역시 각각 왕이 되었다. 수로왕 신화는 이렇게 한꺼번에 여섯 개 알이 나타나 거기서 태어난 이가 모두 왕이 된다는 점에서 다른 건국 신화와 큰 차이가 있다. 당시 세워진 여섯 나라는 강력한 왕권 국가가 아니었다. 황금알은 하늘로부터 부여받은 절대적 권위를 상징하는데 수로가 앞에서 최초로 탄생했다는 부분은 수로왕이 중심이 되어 여섯 나라를 하나의 강력한 국가 '가야'로 통합하려 했다는 것을 말해 준다.","options":["알을 가지고 내려온","기존의 왕을 물리치고","수로에 이어 알에서 태어난","탄생을 축하하며 몹시 기뻐하던"],"answer":3,"explain":"✅ <b>③ 수로에 이어 알에서 태어난</b>: дальше «다섯 아이 역시 각각 왕이 되었다» — и пятеро ДЕТЕЙ тоже стали ванами; они, как и Суро, родились из яиц (вслед за ним).<br>✖️ ① «спустились с яйцами» — они рождаются ИЗ яиц; ② «победив прежнего вана» — государств ещё не было; ④ «радуясь рождению» — не вяжется с «다섯 아이».<br>🧩 건국 신화 — миф об основании государства; 알에서 태어나다 — рождаться из яйца; 통합하다 — объединять; 왕권 — царская власть."},{"n":45,"points":2,"instr":"Выберите главную тему текста.","passage":"'수로왕 신화'는 … 한꺼번에 여섯 개 알이 나타나 거기서 태어난 이가 모두 왕이 된다는 점에서 다른 건국 신화와 큰 차이가 있다. … 황금알은 하늘로부터 부여받은 절대적 권위를 상징하는데 수로가 앞에서 최초로 탄생했다는 부분은 수로왕이 중심이 되어 여섯 나라를 하나의 강력한 국가 '가야'로 통합하려 했다는 것을 말해 준다.","options":["이 신화는 전형적인 건국 신화의 특성을 지니고 있다.","이 신화는 낙동강 일대의 유용한 지리적 정보를 담고 있다.","이 신화는 고대의 문학 작품으로서 훌륭한 가치를 지니고 있다.","이 신화는 강력한 왕권 국가를 이루려고 한 통합 의식을 반영한다."],"answer":4,"explain":"✅ <b>④</b>: миф (шесть яиц → шесть ванов, Суро первый и главный) отражает стремление объединить шесть земель в одно сильное государство «Кая» во главе с Суро.<br>✖️ ① он, наоборот, ОТЛИЧАЕТСЯ от типичных мифов (큰 차이가 있다); ② географическая информация — не тема; ③ литературная ценность не обсуждается.<br>🧩 왕권 국가 — монархическое государство; 통합 — объединение; 의식 — сознание, идея; 반영하다 — отражать."},{"n":46,"points":2,"instr":"Выберите позицию (отношение) автора.","passage":"주가 조작이나 공금 횡령 등의 경제 범죄는 사람에게 직접적인 상해를 가하는 흉악 범죄보다 범죄 정도가 낮다고 생각하기 쉽다. 그러나 경제 범죄의 수법이 날이 갈수록 다양해지고 지능화되어 사회에 미치는 충격과 피해가 막심하다. 최근 증권사 직원의 주가 조작으로 고객들이 천억 넘게 손해 본 사건만 해도 그렇다. 이러한 경제 범죄는 개인 손해를 넘어 국가 경제와도 직결될 수 있다. 따라서 이를 가벼이 여겨서는 안 되며 관대하게 처벌해서도 안 된다. 건전한 경제 질서를 확립하기 위해 경제 사범을 엄벌할 필요가 있다. '한방 크게 해 먹고 몸으로 때우면 된다'는 한탕주의가 만연하지 않도록 처벌 수준을 더 높여야 한다. 지금까지 미진했던 부당 이익 환수도 앞으로 잘 이루어져 경제 범죄가 재발되지 않도록 해야 할 것이다.","options":["경제 범죄가 사회에 미치는 영향을 부정하고 있다.","경제 사범에 대한 처벌을 강화하도록 촉구하고 있다.","경제 사범의 처벌로 생긴 결과에 대해 우려하고 있다.","경제 범죄의 다양한 수법을 객관적으로 분석하고 있다."],"answer":2,"explain":"✅ <b>②</b>: автор настаивает усилить наказание экономических преступников (엄벌할 필요가 있다, 처벌 수준을 더 높여야 한다).<br>✖️ ① он не отрицает влияние — наоборот, подчёркивает ущерб; ③ не «опасается последствий наказания»; ④ не «объективно анализирует приёмы», а призывает к мерам.<br>🧩 경제 사범 — экономический преступник; 처벌 — наказание; 강화하다 — усиливать; 촉구하다 — призывать."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"주가 조작이나 공금 횡령 등의 경제 범죄는 … 사회에 미치는 충격과 피해가 막심하다. … 이러한 경제 범죄는 개인 손해를 넘어 국가 경제와도 직결될 수 있다. … 지금까지 미진했던 부당 이익 환수도 앞으로 잘 이루어져 경제 범죄가 재발되지 않도록 해야 할 것이다.","options":["경제 범죄로 생긴 부당 이익을 문제없이 잘 환수해 왔다.","공금을 불법으로 가로채는 범죄는 경제 범죄에 포함된다.","개인이 저지른 주가 조작 범죄는 국가 경제와 큰 관련이 없다.","경제 범죄 수법이 교묘해졌지만 사회에 미치는 충격은 크지 않다."],"answer":2,"explain":"✅ <b>②</b>: текст прямо относит к экономическим преступлениям «주가 조작이나 공금 횡령» — присвоение (횡령) общественных средств входит в эконом. преступления.<br>✖️ ① взыскание незаконной прибыли было НЕДОСТАТОЧНЫМ (미진했던); ③ такие преступления МОГУТ напрямую затрагивать экономику страны (국가 경제와도 직결); ④ удар по обществу как раз ОГРОМНЫЙ (충격과 피해가 막심).<br>🧩 공금 횡령 — растрата казённых средств; 가로채다 — присваивать; 부당 이익 — незаконная прибыль; 환수 — взыскание."},{"n":48,"points":2,"instr":"С какой целью написан текст?","passage":"예술인은 독창적인 문화를 창조하고 고유한 문화를 보존하는 동시에 예술 활동을 업으로 삼아 수익을 내서 생활하는 사람이다. 그런데 많은 예술인이 기본 생활이 불가능한 적은 수입 탓에 예술 활동을 포기한다. … 2012년부터 예술인의 권리 보호를 위해 '예술인 복지법'이 시행되었다. 그러나 이는 예술 현장의 실상에 맞지 않아 많은 예술인이 여전히 (생계의 어려움을 겪고 있다). … 올해 … 예술인 복지법이 개정되었다. … 앞으로는 이를 바탕으로 유능한 예술인이 활동을 포기하지 않도록 해야 할 것이다.","options":["예술인의 자질에 대해 분석하려고","예술 발전의 어려움을 토로하려고","예술 작품의 창작 활동을 설명하려고","예술인 생활 보장의 필요성을 강조하려고"],"answer":4,"explain":"✅ <b>④</b>: текст подчёркивает необходимость обеспечить деятелям искусства условия для жизни (закон о соцзащите, стабильность занятости), чтобы они не бросали творчество.<br>✖️ ① «качества артиста» не анализируются; ② это не просто «жалоба» на трудности; ③ творческий процесс не описывается.<br>🧩 예술인 — деятель искусства; 보장 — обеспечение; 강조하다 — подчёркивать; 복지법 — закон о соц. защите."},{"n":49,"points":2,"instr":"Выберите подходящее выражение в пропуск ( ).","passage":"예술인은 … 예술 활동을 업으로 삼아 수익을 내서 생활하는 사람이다. 그런데 많은 예술인이 기본 생활이 불가능한 적은 수입 탓에 예술 활동을 포기한다. … 2012년부터 … '예술인 복지법'이 시행되었다. 그러나 이는 예술 현장의 실상에 맞지 않아 많은 예술인이 여전히 (        ). 이런 상황에서 올해 … 예술인 복지법이 개정되었다.","options":["안전을 중요시해야 한다","생계의 어려움을 겪고 있다","한 번에 큰돈을 모을 수 있다","창작에 관한 기쁨을 지켜야 한다"],"answer":2,"explain":"✅ <b>② 생계의 어려움을 겪고 있다</b>: артисты бросают творчество из-за низких доходов, а закон не отражал реальность — поэтому многие ВСЁ ЕЩЁ испытывают трудности с заработком.<br>✖️ ① про «безопасность» — нет; ③ «разом скопить много денег» — противоречит контексту; ④ «беречь радость творчества» — не вяжется с «여전히».<br>🧩 실상 — реальное положение; 생계 — средства к жизни; 겪다 — испытывать; 여전히 — по-прежнему."},{"n":50,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с текстом.","passage":"2012년부터 예술인의 권리 보호를 위해 '예술인 복지법'이 시행되었다. 그러나 이는 예술 현장의 실상에 맞지 않아 많은 예술인이 여전히 생계의 어려움을 겪고 있다. 이런 상황에서 올해 예술 활동을 증명하지 못해 지원을 못 받았던 예술인을 위해 예술인 복지법이 개정되었다. 개정안은 이런 예술인도 일반 직업인과 같이 권리를 보호받을 수 있는 대상임을 명확히 하고 있다.","options":["예술인 복지법은 한 번 신설된 후 개정된 적이 없다.","전국에서 예술 분야에 종사하는 사람들 수가 늘고 있다.","올해부터 예술인은 활동을 반드시 증명해야 지원을 받을 수 있다.","2012년의 예술인 복지법은 현장의 실상을 반영하는 데 한계가 있었다."],"answer":4,"explain":"✅ <b>④</b>: закон 2012 года «예술 현장의 실상에 맞지 않아» — плохо отражал реальность сферы, отсюда его ограниченность.<br>✖️ ① закон КАК РАЗ изменили в этом году (개정되었다); ② деятелей искусства становится МЕНЬШЕ, идёт старение (감소하며 고령화); ③ поправка, наоборот, помогает тем, кто НЕ смог подтвердить деятельность (증명하지 못해 지원을 못 받았던 예술인을 위해).<br>🧩 복지법 — закон о соц. защите; 개정 — пересмотр, поправка; 실상 — реальность; 한계 — ограничение."}]
      },
      writing: {
        durationMin: 50, label: '제91회 · 쓰기 (51~54)',
        tasks: [
          { n:51, points:10, korInstr:'다음 글의 ㉠과 ㉡에 알맞은 말을 각각 쓰시오. (각 10점)',
            instr:'Впишите подходящие выражения в ㉠ и ㉡. Переписка с клиникой — формальный стиль -습니다.',
            passage:`💬 인주 피부과 병원\n[병원] 인주 피부과 병원입니다. 11월 13일 오전 10시에 진료 예약이 되어 있습니다.\n[나] 안녕하세요. 제가 13일에 일이 생겨서 병원에 못 가게 되었습니다. 그래서 예약을 14일 오전 10시로 ( ㉠ ). 만약에 이날 예약이 ( ㉡ ) 저는 15일 오전도 괜찮습니다. 예약 변경이 가능한지 확인해 주십시오.`,
            blanks:[
              { slot:'㉠', model:'바꾸고 싶습니다 / 변경하고 싶습니다 / 바꿨으면 합니다',
                check:'Смысл — «хочу перенести запись на 14-е»: 바꾸다/변경하다 + желание -고 싶다. Формальный стиль -습니다, законченное предложение.' },
              { slot:'㉡', model:'안 되면 / 어려우면 / 불가능하면',
                check:'«만약에» (если) → условие -(으)면. Смысл — «если на этот день записаться нельзя»: 안 되다/어렵다/불가능하다 + -(으)면.' }
            ] },
          { n:52, points:10, korInstr:'다음 글의 ㉠과 ㉡에 알맞은 말을 각각 쓰시오. (각 10점)',
            instr:'Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст — письменный стиль -ㄴ다.',
            passage:`스트레스를 받았을 때 사탕이나 과자와 같이 단 음식을 먹으면 기분이 좋아진다. 단 음식으로 인해 뇌에서 기분을 좋게 만드는 호르몬이 나오기 때문이다. 그런데 전문가들은 사람들이 술이나 담배에 중독되는 것처럼 단맛에도 ( ㉠ ). 따라서 평소에 단 음식을 지나치게 많이 ( ㉡ ) 주의할 필요가 있다.`,
            blanks:[
              { slot:'㉠', model:'중독될 수 있다고 한다 / 중독될 수 있다고 말한다',
                check:'«전문가들은…» → косвенная речь -다고 하다/말하다. Смысл — «к сладкому тоже можно пристраститься»: 중독되다 + возможность -(으)ㄹ 수 있다. Стиль -ㄴ다.' },
              { slot:'㉡', model:'먹지 않도록 / 먹지 않게',
                check:'Смысл — «следить, чтобы НЕ есть слишком много»: отрицание -지 않다 + -도록 (чтобы).' }
            ] },
          { n:53, points:30, min:200, max:300, korInstr:'다음은 \'편의점 매출액 변화\'에 대한 자료이다. 이 내용을 200~300자의 글로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)',
            instr:'Опишите данные «편의점 매출액 변화» (изменение выручки минимаркетов) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.',
            image:'assets/topik2/exams/img/91-w53.png',
            model:'산업경제연구소의 조사에 따르면 편의점 매출액은 2015년 17조 2천억 원에서 2022년 22조 3천억 원으로 크게 증가하였다. 반면에 대형 마트의 매출액은 같은 기간 24조 2천억 원에서 24조 3천억 원으로 거의 변화가 없었다. 편의점 매출액이 이렇게 증가한 원인으로는 편의점 수가 늘면서 고객 접근성이 향상된 것과 소포장 상품에 대한 수요가 증가한 것을 들 수 있다. 이에 따라 2023년에는 편의점 매출액이 대형 마트 매출액을 넘어설 것으로 전망된다.',
            check:'① Источник назван (산업경제연구소 / N에 따르면)? ② Обе линии графика с цифрами (편의점 17조 2천억→22조 3천억, 대형 마트 почти без изменений)? ③ Обе причины (рост числа магазинов → доступность; спрос на мелкую фасовку)? ④ Прогноз 2023 (편의점 > 대형 마트, -(으)ㄹ 것으로 전망된다)? ⑤ Стиль -ㄴ다, объём 200–300.' },
          { n:54, points:50, min:600, max:700, korInstr:'다음을 참고하여 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)',
            instr:'Эссе 600–700 знаков на тему «가짜 뉴스의 등장이 사회에 미치는 영향» (влияние фейковых новостей на общество). Раскройте все три вопроса из задания (фон появления → проблемы → пути решения), каждый — отдельным абзацем.',
            passage:`오늘날 우리는 정보 통신 기술의 발달로 누구나 쉽게 정보를 생산하여 대중에게 전달할 수 있다. 그런데 정보의 생산과 유통을 통해 개인과 집단이 이익을 얻을 수도 있게 되면서 사실과 다른 '가짜 뉴스'가 늘어나고 있다.\n• 가짜 뉴스가 생겨나는 사회적 배경은 무엇인가?\n• 가짜 뉴스로 인해 어떤 문제가 생길 수 있는가?\n• 이러한 문제들을 해결하기 위해서 어떤 방안이 필요한가?`,
            model:'오늘날 정보 통신 기술의 발달로 누구나 쉽게 정보를 만들고 퍼뜨릴 수 있게 되었다. 이러한 환경에서 사실과 다른 가짜 뉴스가 빠르게 늘어나고 있다. 가짜 뉴스가 생겨나는 사회적 배경으로는 우선 정보의 생산과 유통으로 경제적 이익을 얻을 수 있다는 점을 들 수 있다. 사람들의 관심을 끌수록 광고 수익이 커지기 때문에 일부러 자극적인 거짓 정보를 만드는 것이다. 또한 누구나 검증 없이 정보를 올릴 수 있는 인터넷 환경도 가짜 뉴스가 퍼지기 쉬운 조건이 된다.\n가짜 뉴스는 심각한 문제를 일으킨다. 개인은 잘못된 정보 때문에 건강이나 재산에 피해를 입을 수 있고, 거짓 소문으로 명예를 잃기도 한다. 나아가 사회 전체적으로는 언론에 대한 신뢰가 무너지고 사람들 사이의 갈등이 깊어지며, 올바른 판단이 필요한 순간에 사회가 잘못된 방향으로 움직일 수 있다.\n이러한 문제를 해결하기 위해서는 여러 가지 노력이 필요하다. 먼저 정보를 받아들이는 사람들이 출처를 확인하고 비판적으로 판단하는 능력을 길러야 한다. 또한 언론과 인터넷 기업은 사실 확인을 강화하여 가짜 뉴스가 퍼지는 것을 막아야 한다. 정부 역시 거짓 정보로 이익을 얻는 행위를 제재할 수 있는 제도를 마련해야 한다.\n결국 가짜 뉴스 문제는 개인과 기업, 정부가 함께 노력할 때 해결될 수 있으며, 이를 통해 우리는 건강한 정보 사회를 만들어 갈 수 있을 것이다.',
            check:'① Все 3 вопроса раскрыты (фон появления / проблемы / решения) — каждый в своём абзаце? ② Есть вступление и вывод? ③ Связки уровня (뿐만 아니라, 나아가, 따라서, 이를 통해)? ④ Стиль -ㄴ다, без разговорных форм? ⑤ Объём 600–700 знаков?' }
        ]
      }
    },
    83: {
      listening: {
        durationMin: 60, total: 100, label: '제83회 · 듣기 (1~50)',
        audio: 'assets/topik2/past-papers/83/83rd%20TOPIK%20II%20Listening%20Audio.mp3',
        questions: [{"n":1,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/83-l-q1.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 여자: 지금 전시장에 들어갈 수 있어요? 남자: 잠시만 기다려 주세요. 곧 입장 시작합니다. 여자: 네, 알겠습니다.<br>✅ <b>①</b>: посетительница спрашивает, можно ли уже войти в выставочный зал; сотрудник просит немного подождать — вход вот-вот откроют. На картинке ① — вход на выставку (витрина с вазой), люди ждут у входа.<br>✖️ ② сцена у кассы в магазине; ③ пара рассматривает что-то вместе; ④ люди стоят порознь — «ждём открытия входа» там не показано.<br>🧩 전시장 — выставочный зал; 입장 — вход (на мероприятие); 곧 — скоро; 잠시만 기다려 주세요 — подождите немного."},{"n":2,"points":2,"instr":"Послушайте и выберите подходящую картинку.","image":"assets/topik2/exams/img/83-l-q2.png","options":["①","②","③","④"],"answer":1,"explain":"🎧 남자: 아, 무거워. 이 화분은 어디에 놓을까? 여자: 여기 창문 앞은 어때요? 남자: 그래, 거기가 좋겠다.<br>✅ <b>①</b>: мужчина держит тяжёлый горшок с цветком и думает, куда поставить; женщина предлагает место перед окном. На ① мужчина с горшком, женщина показывает к окну.<br>✖️ ② оба сидят за столом и возятся с цветами; ③ мужчина один с растениями; ④ другая расстановка. «Держит горшок и выбирает место» — только ①.<br>🧩 화분 — горшок с растением; 놓다 — ставить; 무겁다 — тяжёлый; 창문 앞 — перед окном."},{"n":3,"points":2,"instr":"Послушайте и выберите подходящий график.","image":"assets/topik2/exams/img/83-l-q3.png","options":["①","②","③","④"],"answer":3,"explain":"🎧 Цель визита иностранных туристов: чаще всего «отпуск» (휴가), затем «бизнес» и «визит к родственникам». С кем приезжают: «семья или друзья» 54%, «в одиночку» 33%, «коллеги» 10%.<br>✅ <b>③</b>: вопрос — с КЕМ приезжают. Круговая диаграмма ③ показывает ровно эти доли: 가족·친구 54%, 혼자 33%, 동료 10%.<br>✖️ ①② — это графики «цель визита», а спрашивают про спутников; ④ — доли «혼자» и «동료» перепутаны (10% и 33%).<br>🧩 함께 — вместе; 혼자 — в одиночку; 동료 — коллега; -(으)로 나타나다 — оказаться/составить (в статистике)."},{"n":4,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["어제 다 읽었어요.","천천히 읽고 돌려줘.","책 읽을 시간이 없었어.","재미있는 책 좀 추천해 줘."],"answer":2,"explain":"🎧 여자: 민수야, 내가 빌려 준 책 읽고 있어? 재미있지? 남자: 응, 재미있어. 근데 언제까지 돌려주면 돼?<br>✅ <b>② 천천히 읽고 돌려줘</b>: парень спрашивает, к какому сроку вернуть книгу; та, что дала книгу, отвечает «читай не спеша и потом верни» — то есть не торопись.<br>✖️ ① «вчера всё прочитал» — не отвечает на «когда вернуть»; ③ «не было времени читать» — противоречит «읽고 있어»; ④ «посоветуй интересную книгу» — не в тему.<br>🧩 빌려주다 — дать в долг/одолжить; 돌려주다 — вернуть; 천천히 — медленно, не спеша."},{"n":5,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["그래요? 한번 가 봐야겠어요.","그럼요. 내일부터 일하기로 했어요.","정말요? 힘들면 언제든지 그만두세요.","맞아요. 좋은 곳을 구해서 기분이 좋아요."],"answer":1,"explain":"🎧 남자: 아직도 아르바이트를 못 구했어요. 여자: 학교 앞 식당에서 일할 사람을 찾던데요.<br>✅ <b>① 그래요? 한번 가 봐야겠어요</b>: парень ещё не нашёл подработку; ему подсказывают вакансию в кафе у школы — логичная реакция «правда? надо бы туда сходить».<br>✖️ ② «договорился работать с завтра» — он ещё не нашёл; ③ «бросайте, если тяжело» — обращено к нему же, нелогично; ④ «нашёл хорошее место» — противоречит «못 구했어요».<br>🧩 아르바이트를 구하다 — искать/находить подработку; -아/어야겠다 — «надо бы, пожалуй»; 찾던데요 — «искали, между прочим» (-던데요, мягкая подсказка)."},{"n":6,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["그럼 하얀색으로 바꾸러 가자.","나는 다른 운동화 신어 볼래.","새로 산 운동화가 마음에 들어.","파란색이 너한테 더 잘 어울려."],"answer":4,"explain":"🎧 여자: 나는 이 운동화로 할래. 너는 뭐 살 거야? 남자: 난 파란색이랑 하얀색 둘 다 마음에 드는데, 뭐가 더 괜찮아?<br>✅ <b>④ 파란색이 너한테 더 잘 어울려</b>: парень не может выбрать между синими и белыми кроссовками и спрашивает совета; естественный ответ — «синие тебе больше идут».<br>✖️ ① «пойдём поменяем на белые» — он ещё ничего не купил; ② «примерю другие» — отвечает за себя, а спрашивал он; ③ «нравятся новые кроссовки» — не про выбор цвета.<br>🧩 마음에 들다 — нравиться; 어울리다 — идти, подходить (об одежде); 둘 다 — оба."},{"n":7,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["비가 곧 그칠 거래요.","일기 예보를 볼 걸 그랬어요.","장마가 끝나니까 진짜 더워질 거예요.","작년하고 거의 비슷할 거래요."],"answer":4,"explain":"🎧 여자: 뉴스에서 봤는데 주말부터 장마가 시작된대요. 남자: 그래요? 올해도 작년만큼 비가 많이 올까요?<br>✅ <b>④ 작년하고 거의 비슷할 거래요</b>: мужчина спрашивает, будет ли в этом году дождей столько же, сколько в прошлом; ответ по теме — «будет примерно как в прошлом году».<br>✖️ ① «дождь скоро прекратится» — сезон только начинается; ② «надо было посмотреть прогноз» — не отвечает на вопрос; ③ «когда сезон дождей кончится, станет жарко» — не про сравнение с прошлым годом.<br>🧩 장마 — сезон дождей; 만큼 — «столько же, как»; -ㄴ대요/-(ㄴ)다고 해요 — пересказ чужих слов."},{"n":8,"points":2,"instr":"Выберите подходящее продолжение диалога.","options":["곧 배송된다니 다행이에요.","제품에 문제가 있는 것 같아요.","언제쯤 배송될지 확인해 주시겠어요?","고객 센터 전화번호 좀 알려 주실래요?"],"answer":3,"explain":"🎧 남자: 고객 센터죠? 일주일 전에 의자를 주문했는데 아직 안 와서요. 여자: 죄송합니다. 주문량이 많아서 배송이 늦어지고 있습니다.<br>✅ <b>③ 언제쯤 배송될지 확인해 주시겠어요?</b>: заказ задерживается; естественно попросить уточнить, когда же доставят.<br>✖️ ① «хорошо, что скоро доставят» — срок ещё не назвали; ② «кажется, товар бракованный» — речь о доставке, не о браке; ④ «дайте телефон call-центра» — он уже звонит в call-центр.<br>🧩 배송 — доставка; 늦어지다 — задерживаться; -(으)ㄹ지 — «когда/ли» (косвенный вопрос); 확인하다 — уточнять, проверять."},{"n":9,"points":2,"instr":"Что женщина сделает следующим действием?","options":["사과를 씻는다.","과일을 자른다.","설탕을 가져온다.","냄비를 찾아온다."],"answer":3,"explain":"🎧 여자: 사과는 다 씻었고, 이제 자르면 되겠다. 남자: 자르는 건 내가 할 테니까 거기 있는 냄비 좀 줄래? 여자: 여기 있어. 근데 잼 만들려면 설탕이 더 필요하겠네. 내가 찾아올까? 남자: 응, 좀 갖다 줘.<br>✅ <b>③ 설탕을 가져온다</b>: яблоки помыты, резать вызвался мужчина; женщина замечает, что для джема нужен сахар, и предлагает «내가 찾아올까?» — мужчина просит принести. Значит дальше она идёт за сахаром.<br>✖️ ① яблоки уже помыты; ② резать будет мужчина; ④ кастрюлю она уже подала.<br>🧩 잼 — джем; 설탕 — сахар; 갖다 주다 — принести (и отдать); -(으)ㄹ까? — «может, я …?»"},{"n":10,"points":2,"instr":"Что женщина сделает следующим действием?","options":["모자를 벗는다.","놀이 기구에 탄다.","떨어진 물건을 줍는다.","남자에게 가방을 받는다."],"answer":1,"explain":"🎧 남자: 손님, 놀이 기구 타실 거죠? 그러면 가방은 여기에 보관하시겠어요? 여자: 네, 여기요. 모자는 쓰고 타도 돼요? 남자: 그것도 날아갈 수 있으니까 같이 보관해 드릴게요. 여자: 알겠습니다.<br>✅ <b>① 모자를 벗는다</b>: сотрудник предлагает сдать на хранение и шапку — может слететь на аттракционе; женщина соглашается, значит дальше снимает шапку, чтобы отдать.<br>✖️ ② на аттракцион сядет позже; ③ ничего не падало; ④ сумку она ОТДАЁТ на хранение, а не получает.<br>🧩 놀이 기구 — аттракцион; 보관하다 — хранить, сдавать на хранение; 벗다 — снимать (одежду/головной убор); 날아가다 — улететь."},{"n":11,"points":2,"instr":"Что женщина сделает следующим действием?","options":["세탁물을 넣는다.","안내문을 읽는다.","동전을 바꾸러 간다.","세탁 코스를 선택한다."],"answer":3,"explain":"🎧 여자: 빨래방은 처음인데 먼저 코스 선택하고 세탁물 넣으면 되나? 남자: 여기 안내문 있다. 세탁물 넣은 후에 코스 선택하고, 동전 넣으래. 여자: 나 동전은 없는데. 아, 저기 동전 교환기 있네. 바꿔 올게. 남자: 응, 난 또 뭘 해야 되는지 읽어 볼게.<br>✅ <b>③ 동전을 바꾸러 간다</b>: нужны монеты, у женщины их нет, она замечает разменный автомат и говорит «바꿔 올게» — идёт менять.<br>✖️ ① бельё кладут после выбора (по инструкции); ② инструкцию читает мужчина («읽어 볼게»); ④ курс выбирают после загрузки белья.<br>🧩 빨래방 — прачечная-автомат; 동전 — монета; 교환기 — разменный автомат; -(으)ㄹ게 — «я (сделаю)»."},{"n":12,"points":2,"instr":"Что женщина сделает следующим действием?","options":["거울을 치운다.","카메라를 설치한다.","카메라 화면을 본다.","촬영할 물건을 가져온다."],"answer":1,"explain":"🎧 여자: 감독님, 촬영 준비 끝났습니다. 물건들도 제자리에 놓았고요. 남자: 그럼 카메라 화면에서 어떻게 보이는지 확인해 봅시다. 음, 저 거울이 꼭 필요할까요? 여자: 거울이 커서 그런지 사무실처럼 보이지가 않네요. 치울까요? 남자: 네, 그렇게 해 주세요.<br>✅ <b>① 거울을 치운다</b>: режиссёр сомневается, нужно ли большое зеркало; женщина предлагает «치울까요?» — он соглашается, значит дальше убирает зеркало.<br>✖️ ② камеру уже навели (смотрят в кадр); ③ кадр уже посмотрели; ④ реквизит уже расставлен («제자리에 놓았고요»).<br>🧩 촬영 — съёмка; 감독 — режиссёр; 치우다 — убирать; 제자리 — своё место."},{"n":13,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["두 사람은 모형 배를 만드는 중이다.","이 모형 배는 가죽으로 만들었다.","여자는 남자가 준 사진을 보고 있다.","남자는 이 모형 배를 직접 본 적이 있다."],"answer":2,"explain":"🎧 여자: 이 사진 좀 볼래? 이게 모형이래. 실제 배하고 똑같지? 남자: 와, 정말 잘 만들었다. 근데 뭐로 만든 거야? 나무인가? 여자: 아니, 가죽으로 만든 거래. 남자: 신기하네. 가죽을 이용해서 배 모형을 만들다니. 직접 한번 보고 싶다.<br>✅ <b>②</b>: модель корабля сделана из кожи (가죽으로 만든 거래).<br>✖️ ① они не делают модель, а смотрят фото; ③ фото показывает женщина мужчине, а не наоборот; ④ мужчина только хочет увидеть вживую («직접 보고 싶다»), ещё не видел.<br>🧩 모형 — модель, макет; 가죽 — кожа; 직접 — лично, вживую; -다니 — «надо же, …!» (удивление)."},{"n":14,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["개회식은 대회장에서 열린다.","대회의 장면을 찍을 수 있다.","예선 경기는 두 시에 시작된다.","개회식 후에 대기실로 가야 한다."],"answer":1,"explain":"🎧 (объявление) Танцевальный конкурс. Через некоторое время, с 2 часов, состоится церемония открытия. Участникам из комнаты ожидания нужно пройти в зал соревнований (대회장으로). Сразу после открытия начнутся отборочные — ждите на месте. Во время конкурса съёмка запрещена.<br>✅ <b>①</b>: церемония открытия проходит в зале соревнований (участников зовут именно туда).<br>✖️ ② съёмка ЗАПРЕЩЕНА (촬영을 할 수 없으니); ③ отборочные — ПОСЛЕ открытия (а открытие в 2 часа), не в 2; ④ идти надо в зал, а не в комнату ожидания.<br>🧩 개회식 — церемония открытия; 대회장 — зал/место соревнований; 예선 — отборочный тур; -는 대로 — «как только»."},{"n":15,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 사고는 오전에 발생했다.","등산객들은 모두 구조되었다.","사고 발생 원인을 조사할 예정이다.","산 정상에 오르다가 사고가 발생했다."],"answer":2,"explain":"🎧 (новости) Вчера в 10 вечера на горе Инджу спасли четверых заблудившихся туристов. Получив сигнал, спасатели сразу начали поиски и за два часа нашли всех. Выяснилось, что туристы заблудились, когда спускались с вершины и стемнело.<br>✅ <b>②</b>: все туристы спасены (네 명이 구조됐습니다 / 모두를 발견).<br>✖️ ① происшествие ночью (열 시), не утром; ③ причина уже установлена (확인됐습니다) — расследование не планируют; ④ заблудились на СПУСКЕ (내려오던 중), а не на подъёме.<br>🧩 등산객 — турист/альпинист; 구조되다 — быть спасённым; 정상 — вершина; 길을 잃다 — заблудиться."},{"n":16,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["여자는 전문적으로 그림을 배웠다.","여자의 그림은 화려한 느낌을 준다.","여자가 화가가 된 지 70년이 넘었다.","여자는 평범한 것을 그림의 소재로 삼는다."],"answer":4,"explain":"🎧 남자: 작가님의 그림이 인기를 얻고 있는 이유는 뭐라고 생각하십니까? 여자: 우리 주변의 흔하고 평범한 소재를 따뜻하게 그리기 때문이 아닐까요? 저는 행복했던 어린 시절을 기억하고 싶어서 70세가 넘어서야 그림을 그리기 시작했어요. 물론 배운 적도 없고요. 꾸미지 않은 그런 느낌을 사람들이 좋아해 주는 것 같아요.<br>✅ <b>④</b>: художница берёт сюжетами обычные, повседневные вещи (흔하고 평범한 소재).<br>✖️ ① она нигде не училась (배운 적도 없고요); ② её работы дают «неприукрашенное» чувство (꾸미지 않은), а не пышное/яркое; ③ она НАЧАЛА рисовать после 70 лет, а не «70 лет как стала художницей».<br>🧩 소재 — материал, сюжет; 평범하다 — обычный; 꾸미다 — украшать; -아/어서야 — «только после того как»."},{"n":17,"points":2,"instr":"Выберите главную мысль мужчины.","options":["메일을 자주 확인해야 한다.","답장이 올 때까지 기다리는 게 낫다.","메일을 받은 사실을 알려 줘야 한다.","답장을 보내기 전에 확인하는 게 좋다."],"answer":3,"explain":"🎧 남자: 수미야, 내가 보낸 메일 못 받았어? 여자: 아니, 받았어. 어떻게 쓸까 생각하느라고 아직 답장을 못 보냈어. 남자: 난 메일이 안 갔나 걱정했어. 기다렸으면 받았다는 말이라도 해 주지.<br>✅ <b>③</b>: мужчина переживал, дошло ли письмо; его мысль — «хотя бы сообщи, что получил(а) письмо».<br>✖️ ① «надо часто проверять почту» — не его идея; ② «лучше ждать ответа» — наоборот, он недоволен молчанием; ④ «проверять перед отправкой ответа» — не об этом.<br>🧩 답장 — ответ (на письмо); -느라고 — «из-за того что (был занят чем-то)»; -지 (그러다) — мягкий упрёк «мог бы и …»."},{"n":18,"points":2,"instr":"Выберите главную мысль мужчины.","options":["공부는 매일 하는 것이 중요하다.","공부하는 장소를 바꿀 필요가 있다.","새벽에 일어나서 공부하는 게 좋다.","피곤할 때는 적당한 휴식도 필요하다."],"answer":3,"explain":"🎧 남자: 요즘 새벽에 일어나서 공부하는데 집중이 잘되더라. 여자: 그래? 난 새벽에 일어나면 많이 피곤할 것 같은데. 남자: 처음엔 나도 좀 피곤했는데 이제는 공부가 잘돼서 좋아.<br>✅ <b>③</b>: мужчина рано встаёт, хорошо концентрируется и доволен — его мысль «заниматься на рассвете хорошо».<br>✖️ ① про «каждый день» он не говорит; ② место учёбы не обсуждается; ④ про отдых при усталости — не его вывод.<br>🧩 새벽 — рассвет, раннее утро; 집중이 잘되다 — хорошо концентрироваться; -더라 — «оказывается (я заметил)»."},{"n":19,"points":2,"instr":"Выберите главную мысль мужчины.","options":["다양한 분야의 사람을 만나야 한다.","직업을 자주 바꾸는 것은 좋지 않다.","같이 일하는 사람과 잘 지내야 한다.","진로에 대해 충분히 고민할 필요가 있다."],"answer":1,"explain":"🎧 여자: 지난번에 갔던 직업인들과의 만남 프로그램, 진짜 좋았지? 남자: 응, 다양한 직업을 가진 사람들의 이야기를 들으니까 참 좋았어. 여자: 맞아, 진로를 결정하는 데에도 꽤 도움이 됐어. 남자: 여러 분야의 사람들을 만나면 배울 것도 많은 것 같아.<br>✅ <b>①</b>: мужчина делает вывод — встречаясь с людьми из разных сфер, многому учишься → «надо встречаться с людьми из разных областей».<br>✖️ ② про частую смену работы речи нет; ③ про отношения с коллегами — нет; ④ «обдумать карьеру» упоминала женщина, и это не главная мысль мужчины.<br>🧩 분야 — сфера, область; 진로 — карьерный путь; 만남 — встреча; -(으)니까 — «так как»."},{"n":20,"points":2,"instr":"Выберите главную мысль мужчины.","options":["오래된 지명을 새롭게 바꿀 필요가 있다.","지명은 많은 사람이 알기 쉽게 만들어야 한다.","지명에 쓰인 아름다운 옛말이 사용되면 좋겠다.","지명을 만들 때는 마을의 문화를 반영해야 한다."],"answer":3,"explain":"🎧 여자: 선생님, 마을 이름에 대한 책을 내신 특별한 계기가 있으신가요? 남자: 네, 지명에는 지금은 안 쓰는 옛날 말이 많이 남아 있습니다. … 무척 아름다운 표현들이 많은데요. 그런 표현들이 다시 우리의 일상으로 들어와 … 사용됐으면 하는 마음으로 책을 쓰게 됐어요.<br>✅ <b>③</b>: автор хочет, чтобы красивые старинные слова, сохранившиеся в топонимах, снова вошли в обиход.<br>✖️ ① менять старые названия он не предлагает; ② про «простоту для понимания» не говорит; ④ «отражать культуру при создании названий» — не его мысль (он о возвращении старых слов).<br>🧩 지명 — топоним, название места; 옛말 — старинное слово; 일상 — повседневность; -았/었으면 하다 — «хотелось бы, чтобы»."},{"n":21,"points":2,"instr":"Выберите главную мысль мужчины.","options":["설문 조사의 주제를 바꿔야 한다.","설문 조사는 결과 분석이 중요하다.","설문 조사의 계획을 잘 세워야 한다.","설문 조사는 응답자 수가 많을수록 좋다."],"answer":3,"explain":"🎧 여자: 교수님, 제 연구 계획서인데요. 한번 봐 주시겠어요? 남자: '성격과 여행지'라. … 주제가 아주 새롭고 좋아요. 연구 방법으로는 설문 조사를 선택했는데 계획이 거의 없네요. 설문 조사는 조사하려는 내용이 분명해야 하니까 조사 대상과 내용을 잘 계획할 필요가 있어요.<br>✅ <b>③</b>: профессор хвалит тему, но видит, что план опроса почти не проработан → «нужно хорошо спланировать опрос» (предмет и содержание).<br>✖️ ① тему менять не надо — она новая и хорошая; ② про анализ результатов он не говорит; ④ про число респондентов — нет.<br>🧩 설문 조사 — опрос, анкетирование; 연구 계획서 — план исследования; 조사 대상 — объект опроса; -아/어야 하다 — нужно."},{"n":22,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["남자는 연구 계획서를 작성하고 있다.","남자는 성격에 대한 연구를 하려고 한다.","남자는 연구 방법을 아직 결정하지 못했다.","남자는 여자의 연구 주제가 새롭다고 생각한다."],"answer":4,"explain":"🎧 (тот же диалог) 남자: 주제가 아주 새롭고 좋아요.<br>✅ <b>④</b>: мужчина (профессор) считает тему исследования женщины новой.<br>✖️ ① план исследования пишет ЖЕНЩИНА (제 연구 계획서); ② исследование о «характере и месте отдыха» ведёт женщина; ③ метод уже выбран — опрос (설문 조사를 선택했는데).<br>🧩 작성하다 — составлять (документ); 주제 — тема; 결정하다 — решать; 새롭다 — новый."},{"n":23,"points":2,"instr":"Что делает мужчина (с какой целью говорит)?","options":["취업에 성공한 방법을 소개하고 있다.","신입 사원 연수 일정을 변경하고 있다.","신입 사원 채용 절차를 설명하고 있다.","입사 전에 해야 할 일을 안내하고 있다."],"answer":4,"explain":"🎧 남자: 안녕하십니까, 인주 상사입니다. 합격자 분들에게 건강 검진과 신입 사원 연수 일정을 문자로 보내 드렸는데 확인하셨나요? … 검진 결과는 … 출근 첫날에 내시면 되고요. 신입 사원 연수 때는 … 증명서만 제출하시면 됩니다.<br>✅ <b>④</b>: сотрудник компании объясняет принятому кандидату медосмотр, программу адаптации и что сдать — то есть что нужно сделать ДО выхода на работу.<br>✖️ ① «как устроиться на работу» он не рассказывает; ② график не меняют — его только сообщают; ③ процедуру НАЙМА (отбора) не описывает — кандидат уже прошёл (합격자).<br>🧩 합격자 — прошедший отбор; 신입 사원 — новый сотрудник; 연수 — стажировка, адаптация; 입사 — поступление на работу."},{"n":24,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 회사의 신입 사원 연수가 끝났다.","신입 사원 연수 일정을 문자로 공지했다.","건강 검진은 정해진 병원에서 받아야 한다.","건강 검진 결과는 출근 후에 제출하면 된다."],"answer":2,"explain":"🎧 (тот же диалог) 남자: 건강 검진과 신입 사원 연수 일정을 문자로 보내 드렸는데…<br>✅ <b>②</b>: график адаптации новых сотрудников сообщили по СМС.<br>✖️ ① стажировка ещё не прошла (на ней только встретятся); ③ медосмотр можно пройти в ближайшей поликлинике/больнице (집 근처 보건소나 병원), не в строго определённой; ④ результаты сдают КОНКРЕТНО в первый день выхода (출근 첫날에), а не «когда-нибудь после выхода».<br>🧩 공지하다 — оповещать; 정해진 — установленный; 보건소 — поликлиника; 출근 첫날 — первый рабочий день."},{"n":25,"points":2,"instr":"Выберите главную мысль мужчины.","options":["타이어를 설계할 때는 환경을 생각해야 한다.","생산된 타이어의 저장 공간을 마련해야 한다.","운전자의 의견을 타이어 디자인에 반영해야 한다.","타이어의 재료로 쓸 새로운 소재를 연구해야 한다."],"answer":1,"explain":"🎧 남자: 환경 보호를 위해서는 성능만 강조하는 기존의 타이어 설계에 변화가 필요하다고 생각했습니다. 타이어에서 생기는 작은 플라스틱들이 대기 오염의 가장 큰 원인이 되고 있거든요. … 미세 플라스틱 조각이 … 캡슐 장치에 모여 저장되도록 설계했습니다.<br>✅ <b>①</b>: ради защиты среды дизайн шин должен меняться — то есть «проектируя шины, надо думать об экологии».<br>✖️ ② «хранилище для шин» — речь о капсуле для микропластика, а не о складе; ③ мнение водителей в дизайн не закладывают; ④ про поиск нового материала шины не говорит.<br>🧩 설계하다 — проектировать; 환경 보호 — защита среды; 미세 플라스틱 — микропластик; 대기 오염 — загрязнение воздуха."},{"n":26,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 타이어는 많은 판매량을 기록했다.","이 타이어의 안쪽에는 특수한 장치가 있다.","이 타이어는 성능 향상에 중점을 두고 개발되었다.","이 타이어는 대기 오염의 정도를 색깔로 알려 준다."],"answer":2,"explain":"🎧 (то же интервью) 남자: 타이어 안쪽의 캡슐 장치에 모여 저장되도록 설계했습니다. 캡슐이 가득 차면 타이어 옆면의 색이 바뀌어서…<br>✅ <b>②</b>: внутри шины есть специальное устройство — капсула.<br>✖️ ① продажи только вот-вот начнутся (판매를 곧 시작) — рекордов ещё нет; ③ упор сделан на экологию, а не на рост производительности; ④ смена цвета сообщает, что КАПСУЛА заполнилась, а не «степень загрязнения воздуха».<br>🧩 장치 — устройство; 판매량 — объём продаж; 중점을 두다 — делать упор; 향상 — улучшение."},{"n":27,"points":2,"instr":"С какой целью говорит мужчина?","options":["공간 대여 사업의 결과를 알려 주려고","공간 대여에 필요한 서류를 문의하려고","공간 대여를 위한 신청서의 작성을 부탁하려고","공간 대여 사업에 함께 신청할 것을 제안하려고"],"answer":4,"explain":"🎧 남자: 학교에서 남는 공간을 창업 동아리에 무료로 대여해 준대. 우리도 한번 지원해 보자.<br>✅ <b>④</b>: мужчина рассказывает о программе бесплатной аренды свободных помещений и предлагает «подадим вместе».<br>✖️ ① результатов ещё нет — приём заявок только идёт; ② про документы он сам не знает («정확히 모르겠어») — не выясняет их как цель речи; ③ заполнить заявку он не просит — предлагает участвовать вместе.<br>🧩 대여하다 — сдавать в аренду; 창업 동아리 — стартап-кружок; 지원하다 — подавать заявку; 제안하다 — предлагать."},{"n":28,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 사업은 다음 주까지 신청할 수 있다.","이 사업에서는 비어 있는 공간을 활용한다.","이 사업을 통해 적은 비용으로 공간을 빌릴 수 있다.","이 사업에 지원하려면 사무실에 서류를 제출해야 한다."],"answer":2,"explain":"🎧 (тот же разговор) 여자: 학교 안의 빈 공간을 빌려 주는 사업 맞지?<br>✅ <b>②</b>: программа использует пустующие помещения школы.<br>✖️ ① подать заявку (ввести данные) нужно до ПЯТНИЦЫ, до след. недели — лишь догрузка документов; ③ аренда БЕСПЛАТНАЯ (무료로), а не «за небольшую плату»; ④ заявка — через сайт (홈페이지에 입력), а в офис идут только СПРОСИТЬ про документы.<br>🧩 활용하다 — использовать; 비어 있다 — быть пустым; 비용 — расходы; 제출하다 — подавать."},{"n":29,"points":2,"instr":"Кто такой мужчина (чем он занимается)?","options":["게임의 오류를 찾아내는 사람","새로운 게임을 기획하는 사람","게임에 음향 효과를 넣는 사람","새로 개발한 게임을 홍보하는 사람"],"answer":1,"explain":"🎧 남자: 개발팀이 완성한 게임을 일정 기간 동안 직접 해 보면서 기술적인 오류를 찾아내고 있습니다.<br>✅ <b>①</b>: до релиза он сам играет в готовую игру и находит технические ошибки → «человек, который находит ошибки в игре».<br>✖️ ② игру задумывает команда разработки; ③ он не добавляет звуковые эффекты, а проверяет связанные с ними проблемы; ④ рекламой игры не занимается.<br>🧩 오류 — ошибка, сбой; 출시 — выпуск (на рынок); 기획하다 — планировать, задумывать; 음향 효과 — звуковой эффект."},{"n":30,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 일은 개발팀이 담당하고 있다.","이 일은 게임의 판매에 영향을 미친다.","남자는 게임 출시 후에 일을 시작한다.","남자는 게임 캐릭터도 직접 디자인한다."],"answer":2,"explain":"🎧 (то же интервью) 남자: 출시 후에 이런 문제가 발생하면 게임 판매에 부정적인 영향을 주게 되거든요.<br>✅ <b>②</b>: эта работа влияет на продажи игры.<br>✖️ ① ошибки ищет команда тестировщика (мужчины), а не команда разработки; ③ он работает ДО релиза (출시 전까지); ④ дизайн персонажей он не делает — лишь находит в нём проблемы.<br>🧩 담당하다 — отвечать за; 영향을 미치다 — влиять; 부정적 — негативный; 책임감 — чувство ответственности."},{"n":31,"points":2,"instr":"Выберите главную мысль мужчины.","options":["업무 관리 프로그램의 도입이 필요하다.","업무 방식의 개선을 신중히 결정해야 한다.","직원 교육을 통해 업무의 효율을 높여야 한다.","일의 속도를 강조하는 분위기를 바꿀 필요가 있다."],"answer":1,"explain":"🎧 남자: 현재 검토 중인 업무 관리 프로그램요. … 일의 속도와 효율성을 향상시킬 것으로 보입니다. … 초기에는 어려움이 있겠지만 장기적으로는 업무를 관리하는 데 큰 도움이 될 겁니다.<br>✅ <b>①</b>: мужчина выступает за внедрение программы управления работой — она повысит скорость и эффективность.<br>✖️ ② «осторожно решать» — это позиция женщины; ③ обучение сотрудников — лишь средство, не главная мысль; ④ про «изменить атмосферу гонки за скоростью» речи нет.<br>🧩 도입 — внедрение; 업무 관리 — управление работой; 효율성 — эффективность; 장기적으로 — в долгосрочной перспективе."},{"n":32,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["예상되는 문제점을 우려하고 있다.","문제의 해결 방안을 요구하고 있다.","자신의 의견을 일관되게 주장하고 있다.","상대방의 의견에 적극적으로 동의하고 있다."],"answer":3,"explain":"🎧 (то же обсуждение) женщина сомневается (адаптация сложна, обучение в тягость), но мужчина последовательно отстаивает: «초기에는 어렵지만 장기적으로 도움이 된다», «교육하면 잘 활용할 수 있다».<br>✅ <b>③</b>: мужчина последовательно отстаивает своё мнение.<br>✖️ ① опасения высказывает женщина, а не он; ② решения проблемы он не «требует»; ④ с возражениями собеседницы он как раз НЕ соглашается.<br>🧩 일관되다 — быть последовательным; 주장하다 — утверждать, настаивать; 우려하다 — опасаться; 동의하다 — соглашаться."},{"n":33,"points":2,"instr":"О чём этот рассказ?","options":["기능에 따른 지퍼의 형태","지퍼를 활용한 상품의 종류","초기의 지퍼가 가진 문제점","지퍼가 널리 쓰이게 된 과정"],"answer":4,"explain":"🎧 여자: 처음 발명된 19세기 후반에는 시장의 주목을 받지 못했습니다. … 형태가 바뀌고 기능도 개선됐는데요. 지퍼를 단 지갑이 선원들에게 인기를 끌면서 … 이후 지퍼 달린 장화가 … 큰 성공을 거두면서 전 세계로 지퍼가 퍼지게 되었습니다.<br>✅ <b>④</b>: рассказ прослеживает, как молния от провала дошла до всемирного распространения — «процесс, как молния вошла в обиход».<br>✖️ ① «формы молнии по функциям» — нет такой классификации; ② «виды товаров с молнией» — лишь примеры внутри истории; ③ ранние проблемы — только один эпизод, а не вся тема.<br>🧩 지퍼 — молния (застёжка); 발명되다 — быть изобретённым; 개선되다 — улучшаться; 퍼지다 — распространяться."},{"n":34,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["지퍼는 20세기 초반에 발명되었다.","지퍼는 선원들을 통해 알려지기 시작했다.","지퍼는 신발 제작에 가장 먼저 활용되었다.","지퍼는 초기부터 깔끔한 모양으로 주목을 받았다."],"answer":2,"explain":"🎧 (та же лекция) 지퍼를 단 지갑이 선원들에게 인기를 끌면서 지퍼가 알려지기 시작했습니다. 흔들리는 배에서도 동전을 잘 보관할 수 있었기 때문이죠.<br>✅ <b>②</b>: молния стала известной благодаря морякам (кошельки с молнией удобно хранили монеты на качающемся судне).<br>✖️ ① изобретена в конце 19 века (19세기 후반), а в начале 20-го лишь улучшена; ③ сперва — кошельки, обувь (장화) позже; ④ вначале форма была сложной и часто ломалась — внимания не привлекала.<br>🧩 선원 — моряк; 알려지다 — становиться известным; 보관하다 — хранить; 장화 — сапоги."},{"n":35,"points":2,"instr":"Что делает мужчина (с какой целью говорит)?","options":["연극인들을 위한 극장 건축을 다짐하고 있다.","재개관한 극장의 모습과 시설을 소개하고 있다.","연극인들에 대한 관심과 지원을 부탁하고 있다.","극장 재개관에 따른 소감과 기대를 밝히고 있다."],"answer":4,"explain":"🎧 남자: 오늘은 인주 극장이 시민과 연극이 곁으로 다시 돌아오게 된 뜻 깊은 날입니다. … 마음이 아팠습니다. … 다시 문을 연 이곳이 시민과 연극인의 소중한 보금자리가 되어 주리라 생각합니다.<br>✅ <b>④</b>: речь на повторном открытии театра — мужчина делится чувствами и надеждами.<br>✖️ ① строить театр не обещает — он уже открыт заново; ② устройство и оборудование зала не описывает; ③ о поддержке театралов не просит.<br>🧩 재개관 — повторное открытие; 소감 — впечатления, отклик; 보금자리 — родное гнездо, приют; 뜻 깊다 — знаменательный."},{"n":36,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 극장은 작년에 문을 닫았다.","이 극장은 주인이 여러 번 바뀌었다.","오늘 이 극장에서는 400번째 연극을 올린다.","일반 시민이 뜻을 모아 이 극장을 다시 열었다."],"answer":2,"explain":"🎧 (та же речь) 인주 극장은 주인이 수차례 바뀌는 와중에도 400여 편의 연극을 올리고…<br>✅ <b>②</b>: у театра несколько раз менялись владельцы.<br>✖️ ① закрылся «몇 년 전» (несколько лет назад), не в прошлом году; ③ за всю историю поставлено 400+ спектаклей, а не «сегодня 400-й»; ④ заново открыли его ТЕАТРАЛЫ (연극인들), а не обычные горожане.<br>🧩 수차례 — несколько раз; 와중에 — в разгар, среди; 배출하다 — выпускать (кадры); 올리다 — ставить (спектакль)."},{"n":37,"points":2,"instr":"Выберите главную мысль женщины.","options":["사진을 찍을 때는 정성을 들이는 게 중요하다.","필름 사진을 잘 찍으려면 많이 찍어 봐야 한다.","사진을 여러 장 인화하면 원본의 가치가 떨어진다.","필름 사진에는 감성을 자극하는 특별한 매력이 있다."],"answer":4,"explain":"🎧 여자: 필름 사진만이 갖는 독특한 감성 때문입니다. … 묘한 색감과 분위기가 나는데 그것이 아주 매력적이죠. … 이런 번거로움이 오히려 … 사진 한 장 한 장을 소중하고 특별하게 느끼는 이유가 됩니다.<br>✅ <b>④</b>: у плёночных фото особое обаяние, цепляющее за эмоции.<br>✖️ ① «вкладывать старание при съёмке» — не её главная мысль; ② «снимать побольше» — наоборот, число кадров ограничено; ③ про падение ценности оригинала при печати — нет.<br>🧩 감성 — чувственность, эмоции; 색감 — цветопередача; 매력적 — привлекательный; 번거로움 — хлопотность."},{"n":38,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["필름 사진은 인화하기 전에 미리 볼 수 있다.","필름 사진은 얻을 때까지의 과정이 수월해졌다.","필름 사진의 색감은 약품 처리를 할 때 생긴다.","필름 카메라가 부모 세대에게 재유행하고 있다."],"answer":3,"explain":"🎧 (та же передача) 필름을 현상하기 위해 약품 처리를 하는 과정에서 묘한 색감과 분위기가 나는데…<br>✅ <b>③</b>: особая цветопередача плёнки возникает при химической обработке (проявке).<br>✖️ ① фото нельзя увидеть до проявки (인화 과정을 거쳐야만 받아볼 수 있고); ② процесс получения — ХЛОПОТНЫЙ (번거로움), не упростился; ④ плёночные камеры покорили МОЛОДОЕ поколение (젊은 세대), а не «снова в моде у родителей».<br>🧩 현상하다 — проявлять (плёнку); 약품 처리 — химобработка; 인화 — печать (фото); 수월하다 — лёгкий, необременительный."},{"n":39,"points":2,"instr":"Что было сказано ДО этого разговора?","options":["바다 생태 환경을 평가하는 지표가 개발됐다.","정부는 해양 생태계 개선 사업을 긍정적으로 평가했다.","어업인의 소득을 늘리기 위한 새로운 정책안이 발표됐다.","사업의 실효성에 대해 의문을 제기하는 언론 보도가 있었다."],"answer":2,"explain":"🎧 여자: 그렇다면 정부는 지난 10년간 해양 생태계 개선 사업이 성공적이었다고 판단한 거군요.<br>✅ <b>②</b>: реплика начинается с «그렇다면…» и подытоживает, что правительство сочло проект успешным → до этого мужчина говорил именно о положительной оценке проекта.<br>✖️ ① про разработку индикатора оценки — нет; ③ про новый курс ради доходов рыбаков — нет; ④ про критические публикации в СМИ — нет.<br>🧩 그렇다면 — «в таком случае, значит»; 판단하다 — судить, оценивать; 해양 생태계 — морская экосистема; 개선 — улучшение."},{"n":40,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["어업인들은 이 사업의 확대 시행을 주장하고 있다.","정부가 경제적인 이유로 사업 중단을 검토 중이다.","이 사업은 이번에 시작해 향후 10년 동안 진행된다.","어업인들은 이 사업을 통해 소득이 늘 것으로 기대했다."],"answer":4,"explain":"🎧 (та же беседа) 바다 생물의 서식 환경이 개선되면 소득이 증대할 것이라 기대했으나 어획량은 기대만큼 늘지 않았기 때문입니다.<br>✅ <b>④</b>: рыбаки рассчитывали, что проект увеличит их доходы.<br>✖️ ① часть рыбаков, наоборот, ПРОТИВ расширения (일부 어업인의 반대); ② правительство рассматривает РАСШИРЕНИЕ (확대 시행), а не остановку; ③ проект шёл ПОСЛЕДНИЕ 10 лет (지난 10년간), а не стартует сейчас.<br>🧩 어업인 — рыбак, рыбопромышленник; 어획량 — улов; 증대하다 — увеличивать(ся); 확대 시행 — расширенное внедрение."},{"n":41,"points":2,"instr":"О чём в основном эта лекция?","options":["탐사선의 기능에 따라 바퀴를 접을 수 있게 달라진다.","화성 탐사선에 종이 접기 기술이 유용하게 활용된다.","지구 밖을 탐사하기 위한 인간의 노력이 이어지고 있다.","작은 부품이 기계를 구동하는 데에 결정적인 역할을 한다."],"answer":2,"explain":"🎧 여자: 종이 접기 기술이 적용된 이 부분을 펼쳤다 접었다 하면 양쪽 바퀴의 크기를 유연하게 바꿀 수 있어 균형 잡기가 쉽습니다. … 접는 선이 새겨진 얇은 판 한 장만으로 만들어졌습니다.<br>✅ <b>②</b>: главное — техника оригами полезно применена в колёсах марсохода.<br>✖️ ① «колёса меняются в зависимости от функций аппарата» — не суть; ③ «усилия человека по освоению космоса» — слишком общо; ④ «маленькие детали решают всё» — наоборот, деталей почти нет.<br>🧩 탐사선 — исследовательский аппарат, зонд; 종이 접기 — оригами; 펼치다 — раскрывать; 유연하다 — гибкий."},{"n":42,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 바퀴에는 많은 부품이 들어간다.","이 바퀴는 평면의 얇은 판을 접어서 만든다.","이 바퀴가 접히는 부분에는 종이가 부착된다.","이 바퀴는 양쪽이 같은 크기로 고정되어 있다."],"answer":2,"explain":"🎧 (та же лекция) 특별한 부품 없이 접는 선이 새겨진 얇은 판 한 장만으로 만들어졌습니다.<br>✅ <b>②</b>: колесо делается складыванием плоской тонкой пластины.<br>✖️ ① оно сделано БЕЗ особых деталей; ③ применяется лишь ПРИНЦИП оригами — настоящая бумага не приклеена; ④ размеры обоих колёс можно гибко МЕНЯТЬ (유연하게 바꿀 수 있어), они не зафиксированы.<br>🧩 평면 — плоскость; 판 — пластина, доска; 부착되다 — прикрепляться; 고정되다 — быть закреплённым."},{"n":43,"points":2,"instr":"О чём этот рассказ?","options":["뇌에 의한 착각 현상","시간을 인식하는 뇌의 부위","생존을 위한 뇌의 작동 방식","손상된 뇌로 인한 특이 반응"],"answer":3,"explain":"🎧 남자: 특정 장면에 대한 공포는 생존을 위한 뇌의 학습 결과인 것이다. … 편도체가 손상된 쥐는 천적에 대한 기억이 없어 위험에 그대로 노출된다.<br>✅ <b>③</b>: тема — как мозг работает ради выживания (страх запоминается, чтобы выжить).<br>✖️ ① про иллюзии/обман восприятия — нет; ② про участок мозга, отвечающий за время, — нет; ④ «особая реакция повреждённого мозга» — лишь пример в конце, не основная тема.<br>🧩 편도체 — миндалевидное тело (амигдала); 생존 — выживание; 공포 — страх; 천적 — естественный враг, хищник."},{"n":44,"points":2,"instr":"Почему участники запомнили фото лица?","options":["익숙함을 느꼈기 때문에","반복적으로 노출되었기 때문에","위험한 요소로 받아들였기 때문에","다른 사진과 공통점을 발견했기 때문에"],"answer":3,"explain":"🎧 (тот же фильм) 편도체가 그것을 생존을 위협하는 요소로 인식해 재빨리 기억하도록 했기 때문이다.<br>✅ <b>③</b>: амигдала восприняла хмурое лицо как опасный (угрожающий выживанию) элемент и заставила быстро его запомнить.<br>✖️ ① «почувствовали привычность» — нет; ② «многократно показывали» — лицо лишь мелькнуло один раз (스쳐 간다); ④ «нашли сходство с другими фото» — нет.<br>🧩 받아들이다 — воспринимать, принимать; 위협하다 — угрожать; 인식하다 — распознавать; 재빨리 — быстро."},{"n":45,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["장악원의 운영 방식은 법으로 규정되어 있었다.","장악원은 소수의 전문 음악인들로 이루어졌다.","장악원에 소속된 음악인을 교육하는 외부 기관이 존재했다.","장악원의 음악은 행사에 관계없이 일정한 형식을 갖추었다."],"answer":1,"explain":"🎧 여자: 천여 명에 달하는 소속 음악인들의 연습 일정까지 법으로 정해 놓을 만큼 철저하게 운영되었습니다.<br>✅ <b>①</b>: работа Чанагвона была закреплена законом (вплоть до графика репетиций).<br>✖️ ② музыкантов было около тысячи (천여 명), не «несколько»; ③ обучение вели ВНУТРЕННИМ учреждением (내부 교육 기관), не внешним; ④ для каждого события — разные методы исполнения (다양한 연주 방법), а не единый формат.<br>🧩 규정되다 — быть установленным (правилом/законом); 운영 — управление; 양성하다 — готовить (кадры); 관장하다 — ведать, заведовать."},{"n":46,"points":2,"instr":"Каким образом женщина подаёт материал?","options":["장악원의 연주 장면을 묘사하고 있다.","장악원을 다른 기관과 비교하고 있다.","장악원의 변천 과정을 요약하고 있다.","장악원이 담당한 역할을 설명하고 있다."],"answer":4,"explain":"🎧 (та же лекция) 궁중 음악에 관한 모든 일을 관장했는데요. … 전문 음악인을 양성하고, … 악기를 직접 제작하는 것도 장악원에서 담당했습니다.<br>✅ <b>④</b>: женщина перечисляет и поясняет функции, которые выполнял Чанагвон.<br>✖️ ① сцену исполнения не описывает; ② с другими учреждениями не сравнивает; ③ процесс изменений во времени не подытоживает.<br>🧩 묘사하다 — описывать (картину); 비교하다 — сравнивать; 변천 — изменения, эволюция; 역할 — роль."},{"n":47,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["경제학에서는 사회적 자본에 대한 연구가 미비하다.","경제학에서는 물질 자본을 더 중요한 지표로 삼는다.","사회적 자본은 구성원들의 신뢰 정도를 측정한 것이다.","사회적 자본은 높은 거래 비용을 요구하는 경우가 많다."],"answer":3,"explain":"🎧 남자: 사회적 자본은 구성원들 간의 신뢰를 측정한 값으로 정의되는데요.<br>✅ <b>③</b>: социальный капитал — это измерение степени доверия между членами общества.<br>✖️ ① его экономическая ценность уже доказана — исследований достаточно; ② сейчас важнее СОЦИАЛЬНЫЙ капитал, а не материальный; ④ соц. капитал, наоборот, СНИЖАЕТ издержки сделок (거래 비용이 줄어).<br>🧩 사회적 자본 — социальный капитал; 신뢰 — доверие; 측정하다 — измерять; 거래 비용 — транзакционные издержки."},{"n":48,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["사회적 자본의 가치를 높이 평가하고 있다.","사회적 자본의 활용 방안을 검토하고 있다.","사회적 자본에 대한 맹신을 경계하고 있다.","사회적 자본이 미칠 영향을 우려하고 있다."],"answer":1,"explain":"🎧 (та же беседа) 사회적 자본은 경제 성장의 원동력이 된다는 점에서 매우 중요합니다.<br>✅ <b>①</b>: мужчина высоко оценивает ценность социального капитала (его польза доказана, он — движущая сила роста).<br>✖️ ② конкретные способы применения он не «рассматривает»; ③ от слепой веры не предостерегает; ④ опасений насчёт негативного влияния не высказывает.<br>🧩 높이 평가하다 — высоко оценивать; 맹신 — слепая вера; 경계하다 — остерегаться; 원동력 — движущая сила."},{"n":49,"points":2,"instr":"Выберите то, что СОВПАДАЕТ с услышанным.","options":["이 제도는 재판의 신속성을 목적으로 한다.","이 제도는 많은 국가에서 시행을 앞두고 있다.","이 제도는 특정 사건에 한해 제한적으로 적용된다.","이 제도는 상급 법원에 재판을 청구할 권리를 보장한다."],"answer":4,"explain":"🎧 남자: 하급심의 법원이 법을 잘못 해석했거나 판결이 부당하다고 판단하면 누구나 이 제도를 통해 상급 법원에 다시 재판을 청구할 수 있지요.<br>✅ <b>④</b>: система инстанций гарантирует право обжаловать дело в вышестоящем суде.<br>✖️ ① её цель — СПРАВЕДЛИВОСТЬ (공정함), а не быстрота (быстроты хотят критики, упрощая её); ② многие страны её УЖЕ применяют (시행하고 있는데요); ③ применяется к любому делу (누구나), не к отдельным.<br>🧩 심급 제도 — система судебных инстанций; 하급심/상급 법원 — нижестоящий/вышестоящий суд; 부당하다 — несправедливый; 청구하다 — требовать, подавать (иск)."},{"n":50,"points":2,"instr":"Выберите позицию (отношение) мужчины.","options":["제도의 새로운 변화를 기대하고 있다.","제도의 필요성과 의의를 강조하고 있다.","제도의 개선 방향에 적극 동의하고 있다.","제도의 확대 적용을 강력하게 주장하고 있다."],"answer":2,"explain":"🎧 (та же лекция) 그럼에도 불구하고 심급 제도는 법 앞의 공정함을 실현하도록 한다는 점에서 반드시 필요한 제도라 할 수 있습니다.<br>✅ <b>②</b>: признавая издержки времени и ресурсов, мужчина подчёркивает необходимость и значимость системы.<br>✖️ ① перемен в системе не ждёт; ③ с идеей упрощения он как раз НЕ соглашается («그럼에도 불구하고»); ④ расширять её применение настойчиво не требует.<br>🧩 의의 — значимость, смысл; 강조하다 — подчёркивать; 그럼에도 불구하고 — несмотря на это; 실현하다 — реализовывать."}]
      },
      reading: { durationMin: 70, total: 100, label: '제83회 · 읽기 (1~50)', questions: [{"n":1,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"책을 많이 (　　) 지식을 쌓을 수 있다.","options":["읽으면","읽든지","읽지만","읽거나"],"answer":1,"explain":"✅ <b>① 읽으면</b> — «если много читать, можно копить знания»: условие → следствие, нужна форма -(으)면.<br>✖️ ② -든지 «читать ли…» (выбор); ③ -지만 «но» (контраст); ④ -거나 «или». По смыслу подходит только условие.<br>🧩 V-(으)면 — «если/когда»: 읽으면 (после согласной — 으면)."},{"n":2,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"꽃이 피기 시작하는 걸 보니 봄이 (　　).","options":["오곤 한다","온 모양이다","오는 편이다","온 적이 있다"],"answer":2,"explain":"✅ <b>② 온 모양이다</b> — «судя по тому, что зацвели цветы, похоже, пришла весна»: вывод по признаку → -(으)ㄴ/는 모양이다.<br>✖️ ① -곤 하다 «бывает, что» (повтор); ③ -는 편이다 «скорее»; ④ -(으)ㄴ 적이 있다 «доводилось».<br>🧩 보니(까) … 모양이다 — «вижу… и, похоже…»: умозаключение по наблюдению."},{"n":3,"points":2,"instr":"밑줄 친 부분과 의미가 가장 비슷한 것을 고르십시오.","passage":"시험이 시작되자 교실은 숨소리가 <u>들릴 만큼</u> 조용해졌다.","options":["들리다가","들리더라도","들릴 정도로","들릴 때까지"],"answer":3,"explain":"✅ <b>③ 들릴 정도로</b> — «настолько тихо, что слышно дыхание»: -(으)ㄹ 만큼 = -(으)ㄹ 정도로 «до такой степени, что».<br>✖️ ① -다가 «и потом»; ② -더라도 «даже если»; ④ -(으)ㄹ 때까지 «пока не».<br>🧩 A/V-(으)ㄹ 만큼/정도로 — степень: «настолько…, что»."},{"n":4,"points":2,"instr":"밑줄 친 부분과 의미가 가장 비슷한 것을 고르십시오.","passage":"집의 분위기는 <u>꾸미기 나름이다</u>.","options":["꾸밀 만하다","꾸미기가 쉽다","꾸밀 수도 있다","꾸미기에 달려 있다"],"answer":4,"explain":"✅ <b>④ 꾸미기에 달려 있다</b> — «атмосфера дома зависит от того, как обставишь»: V-기 나름이다 = «зависит от того, как…» = -기에 달려 있다.<br>✖️ ① -(으)ㄹ 만하다 «стоит того»; ② -기가 쉽다 «легко»; ③ -(으)ㄹ 수도 있다 «может быть».<br>🧩 N/V-기 나름이다 — «всё зависит от…»."},{"n":5,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"🪧 가벼움을 신다!\n어떤 길에서도 편한 세상을 경험해 보세요.","options":["안경","침대","운동화","노트북"],"answer":3,"explain":"✅ <b>③ 운동화</b> (кроссовки) — «надень лёгкость! комфорт на любой дороге»: 신다 (надевать обувь) + 길 (дорога) → обувь.<br>✖️ ① очки, ② кровать, ④ ноутбук — их не «надевают на ногах».<br>🧩 신다 — надевать (обувь/носки); 입다 — одежду, 쓰다 — очки/шапку."},{"n":6,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"🪧 매일 정성을 담아 더 맛있게~\n자연에서 얻은 신선한 재료만을 사용합니다.","options":["공원","식당","꽃집","서점"],"answer":2,"explain":"✅ <b>② 식당</b> (ресторан) — «вкуснее с душой каждый день; только свежие натуральные продукты»: 맛있게 + 재료 → еда.<br>✖️ ① парк, ③ цветочный, ④ книжный — «вкус» и «ингредиенты» к ним не подходят.<br>🧩 정성을 담다 — «вкладывать душу/старание»; 재료 — продукты, ингредиенты."},{"n":7,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"🪧 웃는 얼굴, 밝은 인사\n모두가 기분 좋은 하루의 시작입니다.","options":["환경 보호","생활 예절","건강 관리","봉사 활동"],"answer":2,"explain":"✅ <b>② 생활 예절</b> (этикет) — «улыбка и приветливое приветствие — хорошее начало дня для всех»: о манерах общения.<br>✖️ ① экология, ③ здоровье, ④ волонтёрство.<br>🧩 인사 — приветствие; 예절 — этикет, правила вежливости."},{"n":8,"points":2,"instr":"다음은 무엇에 대한 글인지 고르십시오.","passage":"❶ 승강장에서 뛰지 마세요.\n❷ 출입문이 닫힐 때는 무리하게 타지 마세요.","options":["안전 규칙","신청 방법","사용 순서","교환 안내"],"answer":1,"explain":"✅ <b>① 안전 규칙</b> (правила безопасности) — «не бегайте на платформе; не вбегайте, когда двери закрываются»: предупреждения на станции.<br>✖️ ② порядок подачи заявки, ③ порядок использования, ④ обмен.<br>🧩 승강장 — платформа; 무리하게 — через силу, рискованно."},{"n":9,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"🪧 인주시의 과거 모습을 찾습니다\n▪ 기간: 2022년 9월 1일(목)~9월 30일(금)\n▪ 대상: 1980년 이전에 찍은 사진\n▪ 방법: 인주 시청 홍보실로 방문 제출\n※ 사진을 제출하신 분께는 문화 상품권(3만 원)을 드립니다.","options":["이 행사는 한 달 동안 진행된다.","사진은 이메일로 제출해야 한다.","인주시에서 올해 찍은 사진을 내면 된다.","이 행사에 참여하면 인주시의 옛날 사진을 받는다."],"answer":1,"explain":"✅ <b>①</b> — с 1 по 30 сентября = месяц (한 달 동안).<br>✖️ ② сдавать лично в홍보실 (не e-mail); ③ нужны фото <b>до 1980 г.</b>, не этого года; ④ участникам дают подарочный сертификат, а не старые фото.<br>🧩 기간 — период; 방문 제출 — подать лично; 상품권 — подарочный сертификат."},{"n":10,"points":2,"instr":"다음 그래프의 내용과 같은 것을 고르십시오.","passage":"📊 대학생 한 달 용돈 어디에 쓸까? (대학생 1,000명)\n식비 53% · 학원비 21% · 교통비 16% · 물건 구입비 6% · 문화생활비 3% · 기타 1%","options":["용돈 중 물건 구입비의 비율이 가장 낮았다.","학원비 사용은 교통비보다 두 배 이상 많았다.","대학생들은 용돈의 절반 이상을 식비로 지출했다.","대학생들은 문화생활비보다 교통비를 더 적게 사용했다."],"answer":3,"explain":"✅ <b>③</b> — 식비 53% > половины (절반 이상).<br>✖️ ① самая низкая доля — 기타 1%, а не 물건 구입비 6%; ② 학원비 21% не вдвое больше 교통비 16%; ④ наоборот: 교통비(16%) > 문화생활비(3%).<br>🧩 절반 이상 — больше половины; 지출하다 — тратить."},{"n":11,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"그림책 작가 이수지 씨가 한국인 최초로 어린이책 노벨상이라는 안데르센 상을 받아 주목받고 있다. 이 상은 1956년에 만들어진 상으로 작가가 발표한 모든 작품을 대상으로 심사한다. 이 작가는 어린이들이 꿈꾸고 상상하는 세계를 그림으로 잘 표현해 낸다는 평을 받았다.","options":["이 작가가 받은 상은 작년에 만들어졌다.","이 작가는 한국인 중 처음으로 이 상을 받았다.","이 작가는 자신이 직접 경험한 이야기를 그림으로 표현했다.","이 작가는 자신의 작품 중 한 편을 골라 심사 대상으로 제출했다."],"answer":2,"explain":"✅ <b>②</b> — «한국인 최초로 … 받아» — первой из корейцев получила премию.<br>✖️ ① премия учреждена в 1956 г., не «в прошлом году»; ③ рисует мир детских грёз/фантазий, не свой опыт; ④ оцениваются <b>все</b> произведения (모든 작품), а не одно избранное.<br>🧩 최초로 — впервые; 심사하다 — оценивать (жюри)."},{"n":12,"points":2,"instr":"다음 글의 내용과 같은 것을 고르십시오.","passage":"17일 오전 6시 22분 인주시에서 규모 3.2의 지진이 발생했다. 이날 지진은 올해 인주시에서 발생한 지진 중 가장 큰 규모다. 119 상황실에는 지진을 느낀 시민들의 신고가 여러 건 접수됐다. 그러나 이번 지진으로 입은 큰 피해는 없는 것으로 조사됐다. 기상청은 이번 주 내로 규모 2.0 정도의 지진이 몇 번 더 발생할 것으로 보고 있다.","options":["이번 지진은 늦은 밤에 일어났다.","시민들이 지진을 느껴 상황실에 신고를 했다.","이번 지진으로 큰 피해를 입은 사람들이 많다.","이번 주에는 더 이상 지진이 일어나지 않을 것이다."],"answer":2,"explain":"✅ <b>②</b> — «지진을 느낀 시민들의 신고가 … 접수됐다» — жители звонили, почувствовав толчки.<br>✖️ ① это было утром 6:22 (오전), не поздней ночью; ③ «큰 피해는 없는 것으로» — серьёзного ущерба нет; ④ метеослужба ждёт ещё несколько толчков ~2.0 на этой неделе.<br>🧩 지진 — землетрясение; 신고 접수 — приём обращений."},{"n":13,"points":2,"instr":"다음을 순서에 맞게 배열한 것을 고르십시오.","passage":"(가) 그러나 이를 닦을 때는 순서에 맞춰 닦는 것이 좋다.\n(나) 사람들은 보통 이를 닦을 때 순서에 별로 신경 쓰지 않는다.\n(다) 전문가들은 안쪽 구석에서부터 앞쪽 방향이 좋다고 조언한다.\n(라) 안쪽 이가 상하기 쉬워서 더 꼼꼼하게 닦아야 하기 때문이다.","options":["(나)-(가)-(다)-(라)","(나)-(라)-(가)-(다)","(다)-(가)-(라)-(나)","(다)-(나)-(라)-(가)"],"answer":1,"explain":"✅ <b>① (나)-(가)-(다)-(라)</b>: (нет внимания к порядку) → (가) «그러나 … порядок важен» → (다) совет специалистов (изнутри наружу) → (라) причина (внутренние зубы портятся).<br>✖️ Зачин — общий факт (나) без отсылок; (가) с «그러나» опровергает его; причина (라) идёт после совета.<br>🧩 Первым — предложение без 그러나/그래서; 꼼꼼하게 — тщательно."},{"n":14,"points":2,"instr":"다음을 순서에 맞게 배열한 것을 고르십시오.","passage":"(가) 그 사업이 쉽지는 않겠지만 한번 시도해 보고 싶다.\n(나) 친구들은 마지막까지 퇴사를 다시 고민해 보라고 했다.\n(다) 내일은 내가 10년 동안 다니던 회사를 그만두는 날이다.\n(라) 하지만 나는 오랫동안 생각해 온 사업을 시작해 보려고 한다.","options":["(나)-(가)-(라)-(다)","(나)-(다)-(가)-(라)","(다)-(라)-(가)-(나)","(다)-(나)-(라)-(가)"],"answer":4,"explain":"✅ <b>④ (다)-(나)-(라)-(가)</b>: (다) завтра увольняюсь → (나) друзья отговаривали → (라) «하지만» всё же начну своё дело → (가) пусть нелегко, но хочу попробовать.<br>✖️ Зачин — факт (다); (나)/(라)/(가) опираются на него.<br>🧩 퇴사 — увольнение; -아/어 보고 싶다 — «хочу попробовать»."},{"n":15,"points":2,"instr":"다음을 순서에 맞게 배열한 것을 고르십시오.","passage":"(가) 모래시계는 모래를 이용해 일정 단위의 시간을 재는 기구이다.\n(나) 또한 모래시계의 구멍 크기를 통해서도 시간 단위를 조절한다.\n(다) 구멍 크기가 작을수록 큰 시간 단위의 모래시계를 만들 수 있다.\n(라) 모래의 양을 조절하면 다양한 시간 단위의 모래시계를 만들 수 있다.","options":["(가)-(다)-(나)-(라)","(가)-(라)-(나)-(다)","(라)-(다)-(나)-(가)","(라)-(가)-(다)-(나)"],"answer":2,"explain":"✅ <b>② (가)-(라)-(나)-(다)</b>: (가) что такое песочные часы → (라) регулируют кол-вом песка → (나) «또한» ещё и размером отверстия → (다) чем меньше отверстие, тем крупнее единица времени.<br>✖️ Определение (가) первым; (나) с «또한» добавляет второй способ после (라).<br>🧩 또한 — кроме того; -(으)ㄹ수록 — «чем…, тем…»."},{"n":16,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"필름형 스피커는 종이보다 얇고 투명해서 (　　) 사용할 수 있다. 이 스피커를 활용하면 컴퓨터 화면이나 액자뿐만 아니라 벽이나 천장에서도 소리가 나오게 할 수 있다. 또 소재가 부드러워서 옷이나 커튼에 달아도 불편함 없이 사용이 가능하다.","options":["소리 크기를 높여","단독 형태로 분리해","다양한 물건에 붙여","특수한 영역을 제한해"],"answer":3,"explain":"✅ <b>③ 다양한 물건에 붙여</b> — далее перечислено: экран, рамка, стена, потолок, одежда, шторы → плёночный динамик «клеят на разные предметы».<br>✖️ ① громче; ② отделить отдельно; ④ ограничить особую зону — не вяжутся с «тонкий и гибкий».<br>🧩 붙이다 — приклеивать; 뿐만 아니라 — «не только…, но и…»."},{"n":17,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"여권은 국제 신분증으로 통할 뿐만 아니라 한 국가의 정체성과 문화를 드러내기도 한다. 그래서 많은 국가들은 여권의 (　　) 결정한다. 여권 표지의 색깔을 국가의 상징색으로 표현하거나 국가를 상징하는 문양을 넣기도 한다. 또한 여권에 불빛이 비치면 주요 문화재가 화려하게 보이도록 한 것도 있다.","options":["두께를 자율적으로","디자인을 신중하게","이용 범위를 확실히","발급 방식을 구체적으로"],"answer":2,"explain":"✅ <b>② 디자인을 신중하게</b> — далее про цвет обложки, символику, узоры, подсветку культурных памятников → страны тщательно решают «дизайн» паспорта.<br>✖️ ① толщину; ③ сферу использования; ④ способ выдачи — не о внешнем виде.<br>🧩 정체성 — идентичность; 드러내다 — выражать, проявлять; 신중하게 — обдуманно."},{"n":18,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"얼마 전 일본에서만 사는 텃새 두 마리가 한국의 작은 섬에서 발견됐다. 텃새는 자리를 옮기지 않고 한 지역에서만 살기 때문에 장거리 이동을 거의 하지 않는다. 따라서 전문가는 이번에 발견된 텃새가 태풍에 휩쓸려 한국에 온 것으로 추측된다며 이 섬에서 (　　) 것이 매우 보기 드문 사례라고 언급했다.","options":["살던 텃새가 줄어든","한국의 텃새가 사라진","일본의 텃새가 관찰된","부상당한 텃새가 보호된"],"answer":3,"explain":"✅ <b>③ 일본의 텃새가 관찰된</b> — оседлые птицы, живущие только в Японии, замечены на корейском острове (занесло тайфуном) → редкий случай «наблюдения японской оседлой птицы».<br>✖️ ① сокращение местных птиц; ② исчезновение корейских; ④ защита раненых — текст не об этом.<br>🧩 텃새 — оседлая птица; 태풍에 휩쓸리다 — быть унесённым тайфуном; 드문 사례 — редкий случай."},{"n":19,"points":2,"instr":"( ㉠ )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"흥미와 재미 요소를 내세워 홍보하는 마케팅 전략이 주목받고 있다. 이런 마케팅은 소비자의 호기심을 자극해 구매로 이어지게 한다. 그러나 제품의 품질이 소비자의 기대에 미치지 못하는 경우 (　㉠　) 브랜드 이미지까지 나빠지기도 한다. 실제로 한 햄버거 회사에서 '주머니 버거', '눌러 먹는 버거'를 만들어 소비자의 관심을 끌었지만 품질이 기대에 못 미치자 회사의 다른 제품까지 판매가 감소한 경우가 있었다.","options":["과연","비록","차라리","오히려"],"answer":4,"explain":"✅ <b>④ 오히려</b> — «если качество не оправдало ожиданий, <b>наоборот</b> страдает и имидж бренда»: вопреки цели рекламы.<br>✖️ ① 과연 «и впрямь»; ② 비록 «хотя» (нужно -지만); ③ 차라리 «уж лучше».<br>🧩 오히려 — наоборот, напротив (обратный ожидаемому результат)."},{"n":20,"points":2,"instr":"윗글의 주제로 가장 알맞은 것을 고르십시오.","passage":"흥미와 재미 요소를 내세워 홍보하는 마케팅 전략이 주목받고 있다. 이런 마케팅은 소비자의 호기심을 자극해 구매로 이어지게 한다. 그러나 제품의 품질이 소비자의 기대에 미치지 못하는 경우 (　㉠　) 브랜드 이미지까지 나빠지기도 한다. 실제로 한 햄버거 회사에서 '주머니 버거', '눌러 먹는 버거'를 만들어 소비자의 관심을 끌었지만 품질이 기대에 못 미치자 회사의 다른 제품까지 판매가 감소한 경우가 있었다.","options":["마케팅도 중요하지만 제품의 품질이 더 중요하다.","식품 기업은 먼저 소비자의 요구를 확인해야 한다.","제품에 재미 요소를 포함하는 마케팅 전략이 필요하다.","특이한 제품보다 소비자에게 익숙한 것이 홍보에 더 좋다."],"answer":1,"explain":"✅ <b>①</b> — главная мысль: завлекающий маркетинг хорош, но если качество не дотягивает, бренд проигрывает → «качество важнее маркетинга».<br>✖️ ② про изучение спроса — не главное; ③ противоречит выводу; ④ про «привычные товары» текст не говорит.<br>🧩 주제 — основная мысль; 품질 — качество."},{"n":21,"points":2,"instr":"( ㉠ )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"소방관은 재난 현장에서 끔찍한 상황을 자주 접하기 때문에 정신 건강에 위험이 따른다. 최근 이러한 문제가 심각해지자 인주시가 해결을 위해 (　㉠　). 인주시는 빠른 시일 내에 정신 건강에 대해 조사를 실시하고 문제를 겪는 소방관이 있으면 전문 상담사를 보내 상담을 진행하기로 했다. 이와 더불어 심리 안정 프로그램 개발과 진료비 지원을 위한 예산을 확보했다고 발표했다.","options":["등 떠밀었다","눈을 맞췄다","발 벗고 나섰다","손에 땀을 쥐었다"],"answer":3,"explain":"✅ <b>③ 발 벗고 나섰다</b> (идиома) — «город активно взялся за решение»: далее перечислены реальные меры (опрос, психологи, бюджет).<br>✖️ ① 등 떠밀다 «подталкивать (заставлять)»; ② 눈을 맞추다 «встретиться взглядом»; ④ 손에 땀을 쥐다 «затаить дыхание».<br>🧩 발 벗고 나서다 —活ивно взяться за дело, не жалея сил."},{"n":22,"points":2,"instr":"윗글의 내용과 같은 것을 고르십시오.","passage":"소방관은 재난 현장에서 끔찍한 상황을 자주 접하기 때문에 정신 건강에 위험이 따른다. 최근 이러한 문제가 심각해지자 인주시가 해결을 위해 (　㉠　). 인주시는 빠른 시일 내에 정신 건강에 대해 조사를 실시하고 문제를 겪는 소방관이 있으면 전문 상담사를 보내 상담을 진행하기로 했다. 이와 더불어 심리 안정 프로그램 개발과 진료비 지원을 위한 예산을 확보했다고 발표했다.","options":["소방관의 심리적 어려움은 최근 많이 해소되었다.","인주시는 소방관의 정신 건강 조사를 모두 마쳤다.","인주시는 소방관 심리 안정 프로그램을 운영할 계획이다.","소방관이 정신 건강 상담을 받으려면 상담사를 찾아가야 한다."],"answer":3,"explain":"✅ <b>③</b> — «심리 안정 프로그램 개발 … 예산을 확보했다» — город планирует программу психологической поддержки.<br>✖️ ① проблема обострилась, не «решена»; ② опрос только собираются провести (빠른 시일 내에); ④ психолога <b>присылают</b> (보내), идти к нему не нужно.<br>🧩 정신 건강 — психическое здоровье; 예산을 확보하다 — выделить бюджет."},{"n":23,"points":2,"instr":"밑줄 친 부분에 나타난 '나'의 심정으로 가장 알맞은 것을 고르십시오.","passage":"며칠 전 창고 선반 위에 올려 둔 가방을 꺼내는데 공책 한 권이 툭 하고 떨어졌다. 나는 '뭐지?' 하고 별 생각 없이 안을 펼쳐 보고는 눈물이 왈칵 나올 뻔했다. 그것은 바로 어릴 때 돌아가신 아버지의 일기장이었다. 아버지 물건이 아직도 집에 남아 있을 줄은 전혀 생각하지 못했다. 두근거리는 마음으로 거실로 나와 일기장을 펼쳤다. 30년 전 날짜가 적힌 일기장의 누렇게 변한 페이지마다 아버지의 하루하루가 적혀 있었다. 내가 초등학교에 입학한 날, 여행한 날, 혼난 날……. 그때의 추억들이 펼쳐졌다. 아버지는 언제 어디서 무엇을 하셨는지 빼곡히 적혀 두셨다. 일기장에 적혀 있는 곳을 인터넷으로 찾아보니 자주 가시던 빵집과 국숫집이 아직도 그대로 있었다. 그곳에 가면 아버지의 흔적을 느낄 수 있을까? 나는 이번 주말에 일기장에 적혀 있는 곳에 한번 찾아가 보려고 한다.","options":["반갑고 감격스럽다","편하고 만족스럽다","아쉽고 걱정스럽다","기쁘고 자랑스럽다"],"answer":1,"explain":"✅ <b>① 반갑고 감격스럽다</b> (радостно и трогательно) — неожиданно нашёл дневник покойного отца, «눈물이 왈칵» — на глаза навернулись слёзы: тёплое волнение.<br>✖️ ② спокойно/довольно; ③ жаль/тревожно; ④ радостно/гордо — не передают трогательность находки.<br>🧩 감격스럽다 — быть растроганным; 왈칵 — внезапно (о слезах)."},{"n":24,"points":2,"instr":"윗글의 내용과 같은 것을 고르십시오.","passage":"며칠 전 창고 선반 위에 올려 둔 가방을 꺼내는데 공책 한 권이 툭 하고 떨어졌다. 나는 '뭐지?' 하고 별 생각 없이 안을 펼쳐 보고는 눈물이 왈칵 나올 뻔했다. 그것은 바로 어릴 때 돌아가신 아버지의 일기장이었다. 아버지 물건이 아직도 집에 남아 있을 줄은 전혀 생각하지 못했다. 두근거리는 마음으로 거실로 나와 일기장을 펼쳤다. 30년 전 날짜가 적힌 일기장의 누렇게 변한 페이지마다 아버지의 하루하루가 적혀 있었다. 내가 초등학교에 입학한 날, 여행한 날, 혼난 날……. 그때의 추억들이 펼쳐졌다. 아버지는 언제 어디서 무엇을 하셨는지 빼곡히 적혀 두셨다. 일기장에 적혀 있는 곳을 인터넷으로 찾아보니 자주 가시던 빵집과 국숫집이 아직도 그대로 있었다. 그곳에 가면 아버지의 흔적을 느낄 수 있을까? 나는 이번 주말에 일기장에 적혀 있는 곳에 한번 찾아가 보려고 한다.","options":["나는 아버지의 물건을 많이 가지고 있다.","나는 전에 아버지의 일기장을 자주 꺼내 읽었다.","나는 거실에 아버지의 일기장을 보관하고 있었다.","나는 아버지가 자주 가시던 빵집에 가 보려고 한다."],"answer":4,"explain":"✅ <b>④</b> — в дневнике указаны места (빵집과 국숫집), и «이번 주말에 … 찾아가 보려고 한다» — герой собирается сходить в булочную, куда часто ходил отец.<br>✖️ ① «вещей отца почти не осталось» (전혀 생각 못 했다); ② дневник нашёл только что, не читал часто; ③ дневник лежал в сумке в кладовой, не в гостиной.<br>🧩 찾아가다 — наведаться; 그대로 — как есть, по-прежнему."},{"n":25,"points":2,"instr":"다음 신문 기사의 제목을 가장 잘 설명한 것을 고르십시오.","passage":"📰 드라마 '진실' 인기 효과, 원작 베스트셀러 1위","options":["드라마 '진실'이 인기를 얻으면서 원작이 판매량 1위를 차지했다.","드라마 '진실'이 시청률 1위가 되자 원작 작가에 대한 관심이 높아졌다.","드라마 '진실'의 인기로 원작 작가의 모든 작품들의 판매율이 상승했다.","드라마 '진실'이 원작의 인기 요소를 추가해 시청률 1위의 드라마가 됐다."],"answer":1,"explain":"✅ <b>①</b> — «эффект популярности дорамы → первоисточник стал бестселлером №1 по продажам».<br>✖️ ② про интерес к автору — шире заголовка; ③ «все произведения автора» — не сказано; ④ переставляет причину и следствие.<br>🧩 원작 — оригинал/первоисточник; 판매량 — объём продаж."},{"n":26,"points":2,"instr":"다음 신문 기사의 제목을 가장 잘 설명한 것을 고르십시오.","passage":"📰 기습 폭우에 차량 '엉금엉금', 출근길 정체","options":["폭우로 피해를 입은 차량들이 늘면서 사람들의 출근이 늦어졌다.","큰비에 차량 사고가 잇따르면서 출근하던 사람들이 곤란을 겪었다.","갑자기 많이 쏟아진 비로 차들이 천천히 운행하면서 출근길이 막혔다.","계속된 비에 대중교통 이용자가 한꺼번에 몰리면서 출근길이 혼잡해졌다."],"answer":3,"explain":"✅ <b>③</b> — 기습 폭우 (внезапный ливень) + 엉금엉금 (ползком) → машины едут медленно, пробки в час пик.<br>✖️ ① про «ущерб машинам»; ② про «аварии»; ④ про «общественный транспорт» — заголовок про медленное движение машин.<br>🧩 기습 — внезапный; 정체 — затор; 엉금엉금 — медленно ползти."},{"n":27,"points":2,"instr":"다음 신문 기사의 제목을 가장 잘 설명한 것을 고르십시오.","passage":"📰 온라인 거래 사기 급증, 정부 대책 마련은 미흡","options":["온라인 거래 사기가 늘었지만 정부의 대책 마련은 충분하지 않다.","온라인 시장에서 거래 사기가 증가해 정부가 대책을 수립하고 있다.","온라인 거래 사기를 막기 위해 마련한 정부의 대책은 큰 효과가 없었다.","온라인 거래 사기 피해자들을 위해 정부가 대책을 마련하겠다고 발표했다."],"answer":1,"explain":"✅ <b>①</b> — 급증 (резкий рост) + 대책 마련 미흡 (меры недостаточны) → мошенничество выросло, но мер мало.<br>✖️ ② «разрабатывает» — заголовок говорит, что мер НЕ хватает; ③ «не дали эффекта» — речь о нехватке самих мер; ④ «объявило, что подготовит» — не сказано.<br>🧩 급증 — резкий рост; 미흡 — недостаточно, неудовлетворительно."},{"n":28,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"최근 한국의 편의점 업체가 해외로 진출하면서 현지에서 큰 인기를 끌고 있다. 인테리어에서 판매 상품까지 (　　) 전략을 썼기 때문이다. 보통 마트가 해외에 진출할 때는 현지인의 취향에 맞추려고 하는데 이 편의점 업체는 이와 반대되는 방법을 써서 성공한 것이다.","options":["빠뜨리지 않고 홍보하는","판매자의 기호에 맞추는","편의점의 특성을 최대한 감추는","한국 편의점을 그대로 재현하는"],"answer":4,"explain":"✅ <b>④ 한국 편의점을 그대로 재현하는</b> — обычно подстраиваются под местных, а эта сеть сделала «наоборот» (이와 반대) → воспроизвела корейский магазин как есть.<br>✖️ ① «рекламировать без пропусков»; ② под вкус продавца; ③ скрыть особенности — противоречат «반대되는 방법».<br>🧩 재현하다 — воспроизводить; 진출하다 — выходить (на рынок)."},{"n":29,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"고대 이집트 피라미드를 건축할 때 거대한 바위를 모래 위에서 운반해야 했는데 이를 위해서는 (　　) 기술이 중요했다. 모래에 수분이 일정하게 유지되면 모랫길이 단단해져서 운반이 수월했기 때문이다. 실제로 고대 벽화에는 바위를 운반하는 길 위에 사람들이 물을 뿌리고 있는 장면이 묘사되어 있다.","options":["적정량의 물을 뿌리는","모래를 부드럽게 만드는","바위의 무게를 계산하는","운반하는 사람들을 배치하는"],"answer":1,"explain":"✅ <b>① 적정량의 물을 뿌리는</b> — влажный песок твердеет → легче везти; на фресках люди льют воду на дорогу → важна техника «полива нужным кол-вом воды».<br>✖️ ② сделать песок мягким (наоборот — нужен твёрдый); ③ расчёт веса; ④ расстановка людей — не о влаге.<br>🧩 뿌리다 — брызгать, поливать; 수월하다 — легко даваться."},{"n":30,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"일부 프로 농구 리그에서는 반드시 주황색 공을 쓰게 하고 있다. 여러 이유가 있지만 그중 하나는 (　　) 데 있다. 바닥에 공을 많이 튕겨야 하는 농구의 특성상 공이 바닥의 색과 많이 다르면 선수나 관중 모두 부담을 느낄 수 있기 때문이다.","options":["골을 잘 넣게 하려는","공이 잘 보이게 하려는","눈의 피로감을 줄이려는","선수들의 운동복과 구별하려는"],"answer":2,"explain":"✅ <b>② 공이 잘 보이게 하려는</b> — оранжевый мяч сильно отличается от цвета пола → «чтобы мяч было хорошо видно».<br>✖️ ① забивать голы; ③ снижать усталость глаз (объясняется через видимость, но цель — видимость); ④ отличать от формы — текст про цвет пола.<br>🧩 튕기다 — отбивать (мяч); 부담을 느끼다 — испытывать дискомфорт/нагрузку."},{"n":31,"points":2,"instr":"( )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"'가면 증후군'이란 사회적으로 인정을 받고 있지만 그것이 자신의 진짜 실력 때문이 아니라는 생각으로 괴로워하는 현상이다. 성과를 내고 있음에도 (　　) 언젠가 가면이 벗겨질지도 모른다는 생각에 불안해 하는 것이다. 이런 현상이 생긴 원인은 다양한데 양육 과정에서 부모의 인정을 받지 못했거나 겸손을 강조하는 분위기 속에서 자랐기 때문이다.","options":["일을 계속 미루면서","타인의 평가를 원하면서","낮은 지위에 머무르면서","자신의 능력을 의심하면서"],"answer":4,"explain":"✅ <b>④ 자신의 능력을 의심하면서</b> — «синдром самозванца»: несмотря на успехи, человек сомневается в себе и боится, что «маску сорвут».<br>✖️ ① откладывать дела; ② желать чужой оценки; ③ оставаться на низкой позиции — не о сомнении в себе.<br>🧩 가면 증후군 — синдром самозванца; 의심하다 — сомневаться."},{"n":32,"points":2,"instr":"다음을 읽고 글의 내용과 같은 것을 고르십시오.","passage":"오케스트라는 연주하기 전에 악기들의 음을 서로 맞춰 보는 과정을 거친다. 그때 오케스트라의 한가운데에 자리 잡은 오보에가 기준 음을 낸다. 오보에는 다른 관악기와 달리 나무 떨림판인 '리드'를 두 장 겹쳐 사용해서 소리가 더 정확하고 또렷하기 때문이다. 또 음을 안정적으로 길게 유지할 수 있어서 다른 악기들이 음을 쉽게 맞출 수 있도록 해 준다.","options":["오보에는 다른 악기와 달리 리드 하나로 음을 낸다.","오보에의 첫 음과 함께 오케스트라 연주가 시작된다.","오보에는 소리가 작아서 오케스트라의 앞쪽에 위치한다.","오보에는 오케스트라에서 소리를 맞출 때 기준 역할을 한다."],"answer":4,"explain":"✅ <b>④</b> — «오보에가 기준 음을 낸다 … 다른 악기들이 음을 쉽게 맞출 수 있도록» — гобой задаёт эталонную ноту для настройки.<br>✖️ ① у гобоя <b>две</b> пластинки-리드 (두 장 겹쳐), не одна; ② настройка ≠ начало исполнения; ③ гобой <b>в центре</b> (한가운데), не впереди, и не из-за тихости.<br>🧩 기준 음 — эталонный звук; 맞추다 — настраивать, согласовывать."},{"n":33,"points":2,"instr":"다음을 읽고 글의 내용과 같은 것을 고르십시오.","passage":"애기장대는 각종 식물 실험에 빠지지 않고 등장하는 식물이다. 식물 중에서는 처음으로 유전체 해독이 완료되어 식물의 유전자 연구를 할 때 주로 이용된다. 전 세계에 고루 분포하고, 곤충의 도움 없이 씨앗을 맺을 수 있어서 재배도 쉽다. 또한 한 세대 기간이 6주 정도밖에 되지 않아 실험 결과를 빨리 확인할 수 있기 때문에 실험에 널리 이용되고 있다.","options":["애기장대는 세계 곳곳에서 볼 수 있는 식물이다.","애기장대의 유전체 해독을 위한 연구가 진행 중이다.","애기장대가 씨앗을 만드는 데에 곤충의 역할이 필요하다.","애기장대는 성장 기간이 길어 유전자 연구에 효율적이다."],"answer":1,"explain":"✅ <b>①</b> — «전 세계에 고루 분포» — резуховидка растёт повсюду.<br>✖️ ② расшифровка генома уже <b>завершена</b> (완료), не «идёт»; ③ даёт семена <b>без</b> насекомых (곤충의 도움 없이); ④ поколение короткое (6 недель), не длинное.<br>🧩 유전체 해독 — расшифровка генома; 고루 분포하다 — равномерно распространён."},{"n":34,"points":2,"instr":"다음을 읽고 글의 내용과 같은 것을 고르십시오.","passage":"아이가 '엄마' 다음으로 빨리 배우는 말 중에는 '이것'과 같이 여러 물건을 가리키는 지시어가 있다. 지시어는 대화하는 상황을 타인과 공유해야 그 의미를 이해할 수 있다는 특성이 있다. 아기들은 이러한 지시어를 사용해 자연스럽게 부모의 관심을 끄는 것이다. 대부분의 아기들이 생후 12~18개월 무렵에 이런 지시어를 사용한다는 것은 이미 여러 언어 연구에서 밝혀진 바 있다.","options":["아기는 혼잣말을 할 때 지시어를 자주 사용한다.","아기는 엄마라는 단어보다 지시어를 먼저 습득한다.","지시어를 습득하는 시기는 언어권마다 다르게 나타난다.","지시어는 상대방과 상황을 공유해야 의미를 전달할 수 있다."],"answer":4,"explain":"✅ <b>④</b> — «대화하는 상황을 타인과 공유해야 그 의미를 이해할 수 있다» — указательные слова понятны лишь при общей с собеседником ситуации.<br>✖️ ① не про «разговор с собой»; ② '엄마' учат <b>раньше</b> указательных (다음으로); ③ «по языкам по-разному» — не сказано (наоборот, 12–18 мес. у большинства).<br>🧩 지시어 — указательное слово; 공유하다 — разделять, иметь общим."},{"n":35,"points":2,"instr":"다음을 읽고 글의 주제로 가장 알맞은 것을 고르십시오.","passage":"대중을 대상으로 한 예술 입문서가 작품의 역사적 배경, 작가에 대한 일화 등 독자의 흥미를 끄는 이야기에 집중하는 경우를 많이 볼 수 있다. 작품에 관한 이런 지식은 작품 이해에 도움이 된다. 그러나 예술의 본질은 작품 그 자체에 있다. 작품 외적인 사실들보다 작품에 초점을 두고 작품의 구성 요소, 표현방식 등을 충분히 설명하는 입문서가 늘어나기를 희망한다.","options":["예술 입문서는 작품 외적인 사실들을 다양하게 다뤄야 한다.","작품 자체에 대해 충실히 소개하는 예술 입문서가 많아져야 한다.","대중이 예술 작품에 관해 궁금해 하는 것이 무엇인지 알아야 한다.","예술 입문서는 대중이 예술을 어려운 것이 아니라고 느끼게 해야 한다."],"answer":2,"explain":"✅ <b>②</b> — вывод: «예술의 본질은 작품 그 자체» → нужно больше пособий, рассказывающих о самом произведении.<br>✖️ ① как раз «внешних фактов» уже много — автор хочет обратного; ③/④ не главная мысль.<br>🧩 본질 — суть; 구성 요소 — составные элементы; 충실히 — основательно."},{"n":36,"points":2,"instr":"다음을 읽고 글의 주제로 가장 알맞은 것을 고르십시오.","passage":"점자 표기의 위치, 방식 등이 제조사나 제품별로 달라 시각 장애인들이 불편과 혼란을 겪고 있다. 시각 장애인을 위한 점자 정보가 여러 제품에 표기되고는 있지만 아직 통일된 규정이 없기 때문이다. 현재는 의약품에 한해서만 표기 규정이 정해져 있다. 관계 기관은 더 많은 제품을 대상으로 점자 표기에 대한 규정을 정해야 한다.","options":["의약품의 점자 표기 규정을 검토해야 한다.","점자 표기의 필요성에 대한 인식이 높아져야 한다.","제품에 잘못 표기된 점자 정보가 없는지 조사해야 한다.","다양한 제품에 적용할 점자 표기 규정이 마련되어야 한다."],"answer":4,"explain":"✅ <b>④</b> — вывод: «더 많은 제품을 대상으로 점자 표기에 대한 규정을 정해야 한다» — нужны единые правила Брайля для разных товаров.<br>✖️ ① только для лекарств правила уже есть; ② про «осознание»; ③ про «проверку ошибок» — не главное.<br>🧩 점자 — шрифт Брайля; 통일된 규정 — единые правила; 관계 기관 — профильные ведомства."},{"n":37,"points":2,"instr":"다음을 읽고 글의 주제로 가장 알맞은 것을 고르십시오.","passage":"'자기 길들이기'는 동물이 스스로 공격성을 억제하고 친화력을 높이는 방향으로 진화하는 현상을 말한다. 호모 사피엔스도 이것을 생존 전략으로 삼았다는 가설이 있다. 네안데르탈인은 호모 사피엔스보다 체격도 좋고 뇌의 용량도 컸지만 살아남지 못했다. 반면 호모 사피엔스는 서로를 포용하고 보호하는 친화력을 무기로 살아남았다. 높은 친화력으로 더 큰 집단을 형성함으로써 외부의 공격과 환경 변화에 대응한 것이다.","options":["자기 길들이기는 인간이 가진 고유한 특성이다.","자기 길들이기는 네안데르탈인의 생존 전략이었다.","호모 사피엔스는 신체 능력이 가장 뛰어난 종이었다.","호모 사피엔스는 높은 친화력 덕분에 생존할 수 있었다."],"answer":4,"explain":"✅ <b>④</b> — вывод: H. sapiens выжил благодаря высокой 친화력 (дружелюбию), формируя большие группы.<br>✖️ ① «уникально человеческое» — это явление и у животных; ② это стратегия sapiens, а не неандертальцев; ③ физически крупнее был неандерталец.<br>🧩 친화력 — способность ладить; 포용하다 — принимать, объединять."},{"n":38,"points":2,"instr":"다음을 읽고 글의 주제로 가장 알맞은 것을 고르십시오.","passage":"뚜렷한 신념 없이 사안에 따라 의견을 바꾼다는 인식 때문에 중도층은 부정적 존재로 여겨진다. 그러나 이들에 대한 긍정적 평가도 있다. 주관 없이 흔들리는 것처럼 보이지만 쟁점에 대해 좀 더 유연하고 객관적으로 사고한다고 보는 관점이다. 중도층의 의견이 정치적 양극화를 완화하고 합리적으로 사회적 합의가 도출되도록 이끄는 토대가 될 수 있다는 것이다.","options":["중도층은 사회적 쟁점에 대해 대체로 비판적인 태도를 취한다.","중도층은 사회가 균형을 이루며 발전하도록 돕는 역할을 할 수 있다.","정치적 신념을 적극적으로 표출하는 것은 사회의 발전에 도움이 된다.","정치적 사안에 대해 그때그때 의견을 바꾸는 것은 사회 발전을 저해한다."],"answer":2,"explain":"✅ <b>②</b> — позитивный взгляд: умеренные смягчают поляризацию и помогают разумному согласию → «помогают обществу развиваться сбалансированно».<br>✖️ ① «критичны» — текст подчёркивает гибкость/объективность; ③/④ передают негативный взгляд, который автор оспаривает.<br>🧩 중도층 — умеренные (центристы); 양극화 — поляризация; 완화하다 — смягчать."},{"n":39,"points":2,"instr":"주어진 문장이 들어갈 곳으로 가장 알맞은 것을 고르십시오.","passage":"〈보기〉 이 책은 크게 두 부분으로 구성되어 있는데 먼저 옛 다리들과 그에 얽힌 이야기를 다룬다.\n\n이영천의 [다시, 오래된 다리를 거닐다]는 다리를 소재로 한국인의 삶을 돌아본 책이다. ( ㉠ ) 여기에서는 수백 년 전에 놓인 징검다리, 왕을 위한 다리 등을 통해 우리 고유의 풍속과 역사를 만난다. ( ㉡ ) 이어서 근현대식 다리와 함께 기술의 발전이 다리와 우리 사회에 가져온 변화를 살펴본다. ( ㉢ ) 이 책은 과거와 현재의 다리를 거닐며 우리가 지나온 길과 가야 할 길을 생각해 보게 한다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":1,"explain":"✅ <b>① ㉠</b> — «книга состоит из двух частей, сначала о старых мостах» вводит структуру; следом «여기에서는 … 징검다리» раскрывает первую часть, а «이어서 근현대식» — вторую.<br>✖️ В ㉡–㉣ структура уже описывается/итожится — вводное предложение там лишнее.<br>🧩 먼저 … 이어서 — «сначала… затем»; 〈보기〉 анонсирует обе части."},{"n":40,"points":2,"instr":"주어진 문장이 들어갈 곳으로 가장 알맞은 것을 고르십시오.","passage":"〈보기〉 장 신경계는 주로 장 내의 근육 운동과 소화액을 조절하여 소화를 촉진하는 일을 한다.\n\n뇌는 신경계를 통해 몸 전체의 움직임을 관장하는데 장의 경우에는 뇌의 명령 없이 자율적으로 작동하기도 한다. (　㉠　) 생존에 필수적인 식사와 소화를 위해 장에 별도의 신경계를 두었기 때문이다. (　㉡　) 한편 장 신경계가 오로지 장에만 관여하는 것은 아니다. (　㉢　) 과학자들은 장 신경계와 뇌가 서로 소통하고 있어서 장의 문제가 심리적 변화에 영향을 줄 수 있다고 말한다. (　㉣　)","options":["㉠","㉡","㉢","㉣"],"answer":2,"explain":"✅ <b>② ㉡</b> — перед ㉡ сказано, что у кишечника <b>отдельная</b> нервная система (별도의 신경계); 〈보기〉 поясняет, <b>что именно</b> она делает (моторика, соки, пищеварение), а после ㉡ «한편 … 오로지 장에만 관여하는 것은 아니다» переходит к другой функции.<br>✖️ ㉠ ещё про автономность; ㉢/㉣ уже про связь с мозгом.<br>🧩 장 신경계 — энтеральная (кишечная) нервная система; 촉진하다 — стимулировать."},{"n":41,"points":2,"instr":"주어진 문장이 들어갈 곳으로 가장 알맞은 것을 고르십시오.","passage":"〈보기〉 이처럼 정밀하면서도 실제와 같은 그림은 외부인이 궁궐에 침입할 목적으로 사용할 수 있다.\n\n동궐도는 창덕궁과 창경궁 전체를 그린 조선 시대의 그림이다. ( ㉠ ) 세로 2m, 가로 5m가 넘는 대작으로 건축물은 물론 주변의 산과 궁궐 안 연못, 나무까지 그대로 그려 넣었다. ( ㉡ ) 건물 배치와 건물 사이의 거리도 완벽하게 재현했다. ( ㉢ ) 이러한 이유로 제작자와 제작 연도를 포함하여 그림에 관련된 정보 일체가 왕실 기밀이었을 것으로 추정된다. ( ㉣ )","options":["㉠","㉡","㉢","㉣"],"answer":3,"explain":"✅ <b>③ ㉢</b> — перед ㉢ описана предельная точность (расположение, расстояния «완벽하게 재현»); 〈보기〉 «такая точная карта годится для проникновения» объясняет, почему дальше (이러한 이유로) всё держали в тайне.<br>✖️ ㉠/㉡ ещё описывают саму картину; ㉣ уже после вывода о секретности.<br>🧩 침입하다 — вторгаться; 기밀 — гос. тайна; 이처럼 — «как видно/таким образом»."},{"n":42,"points":2,"instr":"밑줄 친 부분에 나타난 '부모님'의 심정으로 가장 알맞은 것을 고르십시오.","passage":"올해 서른두 살인 준은 어렸을 때부터 특출나게 뛰어난 재능이 없다는 점이 큰 불만이었다. 공부도 그럭저럭, 외모도 그럭저럭이었다. (중략) 특이한 재능이 있긴 했다. 준은 본능적으로 동서남북을 감지할 수 있었다. 어느 장소에 가든지 북쪽과 동쪽이 어디인지 본능적으로 느낄 수 있는 감각이었다. 이게 남들은 못하는 특이한 재능이란 걸 알게 된 건 가족들과 3박 4일 일정으로 포항에 놀러갔던 중학생 때였다. 부모님은 유명하다는 포항 바닷가의 해돋이를 꼭 보고 싶어했다. (중략) \"여보, 이쪽으로 걸어가면 되겠지? 동쪽이 저쪽인가?\" \"아냐, 자기야. 호텔 지배인이 선착장으로 가라고 했잖아. 그러니까 저기가 동쪽이지!\" \"아냐, 엄마. 동쪽은 이쪽이잖아.\" 준은 후드 주머니에 꼼지락거리고 있던 손을 꺼내 반대편으로 가려는 부모를 잡았다. 준이 심드렁한 표정으로 반대쪽을 턱짓으로 가리키자 부모님은 고개를 갸웃했다. \"네가 그걸 어떻게 알아?\" \"이 방향이 북쪽이잖아. 그러니까 동쪽은 이쪽이지.\" (중략) 처음에 부모님은 반신반의했지만, 준이 물어볼 때마다 오차 없이 정확히 맞추는 걸 확인하고는 자기들이 천재를 낳았다며 즐거워했다.","options":["후회스럽다","의심스럽다","실망스럽다","짜증스럽다"],"answer":2,"explain":"✅ <b>② 의심스럽다</b> (недоверчиво) — «네가 그걸 어떻게 알아?» и 고개를 갸웃 (склонили головы), 반신반의 — родители сомневаются в способности сына.<br>✖️ ① сожаление; ③ разочарование; ④ раздражение — не передают сомнение.<br>🧩 반신반의 — сомневаться (наполовину верить); 고개를 갸웃하다 — недоумённо склонить голову."},{"n":43,"points":2,"instr":"윗글의 내용으로 알 수 있는 것을 고르십시오.","passage":"올해 서른두 살인 준은 어렸을 때부터 특출나게 뛰어난 재능이 없다는 점이 큰 불만이었다. 공부도 그럭저럭, 외모도 그럭저럭이었다. (중략) 특이한 재능이 있긴 했다. 준은 본능적으로 동서남북을 감지할 수 있었다. 어느 장소에 가든지 북쪽과 동쪽이 어디인지 본능적으로 느낄 수 있는 감각이었다. 이게 남들은 못하는 특이한 재능이란 걸 알게 된 건 가족들과 3박 4일 일정으로 포항에 놀러갔던 중학생 때였다. 부모님은 유명하다는 포항 바닷가의 해돋이를 꼭 보고 싶어했다. (중략) \"여보, 이쪽으로 걸어가면 되겠지? 동쪽이 저쪽인가?\" \"아냐, 자기야. 호텔 지배인이 선착장으로 가라고 했잖아. 그러니까 저기가 동쪽이지!\" \"아냐, 엄마. 동쪽은 이쪽이잖아.\" 준은 후드 주머니에 꼼지락거리고 있던 손을 꺼내 반대편으로 가려는 부모를 잡았다. 준이 심드렁한 표정으로 반대쪽을 턱짓으로 가리키자 부모님은 고개를 갸웃했다. \"네가 그걸 어떻게 알아?\" \"이 방향이 북쪽이잖아. 그러니까 동쪽은 이쪽이지.\" (중략) 처음에 부모님은 반신반의했지만, 준이 물어볼 때마다 오차 없이 정확히 맞추는 걸 확인하고는 자기들이 천재를 낳았다며 즐거워했다.","options":["준은 여행지에서 해 뜨는 방향을 한 번에 찾았다.","준의 부모님은 아들과 같은 능력을 가지고 있었다.","준은 공부를 잘해서 학교에서 모르는 사람이 없었다.","준의 부모님은 아들의 재능을 발견한 후 걱정하기 시작했다."],"answer":1,"explain":"✅ <b>①</b> — Чжун сразу указал восток (해돋이 — рассвет на востоке), а родители шли не туда → он «с первого раза нашёл сторону восхода».<br>✖️ ② у родителей такой способности нет (поэтому спорили); ③ учился он «그럭저럭» (так себе); ④ родители <b>обрадовались</b> (즐거워했다), а не встревожились.<br>🧩 동서남북 — стороны света; 오차 없이 — без ошибки."},{"n":44,"points":2,"instr":"( ㉠ )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"서양 역사에서는 15ㆍ16세기를 '위대한 발견의 시대'라고 부른다. 콜럼버스처럼 유럽의 많은 탐험가들이 금이나 향신료 등을 얻고자 (　㉠　) 때문이다. 그러나 이 시대에 이루어진 발견의 진정한 의미는 대륙의 발견이 아니라 바다의 발견이었다. 탐험을 통해 지구상의 모든 바다가 하나로 이어져 있다는 인식이 생겼다는 것, 또 이러한 인식을 바탕으로 다양한 해상 항로를 발견한 것이 이 시대의 진정한 소산이라는 것이다. 실제로 탐험가들은 아프리카를 돌아 인도양, 더 나아가 극동까지 가는 바닷길을 열었고 콜럼버스도 대서양을 왕복할 수 있는 경로를 만들었다. 바닷길이 열리자 전 세계가 하나의 지구가 되었고 이로 인해 경제, 기술, 문화뿐만 아니라 생태계의 교환까지 이루어지는 계기가 마련되었다.","options":["값비싼 물건을 매매했기","다양한 지도를 수집했기","미지의 땅을 찾아 떠났기","탐험에 대한 기록을 남겼기"],"answer":3,"explain":"✅ <b>③ 미지의 땅을 찾아 떠났기</b> — «эпоха великих открытий»: ради золота и пряностей исследователи «отправлялись на поиски неизведанных земель».<br>✖️ ① торговали дорогими товарами; ② собирали карты; ④ вели записи — не объясняют «위대한 발견».<br>🧩 미지의 — неизведанный; 떠나다 — отправляться; -고자 — «чтобы, с целью»."},{"n":45,"points":2,"instr":"윗글의 주제로 가장 알맞은 것을 고르십시오.","passage":"서양 역사에서는 15ㆍ16세기를 '위대한 발견의 시대'라고 부른다. 콜럼버스처럼 유럽의 많은 탐험가들이 금이나 향신료 등을 얻고자 (　㉠　) 때문이다. 그러나 이 시대에 이루어진 발견의 진정한 의미는 대륙의 발견이 아니라 바다의 발견이었다. 탐험을 통해 지구상의 모든 바다가 하나로 이어져 있다는 인식이 생겼다는 것, 또 이러한 인식을 바탕으로 다양한 해상 항로를 발견한 것이 이 시대의 진정한 소산이라는 것이다. 실제로 탐험가들은 아프리카를 돌아 인도양, 더 나아가 극동까지 가는 바닷길을 열었고 콜럼버스도 대서양을 왕복할 수 있는 경로를 만들었다. 바닷길이 열리자 전 세계가 하나의 지구가 되었고 이로 인해 경제, 기술, 문화뿐만 아니라 생태계의 교환까지 이루어지는 계기가 마련되었다.","options":["콜럼버스는 새로운 대륙을 개척하는 데 기여한 바가 크다.","신대륙 발견은 동방의 대륙 탐험을 시작하는 계기가 되었다.","신대륙 발견으로 대륙 간에 문물과 생물의 이동이 증가할 수 있었다.","유럽인들의 탐험은 항로를 만들어 세계를 연결시켰다는 데 의의가 있다."],"answer":4,"explain":"✅ <b>④</b> — главная мысль: подлинное значение эпохи — «발견의 진정한 의미는 … 바다의 발견», открытие морских путей соединило мир.<br>✖️ ① про Колумба-первооткрывателя — текст спорит с «открытием материка»; ② «начало восточных экспедиций» — не суть; ③ обмен товаров/биологии — следствие, но тема шире — морские пути.<br>🧩 항로 — морской путь; 의의가 있다 — иметь значение; 소산 — плод, результат."},{"n":46,"points":2,"instr":"윗글에 나타난 필자의 태도로 가장 알맞은 것을 고르십시오.","passage":"세계는 신에너지, 자동화, 우주여행 등이 주도하는 시대로 급속히 접어들고 있다. 세계 각국은 풍력, 태양광 등 재생 가능한 에너지를 개발하는 회사에 대한 정부 보조금을 늘리고 있고 그에 따라 대체 에너지의 사용 비율도 점차 증가하고 있다. 민간 우주 산업 육성을 위해 인공위성 주파수 사용과 우주선 발사 등에 대한 대대적인 규제 완화를 한 국가도 있다. 그 덕분에 한 민간 기업은 화성 여행이 가능한 호텔급 우주여행선을 제작할 수 있었다. 민간 기업이 과학 기술 개발을 주도하며 성장할 수 있게 된 것은 정부가 지원을 확대하면서도 간섭을 최소화했기 때문이다. 이처럼 과학 기술이 유의미하게 발전하기 위해서는 과학 전문가들이 정책 수립을 주도하고 전문 기업이 그 정책의 수행을 담당할 수 있게 해야 한다. 이때 정부는 모든 과정에 지원은 하되 과도하게 관여하는 일은 없어야 할 것이다.","options":["과학 정책에 대한 정부의 지나친 개입을 경계하고 있다.","과학 기술 발전을 위해서는 연구가 중요함을 강조하고 있다.","과학 기술 발전이 경제 성장에 미치는 영향력에 감탄하고 있다.","과학 정책 수립 시 우주 과학이 소홀히 다루어질 것을 우려하고 있다."],"answer":1,"explain":"✅ <b>①</b> — позиция автора: «정부는 지원은 하되 과도하게 관여하는 일은 없어야» — государство должно поддерживать, но не вмешиваться чрезмерно → автор предостерегает от излишнего вмешательства.<br>✖️ ② важность исследований не главный посыл; ③ восхищения экономикой нет; ④ про «недооценку космонауки» — не сказано.<br>🧩 경계하다 — остерегаться; 간섭/관여 — вмешательство; -하되 — «делать, но при этом»."},{"n":47,"points":2,"instr":"윗글의 내용과 같은 것을 고르십시오.","passage":"세계는 신에너지, 자동화, 우주여행 등이 주도하는 시대로 급속히 접어들고 있다. 세계 각국은 풍력, 태양광 등 재생 가능한 에너지를 개발하는 회사에 대한 정부 보조금을 늘리고 있고 그에 따라 대체 에너지의 사용 비율도 점차 증가하고 있다. 민간 우주 산업 육성을 위해 인공위성 주파수 사용과 우주선 발사 등에 대한 대대적인 규제 완화를 한 국가도 있다. 그 덕분에 한 민간 기업은 화성 여행이 가능한 호텔급 우주여행선을 제작할 수 있었다. 민간 기업이 과학 기술 개발을 주도하며 성장할 수 있게 된 것은 정부가 지원을 확대하면서도 간섭을 최소화했기 때문이다. 이처럼 과학 기술이 유의미하게 발전하기 위해서는 과학 전문가들이 정책 수립을 주도하고 전문 기업이 그 정책의 수행을 담당할 수 있게 해야 한다. 이때 정부는 모든 과정에 지원은 하되 과도하게 관여하는 일은 없어야 할 것이다.","options":["많은 국가들이 신에너지 개발에 대한 투자를 줄이고 있다.","과학 정책이 빠르게 변해서 과학 기술이 발전할 수 있었다.","정부가 우주 산업에 대한 규제를 풀어 성장한 민간 기업이 있다.","우주 개발에 참여 중인 민간 기업이 화성에 호텔을 건설하고 있다."],"answer":3,"explain":"✅ <b>③</b> — «규제 완화 … 그 덕분에 한 민간 기업은 … 우주여행선을 제작» — благодаря смягчению регулирования выросла частная компания.<br>✖️ ① субсидии на новую энергию <b>увеличивают</b> (늘리고); ② про «быструю смену политики» — не сказано; ④ строят корабль класса «отель», а не отель на Марсе.<br>🧩 규제 완화 — смягчение регулирования; 민간 기업 — частная компания."},{"n":48,"points":2,"instr":"윗글을 쓴 목적으로 가장 알맞은 것을 고르십시오.","passage":"많은 사람들은 결혼, 수입 등의 객관적 조건이 행복을 결정하는 요인이라고 생각한다. 그러나 이런 요인들로는 행복의 이유를 10% 정도밖에 설명할 수 없다고 한다. 그렇다면 행복을 결정하는 요인은 무엇일까? 그것은 행복에 대해 가지는 믿음과 태도이다. 행복에 대한 태도는 행복의 유한성과 무한성 중 어느 한쪽을 선택함으로써 결정된다. 이 세상에 존재하는 행복의 (　㉠　) 믿는 사람들은 항상 타인이 행복한 정도를 예의 주시하는 특징이 관찰되었다. 남이 행복하면 내 행복이 줄어든다고 생각하는 사람에게는 타인의 행복이 자신의 행복에 위협적인 요소가 되기 때문이다. 반면 행복의 무한성을 믿는 사람들은 타인의 행복에 그다지 관심을 가지지 않는다. 따라서 행복하려면 행복이 무한한 것이라는 믿음을 가질 필요가 있다. 이러한 생각만으로도 행복감은 증대될 수 있으며 자신이 어떻게 할 때 행복해지는지에 집중할 수 있게 되기 때문이다.","options":["행복의 사회적 특성을 파악하려고","행복을 측정하는 방법을 소개하려고","행복에 대한 관점의 변화를 유도하려고","행복이 인간에게 미치는 영향을 분석하려고"],"answer":3,"explain":"✅ <b>③</b> — цель: показать, что счастье определяет не условия, а вера в его «무한성», и призвать сменить взгляд → «изменить точку зрения на счастье».<br>✖️ ① «социальные черты» — не цель; ② метод измерения не вводится; ④ влияние счастья не анализируется.<br>🧩 관점의 변화를 유도하다 — побуждать к смене взгляда; 유한성/무한성 — конечность/бесконечность."},{"n":49,"points":2,"instr":"( ㉠ )에 들어갈 말로 가장 알맞은 것을 고르십시오.","passage":"많은 사람들은 결혼, 수입 등의 객관적 조건이 행복을 결정하는 요인이라고 생각한다. 그러나 이런 요인들로는 행복의 이유를 10% 정도밖에 설명할 수 없다고 한다. 그렇다면 행복을 결정하는 요인은 무엇일까? 그것은 행복에 대해 가지는 믿음과 태도이다. 행복에 대한 태도는 행복의 유한성과 무한성 중 어느 한쪽을 선택함으로써 결정된다. 이 세상에 존재하는 행복의 (　㉠　) 믿는 사람들은 항상 타인이 행복한 정도를 예의 주시하는 특징이 관찰되었다. 남이 행복하면 내 행복이 줄어든다고 생각하는 사람에게는 타인의 행복이 자신의 행복에 위협적인 요소가 되기 때문이다. 반면 행복의 무한성을 믿는 사람들은 타인의 행복에 그다지 관심을 가지지 않는다. 따라서 행복하려면 행복이 무한한 것이라는 믿음을 가질 필요가 있다. 이러한 생각만으로도 행복감은 증대될 수 있으며 자신이 어떻게 할 때 행복해지는지에 집중할 수 있게 되기 때문이다.","options":["개인차가 크지 않다고","총량이 정해져 있다고","양상이 매우 다양하다고","크기가 계속 증가한다고"],"answer":2,"explain":"✅ <b>② 총량이 정해져 있다고</b> — далее: «남이 행복하면 내 행복이 줄어든다» → такие люди верят, что счастья <b>конечное количество</b> (유한성).<br>✖️ ① мало индивидуальных различий; ③ разнообразие форм; ④ постоянный рост — не объясняют «чужое счастье уменьшает моё».<br>🧩 총량 — общее количество; 정해져 있다 — фиксировано; 예의 주시하다 — пристально следить."},{"n":50,"points":2,"instr":"윗글의 내용과 같은 것을 고르십시오.","passage":"많은 사람들은 결혼, 수입 등의 객관적 조건이 행복을 결정하는 요인이라고 생각한다. 그러나 이런 요인들로는 행복의 이유를 10% 정도밖에 설명할 수 없다고 한다. 그렇다면 행복을 결정하는 요인은 무엇일까? 그것은 행복에 대해 가지는 믿음과 태도이다. 행복에 대한 태도는 행복의 유한성과 무한성 중 어느 한쪽을 선택함으로써 결정된다. 이 세상에 존재하는 행복의 (　㉠　) 믿는 사람들은 항상 타인이 행복한 정도를 예의 주시하는 특징이 관찰되었다. 남이 행복하면 내 행복이 줄어든다고 생각하는 사람에게는 타인의 행복이 자신의 행복에 위협적인 요소가 되기 때문이다. 반면 행복의 무한성을 믿는 사람들은 타인의 행복에 그다지 관심을 가지지 않는다. 따라서 행복하려면 행복이 무한한 것이라는 믿음을 가질 필요가 있다. 이러한 생각만으로도 행복감은 증대될 수 있으며 자신이 어떻게 할 때 행복해지는지에 집중할 수 있게 되기 때문이다.","options":["행복에 대한 사람들의 태도는 대체로 유사하다.","행복은 결혼 여부나 수입 정도의 영향을 많이 받는다.","행복의 양이 유한하다고 믿는 사람들은 더 많이 행복할 수 있다.","행복이 무한하다고 믿는 사람들은 자신을 남과 잘 비교하지 않는다."],"answer":4,"explain":"✅ <b>④</b> — «무한성을 믿는 사람들은 타인의 행복에 그다지 관심을 가지지 않는다» — верящие в безграничность счастья не сравнивают себя с другими.<br>✖️ ① отношения как раз делятся на два типа; ② объективные условия объясняют лишь ~10%; ③ наоборот — счастливее те, кто верит в <b>무한성</b>.<br>🧩 무한하다 — безграничный; 비교하다 — сравнивать."}] },
      writing: {
        durationMin: 50, label: '제83회 · 쓰기 (51~54)',
        tasks: [
          { n:51, points:10, korInstr:'다음 글의 ㉠과 ㉡에 알맞은 말을 각각 쓰시오. (각 10점)',
            instr:'Впишите подходящие выражения в ㉠ и ㉡. Сообщение на форуме мэрии — формальный стиль -습니다.',
            passage:`🪧 자유게시판 · 인주시청 — 축제 관련 문의\n지난 주말 '인주시 별빛 축제'에 갔던 외국인입니다.\n지금까지 살면서 이렇게 많은 별을 ( ㉠ ) 한 번도 없었습니다.\n이번 축제에서 별도 보고 공연도 볼 수 있어서 정말 좋았습니다.\n혹시 축제가 언제 또 있습니까?\n있다면 이런 멋진 경험을 다시 ( ㉡ ).`,
            blanks:[
              { slot:'㉠', model:'본 적이',
                check:'Подсказка «한 번도 … 없었습니다» → -(으)ㄴ 적이 없다 («ни разу не доводилось»): 본 적이 (별을 보다 — видеть звёзды).' },
              { slot:'㉡', model:'하고 싶습니다 / 해 보고 싶습니다',
                check:'«있다면 … 다시» (если будет — снова) → желание 하고 싶다 (경험을 하다 — получить опыт). Стиль -습니다, законченное предложение.' }
            ] },
          { n:52, points:10, korInstr:'다음 글의 ㉠과 ㉡에 알맞은 말을 각각 쓰시오. (각 10점)',
            instr:'Впишите подходящие выражения в ㉠ и ㉡. Научно-популярный текст — письменный стиль -ㄴ다.',
            passage:`식물은 다양한 방법으로 자신을 보호한다. 덩굴성 야자나무는 빈 줄기를 개미에게 집으로 제공한다. 이 나무에 다른 동물이 다가오면 줄기 속에 있던 개미들은 밖으로 나온다. 이때 개미들의 움직임으로 소리가 생긴다. 이 소리는 동물을 깜짝 ( ㉠ ). 결국 놀란 동물은 나뭇잎을 먹지 못하고 달아나 버린다. 식물학자들은 이것이 바로 이 나무가 자신을 보호하는 ( ㉡ ).`,
            blanks:[
              { slot:'㉠', model:'놀라게 한다 / 놀라게 만든다',
                check:'Дальше по тексту «놀란 동물은…» (испуганное животное) → звук ПУГАЕТ животное: каузатив -게 하다/만들다 → 놀라게 한다. Стиль -ㄴ다.' },
              { slot:'㉡', model:'방법이라고 본다 / 방법이라고 생각한다',
                check:'«식물학자들은 … 보호하는 ( )» — учёные СЧИТАЮТ это способом защиты: сущ. 방법 + косвенная речь -(이)라고 보다/생각하다. Письменный стиль.' }
            ] },
          { n:53, points:30, min:200, max:300, korInstr:'다음은 \'인주시의 가구 수 변화\'에 대한 자료이다. 이 내용을 200~300자의 글로 쓰시오. 단, 글의 제목은 쓰지 마시오. (30점)',
            instr:'Опишите данные «인주시의 가구 수 변화» (изменение числа домохозяйств г. Инджу) текстом 200–300 знаков. Заголовок не пишите. Письменный стиль -ㄴ다/-는다.',
            image:'assets/topik2/exams/img/83-w53.png',
            model:'인주시 사회연구소의 조사에 따르면 인주시의 가구 수는 2001년 15만 가구에서 2021년 21만 가구로 20년 동안 1.4배 증가하였다. 인원수별 가구의 비율을 살펴보면 1인 가구는 15%에서 30%로 늘었고 2~3인 가구도 45%에서 50%로 증가한 반면 4인 이상 가구는 40%에서 20%로 크게 줄었다. 이러한 변화의 원인으로는 독립하는 20대가 늘어난 것과 노인 가구가 증가한 것을 들 수 있다. 앞으로 2040년에는 1인 가구의 비율이 전체의 43% 이상이 될 것으로 전망된다.',
            check:'① Источник (인주시 사회연구소)? ② Рост числа домохозяйств 15만→21만 (1.4배)? ③ Доли по составу: 1인 15→30%, 2~3인 45→50%, 4인 이상 40→20%? ④ Причины (молодёжь отделяется, больше пожилых домохозяйств)? ⑤ Прогноз 2040 (1인 가구 43%+)? ⑥ Стиль -ㄴ다, объём 200–300.' },
          { n:54, points:50, min:600, max:700, korInstr:'다음을 참고하여 600~700자로 글을 쓰시오. 단, 문제를 그대로 옮겨 쓰지 마시오. (50점)',
            instr:'Эссе 600–700 знаков на тему «창의력의 필요성과 이를 기르기 위한 노력» (зачем нужна креативность и как её развивать). Раскройте все три вопроса из задания, каждый — отдельным абзацем.',
            passage:`창의력은 새로운 것을 생각해 내는 능력이다. 현대 사회는 개인에게 창의력을 더 많이 요구하고 있다.\n• 창의력이 필요한 이유는 무엇인가?\n• 창의력을 발휘했을 때 얻을 수 있는 성과는 무엇인가?\n• 창의력을 기르기 위해서 어떠한 노력을 할 수 있는가?`,
            model:'창의력은 새로운 것을 생각해 내는 능력으로, 현대 사회에서 그 중요성이 점점 커지고 있다. 사회가 빠르게 변화하면서 기존의 방법만으로는 해결할 수 없는 문제들이 계속 생겨나고 있기 때문이다. 이러한 문제를 해결하려면 남과 다른 시각으로 상황을 바라보고 새로운 해결책을 찾아내는 창의력이 반드시 필요하다.\n창의력을 발휘하면 개인과 사회 모두 큰 성과를 얻을 수 있다. 개인은 자신만의 아이디어로 경쟁력을 갖추게 되고 이는 학업이나 업무에서 좋은 결과로 이어진다. 또한 기업과 사회는 창의적인 아이디어를 통해 새로운 제품과 서비스를 만들어 내며 이것이 사회 전체의 발전으로 이어진다. 스마트폰과 같은 발명품이 우리의 생활을 완전히 바꾼 것이 대표적인 예이다.\n창의력을 기르기 위해서는 무엇보다 다양한 경험을 쌓는 노력이 필요하다. 책을 읽거나 여행을 하면서 새로운 세계를 접하면 생각의 폭이 넓어진다. 또한 어떤 문제를 만났을 때 정답이 하나라고 생각하지 말고 여러 가지 해결 방법을 찾아보는 습관을 기르는 것이 좋다. 실패를 두려워하지 않고 새로운 시도를 계속하는 태도 역시 창의력을 기르는 데 큰 도움이 된다.\n결국 창의력은 타고나는 것이 아니라 꾸준한 노력으로 기를 수 있는 능력이며, 현대 사회를 살아가는 우리 모두에게 꼭 필요한 힘이라고 할 수 있다.',
            check:'① Все 3 вопроса раскрыты (зачем нужна / какие результаты даёт / как развивать)? ② Вступление и вывод есть? ③ Примеры в каждом абзаце? ④ Связки уровня (-기 때문에, 또한, 역시, 결국)? ⑤ Стиль -ㄴ다? ⑥ Объём 600–700 знаков?' }
        ]
      }
    }
  };

  // ── 쓰기-режим: 4 задания, таймер 50 мин, самооценка по критериям ──
  let _w2State = null, _w2Timer = null;
  function startTopikWriting(n) {
    const data = (TOPIK2_EXAMS[n] || {}).writing;
    if (!data || !data.tasks || !data.tasks.length) { toast('Этот раздел готовится 🌸', 'var(--berry)'); return; }
    _w2State = { exam: n, label: data.label, tasks: data.tasks, answers: {}, endAt: Date.now() + (data.durationMin || 50) * 60000, finished: false };
    let ov = document.getElementById('topik-exam-overlay');
    if (!ov) { ov = document.createElement('div'); ov.id = 'topik-exam-overlay'; ov.className = 'exam-overlay'; document.body.appendChild(ov); }
    document.body.style.overflow = 'hidden';
    renderW2();
    clearInterval(_w2Timer);
    _w2Timer = setInterval(() => {
      if (!_w2State || _w2State.finished) { clearInterval(_w2Timer); return; }
      const left = _w2State.endAt - Date.now();
      const el = document.getElementById('w2-timer');
      if (el) { el.textContent = '⏱ ' + examFmtTime(left); el.classList.toggle('low', left < 5 * 60000); }
      if (left <= 0) { clearInterval(_w2Timer); finishW2(); }
    }, 1000);
  }
  function exitW2() {
    clearInterval(_w2Timer); _w2State = null;
    document.getElementById('topik-exam-overlay')?.remove();
    document.body.style.overflow = '';
  }
  function _w2Count(id) {
    const t = (document.getElementById('w2-in-' + id)?.value || '');
    return t.replace(/\s/g, '').length; // знаки без пробелов (ориентир для 원고지)
  }
  function w2Input(id) {
    if (!_w2State) return;
    const el = document.getElementById('w2-cnt-' + id);
    const task = _w2State.tasks.find(t => String(t.n) === String(id));
    if (el && task && task.min) {
      const c = _w2Count(id);
      el.textContent = c + ' зн.';
      el.style.color = c < task.min ? 'var(--bad-ink)' : c > task.max ? 'var(--gold-ink)' : 'var(--ok-ink)';
    }
  }
  function renderW2() {
    const ov = document.getElementById('topik-exam-overlay');
    if (!ov || !_w2State) return;
    const tasksHtml = _w2State.tasks.map(t => {
      const id = String(t.n);
      const long = !!t.min;
      let body;
      if (t.blanks) {
        // 51~52: один текст с двумя пропусками ㉠/㉡ — заполняем оба
        body = `<div style="display:grid; gap:10px; margin-top:2px;">` + t.blanks.map(b => `
            <div>
              <div style="font-size:13px; font-weight:800; color:var(--coral); margin-bottom:4px;">${b.slot}</div>
              <input id="w2-in-${id}-${b.slot}" class="input ko" placeholder="Впишите законченное выражение для ${b.slot}" autocomplete="off">
            </div>`).join('') + `</div>`;
      } else if (long) {
        body = `<textarea id="w2-in-${id}" class="input ko" rows="${t.n === 54 ? 10 : 6}" oninput="w2Input('${id}')" placeholder="${t.min}–${t.max} знаков · стиль -ㄴ다/-는다" style="resize:vertical; line-height:1.7;"></textarea>`;
      } else { body = ''; }
      return `
        <div class="card card-padded" style="margin-bottom:14px;">
          <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
            <div style="font-weight:800;">№${t.n} <span class="chip" style="font-size:10px; margin-left:6px;">${t.points} б.</span></div>
            ${long ? `<span id="w2-cnt-${id}" style="font-size:11px; color:var(--soft);">0 зн.</span>` : ''}
          </div>
          ${t.korInstr ? `<div class="ko" style="font-size:12.5px; font-weight:700; color:var(--berry); margin-bottom:6px;">${t.korInstr}</div>` : ''}
          ${t.instr ? `<div style="font-size:12.5px; color:var(--text2); margin-bottom:8px;">${t.instr}</div>` : ''}
          ${t.image ? `<img src="${t.image}" alt="Задание ${t.n}" style="width:100%; border-radius:12px; border:1px solid var(--line); margin-bottom:10px; background:#fff;">` : ''}
          ${t.passage ? `<div class="exam-passage ko" style="margin-bottom:10px; white-space:pre-wrap;">${t.passage}</div>` : ''}
          ${body}
        </div>`;
    }).join('');
    ov.innerHTML = `
      <div class="exam-top">
        <button onclick="exitW2()" class="chat-back-btn" aria-label="Выйти" style="width:38px; height:38px;"><i class="fa-solid fa-xmark"></i></button>
        <div style="font-weight:800; font-size:14px; flex:1;">${_w2State.label || ('쓰기 · 제' + _w2State.exam + '회 (51~54)')}</div>
        <span id="w2-timer" class="exam-timer">⏱ 50:00</span>
      </div>
      <div class="exam-results" style="overflow-y:auto; flex:1;">
        <div class="topik-note" style="margin-bottom:14px;">✍️ Пиши как на настоящем экзамене: №51–52 — впиши пропущенные предложения (㉠ и ㉡), №53 — описание данных (200–300 знаков), №54 — эссе (600–700 знаков). Автопроверки нет — в конце сравнишь с образцом (모범답안) и критериями.</div>
        ${tasksHtml}
        <button onclick="finishW2()" class="btn btn-primary btn-block" style="margin-top:4px;">Завершить 쓰기 ✓</button>
        <div style="height:30px;"></div>
      </div>`;
  }
  function finishW2() {
    if (!_w2State || _w2State.finished) return;
    _w2State.finished = true;
    clearInterval(_w2Timer);
    const ov = document.getElementById('topik-exam-overlay');
    if (!ov) return;
    const rows = _w2State.tasks.map(t => {
      const id = String(t.n);
      if (t.blanks) {
        const inner = t.blanks.map(b => {
          const my = (document.getElementById('w2-in-' + id + '-' + b.slot)?.value || '').trim();
          return `
            <div style="margin-bottom:12px;">
              <div style="font-size:12px; color:var(--soft); margin-bottom:3px;"><b style="color:var(--coral);">${b.slot}</b> · твой ответ:</div>
              <div class="ko" style="white-space:pre-wrap; font-size:13.5px; line-height:1.7; background:var(--veil); border-radius:10px; padding:9px 11px;">${escHtml(my) || '<i style="color:var(--hush)">— пусто —</i>'}</div>
              <div style="font-size:12px; color:var(--soft); margin:7px 0 3px;">모범답안 · образец:</div>
              <div class="ko" style="white-space:pre-wrap; font-size:13.5px; line-height:1.7; background:rgba(var(--accent-rgb),.08); border-radius:10px; padding:9px 11px;">${b.model}</div>
              ${b.check ? `<div style="font-size:12px; color:var(--text2); margin-top:6px; line-height:1.55;">✅ ${b.check}</div>` : ''}
            </div>`;
        }).join('');
        return `
          <div class="card card-padded" style="margin-bottom:12px;">
            <div style="margin-bottom:8px;"><b>№${t.n}</b> <span class="chip" style="font-size:10px; margin-left:4px;">${t.points} б.</span></div>
            ${inner}
          </div>`;
      }
      const my = (document.getElementById('w2-in-' + id)?.value || '').trim();
      const cnt = my.replace(/\s/g, '').length;
      const lenNote = t.min ? `<span style="font-size:11px; color:${cnt < t.min ? 'var(--bad-ink)' : 'var(--ok-ink)'};">${cnt} зн. ${cnt < t.min ? '· меньше минимума!' : '✓'}</span>` : '';
      return `
        <div class="card card-padded" style="margin-bottom:12px;">
          <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
            <b>№${t.n}</b> <span class="chip" style="font-size:10px; margin-left:4px;">${t.points} б.</span>${lenNote}
          </div>
          <div style="font-size:12px; color:var(--soft); margin-bottom:4px;">Твой ответ:</div>
          <div class="ko" style="white-space:pre-wrap; font-size:13.5px; line-height:1.7; background:var(--veil); border-radius:10px; padding:10px 12px;">${escHtml(my) || '<i style="color:var(--hush)">— пусто —</i>'}</div>
          ${t.model ? `
            <div style="font-size:12px; color:var(--soft); margin:10px 0 4px;">모범답안 · образцовый ответ:</div>
            <div class="ko" style="white-space:pre-wrap; font-size:13.5px; line-height:1.7; background:rgba(var(--accent-rgb),.08); border-radius:10px; padding:10px 12px;">${t.model}</div>` : ''}
          ${t.check ? `<div style="font-size:12px; color:var(--text2); margin-top:10px; line-height:1.55;">✅ Проверь себя: ${t.check}</div>` : ''}
        </div>`;
    }).join('');
    ov.querySelector('.exam-results').innerHTML = `
      <div class="exam-score-card" style="margin-bottom:16px;">
        <div class="display" style="font-size:26px; color:var(--berry);">쓰기 готово ✍️</div>
        <div style="font-size:12.5px; color:var(--soft); margin-top:6px;">Сравни свои ответы с образцами и критериями — оцени честно 🌸</div>
      </div>
      ${rows}
      <button onclick="exitW2()" class="btn btn-primary btn-block">Готово ✓</button>
      <div style="height:30px;"></div>`;
    ov.querySelector('.exam-results').scrollTop = 0;
    try { addXp(15); } catch (_) {}
  }

  function renderTopikSection(slot, k, admin) {
    if (k === 'exams') return _topikLevel === '2' ? renderTopik2Exams(slot) : renderTopikExams(slot, admin);
    if (k === 'about2') return renderTopik2About(slot);
    if (k === 'writing2') return renderTopik2WritingGuide(slot);
    if (k === 'words2') {
      slot.innerHTML = topikSectionWrap('📖 Слова', 'Лексика TOPIK II (중급) по темам', `
        <div class="topik-rules">${TOPIK2_VOCAB_THEMES.map((t, i) => topikVocabThemeHtml(t, i)).join('')}</div>`, false, null);
      return;
    }
    if (k === 'grammar2') {
      const groups2 = TOPIK2_GRAMMAR.map(g => `
        <div class="topik-group">
          <div class="topik-group-head"><span class="topik-group-label">${g.title}</span><span class="topik-group-count">${g.items.length}</span></div>
          <div class="topik-gram">${g.items.map(it => `
            <div class="topik-gram-row"><span class="topik-gram-k ko">${it[0]}</span><span class="topik-gram-m">${it[1]}</span><span class="topik-gram-e ko">${it[2]}</span></div>`).join('')}</div>
        </div>`).join('');
      slot.innerHTML = topikSectionWrap('🧩 Грамматика', 'Ключевые конструкции уровней 3–4급 (60)', groups2, false, null);
      return;
    }
    if (k === 'tips2') {
      slot.innerHTML = topikSectionWrap('💡 Советы', 'Стратегия по трём разделам TOPIK II', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK2_TIPS, 'topik2-tip')}</div>`, false, null);
      return;
    }
    if (k === 'howto2') {
      slot.innerHTML = topikSectionWrap('🎯 Как решать', 'Разбор по типам заданий TOPIK II', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK2_HOWTO, 'topik2-how')}</div>`, false, null);
      return;
    }
    if (k === 'hints2') {
      slot.innerHTML = topikSectionWrap('✨ Подсказки', 'Мелочи, которые решают на TOPIK II', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK2_HINTS, 'topik2-hint')}</div>`, false, null);
      return;
    }
    if (k === 'words') {
      slot.innerHTML = topikSectionWrap('📖 Слова', 'Базовая лексика TOPIK I по темам', `
        <div class="topik-rules">${TOPIK_VOCAB_THEMES.map((t, i) => topikVocabThemeHtml(t, i)).join('')}</div>
        ${topikAdminMatsHtml('vocab', admin)}`, admin, 'vocab');
      return;
    }
    if (k === 'grammar') {
      const groups = TOPIK_GRAMMAR.map(g => `
        <div class="topik-group">
          <div class="topik-group-head"><span class="topik-group-label">${g.title}</span><span class="topik-group-count">${g.items.length}</span></div>
          <div class="topik-gram">${g.items.map(it => `
            <div class="topik-gram-row"><span class="topik-gram-k ko">${it[0]}</span><span class="topik-gram-m">${it[1]}</span><span class="topik-gram-e ko">${it[2]}</span></div>`).join('')}</div>
        </div>`).join('');
      slot.innerHTML = topikSectionWrap('🧩 Грамматика', 'Ключевые конструкции уровней 1–2 (84)', groups + topikAdminMatsHtml('grammar', admin), admin, 'grammar');
      return;
    }
    if (k === 'tips') {
      slot.innerHTML = topikSectionWrap('💡 Советы', 'Как готовиться и не терять баллы', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK_TIPS, 'topik-tip')}</div>
        ${topikAdminMatsHtml('tip', admin)}`, admin, 'tip');
      return;
    }
    if (k === 'howto') {
      slot.innerHTML = topikSectionWrap('🎯 Как решать', 'Разбор по типам заданий', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK_HOWTO, 'topik-how')}</div>`, false, null);
      return;
    }
    if (k === 'hints') {
      slot.innerHTML = topikSectionWrap('✨ Подсказки', 'Мелочи, которые решают', `
        <div class="topik-rules">${topikAccordionHtml(TOPIK_HINTS, 'topik-hint')}</div>`, false, null);
      return;
    }
    if (k === 'mustknow') {
      const read = topikReadSet();
      const rulesHtml = TOPIK_WRITING_RULES.map(r => `
        <div class="topik-rule ${read.has(r.id) ? 'read' : ''}" id="topik-rule-${r.id}">
          <button type="button" class="topik-rule-head" onclick="toggleTopikRule('${r.id}')">
            <span class="topik-rule-ico">${r.icon}</span>
            <span class="topik-rule-title">${r.title}</span>
            <span class="topik-rule-check" aria-hidden="true">✓</span>
            <i class="fa-solid fa-chevron-down topik-rule-chev" aria-hidden="true"></i>
          </button>
          <div class="topik-rule-body">${r.body}</div>
        </div>`).join('');
      slot.innerHTML = topikSectionWrap('📌 Что нужно знать', 'Формат экзамена, баллы и основы письма', `
        <div class="card card-padded topik-about">
          <p><b>TOPIK</b> (한국어능력시험) — официальный экзамен на знание корейского: нужен для вузов Кореи, визы и работы. Результат — уровень <b>급</b> (1–6).</p>
          <table class="topik-table">
            <tr><th>Раздел</th><th>Вопросов</th><th>Время</th></tr>
            <tr><td><span class="ko">듣기</span> · Аудирование</td><td>30</td><td>40 мин</td></tr>
            <tr><td><span class="ko">읽기</span> · Чтение</td><td>40</td><td>60 мин</td></tr>
          </table>
          <div class="topik-grades">Итог: <b>200</b> баллов · <b>1급</b> от 80 · <b>2급</b> от 140</div>
          <p class="topik-note">📌 В TOPIK I письма нет. Раздел <b><span class="ko">쓰기</span></b> появляется в TOPIK II — основы ниже подготовят тебя заранее.</p>
        </div>
        <div class="section-head" style="margin-top:18px;">
          <div class="left"><div class="rule"></div><span class="title">쓰기 기초 · Основы письма</span></div>
          <span class="meta">прочитано <span id="topik-read-count">0/${TOPIK_WRITING_RULES.length}</span></span>
        </div>
        <div class="topik-rules">${rulesHtml}</div>
        ${topikAdminMatsHtml('file', admin)}`, admin, 'file');
      updateTopikReadCount();
      return;
    }
    renderTopikMenu(slot);
  }

  function renderTopik() {
    const slot = document.getElementById('topik-hub');
    if (!slot) return;
    const admin = isAdmin();
    if (!_topikSection) { renderTopikMenu(slot); return; }
    renderTopikSection(slot, _topikSection, admin);
  }

