  function ssGroups(sec) {
    let base;
    if (sec.refTitles) base = (typeof TOPIK2_VOCAB_THEMES !== 'undefined' ? TOPIK2_VOCAB_THEMES : [])
      .filter(t => sec.refTitles.includes(t.title));
    else base = sec.groups || [];
    return sec.extra ? base.concat(sec.extra) : base;
  }
  function ssThemeHtml(t) {
    return `<div class="topik-rule">
      <button type="button" class="topik-rule-head" onclick="this.parentElement.classList.toggle('open')">
        <span class="topik-rule-ico">${t.ico}</span>
        <span class="topik-rule-title">${t.title}</span>
        <span class="topik-group-count">${t.words.length}</span>
        <i class="fa-solid fa-chevron-down topik-rule-chev" aria-hidden="true"></i>
      </button>
      <div class="topik-rule-body"><div class="topik-words">${t.words.map(w => `
        <div class="topik-word"><span class="topik-word-ko ko">${w[0]}</span><span class="topik-word-ru">${w[1]}</span><span class="topik-word-ex ko">${w[2] || ''}</span></div>`).join('')}</div></div>
    </div>`;
  }
  function openSelfStudy() { switchScreen('selfstudy'); }
  function ssHome() { _ssSection = null; renderSelfStudy(); requestAnimationFrame(() => _setScroll(_ssMenuScroll)); }
  function openSsSection(k) { _ssMenuScroll = _getScroll(); _ssSection = k; renderSelfStudy(); const sc = document.getElementById('screen-selfstudy'); if (sc) sc.scrollTop = 0; window.scrollTo(0, 0); }
  function selfStudyBack() { if (_ssSection) { ssHome(); } else { switchScreen('lessons', true); } }
  function renderSelfStudy() {
    const slot = document.getElementById('selfstudy-hub');
    if (!slot) return;
    if (!_ssSection) { renderSsMenu(slot); return; }
    renderSsSection(slot, _ssSection);
  }
  function renderSsMenu(slot) {
    slot.innerHTML = `
      <div class="topik-hero">
        <div class="topik-hero-badge">자습 📚</div>
        <div class="topik-hero-title ko">혼자 공부하기</div>
        <div class="topik-hero-sub">Материалы по разделам · корейский с переводом и примерами</div>
      </div>
      <div class="topik-menu-grid">
        ${SELFSTUDY.map(x => `
          <button type="button" class="topik-menu-card" onclick="openSsSection('${x.k}')" aria-label="${x.t}">
            <span class="topik-menu-ico" aria-hidden="true">${x.ico}</span>
            <span class="topik-menu-t">${x.t}</span>
            <span class="topik-menu-s">${x.s}</span>
          </button>`).join('')}
      </div>`;
  }
  function renderSsSection(slot, k) {
    const sec = SELFSTUDY.find(s => s.k === k);
    if (!sec) { ssHome(); return; }
    const groups = ssGroups(sec);
    const total = groups.reduce((n, g) => n + g.words.length, 0);
    slot.innerHTML = `
      <button type="button" class="topik-back" onclick="ssHome()"><i class="fa-solid fa-chevron-left"></i> Разделы</button>
      <div class="topik-sec-head"><h2 class="topik-sec-title">${sec.ico} ${sec.t}</h2><p class="topik-sec-sub">${sec.s} · ${total} карточек</p></div>
      <div class="topik-rules">${groups.map(g => ssThemeHtml(g)).join('')}</div>`;
  }
